const SESSION_COOKIE_NAME = 'chearb_sess'
const SESSION_COOKIE_MAX_AGE_SECONDS = 60 * 60 * 24 * 30
const DEFAULT_ALLOWED_WEB_ORIGINS = new Set([
    'https://app.pubilo.com',
    'https://web.pubilo.com',
    'https://app.oomnn.com',
    'https://web.oomnn.com',
    'https://video-affiliate-webapp.pages.dev',
])

function parseCookieHeader(cookieHeader: string): Record<string, string> {
    const cookies: Record<string, string> = {}
    for (const part of String(cookieHeader || '').split(';')) {
        const segment = String(part || '').trim()
        if (!segment) continue
        const separatorIndex = segment.indexOf('=')
        if (separatorIndex <= 0) continue
        const name = segment.slice(0, separatorIndex).trim()
        const value = segment.slice(separatorIndex + 1).trim()
        if (!name) continue
        cookies[name] = decodeURIComponent(value)
    }
    return cookies
}

function getSessionTokenFromRequest(c: Context<any>): string {
    const cookies = parseCookieHeader(String(c.req.header('cookie') || ''))
    const cookieToken = String(cookies[SESSION_COOKIE_NAME] || '').trim()
    if (cookieToken.startsWith('sess_')) return cookieToken

    const headerToken = String(c.req.header('x-auth-token') || '').trim()
    if (headerToken.startsWith('sess_')) return headerToken

    return ''
}

function buildSessionCookie(sessionToken: string, maxAgeSeconds = SESSION_COOKIE_MAX_AGE_SECONDS): string {
    const normalizedToken = String(sessionToken || '').trim()
    if (!normalizedToken.startsWith('sess_')) return buildClearedSessionCookie()
    return [
        `${SESSION_COOKIE_NAME}=${encodeURIComponent(normalizedToken)}`,
        'Path=/',
        `Max-Age=${Math.max(0, Math.floor(maxAgeSeconds))}`,
        'HttpOnly',
        'Secure',
        'SameSite=Lax',
    ].join('; ')
}

function buildClearedSessionCookie(): string {
    return [
        `${SESSION_COOKIE_NAME}=`,
        'Path=/',
        'Max-Age=0',
        'HttpOnly',
        'Secure',
        'SameSite=Lax',
    ].join('; ')
}

function resolveCorsOrigin(requestOrigin: string | undefined, env: Env): string {
    const normalizedOrigin = String(requestOrigin || '').trim()
    if (normalizedOrigin) {
        try {
            const parsed = new URL(normalizedOrigin)
            const hostname = String(parsed.hostname || '').trim().toLowerCase()
            if (
                DEFAULT_ALLOWED_WEB_ORIGINS.has(normalizedOrigin)
                || hostname === 'app.pubilo.com'
                || hostname === 'web.pubilo.com'
                || hostname === 'app.oomnn.com'
                || hostname === 'web.oomnn.com'
                || hostname === 'video-affiliate-webapp.pages.dev'
                || hostname.endsWith('.video-affiliate-webapp.pages.dev')
            ) {
                return normalizedOrigin
            }
        } catch {
            // Fall through to env/default handling below.
        }
    }

    const configuredOrigin = String(env.CORS_ORIGIN || '').trim()
    if (configuredOrigin && configuredOrigin !== '*') return configuredOrigin
    return normalizedOrigin || 'https://app.pubilo.com'
}

function buildWavFromPcm16le(pcmBytes: Uint8Array, sampleRate = 24000, channels = 1, bitsPerSample = 16): Uint8Array {
    const byteRate = sampleRate * channels * (bitsPerSample / 8)
    const blockAlign = channels * (bitsPerSample / 8)
    const buffer = new ArrayBuffer(44 + pcmBytes.byteLength)
    const view = new DataView(buffer)
    const bytes = new Uint8Array(buffer)
    const writeAscii = (offset: number, value: string) => {
        for (let i = 0; i < value.length; i += 1) {
            view.setUint8(offset + i, value.charCodeAt(i))
        }
    }

    writeAscii(0, 'RIFF')
    view.setUint32(4, 36 + pcmBytes.byteLength, true)
    writeAscii(8, 'WAVE')
    writeAscii(12, 'fmt ')
    view.setUint32(16, 16, true)
    view.setUint16(20, 1, true)
    view.setUint16(22, channels, true)
    view.setUint32(24, sampleRate, true)
    view.setUint32(28, byteRate, true)
    view.setUint16(32, blockAlign, true)
    view.setUint16(34, bitsPerSample, true)
    writeAscii(36, 'data')
    view.setUint32(40, pcmBytes.byteLength, true)
    bytes.set(pcmBytes, 44)
    return bytes
}

async function requestGeminiTtsPreview(apiKey: string, promptText: string, voiceName: string, styleInstructions?: string): Promise<Uint8Array> {
    let lastError = 'gemini_tts_preview_failed'
    const trimmedStyle = String(styleInstructions || '').trim()
    // gemini-3.1-flash-tts-preview rejects `systemInstruction` ("Developer instruction is not
    // enabled for this model"). Both 3.1 and 2.5 require voiceConfig.prebuiltVoiceConfig.voiceName.
    // Style Instructions are inlined as a prefix to the script text — model follows them as
    // delivery direction without reading the prefix aloud (Vertex Studio uses the same approach).
    const combinedText = trimmedStyle
        ? `[Voice direction: ${trimmedStyle}]\n\n${promptText}`
        : promptText
    const payload = JSON.stringify({
        contents: [{ parts: [{ text: combinedText }] }],
        generationConfig: {
            responseModalities: ['AUDIO'],
            speechConfig: {
                voiceConfig: {
                    prebuiltVoiceConfig: { voiceName: voiceName || 'Puck' },
                },
            },
        },
    })
    for (const model of VOICE_PREVIEW_TTS_MODELS) {
        const url = `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${encodeURIComponent(apiKey)}`
        const resp = await fetch(url, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: payload,
        })
        const data = await resp.json().catch(() => ({})) as any
        if (!resp.ok) {
            lastError = String(data?.error?.message || data?.message || `${model}_failed_${resp.status}`)
            continue
        }
        const b64 = String(data?.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || '').trim()
        if (b64) {
            return new Uint8Array(NodeBuffer.from(b64, 'base64'))
        }
        lastError = `${model}_empty_audio`
    }
    throw new Error(lastError)
}

// CORS
app.use('*', async (c, next) => {
    const corsMiddleware = cors({
        origin: (requestOrigin) => resolveCorsOrigin(requestOrigin, c.env),
        allowMethods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
        allowHeaders: ['Content-Type', 'x-auth-token', 'x-admin-token', 'x-bot-id', 'x-tag-sync-secret'],
        exposeHeaders: ['Content-Type'],
        credentials: true,
    })
    return corsMiddleware(c, next)
})


app.use('*', async (c, next) => {
    let token = getSessionTokenFromRequest(c);
    if (!token && c.req.path.startsWith('/api/telegram/')) {
        const parts = c.req.path.split('/');
        if (parts.length >= 4) token = parts[3];
    }
    // Session token auth (webapp)
    if (token.startsWith('sess_')) {
        const user = await c.env.DB.prepare('SELECT namespace_id FROM users WHERE session_token = ?').bind(token).first() as any
        if (!user?.namespace_id) return c.json({ error: 'Unauthorized' }, 401)
        const botId = String(user.namespace_id)
        c.set('botId', botId);
        c.set('bucket', new BotBucket(c.env.BUCKET, botId) as unknown as R2Bucket);
    } else {
        const botId = c.req.header('x-bot-id') || getBotId(token);
        if (!c.req.path.startsWith('/api/telegram/') && !c.req.path.startsWith('/api/r2') && !c.req.path.startsWith('/api/line/')) {
            console.log(`[API REQUEST] path: ${c.req.path} | raw-token: ${token?.substring(0, 15)} | botId: ${botId}`)
        }
        c.set('botId', botId);
        c.set('bucket', new BotBucket(c.env.BUCKET, botId) as unknown as R2Bucket);
    }
    await next();
})

// Cache control middleware — reduce redundant API calls from frontend
app.use('*', async (c, next) => {
    await next()
    if (c.res.headers.get('Cache-Control')) {
        return
    }
    const path = c.req.path
    if (path === '/api/me') {
        c.header('Cache-Control', 'private, max-age=60')
        c.header('Vary', 'x-auth-token')
    } else if (path === '/api/team') {
        c.header('Cache-Control', 'private, max-age=120')
        c.header('Vary', 'x-auth-token')
    } else if (path.startsWith('/api/settings/')) {
        c.header('Cache-Control', 'private, max-age=120')
        c.header('Vary', 'x-auth-token')
    } else if (path === '/api/inbox' || path === '/api/inbox/system') {
        c.header('Cache-Control', 'private, max-age=15')
        c.header('Vary', 'x-auth-token')
    }
})

async function isSystemAdmin(db: D1Database, email: string): Promise<boolean> {
    const row = await db.prepare('SELECT 1 AS ok FROM system_admins WHERE email = ? LIMIT 1')
        .bind(String(email || '').trim().toLowerCase()).first()
    return !!row
}

async function isNamespaceOwner(db: D1Database, email: string): Promise<boolean> {
    const row = await db.prepare('SELECT 1 AS ok FROM email_namespaces WHERE email = ? LIMIT 1')
        .bind(String(email || '').trim().toLowerCase()).first()
    return !!row
}

async function isTeamMemberEmail(db: D1Database, email: string): Promise<boolean> {
    const normalizedEmail = String(email || '').trim().toLowerCase()
    if (!normalizedEmail) return false
    const row = await db.prepare('SELECT 1 AS ok FROM team_members WHERE lower(trim(email)) = ? LIMIT 1')
        .bind(normalizedEmail)
        .first()
        .catch(() => null)
    return !!row
}

async function isNamespaceOwnerIdentity(db: D1Database, email: string, namespaceId: string): Promise<boolean> {
    const normalizedNamespaceId = String(namespaceId || '').trim()
    if (!normalizedNamespaceId) return false

    const normalizedEmail = String(email || '').trim().toLowerCase()
    if (await isTeamMemberEmail(db, normalizedEmail)) return false

    const hasLineOwner = normalizedEmail ? await db.prepare(
        `SELECT 1 AS ok
         FROM line_users
         WHERE namespace_id = ?
           AND lower(trim(email)) = ?
         LIMIT 1`
    ).bind(normalizedNamespaceId, normalizedEmail).first().catch(() => null) : null
    if (hasLineOwner) return true

    if (!normalizedEmail) return false
    const mapped = await db.prepare(
        'SELECT 1 AS ok FROM email_namespaces WHERE email = ? AND namespace_id = ? LIMIT 1'
    ).bind(normalizedEmail, normalizedNamespaceId).first().catch(() => null)
    return !!mapped
}

async function requireOwnerSession(c: Context<{ Bindings: Env, Variables: { botId: string; bucket: R2Bucket } }>) {
    const token = getSessionTokenFromRequest(c)
    if (!token.startsWith('sess_')) {
        return { ok: false as const, response: c.json({ error: 'Unauthorized' }, 401) }
    }
    const user = await c.env.DB.prepare('SELECT email, namespace_id FROM users WHERE session_token = ?').bind(token).first() as { email?: string; namespace_id?: string } | null
    if (!user?.namespace_id) {
        return { ok: false as const, response: c.json({ error: 'Unauthorized' }, 401) }
    }
    const ownerOk = await isNamespaceOwnerIdentity(c.env.DB, String(user.email || ''), String(user.namespace_id || ''))
    if (!ownerOk) {
        return { ok: false as const, response: c.json({ error: 'Forbidden' }, 403) }
    }
    return { ok: true as const }
}

// Resolve the dashboard passkey session against the shared D1
// `dashboard_passkey_sessions` table. The session id comes from the proxy-injected
// x-dashboard-session-id header (preferred — the cross-subdomain cookie does not
// reliably survive the proxy hop) or, as a fallback, the pubilo_dashboard_session
// cookie. Returns a live (unexpired) row with a namespace_id, or null. The table is
// owned by the dashboard worker (apps/dashboard/src/server/auth.ts) on the SAME D1
// binding; a missing table or any DB error degrades to null (treated as
// unauthenticated) rather than throwing. No session value is ever logged.
async function loadDashboardSession(c: Context<any>): Promise<DashboardSessionRow | null> {
    const sessionId = resolveDashboardSessionId(
        c.req.header(DASHBOARD_SESSION_HEADER_NAME),
        c.req.header('cookie'),
    )
    if (!sessionId) return null
    const row = await c.env.DB.prepare(
        `SELECT session_id, user_id, namespace_id, expires_at
           FROM dashboard_passkey_sessions
          WHERE session_id = ? AND datetime(expires_at) > datetime('now')`
    ).bind(sessionId).first().catch(() => null) as DashboardSessionRow | null
    if (!row?.namespace_id) return null
    return row
}

// True when a live dashboard passkey session authorizes this request. The
// namespace check is delegated to the pure decision in ./dashboard-session: the
// request MUST carry a resolved botId (the dashboard sends it via x-bot-id) that
// equals the session namespace_id. A blank botId never authorizes, so a dashboard
// operator can only act inside their own namespace.
async function dashboardSessionAuthorizes(c: Context<any>): Promise<boolean> {
    const session = await loadDashboardSession(c)
    return dashboardSessionNamespaceAuthorizes({
        session,
        requestBotId: c.get('botId'),
    })
}

// Count registered dashboard passkey credentials for a namespace in the shared D1.
// Returns null on any error (missing table / DB failure) so callers treat the
// setup-mode signal as UNCONFIRMED and deny — the header is never trusted alone.
async function loadDashboardCredentialCount(c: Context<any>, namespaceId: string): Promise<number | null> {
    const row = await c.env.DB.prepare(
        'SELECT COUNT(*) AS n FROM dashboard_passkey_credentials WHERE namespace_id = ?'
    ).bind(namespaceId).first().catch(() => null) as { n?: number } | null
    if (!row) return null
    return Number(row.n ?? 0)
}

// Setup-mode (passkey bootstrap) authorization fallback. ONLY reached when there is
// no dashboard session. Accepts the proxy-set x-dashboard-setup-mode:1 header, but
// only after independently re-confirming via the shared D1 that the request's
// namespace has 0 registered credentials. The header alone is never sufficient.
// The DB is queried only when the header is actually present (cheap short-circuit).
async function dashboardSetupModeAuthorizes(c: Context<any>): Promise<boolean> {
    const setupModeHeader = c.req.header(DASHBOARD_SETUP_MODE_HEADER_NAME)
    if (String(setupModeHeader || '').trim() !== '1') return false
    const botId = String(c.get('botId') || '').trim()
    if (!botId) return false
    const credentialCount = await loadDashboardCredentialCount(c, botId)
    return dashboardSetupModeNamespaceAuthorizes({
        setupModeHeader,
        requestBotId: botId,
        credentialCount,
    })
}

async function requireAuthSession(c: Context<{ Bindings: Env, Variables: { botId: string; bucket: R2Bucket } }>) {
    const token = getSessionTokenFromRequest(c)
    if (token.startsWith('sess_')) {
        const user = await c.env.DB.prepare('SELECT email FROM users WHERE session_token = ?').bind(token).first() as { email?: string } | null
        if (!user?.email) {
            return { ok: false as const, response: c.json({ error: 'Unauthorized' }, 401) }
        }
        return { ok: true as const }
    }
    // Dashboard passkey session bridge (pubilo_dashboard_session): the React
    // dashboard never holds a raw `sess_` token, so authenticated operators reach
    // these write routes via their passkey session cookie instead. Namespace is
    // enforced (see dashboardSessionAuthorizes); a present-but-invalid `sess_`
    // token above never falls through here.
    if (await dashboardSessionAuthorizes(c)) {
        return { ok: true as const }
    }
    // Setup-mode fallback: during the passkey bootstrap window (namespace has 0
    // registered credentials) the dashboard has no session to bridge, yet its UI is
    // intentionally accessible. Authorize namespace-scoped writes, re-confirming the
    // 0-credential state against D1 (header alone is never trusted).
    if (await dashboardSetupModeAuthorizes(c)) {
        return { ok: true as const }
    }
    return { ok: false as const, response: c.json({ error: 'Unauthorized' }, 401) }
}

async function requireSystemAdminSession(c: Context<{ Bindings: Env, Variables: { botId: string; bucket: R2Bucket } }>) {
    const token = getSessionTokenFromRequest(c)
    if (!token.startsWith('sess_')) {
        return { ok: false as const, response: c.json({ error: 'Unauthorized' }, 401) }
    }
    const user = await c.env.DB.prepare(
        'SELECT email, namespace_id FROM users WHERE session_token = ?'
    ).bind(token).first().catch(() => null) as { email?: string; namespace_id?: string } | null
    if (!user?.email || !user?.namespace_id) {
        return { ok: false as const, response: c.json({ error: 'Unauthorized' }, 401) }
    }
    const sysAdmin = await isSystemAdmin(c.env.DB, String(user.email))
    if (!sysAdmin) {
        return { ok: false as const, response: c.json({ error: 'Forbidden' }, 403) }
    }
    return {
        ok: true as const,
        email: String(user.email || '').trim().toLowerCase(),
        namespaceId: String(user.namespace_id || '').trim(),
    }
}

async function upsertUserWorkspaceByEmail(db: D1Database, emailRaw: string, namespaceId: string): Promise<void> {
    const email = String(emailRaw || '').trim().toLowerCase()
    const ns = String(namespaceId || '').trim()
    if (!email || !ns) return

    const existing = await db.prepare(
        'SELECT 1 AS ok FROM users WHERE lower(trim(email)) = ? LIMIT 1'
    ).bind(email).first().catch(() => null) as { ok?: number } | null

    if (existing?.ok) {
        await db.prepare(
            'UPDATE users SET namespace_id = ? WHERE lower(trim(email)) = ?'
        ).bind(ns, email).run().catch(() => { })
        return
    }

    await db.prepare(
        "INSERT INTO users (email, namespace_id, session_token) VALUES (?, ?, '')"
    ).bind(email, ns).run().catch(() => { })
}

async function resolveManagedWorkspaceForRole(
    db: D1Database,
    emailRaw: string,
    currentNamespaceId: string,
    adminNamespaceId: string
): Promise<string> {
    const email = String(emailRaw || '').trim().toLowerCase()
    const currentNamespace = String(currentNamespaceId || '').trim()
    const adminNamespace = String(adminNamespaceId || '').trim()

    const mapped = await db.prepare(
        'SELECT namespace_id FROM email_namespaces WHERE email = ? LIMIT 1'
    ).bind(email).first().catch(() => null) as { namespace_id?: string } | null
    const mappedNamespace = String(mapped?.namespace_id || '').trim()
    if (mappedNamespace) return mappedNamespace

    if (currentNamespace && currentNamespace !== adminNamespace) return currentNamespace
    return createOwnerWorkspaceId()
}

async function assignLineUserRole(
    db: D1Database,
    lineUserIdRaw: string,
    targetRoleRaw: string,
    adminNamespaceIdRaw: string
): Promise<{
    line_user_id: string
    namespace_id: string
    role: 'admin' | 'member' | 'team'
    status: 'approved'
  }> {
    const lineUserId = String(lineUserIdRaw || '').trim()
    const adminNamespaceId = String(adminNamespaceIdRaw || '').trim()
    const targetRole = String(targetRoleRaw || '').trim().toLowerCase()
    if (!lineUserId) throw new Error('line_user_id required')
    if (!adminNamespaceId) throw new Error('admin_namespace_id required')
    if (!['admin', 'member', 'team'].includes(targetRole)) throw new Error('invalid_role')

    await ensureLineUsersTable(db)
    const lineUser = await db.prepare(
        'SELECT email, namespace_id FROM line_users WHERE line_user_id = ? LIMIT 1'
    ).bind(lineUserId).first().catch(() => null) as { email?: string; namespace_id?: string } | null

    const email = String(lineUser?.email || '').trim().toLowerCase()
    const currentNamespaceId = String(lineUser?.namespace_id || '').trim()
    if (!email) throw new Error('member_not_found')

    let targetNamespaceId = currentNamespaceId

    if (targetRole === 'team') {
        const existingTeam = await db.prepare(
            'SELECT owner_namespace_id FROM team_members WHERE lower(trim(email)) = ? LIMIT 1'
        ).bind(email).first().catch(() => null) as { owner_namespace_id?: string } | null
        targetNamespaceId = String(existingTeam?.owner_namespace_id || '').trim()
        if (!targetNamespaceId) {
            throw new Error('team_role_requires_existing_invite_namespace')
        }
        await db.prepare('DELETE FROM email_namespaces WHERE email = ?').bind(email).run().catch(() => { })
        await db.prepare('DELETE FROM system_admins WHERE lower(trim(email)) = ?').bind(email).run().catch(() => { })
        await db.prepare('DELETE FROM team_members WHERE lower(trim(email)) = ? AND owner_namespace_id <> ?')
            .bind(email, targetNamespaceId).run().catch(() => { })
        await db.prepare(
            'INSERT OR IGNORE INTO team_members (owner_namespace_id, email) VALUES (?, ?)'
        ).bind(targetNamespaceId, email).run().catch(() => { })
    } else {
        targetNamespaceId = await resolveManagedWorkspaceForRole(db, email, currentNamespaceId, adminNamespaceId)
        await upsertOwnerNamespaceMapping(db, email, targetNamespaceId)
        await db.prepare('DELETE FROM team_members WHERE lower(trim(email)) = ?').bind(email).run().catch(() => { })
        if (targetRole === 'admin') {
            await db.prepare('INSERT OR IGNORE INTO system_admins (email) VALUES (?)').bind(email).run().catch(() => { })
        } else {
            await db.prepare('DELETE FROM system_admins WHERE lower(trim(email)) = ?').bind(email).run().catch(() => { })
        }
    }

    await db.prepare(
        `UPDATE line_users
         SET namespace_id = ?, status = 'approved', updated_at = datetime('now')
         WHERE line_user_id = ?`
    ).bind(targetNamespaceId, lineUserId).run().catch(() => { })
    await upsertUserWorkspaceByEmail(db, email, targetNamespaceId)

    return {
        line_user_id: lineUserId,
        namespace_id: targetNamespaceId,
        role: targetRole as 'admin' | 'member' | 'team',
        status: 'approved',
    }
}

async function resolveNamespacesForTagSync(
    db: D1Database,
    input: { namespaceId?: string; email?: string },
): Promise<string[]> {
    const out: string[] = []
    const seen = new Set<string>()
    const push = (value: unknown) => {
        const ns = String(value || '').trim()
        if (!ns || ns === 'default') return
        if (seen.has(ns)) return
        seen.add(ns)
        out.push(ns)
    }

    push(input.namespaceId)

    const email = String(input.email || '').trim().toLowerCase()
    if (email) {
        const mapped = await db.prepare(
            'SELECT namespace_id FROM email_namespaces WHERE email = ?'
        ).bind(email).first() as { namespace_id?: string } | null
        push(mapped?.namespace_id)

        const fromUsers = await db.prepare(
            `SELECT DISTINCT namespace_id
             FROM users
             WHERE email = ?
               AND namespace_id IS NOT NULL
               AND TRIM(namespace_id) <> ''`
        ).bind(email).all() as { results?: Array<{ namespace_id?: string }> }
        for (const row of (fromUsers.results || [])) push(row?.namespace_id)
    }

    return out
}

