async function ensureTelegramBotSessionsTable(db: D1Database) {
    await db.prepare(
        `CREATE TABLE IF NOT EXISTS telegram_bot_sessions (
            telegram_id TEXT NOT NULL,
            bot_scope TEXT NOT NULL,
            email TEXT NOT NULL,
            namespace_id TEXT NOT NULL,
            session_token TEXT NOT NULL DEFAULT '',
            created_at TEXT DEFAULT (datetime('now')),
            updated_at TEXT DEFAULT (datetime('now')),
            PRIMARY KEY (telegram_id, bot_scope)
        )`
    ).run()
    await db.prepare(
        'CREATE INDEX IF NOT EXISTS idx_telegram_bot_sessions_token ON telegram_bot_sessions(session_token)'
    ).run().catch(() => { })
}

async function getTelegramBotSession(db: D1Database, telegramId: string, botScope: string) {
    await ensureTelegramBotSessionsTable(db)
    return await db.prepare(
        `SELECT telegram_id, bot_scope, email, namespace_id, session_token
         FROM telegram_bot_sessions
         WHERE telegram_id = ? AND bot_scope = ?
         LIMIT 1`
    ).bind(telegramId, botScope).first() as {
        telegram_id?: string
        bot_scope?: string
        email?: string
        namespace_id?: string
        session_token?: string
    } | null
}

async function upsertTelegramBotSession(
    db: D1Database,
    telegramId: string,
    botScope: string,
    email: string,
    namespaceId: string,
    sessionToken: string,
) {
    await ensureTelegramBotSessionsTable(db)
    await db.prepare(
        `INSERT INTO telegram_bot_sessions (telegram_id, bot_scope, email, namespace_id, session_token, created_at, updated_at)
         VALUES (?, ?, ?, ?, ?, datetime('now'), datetime('now'))
         ON CONFLICT(telegram_id, bot_scope)
         DO UPDATE SET
           email = excluded.email,
           namespace_id = excluded.namespace_id,
           session_token = excluded.session_token,
           updated_at = datetime('now')`
    ).bind(telegramId, botScope, email, namespaceId, sessionToken).run()
}

async function upsertUserSessionByTelegram(
    db: D1Database,
    telegramId: string,
    email: string,
    namespaceId: string,
    sessionToken: string,
) {
    const telegramIdValue = Number(String(telegramId || '').trim())
    if (!Number.isFinite(telegramIdValue)) {
        await db.prepare(
            'INSERT INTO users (email, namespace_id, session_token) VALUES (?, ?, ?)'
        ).bind(email, namespaceId, sessionToken).run()
        return
    }

    const existingTgRow = await db.prepare(
        'SELECT email FROM users WHERE telegram_id = ?'
    ).bind(telegramIdValue).first() as { email?: string } | null

    if (existingTgRow) {
        await db.prepare(
            'UPDATE users SET email = ?, namespace_id = ?, session_token = ? WHERE telegram_id = ?'
        ).bind(email, namespaceId, sessionToken, telegramIdValue).run()
        return
    }

    await db.prepare(
        'INSERT INTO users (telegram_id, email, namespace_id, session_token) VALUES (?, ?, ?, ?)'
    ).bind(telegramIdValue, email, namespaceId, sessionToken).run()
}

async function bindTelegramToExistingSession(
    db: D1Database,
    sessionToken: string,
    telegramId: string,
    botScope: string,
) {
    const normalizedSessionToken = String(sessionToken || '').trim()
    const normalizedTelegramId = String(telegramId || '').trim()
    const normalizedBotScope = String(botScope || '').trim()
    if (!normalizedSessionToken.startsWith('sess_') || !normalizedTelegramId || !normalizedBotScope) return null

    const currentUser = await db.prepare(
        'SELECT email, namespace_id, session_token FROM users WHERE session_token = ? LIMIT 1'
    ).bind(normalizedSessionToken).first() as { email?: string; namespace_id?: string; session_token?: string } | null

    const email = String(currentUser?.email || '').trim().toLowerCase()
    const namespaceId = String(currentUser?.namespace_id || '').trim()
    const effectiveSessionToken = String(currentUser?.session_token || '').trim() || normalizedSessionToken
    if (!email || !namespaceId || namespaceId !== normalizedBotScope) return null

    await upsertUserSessionByTelegram(db, normalizedTelegramId, email, namespaceId, effectiveSessionToken)
    await upsertTelegramBotSession(db, normalizedTelegramId, normalizedBotScope, email, namespaceId, effectiveSessionToken)
    return {
        session_token: effectiveSessionToken,
        namespace_id: namespaceId,
        email,
    }
}

async function hasTelegramWorkspaceAccess(
    db: D1Database,
    telegramId: string,
    botScope: string,
): Promise<boolean> {
    const normalizedTelegramId = String(telegramId || '').trim()
    const normalizedBotScope = String(botScope || '').trim()
    if (!normalizedTelegramId || !normalizedBotScope) return false

    const scoped = await getTelegramBotSession(db, normalizedTelegramId, normalizedBotScope).catch(() => null)
    if (String(scoped?.email || '').trim()) return true

    const telegramIdValue = Number(normalizedTelegramId)
    if (!Number.isFinite(telegramIdValue)) return false

    const user = await db.prepare(
        'SELECT email FROM users WHERE telegram_id = ? AND namespace_id = ? LIMIT 1'
    ).bind(telegramIdValue, normalizedBotScope).first() as { email?: string } | null
    return !!String(user?.email || '').trim()
}

async function clearTelegramBotSessionByScope(db: D1Database, telegramId: string, botScope: string) {
    const current = await getTelegramBotSession(db, telegramId, botScope)
    const sessionToken = String(current?.session_token || '').trim()
    if (sessionToken) {
        await db.prepare("UPDATE users SET session_token = '' WHERE session_token = ?").bind(sessionToken).run().catch(() => { })
    }
    await ensureTelegramBotSessionsTable(db)
    await db.prepare(
        "UPDATE telegram_bot_sessions SET session_token = '', updated_at = datetime('now') WHERE telegram_id = ? AND bot_scope = ?"
    ).bind(telegramId, botScope).run().catch(() => { })
    return !!sessionToken
}

async function clearTelegramBotSessionByToken(db: D1Database, sessionToken: string) {
    const normalized = String(sessionToken || '').trim()
    if (!normalized) return
    await ensureTelegramBotSessionsTable(db)
    await db.prepare(
        "UPDATE telegram_bot_sessions SET session_token = '', updated_at = datetime('now') WHERE session_token = ?"
    ).bind(normalized).run().catch(() => { })
}

async function resolveTelegramWorkspaceSession(db: D1Database, telegramId: string, botScope: string) {
    const scoped = botScope ? await getTelegramBotSession(db, telegramId, botScope).catch(() => null) : null
    if (scoped?.namespace_id) {
        return {
            namespace_id: String(scoped.namespace_id || '').trim(),
            session_token: String(scoped.session_token || '').trim(),
            email: String(scoped.email || '').trim(),
        }
    }
    const legacy = await db.prepare(
        'SELECT namespace_id, session_token, email FROM users WHERE telegram_id = ?'
    ).bind(telegramId).first() as {
        namespace_id?: string
        session_token?: string
        email?: string
    } | null
    if (!legacy?.namespace_id) return null
    const legacyNamespaceId = String(legacy.namespace_id || '').trim()
    const normalizedBotScope = String(botScope || '').trim()
    if (normalizedBotScope && legacyNamespaceId && legacyNamespaceId !== normalizedBotScope) {
        const knownChannelBot = await db.prepare(
            'SELECT 1 AS ok FROM channels WHERE bot_id = ? LIMIT 1'
        ).bind(normalizedBotScope).first().catch(() => null) as { ok?: number } | null
        if (Number(knownChannelBot?.ok || 0) === 1) {
            return null
        }
    }
    return {
        namespace_id: legacyNamespaceId,
        session_token: String(legacy.session_token || '').trim(),
        email: String(legacy.email || '').trim(),
    }
}

async function resolveOwnerEmailForNamespace(db: D1Database, namespaceId: string): Promise<string> {
    const normalizedNamespaceId = String(namespaceId || '').trim()
    if (!normalizedNamespaceId) return ''

    try {
        const mapped = await db.prepare(
            `SELECT email
             FROM email_namespaces
             WHERE namespace_id = ?
             ORDER BY datetime(updated_at) DESC, datetime(created_at) DESC
             LIMIT 1`
        ).bind(normalizedNamespaceId).first() as { email?: string } | null
        const mappedEmail = String(mapped?.email || '').trim().toLowerCase()
        if (mappedEmail) return mappedEmail
    } catch {
        // ignore older db states
    }

    const user = await db.prepare(
        `SELECT email
         FROM users
         WHERE namespace_id = ?
           AND TRIM(COALESCE(email, '')) <> ''
         ORDER BY datetime(created_at) ASC, telegram_id ASC
         LIMIT 1`
    ).bind(normalizedNamespaceId).first() as { email?: string } | null
    return String(user?.email || '').trim().toLowerCase()
}

async function claimOrValidateChannelOwner(
    db: D1Database,
    botId: string,
    telegramId: string,
    displayName?: string,
): Promise<{ allowed: boolean; claimed: boolean; ownerTelegramId: string }> {
    const normalizedBotId = String(botId || '').trim()
    const normalizedTelegramId = String(telegramId || '').trim()
    if (!normalizedBotId || !normalizedTelegramId) {
        return { allowed: false, claimed: false, ownerTelegramId: '' }
    }

    const channel = await db.prepare(
        'SELECT owner_telegram_id FROM channels WHERE bot_id = ? LIMIT 1'
    ).bind(normalizedBotId).first() as { owner_telegram_id?: string | number } | null

    if (!channel) {
        return { allowed: false, claimed: false, ownerTelegramId: '' }
    }

    const currentOwnerTelegramId = String(channel.owner_telegram_id || '').trim()
    if (currentOwnerTelegramId && currentOwnerTelegramId !== normalizedTelegramId) {
        return { allowed: false, claimed: false, ownerTelegramId: currentOwnerTelegramId }
    }

    let claimed = false
    if (!currentOwnerTelegramId) {
        await db.prepare(
            "UPDATE channels SET owner_telegram_id = ? WHERE bot_id = ? AND TRIM(COALESCE(owner_telegram_id, '')) = ''"
        ).bind(normalizedTelegramId, normalizedBotId).run()
        claimed = true
    }

    const resolvedOwnerTelegramId = claimed ? normalizedTelegramId : currentOwnerTelegramId
    const telegramIdValue = Number(normalizedTelegramId)
    if (Number.isFinite(telegramIdValue)) {
        await db.prepare(
            'INSERT INTO allowed_users (telegram_id, name) VALUES (?, ?) ON CONFLICT DO NOTHING'
        ).bind(telegramIdValue, String(displayName || 'owner').trim() || 'owner').run().catch(() => { })
    }

    return {
        allowed: true,
        claimed,
        ownerTelegramId: resolvedOwnerTelegramId || normalizedTelegramId,
    }
}

async function provisionTelegramOwnerSession(
    db: D1Database,
    telegramId: string,
    botScope: string,
    displayName?: string,
) {
    const normalizedTelegramId = String(telegramId || '').trim()
    const normalizedBotScope = String(botScope || '').trim()
    if (!normalizedTelegramId || !normalizedBotScope) return null

    const ownerAccess = await claimOrValidateChannelOwner(db, normalizedBotScope, normalizedTelegramId, displayName)
    if (!ownerAccess.allowed) return null

    const ownerEmail = await resolveOwnerEmailForNamespace(db, normalizedBotScope)
    if (!ownerEmail) return null

    await upsertOwnerNamespaceMapping(db, ownerEmail, normalizedBotScope).catch(() => { })

    const sessionToken = 'sess_' + crypto.randomUUID().replace(/-/g, '')
    const telegramIdValue = Number(normalizedTelegramId)
    const existingTgRow = Number.isFinite(telegramIdValue)
        ? await db.prepare('SELECT email FROM users WHERE telegram_id = ?').bind(telegramIdValue).first() as { email?: string } | null
        : null

    if (existingTgRow) {
        await db.prepare(
            'UPDATE users SET email = ?, namespace_id = ?, session_token = ? WHERE telegram_id = ?'
        ).bind(ownerEmail, normalizedBotScope, sessionToken, telegramIdValue).run()
    } else if (Number.isFinite(telegramIdValue)) {
        await db.prepare(
            'INSERT INTO users (telegram_id, email, namespace_id, session_token) VALUES (?, ?, ?, ?)'
        ).bind(telegramIdValue, ownerEmail, normalizedBotScope, sessionToken).run()
    } else {
        await db.prepare(
            'INSERT INTO users (email, namespace_id, session_token) VALUES (?, ?, ?)'
        ).bind(ownerEmail, normalizedBotScope, sessionToken).run()
    }

    await upsertTelegramBotSession(db, normalizedTelegramId, normalizedBotScope, ownerEmail, normalizedBotScope, sessionToken)

    return {
        session_token: sessionToken,
        namespace_id: normalizedBotScope,
        email: ownerEmail,
        claimed_owner: ownerAccess.claimed,
    }
}

function buildScopedWebAppUrl(baseUrl: string, botScope: string) {
    const scope = String(botScope || '').trim()
    if (!scope) return baseUrl
    try {
        const url = new URL(baseUrl)
        url.searchParams.set('bot', scope)
        return url.toString()
    } catch {
        return `${baseUrl}${baseUrl.includes('?') ? '&' : '?'}bot=${encodeURIComponent(scope)}`
    }
}

function buildScopedAppPathUrl(baseUrl: string, botScope: string, targetPath: string, extraParams?: Record<string, string>) {
    const scopedBaseUrl = buildScopedWebAppUrl(baseUrl, botScope)
    const normalizedTargetPath = String(targetPath || '').trim().replace(/^\/+/, '')
    try {
        const url = new URL(scopedBaseUrl)
        const isLiffUrl = url.hostname === 'liff.line.me'
        const preservedBasePath = isLiffUrl
            ? String(url.pathname || '').replace(/\/+$/, '')
            : ''
        const mergedParams = new URLSearchParams()
        const scope = String(botScope || '').trim()
        if (scope) mergedParams.set('bot', scope)
        for (const [key, value] of Object.entries(extraParams || {})) {
            const normalizedValue = String(value || '').trim()
            if (normalizedValue) mergedParams.set(key, normalizedValue)
        }
        if (isLiffUrl) {
            url.pathname = preservedBasePath || url.pathname || '/'
            const liffStatePath = `/${normalizedTargetPath}${mergedParams.toString() ? `?${mergedParams.toString()}` : ''}`
            url.searchParams.set('liff.state', liffStatePath)
            if (scope) url.searchParams.set('bot', scope)
            else url.searchParams.delete('bot')
        } else {
            url.pathname = preservedBasePath && preservedBasePath !== '/'
                ? `${preservedBasePath}/${normalizedTargetPath}`
                : `/${normalizedTargetPath}`
            for (const [key, value] of mergedParams.entries()) {
                url.searchParams.set(key, value)
            }
        }
        return url.toString()
    } catch {
        const params = new URLSearchParams()
        const scope = String(botScope || '').trim()
        if (scope) params.set('bot', scope)
        for (const [key, value] of Object.entries(extraParams || {})) {
            const normalizedValue = String(value || '').trim()
            if (normalizedValue) params.set(key, normalizedValue)
        }
        const query = params.toString()
        return `${baseUrl.replace(/\/+$/, '')}/${normalizedTargetPath}${query ? `?${query}` : ''}`
    }
}

function buildScopedGalleryWebAppUrl(baseUrl: string, botScope: string, store: 'shopee' | 'lazada', videoId?: string) {
    const params: Record<string, string> = { store }
    const trimmedVideoId = String(videoId || '').trim()
    if (trimmedVideoId) params.q = trimmedVideoId
    return buildScopedAppPathUrl(baseUrl, botScope, 'gallery', params)
}

function buildScopedTabWebAppUrl(baseUrl: string, botScope: string, tab: string, extraParams?: Record<string, string>) {
    return buildScopedAppPathUrl(baseUrl, botScope, String(tab || '').trim(), extraParams)
}

function buildScopedLiffTabQueryUrl(baseUrl: string, botScope: string, tab: string, extraParams?: Record<string, string>) {
    const scopedBaseUrl = buildScopedWebAppUrl(baseUrl, botScope)
    const normalizedTab = String(tab || '').trim()
    try {
        const url = new URL(scopedBaseUrl)
        if (normalizedTab) url.searchParams.set('tab', normalizedTab)
        else url.searchParams.delete('tab')
        url.searchParams.delete('liff.state')
        for (const [key, value] of Object.entries(extraParams || {})) {
            const normalizedValue = String(value || '').trim()
            if (normalizedValue) url.searchParams.set(key, normalizedValue)
            else url.searchParams.delete(key)
        }
        return url.toString()
    } catch {
        const params = new URLSearchParams()
        const scope = String(botScope || '').trim()
        if (scope) params.set('bot', scope)
        if (normalizedTab) params.set('tab', normalizedTab)
        for (const [key, value] of Object.entries(extraParams || {})) {
            const normalizedValue = String(value || '').trim()
            if (normalizedValue) params.set(key, normalizedValue)
        }
        const query = params.toString()
        return `${baseUrl}${query ? `?${query}` : ''}`
    }
}

function buildScopedLiffPermanentPathUrl(baseUrl: string, botScope: string, targetPath: string, extraParams?: Record<string, string>) {
    const scopedBaseUrl = buildScopedWebAppUrl(baseUrl, botScope)
    const normalizedTargetPath = String(targetPath || '').trim().replace(/^\/+/, '')
    try {
        const url = new URL(scopedBaseUrl)
        const basePath = String(url.pathname || '').replace(/\/+$/, '')
        url.pathname = normalizedTargetPath
            ? `${basePath}/${normalizedTargetPath}`
            : (basePath || '/')
        url.searchParams.delete('tab')
        url.searchParams.delete('liff.state')
        for (const [key, value] of Object.entries(extraParams || {})) {
            const normalizedValue = String(value || '').trim()
            if (normalizedValue) url.searchParams.set(key, normalizedValue)
            else url.searchParams.delete(key)
        }
        return url.toString()
    } catch {
        const params = new URLSearchParams()
        const scope = String(botScope || '').trim()
        if (scope) params.set('bot', scope)
        for (const [key, value] of Object.entries(extraParams || {})) {
            const normalizedValue = String(value || '').trim()
            if (normalizedValue) params.set(key, normalizedValue)
        }
        const query = params.toString()
        const suffix = normalizedTargetPath ? `/${normalizedTargetPath}` : ''
        return `${baseUrl.replace(/\/+$/, '')}${suffix}${query ? `?${query}` : ''}`
    }
}

function getAppWebBaseUrl(env: Env): string {
    return String(env.WEBAPP_URL || 'https://app.pubilo.com').trim() || 'https://app.pubilo.com'
}

function getDesktopWebBaseUrl(env: Env): string {
    // web.* host is not currently bound to the webapp wrangler (no web.pubilo.com
    // route in apps/video-affiliate/webapp/wrangler.jsonc). Fall back to the
    // canonical app host so the desktop link never points at a host without an
    // active route during the pubilo cutover. Set WEBAPP_DESKTOP_URL explicitly
    // (env var) once a dedicated web.* deployment exists.
    return String(env.WEBAPP_DESKTOP_URL || 'https://app.pubilo.com').trim() || 'https://app.pubilo.com'
}

// Push sync from BrowserSaving after tag updates.
// Default mode is metadata-only (no heavy Graph calls).
app.post('/api/pages/tag-sync', async (c) => {
    return c.json({ error: 'direct_page_management_only' }, 410)
    let body: any = {}
    try {
        body = await c.req.json()
    } catch {
        body = {}
    }

    const forceFullSync = body?.force_full_sync === true
    const configuredSecret = String(c.env.TAG_SYNC_PUSH_SECRET || '').trim()
    const providedSecret = String(c.req.header('x-tag-sync-secret') || '').trim()

    let namespaces: string[] = []

    if (configuredSecret && providedSecret === configuredSecret) {
        const namespaceId = String(body?.namespace_id || body?.namespaceId || c.req.header('x-bot-id') || '').trim()
        const email = String(body?.email || '').trim().toLowerCase()
        namespaces = await resolveNamespacesForTagSync(c.env.DB, { namespaceId, email })
    } else {
        const owner = await requireOwnerSession(c)
        if (!owner.ok) return owner.response
        namespaces = [String(c.get('botId') || '').trim()].filter(Boolean)
    }

    if (namespaces.length === 0) {
        return c.json({ error: 'namespace_not_found' }, 400)
    }

    const result: Array<{ namespace_id: string; pages_count: number }> = []
    for (const ns of namespaces) {
        await clearNamespaceHiddenTaggedProfiles(c.env.DB, ns).catch((e) => {
            console.log(`[TAG-SYNC] clear hidden profiles failed ns=${ns}: ${String(e)}`)
        })

        await syncTaggedPagesFromProfileMetadata(c.env, ns).catch((e) => {
            console.log(`[TAG-SYNC] metadata sync failed ns=${ns}: ${String(e)}`)
        })

        if (forceFullSync) {
            await autoSyncPagesForNamespace(c.env, ns, { force: true }).catch((e) => {
                console.log(`[TAG-SYNC] full sync failed ns=${ns}: ${String(e)}`)
            })
        }

        const row = await c.env.DB.prepare(
            'SELECT COUNT(*) AS total FROM pages WHERE bot_id = ?'
        ).bind(ns).first() as { total?: number } | null
        result.push({
            namespace_id: ns,
            pages_count: Number(row?.total || 0),
        })
    }

    return c.json({
        success: true,
        mode: forceFullSync ? 'full' : 'metadata',
        synced: result,
    })
})

app.post('/api/pages/profile-sync', async (c) => {
    // Direct/client page management stays disabled (410). ONLY the secret-authed
    // server-to-server BrowserSaving push is honored: this is how a freshly re-minted
    // Facebook Lite token reaches the namespace token pool, which is the root fix for the
    // permanent "token expired" state (a stored token is never terminal because stored
    // credentials can always mint a new one). The push originates from BrowserSaving's
    // /api/fb-lite/refresh-comment-token route. The legacy owner-session branch is removed.
    let body: any = {}
    try {
        body = await c.req.json()
    } catch {
        body = {}
    }

    // Accept EITHER the existing BrowserSaving tag-sync secret OR a dedicated Bridge Token sync
    // secret. The Bridge Token (facebook-token-cloak) local exporter pushes freshly-resolved
    // Facebook Lite page tokens through this same route; giving it its own secret means the Dev
    // can provision it without rotating/breaking the existing BrowserSaving TAG_SYNC_PUSH_SECRET.
    // Behavior is otherwise unchanged: if neither secret is configured, or the provided header
    // matches neither, the route stays 410 (no direct/client page management).
    const tagSyncSecret = String(c.env.TAG_SYNC_PUSH_SECRET || '').trim()
    const bridgeTokenSecret = String((c.env as Env & { BRIDGE_TOKEN_SYNC_SECRET?: string }).BRIDGE_TOKEN_SYNC_SECRET || '').trim()
    const providedSecret = String(c.req.header('x-tag-sync-secret') || '').trim()
    const secretAuthorized = !!providedSecret && (
        (!!tagSyncSecret && providedSecret === tagSyncSecret) ||
        (!!bridgeTokenSecret && providedSecret === bridgeTokenSecret)
    )
    if (!secretAuthorized) {
        return c.json({ error: 'direct_page_management_only' }, 410)
    }

    let namespaceId = String(body?.namespace_id || body?.namespaceId || c.req.header('x-bot-id') || '').trim()
    const email = String(body?.email || '').trim().toLowerCase()
    if (!namespaceId && email) {
        const namespaces = await resolveNamespacesForTagSync(c.env.DB, { email })
        namespaceId = String(namespaces[0] || '').trim()
    }

    const pageId = String(body?.page_id || body?.pageId || '').trim()
    const pageName = String(body?.page_name || body?.pageName || '').trim()
    const pageAvatarUrl = String(body?.page_avatar_url || body?.pageAvatarUrl || '').trim()
    const accessToken = String(body?.access_token || body?.accessToken || '').trim()
    const commentToken = String(body?.comment_token || body?.commentToken || '').trim()
    const profileId = String(body?.profile_id || body?.profileId || '').trim()
    // Advisory source tag from the Token Bridge export (e.g. facebook_lite_bridge). Used only for
    // logging/diagnostics — prioritization is driven by the token VALUE, not this hint.
    const tokenSource = String(body?.token_source || body?.tokenSource || body?.post_token_hint || '').trim()

    // Optional safe staging flag for the Facebook Lite bridge BULK import: stage a NEWLY created
    // page inactive (is_active=0) so the operator decides activation later. Default behavior is
    // unchanged (new rows active) for every normal profile-sync / Bridge Token export / token
    // refresh — those omit these fields. Existing rows' is_active is NEVER changed here.
    const importMode = String(body?.import_mode || body?.importMode || '').trim().toLowerCase()
    const rawInitialActive = body?.initial_is_active ?? body?.initialIsActive ?? body?.is_active ?? body?.isActive
    const stageInactive = importMode === 'facebook_lite_bridge_import' ||
        rawInitialActive === 0 || rawInitialActive === false || rawInitialActive === '0'
    const initialIsActive = stageInactive ? 0 : 1

    if (!namespaceId) return c.json({ error: 'namespace_not_found' }, 400)
    if (!pageId) return c.json({ error: 'page_id_required' }, 400)
    if (!accessToken) return c.json({ error: 'access_token_required' }, 400)

    try {
        await clearNamespaceHiddenTaggedProfilesForPage(c.env.DB, namespaceId, pageId).catch((e) => {
            console.log(`[PAGE-PROFILE-SYNC] clear hidden profiles failed ns=${namespaceId} page=${pageId}: ${String(e)}`)
        })

        const result = await upsertNamespacePageFromProfileSync(c.env, {
            namespaceId,
            pageId,
            pageName,
            pageAvatarUrl,
            accessToken,
            commentToken,
            tokenSource,
            initialIsActive,
            // Forward the staging-import marker so the upsert declines to MOVE a page that already
            // posts in another namespace (it returns skipped/conflict instead of stealing the row).
            importMode,
        })

        if (profileId && looksLikeBrowserSavingProfileId(profileId)) {
            try {
                const linkedProfiles = await getNamespaceLinkedTaggedProfiles(c.env.DB, namespaceId)
                linkedProfiles[pageId] = normalizeHiddenTaggedProfileIds([
                    ...(hasLinkedTaggedProfilesEntryForPage(linkedProfiles, pageId) ? linkedProfiles[pageId] || [] : []),
                    profileId,
                ])
                await setNamespaceLinkedTaggedProfiles(c.env.DB, namespaceId, linkedProfiles)
            } catch (e) {
                console.log(`[PAGE-PROFILE-SYNC] persist linked profile failed ns=${namespaceId} page=${pageId}: ${e instanceof Error ? e.message : String(e)}`)
            }
        }

        return c.json({
            success: true,
            namespace_id: namespaceId,
            page_id: pageId,
            profile_id: profileId || null,
            // Token-free diagnostic: whether a NEW row was staged inactive (only meaningful when created).
            staged_inactive: stageInactive,
            // Onboarding safety: a staging import that found the page already owned by ANOTHER
            // namespace skips it (leaves the live posting row intact) instead of moving it. Surface
            // both the camelCase upsert result fields (...result) AND a snake_case alias so the
            // /token/import-pages importer can count skipped/conflict pages without raw tokens.
            skipped: result.skipped,
            conflict_namespace_id: result.conflictNamespaceId || null,
            ...result,
        })
    } catch (e) {
        const message = e instanceof Error ? e.message : String(e)
        console.log(`[PAGE-PROFILE-SYNC] failed ns=${namespaceId} page=${pageId} profile=${profileId || 'unknown'}: ${message}`)
        return c.json({ error: 'page_profile_sync_failed', details: message }, 500)
    }
})

app.post('/api/pages/profile-token-health', async (c) => {
    return c.json({ error: 'direct_page_management_only' }, 410)
    let body: any = {}
    try {
        body = await c.req.json()
    } catch {
        body = {}
    }

    const configuredSecret = String(c.env.TAG_SYNC_PUSH_SECRET || '').trim()
    const providedSecret = String(c.req.header('x-tag-sync-secret') || '').trim()

    let namespaceId = ''
    if (configuredSecret && providedSecret === configuredSecret) {
        namespaceId = String(body?.namespace_id || body?.namespaceId || c.req.header('x-bot-id') || '').trim()
        const email = String(body?.email || '').trim().toLowerCase()
        if (!namespaceId && email) {
            const namespaces = await resolveNamespacesForTagSync(c.env.DB, { email })
            namespaceId = String(namespaces[0] || '').trim()
        }
    } else {
        const owner = await requireOwnerSession(c)
        if (!owner.ok) return owner.response
        namespaceId = String(c.get('botId') || '').trim()
    }

    if (!namespaceId) return c.json({ error: 'namespace_not_found' }, 400)

    const inputProfiles = Array.isArray(body?.profiles) ? body.profiles : []
    if (inputProfiles.length === 0) {
        return c.json({ success: true, namespace_id: namespaceId, profiles: [] })
    }

    const pages = (((await c.env.DB.prepare(
        'SELECT id, name, access_token FROM pages WHERE bot_id = ?'
    ).bind(namespaceId).all()).results || []) as Array<{ id?: string; name?: string; access_token?: string | null }>)

    const pagesById = new Map<string, { id: string; name: string; access_token: string }>()
    const pagesByName = new Map<string, Array<{ id: string; name: string; access_token: string }>>()
    for (const row of pages) {
        const id = String(row?.id || '').trim()
        if (!id) continue
        const name = String(row?.name || '').trim() || id
        const accessToken = String(row?.access_token || '').trim()
        const normalizedName = normalizePageName(name)
        const pageRecord = { id, name, access_token: accessToken }
        pagesById.set(id, pageRecord)
        if (!pagesByName.has(normalizedName)) pagesByName.set(normalizedName, [])
        pagesByName.get(normalizedName)!.push(pageRecord)
    }

    const linkedProfiles = await getNamespaceLinkedTaggedProfiles(c.env.DB, namespaceId)
    const tokenPool = await getNamespacePagesTokenPool(c.env.DB, namespaceId)

    // Query latest post per page to check for actual post failures
    const latestPostByPage = new Map<string, { status: string; error_message: string }>()
    try {
        const { results: latestPosts } = await c.env.DB.prepare(
            `SELECT page_id, status, error_message FROM post_history WHERE bot_id = ? AND id IN (SELECT MAX(id) FROM post_history WHERE bot_id = ? GROUP BY page_id)`
        ).bind(namespaceId, namespaceId).all<{ page_id: string; status: string; error_message: string | null }>()
        for (const row of (latestPosts || [])) {
            const pid = String(row?.page_id || '').trim()
            if (pid) latestPostByPage.set(pid, { status: String(row?.status || '').trim(), error_message: String(row?.error_message || '').trim() })
        }
    } catch (err) {
        console.log(`[PROFILE-TOKEN-HEALTH] failed to query latest post_history: ${String(err)}`)
    }

    const results: BrowserSavingProfileTokenHealthResult[] = []

    for (const rawProfile of inputProfiles as BrowserSavingProfileRecord[]) {
        const profileId = String(rawProfile?.id || '').trim()
        if (!profileId) continue

        const profileName = String(rawProfile?.name || '').trim() || profileId
        const tags = normalizeBrowserSavingProfileTags(rawProfile?.tags)
        const wantsPost = tags.includes('post')
        const wantsComment = tags.includes('comment')
        const localPostcronToken = pickProfilePostcronToken(rawProfile)
        const localCommentToken = pickProfileCommentToken(rawProfile)
        const localPageId = parsePageIdFromAvatarUrl(String(rawProfile?.page_avatar_url || ''))
        const localPageName = getExplicitTaggedProfilePageName(rawProfile)
        const normalizedLocalPageName = normalizePageName(localPageName)

        let matchedPage = localPageId ? pagesById.get(localPageId) : undefined
        if (!matchedPage && normalizedLocalPageName) {
            const namedMatches = pagesByName.get(normalizedLocalPageName) || []
            if (namedMatches.length > 0) matchedPage = namedMatches[0]
        }

        const pageId = String(matchedPage?.id || localPageId || '').trim()
        const pageName = String(matchedPage?.name || localPageName || '').trim()
        const pageFound = !!matchedPage

        let hasPagePostToken = false
        let hasPageCommentToken = false
        let explicitlyLinked = false

        if (matchedPage) {
            const linkedEntryExists = hasLinkedTaggedProfilesEntryForPage(linkedProfiles, matchedPage.id)
            const linkedProfileIds = linkedEntryExists
                ? getLinkedTaggedProfileIdsForPage(linkedProfiles, matchedPage.id)
                : new Set<string>()
            explicitlyLinked = linkedEntryExists ? linkedProfileIds.has(profileId.toLowerCase()) : false

            const pagePoolEntry = tokenPool[matchedPage.id] || { post_tokens: [], comment_tokens: [] }
            hasPagePostToken = normalizePostTokenPool([
                String(matchedPage.access_token || '').trim(),
                ...((pagePoolEntry.post_tokens || []).map((item) => String(item || '').trim())),
            ]).length > 0
            hasPageCommentToken = normalizeCommentTokenPool(
                (pagePoolEntry.comment_tokens || []).map((item) => String(item || '').trim()),
            ).length > 0
        }

        // Only flag as issue when the latest post for this page actually failed
        const latestPost = pageId ? latestPostByPage.get(pageId) : undefined
        const hasPostFailure = latestPost?.status === 'failed'
        const issues: string[] = []
        if (hasPostFailure) {
            issues.push(latestPost.error_message || 'โพสต์ล่าสุดไม่สำเร็จ')
        }

        results.push({
            profile_id: profileId,
            profile_name: profileName,
            namespace_id: namespaceId,
            page_id: pageId,
            page_name: pageName,
            page_found: pageFound,
            has_issue: hasPostFailure,
            issues,
            issue_summary: issues[0] || '',
            has_local_postcron_token: !!localPostcronToken,
            has_local_comment_token: !!localCommentToken,
            has_page_post_token: hasPagePostToken,
            has_page_comment_token: hasPageCommentToken,
            explicitly_linked: explicitlyLinked,
        })
    }

    return c.json({
        success: true,
        namespace_id: namespaceId,
        profiles: results,
    })
})

// TEMP MIGRATION ENDPOINT
app.get('/api/migrate-bucket-back', async (c) => {
    const fromPrefix = c.req.query('from') || '8328894625/'
    const toPrefix = c.req.query('to') || ''

    try {
        const bucket = c.env.BUCKET
        const list = await bucket.list({ prefix: fromPrefix })
        const stats = { copied: 0, skipped: 0, errors: [] as string[] }

        for (const obj of list.objects) {
            // we only want things starting with 8328894625/
            if (!obj.key.startsWith(fromPrefix)) continue;
            const newKey = obj.key.replace(fromPrefix, toPrefix);

            try {
                const oldObj = await bucket.get(obj.key)
                if (oldObj) {
                    await bucket.put(newKey, oldObj.body, {
                        httpMetadata: oldObj.httpMetadata,
                        customMetadata: oldObj.customMetadata
                    })
                    stats.copied++
                } else {
                    stats.skipped++
                }
            } catch (err: any) {
                stats.errors.push(`Failed to copy ${obj.key}: ${err.message}`)
            }
        }
        return c.json({ ok: true, stats })
    } catch (e: any) {
        return c.json({ error: e.message }, 500)
    }
})

// ==================== R2 Upload Proxy (Container เรียกกลับมา) ====================

app.put('/api/r2-upload/:key{.+}', async (c) => {
    // Auth: accept session cookie/header token (sess_*) or bot token
    const rawHeaderToken = String(c.req.header('x-auth-token') || '').trim()
    const authToken = getSessionTokenFromRequest(c)
    let authorized = false
    if (rawHeaderToken === c.env.TELEGRAM_BOT_TOKEN) {
        authorized = true
    } else if (authToken.startsWith('sess_')) {
        const user = await c.env.DB.prepare('SELECT email FROM users WHERE session_token = ?').bind(authToken).first().catch(() => null)
        if (user) authorized = true
    }
    // Dashboard passkey session bridge: the React dashboard uploads page avatars
    // through /worker-api with its pubilo_dashboard_session cookie (no raw `sess_`
    // token). Namespace is enforced against the resolved botId (x-bot-id), and the
    // bucket below is already scoped to that botId.
    if (!authorized && await dashboardSessionAuthorizes(c)) {
        authorized = true
    }
    // Setup-mode fallback (passkey bootstrap window) — namespace-scoped, D1-confirmed
    // 0-credential state; the x-dashboard-setup-mode header is never trusted alone.
    if (!authorized && await dashboardSetupModeAuthorizes(c)) {
        authorized = true
    }
    if (!authorized) {
        return c.json({ error: 'unauthorized' }, 401)
    }

    const key = c.req.param('key')
    const contentType = c.req.header('content-type') || 'application/octet-stream'
    const requestBody = c.req.raw.body
    const fallbackBody = requestBody ? null : await c.req.arrayBuffer()
    const contentLength = Number(c.req.header('content-length') || 0)

    await c.get('bucket').put(key, requestBody || fallbackBody || new ArrayBuffer(0), {
        httpMetadata: { contentType },
    })

    const processedVideoId = parseProcessedVideoR2Key(key)
    if (processedVideoId) {
        const scopedNamespaceId = String(c.get('botId') || '').trim()
        const fallbackNamespaceId = String(
            c.req.query('namespace_id')
            || c.req.header('x-namespace-id')
            || c.req.header('x-bot-id')
            || '',
        ).trim()
        const namespaceId = scopedNamespaceId && scopedNamespaceId !== 'default'
            ? scopedNamespaceId
            : fallbackNamespaceId || scopedNamespaceId
        if (namespaceId) {
            c.executionCtx.waitUntil(
                uploadProcessedVideoToMetaAssetLibrary({
                    env: c.env,
                    namespaceId,
                    videoId: processedVideoId,
                }).catch((error) => {
                    console.error(
                        `[PROCESSED-ASSET-LIBRARY] waitUntil failed namespace=${namespaceId} video=${processedVideoId} error=${sanitizeMetaGraphError(error)}`
                    )
                }),
            )
        }
    }

    return c.json({ ok: true, key, size: requestBody ? (Number.isFinite(contentLength) ? contentLength : null) : fallbackBody?.byteLength || 0 })
})

app.get('/api/r2-proxy/:key{.+}', async (c) => {
    const authToken = c.req.header('x-auth-token')
    if (authToken !== (c.req.param('token') || c.req.header('x-auth-token') || c.env.TELEGRAM_BOT_TOKEN)) return c.json({ error: 'unauthorized' }, 401)

    const key = c.req.param('key')
    const obj = await c.get('bucket').get(key)
    if (!obj) return c.json({ error: 'not found' }, 404)

    return new Response(obj.body, { headers: { 'Content-Type': obj.httpMetadata?.contentType || 'application/octet-stream' } })
})

app.get('/api/inbox-cover/:videoId/preview', async (c) => {
    const videoId = String(c.req.param('videoId') || '').trim()
    const namespaceId = String(c.req.query('namespace_id') || '').trim()
    if (!videoId) return c.json({ error: 'video_id_required' }, 400)
    if (!namespaceId) return c.json({ error: 'namespace_id_required' }, 400)

    const bucket = new BotBucket(c.env.BUCKET, namespaceId) as unknown as R2Bucket
    const jpgKey = `_inbox_cover/${videoId}_preview.jpg`
    const webpKey = `_inbox_cover/${videoId}.webp`

    const obj = await bucket.get(jpgKey).catch(() => null) || await bucket.get(webpKey).catch(() => null)
    if (!obj) return c.json({ error: 'not found' }, 404)

    const headers = new Headers()
    headers.set('Content-Type', obj.httpMetadata?.contentType || (String(obj.key || '').endsWith('.jpg') ? 'image/jpeg' : 'image/webp'))
    headers.set('Cache-Control', 'public, max-age=31536000, immutable')
    return new Response(obj.body, { headers })
})

app.delete('/api/r2-proxy/:key{.+}', async (c) => {
    const authToken = c.req.header('x-auth-token')
    if (authToken !== (c.req.param('token') || c.req.header('x-auth-token') || c.env.TELEGRAM_BOT_TOKEN)) return c.json({ error: 'unauthorized' }, 401)

    const key = c.req.param('key')
    await c.get('bucket').delete(key)
    return c.json({ ok: true, key })
})

// ==================== CATEGORIES HELPER ====================

const DEFAULT_CATEGORIES = ['เครื่องมือช่าง', 'อาหาร', 'เครื่องครัว', 'ของใช้ในบ้าน', 'เฟอร์นิเจอร์', 'บิวตี้', 'แฟชั่น', 'อิเล็กทรอนิกส์', 'สุขภาพ', 'กีฬา', 'สัตว์เลี้ยง', 'ยานยนต์', 'อื่นๆ']

async function getCategories(bucket: R2Bucket): Promise<string[]> {
    const obj = await bucket.get('_config/categories.json')
    if (obj) return await obj.json() as string[]
    return DEFAULT_CATEGORIES
}

function toThaiDateString(value: string | Date): string {
    const date = value instanceof Date ? value : new Date(value)
    if (Number.isNaN(date.getTime())) return ''
    const thai = new Date(date.getTime() + (7 * 60 * 60 * 1000))
    return thai.toISOString().split('T')[0]
}

function uniqueVideoIds(ids: string[]): string[] {
    const out: string[] = []
    const seen = new Set<string>()
    for (const raw of ids) {
        const id = String(raw || '').trim()
        if (!id || seen.has(id)) continue
        seen.add(id)
        out.push(id)
    }
    return out
}

function parseVideoCreatedAtMs(value: unknown): number {
    const ms = new Date(String(value || '')).getTime()
    return Number.isFinite(ms) ? ms : Number.POSITIVE_INFINITY
}

function dedupeVideosById(videos: any[]): any[] {
    const byId = new Map<string, any>()
    for (const video of videos || []) {
        const id = String(video?.id || '').trim()
        if (!id) continue
        const namespaceId = String(video?.namespace_id || '').trim()
        const key = namespaceId ? `${namespaceId}:${id}` : id
        const prev = byId.get(key)
        if (!prev) {
            byId.set(key, video)
            continue
        }
        const prevTs = new Date(String(prev?.updatedAt || prev?.createdAt || '')).getTime()
        const nextTs = new Date(String(video?.updatedAt || video?.createdAt || '')).getTime()
        if ((Number.isFinite(nextTs) ? nextTs : 0) >= (Number.isFinite(prevTs) ? prevTs : 0)) {
            byId.set(key, video)
        }
    }
    return Array.from(byId.values())
}

function getGalleryVideoSortMs(video: Record<string, unknown> | null | undefined): number {
    const ts = new Date(String(
        video?.processedAt
        || video?.processed_at
        || video?.postedAt
        || video?.posted_at
        || video?.updatedAt
        || video?.updated_at
        || video?.createdAt
        || video?.created_at
        || ''
    )).getTime()
    return Number.isFinite(ts) ? ts : 0
}

function pickOldestGalleryVideoForPosting(videos: Array<Record<string, unknown>>): Record<string, unknown> | null {
    let picked: Record<string, unknown> | null = null
    let pickedTs = Number.POSITIVE_INFINITY

    for (const video of videos || []) {
        const ts = getGalleryVideoSortMs(video)
        if (!picked) {
            picked = video
            pickedTs = ts
            continue
        }

        if (ts < pickedTs) {
            picked = video
            pickedTs = ts
            continue
        }

        if (ts === pickedTs) {
            const pickedId = String(picked.id || '').trim()
            const nextId = String(video.id || '').trim()
            if (nextId && (!pickedId || nextId.localeCompare(pickedId) < 0)) {
                picked = video
                pickedTs = ts
            }
        }
    }

    return picked
}

function pickNewestGalleryVideoForPosting(videos: Array<Record<string, unknown>>): Record<string, unknown> | null {
    let picked: Record<string, unknown> | null = null
    let pickedTs = Number.NEGATIVE_INFINITY

    for (const video of videos || []) {
        const ts = getGalleryVideoSortMs(video)
        if (!picked) {
            picked = video
            pickedTs = ts
            continue
        }

        if (ts > pickedTs) {
            picked = video
            pickedTs = ts
            continue
        }

        if (ts === pickedTs) {
            const pickedId = String(picked.id || '').trim()
            const nextId = String(video.id || '').trim()
            if (nextId && (!pickedId || nextId.localeCompare(pickedId) > 0)) {
                picked = video
                pickedTs = ts
            }
        }
    }

    return picked
}

function pickRandomGalleryVideoForPostingOrder(videos: Array<Record<string, unknown>>): Record<string, unknown> | null {
    if (!Array.isArray(videos) || videos.length === 0) return null
    const index = Math.floor(Math.random() * videos.length)
    return videos[index] || null
}

const POSTING_ORDER_VALUES = ['oldest_first', 'newest_first', 'random'] as const
type NamespacePostingOrder = typeof POSTING_ORDER_VALUES[number]
type PostingOrderSource = 'global' | 'page'

function isNamespacePostingOrder(value: string): value is NamespacePostingOrder {
    return POSTING_ORDER_VALUES.includes(value as NamespacePostingOrder)
}

function pickGalleryVideoForPostingByOrder(
    videos: Array<Record<string, unknown>>,
    postingOrder: NamespacePostingOrder,
): Record<string, unknown> | null {
    switch (postingOrder) {
        case 'newest_first':
            return pickNewestGalleryVideoForPosting(videos)
        case 'random':
            return pickRandomGalleryVideoForPostingOrder(videos)
        case 'oldest_first':
        default:
            return pickOldestGalleryVideoForPosting(videos)
    }
}

function orderGalleryVideosForPosting(
    videos: Array<Record<string, unknown>>,
    postingOrder: NamespacePostingOrder,
): Array<Record<string, unknown>> {
    const ordered = [...(videos || [])].filter((video) => !!String(video?.id || '').trim())
    if (postingOrder === 'random') {
        for (let index = ordered.length - 1; index > 0; index -= 1) {
            const swapIndex = Math.floor(Math.random() * (index + 1))
            const current = ordered[index]
            ordered[index] = ordered[swapIndex]
            ordered[swapIndex] = current
        }
        return ordered
    }

    ordered.sort((current, next) => {
        const currentTs = getGalleryVideoSortMs(current)
        const nextTs = getGalleryVideoSortMs(next)
        if (currentTs !== nextTs) {
            return postingOrder === 'newest_first'
                ? nextTs - currentTs
                : currentTs - nextTs
        }
        const currentId = String(current?.id || '').trim()
        const nextId = String(next?.id || '').trim()
        return postingOrder === 'newest_first'
            ? nextId.localeCompare(currentId)
            : currentId.localeCompare(nextId)
    })
    return ordered
}

async function getLatestSuccessfulPostHistoryRow(db: D1Database, params: {
    namespaceId: string
    pageId: string
    videoId: string
    sourceFingerprint?: string
}): Promise<{ id: number | null; fbPostId: string | null; postedAt: string | null } | null> {
    const namespaceId = String(params.namespaceId || '').trim()
    const pageId = String(params.pageId || '').trim()
    const videoId = String(params.videoId || '').trim()
    const sourceFingerprint = normalizeNamespaceVideoSourceFingerprint(params.sourceFingerprint)
    if (!namespaceId || !pageId || (!videoId && !sourceFingerprint)) return null

    const row = await db.prepare(
        `SELECT ph.id, ph.fb_post_id, ph.posted_at
         FROM post_history ph
         LEFT JOIN namespace_video_state nvs
           ON nvs.namespace_id = ph.bot_id
          AND nvs.video_id = ph.video_id
         WHERE ph.bot_id = ?
           AND ph.page_id = ?
           AND ph.status = 'success'
           AND (
               (? <> '' AND ph.video_id = ?)
               OR (? <> '' AND COALESCE(NULLIF(TRIM(ph.source_fingerprint), ''), nvs.source_fingerprint) = ?)
           )
         ORDER BY datetime(ph.posted_at) DESC, ph.id DESC
         LIMIT 1`
    ).bind(namespaceId, pageId, videoId, videoId, sourceFingerprint, sourceFingerprint).first() as {
        id?: number
        fb_post_id?: string | null
        posted_at?: string | null
    } | null

    if (!row) return null
    return {
        id: typeof row.id === 'number' ? row.id : null,
        fbPostId: String(row.fb_post_id || '').trim() || null,
        postedAt: String(row.posted_at || '').trim() || null,
    }
}

async function ensurePagePostedVideoGuardsTable(db: D1Database): Promise<void> {
    await db.prepare(
        `CREATE TABLE IF NOT EXISTS page_posted_video_guards (
            guard_key TEXT PRIMARY KEY,
            bot_id TEXT NOT NULL,
            page_id TEXT NOT NULL,
            video_id TEXT NOT NULL DEFAULT '',
            source_fingerprint TEXT NOT NULL DEFAULT '',
            history_id INTEGER,
            created_at TEXT NOT NULL DEFAULT (datetime('now')),
            updated_at TEXT NOT NULL DEFAULT (datetime('now'))
        )`
    ).run()
    await db.prepare(
        'CREATE INDEX IF NOT EXISTS idx_page_posted_video_guards_page ON page_posted_video_guards(bot_id, page_id)'
    ).run()
}

async function ensurePagePostedVideoGuardsBackfilled(db: D1Database): Promise<void> {
    await ensurePostHistoryTraceColumns(db)
    await ensurePagePostedVideoGuardsTable(db)
    await db.prepare(
        `INSERT OR IGNORE INTO page_posted_video_guards (
            guard_key,
            bot_id,
            page_id,
            video_id,
            source_fingerprint,
            history_id,
            created_at,
            updated_at
        )
        SELECT
            'video::' || ph.bot_id || '::' || ph.page_id || '::' || ph.video_id,
            ph.bot_id,
            ph.page_id,
            ph.video_id,
            COALESCE(NULLIF(TRIM(ph.source_fingerprint), ''), ''),
            ph.id,
            ph.posted_at,
            ph.posted_at
        FROM post_history ph
        WHERE ph.status = 'success'
          AND TRIM(COALESCE(ph.video_id, '')) <> ''`
    ).run().catch(() => { })
    await db.prepare(
        `INSERT OR IGNORE INTO page_posted_video_guards (
            guard_key,
            bot_id,
            page_id,
            video_id,
            source_fingerprint,
            history_id,
            created_at,
            updated_at
        )
        SELECT
            'fingerprint::' || ph.bot_id || '::' || ph.page_id || '::' || COALESCE(NULLIF(TRIM(ph.source_fingerprint), ''), TRIM(nvs.source_fingerprint)),
            ph.bot_id,
            ph.page_id,
            ph.video_id,
            COALESCE(NULLIF(TRIM(ph.source_fingerprint), ''), TRIM(nvs.source_fingerprint)),
            ph.id,
            ph.posted_at,
            ph.posted_at
        FROM post_history ph
        LEFT JOIN namespace_video_state nvs
          ON nvs.namespace_id = ph.bot_id
         AND nvs.video_id = ph.video_id
        WHERE ph.status = 'success'
          AND TRIM(COALESCE(NULLIF(TRIM(ph.source_fingerprint), ''), nvs.source_fingerprint, '')) <> ''`
    ).run().catch(() => { })
}

function buildPagePostedVideoGuardKeys(params: {
    namespaceId: string
    pageId: string
    videoId: string
    sourceFingerprint?: string
}): string[] {
    const namespaceId = String(params.namespaceId || '').trim()
    const pageId = String(params.pageId || '').trim()
    const videoId = String(params.videoId || '').trim()
    const sourceFingerprint = normalizeNamespaceVideoSourceFingerprint(params.sourceFingerprint)
    if (!namespaceId || !pageId) return []

    const keys: string[] = []
    if (videoId) keys.push(`video::${namespaceId}::${pageId}::${videoId}`)
    if (sourceFingerprint) keys.push(`fingerprint::${namespaceId}::${pageId}::${sourceFingerprint}`)
    return keys
}

async function getExistingPagePostedVideoGuard(db: D1Database, params: {
    namespaceId: string
    pageId: string
    videoId: string
    sourceFingerprint?: string
}): Promise<{ historyId: number | null; createdAt: string | null } | null> {
    const keys = buildPagePostedVideoGuardKeys(params)
    if (keys.length === 0) return null
    await ensurePagePostedVideoGuardsBackfilled(db)
    const placeholders = keys.map(() => '?').join(', ')
    const row = await db.prepare(
        `SELECT p.history_id, p.created_at
         FROM page_posted_video_guards p
         WHERE p.guard_key IN (${placeholders})
         ORDER BY datetime(p.updated_at) DESC, p.history_id DESC
         LIMIT 1`
    ).bind(...keys).first() as { history_id?: number | null; created_at?: string | null } | null
    if (!row) return null
    return {
        historyId: typeof row.history_id === 'number' ? row.history_id : null,
        createdAt: String(row.created_at || '').trim() || null,
    }
}

async function recordPagePostedVideoGuard(db: D1Database, params: {
    namespaceId: string
    pageId: string
    videoId: string
    sourceFingerprint?: string
    historyId?: number | null
    postedAt?: string | null
}): Promise<void> {
    const keys = buildPagePostedVideoGuardKeys(params)
    if (keys.length === 0) return
    await ensurePagePostedVideoGuardsBackfilled(db)
    const namespaceId = String(params.namespaceId || '').trim()
    const pageId = String(params.pageId || '').trim()
    const videoId = String(params.videoId || '').trim()
    const sourceFingerprint = normalizeNamespaceVideoSourceFingerprint(params.sourceFingerprint)
    const historyId = typeof params.historyId === 'number' ? params.historyId : null
    const postedAt = String(params.postedAt || '').trim() || new Date().toISOString()

    for (const guardKey of keys) {
        await db.prepare(
            `INSERT INTO page_posted_video_guards (
                guard_key,
                bot_id,
                page_id,
                video_id,
                source_fingerprint,
                history_id,
                created_at,
                updated_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?)
            ON CONFLICT(guard_key) DO UPDATE SET
                history_id = COALESCE(excluded.history_id, page_posted_video_guards.history_id),
                updated_at = excluded.updated_at`
        ).bind(
            guardKey,
            namespaceId,
            pageId,
            videoId,
            sourceFingerprint,
            historyId,
            postedAt,
            postedAt,
        ).run().catch(() => { })
    }
}

async function claimGalleryVideoForPosting(params: {
    db: D1Database
    namespaceId: string
    pageId: string
    videos: Array<Record<string, unknown>>
    postingOrder: NamespacePostingOrder
}): Promise<{ video: Record<string, unknown>; videoLockKey: string } | null> {
    const namespaceId = String(params.namespaceId || '').trim()
    const pageId = String(params.pageId || '').trim()
    if (!namespaceId || !pageId) return null

    const orderedVideos = orderGalleryVideosForPosting(params.videos, params.postingOrder)
    for (const video of orderedVideos) {
        const videoId = String(video?.id || '').trim()
        if (!videoId) continue

        const sourceFingerprint = normalizeNamespaceVideoSourceFingerprint(
            video?.sourceFingerprint || video?.source_fingerprint,
        )

        // 2026-06-21 (multi-page starvation fix): final eligibility is PER PAGE,
        // not namespace-wide. The fast selector intentionally avoids page-aware
        // subqueries because they were expensive enough to trip D1 CPU limits in
        // production; it only separates namespace-unposted primary rows from the
        // namespace-posted fallback. This guard remains the authoritative same-page
        // block (page-scoped post_history + page_posted_video_guards, honouring
        // manual_unposted_at). A video posted by a SIBLING page therefore stays
        // claimable here during the explicit fallback pass.
        //
        // So we deliberately do NOT re-apply the namespace-wide posted_at guards
        // (isNamespaceGalleryVideoPosted / getFreshNamespacePostedState) that used
        // to live here — namespace_video_state.posted_at is set the moment ANY page
        // posts a video, so re-checking it would re-starve every sibling page. The
        // authoritative per-page block below (ensurePageVideoNeverPosted: page-scoped
        // post_history + page guards, both respecting manual_unposted_at) plus the
        // video-scoped posting lock are the only gates the claim path needs. We also
        // never seed a page guard for this page off a sibling's row.
        const duplicateCheck = await ensurePageVideoNeverPosted({
            db: params.db,
            namespaceId,
            pageId,
            videoId,
            sourceFingerprint,
        })
        if (duplicateCheck.ok === false) {
            continue
        }

        const videoLockKey = await tryAcquirePostingLock(params.db, {
            scope: 'video',
            namespaceId,
            videoId,
        })
        if (!videoLockKey) continue

        return { video, videoLockKey }
    }

    return null
}

async function ensurePageVideoNeverPosted(params: {
    db: D1Database
    namespaceId: string
    pageId: string
    videoId: string
    sourceFingerprint?: string
}): Promise<{ ok: true } | { ok: false; postedAt: string | null; historyId: number | null }> {
    // Read the user's manual-unpost timestamp. If the user clicked the amber refresh
    // button on this video AFTER the last successful post / guard creation, treat it
    // as a fresh post candidate and DO NOT block. Without this check, cron would see
    // the historical post_history row and re-mark the video as posted, undoing the
    // user's intent silently.
    let manualUnpostedAtMs = 0
    try {
        const row = await params.db.prepare(
            `SELECT manual_unposted_at FROM namespace_video_state
             WHERE namespace_id = ? AND video_id = ?`
        ).bind(params.namespaceId, params.videoId).first() as { manual_unposted_at?: string | null } | null
        const raw = String(row?.manual_unposted_at || '').trim()
        if (raw) {
            const ts = Date.parse(raw)
            if (Number.isFinite(ts)) manualUnpostedAtMs = ts
        }
    } catch {
        // best-effort: fall through to default behavior
    }

    const latestHistory = await getLatestSuccessfulPostHistoryRow(params.db, params)
    if (latestHistory) {
        const postedAtMs = latestHistory.postedAt ? Date.parse(latestHistory.postedAt) : NaN
        const historyIsStale = manualUnpostedAtMs > 0
            && Number.isFinite(postedAtMs)
            && postedAtMs <= manualUnpostedAtMs
        if (!historyIsStale) {
            // 2026-05-04 (v3): NO heal of state.posted_at. Just seed the page
            // guard for fast next-tick skip + return ok:false to block repost.
            // Was: markNamespaceVideoPosted(...) which surfaced stale timestamps.
            await recordPagePostedVideoGuard(params.db, {
                namespaceId: params.namespaceId,
                pageId: params.pageId,
                videoId: params.videoId,
                sourceFingerprint: params.sourceFingerprint,
                historyId: latestHistory.id,
                postedAt: latestHistory.postedAt,
            }).catch(() => { })
            return {
                ok: false,
                postedAt: latestHistory.postedAt,
                historyId: latestHistory.id,
            }
        }
    }

    const existingGuard = await getExistingPagePostedVideoGuard(params.db, params)
    if (!existingGuard) return { ok: true }

    const guardCreatedAtMs = existingGuard.createdAt ? Date.parse(existingGuard.createdAt) : NaN
    const guardIsStale = manualUnpostedAtMs > 0
        && Number.isFinite(guardCreatedAtMs)
        && guardCreatedAtMs <= manualUnpostedAtMs
    if (guardIsStale) return { ok: true }

    const postedAt = existingGuard.createdAt || null
    // 2026-05-04 (v3): No heal. Page guard already exists; ok:false blocks repost.
    return {
        ok: false,
        postedAt,
        historyId: existingGuard.historyId ?? null,
    }
}

function hasGalleryVideoThumbnail(video: Record<string, unknown> | null | undefined): boolean {
    return !!String(
        video?.thumbnailUrl
        || video?.thumbnail_url
        || ''
    ).trim()
}

function pickPreferredSystemGalleryVideo(current: Record<string, unknown>, next: Record<string, unknown>): Record<string, unknown> {
    const getCommerceRank = (video: Record<string, unknown>) => {
        if (normalizeMetaLazadaLink(video)) return 2
        if (normalizeMetaShopeeLink(video)) return 1
        return 0
    }
    const currentLinkRank = getCommerceRank(current)
    const nextLinkRank = getCommerceRank(next)
    if (currentLinkRank !== nextLinkRank) {
        return nextLinkRank > currentLinkRank ? next : current
    }

    const currentHasThumbnail = hasGalleryVideoThumbnail(current)
    const nextHasThumbnail = hasGalleryVideoThumbnail(next)
    if (currentHasThumbnail !== nextHasThumbnail) {
        return nextHasThumbnail ? next : current
    }

    const currentTs = getGalleryVideoSortMs(current)
    const nextTs = getGalleryVideoSortMs(next)
    if (currentTs !== nextTs) {
        return nextTs >= currentTs ? next : current
    }

    const currentNamespaceId = String(current.namespace_id || '').trim()
    const nextNamespaceId = String(next.namespace_id || '').trim()
    return nextNamespaceId.localeCompare(currentNamespaceId) <= 0 ? next : current
}

function normalizeVideoDuplicateValue(value: unknown): string {
    return String(value || '').trim().replace(/#.*$/, '')
}

function getNamespaceVideoDuplicateKey(video: Record<string, unknown>): string {
    const namespaceId = String(video.namespace_id || video.namespaceId || '').trim()
    const originalUrl = normalizeVideoDuplicateValue(video.originalUrl || video.original_url)
    if (namespaceId && originalUrl) return `${namespaceId}::original::${originalUrl}`

    const sourceType = String(video.sourceType || video.source_type || '').trim().toLowerCase()
    const sourceLabel = normalizeVideoDuplicateValue(video.sourceLabel || video.source_label)
    const videoUrl = normalizeVideoDuplicateValue(video.videoUrl || video.video_url)
    const previewUrl = normalizeVideoDuplicateValue(video.previewUrl || video.preview_url)

    if (namespaceId && sourceType === 'xhs_url' && sourceLabel) return `${namespaceId}::xhs::${sourceLabel}`
    if (namespaceId && videoUrl) return `${namespaceId}::video::${videoUrl}`
    if (namespaceId && previewUrl) return `${namespaceId}::preview::${previewUrl}`
    return ''
}

function dedupeSystemGalleryVideos(videos: any[]): any[] {
    const byVideoId = new Map<string, Record<string, unknown>>()
    for (const rawVideo of videos || []) {
        const video = rawVideo as Record<string, unknown>
        const id = String(video?.id || '').trim()
        if (!id) continue
        const prev = byVideoId.get(id)
        if (!prev) {
            byVideoId.set(id, video)
            continue
        }
        byVideoId.set(id, pickPreferredSystemGalleryVideo(prev, video))
    }

    const bySourceKey = new Map<string, Record<string, unknown>>()
    for (const video of byVideoId.values()) {
        const sourceKey = getNamespaceVideoDuplicateKey(video)
        if (!sourceKey) {
            bySourceKey.set(`id::${String(video.id || '').trim()}`, video)
            continue
        }
        const previous = bySourceKey.get(sourceKey)
        if (!previous) {
            bySourceKey.set(sourceKey, video)
            continue
        }
        bySourceKey.set(sourceKey, pickPreferredSystemGalleryVideo(previous, video))
    }

    return Array.from(bySourceKey.values()).sort((a, b) => getGalleryVideoSortMs(b) - getGalleryVideoSortMs(a))
}

function getNamespaceInventoryGroupKey(video: Record<string, unknown>): string {
    const namespaceId = String(video.namespace_id || video.namespaceId || '').trim()
    const videoId = String(video.id || '').trim()
    const fingerprint = normalizeNamespaceVideoSourceFingerprint(
        video.sourceFingerprint || video.source_fingerprint
    )
    if (namespaceId && fingerprint) return `${namespaceId}::fingerprint::${fingerprint}`
    if (namespaceId && videoId) return `${namespaceId}::id::${videoId}`
    return videoId
}

function getPostedAtMs(video: Record<string, unknown>): number {
    const ts = new Date(String(video.postedAt || video.posted_at || '')).getTime()
    return Number.isFinite(ts) ? ts : 0
}

function pickPreferredNamespaceInventoryVideo(current: Record<string, unknown>, next: Record<string, unknown>): Record<string, unknown> {
    const currentPosted = isNamespaceGalleryVideoPosted(current)
    const nextPosted = isNamespaceGalleryVideoPosted(next)
    if (currentPosted !== nextPosted) {
        return currentPosted ? current : next
    }

    if (currentPosted && nextPosted) {
        const currentPostedAtMs = getPostedAtMs(current)
        const nextPostedAtMs = getPostedAtMs(next)
        if (currentPostedAtMs !== nextPostedAtMs) {
            return nextPostedAtMs >= currentPostedAtMs ? next : current
        }
    }

    const currentHasThumbnail = hasGalleryVideoThumbnail(current)
    const nextHasThumbnail = hasGalleryVideoThumbnail(next)
    if (currentHasThumbnail !== nextHasThumbnail) {
        return nextHasThumbnail ? next : current
    }

    const currentTs = getGalleryVideoSortMs(current)
    const nextTs = getGalleryVideoSortMs(next)
    if (currentTs !== nextTs) {
        return nextTs >= currentTs ? next : current
    }

    const currentId = String(current.id || '').trim()
    const nextId = String(next.id || '').trim()
    return nextId.localeCompare(currentId) >= 0 ? next : current
}

function dedupeNamespaceInventoryVideos(videos: Array<Record<string, unknown>>): Array<Record<string, unknown>> {
    const grouped = new Map<string, Record<string, unknown>>()
    for (const video of videos || []) {
        const key = getNamespaceInventoryGroupKey(video)
        if (!key) continue
        const previous = grouped.get(key)
        if (!previous) {
            grouped.set(key, video)
            continue
        }
        grouped.set(key, pickPreferredNamespaceInventoryVideo(previous, video))
    }
    return Array.from(grouped.values()).sort((a, b) => getGalleryVideoSortMs(b) - getGalleryVideoSortMs(a))
}

function shuffleInPlace<T>(items: T[]): T[] {
    for (let i = items.length - 1; i > 0; i -= 1) {
        const j = Math.floor(Math.random() * (i + 1))
        const tmp = items[i]
        items[i] = items[j]
        items[j] = tmp
    }
    return items
}

async function listAllVideoJsonIds(bucket: R2Bucket): Promise<string[]> {
    const objects = await listAllVideoObjects(bucket)
    const ids: string[] = []
    for (const obj of objects) {
        if (!obj.key.endsWith('.json')) continue
        ids.push(obj.key.replace('videos/', '').replace('.json', ''))
    }
    return uniqueVideoIds(ids)
}

async function listAllVideoObjects(bucket: R2Bucket): Promise<R2Object[]> {
    const objects: R2Object[] = []
    let cursor: string | undefined
    do {
        const page = await bucket.list(cursor ? { prefix: 'videos/', cursor } : { prefix: 'videos/' })
        objects.push(...page.objects)
        cursor = page.truncated && page.cursor ? page.cursor : undefined
    } while (cursor)
    return objects
}

async function orderVideoIdsNewestFirst(bucket: R2Bucket, candidateIds: string[]): Promise<string[]> {
    const normalizedIds = uniqueVideoIds(candidateIds)
    if (normalizedIds.length <= 1) return normalizedIds

    try {
        const cacheObj = await bucket.get('_cache/gallery.json')
        if (!cacheObj) return normalizedIds

        const payload = await cacheObj.json() as { videos?: Array<{ id?: unknown; createdAt?: unknown }> }
        const cacheVideos = Array.isArray(payload?.videos) ? payload.videos : []
        const idSet = new Set(normalizedIds)
        const orderedFromCache: Array<{ id: string; createdAtMs: number; index: number }> = []

        for (let i = 0; i < cacheVideos.length; i += 1) {
            const row = cacheVideos[i]
            const id = String(row?.id || '').trim()
            if (!id || !idSet.has(id)) continue
            orderedFromCache.push({
                id,
                createdAtMs: parseVideoCreatedAtMs(row?.createdAt),
                index: i,
            })
        }

        orderedFromCache.sort((a, b) => {
            if (a.createdAtMs !== b.createdAtMs) return b.createdAtMs - a.createdAtMs
            return a.index - b.index
        })

        const seen = new Set<string>()
        const orderedIds: string[] = []
        for (const row of orderedFromCache) {
            if (seen.has(row.id)) continue
            seen.add(row.id)
            orderedIds.push(row.id)
        }
        for (const id of normalizedIds) {
            if (!seen.has(id)) orderedIds.push(id)
        }
        return orderedIds
    } catch (e) {
        console.log(`[VIDEO ORDER] failed to read gallery cache for newest-first: ${e instanceof Error ? e.message : String(e)}`)
        return normalizedIds
    }
}

function hasShopeeLinkInMeta(meta: Record<string, unknown>): boolean {
    return isUsableShopeeLink(normalizeMetaShopeeLink(meta) || '')
}

function hasLazadaLinkInMeta(meta: Record<string, unknown>): boolean {
    return !!normalizeMetaLazadaLink(meta)
}

function hasAffiliateLinkInMeta(meta: Record<string, unknown>): boolean {
    return hasShopeeLinkInMeta(meta) || hasLazadaLinkInMeta(meta)
}

function normalizeGallerySearchQuery(value: string | null | undefined): string {
    return String(value || '').trim().toLowerCase().replace(/\s+/g, ' ')
}

function normalizeGalleryVideoIdSearchToken(value: string | null | undefined): string {
    return String(value || '').trim().toLowerCase().replace(/\s+/g, '').replace(/o/g, '0')
}

function matchesGallerySearchQuery(video: Record<string, unknown>, query: string): boolean {
    const needle = normalizeGallerySearchQuery(query)
    if (!needle) return true
    const idNeedle = normalizeGalleryVideoIdSearchToken(query)

    const haystacks = [
        video.id,
        video.video_id,
        video.title,
        video.script,
        video.category,
        video.owner_email,
        video.namespace_id,
    ]

    if (haystacks.some((value) => normalizeGallerySearchQuery(String(value || '')).includes(needle))) {
        return true
    }

    if (!idNeedle) return false

    const idHaystacks = [video.id, video.video_id]
    return idHaystacks.some((value) => normalizeGalleryVideoIdSearchToken(String(value || '')).includes(idNeedle))
}

function parseNonNegativeInt(value: string | null | undefined, fallback: number): number {
    const parsed = Number.parseInt(String(value || '').trim(), 10)
    if (!Number.isFinite(parsed) || parsed < 0) return fallback
    return parsed
}

function sliceGalleryPage<T>(videos: T[], offset: number, limit: number): { videos: T[]; hasMore: boolean } {
    const safeOffset = Math.max(0, offset)
    const safeLimit = Math.max(1, limit)
    const pageVideos = videos.slice(safeOffset, safeOffset + safeLimit)
    return {
        videos: pageVideos,
        hasMore: safeOffset + pageVideos.length < videos.length,
    }
}

async function pickPostableVideoNewestFirst(
    bucket: R2Bucket,
    candidateIds: string[],
): Promise<{ id: string; meta: Record<string, unknown>; shopeeLink: string; sourceNamespaceId?: string } | null> {
    const orderedIds = await orderVideoIdsNewestFirst(bucket, candidateIds)
    if (orderedIds.length === 0) return null

    const cacheHasLink = new Map<string, boolean>()
    const cacheShopeeLink = new Map<string, string>()
    try {
        const cacheObj = await bucket.get('_cache/gallery.json')
        if (cacheObj) {
            const payload = await cacheObj.json() as { videos?: Array<Record<string, unknown>> }
            const rows = Array.isArray(payload?.videos) ? payload.videos : []
            for (const row of rows) {
                const id = String(row?.id || '').trim()
                if (!id) continue
                const shopeeFromCache = normalizeMetaShopeeLink(row) || ''
                cacheHasLink.set(id, !!shopeeFromCache)
                if (shopeeFromCache) {
                    cacheShopeeLink.set(id, shopeeFromCache)
                }
            }
        }
    } catch (e) {
        console.log(`[VIDEO PICK] failed to read gallery cache: ${e instanceof Error ? e.message : String(e)}`)
    }

    const strictCandidates: string[] = []
    const unknownCandidates: string[] = []
    for (const id of orderedIds) {
        if (cacheHasLink.has(id)) {
            if (cacheHasLink.get(id)) strictCandidates.push(id)
            continue
        }
        unknownCandidates.push(id)
    }

    const scanOrder = [...strictCandidates, ...unknownCandidates]
    for (const id of scanOrder) {
        const metaObj = await bucket.get(`videos/${id}.json`)
        if (!metaObj) continue
        const meta = await metaObj.json() as Record<string, unknown>
        const shopeeLink = normalizeMetaShopeeLink(meta) || cacheShopeeLink.get(id) || ''
        if (!shopeeLink) continue
        return { id, meta, shopeeLink }
    }

    return null
}

async function pickRandomPostableVideoFromNamespaceGallery(
    bucket: R2Bucket,
    candidateIds: string[],
    namespaceId: string,
): Promise<{ id: string; meta: Record<string, unknown>; shopeeLink: string; sourceNamespaceId: string } | null> {
    const normalizedNamespaceId = String(namespaceId || '').trim() || 'default'
    const allowedIds = new Set(uniqueVideoIds(candidateIds))
    if (allowedIds.size === 0) return null

    try {
        const cacheObj = await bucket.get('_cache/gallery.json')
        if (cacheObj) {
            const payload = await cacheObj.json() as { videos?: Array<Record<string, unknown>> }
            const rows = dedupeVideosById(Array.isArray(payload?.videos) ? payload.videos : [])
            const shuffled = shuffleInPlace(rows.filter((row) => {
                const id = String(row?.id || '').trim()
                return !!id && allowedIds.has(id) && !!normalizeMetaShopeeLink(row)
            }))
            for (const row of shuffled) {
                const id = String(row?.id || '').trim()
                const shopeeLink = normalizeMetaShopeeLink(row)
                if (!id || !shopeeLink) continue
                return {
                    id,
                    meta: row,
                    shopeeLink,
                    sourceNamespaceId: normalizedNamespaceId,
                }
            }
        }
    } catch (e) {
        console.log(`[VIDEO PICK] failed to read gallery cache for random pick: ${e instanceof Error ? e.message : String(e)}`)
    }

    const shuffledIds = shuffleInPlace([...allowedIds])
    for (const id of shuffledIds) {
        const metaObj = await bucket.get(`videos/${id}.json`)
        if (!metaObj) continue
        const meta = await metaObj.json() as Record<string, unknown>
        const shopeeLink = normalizeMetaShopeeLink(meta) || ''
        if (!shopeeLink) continue
        return {
            id,
            meta,
            shopeeLink,
            sourceNamespaceId: normalizedNamespaceId,
        }
    }

    return null
}

async function pickRandomGalleryVideoForPosting(params: {
    env: Env
    namespaceId: string
    bucket: R2Bucket
    candidateIds: string[]
    excludedVideoIds: Set<string>
}): Promise<{ id: string; meta: Record<string, unknown>; shopeeLink: string; sourceNamespaceId: string } | null> {
    const namespaceId = String(params.namespaceId || '').trim() || 'default'
    const candidateIds = uniqueVideoIds(params.candidateIds).filter((id) => !params.excludedVideoIds.has(id))
    if (candidateIds.length === 0) return null
    const allowedIds = new Set(candidateIds)

    const shortlinkEnabled = await isSystemGalleryEnabledForNamespace(params.env.DB, namespaceId)
    if (!shortlinkEnabled) {
        return null
    }

    const galleryVideos = await listNamespaceGalleryVideos(params.env, namespaceId)
    const candidates = galleryVideos.filter((video) => {
        const id = String(video?.id || '').trim()
        return !!id && allowedIds.has(id) && !params.excludedVideoIds.has(id)
    })
    if (candidates.length > 0) {
        shuffleInPlace(candidates)
        const picked = candidates[0] as Record<string, unknown>
        return {
            id: String(picked.id || '').trim(),
            meta: picked,
            shopeeLink: normalizeMetaShopeeLink(picked) || '',
            sourceNamespaceId: String((picked as any).sourceNamespaceId || (picked as any).source_namespace_id || namespaceId).trim() || namespaceId,
        }
    }

    return null
}

async function resolveGalleryVideoForRepost(params: {
    env: Env
    fallbackNamespaceId: string
    videoId: string
}): Promise<{ id: string; meta: Record<string, unknown>; shopeeLink: string; sourceNamespaceId: string } | null> {
    const videoId = String(params.videoId || '').trim()
    const fallbackNamespaceId = String(params.fallbackNamespaceId || '').trim() || 'default'
    if (!videoId) return null

    const shortlinkEnabled = await isSystemGalleryEnabledForNamespace(params.env.DB, fallbackNamespaceId)
    if (!shortlinkEnabled) {
        return null
    }

    const namespaceGalleryVideos = await listNamespaceGalleryVideos(params.env, fallbackNamespaceId)
    const namespaceHit = namespaceGalleryVideos.find((video) => String(video.id || '').trim() === videoId)
    if (namespaceHit) {
        return {
            id: videoId,
            meta: namespaceHit,
            shopeeLink: normalizeMetaShopeeLink(namespaceHit as Record<string, unknown>) || '',
            sourceNamespaceId: fallbackNamespaceId,
        }
    }

    await ensureGalleryIndexTable(params.env.DB)
    const galleryRow = await params.env.DB.prepare(
        `SELECT
            namespace_id,
            owner_email,
            script,
            title,
            category,
            duration,
            shopee_link,
            public_url,
            original_url,
            thumbnail_url,
            created_at,
            updated_at
         FROM gallery_index
         WHERE video_id = ?
         ORDER BY CASE WHEN namespace_id = ? THEN 0 ELSE 1 END,
                  COALESCE(updated_at, created_at) DESC,
                  namespace_id ASC
         LIMIT 1`
    ).bind(videoId, fallbackNamespaceId).first() as {
        namespace_id?: string
        owner_email?: string
        script?: string
        title?: string
        category?: string
        duration?: number
        shopee_link?: string
        public_url?: string
        original_url?: string
        thumbnail_url?: string
        created_at?: string
        updated_at?: string
    } | null

    const namespaceCandidates = uniqueVideoIds([
        String(galleryRow?.namespace_id || '').trim(),
        fallbackNamespaceId,
    ])

    for (const namespaceId of namespaceCandidates) {
        if (!namespaceId) continue
        const bucket = namespaceId === fallbackNamespaceId
            ? new BotBucket(params.env.BUCKET, fallbackNamespaceId) as unknown as R2Bucket
            : new BotBucket(params.env.BUCKET, namespaceId) as unknown as R2Bucket

        const metaObj = await bucket.get(`videos/${videoId}.json`)
        if (!metaObj && namespaceId !== String(galleryRow?.namespace_id || '').trim()) {
            continue
        }

        let meta: Record<string, unknown> = {
            id: videoId,
            namespace_id: namespaceId,
            owner_email: String(galleryRow?.owner_email || '').trim(),
            script: String(galleryRow?.script || '').trim(),
            title: String(galleryRow?.title || '').trim(),
            category: String(galleryRow?.category || '').trim(),
            duration: Number(galleryRow?.duration || 0),
            shopeeLink: String(galleryRow?.shopee_link || '').trim(),
            publicUrl: String(galleryRow?.public_url || '').trim(),
            originalUrl: String(galleryRow?.original_url || '').trim(),
            thumbnailUrl: String(galleryRow?.thumbnail_url || '').trim(),
            createdAt: String(galleryRow?.created_at || '').trim(),
            updatedAt: String(galleryRow?.updated_at || '').trim(),
        }
        if (metaObj) {
            try {
                meta = {
                    ...meta,
                    ...(await metaObj.json() as Record<string, unknown>),
                }
            } catch {
                // Keep index-derived metadata as fallback.
            }
        }

        const shopeeLink = normalizeMetaShopeeLink(meta) || String(galleryRow?.shopee_link || '').trim()
        return {
            id: videoId,
            meta,
            shopeeLink,
            sourceNamespaceId: namespaceId,
        }
    }

    return null
}

function getVideoPublicUrlForNamespace(r2BaseUrl: string, namespaceId: string, videoId: string): string {
    return String(namespaceId || '').trim() === 'default'
        ? `${r2BaseUrl}/videos/${videoId}.mp4`
        : `${r2BaseUrl}/${namespaceId}/videos/${videoId}.mp4`
}

function getVideoThumbnailUrlForNamespace(r2BaseUrl: string, namespaceId: string, videoId: string): string {
    return String(namespaceId || '').trim() === 'default'
        ? `${r2BaseUrl}/videos/${videoId}_thumb.webp`
        : `${r2BaseUrl}/${namespaceId}/videos/${videoId}_thumb.webp`
}

function getVideoOriginalThumbnailUrlForNamespace(r2BaseUrl: string, namespaceId: string, videoId: string): string {
    return String(namespaceId || '').trim() === 'default'
        ? `${r2BaseUrl}/videos/${videoId}_original_thumb.webp`
        : `${r2BaseUrl}/${namespaceId}/videos/${videoId}_original_thumb.webp`
}

type GalleryAssetVariant = 'public' | 'original' | 'thumb' | 'original-thumb'

function buildNamespaceObjectUrl(r2BaseUrl: string, namespaceId: string, objectKey: string): string {
    const base = String(r2BaseUrl || '').trim().replace(/\/+$/, '')
    const normalizedKey = String(objectKey || '').trim().replace(/^\/+/, '')
    const normalizedNamespaceId = String(namespaceId || '').trim()
    if (!base || !normalizedKey) return ''
    return normalizedNamespaceId === 'default'
        ? `${base}/${normalizedKey}`
        : `${base}/${normalizedNamespaceId}/${normalizedKey}`
}

function getOriginalVideoAssetKeys(videoId: string): string[] {
    const normalizedId = String(videoId || '').trim()
    if (!normalizedId) return []
    return [
        `videos/${normalizedId}_original.mp4`,
        `videos/${normalizedId}_line_original.mp4`,
    ]
}

function getProcessedThumbnailAssetKey(videoId: string): string {
    return `videos/${String(videoId || '').trim()}_thumb.webp`
}

function getOriginalThumbnailAssetKey(videoId: string): string {
    return `videos/${String(videoId || '').trim()}_original_thumb.webp`
}

function isNamespaceAssetUrlForNamespace(url: unknown, namespaceId: string): boolean {
    const normalizedUrl = String(url || '').trim()
    const normalizedNamespaceId = String(namespaceId || '').trim()
    if (!normalizedUrl || !normalizedNamespaceId) return false
    return normalizedUrl.includes(`/${normalizedNamespaceId}/videos/`)
}

async function clearNamespaceProcessedArtifacts(bucket: R2Bucket, videoId: string): Promise<void> {
    const normalizedVideoId = String(videoId || '').trim()
    if (!normalizedVideoId) return
    await Promise.all([
        bucket.delete(`videos/${normalizedVideoId}.json`).catch(() => { }),
        bucket.delete(`videos/${normalizedVideoId}.mp4`).catch(() => { }),
        bucket.delete(getProcessedThumbnailAssetKey(normalizedVideoId)).catch(() => { }),
        bucket.delete(`_processing/${normalizedVideoId}.json`).catch(() => { }),
        bucket.delete(`_queue/${normalizedVideoId}.json`).catch(() => { }),
    ])
}

function isImportedVideoMetaPointingAtSourceNamespace(params: {
    meta: Record<string, unknown>
    targetNamespaceId: string
    sourceNamespaceId: string
}): boolean {
    const targetNamespaceId = String(params.targetNamespaceId || '').trim()
    const sourceNamespaceId = String(params.sourceNamespaceId || '').trim()
    if (!targetNamespaceId || !sourceNamespaceId || targetNamespaceId === sourceNamespaceId) return false

    const meta = params.meta || {}
    const importedFrom = String(meta.importedFrom || meta.sourceNamespaceId || meta.source_namespace_id || '').trim()
    const originalUrl = String(meta.originalUrl || meta.original_url || '').trim()
    const publicUrl = String(meta.publicUrl || meta.public_url || '').trim()
    const thumbnailUrl = String(meta.thumbnailUrl || meta.thumbnail_url || '').trim()

    const pointsToSource =
        isNamespaceAssetUrlForNamespace(originalUrl, sourceNamespaceId)
        || isNamespaceAssetUrlForNamespace(publicUrl, sourceNamespaceId)
        || isNamespaceAssetUrlForNamespace(thumbnailUrl, sourceNamespaceId)
    const pointsToTarget =
        isNamespaceAssetUrlForNamespace(originalUrl, targetNamespaceId)
        || isNamespaceAssetUrlForNamespace(publicUrl, targetNamespaceId)
        || isNamespaceAssetUrlForNamespace(thumbnailUrl, targetNamespaceId)

    return !!(
        (importedFrom && importedFrom === sourceNamespaceId && !pointsToTarget)
        || pointsToSource
    )
}

function getGalleryAssetKeys(videoId: string, variant: GalleryAssetVariant): string[] {
    const normalizedId = String(videoId || '').trim()
    if (!normalizedId) return []
    switch (variant) {
        case 'original-thumb':
            return [getOriginalThumbnailAssetKey(normalizedId)]
        case 'thumb':
            return [getProcessedThumbnailAssetKey(normalizedId)]
        case 'original':
            return getOriginalVideoAssetKeys(normalizedId)
        case 'public':
        default:
            return [`videos/${normalizedId}.mp4`]
    }
}

function getGalleryAssetKey(videoId: string, variant: GalleryAssetVariant): string {
    return getGalleryAssetKeys(videoId, variant)[0] || ''
}

async function resolveGalleryAssetKey(bucket: R2Bucket, videoId: string, variant: GalleryAssetVariant): Promise<string> {
    const candidates = getGalleryAssetKeys(videoId, variant)
    if (candidates.length <= 1) return candidates[0] || ''

    for (const candidate of candidates) {
        const head = await bucket.head(candidate).catch(() => null)
        if (head) return candidate
    }
    return candidates[0] || ''
}

function getGalleryAssetFallbackContentType(variant: GalleryAssetVariant): string {
    return variant === 'thumb' || variant === 'original-thumb' ? 'image/webp' : 'video/mp4'
}

function buildWorkerGalleryAssetUrl(workerUrl: string, namespaceId: string, videoId: string, variant: GalleryAssetVariant): string {
    const normalizedWorkerUrl = String(workerUrl || '').trim().replace(/\/+$/, '')
    const normalizedNamespaceId = String(namespaceId || '').trim()
    const normalizedVideoId = String(videoId || '').trim()
    if (!normalizedWorkerUrl || !normalizedNamespaceId || !normalizedVideoId) return ''
    try {
        const url = new URL(`${normalizedWorkerUrl}/api/gallery/${encodeURIComponent(normalizedVideoId)}/asset/${variant}`)
        url.searchParams.set('namespace_id', normalizedNamespaceId)
        return url.toString()
    } catch {
        return `${normalizedWorkerUrl}/api/gallery/${encodeURIComponent(normalizedVideoId)}/asset/${variant}?namespace_id=${encodeURIComponent(normalizedNamespaceId)}`
    }
}

function extractGalleryVideoIdFromUrl(url: string): string {
    const raw = String(url || '').trim()
    if (!raw) return ''
    try {
        const parsed = new URL(raw)
        const galleryMatch = parsed.pathname.match(/\/api\/gallery\/([^/]+)\/asset\//i)
        if (galleryMatch?.[1]) return decodeURIComponent(galleryMatch[1]).trim()
        const r2Match = parsed.pathname.match(/\/videos\/([a-zA-Z0-9_-]+)(?:_(?:original|line_original|thumb))?\.(?:mp4|webm|mov|m4v|webp|jpg|jpeg|png)$/i)
        if (r2Match?.[1]) return decodeURIComponent(r2Match[1]).trim()
    } catch {
        const galleryMatch = raw.match(/\/api\/gallery\/([^/?#]+)\/asset\//i)
        if (galleryMatch?.[1]) return decodeURIComponent(galleryMatch[1]).trim()
        const r2Match = raw.match(/\/videos\/([a-zA-Z0-9_-]+)(?:_(?:original|line_original|thumb))?\.(?:mp4|webm|mov|m4v|webp|jpg|jpeg|png)(?:[?#]|$)/i)
        if (r2Match?.[1]) return decodeURIComponent(r2Match[1]).trim()
    }
    return ''
}

function resolveCreateAdVideoName(params: { explicitName?: string; sourceVideoId?: string; videoUrl?: string; videoId?: string }): string {
    const explicitName = String(params.explicitName || '').trim()
    if (explicitName) return explicitName
    const sourceVideoId = String(params.sourceVideoId || '').trim()
    if (sourceVideoId) return sourceVideoId
    const urlVideoId = extractGalleryVideoIdFromUrl(String(params.videoUrl || ''))
    if (urlVideoId) return urlVideoId
    return String(params.videoId || '').trim()
}

function buildWorkerGalleryFrameUrl(
    workerUrl: string,
    namespaceId: string,
    videoId: string,
    options?: {
        seed?: string
        format?: 'webp' | 'jpg'
        width?: number
        height?: number
        timeSeconds?: number
        coverText?: string
        coverTextYPercent?: number
        coverTemplateId?: string
        coverTextStyle?: Partial<CoverTextStyleSettings> | null
    },
): string {
    const normalizedWorkerUrl = String(workerUrl || '').trim().replace(/\/+$/, '')
    const normalizedNamespaceId = String(namespaceId || '').trim()
    const normalizedVideoId = String(videoId || '').trim()
    if (!normalizedWorkerUrl || !normalizedNamespaceId || !normalizedVideoId) return ''

    const normalizedSeed = String(options?.seed || '').trim()
    const requestedFormat = options?.format === 'jpg' ? 'jpg' : 'webp'
    const width = Number.isFinite(options?.width) ? Math.max(120, Math.min(1440, Math.round(Number(options?.width)))) : undefined
    const height = Number.isFinite(options?.height) ? Math.max(160, Math.min(2560, Math.round(Number(options?.height)))) : undefined
    const timeSeconds = Number.isFinite(options?.timeSeconds) ? Math.max(0, Number(options?.timeSeconds)) : undefined
    const coverText = normalizeLineCoverText(options?.coverText)
    const coverTextYPercent = Number.isFinite(options?.coverTextYPercent)
        ? Math.max(10, Math.min(90, Math.round(Number(options?.coverTextYPercent))))
        : undefined
    const coverTemplateId = normalizeCoverTemplateId(String(options?.coverTemplateId || ''))
    const coverTextStyle = normalizeCoverTextStyle(options?.coverTextStyle, coverTemplateId)

    try {
        const url = new URL(`${normalizedWorkerUrl}/api/gallery/${encodeURIComponent(normalizedVideoId)}/frame`)
        url.searchParams.set('namespace_id', normalizedNamespaceId)
        if (normalizedSeed) url.searchParams.set('seed', normalizedSeed)
        if (requestedFormat) url.searchParams.set('format', requestedFormat)
        if (width) url.searchParams.set('w', String(width))
        if (height) url.searchParams.set('h', String(height))
        if (Number.isFinite(timeSeconds)) url.searchParams.set('t', String(timeSeconds))
        if (coverText) url.searchParams.set('ct', coverText)
        if (Number.isFinite(coverTextYPercent)) url.searchParams.set('cy', String(coverTextYPercent))
        if (coverText) {
            url.searchParams.set('tid', coverTemplateId)
            url.searchParams.set('tf', coverTextStyle.fontId)
            url.searchParams.set('tc', coverTextStyle.textColor)
            url.searchParams.set('tc2', coverTextStyle.secondaryTextColor)
            url.searchParams.set('bc', coverTextStyle.backgroundColor)
            url.searchParams.set('bo', String(coverTextStyle.backgroundOpacity))
            url.searchParams.set('ts', String(coverTextStyle.sizeScale))
            url.searchParams.set('af', coverTextStyle.autoFit ? '1' : '0')
            url.searchParams.set('om', coverTextStyle.mode)
            url.searchParams.set('oc', coverTextStyle.outlineColor)
            url.searchParams.set('ow', String(coverTextStyle.outlineWidth))
        }
        return url.toString()
    } catch {
        const params = new URLSearchParams()
        params.set('namespace_id', normalizedNamespaceId)
        if (normalizedSeed) params.set('seed', normalizedSeed)
        if (requestedFormat) params.set('format', requestedFormat)
        if (width) params.set('w', String(width))
        if (height) params.set('h', String(height))
        if (Number.isFinite(timeSeconds)) params.set('t', String(timeSeconds))
        if (coverText) params.set('ct', coverText)
        if (Number.isFinite(coverTextYPercent)) params.set('cy', String(coverTextYPercent))
        if (coverText) {
            params.set('tid', coverTemplateId)
            params.set('tf', coverTextStyle.fontId)
            params.set('tc', coverTextStyle.textColor)
            params.set('tc2', coverTextStyle.secondaryTextColor)
            params.set('bc', coverTextStyle.backgroundColor)
            params.set('bo', String(coverTextStyle.backgroundOpacity))
            params.set('ts', String(coverTextStyle.sizeScale))
            params.set('af', coverTextStyle.autoFit ? '1' : '0')
            params.set('om', coverTextStyle.mode)
            params.set('oc', coverTextStyle.outlineColor)
            params.set('ow', String(coverTextStyle.outlineWidth))
        }
        return `${normalizedWorkerUrl}/api/gallery/${encodeURIComponent(normalizedVideoId)}/frame?${params.toString()}`
    }
}

function resolvePostingVideoDownloadUrl(
    env: Env,
    namespaceId: string,
    videoId: string,
    rawPublicUrl = '',
): string {
    const normalizedNamespaceId = String(namespaceId || '').trim()
    const normalizedVideoId = String(videoId || '').trim()
    const workerAssetUrl = buildWorkerGalleryAssetUrl(
        String(env.WORKER_URL || '').trim(),
        normalizedNamespaceId,
        normalizedVideoId,
        'public',
    )
    if (workerAssetUrl) return workerAssetUrl

    const publicUrl = String(rawPublicUrl || '').trim()
    if (publicUrl && publicUrl.includes(`/${normalizedNamespaceId}/videos/`)) {
        return publicUrl
    }

    return getVideoPublicUrlForNamespace(env.R2_PUBLIC_URL, normalizedNamespaceId, normalizedVideoId)
}

function parseSingleRangeHeader(rangeHeader: string, size: number): { offset: number; length: number; end: number } | 'unsatisfiable' | null {
    const normalized = String(rangeHeader || '').trim()
    if (!normalized) return null

    const match = normalized.match(/^bytes=(\d*)-(\d*)$/i)
    if (!match) return null

    const [, startRaw, endRaw] = match
    if (!startRaw && !endRaw) return 'unsatisfiable'

    if (!startRaw) {
        const suffixLength = Number(endRaw)
        if (!Number.isFinite(suffixLength) || suffixLength <= 0) return 'unsatisfiable'
        const length = Math.min(size, suffixLength)
        const offset = Math.max(0, size - length)
        return { offset, length, end: size - 1 }
    }

    const start = Number(startRaw)
    if (!Number.isFinite(start) || start < 0 || start >= size) return 'unsatisfiable'

    const requestedEnd = endRaw ? Number(endRaw) : size - 1
    if (!Number.isFinite(requestedEnd) || requestedEnd < start) return 'unsatisfiable'

    const end = Math.min(size - 1, requestedEnd)
    return { offset: start, length: end - start + 1, end }
}

async function buildGalleryAssetResponse(
    bucket: R2Bucket,
    key: string,
    variant: GalleryAssetVariant,
    rangeHeader?: string | null,
): Promise<Response> {
    const head = await bucket.head(key)
    if (!head) return new Response('Not found', { status: 404 })

    const headers = new Headers({
        'Accept-Ranges': 'bytes',
        'Cache-Control': 'public, max-age=31536000, immutable',
        'Content-Type': head.httpMetadata?.contentType || getGalleryAssetFallbackContentType(variant),
        'Access-Control-Allow-Origin': '*',
    })
    if (head.httpEtag) headers.set('ETag', head.httpEtag)

    const range = parseSingleRangeHeader(String(rangeHeader || ''), head.size)
    if (range === 'unsatisfiable') {
        headers.set('Content-Range', `bytes */${head.size}`)
        return new Response(null, { status: 416, headers })
    }

    if (range) {
        const obj = await bucket.get(key, { range: { offset: range.offset, length: range.length } })
        if (!obj) return new Response('Not found', { status: 404 })
        headers.set('Content-Length', String(range.length))
        headers.set('Content-Range', `bytes ${range.offset}-${range.end}/${head.size}`)
        return new Response(obj.body, { status: 206, headers })
    }

    const obj = await bucket.get(key)
    if (!obj) return new Response('Not found', { status: 404 })
    headers.set('Content-Length', String(head.size))
    return new Response(obj.body, { status: 200, headers })
}

