// Full resync — loops through ALL FB page posts in one request, discovering NEW videos
// AND refreshing views for existing ones. Use when cron is too slow or after threshold drift.
// Bypasses the 100-videos-per-minute cron pacing entirely.
app.post('/api/dashboard/facebook-page-videos/full-resync', async (c) => {
    const body = await c.req.json().catch(() => ({})) as {
        page_id?: string
        page_name?: string
        max_pages?: number
    }
    const pageId = String(body.page_id || c.req.query('page_id') || DASHBOARD_FACEBOOK_GALLERY_PAGE_ID).trim()
    const pageName = String(body.page_name || c.req.query('page_name') || DASHBOARD_FACEBOOK_GALLERY_PAGE_NAME).trim()
    const maxPagesRaw = Number(body.max_pages || 30)
    const maxPages = Number.isFinite(maxPagesRaw) ? Math.min(50, Math.max(1, Math.floor(maxPagesRaw))) : 30

    if (!pageId) return c.json({ ok: false, error: 'page_id_required' }, 400)

    const token = await resolveFacebookSyncToken(c.env.DB, pageId)
    if (!token) return c.json({ ok: false, error: 'facebook_sync_token_missing' }, 400)

    const beforeOver100k = await countFacebookPageVideoCache(c.env.DB, { pageId, minViews: 100000 })
    const beforeTotal = await countFacebookPageVideoCache(c.env.DB, { pageId, minViews: 0 })

    let nextAfter = ''
    let totalDiscovered = 0
    let pagesScanned = 0
    let firstError = ''
    let firstSampleResponse: unknown = null
    const fbErrors: string[] = []

    for (let i = 0; i < maxPages; i++) {
        try {
            const batch = await fetchFacebookPageVideoBatchFromGraphToken(token, pageId, nextAfter)
            pagesScanned++

            // Capture first batch's first item for debugging (so user can verify insights field is working)
            if (i === 0 && batch.items.length > 0) {
                firstSampleResponse = {
                    sample_video_id: batch.items[0].video_id,
                    sample_views: batch.items[0].views,
                    fields_present: Object.keys(batch.items[0] || {}),
                }
            }

            const rows = batch.items
                .map((item) => normalizeFacebookPageVideoCacheRow(pageId, {
                    ...item,
                    page_name: pageName,
                }))
                .filter((item): item is FacebookPageVideoCacheRow => !!item)
            if (rows.length > 0) {
                await upsertFacebookPageVideoCacheRows(c.env.DB, pageId, pageName, rows)
                totalDiscovered += rows.length
            }
            nextAfter = batch.nextAfter || ''
            if (!nextAfter) break  // Reached end of page posts
        } catch (e) {
            const msg = e instanceof Error ? e.message : String(e)
            if (!firstError) firstError = msg
            fbErrors.push(`page_${i}: ${msg}`)
            // Don't stop — try next page (FB might rate-limit one page)
            if (msg.includes('rate_limited') || msg.includes('facebook_graph_http_4')) break
        }
    }

    // Update sync state to reflect this full re-scan
    const nowIso = new Date().toISOString()
    await upsertFacebookPageVideoSyncState(c.env.DB, pageId, {
        page_name: pageName,
        next_after: nextAfter,
        last_attempt_at: nowIso,
        last_synced_at: nowIso,
        last_full_scan_at: nextAfter ? undefined : nowIso,
        fully_scanned: nextAfter ? 0 : 1,
        last_batch_count: totalDiscovered,
        last_error: firstError || '',
    })

    const afterOver100k = await countFacebookPageVideoCache(c.env.DB, { pageId, minViews: 100000 })
    const afterTotal = await countFacebookPageVideoCache(c.env.DB, { pageId, minViews: 0 })

    return c.json({
        ok: !firstError,
        page_id: pageId,
        pages_scanned: pagesScanned,
        max_pages: maxPages,
        rows_upserted: totalDiscovered,
        fully_scanned: !nextAfter,
        next_after: nextAfter,
        before: { total: beforeTotal, over_100k: beforeOver100k },
        after: { total: afterTotal, over_100k: afterOver100k },
        delta_over_100k: afterOver100k - beforeOver100k,
        first_error: firstError || null,
        fb_errors: fbErrors.slice(0, 5),
        debug_sample: firstSampleResponse,
    }, 200, { 'Cache-Control': 'no-store' })
})

// ---------------------------------------------------------------------------
// Page posts inventory — live Graph cursor crawl
//
// The CSV importer (/api/dashboard/page-post-inventory/import) and the read-only
// query (GET /api/dashboard/page-post-inventory) above are intentionally
// fetch-free. This endpoint is the ONLY place that walks the Graph /posts edge
// to backfill the same facebook_page_post_inventory table beyond the first page,
// following paging.cursors.after until exhausted or the caller's caps. Crawl
// rows never overwrite comment columns that a CSV import already populated.
// ---------------------------------------------------------------------------

// Read one /{page}/posts batch as raw inventory-shaped Graph nodes. Throws on
// Graph errors so the crawler can record last_error and keep the resume cursor.
async function fetchPagePostInventoryBatchFromGraphToken(token: string, pageId: string, after = ''): Promise<PagePostInventoryGraphBatch> {
    const params = new URLSearchParams({
        fields: 'id,message,permalink_url,created_time,attachments{media_type,target{id}}',
        limit: String(PAGE_POST_INVENTORY_GRAPH_DEFAULT_BATCH_SIZE),
        access_token: String(token || '').trim(),
    })
    if (after) params.set('after', after)
    const response = await fetch(`https://graph.facebook.com/v21.0/${encodeURIComponent(pageId)}/posts?${params.toString()}`)
    if (!response.ok) {
        const errorBody = await response.text().catch(() => '')
        throw new Error(`facebook_graph_http_${response.status}${errorBody ? `:${errorBody.slice(0, 120)}` : ''}`)
    }
    const payload = await response.json().catch(() => ({})) as {
        error?: { code?: number | string; message?: string }
        data?: Array<Record<string, unknown>>
        paging?: { next?: string; cursors?: { after?: string; before?: string } }
    }
    if (payload?.error) {
        const code = Number(payload.error?.code || 0)
        const message = String(payload.error?.message || 'facebook_graph_failed')
        if (code === 368) throw new Error(`facebook_rate_limited:${code}`)
        throw new Error(`${message}${code ? `:${code}` : ''}`)
    }
    return {
        posts: Array.isArray(payload?.data) ? payload.data : [],
        paging: payload?.paging || null,
    }
}

async function getPagePostInventorySyncState(db: D1Database, pageId: string): Promise<Record<string, unknown> | null> {
    await ensurePagePostInventoryTable(db)
    return await db.prepare(
        `SELECT page_id, next_after, last_attempt_at, last_synced_at, last_full_scan_at,
                fully_scanned, last_batch_count, last_error, updated_at
         FROM facebook_page_post_inventory_sync_state WHERE page_id = ?`
    ).bind(pageId).first() as Record<string, unknown> | null
}

async function upsertPagePostInventorySyncState(db: D1Database, pageId: string, fields: {
    next_after?: string
    last_attempt_at?: string
    last_synced_at?: string
    last_full_scan_at?: string
    fully_scanned?: number
    last_batch_count?: number
    last_error?: string
}): Promise<void> {
    await ensurePagePostInventoryTable(db)
    const current = await getPagePostInventorySyncState(db, pageId)
    const nextAfter = String(fields.next_after ?? current?.next_after ?? '').trim()
    const lastAttempt = String(fields.last_attempt_at ?? current?.last_attempt_at ?? '').trim()
    const lastSynced = String(fields.last_synced_at ?? current?.last_synced_at ?? '').trim()
    const lastFullScan = String(fields.last_full_scan_at ?? current?.last_full_scan_at ?? '').trim()
    const fullyScanned = Number(fields.fully_scanned ?? current?.fully_scanned ?? 0) > 0 ? 1 : 0
    const lastBatchCount = Number(fields.last_batch_count ?? current?.last_batch_count ?? 0)
    const lastError = String(fields.last_error ?? current?.last_error ?? '').trim()
    await db.prepare(
        `INSERT INTO facebook_page_post_inventory_sync_state (
            page_id, next_after, last_attempt_at, last_synced_at, last_full_scan_at,
            fully_scanned, last_batch_count, last_error, updated_at
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, datetime('now'))
        ON CONFLICT(page_id) DO UPDATE SET
            next_after = excluded.next_after,
            last_attempt_at = excluded.last_attempt_at,
            last_synced_at = excluded.last_synced_at,
            last_full_scan_at = excluded.last_full_scan_at,
            fully_scanned = excluded.fully_scanned,
            last_batch_count = excluded.last_batch_count,
            last_error = excluded.last_error,
            updated_at = datetime('now')`
    ).bind(pageId, nextAfter, lastAttempt, lastSynced, lastFullScan, fullyScanned, lastBatchCount, lastError).run()
}

// Upsert crawl-discovered posts WITHOUT clobbering comment columns that a CSV
// import may have already populated. New rows are tagged source = GRAPH source;
// existing rows keep their source and all page_comment* fields untouched.
async function upsertPagePostInventoryGraphRows(db: D1Database, rows: PagePostInventoryRow[]): Promise<void> {
    if (rows.length === 0) return
    await ensurePagePostInventoryTable(db)
    const sql = `INSERT INTO facebook_page_post_inventory (
            page_id, date, time, post_id, post_id_tail, type, post_url, message,
            page_commented, page_comment_id, page_comment_link, page_comment, source,
            imported_at, updated_at
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, '', '', '', '', ?, datetime('now'), datetime('now'))
        ON CONFLICT(page_id, post_id) DO UPDATE SET
            date = excluded.date,
            time = excluded.time,
            post_id_tail = excluded.post_id_tail,
            type = excluded.type,
            post_url = excluded.post_url,
            message = excluded.message,
            updated_at = excluded.updated_at`
    const statements = rows.map((row) => db.prepare(sql).bind(
        row.page_id,
        row.date,
        row.time,
        row.post_id,
        row.post_id_tail,
        row.type,
        row.post_url,
        row.message,
        row.source,
    ))
    await db.batch(statements)
}

app.post('/api/dashboard/page-post-inventory/graph-sync', async (c) => {
    const auth = await requireAuthSession(c)
    if (!auth.ok) return auth.response

    const body = await c.req.json().catch(() => ({})) as {
        page_id?: string
        max_pages?: number
        max_rows?: number
        reset_cursor?: boolean
    }
    const pageId = String(body.page_id || c.req.query('page_id') || DEFAULT_PAGE_POST_INVENTORY_PAGE_ID).trim()
    if (!pageId) return c.json({ ok: false, error: 'page_id_required' }, 400, { 'Cache-Control': 'no-store' })
    const maxPages = normalizePagePostInventoryGraphMaxPages(body.max_pages)
    const maxRowsRaw = Number(body.max_rows)
    const maxRows = Number.isFinite(maxRowsRaw) && maxRowsRaw > 0 ? Math.floor(maxRowsRaw) : 0

    const token = await resolveFacebookSyncToken(c.env.DB, pageId)
    if (!token) return c.json({ ok: false, error: 'facebook_sync_token_missing' }, 400, { 'Cache-Control': 'no-store' })

    await ensurePagePostInventoryTable(c.env.DB)
    const priorState = await getPagePostInventorySyncState(c.env.DB, pageId)
    // Resume from the stored cursor unless the caller asks to restart from the
    // newest posts (reset_cursor) or the page was already fully scanned.
    const resume = !body.reset_cursor && Number(priorState?.fully_scanned || 0) === 0
    const startAfter = resume ? String(priorState?.next_after || '').trim() : ''

    const nowIso = new Date().toISOString()
    await upsertPagePostInventorySyncState(c.env.DB, pageId, { last_attempt_at: nowIso })

    let upserted = 0
    const result = await crawlPagePostInventoryFromGraph({
        pageId,
        startAfter,
        maxPages,
        maxRows,
        fetchBatch: (after) => fetchPagePostInventoryBatchFromGraphToken(token, pageId, after),
        persistBatch: async (rows) => {
            await upsertPagePostInventoryGraphRows(c.env.DB, rows)
            upserted += rows.length
        },
    })

    await upsertPagePostInventorySyncState(c.env.DB, pageId, {
        next_after: result.next_after,
        last_attempt_at: nowIso,
        last_synced_at: result.error ? undefined : nowIso,
        last_full_scan_at: result.fully_scanned ? nowIso : undefined,
        fully_scanned: result.fully_scanned ? 1 : 0,
        last_batch_count: upserted,
        last_error: result.error || '',
    })

    return c.json({
        ok: !result.error,
        page_id: pageId,
        source: PAGE_POST_INVENTORY_GRAPH_SOURCE,
        started_after: startAfter || null,
        resumed: resume && !!startAfter,
        pages_scanned: result.pages_scanned,
        max_pages: maxPages,
        max_rows: maxRows || null,
        rows_discovered: result.rows.length,
        rows_upserted: upserted,
        next_after: result.next_after,
        fully_scanned: result.fully_scanned,
        reached_limit: result.reached_limit,
        error: result.error || null,
    }, result.error ? 502 : 200, { 'Cache-Control': 'no-store' })
})

// Read-only status of the page posts inventory Graph crawl cursor/sync state.
app.get('/api/dashboard/page-post-inventory/graph-sync/status', async (c) => {
    const pageId = String(c.req.query('page_id') || DEFAULT_PAGE_POST_INVENTORY_PAGE_ID).trim()
    if (!pageId) return c.json({ ok: false, error: 'page_id_required' }, 400, { 'Cache-Control': 'no-store' })
    const state = await getPagePostInventorySyncState(c.env.DB, pageId)
    return c.json({
        ok: true,
        page_id: pageId,
        sync: state ? {
            next_after: String(state.next_after || '').trim(),
            last_attempt_at: String(state.last_attempt_at || '').trim(),
            last_synced_at: String(state.last_synced_at || '').trim(),
            last_full_scan_at: String(state.last_full_scan_at || '').trim(),
            fully_scanned: Number(state.fully_scanned || 0) > 0,
            last_batch_count: Number(state.last_batch_count || 0),
            last_error: String(state.last_error || '').trim(),
            updated_at: String(state.updated_at || '').trim(),
        } : null,
    }, 200, { 'Cache-Control': 'no-store' })
})

// ---------------------------------------------------------------------------
// Clean Facebook Page Posts inventory — official Graph reads only.
//
// Captures EVERY real post of a Page via /{page}/published_posts cursor
// pagination (no HTML scraping, no view-count filter). There is no artificial
// total-post cap: each sync invocation walks a bounded number of cursor pages and
// persists a resume cursor, so the UI/cron simply calls again while pending_more
// stays true. Reads serve from facebook_page_post_cache for speed.
// ---------------------------------------------------------------------------

// Read cached posts. No min_views filter — this is a full-post inventory.
app.get('/api/dashboard/facebook-page-posts', async (c) => {
    const namespaceId = String(c.req.query('namespace_id') || DASHBOARD_FACEBOOK_GALLERY_NAMESPACE_ID).trim()
    const pageId = String(c.req.query('page_id') || '').trim()
    const mediaType = String(c.req.query('media_type') || '').trim()
    const q = String(c.req.query('q') || '').trim()
    const sort = String(c.req.query('sort') || 'newest').trim()
    const limit = normalizeFacebookPagePostsReadLimit(c.req.query('limit'))
    const offset = normalizeFacebookPagePostsOffset(c.req.query('offset'))

    const [items, total] = await Promise.all([
        listFacebookPagePostCache(c.env.DB, { namespaceId, pageId, mediaType, q, sort, limit, offset }),
        countFacebookPagePostCache(c.env.DB, { namespaceId, pageId, mediaType, q }),
    ])

    // Surface sync state: a single page's row, or every page's row in all-pages mode.
    let sync: Record<string, unknown> | null = null
    let syncAll: Array<Record<string, unknown>> | null = null
    if (pageId) {
        const state = await getFacebookPagePostSyncState(c.env.DB, namespaceId, pageId)
        sync = state ? {
            page_id: pageId,
            page_name: String(state.page_name || '').trim(),
            next_after: String(state.next_after || '').trim(),
            fully_scanned: Number(state.fully_scanned || 0) > 0,
            last_attempt_at: String(state.last_attempt_at || '').trim(),
            last_synced_at: String(state.last_synced_at || '').trim(),
            last_full_scan_at: String(state.last_full_scan_at || '').trim(),
            last_batch_count: Number(state.last_batch_count || 0),
            last_error: String(state.last_error || '').trim(),
            total_cached: Number(state.total_cached || 0),
        } : null
    } else {
        await ensureFacebookPagePostCacheTables(c.env.DB)
        const states = await c.env.DB.prepare(
            `SELECT page_id, page_name, fully_scanned, last_synced_at, last_full_scan_at, total_cached, last_error
             FROM facebook_page_post_sync_state WHERE namespace_id = ? ORDER BY page_name COLLATE NOCASE ASC`
        ).bind(namespaceId).all() as { results?: Array<Record<string, unknown>> }
        syncAll = (states.results || []).map((s) => ({
            page_id: String(s.page_id || '').trim(),
            page_name: String(s.page_name || '').trim(),
            fully_scanned: Number(s.fully_scanned || 0) > 0,
            last_synced_at: String(s.last_synced_at || '').trim(),
            last_full_scan_at: String(s.last_full_scan_at || '').trim(),
            total_cached: Number(s.total_cached || 0),
            last_error: String(s.last_error || '').trim(),
        }))
    }

    return c.json({
        ok: true,
        namespace_id: namespaceId,
        page_id: pageId || null,
        data_source: FACEBOOK_PAGE_POSTS_SOURCE,
        sort,
        total,
        items,
        sync,
        sync_all: syncAll,
    }, 200, { 'Cache-Control': 'no-store' })
})

// Sync ONE page: walk a bounded number of cursor pages, persist after every Graph
// page, and report pending_more so the caller can resume until fully_scanned.
app.post('/api/dashboard/facebook-page-posts/sync-page', async (c) => {
    const auth = await requireAuthSession(c)
    if (!auth.ok) return auth.response

    const body = await c.req.json().catch(() => ({})) as {
        page_id?: string
        page_name?: string
        namespace_id?: string
        reset?: boolean
        limit?: number
        batches?: number
    }
    const pageId = String(body.page_id || c.req.query('page_id') || DASHBOARD_FACEBOOK_GALLERY_PAGE_ID).trim()
    if (!pageId) return c.json({ ok: false, error: 'page_id_required' }, 400, { 'Cache-Control': 'no-store' })
    const namespaceId = String(body.namespace_id || c.req.query('namespace_id') || DASHBOARD_FACEBOOK_GALLERY_NAMESPACE_ID).trim()
    const pageName = String(body.page_name || c.req.query('page_name') || '').trim()
    const reset = body.reset === true || c.req.query('reset') === '1'
    const limit = normalizeFacebookPagePostsGraphLimit(body.limit ?? c.req.query('limit'))
    const batches = normalizeFacebookPagePostsBatches(body.batches ?? c.req.query('batches'))

    const result = await runFacebookPagePostsSyncPass(c.env.DB, { namespaceId, pageId, pageName, reset, limit, batches })
    return c.json({ ...result, edge: FACEBOOK_PAGE_POSTS_EDGE, graph_limit: limit, batches }, result.error ? 502 : 200, { 'Cache-Control': 'no-store' })
})

// Sync ALL configured pages in the namespace, advancing a few pages per call.
// Prioritizes pages that still have work (not fully scanned) and aggregates
// pending_more so the caller keeps invoking until the whole namespace is done.
app.post('/api/dashboard/facebook-page-posts/sync-all', async (c) => {
    const auth = await requireAuthSession(c)
    if (!auth.ok) return auth.response

    const body = await c.req.json().catch(() => ({})) as {
        namespace_id?: string
        pages_limit?: number
        limit?: number
        batches_per_page?: number
        reset?: boolean
    }
    const namespaceId = String(body.namespace_id || c.req.query('namespace_id') || DASHBOARD_FACEBOOK_GALLERY_NAMESPACE_ID).trim()
    if (!namespaceId) return c.json({ ok: false, error: 'namespace_id_required' }, 400, { 'Cache-Control': 'no-store' })
    const pagesLimit = normalizeFacebookPagePostsSyncAllPages(body.pages_limit ?? c.req.query('pages_limit'))
    const limit = normalizeFacebookPagePostsGraphLimit(body.limit ?? c.req.query('limit'))
    const batchesPerPage = normalizeFacebookPagePostsBatches(
        body.batches_per_page ?? c.req.query('batches_per_page') ?? FACEBOOK_PAGE_POSTS_SYNC_ALL_DEFAULT_BATCHES_PER_PAGE,
    )
    const reset = body.reset === true || c.req.query('reset') === '1'

    await ensureFacebookPagePostCacheTables(c.env.DB)

    // Source the page list the same way the dashboard page-sources endpoint does:
    // every page in the namespace, active first.
    const pageRows = await c.env.DB.prepare(
        `SELECT id, name FROM pages WHERE bot_id = ?
         ORDER BY CASE WHEN is_active = 1 THEN 0 ELSE 1 END, name COLLATE NOCASE ASC`
    ).bind(namespaceId).all() as { results?: Array<{ id?: string; name?: string }> }
    const allPages = (pageRows.results || [])
        .map((r) => ({ id: String(r.id || '').trim(), name: String(r.name || '').trim() }))
        .filter((p) => p.id)

    // Which pages still need work? On reset, everyone; otherwise pages not yet
    // fully scanned (no state row counts as "needs work").
    const states = await c.env.DB.prepare(
        `SELECT page_id, fully_scanned FROM facebook_page_post_sync_state WHERE namespace_id = ?`
    ).bind(namespaceId).all() as { results?: Array<{ page_id?: string; fully_scanned?: number }> }
    const scannedSet = new Set<string>()
    for (const s of (states.results || [])) {
        if (Number(s.fully_scanned || 0) > 0) scannedSet.add(String(s.page_id || '').trim())
    }
    const pending = reset ? allPages : allPages.filter((p) => !scannedSet.has(p.id))
    const toProcess = pending.slice(0, pagesLimit)

    const results: Array<Record<string, unknown>> = []
    for (const page of toProcess) {
        const res = await runFacebookPagePostsSyncPass(c.env.DB, {
            namespaceId, pageId: page.id, pageName: page.name, reset, limit, batches: batchesPerPage,
        })
        results.push(res)
    }

    // More work remains if any processed page still has a cursor/error, OR there
    // are pending pages we did not reach this call.
    const pendingMore = results.some((r) => r.pending_more) || pending.length > toProcess.length
    return c.json({
        ok: results.every((r) => r.ok !== false) || results.length === 0,
        namespace_id: namespaceId,
        edge: FACEBOOK_PAGE_POSTS_EDGE,
        graph_limit: limit,
        batches_per_page: batchesPerPage,
        total_pages: allPages.length,
        pending_pages: pending.length,
        processed_pages: toProcess.length,
        pending_more: pendingMore,
        results,
    }, 200, { 'Cache-Control': 'no-store' })
})

// Refresh view counts for ALL cached videos in one shot.
// Useful when cron is too slow to cycle through every page (one batch per minute).
// Hits Facebook Graph API in batches of 50 (FB API limit for ?ids=) and updates
// any video whose view count has increased — never decreases values.
app.post('/api/dashboard/facebook-page-videos/refresh-all-views', async (c) => {
    const body = await c.req.json().catch(() => ({})) as {
        page_id?: string
    }
    const pageId = String(body.page_id || c.req.query('page_id') || DASHBOARD_FACEBOOK_GALLERY_PAGE_ID).trim()
    if (!pageId) return c.json({ ok: false, error: 'page_id_required' }, 400)

    const token = await resolveFacebookSyncToken(c.env.DB, pageId)
    if (!token) return c.json({ ok: false, error: 'facebook_sync_token_missing' }, 400)

    // Cloudflare Workers cap outbound subrequests per invocation (1,000 on Standard,
    // 50 on Bundled). Per-video fallback at full vault size (≈3,000 videos) blows past
    // that ceiling, so we always work in size-bounded chunks ordered by staleness.
    // Body params: { limit?: number = 800, max_age_minutes?: number = 0 = always include }
    const limitRaw = Number((body as Record<string, unknown>)?.limit ?? 800)
    const limit = Number.isFinite(limitRaw) ? Math.max(50, Math.min(900, Math.floor(limitRaw))) : 800
    const maxAgeMinutesRaw = Number((body as Record<string, unknown>)?.max_age_minutes ?? 0)
    const maxAgeMinutes = Number.isFinite(maxAgeMinutesRaw) && maxAgeMinutesRaw > 0
        ? Math.floor(maxAgeMinutesRaw)
        : 0

    await ensureFacebookPageVideoCacheTables(c.env.DB)
    const totalCachedRow = await c.env.DB.prepare(
        `SELECT COUNT(*) AS c FROM facebook_page_video_cache WHERE page_id = ? AND video_id <> ''`,
    ).bind(pageId).first<{ c: number }>().catch(() => null)
    const totalCachedRows = Number(totalCachedRow?.c || 0)

    // Take the chunk most in need: oldest fetched_at first, NULLs treated as oldest.
    // Optional max_age filter so callers can ask "only rows older than N minutes".
    const ageWhere = maxAgeMinutes > 0
        ? `AND (fetched_at IS NULL OR fetched_at < datetime('now', ?))`
        : ''
    const ageBindings: unknown[] = maxAgeMinutes > 0 ? [`-${maxAgeMinutes} minutes`] : []
    const cachedRows = await c.env.DB.prepare(
        `SELECT video_id, views, fetched_at FROM facebook_page_video_cache
         WHERE page_id = ? AND video_id <> '' ${ageWhere}
         ORDER BY (fetched_at IS NULL) DESC, fetched_at ASC
         LIMIT ?`,
    ).bind(pageId, ...ageBindings, limit).all() as { results?: Array<{ video_id: string; views: number; fetched_at: string | null }> }
    const cachedVideos = Array.isArray(cachedRows.results) ? cachedRows.results : []
    if (cachedVideos.length === 0) {
        const totalOver100k = await countFacebookPageVideoCache(c.env.DB, { pageId, minViews: 100000 })
        return c.json({
            ok: true,
            page_id: pageId,
            total: 0,
            total_in_cache: totalCachedRows,
            refreshed: 0,
            raised: 0,
            errors: 0,
            total_views_delta: 0,
            total_over_100k: totalOver100k,
            pending_more: false,
        })
    }

    // Larger batch since fetchVideoViewsResilient handles fallback internally — and
    // because per-video fallback runs 10-way concurrent, oversize batches stay fast.
    const BATCH = 200
    let refreshed = 0
    let raised = 0
    let errors = 0
    let totalViewsDelta = 0
    let lastErrorSample = ''
    const modesCount: Record<string, number> = { batch: 0, mixed: 0, per_video: 0 }

    for (let i = 0; i < cachedVideos.length; i += BATCH) {
        const batch = cachedVideos.slice(i, i + BATCH)
        const ids = batch.map((v) => String(v.video_id || '').trim()).filter(Boolean)
        if (ids.length === 0) continue
        try {
            const { viewsByVideoId, mode, errorSample } = await fetchVideoViewsResilient(token, ids)
            modesCount[mode] = (modesCount[mode] || 0) + 1
            if (errorSample) lastErrorSample = errorSample

            for (const cached of batch) {
                const newViews = viewsByVideoId.get(String(cached.video_id || '').trim())
                if (newViews === undefined) {
                    errors++
                    continue
                }
                const oldViews = Math.max(0, Math.floor(Number(cached.views) || 0))
                if (newViews > oldViews) {
                    await c.env.DB.prepare(
                        `UPDATE facebook_page_video_cache
                         SET views = ?, fetched_at = datetime('now'), updated_at = datetime('now')
                         WHERE page_id = ? AND video_id = ?`,
                    ).bind(newViews, pageId, cached.video_id).run()
                    raised++
                    totalViewsDelta += (newViews - oldViews)
                }
                refreshed++
            }
        } catch (e) {
            errors += batch.length
            if (!lastErrorSample) lastErrorSample = e instanceof Error ? e.message : String(e)
        }
    }

    // Recount videos crossing the 100K threshold so the dashboard sees the new count immediately
    const totalOver100k = await countFacebookPageVideoCache(c.env.DB, { pageId, minViews: 100000 })

    return c.json({
        ok: true,
        page_id: pageId,
        total: cachedVideos.length,
        total_in_cache: totalCachedRows,
        refreshed,
        raised,
        errors,
        total_views_delta: totalViewsDelta,
        total_over_100k: totalOver100k,
        // Caller (dashboard / cron / curl loop) should re-call until pending_more=false
        // to fully refresh the vault. Each call processes the staleest `limit` rows.
        pending_more: cachedVideos.length >= limit && (totalCachedRows > limit),
        // Diagnostic: which fetch path each batch used. If `per_video` dominates,
        // the operator's token doesn't support /?ids= batch reads (page-scoped
        // tokens behave that way). Pasting a user token in Settings will move
        // batches to the faster `batch` path. `mixed` = batch returned partial.
        modes: modesCount,
        last_error_sample: lastErrorSample || null,
    }, 200, { 'Cache-Control': 'no-store' })
})

// Deep backfill — calls Facebook Graph API to fill missing post_id + scan
// post description + first page-authored comment for shopee links.
// Use this when DB-side fallback chain cannot find the link.
app.post('/api/dashboard/facebook-page-videos/backfill-from-facebook', async (c) => {
    // Date-bounded, dry-run-by-default audit/backfill for Shopee links on cached
    // Facebook page videos. Reads ONLY via Graph GET (video caption/title/permalink/
    // post_id plus a small bounded comment window) and, in write mode, updates ONLY
    // the D1 cache (shopee_link / post_id / audit timestamps). It never writes to
    // Facebook, never edits comments, and never mints customlinks.
    //
    // Backward compatibility: old callers POST { page_id, limit } without dry_run.
    // dry_run now DEFAULTS TO TRUE, so those callers become a safe read-only audit
    // (no D1 writes) instead of silently mutating rows.
    const body = await c.req.json().catch(() => ({})) as {
        page_id?: string
        from_date?: string
        to_date?: string
        limit?: number
        offset?: number
        only_missing?: boolean
        dry_run?: boolean
        include_comment_counts?: boolean
        include_cta?: boolean
    }
    // Harmless query-string fallback for each param (body wins when present).
    const queryStr = (name: string): string => String(c.req.query(name) ?? '').trim()
    // A value explicitly meaning "false" (used for tri-state boolean defaults).
    const isExplicitFalse = (v: unknown): boolean => {
        const s = String(v ?? '').trim().toLowerCase()
        return v === false || s === 'false' || s === '0' || s === 'no' || s === 'off'
    }
    // A value explicitly meaning "true" (used for default-off boolean opt-ins).
    const isExplicitTrue = (v: unknown): boolean => {
        const s = String(v ?? '').trim().toLowerCase()
        return v === true || s === 'true' || s === '1' || s === 'yes' || s === 'on'
    }

    const pageId = String(body.page_id ?? queryStr('page_id') ?? '').trim()
    if (!pageId) return c.json({ ok: false, error: 'page_id_required' }, 400)

    // dry_run defaults TRUE; only an explicit false (body or query) enables writes.
    const dryRunRaw = body.dry_run !== undefined ? body.dry_run : c.req.query('dry_run')
    const dryRun = !isExplicitFalse(dryRunRaw)
    const writeMode = !dryRun

    // only_missing defaults TRUE; only an explicit false includes rows that already
    // have a cache shopee_link (counted as "existing").
    const onlyMissingRaw = body.only_missing !== undefined ? body.only_missing : c.req.query('only_missing')
    const onlyMissing = !isExplicitFalse(onlyMissingRaw)

    // include_comment_counts defaults FALSE (preserves old "do not scan comments
    // for cached rows" behavior); only an explicit true-like value opts in. Body
    // wins over query. When on, each scanned item gets read-only comment counts.
    const includeCommentCountsRaw = body.include_comment_counts !== undefined
        ? body.include_comment_counts
        : c.req.query('include_comment_counts')
    const includeCommentCounts = isExplicitTrue(includeCommentCountsRaw)

    // include_cta defaults FALSE (opt-in). When on, each scanned item gets a single
    // read-only Graph GET that surfaces any call-to-action/button/attached link for
    // the post (preferred) or video/reel. Body wins over query, same as the others.
    // This NEVER writes D1 (CTA fields are response-only) and never mutates Facebook.
    const includeCtaRaw = body.include_cta !== undefined
        ? body.include_cta
        : c.req.query('include_cta')
    const includeCta = isExplicitTrue(includeCtaRaw)

    // Bounded scan window. limit is capped small (<=150); offset is bounded.
    const limitRaw = Number(body.limit ?? c.req.query('limit') ?? 100)
    const limit = Number.isFinite(limitRaw) ? Math.min(150, Math.max(1, Math.floor(limitRaw))) : 100
    const offsetRaw = Number(body.offset ?? c.req.query('offset') ?? 0)
    const offset = Number.isFinite(offsetRaw) ? Math.min(10000, Math.max(0, Math.floor(offsetRaw))) : 0

    // Dates validated with the same whitelist/next-day helpers used by the read API.
    const fromInput = sanitizeFacebookPageVideoDateInput(body.from_date ?? c.req.query('from_date'))
    const toInput = sanitizeFacebookPageVideoDateInput(body.to_date ?? c.req.query('to_date'))
    const fromDate = fromInput?.value || ''
    const toDate = toInput?.value || ''

    // Write mode is the only path that mutates D1, so it requires an explicit, valid
    // date range to keep the blast radius bounded. dry_run may run unbounded reads.
    if (writeMode) {
        if (!fromInput || !toInput) return c.json({ ok: false, error: 'date_range_required_for_write' }, 400)
        if (fromInput.value > toInput.value) return c.json({ ok: false, error: 'invalid_date_range' }, 400)
    }

    // Comment-count scanning issues extra (read-only) Graph comment reads per row,
    // so it requires an explicit, valid (ordered) date range too — even in dry_run —
    // to keep the scan window bounded.
    if (includeCommentCounts) {
        if (!fromInput || !toInput) return c.json({ ok: false, error: 'date_range_required_for_comment_counts' }, 400)
        if (fromInput.value > toInput.value) return c.json({ ok: false, error: 'invalid_date_range' }, 400)
    }

    // CTA auditing issues an extra (read-only) per-row Graph read, so — like the
    // comment-count scan — it requires an explicit, valid (ordered) date range even
    // in dry_run to keep the scan window bounded.
    if (includeCta) {
        if (!fromInput || !toInput) return c.json({ ok: false, error: 'date_range_required_for_cta' }, 400)
        if (fromInput.value > toInput.value) return c.json({ ok: false, error: 'invalid_date_range' }, 400)
    }

    const syncToken = await resolveFacebookSyncToken(c.env.DB, pageId).catch(() => '')
    const commentTokenResolution = await resolveFacebookCommentToken(c.env.DB, pageId).catch(() => emptyFacebookTokenResolution())
    const commentReadToken = commentTokenResolution.token || syncToken
    const token = syncToken || commentReadToken
    if (!token) return c.json({ ok: false, error: 'facebook_sync_token_missing', ...facebookTokenDebugFields(commentTokenResolution) }, 400)

    await ensureFacebookPageVideoCacheTables(c.env.DB)
    await ensurePageCommentLinkWorkflowTables(c.env.DB)

    // Candidate query: constrained by page_id + (optional) date range + limit/offset.
    // created_time holds sortable ISO strings, so lexical comparison is correct for
    // both date-only and ISO inputs. Values flow through bound params only.
    const conditions: string[] = ['page_id = ?']
    const binds: unknown[] = [pageId]
    if (fromInput) {
        conditions.push('created_time >= ?')
        binds.push(fromInput.value)
    }
    if (toInput) {
        if (toInput.kind === 'date') {
            conditions.push('created_time < ?')
            binds.push(nextUtcDayFromDateOnly(toInput.value))
        } else {
            conditions.push('created_time <= ?')
            binds.push(toInput.value)
        }
    }
    if (onlyMissing) conditions.push("(shopee_link = '' OR shopee_link IS NULL)")
    binds.push(limit, offset)

    const rowsQuery = await c.env.DB.prepare(
        `SELECT video_id, post_id, description, title, created_time, shopee_link
         FROM facebook_page_video_cache
         WHERE ${conditions.join(' AND ')}
         ORDER BY created_time DESC, views DESC
         LIMIT ? OFFSET ?`
    ).bind(...binds).all().catch(() => null) as {
        results?: Array<{ video_id: string; post_id: string; description: string; title: string; created_time: string; shopee_link: string }>
    } | null
    const rows = Array.isArray(rowsQuery?.results) ? rowsQuery!.results : []

    const shopeeRe = /https?:\/\/(?:[^\s<>"']+\.)?shopee\.[^\s<>"']+/i
    const safeGraphIdRe = /^[A-Za-z0-9]+(?:_[A-Za-z0-9]+)*$/
    const normalizeGraphPostId = (raw: unknown): string => {
        const id = String(raw || '').trim()
        if (!id || !safeGraphIdRe.test(id)) return ''
        const pagePrefix = `${pageId}_`
        return id.startsWith(pagePrefix) ? id.slice(pagePrefix.length) : id
    }
    const derivePostIdFromCommentId = (raw: unknown): string => {
        const id = String(raw || '').trim()
        if (!id || !safeGraphIdRe.test(id)) return ''
        const splitAt = id.lastIndexOf('_')
        if (splitAt <= 0) return ''
        const prefix = id.slice(0, splitAt)
        return normalizeGraphPostId(prefix)
    }
    const buildPostCommentTarget = (storedPostId: string): string => {
        const id = String(storedPostId || '').trim()
        if (!id) return ''
        return id.includes('_') ? id : `${pageId}_${id}`
    }
    // Sanitize any Graph error text before surfacing it to the operator: never
    // echo the access_token (neither the literal value nor an access_token=... pair).
    const sanitizeGraphErrorText = (text: unknown): string => {
        let s = String(text ?? '')
        if (token) s = s.split(token).join('[REDACTED]')
        if (commentReadToken && commentReadToken !== token) s = s.split(commentReadToken).join('[REDACTED]')
        s = s.replace(/access_token=[^&\s"']+/gi, 'access_token=[REDACTED]')
        return s.trim()
    }
    const pickShopeeLinkFromComments = (comments: Array<Record<string, unknown>>): string => {
        for (const cmt of comments) {
            const from = cmt.from as Record<string, unknown> | undefined
            const fromId = String(from?.id || '').trim()
            if (fromId && fromId !== pageId) continue // prefer page-authored
            const m = String(cmt.message || '').match(shopeeRe)
            if (m) return m[0]
        }
        for (const cmt of comments) {
            const m = String(cmt.message || '').match(shopeeRe)
            if (m) return m[0]
        }
        return ''
    }

    let scanned = 0
    let found = 0
    let updated = 0
    let missing = 0
    let existing = 0
    const sourceCounts = { caption: 0, comment: 0, cache: 0 }
    const errors: Array<{ video_id: string; error: string }> = []
    const items: Array<{
        video_id: string
        post_id: string
        created_time: string
        caption: string
        shopee_link: string
        source: string
        error: string
        page_comment_count: number
        page_comment_ids: string[]
        other_comment_count: number
        comment_scan_status: string
        comment_scan_error: string
        post_id_resolution_status: string
        post_id_resolution_reason: string
        cta_present: boolean
        cta_type: string
        cta_title: string
        cta_url: string
        cta_source: string
        cta_scan_status: string
        cta_scan_error: string
    }> = []

    // Read-only bounded comment-window fetch (GET, limit 10) reused by both the
    // existing link-resolution path and the new comment-count population. It counts
    // page-authored vs. other comments and collects up to the first 5 page comment
    // ids. The token is used only inside the Graph URL and never returned.
    const scanCommentWindow = async (targetId: string): Promise<{
        data: Array<Record<string, unknown>>
        pageCommentCount: number
        otherCommentCount: number
        pageCommentIds: string[]
        resolvedPostId: string
        ok: boolean
        error: string
    }> => {
        const guard = await checkGraphCommentGuard(c.env.DB, c.env, pageId, GRAPH_COMMENT_FEATURE_BACKFILL)
        if (!guard.allowed) {
            return { data: [], pageCommentCount: 0, otherCommentCount: 0, pageCommentIds: [], resolvedPostId: '', ok: false, error: `${guard.status}:${guard.reason}:${guard.block_until}`.slice(0, 200) }
        }
        const commentsResp = await fetch(
            `https://graph.facebook.com/v21.0/${encodeURIComponent(targetId)}/comments?fields=id,from,message,created_time&limit=10&access_token=${encodeURIComponent(commentReadToken)}`
        )
        const commentsJson = await commentsResp.json().catch(() => ({})) as Record<string, unknown>
        await recordGraphCommentOperation(c.env.DB, pageId, GRAPH_COMMENT_FEATURE_BACKFILL)
        const data = Array.isArray((commentsJson as { data?: unknown[] }).data)
            ? ((commentsJson as { data: Array<Record<string, unknown>> }).data)
            : []
        // Build a sanitized failure reason: HTTP status + Graph error message/code/
        // type when available. Token is never included (see sanitizeGraphErrorText).
        const graphErr = commentsJson.error as Record<string, unknown> | undefined
        const errCode = graphErr?.code !== undefined ? sanitizeGraphErrorText(graphErr.code) : ''
        const errType = graphErr?.type !== undefined ? sanitizeGraphErrorText(graphErr.type) : ''
        const errMsg = sanitizeGraphErrorText((graphErr?.message) || `comments_fetch_${commentsResp.status}`)
        let error = commentsResp.ok
            ? ''
            : [`http_${commentsResp.status}`, errMsg, errCode ? `code=${errCode}` : '', errType ? `type=${errType}` : '']
                .filter(Boolean)
                .join(' ')
                .slice(0, 200)
        if (!commentsResp.ok) {
            const sig = detectGraphStopSignal(graphErr)
            if (sig.stop) {
                const blocked = await blockGraphCommentGuard(c.env.DB, pageId, GRAPH_COMMENT_FEATURE_BACKFILL, sig.reason)
                error = `${blocked.status}:${blocked.reason}:${blocked.block_until}`.slice(0, 200)
            }
        }
        let pageCommentCount = 0
        let otherCommentCount = 0
        let resolvedPostId = ''
        const pageCommentIds: string[] = []
        for (const cmt of data) {
            if (!resolvedPostId) {
                resolvedPostId = derivePostIdFromCommentId(cmt.id)
            }
            const from = cmt.from as Record<string, unknown> | undefined
            const fromId = String(from?.id || '').trim()
            if (fromId && fromId === pageId) {
                pageCommentCount++
                if (pageCommentIds.length < 5) {
                    const cid = String(cmt.id || '').trim()
                    if (cid) pageCommentIds.push(cid)
                }
            } else {
                otherCommentCount++
            }
        }
        return { data, pageCommentCount, otherCommentCount, pageCommentIds, resolvedPostId, ok: commentsResp.ok, error }
    }

    // Normalize a Graph call_to_action object into {type,title,url}. CTA buttons can
    // be shaped { type, value: { link|title } } (posts) or carry a flat title; this
    // returns null when the object exposes no usable type/title/url. Never reads tokens.
    const readCtaObject = (cta: unknown): { type: string; title: string; url: string } | null => {
        if (!cta || typeof cta !== 'object') return null
        const obj = cta as Record<string, unknown>
        const value = (obj.value && typeof obj.value === 'object') ? obj.value as Record<string, unknown> : undefined
        const type = String(obj.type || '').trim()
        const title = String(value?.title || obj.title || '').trim()
        const url = String(value?.link || value?.url || obj.link || obj.url || '').trim()
        if (!type && !title && !url) return null
        return { type, title, url }
    }

    // Read-only bounded CTA reader for a post (preferred) or video/reel id.
    // It uses GET-only Graph reads and avoids deprecated inline attachment field
    // expansion. Field-specific Graph rejects are retried with smaller field sets;
    // only a successful Graph read can produce status=scanned.
    const scanCtaTarget = async (targetId: string): Promise<{
        present: boolean
        type: string
        title: string
        url: string
        source: string
        ok: boolean
        status: 'scanned' | 'field_unavailable' | 'unsupported' | 'error'
        error: string
    }> => {
        const formatGraphCtaError = (resp: Response, json: Record<string, unknown>, fallback: string) => {
            const graphErr = json.error as Record<string, unknown> | undefined
            const errCode = graphErr?.code !== undefined ? sanitizeGraphErrorText(graphErr.code) : ''
            const errType = graphErr?.type !== undefined ? sanitizeGraphErrorText(graphErr.type) : ''
            const errMsg = sanitizeGraphErrorText((graphErr?.message) || fallback)
            return [`http_${resp.status}`, errMsg, errCode ? `code=${errCode}` : '', errType ? `type=${errType}` : '']
                .filter(Boolean)
                .join(' ')
                .slice(0, 200)
        }
        const isFieldUnavailableGraphError = (resp: Response, json: Record<string, unknown>) => {
            if (resp.ok) return false
            const graphErr = json.error as Record<string, unknown> | undefined
            const code = String(graphErr?.code ?? '')
            const msg = String(graphErr?.message ?? '').toLowerCase()
            return resp.status === 400 && (
                code === '12' ||
                msg.includes('deprecate_post_aggregated_fields_for_attachement') ||
                msg.includes('unsupported get request') ||
                msg.includes('nonexisting field') ||
                msg.includes('unknown path components') ||
                msg.includes('tried accessing nonexisting field')
            )
        }
        const graphGet = async (path: string, fields: string) => {
            const resp = await fetch(
                `https://graph.facebook.com/v21.0/${path}?fields=${encodeURIComponent(fields)}&access_token=${encodeURIComponent(token)}`
            )
            const json = await resp.json().catch(() => ({})) as Record<string, unknown>
            const error = resp.ok ? '' : formatGraphCtaError(resp, json, `cta_fetch_${resp.status}`)
            return { resp, json, error, fieldUnavailable: isFieldUnavailableGraphError(resp, json) }
        }

        const targetPath = encodeURIComponent(targetId)
        const nodeFieldSets = [
            'call_to_action,link,permalink_url',
            'link,permalink_url',
            'permalink_url',
        ]
        const attachmentFieldSets = [
            'call_to_action,title,description,type,url,unshimmed_url,target',
            'title,description,type,url,unshimmed_url',
            'title,type,url',
        ]

        let nodeJson: Record<string, unknown> | null = null
        let attData: unknown[] = []
        let scannedAny = false
        let lastFieldUnavailableError = ''

        for (const fields of nodeFieldSets) {
            const read = await graphGet(targetPath, fields)
            if (read.resp.ok) { nodeJson = read.json; scannedAny = true; break }
            if (read.fieldUnavailable) { lastFieldUnavailableError = read.error; continue }
            return { present: false, type: '', title: '', url: '', source: '', ok: false, status: 'error', error: read.error }
        }

        for (const fields of attachmentFieldSets) {
            const read = await graphGet(`${targetPath}/attachments`, fields)
            if (read.resp.ok) {
                scannedAny = true
                attData = Array.isArray((read.json.data as unknown[] | undefined)) ? read.json.data as unknown[] : []
                break
            }
            if (read.fieldUnavailable) { lastFieldUnavailableError = read.error; continue }
            return { present: false, type: '', title: '', url: '', source: '', ok: false, status: 'error', error: read.error }
        }

        if (!scannedAny) {
            return {
                present: false,
                type: '',
                title: '',
                url: '',
                source: '',
                ok: false,
                status: 'field_unavailable',
                error: lastFieldUnavailableError || 'cta_fields_unavailable',
            }
        }

        let hit: { type: string; title: string; url: string } | null = null
        let source = ''
        if (nodeJson) {
            hit = readCtaObject(nodeJson.call_to_action)
            if (hit) source = 'call_to_action'
        }
        if (!hit) {
            for (const att of attData) {
                const a = (att && typeof att === 'object') ? att as Record<string, unknown> : {}
                const aCta = readCtaObject(a.call_to_action)
                if (aCta) { hit = aCta; if (!hit.title) hit.title = String(a.title || '').trim(); source = 'attachment'; break }
            }
        }
        if (!hit) {
            for (const att of attData) {
                const a = (att && typeof att === 'object') ? att as Record<string, unknown> : {}
                const target = (a.target && typeof a.target === 'object') ? a.target as Record<string, unknown> : undefined
                const link = String(target?.url || a.unshimmed_url || a.url || '').trim()
                if (link) { hit = { type: String(a.type || '').trim(), title: String(a.title || '').trim(), url: link }; source = 'attachment_link'; break }
            }
        }
        if (!hit && nodeJson) {
            const topLink = String(nodeJson.link || '').trim()
            if (topLink) { hit = { type: '', title: '', url: topLink }; source = 'link' }
        }

        return {
            present: !!hit,
            type: hit?.type || '',
            title: hit?.title || '',
            url: hit?.url || '',
            source: hit ? source : '',
            ok: true,
            status: 'scanned',
            error: '',
        }
    }

    // Sequential, single-flight per row (no parallel fan-out) to keep Graph load low.
    for (const row of rows) {
        scanned++
        const videoId = String(row.video_id || '').trim()
        const cacheLink = String(row.shopee_link || '').trim()
        const originalPostId = String(row.post_id || '').trim()
        let postId = originalPostId
        let createdTime = String(row.created_time || '').trim()
        let caption = String(row.description || row.title || '')
        let foundLink = ''
        let source = ''
        let rowError = ''
        // Read-only comment-count fields. Default to a non-scanned ("skipped") state
        // so the old default behavior (no comment scan) is reflected truthfully.
        let pageCommentCount = 0
        let otherCommentCount = 0
        let pageCommentIds: string[] = []
        let commentScanStatus = 'skipped'
        // Sanitized reason for a failed comment scan (HTTP status + Graph code/type),
        // surfaced so an 'error' status is never reported with an empty reason.
        let commentScanError = ''
        let postIdResolutionStatus = postId ? 'cached' : 'unresolved'
        let postIdResolutionReason = postId ? 'cache_post_id_present' : 'post_id_missing'
        // Read-only CTA audit fields. Default to a non-scanned ("skipped") state so
        // rows reflect "no CTA read attempted" truthfully when include_cta is off.
        let ctaPresent = false
        let ctaType = ''
        let ctaTitle = ''
        let ctaUrl = ''
        let ctaSource = ''
        let ctaScanStatus = 'skipped'
        let ctaScanError = ''

        const markResolvedPostId = (candidate: unknown, status: string, reason: string): boolean => {
            const normalized = normalizeGraphPostId(candidate)
            if (!normalized) return false
            postId = normalized
            postIdResolutionStatus = status
            postIdResolutionReason = reason
            return true
        }
        const applyCommentScan = (
            scan: Awaited<ReturnType<typeof scanCommentWindow>>,
            scannedStatus: string,
            unresolvedReason: string,
        ) => {
            pageCommentCount = scan.pageCommentCount
            otherCommentCount = scan.otherCommentCount
            pageCommentIds = scan.pageCommentIds
            commentScanStatus = scan.ok ? scannedStatus : 'error'
            if (!scan.ok && scan.error) commentScanError = scan.error
            if (!postId && scan.resolvedPostId) {
                markResolvedPostId(scan.resolvedPostId, 'comment_id_prefix', `derived_from_${scannedStatus}`)
            }
            if (!postId) {
                postIdResolutionStatus = 'unresolved'
                postIdResolutionReason = scan.ok ? unresolvedReason : `${scannedStatus}_comment_scan_error`
            }
        }

        if (!videoId) {
            rowError = 'missing_video_id'
            errors.push({ video_id: '', error: rowError })
            items.push({ video_id: '', post_id: postId, created_time: createdTime, caption: caption.slice(0, 160), shopee_link: '', source: '', error: rowError, page_comment_count: 0, page_comment_ids: [], other_comment_count: 0, comment_scan_status: commentScanStatus, comment_scan_error: commentScanError, post_id_resolution_status: postIdResolutionStatus, post_id_resolution_reason: postIdResolutionReason, cta_present: ctaPresent, cta_type: ctaType, cta_title: ctaTitle, cta_url: ctaUrl, cta_source: ctaSource, cta_scan_status: ctaScanStatus, cta_scan_error: ctaScanError })
            continue
        }

        if (cacheLink) {
            // Already resolved in cache — count as existing, no link Graph call needed.
            foundLink = cacheLink
            source = 'cache'
            existing++
        }

        try {
            // 1. Graph GET: caption/title/permalink/post_id/created_time. Cached-link
            // rows skip this unless their post_id is missing and needs resolution.
            if (!cacheLink || !postId) {
                const vidResp = await fetch(
                    `https://graph.facebook.com/v21.0/${encodeURIComponent(videoId)}?fields=description,title,permalink_url,post_id,created_time&access_token=${encodeURIComponent(token)}`
                )
                const vid = vidResp.ok ? await vidResp.json().catch(() => ({})) as Record<string, unknown> : {}
                caption = String(vid.description || vid.title || caption || '')
                if (!createdTime) createdTime = String(vid.created_time || '').trim()
                const rawPostId = String(vid.post_id || '').trim()
                if (rawPostId) markResolvedPostId(rawPostId, 'graph_post_id', 'video_metadata_post_id')
                if (!cacheLink) {
                    const m1 = caption.match(shopeeRe)
                    if (m1) { foundLink = m1[0]; source = 'caption' }
                }
            }

            if (cacheLink) {
                // Preserve old behavior: do NOT scan comments for cached rows by
                // default. Exception: if post_id is still missing after the metadata
                // read, scan the video id target once to derive post_id from comment
                // ids. Once post_id is known (cached or just resolved) and the operator
                // asked for counts, re-scan the canonical post target so the counts and
                // status reflect the post — never left as scanned_via_video_id after a
                // post_id has been resolved in the same row.
                if (!postId) {
                    const scan = await scanCommentWindow(videoId)
                    applyCommentScan(scan, 'scanned_via_video_id', 'video_id_comments_no_post_id_prefix')
                }
                if (postId && includeCommentCounts) {
                    const commentTargetId = buildPostCommentTarget(postId)
                    const scan = await scanCommentWindow(commentTargetId)
                    applyCommentScan(scan, 'scanned', 'post_id_present')
                }
            } else {
                // 2. Read a small bounded comment window (limit 10) when post_id is
                //    missing (new video-id fallback), when we still need to resolve a
                //    link (existing behavior), OR when the operator asked for comment
                //    counts. Either way it is GET-only and single-flight per row.
                let usedVideoIdCommentScan = false
                if (!postId) {
                    const scan = await scanCommentWindow(videoId)
                    usedVideoIdCommentScan = true
                    applyCommentScan(scan, 'scanned_via_video_id', 'video_id_comments_no_post_id_prefix')
                    if (!foundLink) {
                        const commentLink = pickShopeeLinkFromComments(scan.data)
                        if (commentLink) { foundLink = commentLink; source = 'comment' }
                    }
                }

                // A link scan still avoids re-scanning when the video-id scan above
                // already covered it. A comment-count scan, however, ALWAYS re-targets
                // the canonical post once post_id is known — including a post_id just
                // derived by the video-id scan — so include_comment_counts rows report
                // 'scanned'/'error' for the canonical post, never scanned_via_video_id.
                const needLinkScan = !foundLink && !!postId && !usedVideoIdCommentScan
                const needCountScan = includeCommentCounts && !!postId
                if (needLinkScan || needCountScan) {
                    const commentTargetId = buildPostCommentTarget(postId)
                    const scan = await scanCommentWindow(commentTargetId)
                    applyCommentScan(scan, 'scanned', 'post_comments_no_post_id_prefix')
                    if (!foundLink) {
                        const commentLink = pickShopeeLinkFromComments(scan.data)
                        if (commentLink) { foundLink = commentLink; source = 'comment' }
                    }
                } else if (includeCommentCounts && !postId && !usedVideoIdCommentScan) {
                    commentScanStatus = 'no_post_id'
                }
            }
        } catch (err) {
            rowError = sanitizeGraphErrorText(String(err)).slice(0, 200)
            if ((includeCommentCounts || !postId) && !commentScanStatus.startsWith('scanned')) {
                commentScanStatus = 'error'
                if (!commentScanError) commentScanError = rowError
            }
            if (!postId) {
                postIdResolutionStatus = 'unresolved'
                postIdResolutionReason = 'post_id_resolution_error'
            }
        }

        // Read-only CTA audit: a SINGLE Graph GET per row, run after post_id/comment/
        // link resolution so it targets the canonical post (buildPostCommentTarget)
        // when a post_id exists, else the video/reel id. Sequential and single-flight
        // (no fan-out), matching the comment-scan discipline. Off by default (status
        // 'skipped'); never writes D1 and never mutates Facebook. cta_url is redacted
        // so neither the literal token nor an access_token=... pair can leak; normal
        // affiliate URLs (which never carry the token) pass through unchanged.
        if (includeCta) {
            const ctaTargetId = postId ? buildPostCommentTarget(postId) : videoId
            if (!ctaTargetId) {
                ctaScanStatus = 'no_target'
            } else {
                try {
                    const cta = await scanCtaTarget(ctaTargetId)
                    ctaPresent = cta.present
                    ctaType = cta.type
                    ctaTitle = cta.title
                    ctaUrl = sanitizeGraphErrorText(cta.url)
                    ctaSource = cta.source
                    ctaScanStatus = cta.status
                    ctaScanError = cta.ok ? '' : cta.error
                } catch (err) {
                    ctaScanStatus = 'error'
                    ctaScanError = sanitizeGraphErrorText(String(err)).slice(0, 200)
                }
            }
        }

        if (rowError) {
            errors.push({ video_id: videoId, error: rowError })
        }

        if (foundLink) {
            found++
            if (source === 'caption') sourceCounts.caption++
            else if (source === 'comment') sourceCounts.comment++
            else if (source === 'cache') sourceCounts.cache++
        } else if (!rowError) {
            missing++
        }

        // Write mode persists ONLY to the D1 cache: shopee_link + post_id (if newly
        // resolved) and audit timestamps. dry_run NEVER writes. No Facebook writes,
        // no comment edits, no customlink minting anywhere in this path.
        const postIdChanged = !!postId && postId !== originalPostId
        const linkChanged = !cacheLink && !!foundLink
        if (writeMode && (linkChanged || postIdChanged)) {
            await c.env.DB.prepare(
                `UPDATE facebook_page_video_cache
                 SET post_id = CASE WHEN ? != '' THEN ? ELSE post_id END,
                     shopee_link = CASE WHEN ? != '' THEN ? ELSE shopee_link END,
                     updated_at = datetime('now'),
                     fetched_at = datetime('now')
                 WHERE page_id = ? AND video_id = ?`
            ).bind(postIdChanged ? postId : '', postIdChanged ? postId : '', linkChanged ? foundLink : '', linkChanged ? foundLink : '', pageId, videoId).run().catch(() => { })
            updated++
        }

        items.push({
            video_id: videoId,
            post_id: postId,
            created_time: createdTime,
            caption: caption.slice(0, 160),
            shopee_link: foundLink,
            source,
            // Surface the sanitized comment-scan reason when there is no harder row
            // error, so an 'error' comment_scan_status is never empty/undiagnosable.
            error: rowError || commentScanError,
            page_comment_count: pageCommentCount,
            page_comment_ids: pageCommentIds.slice(0, 5),
            other_comment_count: otherCommentCount,
            comment_scan_status: commentScanStatus,
            comment_scan_error: commentScanError,
            post_id_resolution_status: postIdResolutionStatus,
            post_id_resolution_reason: postIdResolutionReason,
            cta_present: ctaPresent,
            cta_type: ctaType,
            cta_title: ctaTitle,
            cta_url: ctaUrl,
            cta_source: ctaSource,
            cta_scan_status: ctaScanStatus,
            cta_scan_error: ctaScanError,
        })
    }

    return c.json({
        ok: true,
        dry_run: dryRun,
        write_mode: writeMode,
        page_id: pageId,
        only_missing: onlyMissing,
        include_comment_counts: includeCommentCounts,
        include_cta: includeCta,
        ...facebookTokenDebugFields(commentTokenResolution),
        limit,
        offset,
        from_date: fromDate || null,
        to_date: toDate || null,
        scanned,
        found,
        updated,
        missing,
        existing,
        errors_count: errors.length,
        source_counts: sourceCounts,
        errors: errors.slice(0, 5),
        items,
    }, 200, {
        'Cache-Control': 'no-store',
    })
})

// Backfill shopee_link for facebook_page_video_cache rows that currently have empty shopee_link.
// Runs the same fallback chain used on sync, but over existing rows.
app.post('/api/dashboard/facebook-page-videos/backfill-shopee-links', async (c) => {
    const body = await c.req.json().catch(() => ({})) as {
        page_id?: string
        limit?: number
    }
    const pageId = String(body.page_id || '').trim()
    const limitRaw = Number(body.limit || 500)
    const limit = Number.isFinite(limitRaw) ? Math.min(5000, Math.max(1, Math.floor(limitRaw))) : 500

    const query = pageId
        ? c.env.DB.prepare(
            `SELECT page_id, video_id, post_id, description, title
             FROM facebook_page_video_cache
             WHERE (shopee_link = '' OR shopee_link IS NULL) AND page_id = ?
             LIMIT ?`
        ).bind(pageId, limit)
        : c.env.DB.prepare(
            `SELECT page_id, video_id, post_id, description, title
             FROM facebook_page_video_cache
             WHERE shopee_link = '' OR shopee_link IS NULL
             LIMIT ?`
        ).bind(limit)

    const result = await query.all().catch(() => null) as {
        results?: Array<{ page_id: string; video_id: string; post_id: string; description: string; title: string }>
    } | null
    const rows = Array.isArray(result?.results) ? result!.results : []

    let scanned = 0
    let updated = 0
    const examples: Array<{ video_id: string; shopee_link: string }> = []
    for (const row of rows) {
        scanned++
        const link = await resolveShopeeLinkForCacheRow(c.env.DB, {
            postId: String(row.post_id || ''),
            videoId: String(row.video_id || ''),
            description: String(row.description || row.title || ''),
        })
        if (!link) continue
        await c.env.DB.prepare(
            `UPDATE facebook_page_video_cache
             SET shopee_link = ?, updated_at = datetime('now')
             WHERE page_id = ? AND video_id = ?`
        ).bind(link, row.page_id, row.video_id).run().catch(() => { })
        updated++
        if (examples.length < 5) examples.push({ video_id: row.video_id, shopee_link: link })
    }

    return c.json({ ok: true, scanned, updated, examples }, 200, {
        'Cache-Control': 'no-store',
    })
})

// =====================================================================
// Ad Queue — store create-ad requests for cron to process every 20 min.
// User clicks "เพิ่มเข้าคิว" in dashboard → row inserted with status=queued.
// Cron picks oldest queued row every 20 min → calls create-ad logic →
// updates status to done/failed.
// =====================================================================
const AD_QUEUE_INTERVAL_MS = 20 * 60 * 1000  // 20 minutes
const AD_QUEUE_LAST_RUN_KEY = 'ad_queue_last_run_at'

async function ensureAdQueueTable(db: D1Database): Promise<void> {
    await db.prepare(
        `CREATE TABLE IF NOT EXISTS dashboard_ad_queue (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            created_at TEXT NOT NULL DEFAULT (datetime('now')),
            page_id TEXT NOT NULL,
            video_id TEXT NOT NULL,
            caption TEXT NOT NULL DEFAULT '',
            shopee_url TEXT NOT NULL DEFAULT '',
            story_id TEXT NOT NULL DEFAULT '',
            campaign_id TEXT NOT NULL DEFAULT '',
            new_campaign_name TEXT NOT NULL DEFAULT '',
            status TEXT NOT NULL DEFAULT 'queued',
            attempted_at TEXT NOT NULL DEFAULT '',
            completed_at TEXT NOT NULL DEFAULT '',
            error_message TEXT NOT NULL DEFAULT '',
            result_story_id TEXT NOT NULL DEFAULT '',
            result_ad_id TEXT NOT NULL DEFAULT '',
            result_adset_id TEXT NOT NULL DEFAULT ''
        )`
    ).run()
    // Schema migration: video_url column added 2026-05-01 to support gallery
    // (unposted) videos. SQLite has no `ADD COLUMN IF NOT EXISTS`, so swallow
    // the duplicate-column error on re-run.
    await db.prepare(
        `ALTER TABLE dashboard_ad_queue ADD COLUMN video_url TEXT NOT NULL DEFAULT ''`
    ).run().catch(() => undefined)
    await db.prepare(
        `ALTER TABLE dashboard_ad_queue ADD COLUMN ad_name TEXT NOT NULL DEFAULT ''`
    ).run().catch(() => undefined)
    await db.prepare(
        `CREATE INDEX IF NOT EXISTS idx_dashboard_ad_queue_status ON dashboard_ad_queue(status, created_at)`
    ).run()
}

app.post('/api/dashboard/ad-queue/enqueue', async (c) => {
    const body = await c.req.json().catch(() => ({})) as {
        page_id?: string
        video_id?: string
        video_url?: string
        ad_name?: string
        source_video_id?: string
        caption?: string
        shopee_url?: string
        story_id?: string
        campaign_id?: string
        new_campaign_name?: string
    }
    const pageId = String(body.page_id || '').trim()
    const videoId = String(body.video_id || '').trim()
    const videoUrl = String(body.video_url || '').trim()
    const adName = String(body.ad_name || body.source_video_id || '').trim()
    // Accept either video_id (for already-on-FB videos) or video_url (for unposted
    // gallery videos that the electron pipeline will upload to FB Ads first).
    if (!pageId || (!videoId && !videoUrl)) {
        return c.json({ ok: false, error: 'page_id and (video_id or video_url) required' }, 400)
    }
    if (!body.campaign_id && !body.new_campaign_name) {
        return c.json({ ok: false, error: 'campaign_id or new_campaign_name required' }, 400)
    }
    await ensureAdQueueTable(c.env.DB)
    const insert = await c.env.DB.prepare(
        `INSERT INTO dashboard_ad_queue (page_id, video_id, video_url, ad_name, caption, shopee_url, story_id, campaign_id, new_campaign_name)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`
    ).bind(
        pageId,
        videoId,
        videoUrl,
        adName,
        String(body.caption || '').trim(),
        String(body.shopee_url || '').trim(),
        String(body.story_id || '').trim(),
        String(body.campaign_id || '').trim(),
        String(body.new_campaign_name || '').trim(),
    ).run()
    const queueId = (insert as unknown as { meta?: { last_row_id?: number } }).meta?.last_row_id || 0
    const queuedCount = await c.env.DB.prepare(
        `SELECT COUNT(*) AS n FROM dashboard_ad_queue WHERE status = 'queued'`
    ).first() as { n?: number } | null
    const lastRun = await getDashboardSetting(c.env.DB, AD_QUEUE_LAST_RUN_KEY).catch(() => null)
    const lastRunMs = Date.parse(String(lastRun?.value || '').trim())
    const nextRunMs = Number.isFinite(lastRunMs) ? lastRunMs + AD_QUEUE_INTERVAL_MS : Date.now() + AD_QUEUE_INTERVAL_MS
    return c.json({
        ok: true,
        queue_id: queueId,
        queued_count: Number(queuedCount?.n || 0),
        next_run_at: new Date(nextRunMs).toISOString(),
    })
})

app.get('/api/dashboard/ad-queue/list', async (c) => {
    await ensureAdQueueTable(c.env.DB)
    const limitRaw = Number(c.req.query('limit') || 100)
    const limit = Number.isFinite(limitRaw) ? Math.min(500, Math.max(1, Math.floor(limitRaw))) : 100
    const status = String(c.req.query('status') || '').trim()
    const where = status ? `WHERE status = ?` : ''
    const stmt = status
        ? c.env.DB.prepare(`SELECT * FROM dashboard_ad_queue ${where} ORDER BY id DESC LIMIT ?`).bind(status, limit)
        : c.env.DB.prepare(`SELECT * FROM dashboard_ad_queue ORDER BY id DESC LIMIT ?`).bind(limit)
    const rows = await stmt.all() as { results?: Array<Record<string, unknown>> }
    const counts = await c.env.DB.prepare(
        `SELECT status, COUNT(*) AS n FROM dashboard_ad_queue GROUP BY status`
    ).all() as { results?: Array<{ status: string; n: number }> }
    const countsByStatus: Record<string, number> = {}
    for (const r of (counts.results || [])) countsByStatus[String(r.status)] = Number(r.n)
    const lastRun = await getDashboardSetting(c.env.DB, AD_QUEUE_LAST_RUN_KEY).catch(() => null)
    const lastRunMs = Date.parse(String(lastRun?.value || '').trim())
    const nextRunMs = Number.isFinite(lastRunMs) ? lastRunMs + AD_QUEUE_INTERVAL_MS : Date.now()
    return c.json({
        ok: true,
        items: rows.results || [],
        counts: countsByStatus,
        last_run_at: lastRun?.value || '',
        next_run_at: new Date(nextRunMs).toISOString(),
        interval_minutes: AD_QUEUE_INTERVAL_MS / 60000,
    }, 200, { 'Cache-Control': 'no-store' })
})

app.delete('/api/dashboard/ad-queue/:id', async (c) => {
    await ensureAdQueueTable(c.env.DB)
    const id = Number(c.req.param('id') || 0)
    if (!id) return c.json({ ok: false, error: 'id required' }, 400)
    await c.env.DB.prepare(
        `UPDATE dashboard_ad_queue SET status = 'cancelled', completed_at = datetime('now')
         WHERE id = ? AND status = 'queued'`
    ).bind(id).run()
    return c.json({ ok: true, id })
})

// Process the oldest queued item — runs from cron and from manual "run now" button.
async function processNextAdQueueItem(env: Env): Promise<{
    ok: boolean
    skipped?: boolean
    reason?: string
    queue_id?: number
    result?: unknown
    error?: string
}> {
    await ensureAdQueueTable(env.DB)
    const row = await env.DB.prepare(
        `SELECT * FROM dashboard_ad_queue WHERE status = 'queued' ORDER BY id ASC LIMIT 1`
    ).first() as Record<string, unknown> | null
    if (!row) return { ok: true, skipped: true, reason: 'queue_empty' }

    const queueId = Number(row.id)
    const nowIso = new Date().toISOString()
    // Mark processing (atomic-ish: only if still queued)
    const claim = await env.DB.prepare(
        `UPDATE dashboard_ad_queue SET status = 'processing', attempted_at = ? WHERE id = ? AND status = 'queued'`
    ).bind(nowIso, queueId).run()
    const claimed = (claim as unknown as { meta?: { changes?: number } }).meta?.changes || 0
    if (!claimed) return { ok: true, skipped: true, reason: 'claim_lost', queue_id: queueId }

    try {
        // Call our own create-ad endpoint via internal fetch.
        // Forward video_url too — if the queued row was enqueued from the
        // gallery tab (no FB video_id yet), this is what tells the electron
        // pipeline to upload the file to FB Ads first.
        const workerUrl = String(env.WORKER_URL || 'https://api.pubilo.com').trim().replace(/\/+$/, '')
        const resp = await fetch(`${workerUrl}/api/dashboard/create-ad`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                page_id: row.page_id,
                video_id: row.video_id,
                video_url: row.video_url || '',
                ad_name: row.ad_name || '',
                source_video_id: row.ad_name || '',
                caption: row.caption,
                story_id: row.story_id,
                shopee_url: row.shopee_url,
                campaign_id: row.campaign_id || undefined,
                new_campaign_name: row.new_campaign_name || undefined,
            }),
        })
        const data = await resp.json().catch(() => ({})) as Record<string, unknown>
        if (!resp.ok || !data.ok) {
            // Preserve the FULL failure context for debugging:
            //   [step] error_message — electron step name tells operator WHICH phase failed
            //   (upload / thumbnails / creative / campaign / copy / ad / story_id)
            //   Without step, "Invalid parameter" is unhelpful — FB returns the same vague
            //   string from 10+ different validation failures.
            const stepLabel = String(data.step || '').trim()
            const errorMsg = String(data.error || `http_${resp.status}`).trim()
            const combined = stepLabel ? `[${stepLabel}] ${errorMsg}` : errorMsg
            await env.DB.prepare(
                `UPDATE dashboard_ad_queue SET status = 'failed', completed_at = datetime('now'), error_message = ? WHERE id = ?`
            ).bind(combined.substring(0, 500), queueId).run()
            return { ok: false, queue_id: queueId, error: combined }
        }
        await env.DB.prepare(
            `UPDATE dashboard_ad_queue
             SET status = 'done', completed_at = datetime('now'),
                 result_story_id = ?, result_ad_id = ?, result_adset_id = ?, error_message = ''
             WHERE id = ?`
        ).bind(
            String(data.story_id || ''),
            String(data.ad_id || ''),
            String(data.adset_id || ''),
            queueId,
        ).run()
        return { ok: true, queue_id: queueId, result: data }
    } catch (e) {
        const msg = e instanceof Error ? e.message : String(e)
        await env.DB.prepare(
            `UPDATE dashboard_ad_queue SET status = 'failed', completed_at = datetime('now'), error_message = ? WHERE id = ?`
        ).bind(msg.substring(0, 500), queueId).run()
        return { ok: false, queue_id: queueId, error: msg }
    }
}

// Process the oldest queued item immediately, bypassing the 20-min cron interval.
// Doesn't take an id — always picks oldest queued. To prioritize a specific item,
// cancel newer items first.
app.post('/api/dashboard/ad-queue/run-next', async (c) => {
    await ensureAdQueueTable(c.env.DB)
    const result = await processNextAdQueueItem(c.env)
    return c.json(result, 200, { 'Cache-Control': 'no-store' })
})

// Recover a stuck "processing" item — used when create-ad on FB succeeded but the
// worker died before writing result back to DB. Caller looks up story_id by matching
// caption against recent FB posts then calls this with story_id + ad_id (optional).
// Marks status=done and saves result; optionally posts the comment if comment_text given.
app.post('/api/dashboard/ad-queue/:id/recover', async (c) => {
    await ensureAdQueueTable(c.env.DB)
    const id = Number(c.req.param('id') || 0)
    if (!id) return c.json({ ok: false, error: 'id required' }, 400)
    const body = await c.req.json().catch(() => ({} as { story_id?: string; ad_id?: string; adset_id?: string; status?: string })) as {
        story_id?: string; ad_id?: string; adset_id?: string; status?: 'done' | 'failed' | 'queued'
    }
    const status = body.status === 'failed' || body.status === 'queued' ? body.status : 'done'
    await c.env.DB.prepare(
        `UPDATE dashboard_ad_queue
         SET status = ?, completed_at = datetime('now'),
             result_story_id = COALESCE(NULLIF(?, ''), result_story_id),
             result_ad_id = COALESCE(NULLIF(?, ''), result_ad_id),
             result_adset_id = COALESCE(NULLIF(?, ''), result_adset_id),
             error_message = CASE WHEN ? = 'done' THEN '' ELSE error_message END
         WHERE id = ?`
    ).bind(
        status,
        String(body.story_id || '').trim(),
        String(body.ad_id || '').trim(),
        String(body.adset_id || '').trim(),
        status,
        id,
    ).run()
    return c.json({ ok: true, id, status })
})

// Watchdog — reset items stuck in 'processing' for too long.
// Called from cron (and on-demand). 5-min timeout (typical create-ad flow takes 60-120s).
async function recoverStuckAdQueueProcessing(env: Env): Promise<{ recovered: number }> {
    await ensureAdQueueTable(env.DB)
    const STUCK_THRESHOLD_MS = 5 * 60 * 1000
    const cutoffIso = new Date(Date.now() - STUCK_THRESHOLD_MS).toISOString()
    const stuck = await env.DB.prepare(
        `SELECT id FROM dashboard_ad_queue WHERE status = 'processing' AND attempted_at < ?`
    ).bind(cutoffIso).all() as { results?: Array<{ id: number }> }
    const ids = (stuck.results || []).map((r) => Number(r.id)).filter(Boolean)
    if (ids.length === 0) return { recovered: 0 }
    for (const id of ids) {
        await env.DB.prepare(
            `UPDATE dashboard_ad_queue
             SET status = 'failed', completed_at = datetime('now'),
                 error_message = COALESCE(NULLIF(error_message, ''), 'stuck_processing_timeout — verify on FB then call /recover')
             WHERE id = ? AND status = 'processing'`
        ).bind(id).run()
    }
    console.log(`[AD QUEUE WATCHDOG] reset ${ids.length} stuck processing items: ${ids.join(',')}`)
    return { recovered: ids.length }
}

app.post('/api/dashboard/create-ad', async (c) => {
    const body = await c.req.json().catch(() => ({})) as {
        page_id?: string
        video_url?: string
        video_id?: string
        caption?: string
        shopee_url?: string
        comment_shortlink?: string
        story_id?: string
        campaign_id?: string
        new_campaign_name?: string
        sub_id2?: string
        sub_id3?: string
        sub_id4?: string
        sub_id5?: string
        placement_template?: string
        template_adset?: string
        ad_name?: string
        source_video_id?: string
        skip_comment?: boolean
        skip_ad?: boolean
        skip_publish_to_page?: boolean
        daily_campaign_name?: string
    }
    const pageId = String(body.page_id || '').trim()
    const videoUrl = String(body.video_url || '').trim()
    const videoId = String(body.video_id || '').trim()
    const caption = String(body.caption || '').trim()
    const shopeeUrl = String(body.shopee_url || '').trim()
    // Optional explicit pre-shortened/managed comment link. The force-post / cron
    // Ads/Token branch already resolves a managed shortlink via
    // resolvePrePostingShortlinksForNamespace, so re-shortening it here double-shortens
    // an already-short link and fails with shortlink_failed. When this is a valid
    // http(s) URL we use it directly as the comment shortlink and skip our own fetch.
    const explicitCommentShortlink = String(body.comment_shortlink || '').trim()
    const hasExplicitCommentShortlink = /^https?:\/\//i.test(explicitCommentShortlink)
    const originalStoryId = String(body.story_id || '').trim()
    const lookupVideoId = videoId || (/^\d{8,}$/.test(originalStoryId) ? originalStoryId : '')
    const campaignId = String(body.campaign_id || '').trim()
    const newCampaignName = String(body.new_campaign_name || '').trim()
    const placementTemplate = String(body.placement_template || '').trim().toLowerCase()
    // When true, create the ad + publish the page post and return story_id, but do
    // NOT post the first comment here. The OneCard/Ads auto route (force-post/cron)
    // sets this so it can re-mint the comment shortlink with sub2=post id / sub3=page
    // id AFTER story_id exists, then post the single final comment itself. Without it,
    // this route would comment with the pre-posting link (sub2/sub3 blank) and the
    // caller would skip its corrected comment (no duplicate, but wrong link goes live).
    const skipComment = body.skip_comment === true
    // Post-first Phase A: forward skip_ad so the bridge publishes the page post and STOPS
    // (returns story_id + reusable video_id + thumbnail) without creating a campaign/adset/ad.
    const skipAd = body.skip_ad === true
    // Post-first (ad-story-first): create the ad + story but HOLD the page-feed publish so the
    // caller can finalize the visible CTA and publish the SAME story afterwards.
    const skipPublishToPage = body.skip_publish_to_page === true
    // Optional Bangkok-date daily campaign grouping (forwarded straight to the bridge buildAd path).
    const dailyCampaignName = String(body.daily_campaign_name || '').trim()
    const templateAdsetOverride = String(body.template_adset || '').trim()
    const adName = resolveCreateAdVideoName({
        explicitName: body.ad_name,
        sourceVideoId: body.source_video_id,
        videoUrl,
        videoId,
    })
    // Per-ad Sub ID overrides — when blank, fall back to settings defaults below.
    const overrideSub2 = String(body.sub_id2 || '').trim()
    const overrideSub3 = String(body.sub_id3 || '').trim()
    const overrideSub4 = String(body.sub_id4 || '').trim()
    const overrideSub5 = String(body.sub_id5 || '').trim()
    if (!pageId || (!videoUrl && !videoId)) return c.json({ error: 'page_id and video_url or video_id required' }, 400)

    // create-ad runs through the non-Electron Cloak FB posting bridge (apps/cloak-fb-bridge,
    // CLOAK_FB_BRIDGE_URL) /create-ad route. The retired Electron video-onecard app is gone;
    // fail closed with a precise `bridge_not_configured` error (not a vague invalid_response
    // from a dead tunnel) when the bridge URL is unset.
    const baseUrl = resolveCloakFbBridgeBaseUrl(c.env)
    if (!baseUrl) return c.json({ ok: false, error: 'bridge_not_configured', step: 'bridge_config' }, 503)
    try {
        // 1. Get settings + shortlink FIRST (need shortlink for caption). Read
        //    per-page so /chearb and /feed dashboards can hold different
        //    sub_ids / shortlink templates without leaking into each other.
        const settingsRow = await getPageSetting(c.env.DB, pageId, 'shortlink_url').catch(() => null)
        const subIdRow = await getPageSetting(c.env.DB, pageId, 'sub_id').catch(() => null)
        const shortlinkUrlTemplate = String(settingsRow?.value || DEFAULT_SHOPEE_SHORTLINK_URL_TEMPLATE).trim()
        const subId = String(subIdRow?.value || 'yok').trim()

        // 2. Find shopee link: first from facebook_page_video_cache, then post_history fallback
        let shopeeLink = shopeeUrl
        let thumbnailUrl = ''

        // Direct lookup from cache table. Keep the cached `picture` too: for already
        // posted page videos it is a valid FB thumbnail URL, and lets the CloakBrowser bridge
        // avoid calling `/{video_id}?fields=thumbnails` during temporary FB blocks.
        let cacheRow: { shopee_link?: string; post_id?: string; picture?: string } | null = null
        if (lookupVideoId) {
            cacheRow = await c.env.DB.prepare(
                `SELECT shopee_link, post_id, picture FROM facebook_page_video_cache WHERE page_id = ? AND video_id = ? LIMIT 1`
            ).bind(pageId, lookupVideoId).first().catch(() => null) as { shopee_link?: string; post_id?: string; picture?: string } | null
            if (cacheRow?.picture && /^https?:\/\//i.test(cacheRow.picture)) thumbnailUrl = cacheRow.picture
            if (cacheRow?.shopee_link) shopeeLink = cacheRow.shopee_link
        }

        // Direct lookup from cache table
        const shouldResolveOriginalShopee = /^https?:\/\/s\.shopee\.co\.th\//i.test(shopeeLink)
        if ((!shopeeLink || shouldResolveOriginalShopee) && lookupVideoId) {
            // Also try via post_id → post_history → namespace_video_state for ORIGINAL link
            if (cacheRow?.post_id) {
                const nvs = await c.env.DB.prepare(
                    `SELECT nvs.shopee_original_link, nvs.shopee_link FROM post_history ph
                     JOIN namespace_video_state nvs ON nvs.video_id = ph.video_id AND nvs.namespace_id = ph.bot_id
                     WHERE ph.bot_id = '1774858894802785816' AND ph.fb_post_id = ?
                     AND (nvs.shopee_original_link != '' OR nvs.shopee_link != '')
                     ORDER BY ph.posted_at DESC LIMIT 1`
                ).bind(cacheRow.post_id).first().catch(() => null) as { shopee_original_link?: string; shopee_link?: string } | null
                const resolvedShopeeLink = nvs?.shopee_original_link || nvs?.shopee_link || ''
                if (resolvedShopeeLink) shopeeLink = resolvedShopeeLink
            }
        }

        // Fallback: post_history via fb_reel_url
        if (!shopeeLink && lookupVideoId) {
            const mapped = await c.env.DB.prepare(
                `SELECT nvs.shopee_original_link, nvs.shopee_link FROM post_history ph
                 JOIN namespace_video_state nvs ON nvs.video_id = ph.video_id AND nvs.namespace_id = ph.bot_id
                 WHERE ph.bot_id = '1774858894802785816' AND ph.fb_reel_url LIKE ?
                 AND (nvs.shopee_original_link != '' OR nvs.shopee_link != '')
                 ORDER BY ph.posted_at DESC LIMIT 1`
            ).bind(`%${lookupVideoId}%`).first().catch(() => null) as { shopee_original_link?: string; shopee_link?: string } | null
            const mappedShopeeLink = mapped?.shopee_original_link || mapped?.shopee_link || ''
            if (mappedShopeeLink) shopeeLink = mappedShopeeLink
        }

        // Fallback: ANY shopee_link from post_history matching same caption
        if (!shopeeLink && caption) {
            const byCaption = await c.env.DB.prepare(
                `SELECT nvs.shopee_original_link, nvs.shopee_link FROM namespace_video_state nvs
                 JOIN post_history ph ON ph.video_id = nvs.video_id AND ph.bot_id = nvs.namespace_id
                 WHERE nvs.namespace_id = '1774858894802785816'
                 AND (nvs.shopee_original_link != '' OR nvs.shopee_link != '')
                 ORDER BY ph.posted_at DESC LIMIT 1`
            ).first().catch(() => null) as { shopee_original_link?: string; shopee_link?: string } | null
            // Don't use random fallback — only use if we're sure
        }

        // Fallback: from caption text
        if (!shopeeLink) {
            const descMatch = caption.match(/https?:\/\/(?:[^\s]+\.)?shopee\.[^\s]+/i)
            if (descMatch) shopeeLink = descMatch[0]
        }

        // If the page-card supplied an already-short Shopee URL, short.wwoom may
        // fail to fetch it. When we have the internal system video id as adName,
        // recover the original Shopee URL from gallery/state and shorten that —
        // matching the normal dashboard data source instead of re-shortening s.shopee.
        if (/^https?:\/\/s\.shopee\.co\.th\//i.test(shopeeLink) && adName) {
            const originalBySystemId = await c.env.DB.prepare(
                `SELECT COALESCE(NULLIF(TRIM(nvs.shopee_original_link), ''), NULLIF(TRIM(gi.shopee_original_link), '')) AS original_link
                 FROM gallery_index gi
                 LEFT JOIN namespace_video_state nvs ON nvs.namespace_id = gi.namespace_id AND nvs.video_id = gi.video_id
                 WHERE gi.namespace_id = '1774858894802785816' AND gi.video_id = ?
                 LIMIT 1`
            ).bind(adName).first().catch(() => null) as { original_link?: string } | null
            if (originalBySystemId?.original_link && /^https?:\/\//i.test(originalBySystemId.original_link)) {
                shopeeLink = originalBySystemId.original_link
            }
        }

        // ALWAYS shorten with current sub_ids — per-ad override (from popup
        // input) wins over per-page settings. Empty override = fall back to
        // settings.subId2-5 (the page-level default).
        const subId2Row = overrideSub2 ? null : await getPageSetting(c.env.DB, pageId, 'sub_id2').catch(() => null)
        const subId3Row = overrideSub3 ? null : await getPageSetting(c.env.DB, pageId, 'sub_id3').catch(() => null)
        const subId4Row = overrideSub4 ? null : await getPageSetting(c.env.DB, pageId, 'sub_id4').catch(() => null)
        const subId5Row = overrideSub5 ? null : await getPageSetting(c.env.DB, pageId, 'sub_id5').catch(() => null)
        const sub2 = overrideSub2 || String(subId2Row?.value || '').trim()
        const sub3 = overrideSub3 || String(subId3Row?.value || '').trim()
        const sub4 = overrideSub4 || String(subId4Row?.value || '').trim()
        const sub5 = overrideSub5 || String(subId5Row?.value || '').trim()

        let shortLink = ''
        if (hasExplicitCommentShortlink) {
            // Caller supplied an already-shortened managed link (force-post / cron
            // Ads/Token path). Trust it verbatim and skip the legacy short.wwoom fetch
            // so we never double-shorten. shopeeLink is still used for the CTA button.
            shortLink = explicitCommentShortlink
        } else if (shopeeLink) {
            // Replace all placeholders in template
            let shortlinkUrl = shortlinkUrlTemplate
                .replace('{url}', encodeURIComponent(shopeeLink))
                .replace('{sub_id}', encodeURIComponent(subId))
                .replace('{sub_id2}', encodeURIComponent(sub2))
                .replace('{sub_id3}', encodeURIComponent(sub3))
                .replace('{sub_id4}', encodeURIComponent(sub4))
                .replace('{sub_id5}', encodeURIComponent(sub5))
            try {
                const slResp = await fetch(shortlinkUrl, { method: 'GET' })
                if (slResp.ok) {
                    const slData = await slResp.json().catch(() => ({})) as Record<string, unknown>
                    shortLink = String(slData.shortLink || slData.short_link || '').trim()
                }
            } catch {}
        }

        // 3. Stop if no shopee link found
        if (!shopeeLink) {
            return c.json({ ok: false, error: 'ไม่พบลิ้ง Shopee สำหรับวีดีโอนี้', step: 'shopee_link_not_found', video_id: lookupVideoId || videoId }, 400)
        }
        if (!shortLink) {
            return c.json({ ok: false, error: 'ย่อลิ้ง Shopee ไม่สำเร็จ', step: 'shortlink_failed', video_id: lookupVideoId || videoId, shopeeLink }, 400)
        }

        // 4. Caption: default to exactly what the operator typed/pulled (caption +
        // hashtags only, NO shortlink prefix) — matching the cron post format. The
        // shortlink otherwise lives in the first comment + the ad's CTA button only.
        // EXCEPTION: when the page has caption_link_enabled=1 (UI toggle
        // "ใส่ลิงก์ในแคปชั่น") the managed shortlink is prepended as the first caption
        // line, so OneCard/Ads page posts honor the toggle just like organic Reels.
        // buildCaptionLinkFirstDescription is idempotent, so a caller that already
        // prepended the same link won't double it.
        const cleanShortLink = shortLink.replace(/\?lp=aff$/, '').replace(/&lp=aff$/, '')
        const pageCaptionLinkRow = await getPageCaptionLinkEnabled(c.env.DB, pageId).catch(() => false)
        const finalCaption = (pageCaptionLinkRow && cleanShortLink)
            ? buildCaptionLinkFirstDescription(caption, cleanShortLink)
            : caption

        // 4. Create ad with final caption.
        // CTA button (SHOP_NOW) → shopee_url (real Shopee link, like the template)
        // Caption + comment text → cleanShortLink (wwoom for affiliate tracking)
        // Both are passed; the CloakBrowser bridge prefers shopee_url for the button destination.
        //
        // IMPORTANT: forward template_adset + ad_account FROM DASHBOARD SETTINGS so the
        // operator's configured template (read from dashboard_settings.template_adset) is
        // actually used. Before this fix, electron.js fell back to its retired pre-SALES
        // hardcoded default whenever these weren't in the body — meaning changing the
        // template in Settings UI had NO effect on real ad creation. electron.js also
        // reads call_to_action_type dynamically from the template adset's first ad, so
        // whatever CTA the operator set in their new template (SHOP_NOW, LEARN_MORE,
        // LIKE_PAGE, etc.) automatically flows through.
        const templateSettingKey = placementTemplate === 'facebook'
            ? 'template_adset_facebook'
            : (placementTemplate === 'instagram' ? 'template_adset_instagram' : 'template_adset')
        const templateAdsetRow = await getPageSetting(c.env.DB, pageId, templateSettingKey).catch(() => null)
        const fallbackTemplateAdsetRow = templateSettingKey === 'template_adset'
            ? null
            : await getPageSetting(c.env.DB, pageId, 'template_adset').catch(() => null)
        const facebookTemplateAdsetRow = await getPageSetting(c.env.DB, pageId, 'template_adset_facebook').catch(() => null)
        const adAccountRow = await getPageSetting(c.env.DB, pageId, 'ad_account').catch(() => null)
        const templateAdsetFromSettings = templateAdsetOverride || String(templateAdsetRow?.value || fallbackTemplateAdsetRow?.value || '').trim()
        const facebookTemplateAdset = String(facebookTemplateAdsetRow?.value || '').trim()
        const adAccountFromSettings = String(adAccountRow?.value || '').trim()

        const callVideoOnecardCreateAd = async (templateAdsetForAttempt: string, fallbackReason = '') => {
            const onecardResp = await fetch(`${baseUrl}/create-ad`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    page_id: pageId,
                    ...(videoUrl ? { video_url: videoUrl } : { video_id: videoId }),
                    caption: finalCaption,
                    ...(adName ? { ad_name: adName, source_video_id: adName } : {}),
                    shortlink: cleanShortLink,
                    shopee_url: shopeeLink,
                    ...(thumbnailUrl ? { thumbnail_url: thumbnailUrl } : {}),
                    ...(templateAdsetForAttempt ? { template_adset: templateAdsetForAttempt } : {}),
                    ...(adAccountFromSettings ? { ad_account: adAccountFromSettings } : {}),
                    ...(fallbackReason ? { fallback_reason: fallbackReason } : {}),
                    ...(placementTemplate === 'instagram' || skipPublishToPage ? { skip_publish_to_page: true } : {}),
                    ...(skipAd ? { skip_ad: true } : {}),
                    ...(dailyCampaignName ? { daily_campaign_name: dailyCampaignName } : {}),
                    // New campaign name must win over selected existing campaign.
                    // UI can keep an existing campaign highlighted while operator types
                    // a duplicate-name campaign; sending campaign_id here would merge the
                    // new adset into the old campaign instead of creating a new campaign.
                    ...(!newCampaignName && campaignId ? { campaign_id: campaignId } : {}),
                    ...(newCampaignName ? { new_campaign_name: newCampaignName } : {}),
                }),
            })
            const text = await onecardResp.text()
            let parsed: Record<string, unknown>
            try {
                parsed = text ? JSON.parse(text) as Record<string, unknown> : { ok: false, error: 'empty_response' }
            } catch {
                parsed = {
                    ok: false,
                    error: 'invalid_response',
                    step: 'video_onecard_response',
                    upstream_status: onecardResp.status,
                    upstream_content_type: onecardResp.headers.get('content-type') || '',
                    upstream_preview: text.substring(0, 300),
                }
            }
            return { resp: onecardResp, data: parsed }
        }

        // Cloak and Electron Ads sources share this SAME create-ad route — it already
        // targets the CloakBrowser/session-cookie bridge via baseUrl. No
        // separate provider branch; no stored/manual token is used by the bridge.
        let { resp, data } = await callVideoOnecardCreateAd(templateAdsetFromSettings)
        const isIgUnsupportedMedia = Number(data.fb_error_code || 0) === 100
            && Number(data.fb_error_subcode || 0) === 1443078
            && /instagram|ig/i.test(String(data.fb_error_user_msg || data.error || ''))
        // If operator selected Instagram, keep it Instagram. Do NOT auto-fallback
        // to Facebook placements: Thanwa wants IG-only to create an ad only, with
        // no page-feed publish/comment side effects.
        if (isIgUnsupportedMedia && placementTemplate === 'instagram') {
            console.log(`[CREATE-AD] IG template rejected media for video=${videoId}; keeping IG-only failure visible (no FB fallback)`)
        }
        if (!data.ok || !data.story_id) {
            return c.json(data, resp.ok ? 200 : 502)
        }

        // 5. Comment on the post with shortlink.
        // Token priority for COMMENTING:
        //   1) Per-namespace dedicated comment token (LIFF settings → ตั้งค่า → คอมเม้น)
        //      — single source of truth across cron, force-post, and dashboard ads.
        //   2) Fallback: PAGE access_token from /me/accounts via electron user token
        //      (legacy behavior).
        // namespaceId derived from pages.bot_id since this dashboard endpoint accepts
        // page_id as the only routing input.
        let commentId = ''
        let commentError = ''
        let commentTargetId = ''
        if (cleanShortLink && placementTemplate !== 'instagram' && !skipComment) {
            const storyId = String(data.story_id || '').trim()
            try {
                let commentToken = ''
                // Look up the namespace this page belongs to → load dedicated comment token
                const pageRow = await c.env.DB.prepare(
                    'SELECT bot_id FROM pages WHERE id = ? LIMIT 1'
                ).bind(pageId).first().catch(() => null) as { bot_id?: string } | null
                const pageNamespaceId = String(pageRow?.bot_id || '').trim()
                const commentText = await buildAffiliateCommentMessage(c.env.DB, pageNamespaceId, cleanShortLink)
                if (pageNamespaceId) {
                    commentToken = await resolveNamespaceDedicatedCommentToken(c.env.DB, pageNamespaceId).catch(() => '')
                    if (commentToken) {
                        console.log(`[CREATE-AD] Using namespace dedicated comment token for ns=${pageNamespaceId}`)
                    }
                }

                // Fallback: page access_token from /me/accounts (legacy behavior)
                if (!commentToken) {
                    const pagesResp = await fetch(`${baseUrl}/graph?path=${encodeURIComponent('me/accounts')}&fields=id,access_token&limit=100`)
                    const pagesData = await pagesResp.json().catch(() => ({})) as { data?: Array<{ id: string; access_token: string }> }
                    const pageEntry = (pagesData.data || []).find((p) => p.id === pageId)
                    commentToken = pageEntry?.access_token || ''
                }

                const postComment = async (token: string, targetId: string) => {
                    if (!token || !targetId || !commentText) return {} as Record<string, unknown>
                    const commentResp = await fetch(`${baseUrl}/graph?path=${encodeURIComponent(targetId)}/comments`, {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ message: commentText, access_token: token }),
                    })
                    return await commentResp.json().catch(() => ({})) as Record<string, unknown>
                }

                const tryCommentTargets = async (token: string, tokenLabel: string) => {
                    // Dark ad story IDs can be inaccessible/comment-blocked via Graph even
                    // after is_published=true. For dashboard page-post boosts, the source
                    // video_id is the actual page post/reel and is commentable, so fall
                    // back to it instead of reporting "ข้าม".
                    const targets = [storyId, videoId].map((v) => String(v || '').trim()).filter(Boolean)
                    const uniqueTargets = Array.from(new Set(targets))
                    let lastData = {} as Record<string, unknown>
                    for (const targetId of uniqueTargets) {
                        const data = await postComment(token, targetId)
                        lastData = data
                        if (!data.error && data.id) {
                            commentTargetId = targetId
                            return data
                        }
                        if (data.error) {
                            commentError = String((data.error as any)?.message || JSON.stringify(data.error)).substring(0, 240)
                            console.error(`[CREATE-AD] Comment error with ${tokenLabel} token target=${targetId}: ${JSON.stringify(data.error).substring(0, 200)}`)
                        }
                    }
                    return lastData
                }

                if (commentToken && commentText && (storyId || videoId)) {
                    // First try the dedicated token across storyId → source videoId.
                    // If it fails, fall back to the page token from /me/accounts.
                    let commentData = await tryCommentTargets(commentToken, 'primary')
                    if (commentData.error || !commentData.id) {
                        const pagesResp = await fetch(`${baseUrl}/graph?path=${encodeURIComponent('me/accounts')}&fields=id,access_token&limit=100`)
                        const pagesData = await pagesResp.json().catch(() => ({})) as { data?: Array<{ id: string; access_token: string }> }
                        const pageEntry = (pagesData.data || []).find((p) => p.id === pageId)
                        const fallbackToken = pageEntry?.access_token || ''
                        if (fallbackToken && fallbackToken !== commentToken) {
                            commentData = await tryCommentTargets(fallbackToken, 'fallback')
                        }
                    }
                    commentId = String(commentData.id || '').trim()
                }
            } catch (e) {
                commentError = e instanceof Error ? e.message : String(e)
                console.error(`[CREATE-AD] Comment exception: ${commentError}`)
            }
        }

        return c.json({
            ...data,
            shortLink,
            commentId,
            commentTargetId,
            commentPosted: !!commentId,
            // Tell the caller this route deliberately did not comment so it can post
            // the re-minted (sub2/sub3) final comment without risking a duplicate.
            commentSkipped: skipComment,
            ...(commentId ? {} : { commentError }),
        })
    } catch (e) {
        return c.json({ ok: false, error: e instanceof Error ? e.message : String(e) }, 502)
    }
})

// =====================================================================
// Create Ads contract — POST /api/dashboard/create-ad-only + GET /api/dashboard/ad-history.
//
// The endpoint name is kept for compatibility. The product contract is:
// old high-performing Page post/video = source signal only → resolve the matching system video/content
// → create a PAID ad/dark story only. It must NEVER publish a new visible Page post; normal Page posts
// live exclusively in POST /api/pages/:id/force-post. This is deliberately separate from:
//   - POST /api/pages/:id/force-post   (Page Post flow → post_history, cron — NEVER touched here)
//   - POST /api/dashboard/create-ad    (legacy mixed helper — not called by this endpoint)
// It NEVER writes post_history; every attempt is recorded in its OWN audit table dashboard_ad_history.
// =====================================================================
async function ensureAdHistoryTable(db: D1Database): Promise<void> {
    await db.prepare(
        `CREATE TABLE IF NOT EXISTS dashboard_ad_history (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            created_at TEXT NOT NULL DEFAULT (datetime('now')),
            completed_at TEXT NOT NULL DEFAULT '',
            status TEXT NOT NULL DEFAULT 'pending',
            page_id TEXT NOT NULL,
            source_story_id TEXT NOT NULL DEFAULT '',
            source_post_id TEXT NOT NULL DEFAULT '',
            fb_video_id TEXT NOT NULL DEFAULT '',
            system_video_id TEXT NOT NULL DEFAULT '',
            campaign_id TEXT NOT NULL DEFAULT '',
            campaign_name TEXT NOT NULL DEFAULT '',
            adset_id TEXT NOT NULL DEFAULT '',
            ad_id TEXT NOT NULL DEFAULT '',
            creative_id TEXT NOT NULL DEFAULT '',
            effective_object_story_id TEXT NOT NULL DEFAULT '',
            click_link TEXT NOT NULL DEFAULT '',
            error_message TEXT NOT NULL DEFAULT '',
            truncated_result_json TEXT NOT NULL DEFAULT ''
        )`
    ).run()
    // Safe ALTER ADD COLUMN pattern (SQLite has no IF NOT EXISTS for columns) — matches
    // ensureAdQueueTable. Swallow the duplicate-column error on re-run so future columns can be
    // added without a destructive migration.
    await db.prepare(
        `ALTER TABLE dashboard_ad_history ADD COLUMN completed_at TEXT NOT NULL DEFAULT ''`
    ).run().catch(() => undefined)
    // Operator scheduling/budget audit columns (backward-compatible, additive). mode/run_hours are
    // worker-side intent; daily_budget (minor units) / start_time / end_time are echoed from the
    // bridge on the active/scheduled path. Each ALTER swallows the duplicate-column error on re-run.
    for (const col of [
        `ALTER TABLE dashboard_ad_history ADD COLUMN mode TEXT NOT NULL DEFAULT ''`,
        `ALTER TABLE dashboard_ad_history ADD COLUMN daily_budget TEXT NOT NULL DEFAULT ''`,
        `ALTER TABLE dashboard_ad_history ADD COLUMN run_hours TEXT NOT NULL DEFAULT ''`,
        `ALTER TABLE dashboard_ad_history ADD COLUMN start_time TEXT NOT NULL DEFAULT ''`,
        `ALTER TABLE dashboard_ad_history ADD COLUMN end_time TEXT NOT NULL DEFAULT ''`,
        // Auto-pause audit columns (additive). After a system-created ACTIVE ad-only campaign's run
        // window ends (end_time <= now), the cron turns it OFF via the bridge /pause-ad-only route —
        // status=PAUSED only, NEVER deleted. auto_paused_at is set ONLY on a confirmed pause so a
        // failed attempt is retried on the next cron; *_status_after hold the Graph read-back.
        `ALTER TABLE dashboard_ad_history ADD COLUMN auto_paused_at TEXT NOT NULL DEFAULT ''`,
        `ALTER TABLE dashboard_ad_history ADD COLUMN auto_pause_status TEXT NOT NULL DEFAULT ''`,
        `ALTER TABLE dashboard_ad_history ADD COLUMN auto_pause_error TEXT NOT NULL DEFAULT ''`,
        `ALTER TABLE dashboard_ad_history ADD COLUMN campaign_status_after TEXT NOT NULL DEFAULT ''`,
        `ALTER TABLE dashboard_ad_history ADD COLUMN adset_status_after TEXT NOT NULL DEFAULT ''`,
        `ALTER TABLE dashboard_ad_history ADD COLUMN ad_status_after TEXT NOT NULL DEFAULT ''`,
        // Lane column (additive). The Follow lane stamps lane='follow'; the click-link lane leaves it
        // blank. Persisted so the 24h Follow→Click-link handoff can SELECT finished Follow rows directly.
        `ALTER TABLE dashboard_ad_history ADD COLUMN lane TEXT NOT NULL DEFAULT ''`,
        // 24h Follow→Click-link handoff audit (additive). After a Follow ad's run window ends and it is
        // turned OFF (auto_paused_at set), the SAME source system video creates a click-link ad in the
        // page's fixed click-link adset. click_link_handoff_at is the one-shot idempotency stamp (set
        // only on a created/skipped handoff, so a transient failure re-qualifies on the next tick).
        `ALTER TABLE dashboard_ad_history ADD COLUMN click_link_handoff_at TEXT NOT NULL DEFAULT ''`,
        `ALTER TABLE dashboard_ad_history ADD COLUMN click_link_handoff_ad_id TEXT NOT NULL DEFAULT ''`,
        `ALTER TABLE dashboard_ad_history ADD COLUMN click_link_handoff_status TEXT NOT NULL DEFAULT ''`,
        `ALTER TABLE dashboard_ad_history ADD COLUMN click_link_handoff_error TEXT NOT NULL DEFAULT ''`,
        // Follow-lane REMOVAL audit (additive). The corrected Follow lifecycle ARCHIVES (removes) the
        // finished Follow ad from Ads instead of pausing it — pausing alone leaves the LIKE_PAGE button
        // bound to the story and blocks the click-link handoff. follow_removed_at is set ONLY on a
        // confirmed archive read-back, and is the gate the Follow→Click-link handoff requires (NOT
        // auto_paused_at). A transient archive failure leaves it empty so the next cron tick retries.
        `ALTER TABLE dashboard_ad_history ADD COLUMN follow_removed_at TEXT NOT NULL DEFAULT ''`,
        `ALTER TABLE dashboard_ad_history ADD COLUMN follow_removed_status TEXT NOT NULL DEFAULT ''`,
        `ALTER TABLE dashboard_ad_history ADD COLUMN follow_removed_error TEXT NOT NULL DEFAULT ''`,
    ]) {
        await db.prepare(col).run().catch(() => undefined)
    }
    await db.prepare(
        `CREATE INDEX IF NOT EXISTS idx_dashboard_ad_history_page ON dashboard_ad_history(page_id, id)`
    ).run()
    await db.prepare(
        `CREATE INDEX IF NOT EXISTS idx_dashboard_ad_history_status ON dashboard_ad_history(status, id)`
    ).run()
}

async function insertAdHistoryRow(db: D1Database, rec: AdHistoryRecord, completed: boolean): Promise<number> {
    const res = await db.prepare(
        `INSERT INTO dashboard_ad_history
           (completed_at, status, page_id, source_story_id, source_post_id, fb_video_id, system_video_id,
            campaign_id, campaign_name, adset_id, ad_id, creative_id, effective_object_story_id,
            click_link, error_message, truncated_result_json,
            mode, daily_budget, run_hours, start_time, end_time, lane)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`
    ).bind(
        completed ? new Date().toISOString() : '',
        rec.status, rec.page_id, rec.source_story_id, rec.source_post_id, rec.fb_video_id, rec.system_video_id,
        rec.campaign_id, rec.campaign_name, rec.adset_id, rec.ad_id, rec.creative_id, rec.effective_object_story_id,
        rec.click_link, rec.error_message, rec.truncated_result_json,
        rec.mode, rec.daily_budget, rec.run_hours, rec.start_time, rec.end_time, rec.lane,
    ).run()
    return (res as unknown as { meta?: { last_row_id?: number } }).meta?.last_row_id || 0
}

