// Create ONE Follow ad this tick, resilient to a bad page/candidate: walk the ranked cross-page
// candidate list (same eligibility/dedup/cooldown as the click-link auto-pick) and try the next page
// when one fails, up to AD_ONLY_AUTO_MAX_ATTEMPTS. Each create routes through create-ad-only with a
// lane='follow' body. create-ad-only returns HTTP 200 ok:false on failure, so success gates on data.ok.
async function processOneFollowAd(env: Env): Promise<{ ok: boolean; reason?: string; error?: string; result?: unknown; attempted?: number; failedPages?: string[] }> {
    const candidates = await autoPickAdOnlyCandidates(env)
    if (!candidates.length) return { ok: true, reason: 'no_eligible_candidate' }

    const mode = await getFollowAdMode(env.DB)
    // Follow lane must always group each day's proof/live ads under the Bangkok date-named campaign,
    // even in PAUSED review mode. PAUSED still never spends, but the Ads Manager campaign remains
    // discoverable as e.g. 25/Jun/2026 instead of falling back to ADS_PUBLISH_*.
    const dailyCampaignName = bangkokDailyCampaignName()
    const workerUrl = String(env.WORKER_URL || 'https://api.pubilo.com').trim().replace(/\/+$/, '')
    const maxAttempts = Math.min(AD_ONLY_AUTO_MAX_ATTEMPTS, candidates.length)
    const failedPages: string[] = []
    let lastError = ''
    let lastResult: unknown
    for (let i = 0; i < maxAttempts; i++) {
        const candidate = candidates[i]
        const fixedCampaignRow = await getPageSetting(env.DB, candidate.pageId, FOLLOW_LANE_FIXED_CAMPAIGN_ID_SETTING_KEY).catch(() => null)
        const fixedAdsetRow = await getPageSetting(env.DB, candidate.pageId, FOLLOW_LANE_FIXED_ADSET_ID_SETTING_KEY).catch(() => null)
        const fixedCampaignId = String(fixedCampaignRow?.value || '').trim()
        const fixedAdsetId = String(fixedAdsetRow?.value || '').trim()
        const reqBody = buildFollowAutoPickBody({
            candidate,
            mode,
            dailyCampaignName: fixedAdsetId ? '' : dailyCampaignName,
            templateAdset: FOLLOW_LANE_TEMPLATE_ADSET,
            campaignSub1: FOLLOW_LANE_SHORTLINK_SUB1_DEFAULT,
            fixedCampaignId,
            fixedAdsetId,
        })
        try {
            const resp = await fetch(`${workerUrl}/api/dashboard/create-ad-only`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(reqBody),
            })
            const data = await resp.json().catch(() => ({})) as Record<string, unknown>
            if (resp.ok && data.ok) return { ok: true, result: data, attempted: i + 1 }
            lastError = String(data.error || `http_${resp.status}`).trim()
            lastResult = data
        } catch (e) {
            lastError = e instanceof Error ? e.message : String(e)
        }
        failedPages.push(candidate.pageId)
        console.warn(`[FOLLOW-AD] attempt ${i + 1}/${maxAttempts} page=${candidate.pageId} video=${candidate.videoId} failed: ${lastError}`)
    }
    return {
        ok: false,
        error: lastError,
        result: lastResult,
        attempted: maxAttempts,
        failedPages,
        reason: `all_attempts_failed attempted=${maxAttempts} failed_pages=${failedPages.join(',')} last_error=${lastError}`.slice(0, 300),
    }
}

// Manual "run now" for the Follow lane — process immediately, bypassing the interval gate. The create
// call can outrun browser/tool HTTP timeouts, so accept fast and finish in waitUntil.
app.post('/api/dashboard/follow-ad/run-next', async (c) => {
    c.executionCtx.waitUntil(
        processOneFollowAd(c.env).then((result) => {
            console.log(`[FOLLOW-AD] manual run-next ok=${result.ok}${result.attempted ? ` attempted=${result.attempted}` : ''} ${result.reason ? `reason=${result.reason}` : ''} ${result.error ? `error=${result.error}` : ''}`)
        }).catch((error) => {
            console.error(`[FOLLOW-AD] manual run-next failed: ${error instanceof Error ? error.message : String(error)}`)
        })
    )
    return c.json({ ok: true, accepted: true }, 202, { 'Cache-Control': 'no-store' })
})

// Cron entrypoint — create AT MOST ONE Follow ad per operator-set interval, ONLY when the Follow
// scheduler is enabled. The cadence is JITTERED: instead of firing on an exact last_run + interval
// boundary (the lockstep pattern Meta flags as automated), the due time is interval + a bounded random
// offset, stored as an absolute slot (follow_ad_next_run_at) that cron claims once reached. The worker
// request never sleeps — it just reads/derives/stores the timestamp. Claims the cadence slot (sets
// last_run) BEFORE creating so a slow create can't be double-claimed by the next minute's tick, and
// RE-SCHEDULES the next jittered slot from "now" after the run so the gap stays ≈ interval, never exact.
// Never throws (cron must not be derailed).
async function maybeProcessFollowAdOnSchedule(env: Env): Promise<{ ran: boolean; reason?: string }> {
    try {
        const enabled = await isFollowAdSchedulerEnabled(env.DB)
        if (!enabled) return { ran: false, reason: 'scheduler_disabled' }
        const interval = await getFollowAdIntervalMinutes(env.DB)
        const nowMs = Date.now()
        const lastRun = await getDashboardSetting(env.DB, FOLLOW_AD_SCHED_LAST_RUN_KEY).catch(() => null)
        const storedNext = await getDashboardSetting(env.DB, FOLLOW_AD_SCHED_NEXT_RUN_KEY).catch(() => null)
        const decision = decideJitteredScheduleRun({
            nowMs,
            lastRunMs: Date.parse(String(lastRun?.value || '')),
            storedNextRunMs: parseFollowAdNextRunMs(storedNext?.value),
            intervalMinutes: interval,
            rng: makeSeededRng(nowMs),
        })
        if (!decision.due) {
            // First time we derive a jittered slot we persist it, so subsequent ticks gate on the SAME
            // scattered timestamp instead of re-rolling the jitter (and drifting) every minute.
            if (decision.persistNextRun) {
                await setDashboardSetting(env.DB, FOLLOW_AD_SCHED_NEXT_RUN_KEY, new Date(decision.nextRunAtMs).toISOString()).catch(() => null)
            }
            return { ran: false, reason: 'jitter_pending' }
        }
        // Claim the slot: stamp last_run now and pre-arm the NEXT jittered due time from now, so a slow
        // create can't be double-claimed and the following gap is interval + fresh jitter (not exact).
        await setDashboardSetting(env.DB, FOLLOW_AD_SCHED_LAST_RUN_KEY, new Date(nowMs).toISOString()).catch(() => null)
        const nextRunMs = computeJitteredNextRunAtMs({ baseMs: nowMs, intervalMinutes: interval, rng: makeSeededRng(nowMs ^ 0x9e3779b9) })
        await setDashboardSetting(env.DB, FOLLOW_AD_SCHED_NEXT_RUN_KEY, new Date(nextRunMs).toISOString()).catch(() => null)
        const res = await processOneFollowAd(env)
        console.log(`[FOLLOW-AD] ok=${res.ok}${res.attempted ? ` attempted=${res.attempted}` : ''}${res.failedPages?.length ? ` failed_pages=${res.failedPages.join(',')}` : ''} ${res.reason ? `reason=${res.reason}` : ''} ${res.error ? `error=${res.error}` : ''} next_run_at=${new Date(nextRunMs).toISOString()}`)
        return { ran: res.reason !== 'no_eligible_candidate', reason: res.reason }
    } catch (e) {
        console.error(`[FOLLOW-AD] ${e instanceof Error ? e.message : String(e)}`)
        return { ran: false, reason: 'error' }
    }
}

// =====================================================================
// Auto-pause FINISHED ad-only campaigns — turn OFF, never delete. SALES/CLICK-LINK LANE ONLY.
// ---------------------------------------------------------------------
// After a system-created ACTIVE ad-only ad's scheduled run window ends (end_time <= now), this turns
// the campaign + adset (and the ad, when known) OFF via the bridge /pause-ad-only route. It ONLY ever
// requests status=PAUSED — it NEVER deletes a campaign/adset/ad and NEVER sets status='DELETED'. The
// operator contract is close/off, never destroy. Runs from the cron in waitUntil so it can never
// block (or be blocked by) posting or the ad-only queue, and swallows its own errors. A row's
// auto_paused_at is set ONLY on a confirmed pause, so a transient bridge/Graph failure is simply
// retried on the next cron tick (bounded batch, cheapest-first by id).
//
// FOLLOW LANE IS EXCLUDED here (lane='follow'): a finished Follow ad must be REMOVED/ARCHIVED from Ads,
// not merely paused — otherwise its LIKE_PAGE/Follow button stays bound to the story and blocks the
// click-link handoff. Follow rows are handled by autoRemoveCompletedFollowAds below.
const AUTO_PAUSE_AD_ONLY_BATCH = 15

async function autoPauseCompletedAdOnlyCampaigns(
    env: Env,
    opts?: { limit?: number }
): Promise<{ scanned: number; paused: number; failed: number; reason?: string }> {
    try {
        await ensureAdHistoryTable(env.DB)
        const baseUrl = resolveCloakFbBridgeBaseUrl(env)
        if (!baseUrl) return { scanned: 0, paused: 0, failed: 0, reason: 'bridge_not_configured' }

        const limit = Math.min(25, Math.max(1, Math.floor(opts?.limit ?? AUTO_PAUSE_AD_ONLY_BATCH)))
        // Only created (success) ad-only rows whose scheduled run window has ended and that carry a
        // pausable id are eligible — rejected/unsupported/failed rows never created live objects.
        // datetime(end_time) <= datetime('now') is the "finished" gate; auto_paused_at = '' makes
        // each row a one-shot (and lets a failed attempt re-qualify next tick).
        const rows = await env.DB.prepare(
            `SELECT id, campaign_id, adset_id, ad_id
               FROM dashboard_ad_history
              WHERE auto_paused_at = ''
                AND (
                    (end_time != '' AND datetime(end_time) <= datetime('now'))
                    OR (end_time = '' AND run_hours != '' AND created_at != ''
                        AND datetime(created_at, '+' || CAST(run_hours AS INTEGER) || ' hours') <= datetime('now'))
                )
                AND status IN ('created', 'success')
                AND (campaign_id != '' OR adset_id != '')
                AND COALESCE(lane, '') != 'follow'
              ORDER BY id ASC
              LIMIT ?`
        ).bind(limit).all()

        const list = (rows?.results || []) as Array<{ id: number; campaign_id: string; adset_id: string; ad_id: string }>
        let paused = 0
        let failed = 0

        for (const row of list) {
            const campaignId = String(row.campaign_id || '').trim()
            const adsetId = String(row.adset_id || '').trim()
            const adId = String(row.ad_id || '').trim()
            try {
                const resp = await fetch(`${baseUrl}/pause-ad-only`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        ...(campaignId ? { campaign_id: campaignId } : {}),
                        ...(adsetId ? { adset_id: adsetId } : {}),
                        ...(adId ? { ad_id: adId } : {}),
                    }),
                })
                const data = await resp.json().catch(() => ({})) as Record<string, unknown>
                const campaign = (data.campaign || {}) as Record<string, unknown>
                const adset = (data.adset || {}) as Record<string, unknown>
                const ad = (data.ad || {}) as Record<string, unknown>
                if (resp.ok && data.ok) {
                    // Confirmed off — stamp auto_paused_at so this row is never paused again, and
                    // record the Graph read-back status for the audit/proof panel.
                    await env.DB.prepare(
                        `UPDATE dashboard_ad_history
                            SET auto_paused_at = datetime('now'),
                                auto_pause_status = 'success',
                                auto_pause_error = '',
                                campaign_status_after = ?,
                                adset_status_after = ?,
                                ad_status_after = ?
                          WHERE id = ?`
                    ).bind(
                        String(campaign.effective_status || campaign.status || ''),
                        String(adset.effective_status || adset.status || ''),
                        String(ad.effective_status || ad.status || ''),
                        row.id
                    ).run().catch(() => undefined)
                    paused += 1
                } else {
                    // Leave auto_paused_at empty so the next cron tick retries this row.
                    const err = String(data.error || data.step || `pause_http_${resp.status}`).slice(0, 200)
                    await env.DB.prepare(
                        `UPDATE dashboard_ad_history
                            SET auto_pause_status = 'failed', auto_pause_error = ?
                          WHERE id = ?`
                    ).bind(err, row.id).run().catch(() => undefined)
                    failed += 1
                }
            } catch (e) {
                const err = (e instanceof Error ? e.message : String(e)).slice(0, 200)
                await env.DB.prepare(
                    `UPDATE dashboard_ad_history
                        SET auto_pause_status = 'failed', auto_pause_error = ?
                      WHERE id = ?`
                ).bind(err, row.id).run().catch(() => undefined)
                failed += 1
            }
        }
        return { scanned: list.length, paused, failed }
    } catch (e) {
        console.error(`[AD-ONLY-AUTOPAUSE] ${e instanceof Error ? e.message : String(e)}`)
        return { scanned: 0, paused: 0, failed: 0, reason: 'error' }
    }
}

// =====================================================================
// Auto-REMOVE finished FOLLOW ads — archive (remove from Ads), NOT pause. FOLLOW LANE ONLY.
// ---------------------------------------------------------------------
// The corrected Follow lifecycle (operator correction by Thanwa): after a Follow/Page-like ad's run
// window ends it must be REMOVED/ARCHIVED from Ads, not merely paused. Pausing alone leaves the
// LIKE_PAGE/Follow button bound to the story/creative, which blocks the later click-link ad and the
// button removal — so the click-link handoff requires REMOVAL, not pause. This turns the finished
// Follow ad OFF-the-active-surface via the bridge /archive-ad-only route (recoverable status=ARCHIVED;
// NEVER an HTTP DELETE, NEVER a hard delete — Meta keeps the row + insights). It archives the AD ONLY
// (the LIKE_PAGE creative/button carrier); a shared/fixed Follow adset or campaign is never touched.
// follow_removed_at is set ONLY on a CONFIRMED archive read-back, so a transient bridge/Graph failure
// is simply retried on the next cron tick (bounded batch, cheapest-first by id). Never throws.
async function autoRemoveCompletedFollowAds(
    env: Env,
    opts?: { limit?: number }
): Promise<{ scanned: number; removed: number; failed: number; reason?: string }> {
    try {
        await ensureAdHistoryTable(env.DB)
        const baseUrl = resolveCloakFbBridgeBaseUrl(env)
        if (!baseUrl) return { scanned: 0, removed: 0, failed: 0, reason: 'bridge_not_configured' }

        const limit = Math.min(25, Math.max(1, Math.floor(opts?.limit ?? AUTO_PAUSE_AD_ONLY_BATCH)))
        // Only created (success) FOLLOW-lane rows whose run window has ended and that carry an ad id are
        // eligible — the ad is the LIKE_PAGE creative/button carrier we must remove. follow_removed_at=''
        // makes each row a one-shot (and lets a failed archive re-qualify on the next tick). The finished
        // gate mirrors auto-pause: end_time<=now, or created_at + run_hours<=now when no end_time.
        const rows = await env.DB.prepare(
            `SELECT id, campaign_id, adset_id, ad_id
               FROM dashboard_ad_history
              WHERE follow_removed_at = ''
                AND lane = 'follow'
                AND (
                    (end_time != '' AND datetime(end_time) <= datetime('now'))
                    OR (end_time = '' AND run_hours != '' AND created_at != ''
                        AND datetime(created_at, '+' || CAST(run_hours AS INTEGER) || ' hours') <= datetime('now'))
                )
                AND status IN ('created', 'success')
                AND ad_id != ''
              ORDER BY id ASC
              LIMIT ?`
        ).bind(limit).all()

        const list = (rows?.results || []) as Array<{ id: number; campaign_id: string; adset_id: string; ad_id: string }>
        let removed = 0
        let failed = 0

        for (const row of list) {
            const adId = String(row.ad_id || '').trim()
            try {
                // Archive the AD only (the button/creative carrier). Forward the campaign/adset ids for
                // audit, but do NOT request their archive — a shared/fixed Follow adset/campaign must
                // never be removed by the unattended path.
                const resp = await fetch(`${baseUrl}/archive-ad-only`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ ad_id: adId }),
                })
                const data = await resp.json().catch(() => ({})) as Record<string, unknown>
                const ad = (data.ad || {}) as Record<string, unknown>
                if (resp.ok && data.ok) {
                    // Confirmed removed — stamp follow_removed_at so this row is never archived again,
                    // and record the Graph read-back status for the audit/proof panel. The handoff query
                    // gates on follow_removed_at (NOT auto_paused_at).
                    await env.DB.prepare(
                        `UPDATE dashboard_ad_history
                            SET follow_removed_at = datetime('now'),
                                follow_removed_status = 'success',
                                follow_removed_error = '',
                                ad_status_after = ?
                          WHERE id = ?`
                    ).bind(
                        String(ad.effective_status || ad.status || ''),
                        row.id
                    ).run().catch(() => undefined)
                    removed += 1
                } else {
                    // Leave follow_removed_at empty so the next cron tick retries this row.
                    const err = String(data.error || data.step || `archive_http_${resp.status}`).slice(0, 200)
                    await env.DB.prepare(
                        `UPDATE dashboard_ad_history
                            SET follow_removed_status = 'failed', follow_removed_error = ?
                          WHERE id = ?`
                    ).bind(err, row.id).run().catch(() => undefined)
                    failed += 1
                }
            } catch (e) {
                const err = (e instanceof Error ? e.message : String(e)).slice(0, 200)
                await env.DB.prepare(
                    `UPDATE dashboard_ad_history
                        SET follow_removed_status = 'failed', follow_removed_error = ?
                      WHERE id = ?`
                ).bind(err, row.id).run().catch(() => undefined)
                failed += 1
            }
        }
        return { scanned: list.length, removed, failed }
    } catch (e) {
        console.error(`[FOLLOW-AD-REMOVE] ${e instanceof Error ? e.message : String(e)}`)
        return { scanned: 0, removed: 0, failed: 0, reason: 'error' }
    }
}

// =====================================================================
// PER-PAGE CREATE-ADS AUTOMATION — the operator-configured Follow→Click-link lane (Create Ads detail).
// Unlike the GLOBAL Follow scheduler (one dashboard flag, cross-page candidate), this lane is driven by
// PER-PAGE settings: each enabled page runs its OWN jittered cadence, daily quantity cap and run window,
// and creates ACTIVE Follow ads inside its own fixed Follow adset (falling back to the Bangkok daily
// campaign when no fixed adset is configured). Enabling a page is the deliberate spend opt-in; every
// page is DISABLED by default (fail-closed). After a Follow ad finishes its run window and is turned OFF
// by autoPauseCompletedAdOnlyCampaigns, processFollowToClickLinkHandoffs reuses the SAME source system
// video to create the click-link ad in the page's fixed click-link adset (idempotent, one per row).
// =====================================================================
const AUTO_ADS_MAX_PAGES_PER_TICK = 8
const AUTO_ADS_HANDOFF_BATCH = 10
const AUTO_ADS_DAILY_COUNT_SCAN_LIMIT = 500

// Per-page automation cadence (minutes), clamped/defaulted by the SAME helper as the ad-only queue and
// global Follow lane (1–1440, default 30). Read page-scoped first (getPageSetting), so each page keeps
// its own cadence; an unset page falls back to the shared default.
async function getAutoAdsCadenceMinutes(db: D1Database, pageId: string): Promise<number> {
    const row = await getPageSetting(db, pageId, AUTO_ADS_CADENCE_MINUTES_SETTING_KEY).catch(() => null)
    if (row && String(row.value || '').trim()) return clampAdOnlyIntervalMinutes(row.value)
    return DEFAULT_AD_ONLY_INTERVAL_MINUTES
}

// Per-page run window (hours) before the Follow→Click-link handoff. Clamped/defaulted (1–720, default 24).
async function getAutoAdsRunHours(db: D1Database, pageId: string): Promise<number> {
    const row = await getPageSetting(db, pageId, AUTO_ADS_RUN_HOURS_SETTING_KEY).catch(() => null)
    return clampAutoAdsRunHours(row?.value)
}

// Enumerate the pages whose per-page automation is ENABLED. Page settings are flat dashboard_settings
// rows keyed page:<id>:auto_ads_automation_enabled, so a single prefix scan yields the enabled set
// without one read per held page. Fail-closed: only explicit-truthy values count. Returns [] on error.
async function listAutoAdsEnabledPageIds(db: D1Database): Promise<string[]> {
    const prefix = 'page:'
    const suffix = `:${AUTO_ADS_AUTOMATION_ENABLED_SETTING_KEY}`
    const rows = await db.prepare(
        `SELECT key, value FROM dashboard_settings WHERE key LIKE ?`
    ).bind(`${prefix}%${suffix}`).all().catch(() => ({ results: [] as Array<{ key?: string; value?: string }> })) as { results?: Array<{ key?: string; value?: string }> }
    const out: string[] = []
    const seen = new Set<string>()
    for (const r of rows.results || []) {
        const key = String(r?.key || '')
        if (!key.startsWith(prefix) || !key.endsWith(suffix)) continue
        if (!isAutoAdsAutomationEnabled(r?.value)) continue
        const pageId = key.slice(prefix.length, key.length - suffix.length).trim()
        if (!pageId || seen.has(pageId)) continue
        seen.add(pageId)
        out.push(pageId)
    }
    return out
}

// Count the Follow ads the automation already created for a page on the CURRENT Bangkok day (used by the
// per-page daily-quantity cap). Mirrors the dedup window: only created/success Follow-lane rows whose
// created_at falls on today's Bangkok date are counted. Bounded scan.
async function countAutoAdsCreatedTodayForPage(env: Env, pageId: string, nowMs: number): Promise<number> {
    const todayKey = bangkokDateKey(nowMs)
    if (!todayKey) return 0
    const rows = await env.DB.prepare(
        `SELECT created_at FROM dashboard_ad_history
          WHERE page_id = ? AND lane = 'follow' AND status IN ('created', 'success')
          ORDER BY id DESC LIMIT ?`
    ).bind(pageId, AUTO_ADS_DAILY_COUNT_SCAN_LIMIT).all().catch(() => ({ results: [] as Array<{ created_at?: string }> })) as { results?: Array<{ created_at?: string }> }
    let count = 0
    for (const r of rows.results || []) {
        if (bangkokDateKey(String(r?.created_at || '')) === todayKey) count += 1
    }
    return count
}

// Pick ONE fresh, eligible cached video for a SINGLE page (≥ min views + a Shopee link, not already used
// today, page not on a fatal-error cooldown). Mirrors the per-page selection inside
// autoPickAdOnlyCandidates but scoped to the one page the per-page automation is firing for. Requires the
// page's ad_account (the bridge copies the template adset under it); the Follow template adset itself
// falls back to the corrected default. Returns the best random candidate or null.
async function pickBestAutoAdsCandidateForPage(env: Env, pageId: string, rng: () => number, nowMs: number): Promise<AdOnlyAutoCandidate | null> {
    const adAccountRow = await getPageSetting(env.DB, pageId, 'ad_account').catch(() => null)
    if (!String(adAccountRow?.value || '').trim()) return null

    // Resolve the SOURCE page whose cached videos seed this target page's candidates. Defaults to the
    // target page itself (existing behavior); when configured (e.g. the Chearb source page) a smaller
    // target page randomizes its Follow ads from another page's high-reach videos. The ad is ALWAYS
    // created for the TARGET page (candidate.pageId below stays pageId) — only the candidate video pool and
    // the system-video resolution read from the source page.
    const sourcePageRow = await getPageSetting(env.DB, pageId, AUTO_ADS_SOURCE_PAGE_ID_SETTING_KEY).catch(() => null)
    const sourcePageId = resolveAutoAdsSourcePageId(sourcePageRow?.value, pageId)

    const failureRows = await env.DB.prepare(
        `SELECT page_id, status, error_message, truncated_result_json, created_at, published_to_page
         FROM dashboard_ad_history
         WHERE status IN ('failed', 'error', 'unsupported')
           AND lane = 'follow'
         ORDER BY id DESC LIMIT ?`
    ).bind(AD_ONLY_AUTO_FAILURE_SCAN_LIMIT).all().catch(() => ({ results: [] as AdOnlyFailureRow[] })) as { results?: AdOnlyFailureRow[] }
    const skipped = buildAdOnlySkippedPageSet(failureRows.results || [], nowMs)
    if (skipped.has(pageId)) return null

    // Candidate video pool comes from the SOURCE page's cache (Chearb when configured, else this page).
    const videos = await listFacebookPageVideoCache(env.DB, {
        pageId: sourcePageId,
        minViews: AD_ONLY_AUTO_MIN_VIEWS,
        limit: AD_ONLY_AUTO_VIDEOS_PER_PAGE,
        order: 'newest',
    }).catch(() => [] as FacebookPageVideoCacheRow[])
    if (!videos.length) return null

    // Used-id dedup stays keyed on the TARGET page (per-target-page same-day reuse), so two target pages
    // can each promote the same source video on the same day, but neither reuses it for itself.
    const historyRows = await env.DB.prepare(
        `SELECT source_story_id, source_post_id, fb_video_id, system_video_id, effective_object_story_id, created_at, status
         FROM dashboard_ad_history WHERE page_id = ? ORDER BY id DESC LIMIT 5000`
    ).bind(pageId).all().catch(() => ({ results: [] as AdOnlyHistoryIdRow[] })) as { results?: AdOnlyHistoryIdRow[] }
    const used = buildAdOnlyUsedIdSetForBangkokDate(historyRows.results || [], nowMs)

    const mappedCandidates: AdOnlyAutoCandidate[] = []
    const sourceUrlCandidates: AdOnlyAutoCandidate[] = []
    for (const v of videos) {
        const fbVideoId = String(v.video_id || '').trim()
        const postId = String(v.post_id || '').trim()
        const shopeeLink = String(v.shopee_link || '').trim()
        // Resolve the internal system video from the SOURCE page (the cached video, post_history and
        // shopee link all belong to the source page). The created ad still targets the target page.
        const resolved = await resolveAdOnlySystemVideoIdFromSignal(env, { pageId: sourcePageId, postId, fbVideoId, shopeeLink })
        const sourceUrl = String(v.source_url || '').trim()
        const src = resolveAdOnlyCandidateVideoSource({ systemVideoId: resolved.systemVideoId, sourceUrl })
        if (src.source === '') continue
        const candidate: AdOnlyAutoCandidate = {
            pageId,
            videoId: fbVideoId,
            postId,
            systemVideoId: src.systemVideoId,
            videoUrl: src.videoUrl,
            sourceSelection: src.source,
            shopeeLink,
            views: Number(v.views || 0),
            createdTime: String(v.created_time || '').trim(),
            adName: String(v.title || '').trim() || src.systemVideoId || fbVideoId,
        }
        if (src.source === 'system_video') mappedCandidates.push(candidate)
        else sourceUrlCandidates.push(candidate)
    }
    const rankedMapped = rankAdOnlyAutoCandidatesRandom(mappedCandidates, used, rng)
    const ranked = rankedMapped.length ? rankedMapped : rankAdOnlyAutoCandidatesRandom(sourceUrlCandidates, used, rng)
    return ranked.length ? ranked[0] : null
}

// Create ONE ACTIVE Follow ad for a page via the SAME create-ad-only endpoint (lane='follow'). Uses the
// page's fixed Follow campaign/adset when configured (else the Bangkok daily campaign), the page's run
// window, and a default daily budget. create-ad-only returns HTTP 200 ok:false on failure, so success
// gates on data.ok. Never throws.
async function processOnePerPageAutoAd(env: Env, pageId: string, nowMs: number): Promise<{ ok: boolean; reason?: string; error?: string }> {
    const rng = makeSeededRng(nowMs ^ (Number(pageId.replace(/\D/g, '').slice(-9)) || 0))
    const candidate = await pickBestAutoAdsCandidateForPage(env, pageId, rng, nowMs)
    if (!candidate) return { ok: true, reason: 'no_eligible_candidate' }

    const fixedCampaignRow = await getPageSetting(env.DB, pageId, FOLLOW_LANE_FIXED_CAMPAIGN_ID_SETTING_KEY).catch(() => null)
    const fixedAdsetRow = await getPageSetting(env.DB, pageId, FOLLOW_LANE_FIXED_ADSET_ID_SETTING_KEY).catch(() => null)
    const fixedCampaignId = String(fixedCampaignRow?.value || '').trim()
    const fixedAdsetId = String(fixedAdsetRow?.value || '').trim()
    const runHours = await getAutoAdsRunHours(env.DB, pageId)

    const reqBody = buildFollowAutoPickBody({
        candidate,
        mode: 'active',
        dailyCampaignName: fixedAdsetId ? '' : bangkokDailyCampaignName(),
        templateAdset: FOLLOW_LANE_TEMPLATE_ADSET,
        campaignSub1: FOLLOW_LANE_SHORTLINK_SUB1_DEFAULT,
        fixedCampaignId,
        fixedAdsetId,
        runHours,
    })
    const workerUrl = String(env.WORKER_URL || 'https://api.pubilo.com').trim().replace(/\/+$/, '')
    try {
        const resp = await fetch(`${workerUrl}/api/dashboard/create-ad-only`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(reqBody),
        })
        const data = await resp.json().catch(() => ({})) as Record<string, unknown>
        if (resp.ok && data.ok) return { ok: true }
        return { ok: false, error: String(data.error || `http_${resp.status}`).trim() }
    } catch (e) {
        return { ok: false, error: e instanceof Error ? e.message : String(e) }
    }
}

// Cron entrypoint — per-page automation cadence. For each ENABLED page: gate on its OWN jittered cadence
// slot (auto_ads_next_run_at), then its OWN daily quantity cap, then create AT MOST one ACTIVE Follow ad.
// Claims each page's slot (stamps last_run + the next jittered slot) BEFORE creating, so a slow create
// can't be double-claimed and the cap is consulted once per slot. Bounded to AUTO_ADS_MAX_PAGES_PER_TICK
// creates per tick. Never throws (cron must not be derailed).
async function maybeProcessPerPageAutoAdsOnSchedule(env: Env): Promise<{ ran: number; reason?: string }> {
    try {
        const pageIds = await listAutoAdsEnabledPageIds(env.DB)
        if (!pageIds.length) return { ran: 0, reason: 'no_enabled_pages' }
        const nowMs = Date.now()
        let created = 0
        for (const pageId of pageIds) {
            if (created >= AUTO_ADS_MAX_PAGES_PER_TICK) break
            const interval = await getAutoAdsCadenceMinutes(env.DB, pageId)
            const lastRun = await getPageSetting(env.DB, pageId, AUTO_ADS_LAST_RUN_AT_SETTING_KEY).catch(() => null)
            const storedNext = await getPageSetting(env.DB, pageId, AUTO_ADS_NEXT_RUN_AT_SETTING_KEY).catch(() => null)
            const decision = decideJitteredScheduleRun({
                nowMs,
                lastRunMs: Date.parse(String(lastRun?.value || '')),
                storedNextRunMs: Date.parse(String(storedNext?.value || '').trim()),
                intervalMinutes: interval,
                rng: makeSeededRng(nowMs ^ (Number(pageId.replace(/\D/g, '').slice(-9)) || 0)),
            })
            if (!decision.due) {
                if (decision.persistNextRun) {
                    await setPageSetting(env.DB, pageId, AUTO_ADS_NEXT_RUN_AT_SETTING_KEY, new Date(decision.nextRunAtMs).toISOString()).catch(() => null)
                }
                continue
            }
            // Claim the slot first: stamp last_run + pre-arm the next jittered slot, so a slow create can't
            // be double-claimed and the cap is consulted exactly once per cadence slot.
            await setPageSetting(env.DB, pageId, AUTO_ADS_LAST_RUN_AT_SETTING_KEY, new Date(nowMs).toISOString()).catch(() => null)
            const nextRunMs = computeJitteredNextRunAtMs({ baseMs: nowMs, intervalMinutes: interval, rng: makeSeededRng(nowMs ^ 0x9e3779b9 ^ (Number(pageId.replace(/\D/g, '').slice(-9)) || 0)) })
            await setPageSetting(env.DB, pageId, AUTO_ADS_NEXT_RUN_AT_SETTING_KEY, new Date(nextRunMs).toISOString()).catch(() => null)

            // Daily quantity cap (per page; 0 = unlimited). When reached, the slot is still advanced so the
            // page simply waits for the next cadence/day rather than retrying every tick.
            const maxPerDay = clampAutoAdsMaxPerDay((await getPageSetting(env.DB, pageId, AUTO_ADS_MAX_PER_DAY_SETTING_KEY).catch(() => null))?.value)
            const todayCount = await countAutoAdsCreatedTodayForPage(env, pageId, nowMs)
            if (!isUnderDailyAdCap(todayCount, maxPerDay)) {
                console.log(`[AUTO-ADS] page=${pageId} daily_cap_reached count=${todayCount}/${maxPerDay}`)
                continue
            }
            const res = await processOnePerPageAutoAd(env, pageId, nowMs)
            console.log(`[AUTO-ADS] page=${pageId} ok=${res.ok} ${res.reason ? `reason=${res.reason}` : ''} ${res.error ? `error=${res.error}` : ''} next_run_at=${new Date(nextRunMs).toISOString()}`)
            if (res.ok && res.reason !== 'no_eligible_candidate') created += 1
        }
        return { ran: created }
    } catch (e) {
        console.error(`[AUTO-ADS] ${e instanceof Error ? e.message : String(e)}`)
        return { ran: 0, reason: 'error' }
    }
}

// 24h Follow→Click-link handoff. After a per-page automation Follow ad finishes its run window and is
// REMOVED/ARCHIVED from Ads (follow_removed_at set by autoRemoveCompletedFollowAds — NOT merely paused,
// so its LIKE_PAGE button is detached from the story first), reuse the SAME source system video to
// create the click-link (sales lane) ad in the page's FIXED click-link adset. Idempotent: the
// click_link_handoff_at='' gate + a one-shot stamp guarantee AT MOST one click-link ad per Follow row.
// A page with automation disabled or no configured click-link adset is stamped 'skipped' (terminal — the
// handoff decision is made when the Follow ad finishes). A transient create failure leaves the stamp
// empty so the next cron tick retries. Bounded batch, cheapest-first by id. Never throws.
async function processFollowToClickLinkHandoffs(env: Env): Promise<{ scanned: number; handed_off: number; skipped: number; failed: number; reason?: string }> {
    try {
        await ensureAdHistoryTable(env.DB)
        const rows = await env.DB.prepare(
            `SELECT id, page_id, system_video_id, click_link, lane, status, follow_removed_at, click_link_handoff_at
               FROM dashboard_ad_history
              WHERE lane = 'follow'
                AND click_link_handoff_at = ''
                AND follow_removed_at != ''
                AND system_video_id != ''
                AND status IN ('created', 'success')
              ORDER BY id ASC
              LIMIT ?`
        ).bind(AUTO_ADS_HANDOFF_BATCH).all().catch(() => ({ results: [] as Array<Record<string, unknown>> })) as { results?: Array<Record<string, unknown>> }
        const list = rows.results || []
        if (!list.length) return { scanned: 0, handed_off: 0, skipped: 0, failed: 0 }

        const workerUrl = String(env.WORKER_URL || 'https://api.pubilo.com').trim().replace(/\/+$/, '')
        let handedOff = 0
        let skipped = 0
        let failed = 0
        for (const row of list) {
            if (!isFollowRowHandoffEligible(row)) continue
            const id = Number(row.id)
            const pageId = String(row.page_id || '').trim()
            const systemVideoId = String(row.system_video_id || '').trim()
            const enabled = isAutoAdsAutomationEnabled((await getPageSetting(env.DB, pageId, AUTO_ADS_AUTOMATION_ENABLED_SETTING_KEY).catch(() => null))?.value)
            const fixedAdsetId = String((await getPageSetting(env.DB, pageId, CLICK_LINK_LANE_FIXED_ADSET_ID_SETTING_KEY).catch(() => null))?.value || '').trim()
            const fixedCampaignId = String((await getPageSetting(env.DB, pageId, CLICK_LINK_LANE_FIXED_CAMPAIGN_ID_SETTING_KEY).catch(() => null))?.value || '').trim()
            if (!enabled) {
                // Terminal skip — the handoff decision is made when the Follow ad finishes. Stamp so the
                // row is not rescanned while automation is disabled.
                await env.DB.prepare(
                    `UPDATE dashboard_ad_history
                        SET click_link_handoff_at = datetime('now'),
                            click_link_handoff_status = ?
                      WHERE id = ?`
                ).bind('skipped_disabled', id).run().catch(() => undefined)
                skipped += 1
                continue
            }
            const runHours = await getAutoAdsRunHours(env.DB, pageId)
            const handoffBody = buildFollowToClickLinkHandoffBody({
                pageId,
                systemVideoId,
                fixedAdsetId,
                fixedCampaignId,
                dailyCampaignName: fixedAdsetId ? '' : bangkokDailyCampaignName(),
                templateAdset: FOLLOW_LANE_TEMPLATE_ADSET,
                runHours,
                shopeeUrl: String(row.click_link || '').trim(),
                adName: systemVideoId,
            })
            try {
                const resp = await fetch(`${workerUrl}/api/dashboard/create-ad-only`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(handoffBody),
                })
                const data = await resp.json().catch(() => ({})) as Record<string, unknown>
                if (resp.ok && data.ok && data.ad_id) {
                    await env.DB.prepare(
                        `UPDATE dashboard_ad_history
                            SET click_link_handoff_at = datetime('now'),
                                click_link_handoff_ad_id = ?,
                                click_link_handoff_status = 'created',
                                click_link_handoff_error = ''
                          WHERE id = ?`
                    ).bind(String(data.ad_id || ''), id).run().catch(() => undefined)
                    handedOff += 1
                } else {
                    // Leave click_link_handoff_at empty → retried next tick.
                    const err = String(data.error || `handoff_http_${resp.status}`).slice(0, 200)
                    await env.DB.prepare(
                        `UPDATE dashboard_ad_history
                            SET click_link_handoff_status = 'failed', click_link_handoff_error = ?
                          WHERE id = ?`
                    ).bind(err, id).run().catch(() => undefined)
                    failed += 1
                }
            } catch (e) {
                const err = (e instanceof Error ? e.message : String(e)).slice(0, 200)
                await env.DB.prepare(
                    `UPDATE dashboard_ad_history
                        SET click_link_handoff_status = 'failed', click_link_handoff_error = ?
                      WHERE id = ?`
                ).bind(err, id).run().catch(() => undefined)
                failed += 1
            }
        }
        return { scanned: list.length, handed_off: handedOff, skipped, failed }
    } catch (e) {
        console.error(`[AUTO-ADS-HANDOFF] ${e instanceof Error ? e.message : String(e)}`)
        return { scanned: 0, handed_off: 0, skipped: 0, failed: 0, reason: 'error' }
    }
}

// Per-page automation status — the resolved config + next-due slot for one page. GET never mutates the
// cadence (it does not roll/store a jitter), so polling can't shift the schedule.
app.get('/api/dashboard/auto-ads/status', async (c) => {
    const pageId = String(c.req.query('page_id') || '').trim()
    if (!pageId) return c.json({ ok: false, error: 'page_id_required' }, 400)
    const enabled = isAutoAdsAutomationEnabled((await getPageSetting(c.env.DB, pageId, AUTO_ADS_AUTOMATION_ENABLED_SETTING_KEY).catch(() => null))?.value)
    const cadence = await getAutoAdsCadenceMinutes(c.env.DB, pageId)
    const maxPerDay = clampAutoAdsMaxPerDay((await getPageSetting(c.env.DB, pageId, AUTO_ADS_MAX_PER_DAY_SETTING_KEY).catch(() => null))?.value)
    const runHours = await getAutoAdsRunHours(c.env.DB, pageId)
    const sourcePageId = resolveAutoAdsSourcePageId((await getPageSetting(c.env.DB, pageId, AUTO_ADS_SOURCE_PAGE_ID_SETTING_KEY).catch(() => null))?.value, pageId)
    const followCampaign = String((await getPageSetting(c.env.DB, pageId, FOLLOW_LANE_FIXED_CAMPAIGN_ID_SETTING_KEY).catch(() => null))?.value || '').trim()
    const followAdset = String((await getPageSetting(c.env.DB, pageId, FOLLOW_LANE_FIXED_ADSET_ID_SETTING_KEY).catch(() => null))?.value || '').trim()
    const clickCampaign = String((await getPageSetting(c.env.DB, pageId, CLICK_LINK_LANE_FIXED_CAMPAIGN_ID_SETTING_KEY).catch(() => null))?.value || '').trim()
    const clickAdset = String((await getPageSetting(c.env.DB, pageId, CLICK_LINK_LANE_FIXED_ADSET_ID_SETTING_KEY).catch(() => null))?.value || '').trim()
    const lastRun = String((await getPageSetting(c.env.DB, pageId, AUTO_ADS_LAST_RUN_AT_SETTING_KEY).catch(() => null))?.value || '').trim()
    const storedNext = String((await getPageSetting(c.env.DB, pageId, AUTO_ADS_NEXT_RUN_AT_SETTING_KEY).catch(() => null))?.value || '').trim()
    const storedNextMs = Date.parse(storedNext)
    const nextRunMs = !enabled ? 0 : (Number.isFinite(storedNextMs) ? storedNextMs : nextAdOnlyRunAtMs(lastRun, cadence, Date.now()))
    const todayCount = await countAutoAdsCreatedTodayForPage(c.env, pageId, Date.now())
    return c.json({
        ok: true,
        page_id: pageId,
        automation_enabled: enabled,
        cadence_minutes: cadence,
        max_per_day: maxPerDay,
        run_hours: runHours,
        source_page_id: sourcePageId,
        follow_fixed_campaign_id: followCampaign,
        follow_fixed_adset_id: followAdset,
        click_link_fixed_campaign_id: clickCampaign,
        click_link_fixed_adset_id: clickAdset,
        created_today: todayCount,
        last_run_at: lastRun,
        next_run_at: nextRunMs ? new Date(nextRunMs).toISOString() : '',
    }, 200, { 'Cache-Control': 'no-store' })
})

// Manual "run now" for a single page's automation — bypass the cadence gate and create one Follow ad
// immediately (still respects the daily cap). Await the create and return the concrete result; this must
// not be fire-and-forget because long Meta bridge calls can be cancelled after the response ends.
app.post('/api/dashboard/auto-ads/run-next', async (c) => {
    const body = await c.req.json().catch(() => ({})) as { page_id?: string }
    const pageId = String(body.page_id || '').trim()
    if (!pageId) return c.json({ ok: false, error: 'page_id_required' }, 400)
    const nowMs = Date.now()
    const maxPerDay = clampAutoAdsMaxPerDay((await getPageSetting(c.env.DB, pageId, AUTO_ADS_MAX_PER_DAY_SETTING_KEY).catch(() => null))?.value)
    const todayCount = await countAutoAdsCreatedTodayForPage(c.env, pageId, nowMs)
    if (!isUnderDailyAdCap(todayCount, maxPerDay)) {
        console.log(`[AUTO-ADS] manual run-next page=${pageId} daily_cap_reached count=${todayCount}/${maxPerDay}`)
        return c.json({ ok: true, page_id: pageId, created: false, reason: 'daily_cap_reached', today_count: todayCount, max_per_day: maxPerDay }, 200, { 'Cache-Control': 'no-store' })
    }
    const res = await processOnePerPageAutoAd(c.env, pageId, nowMs)
    console.log(`[AUTO-ADS] manual run-next page=${pageId} ok=${res.ok} ${res.reason ? `reason=${res.reason}` : ''} ${res.error ? `error=${res.error}` : ''}`)
    const resRecord = res as Record<string, unknown>
    return c.json({ ok: res.ok, page_id: pageId, created: !!resRecord.ad_id, ...res }, res.ok ? 200 : 500, { 'Cache-Control': 'no-store' })
})

// Manual "run now" for the Follow→Click-link handoff pass (process finished Follow rows immediately).
// First REMOVE/ARCHIVE finished Follow ads (so follow_removed_at is set and the LIKE_PAGE button is
// detached), THEN run the handoff — pausing alone is not completion for the Follow lane.
app.post('/api/dashboard/auto-ads/handoff/run-next', async (c) => {
    c.executionCtx.waitUntil(
        autoRemoveCompletedFollowAds(c.env).then((rm) => {
            console.log(`[FOLLOW-AD-REMOVE] manual scanned=${rm.scanned} removed=${rm.removed} failed=${rm.failed} ${rm.reason ? `reason=${rm.reason}` : ''}`)
            return processFollowToClickLinkHandoffs(c.env)
        }).then((r) => {
            console.log(`[AUTO-ADS-HANDOFF] manual scanned=${r.scanned} handed_off=${r.handed_off} skipped=${r.skipped} failed=${r.failed} ${r.reason ? `reason=${r.reason}` : ''}`)
        }).catch((error) => {
            console.error(`[AUTO-ADS-HANDOFF] manual failed: ${error instanceof Error ? error.message : String(error)}`)
        })
    )
    return c.json({ ok: true, accepted: true }, 202, { 'Cache-Control': 'no-store' })
})

app.get('/api/dashboard/ad-links', async (c) => {
    const adAccount = String(c.req.query('ad_account') || 'act_1030797047648459').trim()
    const pattern = String(c.req.query('pattern') || '^16MAY26FBSPCAD \\((\\d+)\\)$').trim()
    const limitRaw = Number(c.req.query('limit') || 20)
    const campaignLimit = Number.isFinite(limitRaw) ? Math.min(60, Math.max(1, Math.floor(limitRaw))) : 20
    const baseUrl = resolveCloakFbBridgeBaseUrl(c.env)
    if (!baseUrl) return c.json({ ok: false, error: 'bridge_not_configured' }, 503)

    const graph = async (path: string, fields: string, limit = 100) => {
        const resp = await fetch(`${baseUrl}/graph?path=${encodeURIComponent(path)}&fields=${encodeURIComponent(fields)}&limit=${encodeURIComponent(String(limit))}`)
        const data = await resp.json().catch(() => ({})) as Record<string, unknown>
        return { ok: resp.ok && !(data as any)?.error, status: resp.status, data }
    }

    const collectLinks = (value: unknown): string[] => {
        const links: string[] = []
        const walk = (node: unknown) => {
            if (!node) return
            if (typeof node === 'string') {
                const trimmed = node.trim()
                if (/^https?:\/\//i.test(trimmed)) links.push(trimmed)
                const matches = trimmed.match(/https?:\/\/[^\s\"'<>]+/gi) || []
                for (const match of matches) links.push(match.replace(/[),.;\]]+$/g, ''))
                return
            }
            if (Array.isArray(node)) {
                for (const item of node) walk(item)
                return
            }
            if (typeof node === 'object') {
                for (const item of Object.values(node as Record<string, unknown>)) walk(item)
            }
        }
        walk(value)
        return Array.from(new Set(links))
    }

    const pickClickLink = (creative: Record<string, unknown>): string => {
        const spec = (creative.object_story_spec || {}) as any
        const videoData = spec.video_data || {}
        const linkData = spec.link_data || {}
        const assetFeed = (creative.asset_feed_spec || {}) as any
        const candidates = [
            videoData?.call_to_action?.value?.link,
            videoData?.call_to_action?.value?.link_url,
            linkData?.link,
            linkData?.call_to_action?.value?.link,
            linkData?.call_to_action?.value?.link_url,
            Array.isArray(assetFeed?.link_urls) ? assetFeed.link_urls?.[0]?.website_url : '',
            Array.isArray(assetFeed?.link_urls) ? assetFeed.link_urls?.[0]?.url : '',
            creative.object_url,
        ].map((v) => String(v || '').trim()).filter(Boolean)
        const first = candidates.find((v) => /^https?:\/\//i.test(v))
        if (first) return first
        return collectLinks(creative)[0] || ''
    }

    try {
        const campResp = await graph(adAccount + '/campaigns', 'id,name,effective_status,daily_budget,start_time', 60)
        if (!campResp.ok) return c.json({ ok: false, step: 'campaigns', error: (campResp.data as any)?.error || campResp.data }, 502)
        const rx = new RegExp(pattern)
        const campaigns = (((campResp.data as any)?.data || []) as any[])
            .filter((camp) => String(camp?.effective_status || '').trim() === 'ACTIVE')
            .filter((camp) => rx.test(String(camp?.name || '')))
            .slice(0, campaignLimit)

        const rows: Array<Record<string, unknown>> = []
        const errors: Array<Record<string, unknown>> = []
        for (const camp of campaigns) {
            const adsetResp = await graph(`${camp.id}/adsets`, 'id,name,effective_status,daily_budget', 200)
            if (!adsetResp.ok) {
                errors.push({ campaign_id: camp.id, campaign_name: camp.name, step: 'adsets', error: (adsetResp.data as any)?.error || adsetResp.data })
                continue
            }
            const adsets = (((adsetResp.data as any)?.data || []) as any[])
            for (const adset of adsets) {
                const adsResp = await graph(`${adset.id}/ads`, 'id,name,effective_status,creative{id,name,object_story_spec,asset_feed_spec,object_url,url_tags}', 50)
                if (!adsResp.ok) {
                    errors.push({ campaign_id: camp.id, campaign_name: camp.name, adset_id: adset.id, adset_name: adset.name, step: 'ads', error: (adsResp.data as any)?.error || adsResp.data })
                    rows.push({ campaign_id: camp.id, campaign_name: camp.name, campaign_status: camp.effective_status, adset_id: adset.id, adset_name: adset.name, adset_status: adset.effective_status, ad_id: '', ad_name: '', ad_status: '', click_link: '', all_links: [], link_count: 0, short_wwoom: false, has_subid: false, error: 'ads_fetch_failed' })
                    continue
                }
                const ads = (((adsResp.data as any)?.data || []) as any[])
                if (!ads.length) {
                    rows.push({ campaign_id: camp.id, campaign_name: camp.name, campaign_status: camp.effective_status, adset_id: adset.id, adset_name: adset.name, adset_status: adset.effective_status, ad_id: '', ad_name: '', ad_status: '', click_link: '', all_links: [], link_count: 0, short_wwoom: false, has_subid: false })
                    continue
                }
                for (const ad of ads) {
                    const creative = (ad.creative || {}) as Record<string, unknown>
                    const allLinks = collectLinks(creative)
                    const clickLink = pickClickLink(creative)
                    rows.push({
                        campaign_id: camp.id,
                        campaign_name: camp.name,
                        campaign_status: camp.effective_status,
                        adset_id: adset.id,
                        adset_name: adset.name,
                        adset_status: adset.effective_status,
                        ad_id: ad.id,
                        ad_name: ad.name,
                        ad_status: ad.effective_status,
                        creative_id: (creative as any)?.id || '',
                        click_link: clickLink,
                        all_links: allLinks,
                        link_count: allLinks.length,
                        short_wwoom: /short\.wwoom\.com/i.test(clickLink) || allLinks.some((link) => /short\.wwoom\.com/i.test(link)),
                        has_subid: /16MAY26FBSPCAD/i.test(clickLink) || allLinks.some((link) => /16MAY26FBSPCAD/i.test(link)),
                    })
                }
            }
        }

        const adsRows = rows.filter((row) => String(row.ad_id || '').trim())
        const adsetIds = new Set(rows.map((row) => String(row.adset_id || '')).filter(Boolean))
        return c.json({
            ok: true,
            ad_account: adAccount,
            campaign_count: campaigns.length,
            adset_count: adsetIds.size,
            row_count: rows.length,
            ad_count: adsRows.length,
            ads_with_click_link: adsRows.filter((row) => String(row.click_link || '').trim()).length,
            ads_without_click_link: adsRows.filter((row) => !String(row.click_link || '').trim()).length,
            short_wwoom_ads: adsRows.filter((row) => row.short_wwoom).length,
            subid_ads: adsRows.filter((row) => row.has_subid).length,
            errors,
            rows,
        })
    } catch (e) {
        return c.json({ ok: false, error: e instanceof Error ? e.message : String(e) }, 502)
    }
})

// =====================================================================
// ACTIVE-CAMPAIGN HISTORY FALLBACK — used by GET /api/dashboard/campaigns when the live Facebook Graph
// account edge returns no campaigns (empty edge / wrong account / bridge error). It re-derives the
// currently-open campaigns from VERIFIED dashboard_ad_history rows only — fields already persisted in
// D1 (status / mode / campaign ids / lifecycle stamps). It NEVER reads tokens and NEVER fabricates a
// campaign: a row only counts as open if the worker recorded it as created, active, and not yet
// auto-paused (SALES lane) or archived (Follow lane). Live Graph data always takes precedence.
// =====================================================================

// Only consider history rows created within this many days as "currently open". Run windows are ~24h
// (Follow lane) to a few days; this caps ancient stale rows that were never reconciled while still
// surfacing the day's active Follow / click-link campaigns. Kept generous so we don't under-count.
const ACTIVE_CAMPAIGN_HISTORY_FALLBACK_DAYS = 7

interface ActiveCampaignFallback {
    id: string
    name: string
    status: string
    dailyBudget: string
    startTime: string
    adsets: Array<{ id: string; name: string; status: string }>
    adsetCount: number
    activeAdsetCount: number
    reach: string
    impressions: string
    spend: string
    costPerLinkClick: string
    source: 'history_fallback'
}

// Pure mapping: collapse the already-SQL-filtered active history rows into unique campaigns. Groups by
// campaign_id (newest row wins for name/budget since rows arrive id-DESC), unions adset ids, and drops
// any campaign a later Graph read-back recorded as NON-active (campaign_status_after). Exported shape
// matches the live Graph campaign object so the dashboard's normalize() reads both identically.
function buildActiveCampaignsFromAdHistoryRows(rows: Array<Record<string, unknown>>): ActiveCampaignFallback[] {
    const byCampaign = new Map<string, ActiveCampaignFallback>()
    for (const r of rows) {
        const campId = String(r.campaign_id || '').trim()
        if (!campId) continue
        // A later Graph read-back that saw the campaign paused/archived wins over the create-time
        // intent — never resurface a campaign the worker already knows is no longer ACTIVE.
        const after = String(r.campaign_status_after || '').trim().toUpperCase()
        if (after && after !== 'ACTIVE') continue
        const adsetId = String(r.adset_id || '').trim()
        const existing = byCampaign.get(campId)
        if (!existing) {
            byCampaign.set(campId, {
                id: campId,
                name: String(r.campaign_name || '').trim() || campId,
                status: 'ACTIVE',
                dailyBudget: String(r.daily_budget || '').trim(),
                startTime: String(r.start_time || '').trim(),
                adsets: adsetId ? [{ id: adsetId, name: '', status: 'ACTIVE' }] : [],
                adsetCount: adsetId ? 1 : 0,
                activeAdsetCount: adsetId ? 1 : 0,
                reach: '',
                impressions: '',
                spend: '',
                costPerLinkClick: '',
                source: 'history_fallback',
            })
        } else if (adsetId && !existing.adsets.some((a) => a.id === adsetId)) {
            existing.adsets.push({ id: adsetId, name: '', status: 'ACTIVE' })
            existing.adsetCount = existing.adsets.length
            existing.activeAdsetCount = existing.adsets.length
        }
    }
    return Array.from(byCampaign.values())
}

// SQL gate for "currently open" history rows + pure mapping. Filters to created + active-mode rows that
// the worker has NOT auto-paused (SALES lane) or archived (Follow lane), within the recency window, and
// optionally scoped to a set of page ids (the only scope available — there is no ad_account column).
async function fetchActiveCampaignsFromAdHistory(db: D1Database, pageIds: string[]): Promise<ActiveCampaignFallback[]> {
    await ensureAdHistoryTable(db)
    const clauses = [
        "status = 'created'",
        "LOWER(TRIM(COALESCE(mode,''))) = 'active'",
        "TRIM(COALESCE(campaign_id,'')) <> ''",
        "TRIM(COALESCE(auto_paused_at,'')) = ''",
        "TRIM(COALESCE(follow_removed_at,'')) = ''",
        `created_at >= datetime('now', '-${ACTIVE_CAMPAIGN_HISTORY_FALLBACK_DAYS} days')`,
    ]
    const binds: unknown[] = []
    const ids = pageIds.map((id) => id.trim()).filter(Boolean)
    if (ids.length) {
        clauses.push(`page_id IN (${ids.map(() => '?').join(',')})`)
        binds.push(...ids)
    }
    const rows = await db.prepare(
        `SELECT campaign_id, campaign_name, daily_budget, start_time, adset_id, campaign_status_after, id
         FROM dashboard_ad_history
         WHERE ${clauses.join(' AND ')}
         ORDER BY id DESC LIMIT 500`
    ).bind(...binds).all() as { results?: Array<Record<string, unknown>> }
    return buildActiveCampaignsFromAdHistoryRows(rows.results || [])
}

app.get('/api/dashboard/campaigns', async (c) => {
    const adAccount = String(c.req.query('ad_account') || 'act_1030797047648459').trim()
    const mode = String(c.req.query('mode') || '').trim().toLowerCase()
    // Optional page scoping for the history fallback. `page_ids` (comma list) lets the Create Ads
    // master surface the open campaigns across ALL its held pages; `page_id` is the single-page form.
    // dashboard_ad_history has no ad_account column, so the fallback can only be scoped by page id.
    const pageIds = [
        ...String(c.req.query('page_ids') || '').split(','),
        String(c.req.query('page_id') || ''),
    ].map((s) => s.trim()).filter(Boolean)
    // Token-safe history fallback: when the live Graph account edge returns NOTHING (empty edge, wrong
    // account, or a bridge error) we must not show a false zero while Ads Manager has live campaigns.
    // Re-derive the currently-open campaigns from verified dashboard_ad_history rows (status/result
    // fields already in D1 — never tokens, never fabricated). Live Graph data always wins when present.
    const historyFallback = () =>
        fetchActiveCampaignsFromAdHistory(c.env.DB, pageIds).catch(() => [] as ActiveCampaignFallback[])
    const baseUrl = resolveCloakFbBridgeBaseUrl(c.env)
    if (!baseUrl) {
        const fb = await historyFallback()
        if (fb.length) return c.json({ ok: true, source: 'history_fallback', graph_available: false, campaigns: fb })
        return c.json({ ok: false, error: 'bridge_not_configured', source: '' }, 503)
    }
    try {
        // Pull more than the visible limit (60) so after we filter out paused
        // /archived/etc. we still have enough ACTIVE campaigns to show. Operator
        // wants only ACTIVE in the create-ad picker — paused ones just clutter
        // the list (same FB UX as Ads Manager's 'Active' filter).
        const campResp = await fetch(`${baseUrl}/graph?path=${encodeURIComponent(adAccount)}/campaigns&fields=id,name,effective_status,daily_budget,start_time&limit=60`)
        const campData = await campResp.json().catch(() => ({})) as Record<string, unknown>
        const allCampaigns = Array.isArray((campData as any)?.data) ? (campData as any).data : []
        const campaigns = allCampaigns.filter((c: any) => String(c?.effective_status || '').trim() === 'ACTIVE').slice(0, 20)

        // Create-ad popup needs a fast picker list, but adset counts must be
        // live. Previously mode=picker returned adsetCount=0 for every campaign
        // to avoid the slow insights loop, which made filled campaigns look
        // empty and caused duplicate-selection risk. Keep picker fast by only
        // fetching adset counts (no insights) in parallel.
        if (mode === 'picker') {
            const withCounts = await Promise.all(campaigns.map(async (camp: any) => {
                let adsets: any[] = []
                try {
                    const adsetResp = await fetch(`${baseUrl}/graph?path=${encodeURIComponent(String(camp.id))}/adsets&fields=id,name,effective_status&limit=200`)
                    const adsetData = await adsetResp.json().catch(() => ({})) as Record<string, unknown>
                    adsets = Array.isArray((adsetData as any)?.data) ? (adsetData as any).data : []
                } catch (_e) {
                    adsets = []
                }
                return {
                    id: camp.id,
                    name: camp.name,
                    status: camp.effective_status,
                    dailyBudget: camp.daily_budget,
                    startTime: camp.start_time,
                    adsets: adsets.map((a: any) => ({
                        id: a.id,
                        name: a.name,
                        status: a.effective_status,
                    })),
                    adsetCount: adsets.length,
                    activeAdsetCount: adsets.filter((a: any) => a.effective_status === 'ACTIVE').length,
                    reach: '0',
                    impressions: '0',
                    spend: '0',
                    costPerResult: '0',
                    costPerLinkClick: '',
                }
            }))
            if (withCounts.length > 0) {
                return c.json({ ok: true, mode: 'picker', source: 'graph', campaigns: withCounts })
            }
            // Live account edge is empty in picker mode too — fall back to verified history so the
            // picker isn't a false zero. Marked source so the caller knows it's not live Graph data.
            const fb = await historyFallback()
            return c.json({ ok: true, mode: 'picker', source: fb.length ? 'history_fallback' : 'graph', campaigns: fb })
        }

        // Helper: pull the per-action numeric cost out of the FB insights array
        // shape. cost_per_action_type returns:
        //   [{action_type:'link_click', value:'0.16'}, {action_type:'post_engagement',...}, ...]
        // We surface link_click specifically because that's what the operator
        // sees as 'ต้นทุนต่อการคลิกลิงก์' in Ads Manager UI.
        const pickCostPerAction = (insights: any, actionType: string): string => {
            const arr = Array.isArray(insights?.cost_per_action_type) ? insights.cost_per_action_type : []
            const hit = arr.find((entry: any) => String(entry?.action_type || '').trim() === actionType)
            return hit ? String(hit.value || '0') : ''
        }

        const result: Array<Record<string, unknown>> = []
        for (const camp of campaigns) {
            // Get adsets for each campaign
            const adsetResp = await fetch(`${baseUrl}/graph?path=${encodeURIComponent(String(camp.id))}/adsets&fields=id,name,effective_status,daily_budget&limit=50`)
            const adsetData = await adsetResp.json().catch(() => ({})) as Record<string, unknown>
            const adsets = Array.isArray((adsetData as any)?.data) ? (adsetData as any).data : []

            // Get campaign insights — request cost_per_action_type so we can surface
            // 'cost per link click' per campaign in the create-ad popup.
            const insResp = await fetch(`${baseUrl}/graph?path=${encodeURIComponent(String(camp.id))}/insights&fields=reach,impressions,spend,cost_per_thruplay,cost_per_action_type,actions&date_preset=lifetime`)
            const insData = await insResp.json().catch(() => ({})) as Record<string, unknown>
            const insights = Array.isArray((insData as any)?.data) ? (insData as any).data[0] || {} : {}

            result.push({
                id: camp.id,
                name: camp.name,
                status: camp.effective_status,
                dailyBudget: camp.daily_budget,
                startTime: camp.start_time,
                adsets: adsets.map((a: any) => ({
                    id: a.id,
                    name: a.name,
                    status: a.effective_status,
                })),
                adsetCount: adsets.length,
                activeAdsetCount: adsets.filter((a: any) => a.effective_status === 'ACTIVE').length,
                reach: String(insights.reach || '0'),
                impressions: String(insights.impressions || '0'),
                spend: String(insights.spend || '0'),
                costPerResult: String(insights.cost_per_thruplay || '0'),
                costPerLinkClick: pickCostPerAction(insights, 'link_click'),
            })
        }
        if (result.length > 0) return c.json({ ok: true, source: 'graph', campaigns: result })
        // Live account edge returned no ACTIVE campaigns — re-derive from verified history before
        // reporting an empty list (prevents the dashboard's false zero vs. Ads Manager).
        const fb = await historyFallback()
        return c.json({ ok: true, source: fb.length ? 'history_fallback' : 'graph', campaigns: fb })
    } catch (e) {
        const graphError = e instanceof Error ? e.message : String(e)
        const fb = await historyFallback()
        if (fb.length) return c.json({ ok: true, source: 'history_fallback', graph_error: graphError, campaigns: fb })
        return c.json({ ok: false, error: graphError, source: '' }, 502)
    }
})

app.post('/admin/api/gallery/index/rebuild', async (c) => {
    const result = await rebuildGalleryIndexFromR2(c.env)
    await c.env.BUCKET.delete('_admin_cache/all_gallery_videos.json').catch(() => { })
    await c.env.BUCKET.delete('_admin_cache/all_gallery_owner_videos.json').catch(() => { })
    return c.json({ ok: true, ...result })
})

// Targeted backfill: re-sync only the gallery_index rows that are inbox-stage
// (no processed_at) AND missing shopee or lazada links. Uses syncGalleryIndexEntry
// per-video so the new buildGalleryIndexUpsertRow inbox JSON fallback kicks in.
// Stays well under the 1000 subrequest limit by capping batch size.
//
// Pagination: pass `offset=N` to skip the first N stale videos (they likely have
// no inbox record either). Without offset, the same unhealable rows return every
// call. To run a full sweep, walk offset 0, 30, 60, ... until scanned=0.
app.post('/admin/api/gallery/index/backfill-missing-links', async (c) => {
    const limit = Math.max(1, Math.min(40, parseInt(String(c.req.query('limit') || '20'), 10) || 20))
    const offset = Math.max(0, parseInt(String(c.req.query('offset') || '0'), 10) || 0)
    const namespaceFilter = String(c.req.query('namespace_id') || '').trim()
    const whereNamespace = namespaceFilter ? 'AND namespace_id = ?' : ''
    const sql = `SELECT namespace_id, video_id
                 FROM gallery_index
                 WHERE TRIM(COALESCE(processed_at,'')) = ''
                   AND (TRIM(COALESCE(shopee_link,'')) = '' OR TRIM(COALESCE(lazada_link,'')) = '')
                   AND TRIM(COALESCE(original_url,'')) <> ''
                   ${whereNamespace}
                 ORDER BY namespace_id ASC, video_id ASC
                 LIMIT ? OFFSET ?`
    const stmt = namespaceFilter
        ? c.env.DB.prepare(sql).bind(namespaceFilter, limit, offset)
        : c.env.DB.prepare(sql).bind(limit, offset)
    const rows = await stmt.all() as { results?: Array<{ namespace_id?: string; video_id?: string }> }
    const candidates = (rows.results || [])
        .map((row) => ({ namespaceId: String(row.namespace_id || '').trim(), videoId: String(row.video_id || '').trim() }))
        .filter((row) => row.namespaceId && row.videoId)
    let healed = 0
    let stillMissing = 0
    const failures: Array<{ namespaceId: string; videoId: string; error: string }> = []
    for (const row of candidates) {
        try {
            const result = await syncGalleryIndexEntry(c.env, row.namespaceId, row.videoId)
            if (result?.shopeeLink && result?.lazadaLink) healed += 1
            else stillMissing += 1
        } catch (error) {
            failures.push({
                ...row,
                error: error instanceof Error ? error.message : String(error),
            })
        }
    }
    return c.json({
        ok: true,
        scanned: candidates.length,
        healed,
        still_missing: stillMissing,
        offset,
        next_offset: offset + Math.max(0, stillMissing),
        failures,
    })
})

// Debug: test cover thumbnail generation
app.get('/admin/api/test-cover', async (c) => {
    const videoId = String(c.req.query('video_id') || '').trim()
    const ns = String(c.req.query('namespace_id') || c.get('botId') || '').trim()
    if (!videoId || !ns) return c.json({ error: 'video_id and namespace_id required' }, 400)

    const workerUrl = String(c.env.WORKER_URL || '').trim()
    const assetUrl = buildWorkerGalleryAssetUrl(workerUrl, ns, videoId, 'original')

    try {
        // Test 1: Can the merge service be reached?
        const healthResp = await fetchMergeService(c.env, '/health')
        const healthOk = healthResp.ok
        const healthBody = await healthResp.text().catch(() => '')

        // Test 2: Can the merge service download the video?
        const thumbResp = await fetchMergeService(c.env, '/thumbnail', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                video_url: assetUrl,
                frame_seed: `test|${videoId}|1|1`,
                output_format: 'jpg',
                target_width: 270,
                target_height: 480,
            }),
        })
        const thumbOk = thumbResp.ok
        const thumbStatus = thumbResp.status
        const thumbSize = thumbOk ? (await thumbResp.arrayBuffer()).byteLength : 0
        const thumbError = !thumbOk ? await thumbResp.text().catch(() => '') : ''

        return c.json({
            videoId,
            namespace: ns,
            assetUrl,
            container_health: { ok: healthOk, body: healthBody.substring(0, 200) },
            thumbnail: { ok: thumbOk, status: thumbStatus, size: thumbSize, error: thumbError.substring(0, 300) },
        })
    } catch (e) {
        return c.json({ error: e instanceof Error ? e.message : String(e), assetUrl }, 500)
    }
})

