type LineAffiliateLinkKind = 'shopee' | 'lazada'

function getLineAffiliateTheme(kind: LineAffiliateLinkKind) {
    if (kind === 'shopee') {
        return {
            brand: 'Shopee',
            icon: '🛒',
            primary: '#EE4D2D',
            primaryDark: '#B5371E',
            tint: '#FFF1EC',
            tintStrong: '#FFDCD1',
            note: '#9A3412',
        }
    }
    return {
        brand: 'Lazada',
        icon: '💙',
        primary: '#0F146D',
        primaryDark: '#0A0E52',
        tint: '#EEF2FF',
        tintStrong: '#DCE4FF',
        note: '#1E3A8A',
    }
}

function normalizeHexColor(input: string): string {
    const normalized = String(input || '').trim().toUpperCase()
    return /^#[0-9A-F]{6}$/.test(normalized) ? normalized : ''
}

function normalizeCoverTextStyleFontId(rawValue: unknown): CoverTextStyleFontId {
    const normalized = String(rawValue || '').trim().toLowerCase()
    switch (normalized) {
        case 'kanit-bold':
        case 'prompt-bold':
        case 'sarabun-bold':
        case 'bai-jamjuree-bold':
        case 'mitr-bold':
        case 'krub-bold':
        case 'chakra-petch-bold':
        case 'ibm-plex-sans-thai-bold':
        case 'psl-x-omyim-bold':
            return normalized
        case 'fc-iconic-bold':
            return 'kanit-bold'
        case 'sukhumvit-bold':
            return 'prompt-bold'
        case 'sukhumvit-semibold':
            return 'sarabun-bold'
        default:
            return DEFAULT_COVER_TEXT_STYLE_FONT_ID
    }
}

function normalizeCoverTextStyleMode(rawValue: unknown): CoverTextStyleMode {
    const normalized = String(rawValue || '').trim().toLowerCase()
    return normalized === 'outline' ? 'outline' : 'box'
}

function normalizeCoverTextStyleOutlineWidth(rawValue: unknown): number {
    const parsed = Number(rawValue)
    if (!Number.isFinite(parsed)) return 8
    return Math.max(0, Math.min(40, Math.round(parsed)))
}

function normalizeCoverTextStyleBackgroundOpacity(rawValue: unknown): number {
    const parsed = Number(rawValue)
    if (!Number.isFinite(parsed)) return DEFAULT_COVER_TEXT_STYLE_BACKGROUND_OPACITY
    return Math.max(0, Math.min(1, Math.round(parsed * 100) / 100))
}

function normalizeCoverTextStyleSizeScale(rawValue: unknown): number {
    const parsed = Number(rawValue)
    if (!Number.isFinite(parsed)) return DEFAULT_COVER_TEXT_STYLE_SIZE_SCALE
    return Math.max(
        COVER_TEXT_STYLE_SIZE_SCALE_MIN,
        Math.min(COVER_TEXT_STYLE_SIZE_SCALE_MAX, Math.round(parsed * 100) / 100),
    )
}

function normalizeCoverTextStyleAutoFit(rawValue: unknown): boolean {
    if (rawValue === false || rawValue === 0) return false
    if (typeof rawValue === 'string' && ['false', '0', 'off', 'no'].includes(rawValue.trim().toLowerCase())) return false
    return true
}

function normalizeLineCoverText(input: unknown): string {
    let normalized = String(input || '')
        .replace(/\r\n/g, '\n')
        .replace(/\u00a0/g, ' ')
    // Allow users to force a line break via any of these delimiters:
    //   |  (pipe)         — "ของเล่นใหม่|เอาไว้เกลงแมว"
    //   \n (literal)      — "ของเล่นใหม่\nเอาไว้เกลงแมว"  (typed 2 chars, not a real newline)
    //   // (double slash) — "ของเล่นใหม่//เอาไว้เกลงแมว"
    normalized = normalized
        .replace(/\\n/g, '\n')
        .replace(/\s*\|\s*/g, '\n')
        .replace(/\s*\/\/\s*/g, '\n')
        // collapse runs of plain spaces/tabs within each line (not newlines)
        .split('\n')
        .map((line) => line.replace(/[ \t]+/g, ' ').trim())
        .filter((line, idx, arr) => line.length > 0 || (idx < arr.length - 1))
        .join('\n')
        .trim()
    if (!normalized) return ''
    return normalized.slice(0, MAX_LINE_COVER_TEXT_CHARS)
}

function extractAiHeadlineFromText(rawText: string): string {
    const normalized = String(rawText || '').trim()
    if (!normalized) return ''
    const quotedHeadlineMatch = normalized.match(/["']headline["']\s*:\s*["']([^"']+)["']/i)
    if (quotedHeadlineMatch?.[1]) return normalizeLineCoverText(quotedHeadlineMatch[1])
    const plainHeadlineMatch = normalized.match(/\bheadline\b\s*:\s*([^\n]+)/i)
    if (plainHeadlineMatch?.[1]) return normalizeLineCoverText(plainHeadlineMatch[1])
    const cleanedFirstLine = normalized
        .replace(/```json|```/gi, ' ')
        .replace(/[{}[\]"]/g, ' ')
        .replace(/\btextYPercent\b\s*:?\s*\d+/gi, ' ')
        .split('\n')
        .map((line) => line.trim())
        .find(Boolean) || ''
    return normalizeLineCoverText(cleanedFirstLine)
}

function isInvalidAiCoverHeadline(input: unknown): boolean {
    const normalized = normalizeLineCoverText(input)
    if (!normalized) return true

    const lowered = normalized.toLowerCase()
    const thaiMatches = normalized.match(/[ก-๙]/g) || []
    const alphaNumOnly = /^[A-Za-z0-9 _-]+$/.test(normalized)
    const genericTerms = new Set([
        'พัดลม',
        'แก้ว',
        'กล่อง',
        'เครื่องครัว',
        'สินค้า',
        'ของใช้',
        'ของเล่น',
    ])

    if (normalized.length < 4) return true
    if (thaiMatches.length < 2) return true
    if (alphaNumOnly) return true

    return lowered === 'headline'
        || lowered === 'headline:'
        || lowered === 'ข้อความปก'
        || lowered === 'ข้อความบนปก'
        || lowered === 'cover text'
        || genericTerms.has(normalized)
}

function buildLineCoverTextPositionOptions(): LineCoverTextPositionOption[] {
    return [20, 35, 50, 65, 80].map((yPct, index) => ({
        optionId: String(index + 1),
        yPct,
    }))
}

function normalizeLineCoverTextPositionOptions(input: unknown): LineCoverTextPositionOption[] {
    if (!Array.isArray(input)) return []
    return input
        .map((item, index) => {
            const optionId = String((item as { optionId?: unknown })?.optionId || index + 1).trim()
            const rawYPct = Number((item as { yPct?: unknown })?.yPct)
            const previewUrl = String((item as { previewUrl?: unknown })?.previewUrl || '').trim()
            if (!optionId || !Number.isFinite(rawYPct)) return null
            return {
                optionId: optionId.slice(0, 16),
                yPct: Math.max(10, Math.min(90, Math.round(rawYPct))),
                ...(previewUrl ? { previewUrl: previewUrl.slice(0, 1024) } : {}),
            }
        })
        .filter((item): item is LineCoverTextPositionOption => !!item)
        .slice(0, 5)
}

function getLineCoverTemplateAccentColor(templateId: string): string {
    const normalized = normalizeCoverTemplateId(templateId)
    switch (normalized) {
        case 'template-2': return '#14B8A6'
        case 'template-3': return '#F97316'
        case 'template-4': return '#8B5CF6'
        case 'template-5': return '#EF4444'
        case 'template-6': return '#F59E0B'
        case 'template-7': return '#10B981'
        case 'template-8': return '#0F172A'
        case 'template-9': return '#EC4899'
        case 'template-1':
        default:
            return '#E53935'
    }
}

function createDefaultCoverTextStyle(templateId: string): CoverTextStyleSettings {
    const normalizedTemplateId = normalizeCoverTemplateId(templateId)
    return {
        fontId: DEFAULT_COVER_TEXT_STYLE_FONT_ID,
        textColor: '#FFFFFF',
        secondaryTextColor: '#FFFFFF',
        backgroundColor: getLineCoverTemplateAccentColor(normalizedTemplateId),
        backgroundOpacity: DEFAULT_COVER_TEXT_STYLE_BACKGROUND_OPACITY,
        sizeScale: DEFAULT_COVER_TEXT_STYLE_SIZE_SCALE,
        autoFit: true,
        mode: 'box',
        outlineColor: '#000000',
        outlineWidth: 8,
    }
}

function normalizeCoverTextStyle(
    input: Partial<CoverTextStyleSettings> | Record<string, unknown> | null | undefined,
    templateId: string,
): CoverTextStyleSettings {
    const defaults = createDefaultCoverTextStyle(templateId)
    const normalizedTextColor = normalizeHexColor(String(
        (input as Record<string, unknown> | null | undefined)?.textColor
        ?? (input as Record<string, unknown> | null | undefined)?.text_color
        ?? '',
    ))
    const normalizedBackgroundColor = normalizeHexColor(String(
        (input as Record<string, unknown> | null | undefined)?.backgroundColor
        ?? (input as Record<string, unknown> | null | undefined)?.background_color
        ?? '',
    ))

    const record = (input as Record<string, unknown> | null | undefined) || {}
    const outlineColorRaw = String(record.outlineColor ?? record.outline_color ?? '')
    const normalizedOutlineColor = normalizeHexColor(outlineColorRaw)
    const secondaryTextColorRaw = String(record.secondaryTextColor ?? record.secondary_text_color ?? '')
    const normalizedSecondaryTextColor = normalizeHexColor(secondaryTextColorRaw)
    const baseTextColor = normalizedTextColor || defaults.textColor
    return {
        fontId: normalizeCoverTextStyleFontId(record.fontId ?? record.font_id),
        textColor: baseTextColor,
        secondaryTextColor: normalizedSecondaryTextColor || baseTextColor,
        backgroundColor: normalizedBackgroundColor || defaults.backgroundColor,
        backgroundOpacity: normalizeCoverTextStyleBackgroundOpacity(
            record.backgroundOpacity ?? record.background_opacity,
        ),
        sizeScale: normalizeCoverTextStyleSizeScale(record.sizeScale ?? record.size_scale),
        autoFit: normalizeCoverTextStyleAutoFit(record.autoFit ?? record.auto_fit),
        mode: normalizeCoverTextStyleMode(record.mode ?? record.textMode ?? record.text_mode),
        outlineColor: normalizedOutlineColor || defaults.outlineColor,
        outlineWidth: normalizeCoverTextStyleOutlineWidth(
            record.outlineWidth ?? record.outline_width,
        ),
    }
}

function buildLineCompactFlexCard(params: {
    altText?: string
    pillText: string
    title: string
    message: string
    primary: string
    primaryDark: string
    surface: string
    detailLabel?: string
    detailText?: string
    actionLabel?: string
    actionUrl?: string
}): LineReplyMessage {
    const detailLabel = String(params.detailLabel || '').trim()
    const detailText = String(params.detailText || '').trim()
    const actionLabel = String(params.actionLabel || '').trim()
    const actionUrl = String(params.actionUrl || '').trim()

    return {
        type: 'flex',
        altText: params.altText || `${params.title} ${params.message}`,
        contents: {
            type: 'bubble',
            size: 'mega',
            body: {
                type: 'box',
                layout: 'vertical',
                spacing: 'md',
                paddingAll: '16px',
                contents: [
                    {
                        type: 'box',
                        layout: 'vertical',
                        spacing: 'md',
                        paddingAll: '16px',
                        cornerRadius: '20px',
                        backgroundColor: params.primary,
                        contents: [
                            {
                                type: 'box',
                                layout: 'horizontal',
                                justifyContent: 'center',
                                contents: [
                                    {
                                        type: 'box',
                                        layout: 'vertical',
                                        cornerRadius: '999px',
                                        paddingTop: '4px',
                                        paddingBottom: '4px',
                                        paddingStart: '12px',
                                        paddingEnd: '12px',
                                        backgroundColor: '#FFFFFF',
                                        contents: [{
                                            type: 'text',
                                            text: params.pillText,
                                            size: 'xs',
                                            weight: 'bold',
                                            color: params.primaryDark,
                                            align: 'center',
                                        }],
                                    },
                                ],
                            },
                            {
                                type: 'text',
                                text: params.title,
                                weight: 'bold',
                                size: 'xl',
                                wrap: true,
                                color: '#FFFFFF',
                            },
                            {
                                type: 'text',
                                text: params.message,
                                size: 'sm',
                                wrap: true,
                                color: '#FFF7F5',
                            },
                        ],
                    },
                    ...(detailLabel && detailText ? [{
                        type: 'box',
                        layout: 'vertical',
                        spacing: 'xs',
                        paddingAll: '14px',
                        cornerRadius: '16px',
                        backgroundColor: params.surface,
                        contents: [
                            {
                                type: 'text',
                                text: detailLabel,
                                size: 'xs',
                                weight: 'bold',
                                color: params.primary,
                            },
                            {
                                type: 'text',
                                text: detailText,
                                size: 'md',
                                weight: 'bold',
                                wrap: true,
                                color: '#111827',
                            },
                        ],
                    }] : []),
                ],
            },
            ...(actionLabel && actionUrl ? {
                footer: {
                    type: 'box',
                    layout: 'vertical',
                    spacing: 'sm',
                    paddingTop: '0px',
                    paddingBottom: '16px',
                    paddingStart: '16px',
                    paddingEnd: '16px',
                    contents: [
                        {
                            type: 'box',
                            layout: 'horizontal',
                            justifyContent: 'center',
                            contents: [
                                {
                                    type: 'box',
                                    layout: 'vertical',
                                    width: '72%',
                                    paddingTop: '10px',
                                    paddingBottom: '10px',
                                    paddingStart: '14px',
                                    paddingEnd: '14px',
                                    cornerRadius: '999px',
                                    backgroundColor: params.primary,
                                    action: {
                                        type: 'uri',
                                        label: actionLabel,
                                        uri: actionUrl,
                                    },
                                    contents: [
                                        {
                                            type: 'text',
                                            text: actionLabel,
                                            size: 'sm',
                                            weight: 'bold',
                                            color: '#FFFFFF',
                                            align: 'center',
                                        },
                                    ],
                                },
                            ],
                        },
                    ],
                },
            } : {}),
        },
    }
}

function buildLineAffiliatePromptFlex(params: {
    title: string
    brand: LineAffiliateLinkKind
    message?: string
}): LineReplyMessage {
    const theme = getLineAffiliateTheme(params.brand)
    const message = params.message || `ส่งลิงก์ ${theme.brand} มาเลย`
    return buildLineCompactFlexCard({
        altText: `${params.title} ${message}`,
        pillText: `${theme.icon} ${theme.brand}`,
        title: params.title,
        message,
        primary: theme.primary,
        primaryDark: theme.primaryDark,
        surface: theme.tint,
    })
}

function buildLineCoverOptionSeed(videoId: string, optionIndex: number, optionCount: number, batchKey?: string): string {
    const normalizedVideoId = String(videoId || '').trim()
    const normalizedBatchKey = String(batchKey || 'base').trim() || 'base'
    const normalizedOptionIndex = Math.max(1, Math.floor(Number(optionIndex) || 0) || 1)
    const normalizedOptionCount = Math.max(normalizedOptionIndex, Math.floor(Number(optionCount) || 0) || 1)
    return `line-cover|${normalizedVideoId}|${normalizedBatchKey}|${normalizedOptionIndex}|${normalizedOptionCount}`
}

function createLineCoverOptionBatchKey(): string {
    return `${Date.now().toString(36)}${Math.random().toString(36).slice(2, 6)}`
}

function buildLineCoverOptions(videoId: string, count = 10, batchKey?: string): LineCoverOption[] {
    const normalizedVideoId = String(videoId || '').trim()
    const optionCount = Math.max(1, Math.min(10, Math.floor(Number(count) || 0) || 10))
    const normalizedBatchKey = String(batchKey || createLineCoverOptionBatchKey()).trim() || 'base'
    return Array.from({ length: optionCount }, (_, index) => ({
        optionId: String(index + 1),
        seed: buildLineCoverOptionSeed(normalizedVideoId, index + 1, optionCount, normalizedBatchKey),
    }))
}

function buildLineCoverSelectionPostbackData(videoId: string, optionId: string): string {
    return `cover_select:${String(videoId || '').trim()}:${String(optionId || '').trim()}`
}

function parseLineCoverSelectionPostbackData(input: unknown): { videoId: string; optionId: string } | null {
    const normalized = String(input || '').trim()
    const match = normalized.match(/^cover_select:([A-Za-z0-9_-]+):([A-Za-z0-9_-]+)$/)
    if (!match) return null
    return {
        videoId: String(match[1] || '').trim(),
        optionId: String(match[2] || '').trim(),
    }
}

function buildLineCoverTextPositionPostbackData(videoId: string, optionId: string): string {
    return `cover_text_pos:${String(videoId || '').trim()}:${String(optionId || '').trim()}`
}

function parseLineCoverTextPositionPostbackData(input: unknown): { videoId: string; optionId: string } | null {
    const normalized = String(input || '').trim()
    const match = normalized.match(/^cover_text_pos:([A-Za-z0-9_-]+):([A-Za-z0-9_-]+)$/)
    if (!match) return null
    return {
        videoId: String(match[1] || '').trim(),
        optionId: String(match[2] || '').trim(),
    }
}

function buildLineCoverOptionPreviewUrl(params: {
    workerUrl: string
    namespaceId: string
    videoId: string
    option: LineCoverOption
}): string {
    const workerUrl = String(params.workerUrl || '').trim().replace(/\/+$/, '')
    const namespaceId = String(params.namespaceId || '').trim()
    const videoId = String(params.videoId || '').trim()
    const seed = String(params.option?.seed || '').trim()
    if (!workerUrl || !namespaceId || !videoId || !seed) return ''
    return buildWorkerGalleryFrameUrl(workerUrl, namespaceId, videoId, {
        seed,
        format: 'jpg',
        width: 540,
        height: 960,
    })
}

function buildLineCoverTextPositionPreviewUrl(params: {
    workerUrl: string
    namespaceId: string
    videoId: string
    option: LineCoverOption
    coverText: string
    coverTextYPercent: number
    coverTemplateId?: string
    coverTextStyle?: Partial<CoverTextStyleSettings> | null
}): string {
    const coverText = normalizeLineCoverText(params.coverText)
    if (!coverText) return ''
    const cacheBust = `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`
    const normalizedWorkerUrl = String(params.workerUrl || '').trim().replace(/\/+$/, '')
    const normalizedNamespaceId = String(params.namespaceId || '').trim()
    const normalizedVideoId = String(params.videoId || '').trim()
    const normalizedSeed = String(params.option?.seed || '').trim()
    const coverTemplateId = normalizeCoverTemplateId(String(params.coverTemplateId || ''))
    const coverTextStyle = normalizeCoverTextStyle(params.coverTextStyle, coverTemplateId)
    if (!normalizedWorkerUrl || !normalizedNamespaceId || !normalizedVideoId || !normalizedSeed) return ''
    // Outline width is calibrated for the final 1080-wide cover. Scale it
    // proportionally for this smaller preview thumbnail so the visible stroke
    // ratio matches the final render (otherwise stroke looks ~2x too thick).
    const PREVIEW_WIDTH = 540
    const PREVIEW_HEIGHT = 960
    const FINAL_COVER_WIDTH = 1080
    const scaledOutlineWidth = Math.max(
        coverTextStyle.outlineWidth > 0 ? 1 : 0,
        Math.round(coverTextStyle.outlineWidth * PREVIEW_WIDTH / FINAL_COVER_WIDTH),
    )
    try {
        const url = new URL(`${normalizedWorkerUrl}/api/gallery/${encodeURIComponent(normalizedVideoId)}/frame-preview/${encodeURIComponent(cacheBust)}`)
        url.searchParams.set('namespace_id', normalizedNamespaceId)
        url.searchParams.set('seed', normalizedSeed)
        url.searchParams.set('format', 'jpg')
        url.searchParams.set('w', String(PREVIEW_WIDTH))
        url.searchParams.set('h', String(PREVIEW_HEIGHT))
        url.searchParams.set('ct', coverText)
        url.searchParams.set('cy', String(params.coverTextYPercent))
        url.searchParams.set('tid', coverTemplateId)
        url.searchParams.set('tf', coverTextStyle.fontId)
        url.searchParams.set('tc', coverTextStyle.textColor)
        url.searchParams.set('tc2', coverTextStyle.secondaryTextColor)
        url.searchParams.set('bc', coverTextStyle.backgroundColor)
        url.searchParams.set('bo', String(coverTextStyle.backgroundOpacity))
        url.searchParams.set('ts', String(coverTextStyle.sizeScale))
        url.searchParams.set('af', coverTextStyle.autoFit ? '1' : '0')
        url.searchParams.set('om', coverTextStyle.mode)
        url.searchParams.set('oc', coverTextStyle.outlineColor)
        url.searchParams.set('ow', String(scaledOutlineWidth))
        return url.toString()
    } catch {
        const paramsObj = new URLSearchParams()
        paramsObj.set('namespace_id', normalizedNamespaceId)
        paramsObj.set('seed', normalizedSeed)
        paramsObj.set('format', 'jpg')
        paramsObj.set('w', String(PREVIEW_WIDTH))
        paramsObj.set('h', String(PREVIEW_HEIGHT))
        paramsObj.set('ct', coverText)
        paramsObj.set('cy', String(params.coverTextYPercent))
        paramsObj.set('tid', coverTemplateId)
        paramsObj.set('tf', coverTextStyle.fontId)
        paramsObj.set('tc', coverTextStyle.textColor)
        paramsObj.set('tc2', coverTextStyle.secondaryTextColor)
        paramsObj.set('bc', coverTextStyle.backgroundColor)
        paramsObj.set('bo', String(coverTextStyle.backgroundOpacity))
        paramsObj.set('ts', String(coverTextStyle.sizeScale))
        paramsObj.set('af', coverTextStyle.autoFit ? '1' : '0')
        paramsObj.set('om', coverTextStyle.mode)
        paramsObj.set('oc', coverTextStyle.outlineColor)
        paramsObj.set('ow', String(scaledOutlineWidth))
        return `${normalizedWorkerUrl}/api/gallery/${encodeURIComponent(normalizedVideoId)}/frame-preview/${encodeURIComponent(cacheBust)}?${paramsObj.toString()}`
    }
}

