async function resolveLineCoverPreviewUrl(params: {
    env: Env
    bucket: R2Bucket
    namespaceId: string
    videoId: string
}): Promise<string> {
    const namespaceId = String(params.namespaceId || '').trim()
    const videoId = String(params.videoId || '').trim()
    if (!namespaceId || !videoId) return ''

    const jpgKey = `_inbox_cover/${videoId}_preview.jpg`
    const webpKey = `_inbox_cover/${videoId}.webp`
    const jpgObj = await params.bucket.head(jpgKey).catch(() => null)
    if (jpgObj) return `${params.env.WORKER_URL}/api/inbox-cover/${encodeURIComponent(videoId)}/preview?namespace_id=${encodeURIComponent(namespaceId)}`
    const webpObj = await params.bucket.head(webpKey).catch(() => null)
    if (webpObj) return `${params.env.WORKER_URL}/api/inbox-cover/${encodeURIComponent(videoId)}/preview?namespace_id=${encodeURIComponent(namespaceId)}`
    return ''
}

async function replyLineProcessingResult(params: {
    replyToken: string
    channelAccessToken: string
    namespaceId: string
    result: InboxProcessingStartResult
    previewUrl?: string
    preferProcessingOnly?: boolean
}) {
    const videoId = String(params.result.item.id || '').trim()
    const processingUrl = buildScopedTabWebAppUrl(LIFF_BASE, params.namespaceId, 'processing')
    const galleryUrl = buildScopedTabWebAppUrl(LIFF_BASE, params.namespaceId, 'gallery', videoId ? { q: videoId } : undefined)
    const previewUrl = String(params.previewUrl || '').trim()
    const preferProcessingOnly = !!params.preferProcessingOnly

    const buildProcessingMessage = (title: string, message: string) => (
        previewUrl
            ? buildLineCoverProcessingFlex({
                previewUrl,
                title,
                message,
                actionLabel: 'เปิดหน้าประมวลผล',
                actionUrl: processingUrl,
                videoId,
            })
            : buildLineProcessingReadyFlex({
                title,
                statusLabel: 'Processing',
                message,
                actionLabel: 'เปิดหน้าประมวลผล',
                actionUrl: processingUrl,
                videoId,
                theme: 'processing',
            })
    )

    if (params.result.outcome === 'already_processed' && !preferProcessingOnly) {
        await lineReply(params.replyToken, params.channelAccessToken, [
            buildLineProcessingReadyFlex({
                title: 'อัปเดตลิงก์เรียบร้อยแล้ว',
                statusLabel: 'พร้อมใช้',
                message: 'เปิด Gallery ได้เลย',
                actionLabel: 'เปิด Gallery',
                actionUrl: galleryUrl,
                videoId,
                theme: 'processed',
            }),
        ])
        return
    }

    const status = params.result.outcome === 'started'
        ? params.result.job.status
        : params.result.outcome === 'already_running'
            ? params.result.status
            : 'processing'
    const queued = status === 'queued'
    const alreadyRunning = params.result.outcome === 'already_running'

    await lineReply(params.replyToken, params.channelAccessToken, [
        buildProcessingMessage(
            alreadyRunning
                ? (queued ? 'เลือกปกแล้ว รอคิวประมวลผล' : 'เลือกปกแล้ว กำลังประมวลผล')
                : 'เลือกปกแล้ว กำลังประมวลผล',
            'เปิดหน้าประมวลผลเพื่อติดตามสถานะได้เลย',
        ),
    ])
}

async function pushLineProcessingResult(params: {
    channelAccessToken: string
    lineUserId: string
    namespaceId: string
    result: InboxProcessingStartResult
    previewUrl?: string
    preferProcessingOnly?: boolean
}) {
    const videoId = String(params.result.item.id || '').trim()
    const processingUrl = buildScopedTabWebAppUrl(LIFF_BASE, params.namespaceId, 'processing')
    const galleryUrl = buildScopedTabWebAppUrl(LIFF_BASE, params.namespaceId, 'gallery', videoId ? { q: videoId } : undefined)
    const previewUrl = String(params.previewUrl || '').trim()
    const preferProcessingOnly = !!params.preferProcessingOnly

    const buildProcessingMessage = (title: string, message: string) => (
        previewUrl
            ? buildLineCoverProcessingFlex({
                previewUrl,
                title,
                message,
                actionLabel: 'เปิดหน้าประมวลผล',
                actionUrl: processingUrl,
                videoId,
            })
            : buildLineProcessingReadyFlex({
                title,
                statusLabel: 'Processing',
                message,
                actionLabel: 'เปิดหน้าประมวลผล',
                actionUrl: processingUrl,
                videoId,
                theme: 'processing',
            })
    )

    let messages: LineReplyMessage[] = []
    if (params.result.outcome === 'already_processed' && !preferProcessingOnly) {
        messages = [
            buildLineProcessingReadyFlex({
                title: 'อัปเดตลิงก์เรียบร้อยแล้ว',
                statusLabel: 'พร้อมใช้',
                message: 'เปิด Gallery ได้เลย',
                actionLabel: 'เปิด Gallery',
                actionUrl: galleryUrl,
                videoId,
                theme: 'processed',
            }),
        ]
    } else {
        const status = params.result.outcome === 'started'
            ? params.result.job.status
            : params.result.outcome === 'already_running'
                ? params.result.status
                : 'processing'
        const queued = status === 'queued'
        const alreadyRunning = params.result.outcome === 'already_running'
        messages = [
            buildProcessingMessage(
                alreadyRunning
                    ? (queued ? 'เลือกปกแล้ว รอคิวประมวลผล' : 'เลือกปกแล้ว กำลังประมวลผล')
                    : 'เลือกปกแล้ว กำลังประมวลผล',
                'เปิดหน้าประมวลผลเพื่อติดตามสถานะได้เลย',
            ),
        ]
    }

    await linePushMessage(params.channelAccessToken, params.lineUserId, messages)
}

async function lineReply(
    replyToken: string,
    channelAccessToken: string,
    messages: LineReplyMessage[],
) {
    const enrichQuickReplyItems = (items: unknown[]): unknown[] => {
        const normalizedItems = items.filter((item) => !!item && typeof item === 'object')
        const hasCancel = normalizedItems.some((item) => {
            const action = (item as { action?: { text?: unknown; label?: unknown } })?.action
            return String(action?.text || '').trim() === 'ยกเลิกงาน'
                || String(action?.label || '').trim() === 'ยกเลิกงาน'
        })
        return (hasCancel ? normalizedItems : [...normalizedItems, LINE_CANCEL_QUICK_REPLY_ITEM]).slice(0, 13)
    }

    // Add quick reply to the last message
    const enriched = messages.map((msg, i) => {
        if (i === messages.length - 1) {
            const existingQuickReply = (msg as Record<string, unknown>)?.quickReply as { items?: unknown } | undefined
            const existingItems = Array.isArray(existingQuickReply?.items)
                ? existingQuickReply?.items.filter((item) => !!item && typeof item === 'object')
                : []
            if (existingItems.length > 0) {
                return { ...msg, quickReply: { items: enrichQuickReplyItems(existingItems) } }
            }
            return { ...msg, quickReply: { items: enrichQuickReplyItems(LINE_QUICK_REPLY_ITEMS) } }
        }
        return msg
    })
    const resp = await fetch('https://api.line.me/v2/bot/message/reply', {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${channelAccessToken}`,
        },
        body: JSON.stringify({ replyToken, messages: enriched }),
    })
    if (!resp.ok) {
        const errText = await resp.text().catch(() => '')
        throw new Error(`line_reply_failed_${resp.status}${errText ? `: ${errText}` : ''}`)
    }
}

async function lineReplyOrPush(params: {
    replyToken: string
    channelAccessToken: string
    lineUserId: string
    messages: LineReplyMessage[]
}): Promise<void> {
    if (!String(params.replyToken || '').trim()) {
        const pushResult = await linePushMessage(params.channelAccessToken, params.lineUserId, params.messages)
        if (!pushResult.ok) {
            throw new Error(`line_push_failed${pushResult.error ? `: ${pushResult.error}` : ''}`)
        }
        return
    }
    try {
        await lineReply(params.replyToken, params.channelAccessToken, params.messages)
        return
    } catch (error) {
        console.warn(`[LINE] reply failed, fallback to push: ${error instanceof Error ? error.message : String(error)}`)
    }
    const pushResult = await linePushMessage(params.channelAccessToken, params.lineUserId, params.messages)
    if (!pushResult.ok) {
        throw new Error(`line_push_failed${pushResult.error ? `: ${pushResult.error}` : ''}`)
    }
}

async function lineStartLoading(
    channelAccessToken: string,
    lineUserId: string,
    loadingSeconds: number,
): Promise<void> {
    const token = String(channelAccessToken || '').trim()
    const userId = String(lineUserId || '').trim()
    if (!token || !userId) return

    const seconds = Math.max(5, Math.min(60, Math.round(Number(loadingSeconds) || 0)))
    if (!seconds) return

    try {
        const resp = await fetch('https://api.line.me/v2/bot/chat/loading/start', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${token}`,
            },
            body: JSON.stringify({
                chatId: userId,
                loadingSeconds: seconds,
            }),
        })
        if (!resp.ok) {
            const errText = await resp.text().catch(() => '')
            console.warn(`[LINE] loading/start failed userId=${userId} status=${resp.status} body=${errText.slice(0, 200)}`)
        }
    } catch (e) {
        console.warn(`[LINE] loading/start error userId=${userId}: ${e instanceof Error ? e.message : String(e)}`)
    }
}

function normalizeManualCaption(input: unknown): string {
    const normalized = String(input || '')
        .replace(/\r\n/g, '\n')
        .replace(/\u00a0/g, ' ')
        .trim()
    if (!normalized) return ''
    return normalized.slice(0, MAX_LINE_MANUAL_CAPTION_CHARS)
}

function normalizeLineCoverOptions(input: unknown): LineCoverOption[] {
    if (!Array.isArray(input)) return []
    const normalized = input
        .map((item) => {
            const optionId = String((item as { optionId?: unknown })?.optionId || '').trim()
            const seed = String((item as { seed?: unknown })?.seed || '').trim()
            const previewUrl = String((item as { previewUrl?: unknown })?.previewUrl || '').trim()
            if (!optionId || !seed) return null
            return {
                optionId: optionId.slice(0, 32),
                seed: seed.slice(0, 160),
                ...(previewUrl ? { previewUrl: previewUrl.slice(0, 1024) } : {}),
            }
        })
        .filter((item): item is LineCoverOption => !!item)
    return normalized.slice(0, 10)
}

function normalizeLineWaitingVideoState(input: Partial<LineWaitingVideoState> | null | undefined): LineWaitingVideoState | null {
    const id = String(input?.id || '').trim()
    const videoUrl = String(input?.videoUrl || '').trim()
    if (!id || !videoUrl) return null
    const shopeeLink = pickFirstShopeeUrl(String(input?.shopeeLink || '')) || ''
    const lazadaLink = pickFirstLazadaUrl(String(input?.lazadaLink || '')) || ''
    const awaitingStepRaw = String(input?.awaitingStep || '').trim().toLowerCase()
    const awaitingStep: LineWaitingStep = awaitingStepRaw === 'cover_text_position'
        ? 'cover_text_position'
        : awaitingStepRaw === 'cover_text'
            ? 'cover_text'
            : awaitingStepRaw === 'cover'
                ? 'cover'
                : (awaitingStepRaw === 'caption' || (shopeeLink && lazadaLink))
                    ? 'caption'
                    : 'links'
    const selectedCoverOption = normalizeLineCoverOptions(input?.selectedCoverOption ? [input.selectedCoverOption] : [])[0] || null
    const coverTemplateId = normalizeCoverTemplateId(String(input?.coverTemplateId || ''))
    return {
        id,
        videoUrl,
        createdAt: String(input?.createdAt || '').trim() || new Date().toISOString(),
        sourceType: String(input?.sourceType || '').trim(),
        sourceLabel: String(input?.sourceLabel || '').trim(),
        shopeeLink,
        lazadaLink,
        manualCaption: normalizeManualCaption(input?.manualCaption),
        awaitingStep,
        coverCompleted: Boolean(input?.coverCompleted),
        coverPickerOpened: Boolean(input?.coverPickerOpened),
        coverOptions: normalizeLineCoverOptions(input?.coverOptions),
        selectedCoverOption,
        coverText: normalizeLineCoverText(input?.coverText),
        coverTextYPercent: Number.isFinite(Number(input?.coverTextYPercent))
            ? Math.max(10, Math.min(90, Math.round(Number(input?.coverTextYPercent))))
            : undefined,
        selectedCoverPreviewUrl: String(input?.selectedCoverPreviewUrl || '').trim().slice(0, 2048),
        coverTemplateId,
        coverTextStyle: normalizeCoverTextStyle(input?.coverTextStyle, coverTemplateId),
        coverTextPositionOptions: normalizeLineCoverTextPositionOptions(input?.coverTextPositionOptions),
    }
}

function normalizeLineCurrentVideoIntakeState(input: Partial<LineCurrentVideoIntakeState> | null | undefined): LineCurrentVideoIntakeState | null {
    const videoId = String(input?.videoId || '').trim()
    if (!videoId) return null
    return {
        videoId,
        createdAt: String(input?.createdAt || '').trim() || new Date().toISOString(),
        sourceType: String(input?.sourceType || '').trim(),
        sourceLabel: String(input?.sourceLabel || '').trim().slice(0, 2048),
    }
}

async function getLineCurrentVideoIntake(bucket: R2Bucket, lineUserId: string): Promise<LineCurrentVideoIntakeState | null> {
    const userId = String(lineUserId || '').trim()
    if (!userId) return null
    const key = `_waiting_video_current/${userId}.json`
    const obj = await bucket.get(key).catch(() => null)
    if (!obj) return null
    const raw = await obj.json().catch(() => null) as Partial<LineCurrentVideoIntakeState> | null
    const state = normalizeLineCurrentVideoIntakeState(raw)
    if (!state) {
        await bucket.delete(key).catch(() => { })
        return null
    }
    return state
}

async function putLineCurrentVideoIntake(bucket: R2Bucket, lineUserId: string, input: Partial<LineCurrentVideoIntakeState>): Promise<LineCurrentVideoIntakeState> {
    const userId = String(lineUserId || '').trim()
    const state = normalizeLineCurrentVideoIntakeState(input)
    if (!userId || !state) throw new Error('invalid_line_current_video_intake')
    await bucket.put(`_waiting_video_current/${userId}.json`, JSON.stringify(state), {
        httpMetadata: { contentType: 'application/json' },
    })
    return state
}

async function clearLineCurrentVideoIntake(bucket: R2Bucket, lineUserId: string): Promise<void> {
    const userId = String(lineUserId || '').trim()
    if (!userId) return
    await bucket.delete(`_waiting_video_current/${userId}.json`).catch(() => { })
}

async function clearLineCurrentVideoIntakeIfMatches(bucket: R2Bucket, lineUserId: string, videoId: string): Promise<void> {
    const userId = String(lineUserId || '').trim()
    const normalizedVideoId = String(videoId || '').trim()
    if (!userId || !normalizedVideoId) return
    const current = await getLineCurrentVideoIntake(bucket, userId).catch(() => null)
    if (current?.videoId !== normalizedVideoId) return
    await clearLineCurrentVideoIntake(bucket, userId)
}

async function isLineCurrentVideoIntake(bucket: R2Bucket, lineUserId: string, videoId: string): Promise<boolean> {
    const normalizedVideoId = String(videoId || '').trim()
    if (!String(lineUserId || '').trim() || !normalizedVideoId) return false
    const current = await getLineCurrentVideoIntake(bucket, lineUserId)
    return current?.videoId === normalizedVideoId
}

async function getLineWaitingVideoState(bucket: R2Bucket, lineUserId: string): Promise<LineWaitingVideoState | null> {
    const waitingObj = await bucket.get(`_waiting_video/${lineUserId}.json`)
    if (!waitingObj) return null
    const raw = await waitingObj.json().catch(() => null) as Partial<LineWaitingVideoState> | null
    const state = normalizeLineWaitingVideoState(raw)
    if (!state) {
        await bucket.delete(`_waiting_video/${lineUserId}.json`).catch(() => { })
        return null
    }
    const currentIntake = await getLineCurrentVideoIntake(bucket, lineUserId).catch(() => null)
    if (currentIntake?.videoId && state.id !== currentIntake.videoId) {
        return null
    }
    return state
}

async function putLineWaitingVideoState(bucket: R2Bucket, lineUserId: string, input: Partial<LineWaitingVideoState>): Promise<LineWaitingVideoState> {
    const state = normalizeLineWaitingVideoState(input)
    if (!state) throw new Error('invalid_line_waiting_state')
    await bucket.put(`_waiting_video/${lineUserId}.json`, JSON.stringify(state), {
        httpMetadata: { contentType: 'application/json' },
    })
    return state
}

async function clearLineWaitingVideoState(bucket: R2Bucket, lineUserId: string): Promise<void> {
    await bucket.delete(`_waiting_video/${lineUserId}.json`).catch(() => { })
}

async function markLineWaitingVideoCancelled(bucket: R2Bucket, lineUserId: string, videoId: string): Promise<void> {
    const normalizedVideoId = String(videoId || '').trim()
    if (!String(lineUserId || '').trim() || !normalizedVideoId) return
    await bucket.put(`_waiting_video_cancelled/${lineUserId}.json`, JSON.stringify({
        videoId: normalizedVideoId,
        cancelledAt: new Date().toISOString(),
    }), { httpMetadata: { contentType: 'application/json' } }).catch(() => { })
}

async function clearLineWaitingVideoCancelled(bucket: R2Bucket, lineUserId: string): Promise<void> {
    await bucket.delete(`_waiting_video_cancelled/${lineUserId}.json`).catch(() => { })
}

async function isLineWaitingVideoCancelled(bucket: R2Bucket, lineUserId: string, videoId: string): Promise<boolean> {
    const normalizedVideoId = String(videoId || '').trim()
    if (!String(lineUserId || '').trim() || !normalizedVideoId) return false
    const obj = await bucket.get(`_waiting_video_cancelled/${lineUserId}.json`).catch(() => null)
    if (!obj) return false
    const raw = await obj.json().catch(() => null) as { videoId?: unknown } | null
    return String(raw?.videoId || '').trim() === normalizedVideoId
}

async function listReadyLineWaitingVideoStates(bucket: R2Bucket): Promise<LineWaitingVideoState[]> {
    const list = await bucket.list({ prefix: '_waiting_video/' })
    const tasks = await Promise.all(list.objects.map(async (obj) => {
        const file = await bucket.get(obj.key).catch(() => null)
        if (!file) return null
        const raw = await file.json().catch(() => null) as Partial<LineWaitingVideoState> | null
        const state = normalizeLineWaitingVideoState(raw)
        if (!state) return null
        if (!state.shopeeLink || !state.lazadaLink) return null
        return state
    }))
    return tasks
        .filter((item): item is LineWaitingVideoState => !!item)
        .sort((a, b) => new Date(String(b.createdAt || '')).getTime() - new Date(String(a.createdAt || '')).getTime())
}

