function buildLineShortErrorMessage(error: unknown): string {
    const message = String(error instanceof Error ? error.message : error || '').trim()
    const normalized = message.toLowerCase()
    if (
        normalized.includes('managed_shortlink_conversion_failed')
        || normalized.includes('shortlink')
        || normalized.includes('fail_sys_session_expired')
        || normalized.includes('session过期')
        || normalized.includes('session expired')
        || normalized.includes('lazada_shortlink')
        || normalized.includes('shopee_shortlink')
    ) {
        return 'Shortlink ไม่สำเร็จ'
    }
    return 'เกิดข้อผิดพลาด กรุณาลองใหม่อีกครั้ง'
}

function stripLineAffiliateLinksFromText(input: string): string {
    return String(input || '')
        .replace(/https?:\/\/\S*shopee\S+/gi, ' ')
        .replace(/https?:\/\/shope\.ee\S+/gi, ' ')
        .replace(/https?:\/\/\S*(?:lazada|lzd\.co)\S+/gi, ' ')
        .replace(/[ \t]+/g, ' ')
        .replace(/\n{3,}/g, '\n\n')
        .trim()
}

async function promptLineCaptionCollection(params: {
    env: Env
    bucket: R2Bucket
    namespaceId: string
    channelAccessToken: string
    replyToken: string
    lineUserId: string
    waitingState: LineWaitingVideoState
}) {
    const waitingState = normalizeLineWaitingVideoState(params.waitingState)
    if (!waitingState) throw new Error('invalid_line_waiting_state')

    await putLineWaitingVideoState(params.bucket, params.lineUserId, {
        ...waitingState,
        awaitingStep: 'caption',
    })

    await syncWaitingVideoIntoPrimaryAdminNamespace({
        env: params.env,
        sourceNamespaceId: params.namespaceId,
        sourceBucket: params.bucket,
        waitingState: {
            ...waitingState,
            awaitingStep: 'caption',
        },
    }).catch((error) => {
        console.log(`[LINE-AUTO-IMPORT] ${waitingState.id}: ${error instanceof Error ? error.message : String(error)}`)
    })

    await lineReplyOrPush({
        replyToken: params.replyToken,
        channelAccessToken: params.channelAccessToken,
        lineUserId: params.lineUserId,
        messages: [
        buildLineCaptionPromptFlex({
            videoId: waitingState.id,
            namespaceId: params.namespaceId,
            manualCaption: waitingState.manualCaption,
        }),
        ],
    })
}

async function promptLineCoverPicker(params: {
    env: Env
    bucket: R2Bucket
    namespaceId: string
    channelAccessToken: string
    replyToken: string
    lineUserId: string
    waitingState: LineWaitingVideoState
    manualCaption?: string
    forceRefresh?: boolean
}) {
    const waitingState = normalizeLineWaitingVideoState(params.waitingState)
    if (!waitingState) throw new Error('invalid_line_waiting_state')
    const manualCaption = normalizeManualCaption(params.manualCaption)
    const coverTemplateSettings = await getNamespaceCoverTemplateSettings(params.env.DB, params.namespaceId).catch(() => ({
        template_id: DEFAULT_COVER_TEMPLATE_ID,
        text_style: createDefaultCoverTextStyle(DEFAULT_COVER_TEMPLATE_ID),
    }))
    const coverTemplateId = normalizeCoverTemplateId(String(coverTemplateSettings?.template_id || waitingState.coverTemplateId || ''))
    const coverTextStyle = normalizeCoverTextStyle(coverTemplateSettings?.text_style || waitingState.coverTextStyle, coverTemplateId)
    const nextWaitingState = await putLineWaitingVideoState(params.bucket, params.lineUserId, {
        ...waitingState,
        manualCaption: manualCaption || '',
        awaitingStep: 'cover',
        coverCompleted: false,
        coverPickerOpened: false,
        coverOptions: normalizeLineCoverOptions(waitingState.coverOptions),
        selectedCoverOption: null,
        coverText: '',
        coverTextYPercent: undefined,
        selectedCoverPreviewUrl: '',
        coverTemplateId,
        coverTextStyle,
        coverTextPositionOptions: [],
    })

        await promptLineCoverOptions({
            env: params.env,
            bucket: params.bucket,
            namespaceId: params.namespaceId,
            channelAccessToken: params.channelAccessToken,
            replyToken: params.replyToken,
            lineUserId: params.lineUserId,
            waitingState: nextWaitingState,
            manualCaption,
            forceRefresh: true,
        })
}

async function promptLineCoverOptions(params: {
    env: Env
    bucket: R2Bucket
    namespaceId: string
    channelAccessToken: string
    replyToken: string
    lineUserId: string
    waitingState: LineWaitingVideoState
    manualCaption?: string
    forceRefresh?: boolean
}) {
    const waitingState = normalizeLineWaitingVideoState(params.waitingState)
    if (!waitingState) throw new Error('invalid_line_waiting_state')
    const manualCaption = normalizeManualCaption(params.manualCaption)
    const coverOptions = !params.forceRefresh && waitingState.coverOptions && waitingState.coverOptions.length > 0
        ? waitingState.coverOptions
        : buildLineCoverOptions(waitingState.id, 10)
    const generatedOptions: LineCoverOption[] = []
    for (const option of coverOptions) {
        let previewUrl = String(option.previewUrl || '').trim()
        if (!previewUrl) {
            previewUrl = buildLineCoverOptionPreviewUrl({
                workerUrl: String(params.env.WORKER_URL || '').trim(),
                namespaceId: params.namespaceId,
                videoId: waitingState.id,
                option,
            })
        }
        generatedOptions.push(previewUrl ? { ...option, previewUrl } : option)
    }

    const nextWaitingState = await putLineWaitingVideoState(params.bucket, params.lineUserId, {
        ...waitingState,
        manualCaption: manualCaption || '',
        awaitingStep: 'cover',
        coverCompleted: false,
        coverPickerOpened: true,
        coverOptions: generatedOptions,
        coverTextPositionOptions: [],
    })

    // Do NOT swallow the send failure here. Callers (XHS intake, video upload,
    // cover commands) wrap this in try/catch and send a user-visible fallback
    // when the cover picker can't be delivered. Swallowing it would leave the
    // user stuck on the ack with no follow-up and no error.
    await lineReplyOrPush({
        replyToken: params.replyToken,
        channelAccessToken: params.channelAccessToken,
        lineUserId: params.lineUserId,
        messages: [
            buildLineCoverPickerFlex({
                videoId: waitingState.id,
                namespaceId: params.namespaceId,
                workerUrl: String(params.env.WORKER_URL || '').trim(),
                coverOptions: nextWaitingState.coverOptions || generatedOptions,
            }),
        ],
    })
}

async function promptLineCoverTextPositionOptions(params: {
    env: Env
    bucket: R2Bucket
    namespaceId: string
    channelAccessToken: string
    replyToken: string
    lineUserId: string
    waitingState: LineWaitingVideoState
    coverText: string
    coverTextStyle?: Partial<CoverTextStyleSettings> | null
}) {
    const waitingState = normalizeLineWaitingVideoState(params.waitingState)
    if (!waitingState?.selectedCoverOption) throw new Error('line_cover_selected_option_missing')
    const coverText = normalizeLineCoverText(params.coverText)
    if (!coverText) throw new Error('line_cover_text_missing')
    const coverTemplateSettings = await getNamespaceCoverTemplateSettings(params.env.DB, params.namespaceId).catch(() => ({
        template_id: waitingState.coverTemplateId || DEFAULT_COVER_TEMPLATE_ID,
        text_style: waitingState.coverTextStyle || createDefaultCoverTextStyle(waitingState.coverTemplateId || DEFAULT_COVER_TEMPLATE_ID),
    }))
    const coverTemplateId = normalizeCoverTemplateId(String(
        coverTemplateSettings?.template_id
        || waitingState.coverTemplateId
        || DEFAULT_COVER_TEMPLATE_ID,
    ))
    const resolvedCoverTextStyle = normalizeCoverTextStyle(
        params.coverTextStyle || coverTemplateSettings?.text_style || waitingState.coverTextStyle,
        coverTemplateId,
    )
    const positionOptions = buildLineCoverTextPositionOptions()
    const positionOptionsWithPreview: LineCoverTextPositionOption[] = positionOptions.map((positionOption) => {
        const previewUrl = String(positionOption.previewUrl || '').trim() || buildLineCoverTextPositionPreviewUrl({
            workerUrl: String(params.env.WORKER_URL || '').trim(),
            namespaceId: params.namespaceId,
            videoId: waitingState.id,
            option: waitingState.selectedCoverOption as LineCoverOption,
            coverText,
            coverTextYPercent: positionOption.yPct,
            coverTemplateId,
            coverTextStyle: resolvedCoverTextStyle,
        })
        return previewUrl ? { ...positionOption, previewUrl } : positionOption
    })
    const nextWaitingState = await putLineWaitingVideoState(params.bucket, params.lineUserId, {
        ...waitingState,
        awaitingStep: 'cover_text_position',
        coverText,
        coverTemplateId,
        coverTextStyle: resolvedCoverTextStyle,
        coverTextPositionOptions: positionOptionsWithPreview,
    })

    await lineReplyOrPush({
        replyToken: params.replyToken,
        channelAccessToken: params.channelAccessToken,
        lineUserId: params.lineUserId,
        messages: [
            buildLineCoverTextPositionPickerFlex({
                videoId: waitingState.id,
                namespaceId: params.namespaceId,
                workerUrl: String(params.env.WORKER_URL || '').trim(),
                option: waitingState.selectedCoverOption,
                coverText,
                coverTemplateId,
                coverTextStyle: resolvedCoverTextStyle,
                positionOptions: nextWaitingState.coverTextPositionOptions || positionOptionsWithPreview,
            }),
        ],
    })
}

async function continueLineFlowAfterCover(params: {
    env: Env
    bucket: R2Bucket
    namespaceId: string
    channelAccessToken: string
    replyToken: string
    lineUserId: string
    waitingState: LineWaitingVideoState
    manualCaption?: string
}) {
    const waitingState = normalizeLineWaitingVideoState(params.waitingState)
    if (!waitingState) throw new Error('invalid_line_waiting_state')
    const manualCaption = normalizeManualCaption(params.manualCaption || waitingState.manualCaption)
    const affiliateLinksRequired = true

    if (affiliateLinksRequired && (!String(waitingState.shopeeLink || '').trim() || !String(waitingState.lazadaLink || '').trim())) {
        const hasShopee = !!String(waitingState.shopeeLink || '').trim()
        await putLineWaitingVideoState(params.bucket, params.lineUserId, {
            ...waitingState,
            manualCaption,
            awaitingStep: 'links',
            coverCompleted: true,
            coverPickerOpened: false,
            coverTextPositionOptions: [],
        })
        await lineReplyOrPush({
            replyToken: params.replyToken,
            channelAccessToken: params.channelAccessToken,
            lineUserId: params.lineUserId,
            messages: [
            buildLineAffiliatePromptFlex({
                title: hasShopee ? 'รับปกแล้ว รอ Lazada' : 'รับปกแล้ว รอ Shopee',
                brand: hasShopee ? 'lazada' : 'shopee',
                message: hasShopee ? 'ส่งลิงก์ Lazada มาเลย' : 'ส่งลิงก์ Shopee มาเลย',
            }),
            ],
        })
        return
    }

    await promptLineCaptionCollection({
        env: params.env,
        bucket: params.bucket,
        namespaceId: params.namespaceId,
        channelAccessToken: params.channelAccessToken,
        replyToken: params.replyToken,
        lineUserId: params.lineUserId,
        waitingState: {
            ...waitingState,
            manualCaption,
            awaitingStep: 'caption',
            coverCompleted: true,
            coverPickerOpened: false,
            coverTextPositionOptions: [],
        },
    })
}

/**
 * AI-Auto "Pick Everything" for cover:
 *   - Gemini chooses the best frame out of 6 candidates.
 *   - Generates a 2-line Thai cover text.
 *   - Picks the best y-position (20/35/50/65/80).
 * Then materializes the cover assets and proceeds to the caption step.
 * Called when user taps "ให้ AI คิดให้" at the cover-picker stage.
 */
async function handleLineAiFullCoverAutoPick(params: {
    env: Env
    bucket: R2Bucket
    namespaceId: string
    channelAccessToken: string
    lineUserId: string
    waitingState: LineWaitingVideoState
}): Promise<void> {
    const waitingState = normalizeLineWaitingVideoState(params.waitingState)
    if (!waitingState || !waitingState.id) throw new Error('invalid_line_waiting_state')

    const suggestion = await generateAiInboxCoverSuggestion({
        env: params.env,
        bucket: params.bucket,
        namespaceId: params.namespaceId,
        videoId: waitingState.id,
    })
    if (!suggestion) {
        throw new Error('gemini_cover_suggestion_failed')
    }

    // Pull the user's saved cover template + text style so the AI-generated text
    // inherits the same font/color/outline settings as manual picks.
    const coverTemplateSettings = await getNamespaceCoverTemplateSettings(params.env.DB, params.namespaceId).catch(() => ({
        template_id: DEFAULT_COVER_TEMPLATE_ID,
        text_style: createDefaultCoverTextStyle(DEFAULT_COVER_TEMPLATE_ID),
    }))
    const coverTemplateId = normalizeCoverTemplateId(String(coverTemplateSettings?.template_id || ''))
    const coverTextStyle = normalizeCoverTextStyle(coverTemplateSettings?.text_style, coverTemplateId)

    await materializeSelectedLineCoverOptionAssets({
        env: params.env,
        bucket: params.bucket,
        namespaceId: params.namespaceId,
        videoId: waitingState.id,
        option: suggestion.option,
        coverText: suggestion.coverText,
        coverTextYPercent: suggestion.textYPercent,
        coverTemplateId,
        coverTextStyle,
    })

    const nextWaitingState: LineWaitingVideoState = {
        ...waitingState,
        selectedCoverOption: suggestion.option,
        coverText: suggestion.coverText,
        coverTextYPercent: suggestion.textYPercent,
        coverTemplateId,
        coverTextStyle,
        awaitingStep: 'caption',
        coverCompleted: true,
    }

    // Short summary so the user sees what AI chose (push because we already replied earlier).
    const previewLine = suggestion.coverText.replace(/\n/g, ' / ')
    await linePushMessage(params.channelAccessToken, params.lineUserId, [
        { type: 'text', text: `✅ AI เลือกปกและข้อความให้แล้ว\n"${previewLine}"\nตำแหน่ง ${suggestion.textYPercent}%` },
    ]).catch(() => { })

    // Route into the normal post-cover flow — will ask for caption or finalize.
    await continueLineFlowAfterCover({
        env: params.env,
        bucket: params.bucket,
        namespaceId: params.namespaceId,
        channelAccessToken: params.channelAccessToken,
        replyToken: '',
        lineUserId: params.lineUserId,
        waitingState: nextWaitingState,
        manualCaption: waitingState.manualCaption,
    })
}

async function materializeSelectedLineCoverOptionAssets(params: {
    env: Env
    bucket: R2Bucket
    namespaceId: string
    videoId: string
    option: LineCoverOption
    coverText?: string
    coverTextYPercent?: number
    coverTemplateId?: string
    coverTextStyle?: Partial<CoverTextStyleSettings> | null
}) {
    const namespaceId = String(params.namespaceId || '').trim()
    const videoId = String(params.videoId || '').trim()
    const option = params.option
    if (!namespaceId || !videoId || !option?.seed) throw new Error('invalid_line_cover_option_request')

    const originalVideoUrl = buildWorkerGalleryAssetUrl(
        String(params.env.WORKER_URL || '').trim(),
        namespaceId,
        videoId,
        'original',
    )
    if (!originalVideoUrl) throw new Error('line_cover_option_original_url_missing')

    const coverText = normalizeLineCoverText(params.coverText)
    const coverTextYPercent = Number.isFinite(params.coverTextYPercent)
        ? Math.max(10, Math.min(90, Math.round(Number(params.coverTextYPercent))))
        : undefined
    const coverTextStyle = normalizeCoverTextStyle(params.coverTextStyle, params.coverTemplateId || DEFAULT_COVER_TEMPLATE_ID)
    const overlay = coverText
        ? {
            text: coverText,
            yPercent: coverTextYPercent,
            fontId: coverTextStyle.fontId,
            textColor: coverTextStyle.textColor,
            secondaryTextColor: coverTextStyle.secondaryTextColor,
            backgroundColor: coverTextStyle.backgroundColor,
            backgroundOpacity: coverTextStyle.backgroundOpacity,
            sizeScale: coverTextStyle.sizeScale,
            autoFit: coverTextStyle.autoFit,
            mode: coverTextStyle.mode,
            outlineColor: coverTextStyle.outlineColor,
            outlineWidth: coverTextStyle.outlineWidth,
        }
        : undefined

    const [finalCoverBytes, jpgBytes] = await Promise.all([
        generateThumbnailViaContainer(params.env, originalVideoUrl, option.seed, undefined, 'webp', 1080, 1920, overlay),
        generateThumbnailViaContainer(params.env, originalVideoUrl, option.seed, undefined, 'jpg', 1080, 1920, overlay).catch(() => null),
    ])

    await params.bucket.put(`_inbox_cover/${videoId}.webp`, finalCoverBytes, {
        httpMetadata: { contentType: 'image/webp' },
    })

    if (jpgBytes && jpgBytes.length > 0) {
        await params.bucket.put(`_inbox_cover/${videoId}_preview.jpg`, jpgBytes, {
            httpMetadata: { contentType: 'image/jpeg' },
        })
    } else {
        await params.bucket.delete(`_inbox_cover/${videoId}_preview.jpg`).catch(() => { })
    }
}

async function finalizeLineWaitingVideoAndStartProcessing(params: {
    env: Env
    bucket: R2Bucket
    executionCtx?: ExecutionContext
    namespaceId: string
    channelAccessToken: string
    replyToken: string
    lineUserId: string
    waitingState: LineWaitingVideoState
    manualCaption?: string
    pushOnly?: boolean
}) {
    const waitingState = normalizeLineWaitingVideoState(params.waitingState)
    if (!waitingState) throw new Error('invalid_line_waiting_state')
    const manualCaption = normalizeManualCaption(params.manualCaption || waitingState.manualCaption)
    if (await isLineWaitingVideoCancelled(params.bucket, params.lineUserId, waitingState.id)) {
        await clearLineWaitingVideoState(params.bucket, params.lineUserId)
        return
    }
    const hasShopeeLink = !!String(waitingState.shopeeLink || '').trim()
    const hasLazadaLink = !!String(waitingState.lazadaLink || '').trim()
    if (!hasShopeeLink || !hasLazadaLink) {
        await putLineWaitingVideoState(params.bucket, params.lineUserId, {
            ...waitingState,
            manualCaption,
            awaitingStep: 'links',
            coverCompleted: true,
            coverPickerOpened: false,
            coverTextPositionOptions: [],
        })
        await lineReplyOrPush({
            replyToken: params.replyToken,
            channelAccessToken: params.channelAccessToken,
            lineUserId: params.lineUserId,
            messages: [
                buildLineAffiliatePromptFlex({
                    title: hasShopeeLink ? 'รอ Lazada' : 'รอ Shopee',
                    brand: hasShopeeLink ? 'lazada' : 'shopee',
                    message: hasShopeeLink ? 'ส่งลิงก์ Lazada มาเลย' : 'ส่งลิงก์ Shopee มาเลย',
                }),
            ],
        })
        return
    }
    const nowIso = new Date().toISOString()
    const inboxRecord = await putInboxVideoRecord(params.bucket, {
        id: waitingState.id,
        videoUrl: waitingState.videoUrl,
        chatId: deriveLineSubmissionChatId(params.lineUserId),
        createdAt: String(waitingState.createdAt || '').trim() || nowIso,
        sourceType: (waitingState.sourceType as InboxVideoSourceType) || 'line_video',
        sourceLabel: waitingState.sourceLabel || 'LINE video',
        shopeeLink: waitingState.shopeeLink,
        lazadaLink: waitingState.lazadaLink,
        shopeeOriginalLink: waitingState.shopeeLink,
        lazadaOriginalLink: waitingState.lazadaLink,
        manualCaption,
        captionProvidedAt: manualCaption ? nowIso : '',
        updatedAt: nowIso,
    })
    await syncInboxRecordLinksToNamespaceIndex({
        env: params.env,
        namespaceId: params.namespaceId,
        item: inboxRecord,
    }).catch((error) => {
        console.warn(`[LINE] inbox link sync failed for ${waitingState.id}: ${error instanceof Error ? error.message : String(error)}`)
        return false
    })
    upsertSystemInboxSnapshotVideo({
        env: params.env,
        adminNamespaceId: params.namespaceId,
        bucket: params.bucket,
        record: inboxRecord,
    }).catch((error) => {
        console.warn(`[LINE] system inbox snapshot update failed for ${waitingState.id}: ${error instanceof Error ? error.message : String(error)}`)
    })
    mirrorInboxRecordIntoPrimaryAdminSnapshot({
        env: params.env,
        sourceNamespaceId: params.namespaceId,
        record: inboxRecord,
    }).catch((error) => {
        console.warn(`[LINE] primary admin inbox mirror failed for ${waitingState.id}: ${error instanceof Error ? error.message : String(error)}`)
    })

    const executionCtx = params.executionCtx || {
        waitUntil(promise: Promise<unknown>) {
            promise.catch((error) => {
                console.error(`[LINE] background processing failed for ${waitingState.id}: ${error instanceof Error ? error.message : String(error)}`)
            })
        },
    } as ExecutionContext
    if (await isLineWaitingVideoCancelled(params.bucket, params.lineUserId, waitingState.id)) {
        await clearLineWaitingVideoState(params.bucket, params.lineUserId)
        return
    }
    const startResult = await ensureInboxVideoProcessingStarted({
        env: params.env,
        bucket: params.bucket,
        executionCtx,
        botId: params.namespaceId,
        item: inboxRecord,
        skipIfAlreadyProcessed: true,
    })

    await clearLineWaitingVideoState(params.bucket, params.lineUserId)
    await clearLineWaitingVideoCancelled(params.bucket, params.lineUserId)
    await clearLineCurrentVideoIntakeIfMatches(params.bucket, params.lineUserId, waitingState.id)

    const hasLinks = !!String(inboxRecord.shopeeLink || '').trim() || !!String(inboxRecord.lazadaLink || '').trim()
    const jobStatus = startResult.outcome === 'started'
        ? startResult.job.status
        : startResult.outcome === 'already_running'
            ? startResult.status
            : 'processed'
    const statusText = jobStatus === 'queued'
        ? 'ระบบใส่คิวไว้แล้ว จะทยอยประมวลผลต่ออัตโนมัติ'
        : jobStatus === 'processing'
            ? 'ระบบเริ่มประมวลผลให้อัตโนมัติแล้ว'
            : 'คลิปนี้มีไฟล์ประมวลผลแล้ว'
    // Surface the video id in the headline so the operator can correlate the
    // LINE confirmation with the matching row on the processing/gallery page
    // at app.pubilo.com (same id appears under each clip card). Previously this
    // said "✅ รับลิงก์ครบแล้ว" without identifying which clip — the operator
    // had no way to tell two consecutive uploads apart from chat history.
    const videoIdShort = String(inboxRecord.id || '').trim()
    const messages: LineReplyMessage[] = [
        {
            type: 'text',
            text: hasLinks
                ? `✅ ID: ${videoIdShort}\nรับลิงก์ครบแล้ว — เพิ่มคลิปไว้บนสุดของคลังต้นฉบับแล้ว ${statusText}`
                : `✅ ID: ${videoIdShort}\nรับวิดีโอแล้ว — เพิ่มคลิปไว้บนสุดของคลังต้นฉบับแล้ว ${statusText}`,
        },
    ]

    if (params.pushOnly) {
        await linePushMessage(params.channelAccessToken, params.lineUserId, messages)
        return
    }

    try {
        await lineReplyOrPush({
            replyToken: params.replyToken,
            channelAccessToken: params.channelAccessToken,
            lineUserId: params.lineUserId,
            messages,
        })
    } catch (replyError) {
        console.warn(`[LINE] finalize reply failed for ${waitingState.id}: ${replyError instanceof Error ? replyError.message : String(replyError)}`)
        await linePushMessage(params.channelAccessToken, params.lineUserId, messages)
    }
}

async function linePushMessage(
    channelAccessToken: string,
    lineUserId: string,
    messages: LineReplyMessage[],
): Promise<{ ok: boolean; error?: string }> {
    const token = String(channelAccessToken || '').trim()
    const userId = String(lineUserId || '').trim()
    if (!token || !userId) return { ok: false, error: 'missing_token_or_user_id' }
    try {
        const resp = await fetch('https://api.line.me/v2/bot/message/push', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${token}`,
            },
            body: JSON.stringify({ to: userId, messages }),
        })
        if (!resp.ok) {
            const errText = await resp.text().catch(() => '')
            console.warn(`[LINE] push failed userId=${userId} status=${resp.status} body=${errText.slice(0, 200)}`)
            return { ok: false, error: `HTTP ${resp.status}: ${errText.slice(0, 200)}` }
        }
        return { ok: true }
    } catch (e) {
        console.warn(`[LINE] push error userId=${userId}: ${e instanceof Error ? e.message : String(e)}`)
        return { ok: false, error: e instanceof Error ? e.message : String(e) }
    }
}

async function fetchLineUserProfile(
    channelAccessToken: string,
    lineUserId: string,
): Promise<{ displayName: string; pictureUrl: string }> {
    const token = String(channelAccessToken || '').trim()
    const userId = String(lineUserId || '').trim()
    if (!token || !userId) return { displayName: '', pictureUrl: '' }

    try {
        const resp = await fetch(`https://api.line.me/v2/bot/profile/${encodeURIComponent(userId)}`, {
            method: 'GET',
            headers: {
                'Authorization': `Bearer ${token}`,
            },
        })
        if (!resp.ok) return { displayName: '', pictureUrl: '' }
        const data = await resp.json().catch(() => ({})) as {
            displayName?: string
            pictureUrl?: string
        }
        return {
            displayName: String(data.displayName || '').trim().slice(0, 200),
            pictureUrl: String(data.pictureUrl || '').trim().slice(0, 1000),
        }
    } catch {
        return { displayName: '', pictureUrl: '' }
    }
}

app.post('/api/line/webhook', async (c) => {
    const channelSecret = c.env.LINE_CHANNEL_SECRET || ''
    const channelAccessToken = c.env.LINE_CHANNEL_ACCESS_TOKEN || ''
    if (!channelSecret || !channelAccessToken) {
        console.error('[LINE] Missing LINE_CHANNEL_SECRET or LINE_CHANNEL_ACCESS_TOKEN')
        return c.json({ error: 'LINE not configured' }, 500)
    }

    // Read body as text for signature verification
    const body = await c.req.text()
    const signature = c.req.header('x-line-signature') || ''

    // Verify HMAC-SHA256 signature
    const encoder = new TextEncoder()
    const key = await crypto.subtle.importKey(
        'raw',
        encoder.encode(channelSecret),
        { name: 'HMAC', hash: 'SHA-256' },
        false,
        ['sign'],
    )
    const sig = await crypto.subtle.sign('HMAC', key, encoder.encode(body))
    const expected = btoa(String.fromCharCode(...new Uint8Array(sig)))
    if (expected !== signature) {
        console.error('[LINE] Invalid signature')
        return c.json({ error: 'Invalid signature' }, 403)
    }

    // Parse events
    let parsed: { events?: any[] }
    try {
        parsed = JSON.parse(body)
    } catch {
        return c.json({ error: 'Invalid JSON' }, 400)
    }
    const events = parsed.events || []

    // Process events in background to return 200 immediately. This whole event
    // loop already runs inside the outer executionCtx.waitUntil, which keeps the
    // worker alive until every handler settles.
    //
    // Intentionally DO NOT pass c.executionCtx into handleLineEvent. If we did,
    // the direct-video / XHS handlers would register a SECOND, nested
    // executionCtx.waitUntil for their slow follow-up and then return early.
    // That nested promise is registered from inside an already-detached
    // waitUntil and is not reliably awaited: the outer promise settles, the
    // request is torn down, and the cover picker AND its fallback silently never
    // run — the live "ack then silence" failure. With executionCtx omitted, the
    // handlers await their follow-up inline, so this single outer waitUntil owns
    // the full lifetime. The HTTP 200 is still returned synchronously below.
    c.executionCtx.waitUntil((async () => {
        for (const event of events) {
            try {
                await handleLineEvent(event, c.env, channelAccessToken)
            } catch (e) {
                console.error('[LINE] Event handler error:', e instanceof Error ? e.message : String(e))
            }
        }
    })())

    return c.json({ ok: true })
})

// LIFF auto-login for LINE MINI App
app.post('/api/line/liff-login', async (c) => {
    const body = await c.req.json().catch(() => ({})) as {
        line_user_id?: string
        display_name?: string
        picture_url?: string
        id_token?: string
        invite_namespace?: string
    }

    const lineUserId = String(body.line_user_id || '').trim()
    if (!lineUserId) return c.json({ error: 'line_user_id required' }, 400)

    await ensureLineUsersTable(c.env.DB)

    let displayName = String(body.display_name || '').trim().slice(0, 200)
    let pictureUrl = String(body.picture_url || '').trim().slice(0, 1000)

    if (!displayName || !pictureUrl) {
        const fetchedProfile = await fetchLineUserProfile(String(c.env.LINE_CHANNEL_ACCESS_TOKEN || ''), lineUserId)
        if (fetchedProfile.displayName) displayName = fetchedProfile.displayName
        if (fetchedProfile.pictureUrl) pictureUrl = fetchedProfile.pictureUrl
    }

    // Check if this LINE user is linked to an existing email account
    const linkedRow = await c.env.DB.prepare(
        'SELECT email, status, namespace_id FROM line_users WHERE line_user_id = ?'
    ).bind(lineUserId).first().catch(() => null) as { email?: string; status?: string; namespace_id?: string } | null
    const linkedEmail = String(linkedRow?.email || '').trim()
    const existingStatus = String(linkedRow?.status || '').trim()

    // If linked to a real email (not synthetic), use that account directly
    const hasRealLink = linkedEmail && !linkedEmail.endsWith('@line.local')

    let email: string
    let namespaceId: string
    let isOwner: boolean
    let isSysAdmin: boolean

    if (hasRealLink) {
        // Use existing account (e.g. system admin linked their LINE)
        email = linkedEmail
        const nsRow = await c.env.DB.prepare(
            'SELECT namespace_id FROM email_namespaces WHERE email = ? LIMIT 1'
        ).bind(email).first().catch(() => null) as { namespace_id?: string } | null
        namespaceId = String(nsRow?.namespace_id || '').trim()
        if (!namespaceId) {
            namespaceId = await resolveLineNamespace(c.env.DB, lineUserId, displayName)
        }
        isOwner = await isNamespaceOwnerIdentity(c.env.DB, email, namespaceId)
        isSysAdmin = isOwner ? await isSystemAdmin(c.env.DB, email) : false
    } else {
        email = `line_${lineUserId}@line.local`
        const inviteNs = String(body.invite_namespace || '').trim()
        const syntheticSysAdmin = await isSystemAdmin(c.env.DB, email)

        if (syntheticSysAdmin) {
            const syntheticTeamMember = await isTeamMemberEmail(c.env.DB, email)
            namespaceId = await resolveManagedWorkspaceForRole(
                c.env.DB,
                email,
                String(linkedRow?.namespace_id || '').trim(),
                syntheticTeamMember ? String(linkedRow?.namespace_id || '').trim() : ''
            )
            await upsertOwnerNamespaceMapping(c.env.DB, email, namespaceId)
            await c.env.DB.prepare(
                'DELETE FROM team_members WHERE lower(trim(email)) = ?'
            ).bind(email).run().catch(() => { })
            isOwner = true
            isSysAdmin = true
        } else {
            // Check if already a team member somewhere
            const existingTeam = await c.env.DB.prepare(
                'SELECT owner_namespace_id FROM team_members WHERE lower(trim(email)) = ? LIMIT 1'
            ).bind(String(email || '').trim().toLowerCase()).first().catch(() => null) as { owner_namespace_id?: string } | null
            const existingOwnerNamespace = await c.env.DB.prepare(
                'SELECT namespace_id FROM email_namespaces WHERE email = ? LIMIT 1'
            ).bind(String(email || '').trim().toLowerCase()).first().catch(() => null) as { namespace_id?: string } | null
            const existingOwnerNamespaceId = String(existingOwnerNamespace?.namespace_id || '').trim()

            if (inviteNs) {
                // Invite link always wins for synthetic LINE accounts.
                // This fixes users who first entered as standalone Member and later accepted a Team invite.
                namespaceId = inviteNs
                isOwner = false
                await c.env.DB.prepare(
                    `DELETE FROM email_namespaces WHERE email = ?`
                ).bind(email).run().catch(() => { })
                await c.env.DB.prepare(
                    `DELETE FROM team_members WHERE lower(trim(email)) = ? AND owner_namespace_id <> ?`
                ).bind(email, inviteNs).run().catch(() => { })
                // Add as team member
                await c.env.DB.prepare(
                    `INSERT INTO team_members (owner_namespace_id, email) VALUES (?, ?) ON CONFLICT DO NOTHING`
                ).bind(inviteNs, email).run().catch(() => {})
                // Remove one pending invite
                const pending = await c.env.DB.prepare(
                    `SELECT email FROM team_members WHERE owner_namespace_id = ? AND email LIKE 'invite_%' LIMIT 1`
                ).bind(inviteNs).first() as { email?: string } | null
                if (pending?.email) {
                    await c.env.DB.prepare(
                        `DELETE FROM team_members WHERE owner_namespace_id = ? AND email = ?`
                    ).bind(inviteNs, pending.email).run().catch(() => {})
                }
            } else if (existingTeam?.owner_namespace_id) {
                // Existing team member → use team namespace
                namespaceId = existingTeam.owner_namespace_id
                isOwner = false
                await c.env.DB.prepare(
                    `DELETE FROM email_namespaces WHERE email = ?`
                ).bind(email).run().catch(() => { })
            } else if (existingOwnerNamespaceId) {
                namespaceId = existingOwnerNamespaceId
                isOwner = true
                await c.env.DB.prepare(
                    `DELETE FROM team_members WHERE lower(trim(email)) = ?`
                ).bind(String(email || '').trim().toLowerCase()).run().catch(() => { })
            } else {
                // Regular new user → create own namespace as Member
                namespaceId = String(linkedRow?.namespace_id || '').trim() || await resolveLineNamespace(c.env.DB, lineUserId, displayName)
                isOwner = true
            }
            isSysAdmin = false
        }
    }

    // Team members (invited) are auto-approved, Members (self-registered) need admin approval
    const isAdminEmail = isSysAdmin || (hasRealLink && await isSystemAdmin(c.env.DB, email))
    const teamCheck = await c.env.DB.prepare('SELECT owner_namespace_id FROM team_members WHERE LOWER(email) = LOWER(?) LIMIT 1').bind(email).first().catch(() => null) as { owner_namespace_id?: string } | null
    const isTeamMember = !!teamCheck?.owner_namespace_id
    let userStatus: string
    if (isAdminEmail || isTeamMember) {
        userStatus = 'approved'
    } else if (existingStatus === 'approved') {
        userStatus = 'approved'
        // Auto-fix: ensure email_namespaces exists for approved members
        if (!isTeamMember && namespaceId) {
            await c.env.DB.prepare(
                `INSERT INTO email_namespaces (email, namespace_id) VALUES (?, ?) ON CONFLICT(email) DO NOTHING`
            ).bind(email, namespaceId).run().catch(() => { })
            isOwner = true
        }
    } else {
        userStatus = 'pending'
    }

    // Update display_name, picture_url, and status
    await c.env.DB.prepare(
        `INSERT INTO line_users (line_user_id, namespace_id, email, display_name, picture_url, status)
         VALUES (?, ?, ?, ?, ?, ?)
         ON CONFLICT(line_user_id) DO UPDATE SET
            namespace_id = excluded.namespace_id,
            email = excluded.email,
            display_name = excluded.display_name,
            picture_url = excluded.picture_url,
            status = excluded.status,
            updated_at = datetime('now')`
    ).bind(lineUserId, namespaceId, email, displayName, pictureUrl, userStatus).run().catch(() => { })

    // If user is pending, return early without creating a session
    if (userStatus === 'pending') {
        return c.json({
            status: 'pending',
            message: 'รอการอนุมัติจากแอดมิน',
            line_display_name: displayName,
            line_picture_url: pictureUrl,
        })
    }

    // Reuse active session when possible so app/web don't invalidate each other.
    const existingUser = await c.env.DB.prepare(
        'SELECT email, session_token FROM users WHERE email = ? LIMIT 1'
    ).bind(email).first() as { email?: string; session_token?: string } | null
    const existingSessionToken = String(existingUser?.session_token || '').trim()
    const sessionToken = existingSessionToken.startsWith('sess_')
        ? existingSessionToken
        : ('sess_' + crypto.randomUUID().replace(/-/g, ''))

    if (existingUser) {
        await c.env.DB.prepare(
            'UPDATE users SET namespace_id = ?, session_token = ? WHERE email = ?'
        ).bind(namespaceId, sessionToken, email).run()
    } else {
        await c.env.DB.prepare(
            'INSERT INTO users (email, namespace_id, session_token) VALUES (?, ?, ?)'
        ).bind(email, namespaceId, sessionToken).run()
    }

    return c.json({
        status: 'approved',
        session_token: sessionToken,
        namespace_id: namespaceId,
        email,
        is_owner: isOwner,
        is_system_admin: isSysAdmin,
        is_team_member: isTeamMember,
        line_user_id: lineUserId,
        line_display_name: displayName,
        line_picture_url: pictureUrl,
    }, 200, {
        'Set-Cookie': buildSessionCookie(sessionToken),
        'Cache-Control': 'no-store',
    })
})

