app.post('/api/admin/approve-user', async (c) => {
    const adminCheck = await requireSystemAdminSession(c)
    if (!adminCheck.ok) return adminCheck.response

    const body = await c.req.json().catch(() => ({})) as { line_user_id?: string }
    const lineUserId = String(body.line_user_id || '').trim()
    if (!lineUserId) return c.json({ error: 'line_user_id required' }, 400)

    await ensureLineUsersTable(c.env.DB)
    await c.env.DB.prepare(
        `UPDATE line_users SET status = 'approved', updated_at = datetime('now') WHERE line_user_id = ?`
    ).bind(lineUserId).run()

    const approvedUser = await c.env.DB.prepare(
        'SELECT email, namespace_id FROM line_users WHERE line_user_id = ?'
    ).bind(lineUserId).first() as { email?: string; namespace_id?: string } | null
    const approvedEmail = String(approvedUser?.email || '').trim().toLowerCase()
    const approvedNamespaceId = String(approvedUser?.namespace_id || '').trim()
    const isTeam = approvedEmail
        ? await isTeamMemberEmail(c.env.DB, approvedEmail)
        : false

    if (approvedEmail && approvedNamespaceId && !isTeam) {
        await c.env.DB.prepare(
            `INSERT INTO email_namespaces (email, namespace_id) VALUES (?, ?) ON CONFLICT(email) DO UPDATE SET namespace_id = excluded.namespace_id`
        ).bind(approvedEmail, approvedNamespaceId).run().catch(() => { })
    }
    if (approvedEmail && approvedNamespaceId) {
        await upsertUserWorkspaceByEmail(c.env.DB, approvedEmail, approvedNamespaceId)
    }

    return c.json({ ok: true })
})

app.post('/api/admin/reject-user', async (c) => {
    const adminCheck = await requireSystemAdminSession(c)
    if (!adminCheck.ok) return adminCheck.response

    const body = await c.req.json().catch(() => ({})) as { line_user_id?: string }
    const lineUserId = String(body.line_user_id || '').trim()
    if (!lineUserId) return c.json({ error: 'line_user_id required' }, 400)

    await ensureLineUsersTable(c.env.DB)
    const rejectedUser = await c.env.DB.prepare(
        'SELECT email FROM line_users WHERE line_user_id = ? LIMIT 1'
    ).bind(lineUserId).first().catch(() => null) as { email?: string } | null
    const rejectedEmail = String(rejectedUser?.email || '').trim().toLowerCase()
    await c.env.DB.prepare(
        `DELETE FROM line_users WHERE line_user_id = ?`
    ).bind(lineUserId).run()
    if (rejectedEmail) {
        await c.env.DB.prepare('DELETE FROM email_namespaces WHERE email = ?').bind(rejectedEmail).run().catch(() => { })
        await c.env.DB.prepare('DELETE FROM team_members WHERE lower(trim(email)) = ?').bind(rejectedEmail).run().catch(() => { })
        await c.env.DB.prepare('DELETE FROM system_admins WHERE lower(trim(email)) = ?').bind(rejectedEmail).run().catch(() => { })
        await c.env.DB.prepare('DELETE FROM users WHERE lower(trim(email)) = ?').bind(rejectedEmail).run().catch(() => { })
    }

    return c.json({ ok: true })
})

app.post('/api/admin/members/role', async (c) => {
    const adminCheck = await requireSystemAdminSession(c)
    if (!adminCheck.ok) return adminCheck.response

    const body = await c.req.json().catch(() => ({})) as { line_user_id?: string; role?: string }
    const lineUserId = String(body.line_user_id || '').trim()
    const role = String(body.role || '').trim().toLowerCase()
    if (!lineUserId) return c.json({ error: 'line_user_id required' }, 400)
    if (!['admin', 'member', 'team'].includes(role)) return c.json({ error: 'invalid_role' }, 400)

    try {
        const result = await assignLineUserRole(c.env.DB, lineUserId, role, adminCheck.namespaceId)
        return c.json({ ok: true, ...result })
    } catch (error) {
        return c.json({ error: error instanceof Error ? error.message : String(error) }, 400)
    }
})

app.get('/api/admin/monitor', async (c) => {
    const adminCheck = await requireSystemAdminSession(c)
    if (!adminCheck.ok) return adminCheck.response

    await ensureCronRuntimeStateTable(c.env.DB)
    await ensurePostingLocksTable(c.env.DB)
    await ensurePostHistoryTraceColumns(c.env.DB)

    const activePagesRow = await c.env.DB.prepare(
        `SELECT COUNT(*) AS total,
                COUNT(DISTINCT bot_id) AS namespaces
         FROM pages
         WHERE is_active = 1
           AND TRIM(COALESCE(post_hours, '')) <> ''`
    ).first().catch(() => null) as { total?: number; namespaces?: number } | null

    const postingRowsRow = await c.env.DB.prepare(
        `SELECT COUNT(*) AS total
         FROM post_history
         WHERE status = 'posting'`
    ).first().catch(() => null) as { total?: number } | null

    const pendingCommentsRow = await c.env.DB.prepare(
        `SELECT COUNT(*) AS total
         FROM post_history
         WHERE comment_status IN ('pending', 'processing')`
    ).first().catch(() => null) as { total?: number } | null

    const failedPostsRow = await c.env.DB.prepare(
        `SELECT COUNT(*) AS total
         FROM post_history
         WHERE status = 'failed'
           AND datetime(posted_at) >= datetime('now', '-1 day')`
    ).first().catch(() => null) as { total?: number } | null

    const failedCommentsRow = await c.env.DB.prepare(
        `SELECT COUNT(*) AS total
         FROM post_history
         WHERE comment_status = 'failed'
           AND datetime(posted_at) >= datetime('now', '-1 day')`
    ).first().catch(() => null) as { total?: number } | null

    const latestCronSuccessRow = await c.env.DB.prepare(
        `SELECT posted_at
         FROM post_history
         WHERE trigger_source = 'cron'
           AND status = 'success'
         ORDER BY datetime(posted_at) DESC
         LIMIT 1`
    ).first().catch(() => null) as { posted_at?: string } | null

    const runtimeRow = await c.env.DB.prepare(
        `SELECT run_id, status, started_at, finished_at, heartbeat_at,
                current_page_id, current_page_name, current_namespace_id,
                pages_total, pages_visited, pages_posted, pages_failed, last_error
         FROM cron_runtime_state
         WHERE id = 'scheduled'
         LIMIT 1`
    ).first().catch(() => null) as Record<string, unknown> | null

    const staleCronPages = await c.env.DB.prepare(
        `SELECT
            p.bot_id AS namespace_id,
            p.id AS page_id,
            p.name AS page_name,
            p.post_hours,
            MAX(csl.created_at) AS last_cron_touched
         FROM pages p
         LEFT JOIN cron_schedule_locks csl
           ON csl.namespace_id = p.bot_id
          AND csl.page_id = p.id
         WHERE p.is_active = 1
           AND TRIM(COALESCE(p.post_hours, '')) <> ''
         GROUP BY p.bot_id, p.id, p.name, p.post_hours
         HAVING last_cron_touched IS NULL
             OR datetime(last_cron_touched) < datetime('now', '-2 hours')
         ORDER BY datetime(last_cron_touched) ASC
         LIMIT 20`
    ).all().catch(() => ({ results: [] as unknown[] })) as { results?: unknown[] }

    const postIssues = await c.env.DB.prepare(
        `SELECT id, bot_id, page_id, video_id, status, error_message, posted_at
         FROM post_history
         WHERE status = 'failed'
            OR status = 'posting'
         ORDER BY
            CASE WHEN status = 'posting' THEN 0 ELSE 1 END,
            datetime(posted_at) DESC
         LIMIT 20`
    ).all().catch(() => ({ results: [] as unknown[] })) as { results?: unknown[] }

    const commentIssues = await c.env.DB.prepare(
        `SELECT id, bot_id, page_id, video_id, comment_status, comment_error, posted_at
         FROM post_history
         WHERE comment_status IN ('pending', 'processing', 'failed')
         ORDER BY
            CASE
                WHEN comment_status = 'pending' THEN 0
                WHEN comment_status = 'processing' THEN 1
                ELSE 2
            END,
            datetime(posted_at) DESC
         LIMIT 20`
    ).all().catch(() => ({ results: [] as unknown[] })) as { results?: unknown[] }

    return c.json({
        summary: {
            active_pages: Number(activePagesRow?.total || 0),
            active_namespaces: Number(activePagesRow?.namespaces || 0),
            posting_rows: Number(postingRowsRow?.total || 0),
            pending_comments: Number(pendingCommentsRow?.total || 0),
            failed_posts_24h: Number(failedPostsRow?.total || 0),
            failed_comments_24h: Number(failedCommentsRow?.total || 0),
            latest_cron_success_at: String(latestCronSuccessRow?.posted_at || ''),
        },
        cron_runtime: runtimeRow || null,
        stale_cron_pages: Array.isArray(staleCronPages.results) ? staleCronPages.results : [],
        post_issues: Array.isArray(postIssues.results) ? postIssues.results : [],
        comment_issues: Array.isArray(commentIssues.results) ? commentIssues.results : [],
    }, 200, {
        'Cache-Control': 'no-store',
    })
})

async function handleLineEvent(event: any, env: Env, channelAccessToken: string, executionCtx?: ExecutionContext) {
    // Handle follow event (user adds bot as friend)
    if (event.type === 'follow') {
        await lineReply(event.replyToken, channelAccessToken, [
            { type: 'text', text: 'สวัสดี! ยินดีต้อนรับสู่ Affiliate AiBot 🎉\n\nส่งวิดีโอหรือลิงก์ XHS มาได้เลย\nจากนั้นเลือกปกคลิปก่อน\nแล้วค่อยส่งลิงก์ Shopee/Lazada\nสุดท้ายส่งแคปชั่น หรือกดข้ามให้ AI คิดให้\nระบบจะประมวลผลให้อัตโนมัติ!' },
        ])
        return
    }

    const lineUserId = event.source?.userId
    if (!lineUserId) return
    const replyToken = String(event.replyToken || '').trim()

    // Get or create namespace for this LINE user
    const displayName = '' // LINE profile lookup is optional; skip for now
    const namespaceId = await resolveLineNamespace(env.DB, lineUserId, displayName)
    const bucket = new BotBucket(env.BUCKET, namespaceId) as unknown as R2Bucket

    const incomingText = event.type === 'message' && event.message?.type === 'text'
        ? String(event.message?.text || '').trim()
        : ''
    if (replyToken && !isLineCancelCommand(incomingText)) {
        await lineStartLoading(channelAccessToken, lineUserId, 20)
    }

    if (event.type === 'postback') {
        await handleLinePostbackEvent({
            env,
            bucket,
            namespaceId,
            channelAccessToken,
            replyToken,
            lineUserId,
            data: String(event.postback?.data || '').trim(),
        })
        return
    }

    // Only handle message events
    if (event.type !== 'message') return

    const messageType = event.message?.type
    const messageId = event.message?.id

    if (messageType === 'video' && messageId) {
        await handleLineVideoMessage({
            env,
            bucket,
            executionCtx,
            namespaceId,
            channelAccessToken,
            replyToken,
            lineUserId,
            messageId,
        })
        return
    }

    if (messageType === 'text') {
        const text = String(event.message?.text || '').trim()
        if (!text) return

        await handleLineTextMessage({
            env,
            bucket,
            executionCtx,
            namespaceId,
            channelAccessToken,
            replyToken,
            lineUserId,
            text,
        })
        return
    }

    // Unsupported message type
    if (replyToken) {
        await lineReply(replyToken, channelAccessToken, [
            { type: 'text', text: 'รองรับเฉพาะวิดีโอหรือข้อความลิงก์สินค้า (Shopee/Lazada) เท่านั้น' },
        ])
    }
}

async function handleLineVideoMessage(params: {
    env: Env
    bucket: R2Bucket
    executionCtx?: ExecutionContext
    namespaceId: string
    channelAccessToken: string
    replyToken: string
    lineUserId: string
    messageId: string
}) {
    const { env, bucket, executionCtx, namespaceId, channelAccessToken, replyToken, lineUserId, messageId } = params
    const videoId = crypto.randomUUID().replace(/-/g, '').slice(0, 8)

    // A fresh direct video upload supersedes any older in-flight LINE intake.
    // Write the current-intake marker BEFORE the slow download/store so
    // (a) stale XHS/video background work stops short of pushing an abandoned
    // clip's cover picker, and (b) every later waiting-state read (cover picker,
    // postback selection) resolves to THIS video instead of being filtered out
    // by a leftover marker that points at a different videoId. Without this the
    // bot can silently lose the picker. Mirrors the XHS branch invariants. Do
    // NOT clear the user-level cancel marker here:
    // it is videoId-scoped, and clearing it could un-cancel an older in-flight
    // job; the current-intake marker alone supersedes older work.
    await putLineCurrentVideoIntake(bucket, lineUserId, {
        videoId,
        createdAt: new Date().toISOString(),
        sourceType: 'line_video',
        sourceLabel: 'LINE video',
    })

    // Keep LINE's legacy cover-picker-first UX, identical to the XHS branch: do
    // NOT consume the reply token (or push) with an intermediate "รับวิดีโอแล้ว…"
    // acknowledgement. The cover picker (or an explicit failure message) must be
    // the first visible response. The picker/error use the original reply token
    // first and fall back to push if LINE has expired it.
    //
    // The LINE webhook runs this whole handler inside ITS executionCtx.waitUntil
    // and deliberately passes no executionCtx down, so followupPromise is
    // awaited inline below and that outer waitUntil keeps the worker alive until
    // the picker/fallback is actually delivered. A nested executionCtx.waitUntil
    // here would double-detach and could be dropped before the follow-up runs.
    // The executionCtx branch is retained only for a hypothetical top-level
    // caller that is NOT already inside a waitUntil.
    const followupReplyToken = replyToken

    const followupPromise = (async () => {
        // Only the active (current) request may surface user-visible follow-ups.
        // A newer clip/link or a cancel command flips this guard, so superseded
        // background work exits silently instead of pushing stale covers.
        const isCurrentVideoIntake = () => isLineCurrentVideoIntake(bucket, lineUserId, videoId)

        // Download video content from LINE
        const contentResp = await fetch(`https://api-data.line.me/v2/bot/message/${messageId}/content`, {
            headers: { 'Authorization': `Bearer ${channelAccessToken}` },
        })
        if (!contentResp.ok) {
            if (!(await isCurrentVideoIntake())) return
            console.error(`[LINE] Failed to download video content: HTTP ${contentResp.status}`)
            await lineReplyOrPush({
                replyToken: followupReplyToken,
                channelAccessToken,
                lineUserId,
                messages: [
                    { type: 'text', text: 'ไม่สามารถดาวน์โหลดวิดีโอได้ กรุณาลองใหม่อีกครั้ง' },
                ],
            })
            await clearLineCurrentVideoIntakeIfMatches(bucket, lineUserId, videoId)
            return
        }

        const videoBuffer = await contentResp.arrayBuffer()
        assertDownloadedVideoResponse(contentResp, videoBuffer, `line-message:${messageId}`)
        console.log(`[LINE] Video downloaded: ${(videoBuffer.byteLength / 1024 / 1024).toFixed(1)}MB userId=${lineUserId}`)

        if (!(await isCurrentVideoIntake())) return
        const originalVideoUrl = await storeOriginalVideoBuffer({
            bucket,
            env,
            namespaceId,
            videoId,
            videoBuffer,
            contentType: 'video/mp4',
        })
        await backfillOriginalThumbnail(env, namespaceId, videoId).catch(() => { })

        const createdAt = new Date().toISOString()

        try {
            // Only write waiting state / prompt the picker if this intake is
            // still current — otherwise we would resurrect an abandoned clip.
            if (!(await isCurrentVideoIntake())) return
            const waitingState = await putLineWaitingVideoState(bucket, lineUserId, {
                id: videoId,
                videoUrl: originalVideoUrl,
                createdAt,
                sourceType: 'line_video',
                sourceLabel: 'LINE video',
                awaitingStep: 'cover',
                coverCompleted: false,
            })

            if (!(await isCurrentVideoIntake())) return
            await promptLineCoverOptions({
                env,
                bucket,
                namespaceId,
                channelAccessToken,
                replyToken: followupReplyToken,
                lineUserId,
                waitingState,
                forceRefresh: true,
            })
        } catch (e) {
            if (!(await isCurrentVideoIntake())) return
            console.warn(`[LINE] video cover prompt failed userId=${lineUserId}: ${e instanceof Error ? e.message : String(e)}`)
            await lineReplyOrPush({
                replyToken: followupReplyToken,
                channelAccessToken,
                lineUserId,
                messages: [
                    { type: 'text', text: 'รับวิดีโอแล้ว แต่โหลดตัวเลือกปกไม่สำเร็จ ลองส่งวิดีโอใหม่อีกครั้ง' },
                ],
            })
            await clearLineCurrentVideoIntakeIfMatches(bucket, lineUserId, videoId)
        }
    })().catch(async (e) => {
        // Last-resort guard: only the active request may surface an error;
        // stale/superseded background work exits silently.
        if (!(await isLineCurrentVideoIntake(bucket, lineUserId, videoId))) return
        console.error('[LINE] Video handling error:', e instanceof Error ? e.message : String(e))
        await lineReplyOrPush({
            replyToken: followupReplyToken,
            channelAccessToken,
            lineUserId,
            messages: [
                { type: 'text', text: 'เกิดข้อผิดพลาดในการรับวิดีโอ กรุณาลองใหม่อีกครั้ง' },
            ],
        }).catch(() => { })
        await clearLineCurrentVideoIntakeIfMatches(bucket, lineUserId, videoId)
    })

    // Only self-detach when a TOP-LEVEL caller supplies executionCtx. The LINE
    // webhook intentionally passes none (it already wraps us in waitUntil), so
    // we fall through and await inline, letting that outer waitUntil own the
    // lifetime instead of double-detaching the follow-up.
    if (executionCtx) {
        executionCtx.waitUntil(followupPromise)
        return
    }
    await followupPromise
}

async function ackAndStartLineWaitingVideoFinalization(params: {
    env: Env
    bucket: R2Bucket
    executionCtx?: ExecutionContext
    namespaceId: string
    channelAccessToken: string
    replyToken: string
    lineUserId: string
    waitingState: LineWaitingVideoState
    manualCaption?: string
}) {
    const waitingState = normalizeLineWaitingVideoState(params.waitingState)
    if (!waitingState) throw new Error('invalid_line_waiting_state')

    await lineReplyOrPush({
        replyToken: params.replyToken,
        channelAccessToken: params.channelAccessToken,
        lineUserId: params.lineUserId,
        messages: [
            { type: 'text', text: `รับคำสั่งแล้ว กำลังเริ่มประมวลผล ID: ${waitingState.id}\nถ้าไม่ต้องการรอในแชท เปิดหน้าประมวลผลดูสถานะได้เลย` },
        ],
    })

    const finalizePromise = finalizeLineWaitingVideoAndStartProcessing({
        env: params.env,
        bucket: params.bucket,
        executionCtx: params.executionCtx,
        namespaceId: params.namespaceId,
        channelAccessToken: params.channelAccessToken,
        replyToken: '',
        lineUserId: params.lineUserId,
        waitingState,
        manualCaption: params.manualCaption,
        pushOnly: true,
    }).catch(async (error) => {
        console.error('[LINE] Async finalize error:', error instanceof Error ? error.message : String(error))
        await linePushMessage(params.channelAccessToken, params.lineUserId, [
            { type: 'text', text: buildLineShortErrorMessage(error) },
        ]).catch(() => { })
    })

    if (params.executionCtx) {
        params.executionCtx.waitUntil(finalizePromise)
    } else {
        await finalizePromise
    }
}

async function handleLineTextMessage(params: {
    env: Env
    bucket: R2Bucket
    executionCtx?: ExecutionContext
    namespaceId: string
    channelAccessToken: string
    replyToken: string
    lineUserId: string
    text: string
}) {
    const { env, bucket, executionCtx, namespaceId, channelAccessToken, replyToken, lineUserId, text } = params

    const extractShopeeLink = (input: string): string => {
        const match = input.match(/https?:\/\/\S*shopee\S+/i) || input.match(/https?:\/\/shope\.ee\S+/i)
        return String(match?.[0] || '').trim()
    }
    const extractLazadaLink = (input: string): string => {
        const match = input.match(/https?:\/\/\S*(?:lazada|lzd\.co)\S+/i)
        return String(match?.[0] || '').trim()
    }

    const shopeeLink = extractShopeeLink(text)
    const lazadaLink = extractLazadaLink(text)
    const lowerText = text.trim().toLowerCase()
    const waitingState = await getLineWaitingVideoState(bucket, lineUserId)

    if (isLineCancelCommand(text)) {
        const currentIntake = await getLineCurrentVideoIntake(bucket, lineUserId).catch(() => null)
        if (waitingState) {
            await markLineWaitingVideoCancelled(bucket, lineUserId, waitingState.id)
            if (!currentIntake || currentIntake.videoId === waitingState.id) {
                await clearLineCurrentVideoIntake(bucket, lineUserId)
            }
            await clearLineWaitingVideoState(bucket, lineUserId)
            await lineReply(replyToken, channelAccessToken, [
                { type: 'text', text: 'ยกเลิกงานที่ค้างไว้แล้ว ส่งวิดีโอหรือลิงก์ใหม่ได้เลย' },
            ]).catch(() => { })
            return
        }
        if (currentIntake) {
            await markLineWaitingVideoCancelled(bucket, lineUserId, currentIntake.videoId)
            await clearLineCurrentVideoIntake(bucket, lineUserId)
            await clearLineWaitingVideoState(bucket, lineUserId)
            await lineReply(replyToken, channelAccessToken, [
                { type: 'text', text: 'ยกเลิกงานที่ค้างไว้แล้ว ส่งวิดีโอหรือลิงก์ใหม่ได้เลย' },
            ]).catch(() => { })
            return
        }
        await lineReply(replyToken, channelAccessToken, [
            { type: 'text', text: 'ตอนนี้ไม่มีงานที่ค้างให้ยกเลิก' },
        ]).catch(() => { })
        return
    }

    if (waitingState?.awaitingStep === 'cover_text_position') {
        if (!waitingState.selectedCoverOption) {
            await promptLineCoverPicker({
                env,
                bucket,
                namespaceId,
                channelAccessToken,
                replyToken,
                lineUserId,
                waitingState,
                manualCaption: waitingState.manualCaption,
            }).catch(() => { })
            return
        }

        if (isLineCoverTextSkipCommand(text)) {
            try {
                await materializeSelectedLineCoverOptionAssets({
                    env,
                    bucket,
                    namespaceId,
                    videoId: waitingState.id,
                    option: waitingState.selectedCoverOption,
                    coverTemplateId: waitingState.coverTemplateId,
                    coverTextStyle: waitingState.coverTextStyle,
                })
                await continueLineFlowAfterCover({
                    env, bucket, namespaceId, channelAccessToken, replyToken, lineUserId, waitingState,
                    manualCaption: waitingState.manualCaption,
                })
            } catch (e) {
                console.error('[LINE] Cover text skip finalize error:', e instanceof Error ? e.message : String(e))
                await lineReply(replyToken, channelAccessToken, [
                    { type: 'text', text: 'เกิดข้อผิดพลาด กรุณาลองใหม่อีกครั้ง' },
                ]).catch(() => { })
            }
            return
        }

        const coverTextCandidate = normalizeLineCoverText(stripLineAffiliateLinksFromText(text))
        if (coverTextCandidate) {
            try {
                await promptLineCoverTextPositionOptions({
                    env,
                    bucket,
                    namespaceId,
                    channelAccessToken,
                    replyToken,
                    lineUserId,
                    waitingState,
                    coverText: coverTextCandidate,
                })
            } catch (e) {
                console.error('[LINE] Cover text position refresh error:', e instanceof Error ? e.message : String(e))
                await lineReply(replyToken, channelAccessToken, [
                    { type: 'text', text: 'เกิดข้อผิดพลาดในการสร้างตัวเลือกความสูง กรุณาลองอีกครั้ง' },
                ]).catch(() => { })
            }
            return
        }

        await lineReply(replyToken, channelAccessToken, [
            buildLineCoverTextPositionPickerFlex({
                videoId: waitingState.id,
                namespaceId,
                workerUrl: String(env.WORKER_URL || '').trim(),
                option: waitingState.selectedCoverOption,
                coverText: waitingState.coverText || '',
                coverTemplateId: waitingState.coverTemplateId,
                coverTextStyle: waitingState.coverTextStyle,
                positionOptions: waitingState.coverTextPositionOptions && waitingState.coverTextPositionOptions.length > 0
                    ? waitingState.coverTextPositionOptions
                    : buildLineCoverTextPositionOptions(),
            }),
        ]).catch(() => { })
        return
    }

    if (waitingState?.awaitingStep === 'cover_text') {
        if (!waitingState.selectedCoverOption) {
            await promptLineCoverPicker({
                env,
                bucket,
                namespaceId,
                channelAccessToken,
                replyToken,
                lineUserId,
                waitingState,
                manualCaption: waitingState.manualCaption,
            }).catch(() => { })
            return
        }

        if (isLineAiThinkCommand(text)) {
            await lineReply(replyToken, channelAccessToken, [
                { type: 'text', text: 'ระบบปิดตัวเลือก AI คิดข้อความบนปกไว้ชั่วคราว พิมพ์ข้อความเองได้เลย หรือกดไม่ใส่ข้อความ' },
            ]).catch(() => { })
            return
        }

        if (isLineCoverTextSkipCommand(text)) {
            try {
                await materializeSelectedLineCoverOptionAssets({
                    env,
                    bucket,
                    namespaceId,
                    videoId: waitingState.id,
                    option: waitingState.selectedCoverOption,
                    coverTemplateId: waitingState.coverTemplateId,
                    coverTextStyle: waitingState.coverTextStyle,
                })
                await continueLineFlowAfterCover({
                    env, bucket, namespaceId, channelAccessToken, replyToken, lineUserId, waitingState,
                    manualCaption: waitingState.manualCaption,
                })
            } catch (e) {
                console.error('[LINE] Cover text prompt skip error:', e instanceof Error ? e.message : String(e))
                await lineReply(replyToken, channelAccessToken, [
                    { type: 'text', text: 'เกิดข้อผิดพลาด กรุณาลองใหม่อีกครั้ง' },
                ]).catch(() => { })
            }
            return
        }

        const coverTextCandidate = normalizeLineCoverText(stripLineAffiliateLinksFromText(text))
        if (!coverTextCandidate || /^https?:\/\/\S+$/i.test(text)) {
            await lineReply(replyToken, channelAccessToken, [
                buildLineCoverTextPromptMessage(),
            ]).catch(() => { })
            return
        }

        try {
            await promptLineCoverTextPositionOptions({
                env,
                bucket,
                namespaceId,
                channelAccessToken,
                replyToken,
                lineUserId,
                waitingState,
                coverText: coverTextCandidate,
            })
        } catch (e) {
            console.error('[LINE] Cover text prompt error:', e instanceof Error ? e.message : String(e))
            await lineReply(replyToken, channelAccessToken, [
                { type: 'text', text: 'เกิดข้อผิดพลาดในการสร้างตัวเลือกความสูง กรุณาลองอีกครั้ง' },
            ]).catch(() => { })
        }
        return
    }

    // Cover step (must be before caption check)
    if (waitingState?.awaitingStep === 'cover') {
        if (!waitingState.coverPickerOpened && lowerText === 'เลือกปก') {
            try {
                await promptLineCoverOptions({
                    env,
                    bucket,
                    namespaceId,
                    channelAccessToken,
                    replyToken,
                    lineUserId,
                    waitingState,
                    manualCaption: waitingState.manualCaption,
                })
            } catch (e) {
                console.error('[LINE] Cover option prompt error:', e instanceof Error ? e.message : String(e))
                await lineReply(replyToken, channelAccessToken, [
                    { type: 'text', text: 'เกิดข้อผิดพลาดในการโหลดตัวเลือกหน้าปก กรุณาลองอีกครั้ง' },
                ]).catch(() => { })
            }
            return
        }

        if (isLineCoverReshuffleCommand(text)) {
            if (!waitingState.coverPickerOpened) {
                try {
                    await promptLineCoverOptions({
                        env,
                        bucket,
                        namespaceId,
                        channelAccessToken,
                        replyToken,
                        lineUserId,
                        waitingState,
                        manualCaption: waitingState.manualCaption,
                        forceRefresh: true,
                    })
                } catch (e) {
                    console.error('[LINE] Cover first-load reshuffle error:', e instanceof Error ? e.message : String(e))
                    await lineReply(replyToken, channelAccessToken, [
                        { type: 'text', text: 'เกิดข้อผิดพลาดในการโหลดตัวเลือกหน้าปก กรุณาลองอีกครั้ง' },
                    ]).catch(() => { })
                }
                return
            }
            try {
                await promptLineCoverOptions({
                    env,
                    bucket,
                    namespaceId,
                    channelAccessToken,
                    replyToken,
                    lineUserId,
                    waitingState,
                    manualCaption: waitingState.manualCaption,
                    forceRefresh: true,
                })
            } catch (e) {
                console.error('[LINE] Cover reshuffle error:', e instanceof Error ? e.message : String(e))
                await lineReply(replyToken, channelAccessToken, [
                    { type: 'text', text: 'เกิดข้อผิดพลาดในการสุ่มหน้าปกใหม่ กรุณาลองอีกครั้ง' },
                ]).catch(() => { })
            }
            return
        }

        if (isLineAiThinkCommand(text)) {
            // AI picks: best frame + 2-line cover text + y-position (all via Gemini)
            try {
                await lineReply(replyToken, channelAccessToken, [
                    { type: 'text', text: '✨ AI กำลังเลือกปก+คิดข้อความ+ตำแหน่งให้... สักครู่นะ' },
                ]).catch(() => { })
                await handleLineAiFullCoverAutoPick({
                    env, bucket, namespaceId, channelAccessToken, lineUserId, waitingState,
                })
            } catch (e) {
                console.error('[LINE] AI full cover auto-pick error:', e instanceof Error ? e.message : String(e))
                await linePushMessage(channelAccessToken, lineUserId, [
                    { type: 'text', text: 'ขออภัย AI ทำปกไม่สำเร็จ ลองเลือกปกเองจาก 10 รูป หรือกดสุ่มอีกครั้ง' },
                ]).catch(() => { })
            }
            return
        }

        if (isLineCoverSkipCommand(text) || isLineCaptionSkipCommand(text)) {
            await lineReply(replyToken, channelAccessToken, [
                { type: 'text', text: 'ขั้นตอนนี้ต้องเลือกปกก่อน เลือกจาก 10 รูปได้เลย หรือกด "ให้ AI คิดให้" / "สุ่มอีกครั้ง"' },
            ]).catch(() => { })
            return
        }

        if (!waitingState.coverPickerOpened) {
            try {
                await promptLineCoverOptions({
                    env,
                    bucket,
                    namespaceId,
                    channelAccessToken,
                    replyToken,
                    lineUserId,
                    waitingState,
                    manualCaption: waitingState.manualCaption,
                    forceRefresh: true,
                })
            } catch (e) {
                console.error('[LINE] Cover first prompt error:', e instanceof Error ? e.message : String(e))
                await lineReply(replyToken, channelAccessToken, [
                    { type: 'text', text: 'เกิดข้อผิดพลาดในการโหลดตัวเลือกหน้าปก กรุณาลองอีกครั้ง' },
                ]).catch(() => { })
            }
            return
        }

        await lineReply(replyToken, channelAccessToken, [
            buildLineCoverPickerFlex({
                videoId: waitingState.id,
                namespaceId,
                workerUrl: String(env.WORKER_URL || '').trim(),
                coverOptions: waitingState.coverOptions && waitingState.coverOptions.length > 0
                    ? waitingState.coverOptions
                    : buildLineCoverOptions(waitingState.id, 10),
            }),
        ])
        return
    }

    if (waitingState?.awaitingStep === 'caption') {
        if (isLineCoverSkipCommand(text)) {
            try {
                await ackAndStartLineWaitingVideoFinalization({
                    env, bucket, executionCtx, namespaceId, channelAccessToken, replyToken, lineUserId, waitingState,
                })
            } catch (e) {
                console.error('[LINE] Skip cover during caption error:', e instanceof Error ? e.message : String(e))
                await lineReplyOrPush({
                    replyToken,
                    channelAccessToken,
                    lineUserId,
                    messages: [
                        { type: 'text', text: buildLineShortErrorMessage(e) },
                    ],
                }).catch(() => { })
            }
            return
        }

        if (isLineCaptionEditCommand(text)) {
            await lineReply(replyToken, channelAccessToken, [
                { type: 'text', text: 'พิมพ์แคปชั่นมาได้เลย' },
            ])
            return
        }

        if (isLineCaptionSkipCommand(text)) {
            try {
                await ackAndStartLineWaitingVideoFinalization({
                    env, bucket, executionCtx, namespaceId, channelAccessToken, replyToken, lineUserId, waitingState,
                })
            } catch (e) {
                console.error('[LINE] Skip caption error:', e instanceof Error ? `${e.message}\n${e.stack}` : String(e))
                await lineReplyOrPush({
                    replyToken,
                    channelAccessToken,
                    lineUserId,
                    messages: [
                        { type: 'text', text: buildLineShortErrorMessage(e) },
                    ],
                }).catch(() => { })
            }
            return
        }

        if (lowerText === 'วิธีใช้งาน' || lowerText === 'help' || lowerText === 'ส่งวิดีโอ') {
            await lineReply(replyToken, channelAccessToken, [
                buildLineCaptionPromptFlex({
                    title: 'รอแคปชั่น',
                    message: 'ส่งแคปชั่นมาเลย หรือกดข้ามให้ AI คิดให้',
                    videoId: waitingState.id,
                    namespaceId,
                    manualCaption: waitingState.manualCaption,
                }),
            ])
            return
        }

        const captionCandidate = normalizeManualCaption(stripLineAffiliateLinksFromText(text))
        if (!captionCandidate || /^https?:\/\/\S+$/i.test(text)) {
            await lineReply(replyToken, channelAccessToken, [
                buildLineCaptionPromptFlex({
                    title: 'รอแคปชั่น',
                    message: 'ส่งแคปชั่นมาเลย หรือกดข้ามให้ AI คิดให้',
                    videoId: waitingState.id,
                    namespaceId,
                    manualCaption: waitingState.manualCaption,
                }),
            ])
            return
        }

        try {
            await finalizeLineWaitingVideoAndStartProcessing({
                env, bucket, executionCtx, namespaceId, channelAccessToken, replyToken, lineUserId, waitingState,
                manualCaption: captionCandidate,
            })
        } catch (e) {
            console.error('[LINE] Caption → cover error:', e instanceof Error ? e.message : String(e))
            try {
                await finalizeLineWaitingVideoAndStartProcessing({
                    env, bucket, executionCtx, namespaceId, channelAccessToken, replyToken, lineUserId, waitingState,
                    manualCaption: captionCandidate,
                })
            } catch (finalizeErr) {
                console.error('[LINE] Caption finalize fallback error:', finalizeErr instanceof Error ? finalizeErr.message : String(finalizeErr))
                await lineReplyOrPush({
                    replyToken,
                    channelAccessToken,
                    lineUserId,
                    messages: [
                        { type: 'text', text: buildLineShortErrorMessage(finalizeErr) },
                    ],
                }).catch(() => { })
            }
        }
        return
    }

    // Check if it's an XHS link — resolve, download, thumbnail, then store
    const xhsMatch = text.match(/https?:\/\/(xhslink\.com|www\.xiaohongshu\.com)\S+/)
    if (xhsMatch) {
        const xhsUrl = xhsMatch[0]
        const videoId = crypto.randomUUID().slice(0, 8)
        const xhsResolveTimeoutMs = 15_000
        // XHS full downloads can be large (50MB+ over slow upstreams) and the
        // old 45s budget aborted real videos mid-stream — the dominant cause of
        // "sometimes works, sometimes not". Allow up to 120s, still bounded by
        // the AbortController below so a stalled upstream can never hang forever.
        const xhsDownloadTimeoutMs = 120_000
        await putLineCurrentVideoIntake(bucket, lineUserId, {
            videoId,
            createdAt: new Date().toISOString(),
            sourceType: 'xhs_url',
            sourceLabel: xhsUrl,
        })

        // Keep LINE's legacy cover-picker-first UX: do not consume the reply
        // token with an intermediate acknowledgement. The cover picker (or an
        // explicit failure message) must be the first visible response.
        const followupReplyToken = replyToken

        // The XHS resolve + full video download + R2 store + cover-picker
        // prompt can run well past a minute for large videos. Return the
        // webhook now (executionCtx.waitUntil) so LINE never gives up / retries
        // the event while we work; the follow-up cover picker and any failure
        // message are pushed (followupReplyToken === ''). In test / non-worker
        // contexts (no executionCtx) we fall back to awaiting inline.
        const followupPromise = (async () => {
            const isCurrentXhsIntake = () => isLineCurrentVideoIntake(bucket, lineUserId, videoId)
            const withTimeoutSignal = (timeoutMs: number) => {
                const controller = new AbortController()
                const timeoutId = setTimeout(() => controller.abort(`xhs_timeout_${timeoutMs}ms`), timeoutMs)
                return { controller, timeoutId }
            }

            // Resolve XHS URL to direct video URL via merge service
            let resolvedVideoUrl = xhsUrl
            let resolverFailureReason: 'no_video' | 'request_failed' | null = null
            try {
                const { controller, timeoutId } = withTimeoutSignal(xhsResolveTimeoutMs)
                let resolveResp: Response
                try {
                    resolveResp = await fetchMergeService(env, '/xhs/resolve', {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ url: xhsUrl }),
                        signal: controller.signal,
                    })
                } finally {
                    clearTimeout(timeoutId)
                }
                if (resolveResp.ok) {
                    const resolveData = await resolveResp.json() as { video_url?: string }
                    if (resolveData?.video_url) {
                        resolvedVideoUrl = resolveData.video_url
                    } else {
                        resolverFailureReason = 'no_video'
                    }
                } else if (resolveResp.status === 404) {
                    resolverFailureReason = 'no_video'
                } else {
                    resolverFailureReason = 'request_failed'
                }
            } catch (e) {
                console.warn(`[LINE] XHS resolve failed userId=${lineUserId}: ${e instanceof Error ? e.message : String(e)}`)
                resolverFailureReason = 'request_failed'
            }

            // Download video and store in R2
            let r2VideoUrl = xhsUrl
            let originalStored = false
            let downloadFailed = false
            try {
                if (resolvedVideoUrl !== xhsUrl) {
                    if (!(await isCurrentXhsIntake())) return
                    const { controller, timeoutId } = withTimeoutSignal(xhsDownloadTimeoutMs)
                    let videoResp: Response
                    try {
                        videoResp = await fetch(resolvedVideoUrl, {
                            headers: { 'Referer': 'https://www.xiaohongshu.com/' },
                            signal: controller.signal,
                        })
                    } finally {
                        clearTimeout(timeoutId)
                    }
                    if (videoResp.ok && videoResp.body) {
                        const videoBuffer = await videoResp.arrayBuffer()
                        assertDownloadedVideoResponse(videoResp, videoBuffer, resolvedVideoUrl)
                        if (!(await isCurrentXhsIntake())) return
                        r2VideoUrl = await storeOriginalVideoBuffer({
                            bucket,
                            env,
                            namespaceId,
                            videoId,
                            videoBuffer,
                            contentType: 'video/mp4',
                        })
                        await backfillOriginalThumbnail(env, namespaceId, videoId).catch(() => { })
                        originalStored = true
                    } else {
                        downloadFailed = true
                    }
                }
            } catch (e) {
                console.warn(`[LINE] XHS download failed userId=${lineUserId}: ${e instanceof Error ? e.message : String(e)}`)
                downloadFailed = true
            }

            if (!originalStored) {
                // Superseded/cancelled background work exits silently. The
                // newer/current request owns all user-visible follow-ups.
                if (!(await isCurrentXhsIntake())) return

                const failureText = resolverFailureReason === 'no_video'
                    ? 'ลิงก์ XHS นี้อาจไม่ใช่โพสต์วิดีโอ ลองส่งลิงก์ที่เป็นวิดีโอใหม่อีกครั้ง'
                    : downloadFailed || resolverFailureReason === 'request_failed'
                        ? 'โหลดวิดีโอจาก XHS ไม่สำเร็จ ลองส่งลิงก์ใหม่อีกครั้ง'
                        : 'รับลิงก์ XHS แล้ว แต่ดึงวิดีโอไม่สำเร็จ ลองส่งลิงก์ใหม่อีกครั้ง'

                await lineReplyOrPush({
                    replyToken: followupReplyToken,
                    channelAccessToken,
                    lineUserId,
                    messages: [
                        { type: 'text', text: failureText },
                    ],
                })
                await clearLineCurrentVideoIntakeIfMatches(bucket, lineUserId, videoId)
                return
            }

            const createdAt = new Date().toISOString()

            try {
                if (!(await isCurrentXhsIntake())) return
                const waitingState = await putLineWaitingVideoState(bucket, lineUserId, {
                    id: videoId,
                    videoUrl: r2VideoUrl,
                    createdAt,
                    sourceType: 'xhs_url',
                    sourceLabel: xhsUrl,
                    shopeeLink: shopeeLink || '',
                    lazadaLink: lazadaLink || '',
                    awaitingStep: 'cover',
                    coverCompleted: false,
                })

                if (!(await isCurrentXhsIntake())) return
                await promptLineCoverOptions({
                    env,
                    bucket,
                    namespaceId,
                    channelAccessToken,
                    replyToken: followupReplyToken,
                    lineUserId,
                    waitingState,
                    forceRefresh: true,
                })
            } catch (e) {
                if (!(await isCurrentXhsIntake())) return
                console.warn(`[LINE] XHS cover prompt failed userId=${lineUserId}: ${e instanceof Error ? e.message : String(e)}`)
                await lineReplyOrPush({
                    replyToken: followupReplyToken,
                    channelAccessToken,
                    lineUserId,
                    messages: [
                        { type: 'text', text: 'รับลิงก์ XHS แล้ว แต่โหลดตัวเลือกปกไม่สำเร็จ ลองใหม่' },
                    ],
                })
            }
        })().catch(async (error) => {
            // Last-resort guard: only the active request may surface an error;
            // stale/superseded background work exits silently.
            if (!(await isLineCurrentVideoIntake(bucket, lineUserId, videoId))) return
            console.warn(`[LINE] XHS follow-up crashed userId=${lineUserId}: ${error instanceof Error ? error.message : String(error)}`)
            await lineReplyOrPush({
                replyToken: followupReplyToken,
                channelAccessToken,
                lineUserId,
                messages: [
                    { type: 'text', text: 'โหลดวิดีโอจาก XHS ไม่สำเร็จ ลองส่งลิงก์ใหม่อีกครั้ง' },
                ],
            }).catch(() => { })
            await clearLineCurrentVideoIntakeIfMatches(bucket, lineUserId, videoId)
        })

        if (executionCtx) {
            executionCtx.waitUntil(followupPromise)
            return
        }
        await followupPromise
        return
    }

    if (!shopeeLink && !lazadaLink) {
        // Handle quick reply commands
        if (lowerText === 'วิธีใช้งาน' || lowerText === 'help') {
            await lineReply(replyToken, channelAccessToken, [
                { type: 'text', text: '📖 วิธีใช้งาน Affiliate AiBot\n\n1️⃣ ส่งวิดีโอ หรือ ลิงก์ XHS มาในแชท\n2️⃣ เลือกปกคลิปจาก 10 รูป\n3️⃣ ถ้าต้องการเพิ่มข้อความบนปก พิมพ์มาได้เลย หรือกด AI คิดให้\n4️⃣ ส่งลิงก์ Shopee ของสินค้า\n5️⃣ ส่งลิงก์ Lazada ของสินค้า\n6️⃣ ส่งแคปชั่น หรือกดข้ามให้ AI คิดให้\n\n📱 กดปุ่ม "เปิดแอพ" เพื่อดู Dashboard, Gallery, ตั้งค่า และอื่นๆ' },
            ])
            return
        }
        if (lowerText === 'ส่งวิดีโอ') {
            await lineReply(replyToken, channelAccessToken, [
                { type: 'text', text: '🎬 วิธีส่งวิดีโอ\n\n• กดปุ่ม ➕ แล้วเลือกวิดีโอจากแกลเลอรี่\n• หรือ copy ลิงก์ XHS แล้ววางส่งมาเลย\n\nรอรับวิดีโอจากคุณอยู่นะ!' },
            ])
            return
        }

        if (waitingState) {
            const hasShopee = !!String(waitingState.shopeeLink || '').trim()
            const hasLazada = !!String(waitingState.lazadaLink || '').trim()
            await lineReply(replyToken, channelAccessToken, [
                buildLineAffiliatePromptFlex({
                    title: hasShopee ? 'รอ Lazada' : 'รอ Shopee',
                    brand: hasShopee ? 'lazada' : 'shopee',
                    message: hasShopee
                        ? 'ส่งลิงก์ Lazada มาเลย'
                        : 'ส่งลิงก์ Shopee มาเลย',
                }),
            ])
            return
        }

        await lineReply(replyToken, channelAccessToken, [
            { type: 'text', text: 'ส่งวิดีโอหรือลิงก์ XHS มาเลย\nหรือถ้ามีวิดีโอรออยู่แล้ว ส่งลิงก์ Shopee/Lazada ได้เลย' },
        ])
        return
    }

    // Look for a waiting video state
    if (!waitingState) {
        await lineReply(replyToken, channelAccessToken, [
            { type: 'text', text: 'ยังไม่มีวิดีโอที่รอลิงก์\nส่งวิดีโอมาก่อนแล้วค่อยส่งลิงก์ตามมา' },
        ])
        return
    }

    if (!waitingState?.id || !waitingState?.videoUrl) {
        await clearLineWaitingVideoState(bucket, lineUserId)
        await lineReply(replyToken, channelAccessToken, [
            { type: 'text', text: 'เกิดข้อผิดพลาด กรุณาส่งวิดีโอมาใหม่' },
        ])
        return
    }

    // Merge links
    const updatedShopee = shopeeLink || waitingState.shopeeLink || ''
    const updatedLazada = lazadaLink || waitingState.lazadaLink || ''

    if (!updatedShopee) {
        // Still need Shopee link
        await putLineWaitingVideoState(bucket, lineUserId, {
            ...waitingState,
            lazadaLink: updatedLazada,
            awaitingStep: 'links',
        })
        await lineReply(replyToken, channelAccessToken, [
            buildLineAffiliatePromptFlex({
                title: 'รับลิงก์ Lazada แล้ว',
                brand: 'shopee',
                message: 'ส่งลิงก์ Shopee มาเลย',
            }),
        ])
        return
    }

    if (!updatedLazada) {
        // Still need Lazada link
        await putLineWaitingVideoState(bucket, lineUserId, {
            ...waitingState,
            shopeeLink: updatedShopee,
            awaitingStep: 'links',
        })
        await lineReply(replyToken, channelAccessToken, [
            buildLineAffiliatePromptFlex({
                title: 'รับลิงก์ Shopee แล้ว',
                brand: 'lazada',
                message: 'ส่งลิงก์ Lazada มาเลย',
            }),
        ])
        return
    }

    // Both links are present — ask for caption before processing
    try {
        await promptLineCaptionCollection({
            env,
            bucket,
            namespaceId,
            channelAccessToken,
            replyToken,
            lineUserId,
            waitingState: {
                ...waitingState,
                sourceType: waitingState.sourceType || 'line_video',
                sourceLabel: waitingState.sourceLabel || 'LINE video',
                shopeeLink: updatedShopee,
                lazadaLink: updatedLazada,
                awaitingStep: 'caption',
            },
        })
    } catch (e) {
        console.error('[LINE] Link processing error:', e instanceof Error ? e.message : String(e))
        await lineReply(replyToken, channelAccessToken, [
            { type: 'text', text: 'เกิดข้อผิดพลาด กรุณาลองใหม่อีกครั้ง' },
        ]).catch(() => {})
    }
}

async function handleLinePostbackEvent(params: {
    env: Env
    bucket: R2Bucket
    namespaceId: string
    channelAccessToken: string
    replyToken: string
    lineUserId: string
    data: string
}) {
    const selection = parseLineCoverSelectionPostbackData(params.data)
    const textPositionSelection = parseLineCoverTextPositionPostbackData(params.data)
    if (!selection && !textPositionSelection) return

    const waitingState = await getLineWaitingVideoState(params.bucket, params.lineUserId)
    if (!waitingState) {
        await lineReply(params.replyToken, params.channelAccessToken, [
            { type: 'text', text: 'ไม่มีงานที่รอเลือกปกแล้ว ลองส่งคลิปใหม่ได้เลย' },
        ]).catch(() => { })
        return
    }

    if (selection) {
        if (waitingState.awaitingStep !== 'cover') {
            await lineReply(params.replyToken, params.channelAccessToken, [
                { type: 'text', text: 'ไม่มีงานที่รอเลือกปกแล้ว ลองส่งคลิปใหม่ได้เลย' },
            ]).catch(() => { })
            return
        }

        if (String(waitingState.id || '').trim() !== selection.videoId) {
            await promptLineCoverPicker({
                env: params.env,
                bucket: params.bucket,
                namespaceId: params.namespaceId,
                channelAccessToken: params.channelAccessToken,
                replyToken: params.replyToken,
                lineUserId: params.lineUserId,
                waitingState,
                manualCaption: waitingState.manualCaption,
            }).catch(() => { })
            return
        }

        const selectedOption = normalizeLineCoverOptions(waitingState.coverOptions)
            .find((option) => String(option.optionId || '').trim() === selection.optionId)
        if (!selectedOption) {
            await promptLineCoverPicker({
                env: params.env,
                bucket: params.bucket,
                namespaceId: params.namespaceId,
                channelAccessToken: params.channelAccessToken,
                replyToken: params.replyToken,
                lineUserId: params.lineUserId,
                waitingState,
                manualCaption: waitingState.manualCaption,
            }).catch(() => { })
            return
        }

        try {
        await putLineWaitingVideoState(params.bucket, params.lineUserId, {
            ...waitingState,
            awaitingStep: 'cover_text',
            selectedCoverOption: selectedOption,
            coverText: '',
            coverTextYPercent: undefined,
            selectedCoverPreviewUrl: '',
            coverTextPositionOptions: [],
        })
            await lineReply(params.replyToken, params.channelAccessToken, [
                buildLineCoverTextPromptMessage(),
            ])
        } catch (e) {
            console.error('[LINE] Cover option selection prompt error:', e instanceof Error ? e.message : String(e))
            await lineReply(params.replyToken, params.channelAccessToken, [
                { type: 'text', text: 'เกิดข้อผิดพลาดตอนเลือกปก กรุณาลองอีกครั้ง' },
            ]).catch(() => { })
        }
        return
    }

    if (!textPositionSelection || waitingState.awaitingStep !== 'cover_text_position' || !waitingState.selectedCoverOption) {
        await lineReply(params.replyToken, params.channelAccessToken, [
            { type: 'text', text: 'ไม่มีงานที่รอเลือกความสูงข้อความแล้ว ลองส่งคลิปใหม่ได้เลย' },
        ]).catch(() => { })
        return
    }

    if (String(waitingState.id || '').trim() !== textPositionSelection.videoId) {
        await promptLineCoverTextPositionOptions({
            env: params.env,
            bucket: params.bucket,
            namespaceId: params.namespaceId,
            channelAccessToken: params.channelAccessToken,
            replyToken: params.replyToken,
            lineUserId: params.lineUserId,
            waitingState,
            coverText: waitingState.coverText || '',
        }).catch(() => { })
        return
    }

    const selectedTextPosition = normalizeLineCoverTextPositionOptions(waitingState.coverTextPositionOptions)
        .find((option) => String(option.optionId || '').trim() === textPositionSelection.optionId)
    if (!selectedTextPosition) {
        await lineReply(params.replyToken, params.channelAccessToken, [
            { type: 'text', text: 'ไม่พบตัวเลือกตำแหน่งข้อความ ลองพิมพ์ข้อความใหม่อีกครั้ง' },
        ]).catch(() => { })
        return
    }

    try {
        await materializeSelectedLineCoverOptionAssets({
            env: params.env,
            bucket: params.bucket,
            namespaceId: params.namespaceId,
            videoId: waitingState.id,
            option: waitingState.selectedCoverOption,
            coverText: waitingState.coverText,
            coverTextYPercent: selectedTextPosition.yPct,
            coverTemplateId: waitingState.coverTemplateId,
            coverTextStyle: waitingState.coverTextStyle,
        })
        await continueLineFlowAfterCover({
            env: params.env,
            bucket: params.bucket,
            namespaceId: params.namespaceId,
            channelAccessToken: params.channelAccessToken,
            replyToken: params.replyToken,
            lineUserId: params.lineUserId,
            waitingState: {
                ...waitingState,
                coverTextYPercent: selectedTextPosition.yPct,
                selectedCoverPreviewUrl: String(selectedTextPosition.previewUrl || '').trim(),
            },
            manualCaption: waitingState.manualCaption,
        })
    } catch (e) {
        console.error('[LINE] Cover text position selection error:', e instanceof Error ? e.message : String(e))
        await lineReply(params.replyToken, params.channelAccessToken, [
            { type: 'text', text: 'เกิดข้อผิดพลาดตอนบันทึกปกพร้อมข้อความ กรุณาลองอีกครั้ง' },
        ]).catch(() => { })
    }
}

// ==================== TELEGRAM WEBHOOK ====================

app.post('/api/telegram/:token?', async (c) => {
    const data = await c.req.json() as any
    const msg = data.message
    const cb = data.callback_query
    const chatId = msg?.chat?.id || cb?.message?.chat?.id
    const token = c.req.param('token') || c.req.header('x-auth-token') || c.env.TELEGRAM_BOT_TOKEN
    const botId = c.get('botId') || 'default'
    const workerUrl = new URL(c.req.url).origin
    const adminStateKey = `_admin_auth/${chatId}.json`
    if (!chatId) return c.text('ok')

    console.log('[WEBHOOK] chatId:', chatId, 'token:', token?.substring(0, 15), 'botId:', botId, 'isParam:', c.req.param('token')?.substring(0, 15))

    const clearAdminAuthPending = async () => {
        await c.env.BUCKET.delete(adminStateKey).catch(() => { })
    }

    const askAdminPassword = async () => {
        await clearAdminAuthPending()
        await sendAdminPanelLink()
    }

    const sendAdminPanelLink = async () => {
        await c.env.BUCKET.put(`_admin_grant/${chatId}.json`, JSON.stringify({ expires_at: Date.now() + ADMIN_AUTH_TTL_MS }), {
            httpMetadata: { contentType: 'application/json' },
        })

        const launchToken = 'launch_' + crypto.randomUUID().replace(/-/g, '')
        await c.env.BUCKET.put(`_admin_launch/${launchToken}.json`, JSON.stringify({
            chat_id: String(chatId),
            expires_at: Date.now() + (15 * 60 * 1000),
        }), {
            httpMetadata: { contentType: 'application/json' },
        })

        const adminUrl = `${workerUrl}/admin?launch=${encodeURIComponent(launchToken)}&v=${Date.now()}`
        await sendTelegram(token, 'sendMessage', {
            chat_id: chatId,
            text: '✅ เปิด Admin Panel ได้เลย',
            reply_markup: { inline_keyboard: [[{ text: '⚙️ เปิด Admin Panel', web_app: { url: adminUrl } }]] },
        })
    }

    const tryHandleAdminPasswordInput = async (_inputText: string) => {
        return false
    }

    // Check if this token belongs to a registered Channel Bot
    const isChannelBot = await c.env.DB.prepare('SELECT 1 FROM channels WHERE bot_token = ?').bind(token).first()
    console.log('[WEBHOOK] isChannelBot:', !!isChannelBot)

    // ==================== SETTING BOT (ไม่ใช่ Channel Bot) ====================
    if (!isChannelBot) {
        // Verify allowed user
        const allowedUser = await c.env.DB.prepare('SELECT 1 FROM allowed_users WHERE telegram_id = ?').bind(chatId).first()
        console.log('[SETTING] allowedUser:', !!allowedUser, 'text:', msg?.text)
        if (!allowedUser) return c.text('ok')

        const stateKey = `_setting_state/${chatId}.json`

        // Setting Bot: Callback Queries
        if (cb) {
            const action = cb.data as string
            if (action.startsWith('del_channel:')) {
                const delBotId = action.replace('del_channel:', '')
                await c.env.DB.prepare('DELETE FROM channels WHERE bot_id = ? AND owner_telegram_id = ?').bind(delBotId, chatId).run()
                await sendTelegram(token, 'editMessageText', { chat_id: chatId, message_id: cb.message.message_id, text: `🗑 ลบช่องเรียบร้อยแล้ว` })
            } else if (action.startsWith('view_bot:')) {
                const viewBotId = action.replace('view_bot:', '')
                const ch = await c.env.DB.prepare('SELECT bot_id, bot_username, name, bot_token FROM channels WHERE bot_id = ? AND owner_telegram_id = ?').bind(viewBotId, chatId).first() as any
                if (ch) {
                    const pageCount = await c.env.DB.prepare('SELECT COUNT(*) as cnt FROM pages WHERE bot_id = ?').bind(ch.bot_id).first() as any
                    let text = `🤖 *${ch.name || 'ไม่มีชื่อ'}*\n`
                    text += `├ @${ch.bot_username || '—'}\n`
                    text += `├ เพจ: ${pageCount?.cnt || 0} เพจ\n`
                    text += `└ ID: \`${ch.bot_id}\`\n\n`
                    text += `เลือกดำเนินการกับบอทตัวนี้:`

                    const webAppUrl = getAppWebBaseUrl(c.env)

                    const buttons = [
                        [{ text: `📱 เปิดหน้าจัดการระบบ (Mini App)`, web_app: { url: buildScopedWebAppUrl(webAppUrl, String(ch.bot_id || '')) } }],
                        [{ text: `🗑 ลบ ${ch.name || ch.bot_username}`, callback_data: `del_channel:${ch.bot_id}` }],
                        [{ text: `🔙 กลับรายการช่องทั้งหมด`, callback_data: `back_to_list` }]
                    ]
                    await sendTelegram(token, 'editMessageText', { chat_id: chatId, message_id: cb.message.message_id, text, parse_mode: 'Markdown', reply_markup: { inline_keyboard: buttons } })
                }
            } else if (action === 'back_to_list') {
                const { results: channels } = await c.env.DB.prepare(
                    'SELECT bot_id, bot_username, name FROM channels WHERE owner_telegram_id = ? ORDER BY created_at DESC'
                ).bind(chatId).all() as any

                if (channels.length === 0) {
                    await sendTelegram(token, 'editMessageText', { chat_id: chatId, message_id: cb.message.message_id, text: '📭 ยังไม่มีช่องที่ลงทะเบียนไว้\n\nใช้ /newchannel เพื่อเพิ่มช่องใหม่' })
                } else {
                    const buttons: any[][] = []
                    let row: any[] = []
                    for (const ch of channels) {
                        row.push({ text: `@${ch.bot_username}`, callback_data: `view_bot:${ch.bot_id}` })
                        if (row.length === 2) {
                            buttons.push(row)
                            row = []
                        }
                    }
                    if (row.length > 0) buttons.push(row)
                    await sendTelegram(token, 'editMessageText', {
                        chat_id: chatId,
                        message_id: cb.message.message_id,
                        text: 'Choose a bot from the list below:',
                        reply_markup: { inline_keyboard: buttons }
                    })
                }
            }
            await sendTelegram(token, 'answerCallbackQuery', { callback_query_id: cb.id }).catch(() => null)
            return c.text('ok')
        }

        if (!msg) return c.text('ok')
        const text = msg.text || ''

        if (text === '/canceladmin') {
            await clearAdminAuthPending()
            await sendTelegram(token, 'sendMessage', {
                chat_id: chatId,
                text: 'ยกเลิกการเปิด /admin แล้ว',
            })
            return c.text('ok')
        }

        if (await tryHandleAdminPasswordInput(text)) return c.text('ok')

        // /admin
        if (text === '/admin') {
            await askAdminPassword()
            return c.text('ok')
        }

        // /start
        if (text === '/start' || text === '/menu') {
            await c.env.BUCKET.delete(stateKey).catch(() => { })
            console.log('[SETTING] /start from', chatId, 'token:', token?.substring(0, 10) + '...')
            const result = await sendTelegram(token, 'sendMessage', {
                chat_id: chatId,
                text: `⚙️ *Video Affiliate — ตั้งค่าช่อง*

📋 *คำสั่ง*
🔹 /newchannel — เพิ่มช่องใหม่ (ส่ง Bot Token)
🔹 /mychannel — ดูช่องทั้งหมดของคุณ

1 ช่อง = 1 บอท Telegram
แต่ละช่องมีแดชบอร์ดและเพจแยกกัน`,
                parse_mode: 'Markdown'
            })
            console.log('[SETTING] sendTelegram result:', JSON.stringify(result))
            return c.text('ok')
        }

        // /newchannel
        if (text === '/newchannel') {
            await c.env.BUCKET.put(stateKey, JSON.stringify({ state: 'WAITING_BOT_TOKEN' }), { httpMetadata: { contentType: 'application/json' } })
            await sendTelegram(token, 'sendMessage', {
                chat_id: chatId,
                text: '🤖 *เพิ่มช่องใหม่*\n\nกรุณาส่ง *Bot Token* ที่ได้จาก @BotFather มาเลยครับ\n\nตัวอย่าง:\n`8328894625:AAEgMQwFeBkTLTYP-s5feVUsc7B64jTInAs`',
                parse_mode: 'Markdown'
            })
            return c.text('ok')
        }

        // /mychannel
        if (text === '/mychannel') {
            await c.env.BUCKET.delete(stateKey).catch(() => { })
            const { results: channels } = await c.env.DB.prepare(
                'SELECT bot_id, bot_username, name FROM channels WHERE owner_telegram_id = ? ORDER BY created_at DESC'
            ).bind(chatId).all() as any

            if (channels.length === 0) {
                await sendTelegram(token, 'sendMessage', { chat_id: chatId, text: '📭 ยังไม่มีช่องที่ลงทะเบียนไว้\n\nใช้ /newchannel เพื่อเพิ่มช่องใหม่' })
                return c.text('ok')
            }

            const buttons: any[][] = []
            let row: any[] = []
            for (const ch of channels) {
                row.push({ text: `@${ch.bot_username}`, callback_data: `view_bot:${ch.bot_id}` })
                if (row.length === 2) {
                    buttons.push(row)
                    row = []
                }
            }
            if (row.length > 0) buttons.push(row)

            await sendTelegram(token, 'sendMessage', {
                chat_id: chatId,
                text: 'Choose a bot from the list below:',
                reply_markup: { inline_keyboard: buttons }
            })
            return c.text('ok')
        }

        // Handle state: waiting for bot token
        const stateObj = await c.env.BUCKET.get(stateKey)
        if (stateObj) {
            const state = await stateObj.json() as any

            if (state.state === 'WAITING_BOT_TOKEN' && text && !text.startsWith('/')) {
                await c.env.BUCKET.delete(stateKey)
                const botToken = text.trim()

                // Validate token via Telegram getMe
                const getMeResp = await fetch(`https://api.telegram.org/bot${botToken}/getMe`)
                if (!getMeResp.ok) {
                    await sendTelegram(token, 'sendMessage', { chat_id: chatId, text: '❌ Bot Token ไม่ถูกต้อง กรุณาตรวจสอบแล้วลองใหม่\n\nใช้ /newchannel เพื่อลองอีกครั้ง' })
                    return c.text('ok')
                }
                const getMeData = await getMeResp.json() as any
                const botInfo = getMeData.result
                const newBotId = getBotId(botToken)

                // Check if already registered
                const existing = await c.env.DB.prepare('SELECT 1 FROM channels WHERE bot_id = ?').bind(newBotId).first()
                if (existing) {
                    await sendTelegram(token, 'sendMessage', { chat_id: chatId, text: `⚠️ ช่อง @${botInfo.username} ลงทะเบียนไว้แล้ว` })
                    return c.text('ok')
                }

                // Register channel
                await c.env.DB.prepare(
                    'INSERT INTO channels (bot_id, bot_token, bot_username, owner_telegram_id, name) VALUES (?, ?, ?, ?, ?)'
                ).bind(newBotId, botToken, botInfo.username || '', chatId, botInfo.first_name || '').run()

                // Add owner to allowed_users if not already
                await c.env.DB.prepare(
                    'INSERT INTO allowed_users (telegram_id, name) VALUES (?, ?) ON CONFLICT DO NOTHING'
                ).bind(chatId, botInfo.first_name || 'owner').run()

                // Set webhook for the new channel bot
                const webhookUrl = `${workerUrl}/api/telegram/${botToken}`
                await fetch(`https://api.telegram.org/bot${botToken}/setWebhook`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ url: webhookUrl })
                })

                await sendTelegram(token, 'sendMessage', {
                    chat_id: chatId,
                    text: `✅ *ลงทะเบียนช่องสำเร็จ!*\n\n🤖 ชื่อ: *${botInfo.first_name}*\n👤 @${botInfo.username}\n🔗 Webhook: ตั้งค่าแล้ว\n\nตอนนี้ไปที่ @${botInfo.username} แล้วส่งวิดีโอได้เลย!\nจัดการเพจ Facebook ผ่าน WebApp ของช่องนั้น`,
                    parse_mode: 'Markdown'
                })
                return c.text('ok')
            }
        }

        // Unknown message for Setting Bot
        await sendTelegram(token, 'sendMessage', {
            chat_id: chatId,
            text: '❓ ไม่เข้าใจคำสั่ง\n\nใช้ /start เพื่อดูเมนู'
        })
        return c.text('ok')
    }

    // ==================== CHANNEL BOT (ช่องที่ลงทะเบียนแล้ว) ====================
    const currentBotId = String(getBotId(token) || '').trim()
    const hasScopedTelegramSession = currentBotId
        ? await hasTelegramWorkspaceAccess(c.env.DB, String(chatId), currentBotId).catch(() => false)
        : false
    const ownerAccess = currentBotId && !hasScopedTelegramSession
        ? await claimOrValidateChannelOwner(
            c.env.DB,
            currentBotId,
            String(chatId),
            String(msg?.from?.first_name || cb?.from?.first_name || 'owner'),
        ).catch(() => null)
        : null
    if (currentBotId && !hasScopedTelegramSession && ownerAccess && !ownerAccess.allowed) {
        await sendTelegram(token, 'sendMessage', {
            chat_id: chatId,
            text: '🚫 กรุณาเปิด Workspace แล้ว login ด้วยอีเมลก่อนใช้งานบอท',
        }).catch(() => null)
        return c.text('ok')
    }

    // Handle callbacks (del_email:, close_setting, intake_cancel)
    if (cb) {
        const action = cb.data as string
        if (action === 'intake_cancel') {
            // Cancel an in-flight XHS intake: write the per-chat cancel marker so
            // a still-running materialize won't resurrect the intake, and delete
            // any already-saved waiting state. This callback runs before the
            // request-scoped bucket is set, so resolve the namespace bucket here.
            const cbUser = await resolveTelegramWorkspaceSession(c.env.DB, String(chatId), currentBotId).catch(() => null)
            const cbNamespaceId = String(cbUser?.namespace_id || '').trim()
            if (cbNamespaceId) {
                const cbBucket = new BotBucket(c.env.BUCKET, cbNamespaceId) as unknown as R2Bucket
                await cbBucket.put(`_waiting_video_cancelled/${chatId}.json`, JSON.stringify({ cancelledAt: new Date().toISOString() }), {
                    httpMetadata: { contentType: 'application/json' },
                }).catch(() => { })
                await cbBucket.delete(`_waiting_video/${chatId}.json`).catch(() => { })
            }
            await sendTelegram(token, 'editMessageText', {
                chat_id: chatId,
                message_id: cb.message.message_id,
                text: '🚫 ยกเลิกการดึงวิดีโอ XHS แล้ว',
            }).catch(() => null)
            await sendTelegram(token, 'answerCallbackQuery', { callback_query_id: cb.id }).catch(() => null)
            return c.text('ok')
        }
        if (action.startsWith('del_email:')) {
            const email = action.replace('del_email:', '')
            await c.env.DB.prepare('DELETE FROM email_namespaces WHERE email = ?').bind(email).run().catch(() => { })
            await c.env.DB.prepare('DELETE FROM allowed_emails WHERE email = ?').bind(email).run().catch(() => { })
            await c.env.DB.prepare('DELETE FROM users WHERE email = ?').bind(email).run()
            await sendTelegram(token, 'editMessageText', { chat_id: chatId, message_id: cb.message.message_id, text: `🗑 ลบ ${email} แล้ว` })
        } else if (action === 'close_setting') {
            await sendTelegram(token, 'editMessageText', { chat_id: chatId, message_id: cb.message.message_id, text: '✅ ปิดการตั้งค่า' })
        }
        await sendTelegram(token, 'answerCallbackQuery', { callback_query_id: cb.id }).catch(() => null)
        return c.text('ok')
    }

    if (!msg) return c.text('ok')
    const text = msg.text || ''

    if (text === '/canceladmin') {
        await clearAdminAuthPending()
        await sendTelegram(token, 'sendMessage', {
            chat_id: chatId,
            text: 'ยกเลิกการเปิด /admin แล้ว',
        })
        return c.text('ok')
    }

    if (await tryHandleAdminPasswordInput(text)) return c.text('ok')

    // Auth state & user lookup (session_token NULL = logged out)
    const userRecord = await resolveTelegramWorkspaceSession(c.env.DB, String(chatId), currentBotId)

    // /logout command — ล้าง session จาก bot side
    if (text === '/logout') {
        const clearedScoped = currentBotId
            ? await clearTelegramBotSessionByScope(c.env.DB, String(chatId), currentBotId)
            : false
        if (!clearedScoped) {
            const legacyUser = await c.env.DB.prepare(
                'SELECT namespace_id FROM users WHERE telegram_id = ?'
            ).bind(chatId).first() as { namespace_id?: string } | null
            const legacyNamespaceId = String(legacyUser?.namespace_id || '').trim()
            const canClearLegacy = !currentBotId || !legacyNamespaceId || legacyNamespaceId === currentBotId
            if (canClearLegacy) {
                await c.env.DB.prepare("UPDATE users SET session_token = '' WHERE telegram_id = ?").bind(chatId).run()
            }
        }
        const appUrl = getAppWebBaseUrl(c.env)
        await sendTelegram(token, 'sendMessage', {
            chat_id: chatId,
            text: '✅ ออกจากระบบแล้ว\n\nกด "เปิด Workspace" เพื่อเข้าใช้งานอีกครั้ง',
            reply_markup: { inline_keyboard: [[{ text: '🚀 เปิด Workspace', web_app: { url: buildScopedWebAppUrl(appUrl, currentBotId) } }]] }
        })
        return c.text('ok')
    }

    // /admin command — เปิดหน้า Admin Panel
    if (text === '/admin') {
        await askAdminPassword()
        return c.text('ok')
    }

    // /start and /menu should always surface the Mini App entrypoint.
    if (text === '/start' || text === '/menu') {
        const appUrl = getAppWebBaseUrl(c.env)
        const hasSession = Boolean(userRecord?.session_token)
        await sendTelegram(token, 'sendMessage', {
            chat_id: chatId,
            text: hasSession
                ? '🚀 กด "เปิด Workspace" เพื่อเข้าใช้งาน'
                : '👋 กรุณาเปิด Workspace เพื่อเริ่มใช้งาน',
            reply_markup: {
                inline_keyboard: [[
                    { text: '🚀 เปิด Workspace', web_app: { url: buildScopedWebAppUrl(appUrl, currentBotId) } }
                ]]
            }
        })
        return c.text('ok')
    }

    // Block unauthenticated/logged-out users — send Mini App button to open Workspace
    if (!userRecord || !userRecord.session_token) {
        const appUrl = getAppWebBaseUrl(c.env)
        await sendTelegram(token, 'sendMessage', {
            chat_id: chatId,
            text: '👋 กรุณาเปิด Workspace เพื่อเริ่มใช้งาน',
            reply_markup: {
                inline_keyboard: [[
                    { text: '🚀 เปิด Workspace', web_app: { url: buildScopedWebAppUrl(appUrl, currentBotId) } }
                ]]
            }
        })
        return c.text('ok')
    }

    // Block unknown slash commands for authenticated users
    if (text.startsWith('/')) {
        return c.text('ok')
    }

    // Set user namespace as botId
    c.set('botId', userRecord.namespace_id)
    c.set('bucket', new BotBucket(c.env.BUCKET, userRecord.namespace_id) as unknown as R2Bucket)

    try {
        // Variables defined upstream

        // Dedup: ป้องกัน Telegram retry ขณะ pipeline ยังรันอยู่
        const dedupKey = `_dedup/${data.update_id || msg.message_id}`
        const existing = await c.get('bucket').head(dedupKey)
        if (existing) return c.text('ok')

        const pendingCategoryKey = `_pending_category/${chatId}.json`
        const waitingVideoKey = `_waiting_video/${chatId}.json`
        type WaitingVideoState = {
            id: string
            videoUrl: string
            sourceType?: InboxVideoSourceType
            sourceLabel?: string
            shopeeLink?: string
            lazadaLink?: string
        }
        const extractShopeeLink = (input: string): string => {
            const raw = String(input || '')
            const match = raw.match(/https?:\/\/\S*shopee\S+/i) || raw.match(/https?:\/\/shope\.ee\S+/i)
            return String(match?.[0] || '').trim()
        }
        const extractLazadaLink = (input: string): string => {
            const raw = String(input || '')
            const match = raw.match(/https?:\/\/\S*(?:lazada|lzd\.co)\S+/i)
            return String(match?.[0] || '').trim()
        }
        const normalizeWaitingVideoState = (input: Partial<WaitingVideoState> | null | undefined): WaitingVideoState | null => {
            const id = String(input?.id || '').trim()
            const videoUrl = String(input?.videoUrl || '').trim()
            if (!id || !videoUrl) return null
            const shopeeLink = extractShopeeLink(String(input?.shopeeLink || ''))
            const lazadaLink = extractLazadaLink(String(input?.lazadaLink || ''))
            const sourceType: InboxVideoSourceType = String(input?.sourceType || '').trim().toLowerCase() === 'xhs_url'
                ? 'xhs_url'
                : 'telegram_video'
            const sourceLabel = sourceType === 'telegram_video'
                ? 'Telegram video'
                : String(input?.sourceLabel || '').trim().slice(0, 500)
            return {
                id,
                videoUrl,
                sourceType,
                ...(sourceLabel ? { sourceLabel } : {}),
                ...(shopeeLink ? { shopeeLink } : {}),
                ...(lazadaLink ? { lazadaLink } : {}),
            }
        }
        const getIntakeDuplicateKey = (input: Partial<WaitingVideoState> | Partial<InboxVideoRecord> | null | undefined): string => {
            const sourceType: InboxVideoSourceType = String(input?.sourceType || '').trim().toLowerCase() === 'xhs_url'
                ? 'xhs_url'
                : 'telegram_video'
            return getNamespaceVideoDuplicateKey({
                namespace_id: String(c.get('botId') || '').trim(),
                sourceType,
                sourceLabel: String(input?.sourceLabel || '').trim(),
                videoUrl: String(input?.videoUrl || '').trim(),
            })
        }
        const getWaitingVideoState = async (): Promise<WaitingVideoState | null> => {
            const waitingObj = await c.get('bucket').get(waitingVideoKey)
            if (!waitingObj) return null
            const waitingState = normalizeWaitingVideoState(await waitingObj.json() as Partial<WaitingVideoState>)
            if (!waitingState) {
                await c.get('bucket').delete(waitingVideoKey).catch(() => { })
                return null
            }
            return waitingState
        }
        const saveWaitingVideoState = async (state: WaitingVideoState) => {
            await c.get('bucket').put(waitingVideoKey, JSON.stringify(state), {
                httpMetadata: { contentType: 'application/json' },
            })
        }
        const clearWaitingVideoState = async () => {
            await c.get('bucket').delete(waitingVideoKey).catch(() => { })
        }
        // Cancellation marker for an in-flight XHS intake. The slow part of an
        // intake is materializeOriginalVideoAsset (XHS resolve + download); the
        // user can press the inline "ยกเลิก" button while it runs. The cancel
        // callback writes this marker (and deletes any saved waiting state);
        // handleVideoInput re-checks it after materialize so a late finish does
        // not resurrect the intake by saving waiting state / prompting links.
        const intakeCancelledKey = `_waiting_video_cancelled/${chatId}.json`
        const isIntakeCancelled = async (): Promise<boolean> => {
            const obj = await c.get('bucket').head(intakeCancelledKey).catch(() => null)
            return Boolean(obj)
        }
        const clearIntakeCancelled = async () => {
            await c.get('bucket').delete(intakeCancelledKey).catch(() => { })
        }
        // Any reply that leaves a pending/failed intake (missing-link prompts,
        // the "already waiting" block, invalid-link nags) carries this button so
        // the user can always escape a stuck intake. It triggers the same
        // intake_cancel callback that clears _waiting_video + the cancel marker.
        const intakeCancelKeyboard = { inline_keyboard: [[{ text: '🚫 ยกเลิก/ล้างรายการ', callback_data: 'intake_cancel' }]] }
        const findExistingDuplicateInboxVideo = async (state: WaitingVideoState): Promise<
            | { kind: 'waiting'; item: WaitingVideoState }
            | { kind: 'inbox'; item: InboxVideoRecord }
            | null
        > => {
            const duplicateKey = getIntakeDuplicateKey(state)
            if (!duplicateKey) return null

            const waitingState = await getWaitingVideoState()
            if (waitingState && getIntakeDuplicateKey(waitingState) === duplicateKey) {
                return { kind: 'waiting', item: waitingState }
            }

            const inboxRecords = await listInboxVideoRecords(c.get('bucket'))
            const existing = inboxRecords.find((record) => getIntakeDuplicateKey(record) === duplicateKey)
            return existing ? { kind: 'inbox', item: existing } : null
        }
        const getMissingWaitingLink = (state: WaitingVideoState): 'shopee' | 'lazada' | null => {
            if (!String(state.shopeeLink || '').trim()) return 'shopee'
            if (!String(state.lazadaLink || '').trim()) return 'lazada'
            return null
        }
        const promptWaitingLink = async (state: WaitingVideoState) => {
            const missing = getMissingWaitingLink(state)
            if (missing === 'lazada') {
                await sendTelegram(token, 'sendMessage', {
                    chat_id: chatId,
                    text: 'ส่งลิงก์ Lazada มาเลย',
                    reply_markup: intakeCancelKeyboard,
                })
                return
            }
            await sendTelegram(token, 'sendMessage', {
                chat_id: chatId,
                text: 'ส่งลิงก์ Shopee มาเลย',
                reply_markup: intakeCancelKeyboard,
            })
        }
        const upsertInboxFromWaitingState = async (state: WaitingVideoState) => {
            const existing = await getInboxVideoRecord(c.get('bucket'), state.id)
            return putInboxVideoRecord(c.get('bucket'), {
                ...existing,
                id: state.id,
                videoUrl: state.videoUrl,
                chatId: Number(chatId),
                createdAt: String(existing?.createdAt || '').trim() || new Date().toISOString(),
                updatedAt: new Date().toISOString(),
                sourceType: state.sourceType,
                sourceLabel: state.sourceLabel,
                shopeeLink: state.shopeeLink,
                lazadaLink: state.lazadaLink,
                linkRecordedAt: existing?.linkRecordedAt,
            })
        }
        const sendReadyInboxMessage = async (result: InboxProcessingStartResult) => {
            const targetId = String(result.item.id || '').trim()
            const processingUrl = buildScopedTabWebAppUrl(
                getAppWebBaseUrl(c.env),
                String(c.get('botId') || ''),
                'processing',
            )
            const galleryUrl = buildScopedTabWebAppUrl(
                getAppWebBaseUrl(c.env),
                String(c.get('botId') || ''),
                'gallery',
                { q: targetId },
            )
            if (result.outcome === 'already_processed') {
                await sendTelegram(token, 'sendMessage', {
                    chat_id: chatId,
                    text: '♻️ คลิปนี้เคยประมวลผลแล้ว\nผมอัปเดตลิงก์ให้รายการเดิมเรียบร้อย',
                    reply_markup: {
                        inline_keyboard: [[{ text: '🎞 เปิด Gallery', web_app: { url: galleryUrl } }]],
                    },
                })
                return
            }

            const status = result.outcome === 'started' ? result.job.status : result.status
            const text = result.outcome === 'already_running'
                ? (status === 'queued'
                    ? '♻️ คลิปนี้อยู่ในคิวประมวลผลแล้ว'
                    : '♻️ คลิปนี้กำลังประมวลผลอยู่แล้ว')
                : (status === 'queued'
                    ? '✅ รับลิงก์ครบแล้ว\nผมส่งคลิปเข้า Queue ให้แล้ว ระบบจะประมวลผลอัตโนมัติ'
                    : '✅ รับลิงก์ครบแล้ว\nผมเริ่มประมวลผลให้อัตโนมัติแล้ว')
            await sendTelegram(token, 'sendMessage', {
                chat_id: chatId,
                text,
                reply_markup: {
                    inline_keyboard: [[{ text: '⚙️ ดู Processing', web_app: { url: processingUrl } }]],
                },
            })
        }
        const sendQueuedInboxMessage = async (item: InboxVideoRecord) => {
            const inboxUrl = buildScopedTabWebAppUrl(
                getAppWebBaseUrl(c.env),
                String(c.get('botId') || ''),
                'inbox',
            )
            await sendTelegram(token, 'sendMessage', {
                chat_id: chatId,
                text: '✅ รับลิงก์ครบแล้ว\nผมเพิ่มคลิปไว้บนสุดของคลังต้นฉบับแล้ว ระบบ cron จะทยอยประมวลผลทีละคลิป',
                reply_markup: {
                    inline_keyboard: [[{ text: '📥 เปิดคลังต้นฉบับ', web_app: { url: inboxUrl } }]],
                },
            })
            void item
        }

        const CATEGORIES = await getCategories(c.get('bucket'))

        // กรณีเลือกหมวดหมู่ → บันทึก category
        const pendingCatObj = await c.get('bucket').get(pendingCategoryKey)
        if (pendingCatObj && text.trim() && CATEGORIES.includes(text.trim())) {
            const pending = await pendingCatObj.json() as { videoId: string }

            // ตอบ user ก่อนเลย (ไว)
            const [, metaObj] = await Promise.all([
                c.get('bucket').delete(pendingCategoryKey),
                c.get('bucket').get(`videos/${pending.videoId}.json`),
                sendTelegram(token, 'sendMessage', {
                    chat_id: chatId,
                    text: '📝 บันทึกหมวดหมู่แล้ว',
                    reply_markup: { remove_keyboard: true },
                }),
            ])

            // บันทึก metadata + cache ทีหลัง
            if (metaObj) {
                const meta = await metaObj.json() as Record<string, unknown>
                meta.category = text.trim()
                await c.get('bucket').put(`videos/${pending.videoId}.json`, JSON.stringify(meta, null, 2), {
                    httpMetadata: { contentType: 'application/json' },
                })
                await updateGalleryCache(c.get('bucket'), pending.videoId)
                await syncGalleryIndexEntry(c.env, String(c.get('botId') || ''), pending.videoId).catch((error) => {
                    console.log(`[TG-CATEGORY] sync gallery index failed video=${pending.videoId}: ${error instanceof Error ? error.message : String(error)}`)
                })
            }

            return c.text('ok')
        }

        // Helper สำหรับรวมการเซฟวิดีโอที่รอลิงก์ affiliate links
        const handleVideoInput = async (
            videoUrl: string,
            sourceType: InboxVideoSourceType,
            sourceLabel?: string,
            initialLinks?: { shopeeLink?: string; lazadaLink?: string },
        ) => {
            const videoId = crypto.randomUUID().replace(/-/g, '').slice(0, 8)
            let resolvedVideoUrl = videoUrl
            if (sourceType === 'telegram_video' || sourceType === 'xhs_url') {
                try {
                    const materialized = await materializeOriginalVideoAsset({
                        env: c.env,
                        bucket: c.get('bucket'),
                        namespaceId: String(c.get('botId') || ''),
                        videoId,
                        sourceType,
                        sourceUrl: videoUrl,
                    })
                    if (materialized.originalUrl) resolvedVideoUrl = materialized.originalUrl
                } catch (error) {
                    console.log(`[INBOX-ORIGINAL] materialize skipped video=${videoId}: ${error instanceof Error ? error.message : String(error)}`)
                }
                // The user may have pressed "ยกเลิก" while the (slow) materialize
                // ran. Honor it here so we don't resurrect the intake by saving
                // waiting state / prompting for links after a cancel.
                if (await isIntakeCancelled()) {
                    await clearIntakeCancelled()
                    await clearWaitingVideoState()
                    await c.get('bucket').put(dedupKey, 'processing')
                    return
                }
            }

            const waitingState = normalizeWaitingVideoState({
                id: videoId,
                videoUrl: resolvedVideoUrl,
                sourceType,
                sourceLabel,
                shopeeLink: initialLinks?.shopeeLink,
                lazadaLink: initialLinks?.lazadaLink,
            })
            if (!waitingState) {
                await c.get('bucket').put(dedupKey, 'processing')
                return
            }

            const duplicate = await findExistingDuplicateInboxVideo(waitingState)
            if (duplicate?.kind === 'waiting') {
                const mergedWaitingState = normalizeWaitingVideoState({
                    ...duplicate.item,
                    shopeeLink: initialLinks?.shopeeLink || duplicate.item.shopeeLink,
                    lazadaLink: initialLinks?.lazadaLink || duplicate.item.lazadaLink,
                })
                if (mergedWaitingState) {
                    if (getMissingWaitingLink(mergedWaitingState)) {
                        await saveWaitingVideoState(mergedWaitingState)
                        await sendTelegram(token, 'sendMessage', {
                            chat_id: chatId,
                            text: '♻️ คลิปนี้มีอยู่แล้วในรายการรอลิงก์ ผมอัปเดตข้อมูลให้รายการเดิมแทน',
                        })
                        await promptWaitingLink(mergedWaitingState)
                    } else {
                        const inboxItem = await upsertInboxFromWaitingState(mergedWaitingState)
                        await clearWaitingVideoState()
                        await sendQueuedInboxMessage(inboxItem)
                    }
                }
                await c.get('bucket').put(dedupKey, 'processing')
                return
            }
            if (duplicate?.kind === 'inbox') {
                const mergedRecord = await putInboxVideoRecord(c.get('bucket'), {
                    ...duplicate.item,
                    shopeeLink: initialLinks?.shopeeLink || duplicate.item.shopeeLink,
                    lazadaLink: initialLinks?.lazadaLink || duplicate.item.lazadaLink,
                    updatedAt: new Date().toISOString(),
                })
                if (mergedRecord.status === 'ready') {
                    await sendQueuedInboxMessage(mergedRecord)
                } else {
                    await sendTelegram(token, 'sendMessage', {
                        chat_id: chatId,
                        text: '♻️ คลิปนี้มีอยู่แล้วในคลังต้นฉบับ ผมอัปเดตลิงก์ให้รายการเดิมแทน',
                    })
                }
                await c.get('bucket').put(dedupKey, 'processing')
                return
            }

            const hasWaitingVideo = await getWaitingVideoState()
            if (hasWaitingVideo) {
                await sendTelegram(token, 'sendMessage', {
                    chat_id: chatId,
                    text: '❌ ยังมีวิดีโอที่รอลิงก์ค้างอยู่ 1 รายการ\nกรุณาส่งลิงก์ Shopee และ Lazada ของคลิปก่อนหน้าให้ครบก่อน',
                    reply_markup: intakeCancelKeyboard,
                })
                await c.get('bucket').put(dedupKey, 'processing')
                return
            }

            const inboxItem = await upsertInboxFromWaitingState(waitingState)

            if (inboxItem.status === 'ready') {
                await clearWaitingVideoState()
                await sendQueuedInboxMessage(inboxItem)
                await c.get('bucket').put(dedupKey, 'processing')
                return
            }

            await saveWaitingVideoState(waitingState)
            await promptWaitingLink(waitingState)
            await c.get('bucket').put(dedupKey, 'processing')
        }

        // กรณีส่งวิดีโอมา
        if (msg.video) {
            const fileInfo = await fetch(
                `https://api.telegram.org/bot${token}/getFile?file_id=${msg.video.file_id}`
            ).then(r => r.json()) as { ok: boolean; result?: { file_path: string } }

            if (fileInfo.ok && fileInfo.result) {
                const videoUrl = `https://api.telegram.org/file/bot${token}/${fileInfo.result.file_path}`
                const shopeeFromCaption = extractShopeeLink(msg.caption || '')
                const lazadaFromCaption = extractLazadaLink(msg.caption || '')
                // Fresh intake: drop any stale cancel marker so it can't abort
                // this upload inside handleVideoInput's post-materialize check.
                await clearIntakeCancelled()
                await handleVideoInput(videoUrl, 'telegram_video', 'Telegram video', {
                    shopeeLink: shopeeFromCaption || undefined,
                    lazadaLink: lazadaFromCaption || undefined,
                })
            }
            return c.text('ok')
        }

        // กรณีส่ง XHS link
        const xhsMatch = text.match(/https?:\/\/(xhslink\.com|www\.xiaohongshu\.com)\S+/)
        if (xhsMatch) {
            const videoUrl = xhsMatch[0]
            // Acknowledge immediately BEFORE the slow materialize (XHS resolve +
            // download). Without this the chat just shows "typing" with no reply
            // until materialize finishes — and on failure looks like silence.
            // Clear any stale cancel marker so this fresh intake starts clean,
            // and attach an inline cancel button users can press while it runs.
            await clearIntakeCancelled()
            await sendTelegram(token, 'sendMessage', {
                chat_id: chatId,
                text: '📥 รับลิงก์ XHS แล้ว กำลังดึงวิดีโอ/เตรียมข้อมูลให้นะ รอสักครู่...',
                reply_markup: intakeCancelKeyboard,
            }).catch(() => { })
            await handleVideoInput(videoUrl, 'xhs_url', videoUrl, {
                shopeeLink: extractShopeeLink(text) || undefined,
                lazadaLink: extractLazadaLink(text) || undefined,
            })
            return c.text('ok')
        }

        const shopeeLink = extractShopeeLink(text)
        const lazadaLink = extractLazadaLink(text)
        if (shopeeLink || lazadaLink) {
            const waitingState = await getWaitingVideoState()
            if (waitingState) {
                const nextState = normalizeWaitingVideoState({
                    ...waitingState,
                    shopeeLink: shopeeLink || waitingState.shopeeLink,
                    lazadaLink: lazadaLink || waitingState.lazadaLink,
                })
                if (!nextState) {
                    await c.get('bucket').put(dedupKey, 'processing')
                    return c.text('ok')
                }
                const inboxItem = await upsertInboxFromWaitingState(nextState)
                if (inboxItem.status === 'ready') {
                    await clearWaitingVideoState()
                    await sendQueuedInboxMessage(inboxItem)
                    await c.get('bucket').put(dedupKey, 'processing')
                    return c.text('ok')
                }
                await saveWaitingVideoState(nextState)
                await promptWaitingLink(nextState)
                await c.get('bucket').put(dedupKey, 'processing')
                return c.text('ok')
            }
            await sendTelegram(token, 'sendMessage', {
                chat_id: chatId,
                text: '❌ ไม่มีวิดีโอที่รอลิงก์ Shopee/Lazada\n\nส่งวิดีโอหรือลิงก์ XHS มาก่อน',
            })
            await c.get('bucket').put(dedupKey, 'processing')
            return c.text('ok')
        }

        if (text === '/skip') {
            await sendTelegram(token, 'sendMessage', {
                chat_id: chatId,
                text: '❌ ปิดคำสั่ง /skip แล้ว\nทุกคลิปต้องมี Shopee และ Lazada link ก่อนเริ่มประมวลผล',
            })
            return c.text('ok')
        }

        // /start
        if (text === '/start') {
            await sendTelegram(token, 'sendMessage', {
                chat_id: chatId,
                text: '👋 สวัสดี! ส่งลิงก์วิดีโอจาก Xiaohongshu หรืออัพโหลดวิดีโอมาเลย เดี๋ยวระบบจะถามทั้งลิงก์ Shopee และ Lazada ต่อให้',
            })
            return c.text('ok')
        }

        // ข้อความอื่น
        if (text.trim()) {
            const pendingState = await getWaitingVideoState()
            if (pendingState) {
                const missing = getMissingWaitingLink(pendingState)
                await sendTelegram(token, 'sendMessage', {
                    chat_id: chatId,
                    text: missing === 'lazada'
                        ? '❌ ลิงก์ Lazada ไม่ถูกต้อง\n\nส่งลิงก์ที่ขึ้นต้นด้วย https://s.lazada.co.th/... หรือ https://www.lazada...'
                        : '❌ ลิงก์ Shopee ไม่ถูกต้อง\n\nส่งลิงก์ที่ขึ้นต้นด้วย https://s.shopee.co.th/... หรือ https://shopee.co.th/...',
                    reply_markup: intakeCancelKeyboard,
                })
            } else {
                await sendTelegram(token, 'sendMessage', {
                    chat_id: chatId,
                    text: '❌ รองรับเฉพาะลิงก์ Xiaohongshu หรืออัพโหลดวิดีโอเท่านั้น\n\nตัวอย่าง: http://xhslink.com/...',
                })
            }
        }

        return c.text('ok')
    } catch (e) {
        console.error('[TELEGRAM] Handler error:', e instanceof Error ? e.message : String(e))
        return c.text('ok')
    }
})

