// ==================== PROCESSING QUEUE ====================

function normalizeProcessingStepName(stepName: unknown): string {
    const raw = typeof stepName === 'string' ? stepName : ''
    if (!raw) return raw

    let normalized = raw
    if (normalized.includes('แกะเวลาเสียง')) {
        normalized = normalized.replace('แกะเวลาเสียง', 'สร้างซับจากเสียงพากย์')
    }
    if (normalized.includes('Word Sync')) {
        normalized = normalized.replace('Word Sync', 'Gemini SRT')
    }
    if (normalized.includes('Gemini Audio Sync')) {
        normalized = normalized.replace('Gemini Audio Sync', 'Gemini SRT')
    }
    return normalized
}

function sanitizeProcessingError(raw: unknown): string {
    const text = String(raw || '').trim()
    if (!text) return ''
    return text
        .replace(/([?&]key=)[^&)\s]+/gi, '$1***')
        .replace(/AIza[0-9A-Za-z_-]{20,}/g, 'AIza***')
}

type InboxVideoStatus = 'awaiting_links' | 'ready'
type InboxVideoSourceType = 'telegram_video' | 'xhs_url' | 'line_video'
type InboxProcessingState = 'idle' | 'queued' | 'processing'
type InboxArchiveState = 'original' | 'processed'
type InboxVideoRecord = {
    id: string
    videoUrl: string
    chatId: number
    createdAt: string
    processedAt?: string
    updatedAt: string
    status: InboxVideoStatus
    sourceType: InboxVideoSourceType
    sourceLabel: string
    shopeeLink?: string
    lazadaLink?: string
    shopeeOriginalLink?: string
    lazadaOriginalLink?: string
    linkRecordedAt?: string
    manualCaption?: string
    captionProvidedAt?: string
}

function normalizeInboxVideoRecord(input: Partial<InboxVideoRecord> | null | undefined): InboxVideoRecord | null {
    const id = String(input?.id || '').trim()
    const videoUrl = String(input?.videoUrl || '').trim()
    const chatId = Number(input?.chatId || 0)
    if (!id || !videoUrl || !Number.isFinite(chatId) || chatId < 0) return null

    const shopeeLink = pickFirstShopeeUrl(String(input?.shopeeLink || '')) || ''
    const lazadaLink = pickFirstLazadaUrl(String(input?.lazadaLink || '')) || ''
    const shopeeOriginalLink = pickFirstShopeeUrl(String(input?.shopeeOriginalLink || '')) || shopeeLink
    const lazadaOriginalLink = pickFirstLazadaUrl(String(input?.lazadaOriginalLink || '')) || lazadaLink
    const manualCaption = normalizeManualCaption(input?.manualCaption)
    const sourceTypeRaw = String(input?.sourceType || '').trim().toLowerCase()
    const sourceType: InboxVideoSourceType = sourceTypeRaw === 'xhs_url' ? 'xhs_url' : sourceTypeRaw === 'line_video' ? 'line_video' : 'telegram_video'
    const sourceLabelInput = String(input?.sourceLabel || '').trim()
    const sourceLabel = sourceType === 'telegram_video'
        ? 'Telegram video'
        : sourceType === 'line_video'
            ? 'LINE video'
            : (sourceLabelInput || 'Xiaohongshu link').slice(0, 500)
    const createdAt = String(input?.createdAt || '').trim() || new Date().toISOString()
    const processedAt = String(input?.processedAt || '').trim()
    const updatedAt = String(input?.updatedAt || '').trim() || createdAt
    const status: InboxVideoStatus = shopeeLink && lazadaLink ? 'ready' : 'awaiting_links'

    return {
        id,
        videoUrl,
        chatId,
        createdAt,
        ...(processedAt ? { processedAt } : {}),
        updatedAt,
        status,
        sourceType,
        sourceLabel,
        ...(shopeeLink ? { shopeeLink } : {}),
        ...(lazadaLink ? { lazadaLink } : {}),
        ...(shopeeOriginalLink ? { shopeeOriginalLink } : {}),
        ...(lazadaOriginalLink ? { lazadaOriginalLink } : {}),
        ...(String(input?.linkRecordedAt || '').trim() ? { linkRecordedAt: String(input?.linkRecordedAt || '').trim() } : {}),
        ...(manualCaption ? { manualCaption } : {}),
        ...(String(input?.captionProvidedAt || '').trim() ? { captionProvidedAt: String(input?.captionProvidedAt || '').trim() } : {}),
    }
}

async function getInboxVideoRecord(bucket: R2Bucket, id: string): Promise<InboxVideoRecord | null> {
    const normalizedId = String(id || '').trim()
    if (!normalizedId) return null
    const obj = await bucket.get(`_inbox/${normalizedId}.json`)
    if (!obj) return null
    const raw = await obj.json().catch(() => null) as Partial<InboxVideoRecord> | null
    const record = normalizeInboxVideoRecord(raw)
    if (!record) {
        await bucket.delete(`_inbox/${normalizedId}.json`).catch(() => { })
        return null
    }
    return record
}

async function putInboxVideoRecord(bucket: R2Bucket, input: Partial<InboxVideoRecord>): Promise<InboxVideoRecord> {
    const record = normalizeInboxVideoRecord(input)
    if (!record) throw new Error('invalid_inbox_video_record')
    await bucket.put(`_inbox/${record.id}.json`, JSON.stringify(record), {
        httpMetadata: { contentType: 'application/json' },
    })
    return record
}

async function listInboxVideoRecords(bucket: R2Bucket): Promise<InboxVideoRecord[]> {
    const records: InboxVideoRecord[] = []
    let cursor: string | undefined = undefined
    do {
        const list = await bucket.list({ prefix: '_inbox/', cursor })
        const tasks = await Promise.all(list.objects.map(async (obj) => {
            const record = await getInboxVideoRecord(bucket, obj.key.replace(/^_inbox\//, '').replace(/\.json$/i, ''))
            return record
        }))
        records.push(...tasks.filter((item): item is InboxVideoRecord => !!item))
        cursor = list.truncated ? list.cursor : undefined
    } while (cursor)

    return records
        .filter((item): item is InboxVideoRecord => !!item)
        .sort((a, b) => {
            const aProcessedTs = new Date(String(a.processedAt || '')).getTime()
            const bProcessedTs = new Date(String(b.processedAt || '')).getTime()
            const aUpdatedTs = new Date(String(a.updatedAt || '')).getTime()
            const bUpdatedTs = new Date(String(b.updatedAt || '')).getTime()
            const aCreatedTs = new Date(String(a.createdAt || '')).getTime()
            const bCreatedTs = new Date(String(b.createdAt || '')).getTime()
            const aTs = Number.isFinite(aProcessedTs) && aProcessedTs > 0
                ? aProcessedTs
                : Number.isFinite(aUpdatedTs) && aUpdatedTs > 0
                    ? aUpdatedTs
                    : aCreatedTs
            const bTs = Number.isFinite(bProcessedTs) && bProcessedTs > 0
                ? bProcessedTs
                : Number.isFinite(bUpdatedTs) && bUpdatedTs > 0
                    ? bUpdatedTs
                    : bCreatedTs
            return (Number.isFinite(bTs) ? bTs : 0) - (Number.isFinite(aTs) ? aTs : 0)
        })
}

async function listRecentInboxVideoRecords(bucket: R2Bucket, limit = 50): Promise<InboxVideoRecord[]> {
    const normalizedLimit = Math.min(Math.max(Math.floor(Number(limit) || 50), 1), 100)
    const list = await bucket.list({ prefix: '_inbox/', limit: normalizedLimit })
    const records = await Promise.all(list.objects.map(async (obj) => {
        const id = obj.key.replace(/^_inbox\//, '').replace(/\.json$/i, '')
        const record = await getInboxVideoRecord(bucket, id).catch(() => null)
        return record ? { record, uploadedAt: obj.uploaded.getTime() } : null
    }))
    return records
        .filter((item): item is { record: InboxVideoRecord; uploadedAt: number } => !!item)
        .sort((a, b) => b.uploadedAt - a.uploadedAt)
        .map((item) => item.record)
}

type NamespaceOriginalAsset = {
    id: string
    originalUrl: string
    previewUrl: string
    hasProcessedVideo: boolean
    originalUploadedAt: string
    processedUploadedAt: string
    originalObjectKey?: string
    originalThumbnailObjectKey?: string
}

async function listNamespaceOriginalAssetMap(env: Env, bucket: R2Bucket, namespaceId: string): Promise<Map<string, NamespaceOriginalAsset>> {
    const normalizedNamespaceId = String(namespaceId || '').trim()
    if (!normalizedNamespaceId) return new Map()

    const objects = await listAllVideoObjects(bucket)
    const byId = new Map<string, {
        hasOriginalVideo: boolean
        hasProcessedVideoFile: boolean
        hasMetadata: boolean
        hasOriginalThumbnail: boolean
        originalUploadedAt: string
        processedUploadedAt: string
        originalObjectKey: string
        originalThumbnailObjectKey: string
    }>()

    for (const obj of objects) {
        const key = String(obj.key || '').trim()
        if (!key) continue

        const metadataMatch = key.match(/^videos\/(.+)\.json$/)
        if (metadataMatch) {
            const id = String(metadataMatch[1] || '').trim()
            if (!id) continue
            const current = byId.get(id) || {
                hasOriginalVideo: false,
                hasProcessedVideoFile: false,
                hasMetadata: false,
                hasOriginalThumbnail: false,
                originalUploadedAt: '',
                processedUploadedAt: '',
                originalObjectKey: '',
                originalThumbnailObjectKey: '',
            }
            current.hasMetadata = true
            byId.set(id, current)
            continue
        }

        const originalThumbMatch = key.match(/^videos\/(.+?)_original_thumb\.webp$/)
        if (originalThumbMatch) {
            const id = String(originalThumbMatch[1] || '').trim()
            if (!id) continue
            const current = byId.get(id) || {
                hasOriginalVideo: false,
                hasProcessedVideoFile: false,
                hasMetadata: false,
                hasOriginalThumbnail: false,
                originalUploadedAt: '',
                processedUploadedAt: '',
                originalObjectKey: '',
                originalThumbnailObjectKey: '',
            }
            current.hasOriginalThumbnail = true
            current.originalThumbnailObjectKey = key
            byId.set(id, current)
            continue
        }

        const originalMatch = key.match(/^videos\/(.+?)(?:_line)?_original\.mp4$/)
        if (originalMatch) {
            const id = String(originalMatch[1] || '').trim()
            if (!id) continue
            const current = byId.get(id) || {
                hasOriginalVideo: false,
                hasProcessedVideoFile: false,
                hasMetadata: false,
                hasOriginalThumbnail: false,
                originalUploadedAt: '',
                processedUploadedAt: '',
                originalObjectKey: '',
                originalThumbnailObjectKey: '',
            }
            current.hasOriginalVideo = true
            current.originalUploadedAt = String(obj.uploaded?.toISOString?.() || current.originalUploadedAt || '').trim()
            current.originalObjectKey = key
            byId.set(id, current)
            continue
        }

        const processedMatch = key.match(/^videos\/(.+)\.mp4$/)
        if (!processedMatch) continue
        const id = String(processedMatch[1] || '').trim()
        if (!id) continue

        const current = byId.get(id) || {
            hasOriginalVideo: false,
            hasProcessedVideoFile: false,
            hasMetadata: false,
            hasOriginalThumbnail: false,
            originalUploadedAt: '',
            processedUploadedAt: '',
            originalObjectKey: '',
            originalThumbnailObjectKey: '',
        }
        current.hasProcessedVideoFile = true
        current.processedUploadedAt = String(obj.uploaded?.toISOString?.() || current.processedUploadedAt || '').trim()
        byId.set(id, current)
    }

    const result = new Map<string, NamespaceOriginalAsset>()
    for (const [id, asset] of byId.entries()) {
        if (!asset.hasOriginalVideo) continue
        const hasProcessedVideo = asset.hasProcessedVideoFile && asset.hasMetadata
        const originalUrl = asset.originalObjectKey
            ? buildNamespaceObjectUrl(env.R2_PUBLIC_URL, normalizedNamespaceId, asset.originalObjectKey)
            : getVideoPublicUrlForNamespace(env.R2_PUBLIC_URL, normalizedNamespaceId, id)
        result.set(id, {
            id,
            originalUrl,
            previewUrl: asset.hasOriginalThumbnail
                ? getVideoOriginalThumbnailUrlForNamespace(env.R2_PUBLIC_URL, normalizedNamespaceId, id)
                : '',
            hasProcessedVideo,
            originalUploadedAt: asset.originalUploadedAt,
            processedUploadedAt: asset.processedUploadedAt,
            ...(asset.originalObjectKey ? { originalObjectKey: asset.originalObjectKey } : {}),
            ...(asset.originalThumbnailObjectKey ? { originalThumbnailObjectKey: asset.originalThumbnailObjectKey } : {}),
        })
    }
    return result
}

async function getInboxProcessingStateMap(bucket: R2Bucket): Promise<Map<string, InboxProcessingState>> {
    const stateMap = new Map<string, InboxProcessingState>()

    const applyState = async (prefix: '_queue/' | '_processing/', fallbackState: InboxProcessingState) => {
        const list = await bucket.list({ prefix })
        for (const obj of list.objects) {
            const id = obj.key.replace(prefix, '').replace(/\.json$/i, '').trim()
            if (!id) continue

            let nextState = fallbackState
            try {
                const payload = await bucket.get(obj.key)
                const json = payload ? await payload.json().catch(() => ({} as Record<string, unknown>)) as Record<string, unknown> : {}
                const rawStatus = String(json.status || '').trim().toLowerCase()
                if (rawStatus === 'failed') continue
                if (rawStatus === 'queued') nextState = 'queued'
                else if (rawStatus === 'processing') nextState = 'processing'
            } catch {
                // fall back to the prefix-derived state
            }

            stateMap.set(id, nextState)
        }
    }

    await applyState('_queue/', 'queued')
    await applyState('_processing/', 'processing')
    return stateMap
}

function toInboxVideoResponse(
    record: InboxVideoRecord,
    options?: {
        namespaceId?: string
        previewUrl?: string
        thumbnailUrl?: string
        originalUrl?: string
        canStartProcessing?: boolean
        canDelete?: boolean
    },
) {
    const canStartProcessing = options?.canStartProcessing !== false
    const canDelete = options?.canDelete !== false
    return {
        id: record.id,
        videoUrl: record.videoUrl,
        previewUrl: String(options?.previewUrl || options?.originalUrl || record.videoUrl || '').trim(),
        thumbnailUrl: String(options?.thumbnailUrl || '').trim(),
        originalUrl: String(options?.originalUrl || '').trim(),
        createdAt: record.createdAt,
        processedAt: String(record.processedAt || '').trim() || undefined,
        updatedAt: record.updatedAt,
        status: record.status,
        sourceType: record.sourceType,
        sourceLabel: record.sourceLabel,
        shopeeLink: String(record.shopeeLink || '').trim(),
        lazadaLink: String(record.lazadaLink || '').trim(),
        manualCaption: normalizeManualCaption(record.manualCaption),
        hasManualCaption: !!normalizeManualCaption(record.manualCaption),
        hasShopeeLink: !!String(record.shopeeLink || '').trim(),
        hasLazadaLink: !!String(record.lazadaLink || '').trim(),
        readyToProcess: record.status === 'ready',
        canStartProcessing,
        canDelete,
        namespace_id: String(options?.namespaceId || '').trim() || undefined,
    }
}

function pickPreferredInboxArchiveVideo(current: Record<string, unknown>, next: Record<string, unknown>): Record<string, unknown> {
    const currentCanDelete = current.canDelete === true ? 1 : 0
    const nextCanDelete = next.canDelete === true ? 1 : 0
    if (currentCanDelete !== nextCanDelete) {
        return nextCanDelete > currentCanDelete ? next : current
    }

    const currentLinkCount = (current.hasShopeeLink === true ? 1 : 0) + (current.hasLazadaLink === true ? 1 : 0)
    const nextLinkCount = (next.hasShopeeLink === true ? 1 : 0) + (next.hasLazadaLink === true ? 1 : 0)
    if (currentLinkCount !== nextLinkCount) {
        return nextLinkCount > currentLinkCount ? next : current
    }

    const currentTs = new Date(String(current.updatedAt || current.createdAt || '')).getTime()
    const nextTs = new Date(String(next.updatedAt || next.createdAt || '')).getTime()
    if (currentTs !== nextTs) {
        return nextTs >= currentTs ? next : current
    }

    return String(next.id || '').localeCompare(String(current.id || '')) <= 0 ? next : current
}

function getInboxArchiveDuplicateKey(video: Record<string, unknown>): string {
    const originalUrl = normalizeVideoDuplicateValue(video.originalUrl || video.original_url)
    if (originalUrl) return `original::${originalUrl}`

    const sourceType = String(video.sourceType || video.source_type || '').trim().toLowerCase()
    const sourceLabel = normalizeVideoDuplicateValue(video.sourceLabel || video.source_label)
    const videoUrl = normalizeVideoDuplicateValue(video.videoUrl || video.video_url)
    const previewUrl = normalizeVideoDuplicateValue(video.previewUrl || video.preview_url)

    if (sourceType === 'xhs_url' && sourceLabel) return `xhs::${sourceLabel}`
    if (videoUrl) return `video::${videoUrl}`
    if (previewUrl) return `preview::${previewUrl}`
    return `id::${String(video.id || '').trim()}`
}

function dedupeInboxArchiveVideos(videos: Array<Record<string, unknown>>): Array<Record<string, unknown>> {
    const byKey = new Map<string, Record<string, unknown>>()

    for (const video of videos) {
        const dedupeKey = getInboxArchiveDuplicateKey(video)
        const previous = byKey.get(dedupeKey)
        if (!previous) {
            byKey.set(dedupeKey, video)
            continue
        }
        byKey.set(dedupeKey, pickPreferredInboxArchiveVideo(previous, video))
    }

    return Array.from(byKey.values()).sort((a, b) => {
        const aCreatedTs = new Date(String(a.createdAt || '')).getTime()
        const bCreatedTs = new Date(String(b.createdAt || '')).getTime()
        const at = Number.isFinite(aCreatedTs) && aCreatedTs > 0
            ? aCreatedTs
            : new Date(String(a.updatedAt || '')).getTime()
        const bt = Number.isFinite(bCreatedTs) && bCreatedTs > 0
            ? bCreatedTs
            : new Date(String(b.updatedAt || '')).getTime()
        return (Number.isFinite(bt) ? bt : 0) - (Number.isFinite(at) ? at : 0)
    })
}

function getInboxVideoSortMs(video: Record<string, unknown>): number {
    const processedTs = new Date(String(video.processedAt || video.processed_at || '')).getTime()
    if (Number.isFinite(processedTs) && processedTs > 0) return processedTs
    const updatedTs = new Date(String(video.updatedAt || '')).getTime()
    if (Number.isFinite(updatedTs) && updatedTs > 0) return updatedTs
    const createdTs = new Date(String(video.createdAt || '')).getTime()
    if (Number.isFinite(createdTs) && createdTs > 0) return createdTs
    return Number.isFinite(updatedTs) ? updatedTs : 0
}

function isInboxVideoOwnedByNamespace(video: Record<string, unknown>, namespaceId: string): boolean {
    const videoNamespaceId = String(video.namespace_id || '').trim()
    const currentNamespaceId = String(namespaceId || '').trim()
    return !!videoNamespaceId && !!currentNamespaceId && videoNamespaceId === currentNamespaceId
}

function parseImportedNamespaceIdFromInboxSourceLabel(sourceLabel?: unknown): string {
    const label = String(sourceLabel || '').trim()
    if (!label) return ''
    const match = label.match(/imported from\s+([A-Za-z0-9_:-]+)/i)
    return String(match?.[1] || '').trim()
}

function dedupeSystemInboxVideos(
    videos: Array<Record<string, unknown>>,
    currentNamespaceId: string,
): Array<Record<string, unknown>> {
    const groups = new Map<string, Array<Record<string, unknown>>>()
    const normalizedNamespaceId = String(currentNamespaceId || '').trim()

    for (const video of videos) {
        const videoId = String(video.id || '').trim()
        if (!videoId) continue
        const items = groups.get(videoId) || []
        items.push(video)
        groups.set(videoId, items)
    }

    return Array.from(groups.values())
        .map((items) => {
            const sortedItems = items
                .slice()
                .sort((a, b) => getInboxVideoSortMs(b) - getInboxVideoSortMs(a))
            const preferredOwnVideo = normalizedNamespaceId
                ? sortedItems.find((item) => isInboxVideoOwnedByNamespace(item, normalizedNamespaceId))
                : undefined
            const selected = preferredOwnVideo || sortedItems[0]
            const namespaceIds = Array.from(new Set(
                sortedItems
                    .map((item) => String(item.namespace_id || '').trim())
                    .filter(Boolean)
            ))
            const fallbackThumbVideo = sortedItems.find((item) => !!String(item.thumbnailUrl || '').trim())
            const fallbackPlaybackVideo = sortedItems.find((item) => (
                !!String(item.originalUrl || '').trim()
                || !!String(item.previewUrl || '').trim()
                || !!String(item.videoUrl || '').trim()
            ))
            const selectedNamespaceId = String(selected.namespace_id || '').trim()
            const importedFromNamespaceId = String(
                selected.importedFromNamespaceId
                || parseImportedNamespaceIdFromInboxSourceLabel(selected.sourceLabel)
                || namespaceIds.find((namespaceId) => namespaceId && namespaceId !== selectedNamespaceId)
                || ''
            ).trim() || undefined

            return {
                ...selected,
                thumbnailUrl: String(selected.thumbnailUrl || fallbackThumbVideo?.thumbnailUrl || '').trim() || undefined,
                originalUrl: String(selected.originalUrl || fallbackPlaybackVideo?.originalUrl || '').trim() || undefined,
                previewUrl: String(selected.previewUrl || fallbackPlaybackVideo?.previewUrl || '').trim() || undefined,
                videoUrl: String(selected.videoUrl || fallbackPlaybackVideo?.videoUrl || '').trim() || undefined,
                importedFromNamespaceId,
                duplicateNamespaceIds: namespaceIds,
                dedupedFromOtherNamespace: !!(
                    importedFromNamespaceId
                    && isInboxVideoOwnedByNamespace(selected, normalizedNamespaceId)
                ),
            }
        })
        .sort((a, b) => getInboxVideoSortMs(b) - getInboxVideoSortMs(a))
}

function buildInboxVideoResponseForNamespace(
    env: Env,
    record: InboxVideoRecord,
    namespaceId: string,
    ownerEmail = '',
): Record<string, unknown> {
    const normalizedNamespaceId = String(namespaceId || '').trim()
    const originalUrl = getVideoOriginalUrlForNamespace(env.R2_PUBLIC_URL, normalizedNamespaceId, record.id)
    const fallbackUrl = String(originalUrl || record.videoUrl || '').trim()
    const fallbackThumbnailUrl = buildWorkerGalleryFrameUrl(
        String(env.WORKER_URL || '').trim(),
        normalizedNamespaceId,
        record.id,
        {
            seed: `${normalizedNamespaceId}:${record.id}:original`,
            format: 'jpg',
            width: 540,
            height: 960,
        },
    )
    return {
        ...toInboxVideoResponse(record, {
            namespaceId: normalizedNamespaceId,
            previewUrl: fallbackUrl,
            thumbnailUrl: getVideoOriginalThumbnailUrlForNamespace(env.R2_PUBLIC_URL, normalizedNamespaceId, record.id),
            originalUrl: fallbackUrl,
            canStartProcessing: true,
            canDelete: true,
        }),
        ...(fallbackThumbnailUrl ? { fallbackThumbnailUrl } : {}),
        ...(ownerEmail ? { owner_email: ownerEmail } : {}),
    }
}

function buildInboxVideoResponseFromGalleryIndex(
    env: Env,
    video: Record<string, unknown>,
    ownerEmail = '',
    options?: { shortlinkRequired?: boolean },
): Record<string, unknown> | null {
    const namespaceId = String(video.namespace_id || '').trim()
    const videoId = String(video.id || video.video_id || '').trim()
    const originalUrl = String(video.originalUrl || video.original_url || '').trim()
    if (!namespaceId || !videoId || !originalUrl) return null
    const processedAt = String(video.processedAt || video.processed_at || '').trim()
    const shopeeLink = String(video.shopeeLink || video.shopee_link || '').trim()
    const lazadaLink = String(video.lazadaLink || video.lazada_link || '').trim()
    const shopeeLinkError = getShopeeLinkValidationError(shopeeLink)
    const hasUsableShopeeLink = !shopeeLinkError
    const readyToProcess = !processedAt && hasUsableShopeeLink && !!lazadaLink
    const fallbackThumbnailUrl = buildWorkerGalleryFrameUrl(
        String(env.WORKER_URL || '').trim(),
        namespaceId,
        videoId,
        {
            seed: `${namespaceId}:${videoId}:original`,
            format: 'jpg',
            width: 540,
            height: 960,
        },
    )
    return {
        id: videoId,
        videoUrl: originalUrl,
        previewUrl: originalUrl,
        thumbnailUrl: String(video.thumbnailUrl || video.thumbnail_url || '').trim()
            || getVideoOriginalThumbnailUrlForNamespace(env.R2_PUBLIC_URL, namespaceId, videoId),
        originalUrl,
        fallbackThumbnailUrl,
        createdAt: String(video.createdAt || video.created_at || video.updatedAt || video.updated_at || '').trim() || new Date().toISOString(),
        updatedAt: String(video.updatedAt || video.updated_at || video.createdAt || video.created_at || '').trim() || new Date().toISOString(),
        ...(processedAt ? { processedAt } : {}),
        status: readyToProcess
            ? 'ready'
            : 'awaiting_links',
        sourceType: 'line_video',
        sourceLabel: 'Admin original',
        shopeeLink,
        lazadaLink,
        hasShopeeLink: hasUsableShopeeLink,
        hasLazadaLink: !!lazadaLink,
        ...(shopeeLinkError ? {
            shopeeLinkError,
            linkError: shopeeLinkError === 'invalid_shopee_homepage_link'
                ? 'ลิงก์ Shopee เป็นหน้าแรก กรุณาใส่ลิงก์สินค้า/affiliate short link'
                : 'ยังไม่มีลิงก์ Shopee',
        } : {}),
        readyToProcess,
        canStartProcessing: readyToProcess,
        canDelete: true,
        namespace_id: namespaceId,
        ...(ownerEmail ? { owner_email: ownerEmail } : {}),
    }
}

// Failed-processing cooldown: skip videos whose last failure is fresher than this.
// Prevents one broken video (e.g., Lazada link with t=p-i0-s0 placeholder that
// repeatedly returns HTTP 500) from blocking the entire admin queue every cron tick.
const PROCESSING_FAILURE_COOLDOWN_MS = 24 * 60 * 60 * 1000

async function getNextReadyGalleryIndexInboxRecord(params: {
    env: Env
    bucket: R2Bucket
    namespaceId: string
    excludeVideoIds?: string[]
}): Promise<InboxVideoRecord | null> {
    const namespaceId = String(params.namespaceId || '').trim()
    if (!namespaceId) return null
    const excludeVideoIds = new Set((params.excludeVideoIds || []).map((id) => String(id || '').trim()).filter(Boolean))
    await ensureGalleryIndexTable(params.env.DB).catch(() => { })

    const pageSize = 160
    const maxPages = 12
    let scanned = 0
    for (let pageIndex = 0; pageIndex < maxPages; pageIndex++) {
        const page = await params.env.DB.prepare(
            `SELECT
                gi.namespace_id,
                gi.video_id,
                gi.title,
                ${NAMESPACE_STATE_SHOPEE_LINK_SQL} AS shopee_link,
                ${NAMESPACE_STATE_LAZADA_LINK_SQL} AS lazada_link,
                COALESCE(NULLIF(TRIM(nvs.shopee_original_link), ''), gi.shopee_original_link, gi.shopee_link) AS shopee_original_link,
                COALESCE(NULLIF(TRIM(nvs.lazada_original_link), ''), gi.lazada_original_link, gi.lazada_link) AS lazada_original_link,
                gi.original_url,
                gi.created_at,
                gi.updated_at
             ${DASHBOARD_GALLERY_FROM_JOIN}
             WHERE gi.namespace_id = ?
               AND TRIM(COALESCE(NULLIF(TRIM(gi.original_url), ''), NULLIF(TRIM(gi.public_url), ''))) <> ''
               AND TRIM(COALESCE(gi.processed_at,'')) = ''
               AND ${NAMESPACE_STATE_USABLE_SHOPEE_LINK_SQL}
               AND ${NAMESPACE_STATE_HAS_LAZADA_LINK_SQL}
             ORDER BY COALESCE(NULLIF(TRIM(gi.updated_at), ''), NULLIF(TRIM(gi.created_at), '')) DESC, gi.video_id ASC
             LIMIT ? OFFSET ?`
        ).bind(namespaceId, pageSize, pageIndex * pageSize).all().catch(() => ({ results: [] })) as { results?: Array<Record<string, unknown>> }

        const rows = page.results || []
        if (rows.length <= 0) break
        scanned += rows.length

        for (const row of rows) {
            const id = String(row.video_id || '').trim()
            if (!id) continue

            const processingRecord = await getProcessingJobRecord(params.bucket, id).catch(() => null)
            const existingProcessingStatus = String(processingRecord?.status || '').trim().toLowerCase()
            if (existingProcessingStatus && existingProcessingStatus !== 'failed') continue
            if (existingProcessingStatus === 'failed') {
                const failedAtMs = Date.parse(String(processingRecord?.failedAt || processingRecord?.updatedAt || ''))
                if (Number.isFinite(failedAtMs) && (Date.now() - failedAtMs) < PROCESSING_FAILURE_COOLDOWN_MS) {
                    continue
                }
            }

            const processedAt = await getGalleryIndexProcessedAt(params.env.DB, namespaceId, id).catch(() => '')
            if (processedAt) continue

            const originalUrl = String(row.original_url || '').trim()
            const shopeeLink = String(row.shopee_link || '').trim()
            const lazadaLink = String(row.lazada_link || '').trim()
            if (!originalUrl || !isUsableShopeeLink(shopeeLink) || !lazadaLink) continue

            if (scanned > pageSize) {
                console.log(`[PROCESSING-DISPATCH] ready candidate found after deep scan scanned=${scanned}`)
            }
            const existing = await getInboxVideoRecord(params.bucket, id).catch(() => null)
            const timestamp = String(row.updated_at || row.created_at || '').trim() || new Date().toISOString()
            return putInboxVideoRecord(params.bucket, {
                ...existing,
                id,
                videoUrl: originalUrl,
                chatId: Number(existing?.chatId || 0),
                createdAt: String(existing?.createdAt || row.created_at || timestamp).trim() || timestamp,
                updatedAt: new Date().toISOString(),
                sourceType: existing?.sourceType || 'line_video',
                sourceLabel: String(existing?.sourceLabel || row.title || 'Admin original').trim().slice(0, 500) || 'Admin original',
                shopeeLink,
                lazadaLink,
                shopeeOriginalLink: String(row.shopee_original_link || shopeeLink).trim(),
                lazadaOriginalLink: String(row.lazada_original_link || lazadaLink).trim(),
                linkRecordedAt: String(existing?.linkRecordedAt || timestamp).trim() || timestamp,
                manualCaption: normalizeManualCaption(existing?.manualCaption || ''),
                captionProvidedAt: String(existing?.captionProvidedAt || '').trim(),
            })
        }

        if (rows.length < pageSize) break
    }

    return null
}

async function syncReadyInboxLinksToNamespaceIndex(params: {
    env: Env
    bucket: R2Bucket
    namespaceId: string
    limit?: number
}): Promise<number> {
    const namespaceId = String(params.namespaceId || '').trim()
    if (!namespaceId) return 0

    await ensureGalleryIndexTable(params.env.DB).catch(() => { })
    const limit = Math.min(Math.max(Math.floor(Number(params.limit || 300)), 1), 1000)
    const rows = await params.env.DB.prepare(
        `SELECT video_id
         FROM gallery_index
         WHERE namespace_id = ?
           AND TRIM(COALESCE(original_url,'')) <> ''
           AND TRIM(COALESCE(processed_at,'')) = ''
           AND (NOT (${GALLERY_INDEX_USABLE_SHOPEE_LINK_SQL}) OR TRIM(COALESCE(lazada_link,'')) = '')
         ORDER BY COALESCE(NULLIF(TRIM(updated_at), ''), NULLIF(TRIM(created_at), '')) DESC, video_id ASC
         LIMIT ?`
    ).bind(namespaceId, limit).all().catch(() => ({ results: [] })) as { results?: Array<{ video_id?: string }> }
    let synced = 0
    const nowIso = new Date().toISOString()

    for (const row of rows.results || []) {
        const rowVideoId = String(row.video_id || '').trim()
        if (!rowVideoId) continue
        const record = await getInboxVideoRecord(params.bucket, rowVideoId).catch(() => null)
        const item = normalizeInboxVideoRecord(record)
        if (!item || item.status !== 'ready') continue

        const videoId = String(item.id || '').trim()
        const shopeeLink = String(item.shopeeLink || '').trim()
        const lazadaLink = String(item.lazadaLink || '').trim()
        if (!videoId || !isUsableShopeeLink(shopeeLink) || !lazadaLink) continue

        const shopeeOriginalLink = String(item.shopeeOriginalLink || shopeeLink).trim()
        const lazadaOriginalLink = String(item.lazadaOriginalLink || lazadaLink).trim()

        await upsertNamespaceVideoState(params.env.DB, namespaceId, videoId, {
            shopee_link: shopeeLink,
            lazada_link: lazadaLink,
            shopee_original_link: shopeeOriginalLink,
            lazada_original_link: lazadaOriginalLink,
        }).catch(() => { })

        const result = await params.env.DB.prepare(
            `UPDATE gallery_index
             SET shopee_link = CASE WHEN NOT (${GALLERY_INDEX_USABLE_SHOPEE_LINK_SQL}) THEN ? ELSE shopee_link END,
                 lazada_link = CASE WHEN TRIM(COALESCE(lazada_link,'')) = '' THEN ? ELSE lazada_link END,
                 shopee_original_link = CASE WHEN TRIM(COALESCE(shopee_original_link,'')) = '' THEN ? ELSE shopee_original_link END,
                 lazada_original_link = CASE WHEN TRIM(COALESCE(lazada_original_link,'')) = '' THEN ? ELSE lazada_original_link END,
                 updated_at = ?
             WHERE namespace_id = ?
               AND video_id = ?
               AND TRIM(COALESCE(processed_at,'')) = ''
               AND (NOT (${GALLERY_INDEX_USABLE_SHOPEE_LINK_SQL}) OR TRIM(COALESCE(lazada_link,'')) = '')`
        ).bind(
            shopeeLink,
            lazadaLink,
            shopeeOriginalLink,
            lazadaOriginalLink,
            nowIso,
            namespaceId,
            videoId,
        ).run().catch(() => null) as { meta?: { changes?: number } } | null

        if (Number(result?.meta?.changes || 0) > 0) synced++
    }

    if (synced > 0) {
        console.log(`[INBOX-LINK-SYNC] namespace=${namespaceId} synced=${synced}`)
    }
    return synced
}

async function syncInboxRecordLinksToNamespaceIndex(params: {
    env: Env
    namespaceId: string
    item: InboxVideoRecord
}): Promise<boolean> {
    const namespaceId = String(params.namespaceId || '').trim()
    const item = normalizeInboxVideoRecord(params.item)
    if (!namespaceId || !item || item.status !== 'ready') return false

    const videoId = String(item.id || '').trim()
    const shopeeLink = String(item.shopeeLink || '').trim()
    const lazadaLink = String(item.lazadaLink || '').trim()
    if (!videoId || !shopeeLink || !lazadaLink) return false

    await ensureGalleryIndexTable(params.env.DB).catch(() => { })

    const shopeeOriginalLink = String(item.shopeeOriginalLink || shopeeLink).trim()
    const lazadaOriginalLink = String(item.lazadaOriginalLink || lazadaLink).trim()
    await upsertNamespaceVideoState(params.env.DB, namespaceId, videoId, {
        shopee_link: shopeeLink,
        lazada_link: lazadaLink,
        shopee_original_link: shopeeOriginalLink,
        lazada_original_link: lazadaOriginalLink,
    }).catch(() => { })

    const updateExisting = async () => params.env.DB.prepare(
        `UPDATE gallery_index
         SET shopee_link = ?,
             lazada_link = ?,
             shopee_original_link = ?,
             lazada_original_link = ?,
             updated_at = ?
         WHERE namespace_id = ?
           AND video_id = ?
           AND TRIM(COALESCE(processed_at,'')) = ''`
    ).bind(
        shopeeLink,
        lazadaLink,
        shopeeOriginalLink,
        lazadaOriginalLink,
        new Date().toISOString(),
        namespaceId,
        videoId,
    ).run().catch(() => null) as Promise<{ meta?: { changes?: number } } | null>

    let result = await updateExisting()
    if (Number(result?.meta?.changes || 0) <= 0) {
        await syncGalleryIndexEntry(params.env, namespaceId, videoId).catch(() => null)
        result = await updateExisting()
    }

    return Number(result?.meta?.changes || 0) > 0
}

type InboxListView = 'unprocessed' | 'missing_links' | 'processed'

function parseInboxListView(input: unknown): InboxListView {
    const value = String(input || '').trim().toLowerCase()
    if (value === 'processed') return 'processed'
    if (value === 'missing_links' || value === 'missing-links' || value === 'no_links' || value === 'no-links') return 'missing_links'
    return 'unprocessed'
}

function isInboxResponseProcessed(video: Record<string, unknown>): boolean {
    return !!String(video.processedAt || video.processed_at || '').trim()
}

function isInboxResponseMissingLinks(video: Record<string, unknown>): boolean {
    if (isInboxResponseProcessed(video)) return false
    const hasShopee = video.hasShopeeLink === true || !!String(video.shopeeLink || video.shopee_link || '').trim()
    const hasLazada = video.hasLazadaLink === true || !!String(video.lazadaLink || video.lazada_link || '').trim()
    return !hasShopee || !hasLazada
}

function filterInboxVideosByView<T extends Record<string, unknown>>(videos: T[], view: InboxListView): T[] {
    return videos.filter((video) => {
        const processed = isInboxResponseProcessed(video)
        if (view === 'processed') return processed
        if (view === 'missing_links') return isInboxResponseMissingLinks(video)
        return !processed && !isInboxResponseMissingLinks(video)
    })
}

async function getNamespaceInboxGalleryIndexPage(params: {
    env: Env
    namespaceId: string
    ownerEmail?: string
    view: InboxListView
    offset: number
    limit: number
}): Promise<{
    videos: Array<Record<string, unknown>>
    total: number
    processedTotal: number
    unprocessedTotal: number
    missingLinkTotal: number
    hasMore: boolean
}> {
    const namespaceId = String(params.namespaceId || '').trim()
    if (!namespaceId) {
        return { videos: [], total: 0, processedTotal: 0, unprocessedTotal: 0, missingLinkTotal: 0, hasMore: false }
    }
    await ensureGalleryIndexTable(params.env.DB).catch(() => { })
    const offset = Math.max(0, Number(params.offset || 0))
    const limit = Math.min(Math.max(1, Number(params.limit || 24)), 120)
    const shortlinkRequired = await isNamespaceAffiliateShortlinkRequired(params.env.DB, namespaceId).catch(() => false)
    const processedClause = params.view === 'processed'
        ? "AND TRIM(COALESCE(processed_at,'')) <> ''"
        : params.view === 'missing_links'
            ? `AND TRIM(COALESCE(processed_at,'')) = '' AND (NOT (${GALLERY_INDEX_USABLE_SHOPEE_LINK_SQL}) OR TRIM(COALESCE(lazada_link,'')) = '')`
            : `AND TRIM(COALESCE(processed_at,'')) = '' AND ${GALLERY_INDEX_USABLE_SHOPEE_LINK_SQL} AND TRIM(COALESCE(lazada_link,'')) <> ''`
    const [pageRows, totals] = await Promise.all([
        params.env.DB.prepare(
            `SELECT
                namespace_id,
                video_id,
                owner_email,
                script,
                title,
                category,
                duration,
                shopee_link,
                lazada_link,
                shopee_original_link,
                lazada_original_link,
                public_url,
                original_url,
                thumbnail_url,
                created_at,
                processed_at,
                updated_at
             FROM gallery_index
             WHERE namespace_id = ?
               AND TRIM(COALESCE(original_url,'')) <> ''
               ${processedClause}
             ORDER BY COALESCE(NULLIF(TRIM(processed_at), ''), NULLIF(TRIM(updated_at), ''), NULLIF(TRIM(created_at), '')) DESC, video_id ASC
             LIMIT ? OFFSET ?`
        ).bind(namespaceId, limit, offset).all() as Promise<{ results?: Array<Record<string, unknown>> }>,
        params.env.DB.prepare(
            `SELECT
                COUNT(*) AS total,
                SUM(CASE WHEN TRIM(COALESCE(processed_at,'')) <> '' THEN 1 ELSE 0 END) AS processed_total,
                SUM(CASE WHEN TRIM(COALESCE(processed_at,'')) = '' AND ${GALLERY_INDEX_USABLE_SHOPEE_LINK_SQL} AND TRIM(COALESCE(lazada_link,'')) <> '' THEN 1 ELSE 0 END) AS unprocessed_total,
                SUM(CASE WHEN TRIM(COALESCE(processed_at,'')) = '' AND (NOT (${GALLERY_INDEX_USABLE_SHOPEE_LINK_SQL}) OR TRIM(COALESCE(lazada_link,'')) = '') THEN 1 ELSE 0 END) AS missing_link_total
             FROM gallery_index
             WHERE namespace_id = ?
               AND TRIM(COALESCE(original_url,'')) <> ''`
        ).bind(namespaceId).first() as Promise<{ total?: number; processed_total?: number; unprocessed_total?: number } | null>,
    ])
    const ownerEmail = String(params.ownerEmail || '').trim()
    const bucket = new BotBucket(params.env.BUCKET, namespaceId) as unknown as R2Bucket
    const videos = (await Promise.all((pageRows.results || []).map(async (row) => {
        const videoId = String(row.video_id || row.id || '').trim()
        const existingInboxRecord = videoId ? await getInboxVideoRecord(bucket, videoId).catch(() => null) : null
        const existingLineRecordNeedsLinks = !!(
            existingInboxRecord
            && (existingInboxRecord.sourceType === 'line_video' || existingInboxRecord.sourceType === 'xhs_url')
            && (!String(existingInboxRecord.shopeeLink || '').trim() || !String(existingInboxRecord.lazadaLink || '').trim())
        )
        return buildInboxVideoResponseFromGalleryIndex(params.env, row, ownerEmail || String(row.owner_email || '').trim(), {
            shortlinkRequired: shortlinkRequired || existingLineRecordNeedsLinks,
        })
    })))
        .filter((video): video is Record<string, unknown> => !!video)
    const processedTotal = Number(totals?.processed_total || 0)
    const unprocessedTotal = Number(totals?.unprocessed_total || 0)
    const missingLinkTotal = Number((totals as Record<string, unknown> | null)?.missing_link_total || 0)
    const total = Number(totals?.total || 0)
    const viewTotal = params.view === 'processed'
        ? processedTotal
        : params.view === 'missing_links'
            ? missingLinkTotal
            : unprocessedTotal
    return {
        videos,
        total,
        processedTotal,
        unprocessedTotal,
        missingLinkTotal,
        hasMore: offset + videos.length < viewTotal,
    }
}

const NAMESPACE_INBOX_CACHE_TTL_MS = 15 * 1000
const SYSTEM_INBOX_CACHE_TTL_MS = 15 * 1000

function getNamespaceInboxCacheKey(namespaceId: string): string {
    const normalizedNamespaceId = String(namespaceId || '').trim() || 'default'
    return `_cache/inbox_${normalizedNamespaceId}.json`
}

async function buildNamespaceInboxSnapshot(
    env: Env,
    namespaceId: string,
): Promise<Array<Record<string, unknown>>> {
    const normalizedNamespaceId = String(namespaceId || '').trim()
    if (!normalizedNamespaceId) return []
    const bucket = new BotBucket(env.BUCKET, normalizedNamespaceId) as unknown as R2Bucket
    const records = await listInboxVideoRecords(bucket)
    return records.map((record) => buildInboxVideoResponseForNamespace(env, record, normalizedNamespaceId))
}

async function readNamespaceInboxSnapshot(
    bucket: R2Bucket,
    namespaceId: string,
): Promise<{ videos: Array<Record<string, unknown>>; builtAtMs: number } | null> {
    const cacheObj = await bucket.get(getNamespaceInboxCacheKey(namespaceId)).catch(() => null)
    if (!cacheObj) return null
    const payload = await cacheObj.json().catch(() => null) as { builtAt?: string; videos?: Array<Record<string, unknown>> } | null
    const videos = Array.isArray(payload?.videos) ? payload!.videos : []
    const builtAtMs = Date.parse(String(payload?.builtAt || ''))
    return {
        videos,
        builtAtMs: Number.isFinite(builtAtMs) ? builtAtMs : 0,
    }
}

async function writeNamespaceInboxSnapshot(
    bucket: R2Bucket,
    namespaceId: string,
    videos: Array<Record<string, unknown>>,
): Promise<void> {
    await bucket.put(getNamespaceInboxCacheKey(namespaceId), JSON.stringify({
        builtAt: new Date().toISOString(),
        videos,
    }), {
        httpMetadata: { contentType: 'application/json' },
    })
}

function getSystemInboxCacheKey(namespaceId: string): string {
    const normalizedNamespaceId = String(namespaceId || '').trim() || 'default'
    return `_admin_cache/system_inbox_${normalizedNamespaceId}.json`
}

async function buildSystemInboxSnapshot(
    env: Env,
    currentNamespaceId: string,
): Promise<Array<Record<string, unknown>>> {
    const namespaceEmailMap = await getNamespaceOwnerEmailMap(env.DB)
    const currentNamespaceGalleryVideos = await listGalleryIndexVideos(env.DB, {
        namespaceId: currentNamespaceId,
        playableOnly: true,
    }).catch(() => [])
    const currentNamespaceOriginalVideos = currentNamespaceGalleryVideos
        .map((video) => buildInboxVideoResponseFromGalleryIndex(
            env,
            video as unknown as Record<string, unknown>,
            namespaceEmailMap.get(currentNamespaceId) || '',
        ))
        .filter((video): video is Record<string, unknown> => !!video)
    if (currentNamespaceOriginalVideos.length > 0) {
        return dedupeSystemInboxVideos(currentNamespaceOriginalVideos, currentNamespaceId)
    }

    const namespaceIds = new Set<string>()
    try {
        const { results } = await env.DB.prepare('SELECT DISTINCT namespace_id FROM email_namespaces').all()
        for (const row of results || []) {
            const id = String((row as any)?.namespace_id || '').trim()
            if (id) namespaceIds.add(id)
        }
    } catch { /* email_namespaces table may not exist */ }
    if (currentNamespaceId) namespaceIds.add(currentNamespaceId)

    const hiddenImportedSourceKeys = new Set<string>()
    if (currentNamespaceId) {
        await ensureImportedVideosTable(env.DB)
        const importedRows = await env.DB.prepare(
            'SELECT video_id, source_namespace_id FROM imported_videos WHERE namespace_id = ?'
        ).bind(currentNamespaceId).all().catch(() => ({ results: [] as Array<{ video_id?: string; source_namespace_id?: string }> }))
        for (const row of importedRows.results || []) {
            const videoId = String((row as any)?.video_id || '').trim()
            const sourceNamespaceId = String((row as any)?.source_namespace_id || '').trim()
            if (!videoId || !sourceNamespaceId) continue
            hiddenImportedSourceKeys.add(`${sourceNamespaceId}:${videoId}`)
        }
    }

    const allVideos: Array<Record<string, unknown>> = []
    await Promise.all(Array.from(namespaceIds).map(async (nsId) => {
        const bucket = new BotBucket(env.BUCKET, nsId) as unknown as R2Bucket
        const records = await listInboxVideoRecords(bucket)
        for (const record of records) {
            const videoId = String(record.id || '').trim()
            if (nsId !== currentNamespaceId && videoId && hiddenImportedSourceKeys.has(`${nsId}:${videoId}`)) {
                continue
            }
            allVideos.push(buildInboxVideoResponseForNamespace(
                env,
                record,
                nsId,
                namespaceEmailMap.get(nsId) || '',
            ))
        }
    }))

    return dedupeSystemInboxVideos(allVideos, currentNamespaceId)
}

async function readSystemInboxSnapshot(
    bucket: R2Bucket,
    currentNamespaceId: string,
): Promise<{ videos: Array<Record<string, unknown>>; builtAtMs: number } | null> {
    const cacheObj = await bucket.get(getSystemInboxCacheKey(currentNamespaceId)).catch(() => null)
    if (!cacheObj) return null
    const payload = await cacheObj.json().catch(() => null) as { builtAt?: string; videos?: Array<Record<string, unknown>> } | null
    const videos = Array.isArray(payload?.videos) ? payload!.videos : []
    const builtAtMs = Date.parse(String(payload?.builtAt || ''))
    return {
        videos,
        builtAtMs: Number.isFinite(builtAtMs) ? builtAtMs : 0,
    }
}

async function writeSystemInboxSnapshot(
    bucket: R2Bucket,
    currentNamespaceId: string,
    videos: Array<Record<string, unknown>>,
): Promise<void> {
    await bucket.put(getSystemInboxCacheKey(currentNamespaceId), JSON.stringify({
        builtAt: new Date().toISOString(),
        videos,
    }), {
        httpMetadata: { contentType: 'application/json' },
    })
}

async function upsertSystemInboxSnapshotVideo(params: {
    env: Env
    adminNamespaceId: string
    bucket: R2Bucket
    record: InboxVideoRecord
    recordNamespaceId?: string
}): Promise<void> {
    const adminNamespaceId = String(params.adminNamespaceId || '').trim()
    if (!adminNamespaceId) return
    const recordNamespaceId = String(params.recordNamespaceId || adminNamespaceId).trim() || adminNamespaceId

    const namespaceEmailMap = await getNamespaceOwnerEmailMap(params.env.DB)
    const nextVideo = buildInboxVideoResponseForNamespace(
        params.env,
        params.record,
        recordNamespaceId,
        namespaceEmailMap.get(recordNamespaceId) || '',
    )
    const cachedSnapshot = await readSystemInboxSnapshot(params.bucket, adminNamespaceId).catch(() => null)
    const mergedVideos = dedupeSystemInboxVideos([
        nextVideo,
        ...Array.isArray(cachedSnapshot?.videos) ? cachedSnapshot!.videos : [],
    ], adminNamespaceId)
    await writeSystemInboxSnapshot(params.bucket, adminNamespaceId, mergedVideos)
}

async function removeSystemInboxSnapshotVideo(params: {
    adminNamespaceId: string
    bucket: R2Bucket
    videoId: string
    recordNamespaceId?: string
}): Promise<void> {
    const adminNamespaceId = String(params.adminNamespaceId || '').trim()
    const videoId = String(params.videoId || '').trim()
    if (!adminNamespaceId || !videoId) return

    const recordNamespaceId = String(params.recordNamespaceId || adminNamespaceId).trim() || adminNamespaceId
    const cachedSnapshot = await readSystemInboxSnapshot(params.bucket, adminNamespaceId).catch(() => null)
    const currentVideos = Array.isArray(cachedSnapshot?.videos) ? cachedSnapshot!.videos : []
    const nextVideos = currentVideos.filter((video) => (
        String(video.id || '').trim() !== videoId
        || String(video.namespace_id || '').trim() !== recordNamespaceId
    ))
    await writeSystemInboxSnapshot(params.bucket, adminNamespaceId, nextVideos)
}

async function mirrorInboxRecordIntoPrimaryAdminSnapshot(params: {
    env: Env
    sourceNamespaceId: string
    record: InboxVideoRecord
}): Promise<void> {
    const adminNamespaceId = await resolvePrimaryAdminNamespaceId(params.env.DB).catch(() => '')
    const sourceNamespaceId = String(params.sourceNamespaceId || '').trim()
    if (!adminNamespaceId || !sourceNamespaceId) return
    const adminBucket = new BotBucket(params.env.BUCKET, adminNamespaceId) as unknown as R2Bucket
    await upsertSystemInboxSnapshotVideo({
        env: params.env,
        adminNamespaceId,
        bucket: adminBucket,
        record: params.record,
        recordNamespaceId: sourceNamespaceId,
    })
}

async function removeInboxRecordFromPrimaryAdminSnapshot(params: {
    env: Env
    sourceNamespaceId: string
    videoId: string
}): Promise<void> {
    const adminNamespaceId = await resolvePrimaryAdminNamespaceId(params.env.DB).catch(() => '')
    const sourceNamespaceId = String(params.sourceNamespaceId || '').trim()
    const videoId = String(params.videoId || '').trim()
    if (!adminNamespaceId || !sourceNamespaceId || !videoId) return
    const adminBucket = new BotBucket(params.env.BUCKET, adminNamespaceId) as unknown as R2Bucket
    await removeSystemInboxSnapshotVideo({
        adminNamespaceId,
        bucket: adminBucket,
        videoId,
        recordNamespaceId: sourceNamespaceId,
    })
}

async function listNamespaceOriginalArchiveVideos(params: {
    env: Env
    bucket: R2Bucket
    namespaceId: string
}): Promise<Array<Record<string, unknown>>> {
    const normalizedNamespaceId = String(params.namespaceId || '').trim()
    if (!normalizedNamespaceId) return []

    const inboxRecords = await listInboxVideoRecords(params.bucket)

    const [namespaceStates, originalAssetMap] = await Promise.all([
        listNamespaceVideoStates(params.env.DB, normalizedNamespaceId),
        listNamespaceOriginalAssetMap(params.env, params.bucket, normalizedNamespaceId),
    ])

    const stateByVideoId = new Map(
        namespaceStates
            .map((row) => [String(row.video_id || '').trim(), row] as const)
            .filter(([videoId]) => !!videoId)
    )
    const merged = new Map<string, Record<string, unknown>>()
    const assetEntries = Array.from(originalAssetMap.entries())
    const metaEntries = await Promise.all(assetEntries.map(async ([id, asset]) => {
        const metaObj = await params.bucket.get(`videos/${id}.json`).catch(() => null)
        const meta = metaObj ? await metaObj.json().catch(() => ({} as Record<string, unknown>)) as Record<string, unknown> : {}
        return { id, asset, meta }
    }))
    const metaById = new Map(metaEntries.map((entry) => [entry.id, entry.meta]))

    for (const record of inboxRecords) {
        const asset = originalAssetMap.get(record.id)
        const meta = metaById.get(record.id) || {}
        const originalUrl = asset?.originalUrl || String(meta.originalUrl || meta.original_url || '').trim() || record.videoUrl
        merged.set(record.id, toInboxVideoResponse(record, {
            namespaceId: normalizedNamespaceId,
            previewUrl: originalUrl,
            thumbnailUrl: asset?.previewUrl || String(meta.originalThumbnailUrl || meta.original_thumbnail_url || '').trim(),
            originalUrl,
            canStartProcessing: true,
            canDelete: true,
        }))
        const current = merged.get(record.id)
        if (current) {
            const fallbackThumbnailUrl = buildWorkerGalleryFrameUrl(
                String(params.env.WORKER_URL || '').trim(),
                normalizedNamespaceId,
                record.id,
                {
                    seed: `${normalizedNamespaceId}:${record.id}:original`,
                    format: 'jpg',
                    width: 540,
                    height: 960,
                },
            )
            if (fallbackThumbnailUrl) current.fallbackThumbnailUrl = fallbackThumbnailUrl
        }
    }

    for (const { id, asset, meta } of metaEntries) {
        if (merged.has(id)) continue

        const row = stateByVideoId.get(id)
        const hasMeaningfulMeta = !!(
            String(meta.createdAt || meta.updatedAt || meta.title || meta.originalUrl || meta.original_url || meta.publicUrl || meta.thumbnailUrl || meta.originalThumbnailUrl || meta.original_thumbnail_url || meta.script || '').trim()
            || normalizeMetaShopeeLink(meta)
            || normalizeMetaLazadaLink(meta)
            || normalizeManualCaption(meta.manualCaption || meta.caption || '')
        )
        if (!row && !asset.hasProcessedVideo && !hasMeaningfulMeta) continue

        const shopeeLink = String(row?.shopee_link || normalizeMetaShopeeLink(meta) || '').trim()
        const lazadaLink = String(row?.lazada_link || normalizeMetaLazadaLink(meta) || '').trim()
        const createdAt = String(meta.createdAt || asset.originalUploadedAt || asset.processedUploadedAt || new Date().toISOString()).trim()
        const updatedAt = String(meta.updatedAt || asset.processedUploadedAt || asset.originalUploadedAt || createdAt).trim()
        const title = String(meta.title || '').trim()
        const sourceLabel = title || 'Original video'

        merged.set(id, {
            id,
            videoUrl: asset.originalUrl,
            previewUrl: asset.originalUrl,
            originalUrl: asset.originalUrl || String(meta.originalUrl || meta.original_url || '').trim(),
            thumbnailUrl: asset.previewUrl || String(meta.originalThumbnailUrl || meta.original_thumbnail_url || '').trim(),
            fallbackThumbnailUrl: buildWorkerGalleryFrameUrl(
                String(params.env.WORKER_URL || '').trim(),
                normalizedNamespaceId,
                id,
                {
                    seed: `${normalizedNamespaceId}:${id}:original`,
                    format: 'jpg',
                    width: 540,
                    height: 960,
                },
            ),
            createdAt,
            updatedAt,
            status: shopeeLink && lazadaLink ? 'ready' : 'awaiting_links',
            sourceType: 'telegram_video',
            sourceLabel,
            manualCaption: normalizeManualCaption(meta.manualCaption || meta.caption || ''),
            hasManualCaption: !!normalizeManualCaption(meta.manualCaption || meta.caption || ''),
            shopeeLink,
            lazadaLink,
            hasShopeeLink: !!shopeeLink,
            hasLazadaLink: !!lazadaLink,
            readyToProcess: false,
            canStartProcessing: false,
            canDelete: true,
            namespace_id: normalizedNamespaceId,
        })
    }

    return dedupeInboxArchiveVideos(Array.from(merged.values())).map((video) => {
        const { originalUrl: _originalUrl, ...rest } = video
        return rest
    })
}

async function backfillNamespaceInboxOriginalAssets(params: {
    env: Env
    bucket: R2Bucket
    namespaceId: string
}): Promise<void> {
    const normalizedNamespaceId = String(params.namespaceId || '').trim()
    if (!normalizedNamespaceId) return

    const [inboxRecords, assetMap] = await Promise.all([
        listInboxVideoRecords(params.bucket),
        listNamespaceOriginalAssetMap(params.env, params.bucket, normalizedNamespaceId).catch(() => new Map<string, NamespaceOriginalAsset>()),
    ])

    const candidates: InboxVideoRecord[] = []
    for (const record of inboxRecords) {
        if (candidates.length >= 6) break
        const asset = assetMap.get(record.id)
        const thumbHead = await params.bucket.head(getOriginalThumbnailAssetKey(record.id)).catch(() => null)
        const needsOriginal = !String(asset?.originalObjectKey || '').trim()
        const needsThumbnail = !thumbHead
        if (!needsOriginal && !needsThumbnail) continue
        if (record.sourceType !== 'xhs_url' && record.sourceType !== 'telegram_video' && record.sourceType !== 'line_video') continue
        candidates.push(record)
    }

    for (const record of candidates) {
        try {
            const asset = assetMap.get(record.id)
            const thumbHead = await params.bucket.head(getOriginalThumbnailAssetKey(record.id)).catch(() => null)
            const hasOriginal = !!String(asset?.originalObjectKey || '').trim()
            if (!hasOriginal) {
                await materializeOriginalVideoAsset({
                    env: params.env,
                    bucket: params.bucket,
                    namespaceId: normalizedNamespaceId,
                    videoId: record.id,
                    sourceType: record.sourceType,
                    sourceUrl: record.videoUrl,
                })
            } else if (!thumbHead) {
                await backfillOriginalThumbnail(params.env, normalizedNamespaceId, record.id)
            }
        } catch (error) {
            console.log(`[INBOX-BACKFILL] skip video=${record.id}: ${error instanceof Error ? error.message : String(error)}`)
        }
    }
}

async function hasActiveProcessingJob(bucket: R2Bucket, namespaceId = ''): Promise<boolean> {
    const normalizedNamespaceId = String(namespaceId || '').trim()
    const processingList = await bucket.list({ prefix: '_processing/' })
    // Keep the hot-path active check bounded. A full stale sweep can exceed the
    // Worker subrequest limit on large namespaces and then fail-safe blocks the
    // dispatcher forever. Active jobs are recent, so scan only the newest small
    // window and mark stale entries opportunistically.
    const candidates = processingList.objects
        .slice()
        .sort((a, b) => b.uploaded.getTime() - a.uploaded.getTime())
        .slice(0, 24)
    for (const obj of candidates) {
        const file = await bucket.get(obj.key)
        if (!file) continue
        const data = await file.json().catch(() => ({} as Record<string, unknown>)) as Record<string, unknown>
        if (normalizedNamespaceId) {
            const jobNamespace = String(data.namespace_id || data.namespaceId || data.botId || data.bot_id || '').trim()
            if (jobNamespace && jobNamespace !== normalizedNamespaceId) continue
        }
        const status = String(data.status || '').trim().toLowerCase()
        if (!status || status === 'failed' || status === 'processed' || status === 'cancelled' || status === 'awaiting_links') continue
        if (isProcessingJobStale(data, obj.uploaded)) {
            await markProcessingJobStale(bucket, obj.key, data, obj.uploaded).catch((error) => {
                console.error(`[PROCESSING-STALE] bounded active check failed to mark ${obj.key}: ${error instanceof Error ? error.message : String(error)}`)
            })
            continue
        }
        return true
    }
    return false
}

// True when the namespace already has work in flight: an active `_processing/` job OR any
// durable `_queue/` entry still waiting to start. Used by the AI-clip process handoff to gate
// the one-at-a-time rule — when this is true, the source-library backlog is deferred and NOTHING
// new is enqueued, so an accidental "process all" can never rebuild the long queue again.
async function namespaceHasInFlightProcessingJob(bucket: R2Bucket, namespaceId: string): Promise<boolean> {
    if (await hasActiveProcessingJob(bucket, namespaceId).catch(() => true)) return true
    const queued = await bucket.list({ prefix: '_queue/' }).catch(() => null)
    return !!(queued && Array.isArray(queued.objects) && queued.objects.length > 0)
}

async function getProcessingJobStatus(bucket: R2Bucket, id: string): Promise<string> {
    const normalizedId = String(id || '').trim()
    if (!normalizedId) return ''
    const processingObj = await bucket.get(`_processing/${normalizedId}.json`).catch(() => null)
    if (processingObj) {
        const data = await processingObj.json().catch(() => ({} as Record<string, unknown>)) as Record<string, unknown>
        const status = String(data.status || '').trim().toLowerCase()
        if (status) return status
        return 'processing'
    }
    const queueObj = await bucket.get(`_queue/${normalizedId}.json`).catch(() => null)
    if (queueObj) return 'queued'
    return ''
}

// Returns the full _processing/{id}.json record so callers can inspect the
// failure timestamp + error message for cooldown / "ประมวลผลไม่ผ่าน" UI.
async function getProcessingJobRecord(bucket: R2Bucket, id: string): Promise<Record<string, unknown> | null> {
    const normalizedId = String(id || '').trim()
    if (!normalizedId) return null
    const obj = await bucket.get(`_processing/${normalizedId}.json`).catch(() => null)
    if (!obj) return null
    return await obj.json().catch(() => null) as Record<string, unknown> | null
}

async function writeProcessingJobFailure(bucket: R2Bucket, params: {
    id: string
    chatId?: number
    videoUrl?: string
    shopeeLink?: string
    lazadaLink?: string
    manualCaption?: string
    error: string
    errorCategory: string
    errorDetails?: Record<string, unknown> | string
}): Promise<void> {
    const id = String(params.id || '').trim()
    if (!id) return
    const nowIso = new Date().toISOString()
    const existing = await getProcessingJobRecord(bucket, id).catch(() => null) || {}
    const payload = {
        ...existing,
        id,
        chatId: typeof params.chatId === 'number' ? params.chatId : Number(existing.chatId || 0),
        videoUrl: String(params.videoUrl || existing.videoUrl || '').trim(),
        shopeeLink: String(params.shopeeLink || existing.shopeeLink || '').trim(),
        lazadaLink: String(params.lazadaLink || existing.lazadaLink || '').trim(),
        manualCaption: String(params.manualCaption || existing.manualCaption || ''),
        status: 'failed',
        error: String(params.error || '').trim().slice(0, 500),
        errorCategory: String(params.errorCategory || '').trim().slice(0, 60),
        errorDetails: params.errorDetails && typeof params.errorDetails === 'object'
            ? params.errorDetails
            : params.errorDetails
                ? String(params.errorDetails).slice(0, 500)
                : undefined,
        failedAt: nowIso,
        updatedAt: nowIso,
        createdAt: String(existing.createdAt || nowIso),
    }
    await bucket.put(`_processing/${id}.json`, JSON.stringify(payload), {
        httpMetadata: { contentType: 'application/json' },
    }).catch(() => { })
    // Mirror into `_processing_history/` so the UI's history view shows this
    // failure immediately, regardless of the active-list cap. Best-effort:
    // history is a denormalised mirror, and a write failure here must never
    // hide the primary `_processing/` failure record from reprocess/UI logic.
    await putProcessingHistoryRecord(bucket, id, payload).catch((error) => {
        console.warn(`[PROCESSING-FAILURE] history mirror failed for ${id}: ${error instanceof Error ? error.message : String(error)}`)
    })
}

async function getGalleryIndexProcessedAt(db: D1Database, namespaceId: string, videoId: string): Promise<string> {
    const normalizedNamespaceId = String(namespaceId || '').trim()
    const normalizedVideoId = String(videoId || '').trim()
    if (!normalizedNamespaceId || !normalizedVideoId) return ''
    await ensureGalleryIndexTable(db).catch(() => { })
    const row = await db.prepare(
        `SELECT processed_at
         FROM gallery_index
         WHERE namespace_id = ? AND video_id = ?
         LIMIT 1`
    ).bind(normalizedNamespaceId, normalizedVideoId).first().catch(() => null) as { processed_at?: string } | null
    return String(row?.processed_at || '').trim()
}

async function recordInboxLinkSubmissionIfNeeded(params: {
    db: D1Database
    bucket: R2Bucket
    namespaceId: string
    item: InboxVideoRecord
}): Promise<InboxVideoRecord> {
    if (
        params.item.status !== 'ready'
        || String(params.item.linkRecordedAt || '').trim()
        || Number(params.item.chatId || 0) <= 0
    ) return params.item

    let recorded = false
    await recordLinkSubmission({
        db: params.db,
        namespaceId: params.namespaceId,
        telegramId: String(params.item.chatId),
        videoId: params.item.id,
        shopeeLink: String(params.item.shopeeLink || '').trim(),
    }).then(() => {
        recorded = true
    }).catch((e) => {
        console.error(`[DASHBOARD] failed to record inbox link submission: ${e instanceof Error ? e.message : String(e)}`)
    })
    if (!recorded) return params.item

    const nextRecord = await putInboxVideoRecord(params.bucket, {
        ...params.item,
        linkRecordedAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
    })
    return nextRecord
}

async function copyBucketObjectIfMissing(params: {
    sourceBucket: R2Bucket
    targetBucket: R2Bucket
    sourceKey: string
    targetKey: string
    fallbackContentType?: string
    replaceIfSizeDiffers?: boolean
}): Promise<boolean> {
    const sourceKey = String(params.sourceKey || '').trim()
    const targetKey = String(params.targetKey || '').trim()
    if (!sourceKey || !targetKey) return false

    const sourceHead = await params.sourceBucket.head(sourceKey).catch(() => null)
    if (!sourceHead) return false

    const existing = await params.targetBucket.head(targetKey).catch(() => null)
    const shouldReplaceExisting = !!existing && (
        isLikelyInvalidStoredVideoObject(existing)
        || (
            params.replaceIfSizeDiffers === true
            && Number(existing.size || 0) !== Number(sourceHead.size || 0)
        )
    )
    if (existing && !shouldReplaceExisting) return true

    const obj = await params.sourceBucket.get(sourceKey).catch(() => null)
    if (!obj || !obj.body) return false

    const contentType = String(
        obj.httpMetadata?.contentType
        || sourceHead.httpMetadata?.contentType
        || params.fallbackContentType
        || ''
    ).trim()
    await params.targetBucket.put(targetKey, obj.body, contentType
        ? { httpMetadata: { contentType } }
        : undefined
    )
    return true
}

async function resolvePrimaryAdminNamespaceId(db: D1Database): Promise<string> {
    const row = await db.prepare(
        `SELECT sa.email, en.namespace_id
         FROM system_admins sa
         JOIN email_namespaces en ON en.email = sa.email
         LIMIT 1`
    ).first() as { namespace_id?: string } | null
    return String(row?.namespace_id || '').trim()
}

async function syncImportedOriginalIntoNamespace(params: {
    env: Env
    targetNamespaceId: string
    targetBucket: R2Bucket
    sourceNamespaceId: string
    sourceVideo: Record<string, unknown>
    sourceBucket?: R2Bucket
}): Promise<InboxVideoRecord | null> {
    const targetNamespaceId = String(params.targetNamespaceId || '').trim()
    const sourceNamespaceId = String(params.sourceNamespaceId || '').trim()
    const videoId = String(params.sourceVideo.id || '').trim()
    if (!targetNamespaceId || !sourceNamespaceId || !videoId || targetNamespaceId === sourceNamespaceId) return null

    const sourceBucket = params.sourceBucket || (new BotBucket(params.env.BUCKET, sourceNamespaceId) as unknown as R2Bucket)
    const sourceOriginalKey = await resolveGalleryAssetKey(sourceBucket, videoId, 'original').catch(() => '')
    if (!sourceOriginalKey) return null
    const sourceOriginalHead = await sourceBucket.head(sourceOriginalKey).catch(() => null)
    if (!sourceOriginalHead) return null

    const existingMetaObj = await params.targetBucket.get(`videos/${videoId}.json`).catch(() => null)
    if (existingMetaObj) {
        const existingMeta = await existingMetaObj.json().catch(() => null) as Record<string, unknown> | null
        const targetPublicHead = await params.targetBucket.head(`videos/${videoId}.mp4`).catch(() => null)
        if (
            existingMeta
            && isImportedVideoMetaPointingAtSourceNamespace({
                meta: existingMeta,
                targetNamespaceId,
                sourceNamespaceId,
            })
            && !targetPublicHead
        ) {
            await clearNamespaceProcessedArtifacts(params.targetBucket, videoId)
        }
    }

    const targetOriginalKey = getPrimaryOriginalVideoAssetKey(videoId)
    await copyBucketObjectIfMissing({
        sourceBucket,
        targetBucket: params.targetBucket,
        sourceKey: sourceOriginalKey,
        targetKey: targetOriginalKey,
        fallbackContentType: sourceOriginalHead.httpMetadata?.contentType || 'video/mp4',
        replaceIfSizeDiffers: true,
    })

    const existing = await getInboxVideoRecord(params.targetBucket, videoId).catch(() => null)
    const sourceTypeRaw = String(params.sourceVideo.sourceType || params.sourceVideo.source_type || '').trim().toLowerCase()
    const sourceType: InboxVideoSourceType = sourceTypeRaw === 'xhs_url'
        ? 'xhs_url'
        : sourceTypeRaw === 'telegram_video'
            ? 'telegram_video'
            : 'line_video'
    const sourceLabelBase = String(
        params.sourceVideo.sourceLabel ||
        params.sourceVideo.source_label ||
        params.sourceVideo.title ||
        ''
    ).trim()
    const importedLabel = (sourceLabelBase
        ? `${sourceLabelBase} • imported from ${sourceNamespaceId}`
        : `imported from ${sourceNamespaceId}`
    ).slice(0, 500)
    const sourceState = await params.env.DB.prepare(
        `SELECT shopee_link, lazada_link, shopee_original_link, lazada_original_link
         FROM namespace_video_state
         WHERE namespace_id = ? AND video_id = ?
         LIMIT 1`
    ).bind(sourceNamespaceId, videoId).first().catch(() => null) as {
        shopee_link?: string
        lazada_link?: string
        shopee_original_link?: string
        lazada_original_link?: string
    } | null
    const sourceGallery = await params.env.DB.prepare(
        `SELECT shopee_link, lazada_link, shopee_original_link, lazada_original_link
         FROM gallery_index
         WHERE namespace_id = ? AND video_id = ?
         LIMIT 1`
    ).bind(sourceNamespaceId, videoId).first().catch(() => null) as {
        shopee_link?: string
        lazada_link?: string
        shopee_original_link?: string
        lazada_original_link?: string
    } | null
    const shopeeLink = getVideoSourceShopeeLink(params.sourceVideo)
        || String(sourceState?.shopee_link || sourceState?.shopee_original_link || '').trim()
        || String(sourceGallery?.shopee_link || sourceGallery?.shopee_original_link || '').trim()
    const lazadaLink = getVideoSourceLazadaLink(params.sourceVideo)
        || String(sourceState?.lazada_link || sourceState?.lazada_original_link || '').trim()
        || String(sourceGallery?.lazada_link || sourceGallery?.lazada_original_link || '').trim()
    const sourceShopeeOriginalLink = pickFirstShopeeUrl(String(
        params.sourceVideo.shopeeOriginalLink ||
        params.sourceVideo.shopee_original_link ||
        params.sourceVideo.shopeeSourceLink ||
        params.sourceVideo.shopee_source_link ||
        ''
    )) || ''
    const sourceLazadaOriginalLink = pickFirstLazadaUrl(String(
        params.sourceVideo.lazadaOriginalLink ||
        params.sourceVideo.lazada_original_link ||
        params.sourceVideo.lazadaSourceLink ||
        params.sourceVideo.lazada_source_link ||
        ''
    )) || ''
    const shopeeOriginalLink = String(
        sourceShopeeOriginalLink
        || sourceState?.shopee_original_link
        || sourceGallery?.shopee_original_link
        || shopeeLink
        || ''
    ).trim()
    const lazadaOriginalLink = String(
        sourceLazadaOriginalLink
        || sourceState?.lazada_original_link
        || sourceGallery?.lazada_original_link
        || lazadaLink
        || ''
    ).trim()
    const sourceManualCaption = normalizeManualCaption(params.sourceVideo.manualCaption || params.sourceVideo.caption || '')
    const manualCaption = existing
        ? normalizeManualCaption(existing.manualCaption || '')
        : sourceManualCaption
    const updatedAt = new Date().toISOString()
    const createdAt = String(existing?.createdAt || '').trim() || updatedAt

    const nextRecord = await putInboxVideoRecord(params.targetBucket, {
        id: videoId,
        videoUrl: getVideoOriginalUrlForNamespace(params.env.R2_PUBLIC_URL, targetNamespaceId, videoId),
        chatId: Number(existing?.chatId || 0),
        createdAt,
        updatedAt,
        sourceType,
        sourceLabel: importedLabel,
        shopeeLink,
        lazadaLink,
        shopeeOriginalLink,
        lazadaOriginalLink,
        linkRecordedAt: String(existing?.linkRecordedAt || createdAt).trim() || createdAt,
        manualCaption: manualCaption || existing?.manualCaption || '',
        captionProvidedAt: manualCaption
            ? (String(existing?.captionProvidedAt || '').trim() || updatedAt)
            : String(existing?.captionProvidedAt || '').trim(),
    })
    await upsertSystemInboxSnapshotVideo({
        env: params.env,
        adminNamespaceId: targetNamespaceId,
        bucket: params.targetBucket,
        record: nextRecord,
    }).catch(() => { })

    await ensureImportedVideosTable(params.env.DB)
    await params.env.DB.prepare(
        `INSERT INTO imported_videos (namespace_id, video_id, source_namespace_id, imported_at)
         VALUES (?, ?, ?, ?)
         ON CONFLICT(namespace_id, video_id) DO UPDATE SET
            source_namespace_id = excluded.source_namespace_id,
            imported_at = excluded.imported_at`
    ).bind(targetNamespaceId, videoId, sourceNamespaceId, updatedAt).run().catch(() => { })

    await upsertNamespaceVideoState(params.env.DB, targetNamespaceId, videoId, {
        shopee_link: shopeeLink,
        lazada_link: lazadaLink,
        shopee_original_link: shopeeOriginalLink,
        lazada_original_link: lazadaOriginalLink,
    }).catch(() => { })

    await backfillOriginalThumbnail(params.env, targetNamespaceId, videoId).catch(() => ({ generated: false, thumbnailUrl: '' }))

    return nextRecord
}

async function syncWaitingVideoIntoPrimaryAdminNamespace(params: {
    env: Env
    sourceNamespaceId: string
    sourceBucket: R2Bucket
    waitingState: LineWaitingVideoState
}): Promise<InboxVideoRecord | null> {
    const waitingState = normalizeLineWaitingVideoState(params.waitingState)
    if (!waitingState || !waitingState.shopeeLink || !waitingState.lazadaLink) return null

    const adminNamespaceId = await resolvePrimaryAdminNamespaceId(params.env.DB).catch(() => '')
    const sourceNamespaceId = String(params.sourceNamespaceId || '').trim()
    if (!adminNamespaceId || !sourceNamespaceId || adminNamespaceId === sourceNamespaceId) return null

    const adminBucket = new BotBucket(params.env.BUCKET, adminNamespaceId) as unknown as R2Bucket
    return syncImportedOriginalIntoNamespace({
        env: params.env,
        targetNamespaceId: adminNamespaceId,
        targetBucket: adminBucket,
        sourceNamespaceId,
        sourceBucket: params.sourceBucket,
        sourceVideo: {
            id: waitingState.id,
            videoUrl: waitingState.videoUrl,
            createdAt: waitingState.createdAt,
            sourceType: waitingState.sourceType || 'line_video',
            sourceLabel: waitingState.sourceLabel || 'LINE video',
            shopeeLink: waitingState.shopeeLink,
            lazadaLink: waitingState.lazadaLink,
            manualCaption: '',
        },
    }).catch(() => null)
}

type ManagedLinkFailureTrace = {
    reason?: string
    category?: string
    details?: Record<string, unknown>
}

async function prepareInboxVideoForManagedLinks(params: {
    env: Env
    bucket: R2Bucket
    namespaceId: string
    item: InboxVideoRecord
    logPrefix: string
    failureTrace?: ManagedLinkFailureTrace
}): Promise<InboxVideoRecord | null> {
    const recordFailure = (reason: string, category: string, details?: Record<string, unknown>) => {
        if (params.failureTrace) {
            params.failureTrace.reason = reason
            params.failureTrace.category = category
            if (details) params.failureTrace.details = details
        }
    }
    const namespaceId = String(params.namespaceId || '').trim()
    const item = normalizeInboxVideoRecord(params.item)
    if (!namespaceId || !item || item.status !== 'ready') {
        recordFailure('inbox record invalid or not ready', 'invalid_inbox_record')
        return null
    }

    const [adminManaged, shortlinkProcessingRequired, primaryAdminNamespaceId] = await Promise.all([
        isNamespaceShortlinkAdminManaged(params.env.DB, namespaceId).catch(() => false),
        isNamespaceAffiliateShortlinkProcessingRequired(params.env.DB, namespaceId).catch(() => false),
        resolvePrimaryAdminNamespaceId(params.env.DB).catch(() => ''),
    ])
    const forceManagedShortlink = !!primaryAdminNamespaceId && primaryAdminNamespaceId === namespaceId
    if (adminManaged && !shortlinkProcessingRequired) {
        console.log(`[${params.logPrefix}] Processing shortlink is disabled for ${namespaceId} — processing video with submitted links as-is`)
        return item
    }
    if (!shortlinkProcessingRequired) return item

    const sourceShopeeCandidate = sanitizeAffiliateTrackingLink(pickFirstShopeeUrl(String(item.shopeeOriginalLink || item.shopeeLink || '')) || '')
    const sourceShopeeError = getShopeeLinkValidationError(sourceShopeeCandidate)
    const sourceShopeeLink = sourceShopeeError ? '' : sourceShopeeCandidate
    const sourceLazadaLink = sanitizeAffiliateTrackingLink(pickFirstLazadaUrl(String(item.lazadaOriginalLink || item.lazadaLink || '')) || '')
    if (!sourceShopeeLink || !sourceLazadaLink) {
        recordFailure(
            sourceShopeeError === 'invalid_shopee_homepage_link'
                ? 'Shopee link points to the homepage; submit a product URL or affiliate short link'
                : !sourceShopeeLink && !sourceLazadaLink
                ? 'Missing both Shopee and Lazada source links'
                : !sourceShopeeLink
                    ? 'Missing Shopee source link'
                    : 'Missing Lazada source link',
            sourceShopeeError || 'missing_source_link',
            { shopee: !!sourceShopeeLink, lazada: !!sourceLazadaLink, shopee_error: sourceShopeeError || null }
        )
        return null
    }

    const [expectedUtmId, expectedLazadaMemberId] = await Promise.all([
        resolveNamespaceShopeeShortlinkExpectedUtmId(params.env.DB, namespaceId).catch(() => ''),
        resolveNamespaceLazadaExpectedMemberId(params.env.DB, namespaceId).catch(() => ''),
    ])
    const normalizedExpectedUtmId = normalizeShortlinkExpectedUtmId(expectedUtmId)

    const nextConvertedAt = new Date().toISOString()
    const shopeeTrace: {
        utmSource?: string | null
        status?: 'disabled' | 'shortened' | 'fallback'
        error?: string | null
    } = {}
    let nextShopeeLink = await shortenShopeeLinkForNamespace({
        env: params.env,
        namespaceId,
        shopeeLink: sourceShopeeLink,
        logPrefix: `${params.logPrefix} SHOPEE`,
        allowFallbackWhenEnforced: true,
        trace: shopeeTrace,
    })
    const shopeeReady = (
        !!nextShopeeLink
        && nextShopeeLink !== sourceShopeeLink
        && shopeeTrace.status === 'shortened'
        && (
            !normalizedExpectedUtmId
            || normalizeShortlinkExpectedUtmId(String(shopeeTrace.utmSource || '')) === normalizedExpectedUtmId
        )
    )
    if (!shopeeReady) {
        const resolvedShopeeTrackingLink = await resolveAffiliateTrackingLink(sourceShopeeLink, `${params.logPrefix} SHOPEE_RESOLVE`).catch(() => sourceShopeeLink)
        // extractShopeeAffiliateIdFromLink accepts both utm_source=an_<id> (legacy)
        // and mmp_pid=an_<id> (newer Shopee affiliate bridge output). Strict
        // fail-closed semantics are preserved: an unrelated or missing id still
        // returns '' and falls through to the not-ready branch below.
        const resolvedShopeeAffiliateId = extractShopeeAffiliateIdFromLink(resolvedShopeeTrackingLink)
        const inferredShopeeReady = !!resolvedShopeeTrackingLink
            && !!resolvedShopeeAffiliateId
            && (!normalizedExpectedUtmId || resolvedShopeeAffiliateId === normalizedExpectedUtmId)
        if (inferredShopeeReady) {
            nextShopeeLink = sourceShopeeLink
        } else if (isManagedShortlinkTransientFailure(shopeeTrace.error)) {
            const reason = `Shopee shortlink bridge failed transiently; blocking processing instead of posting original link for ${item.id}`
            console.warn(`[${params.logPrefix}] ${reason}`)
            recordFailure(reason, 'shopee_shortlink_transient_failure', { error: shopeeTrace.error || null })
            return null
        } else {
            const traceErr = sanitizeProcessingError(shopeeTrace.error)
            const reason = normalizedExpectedUtmId
                ? `Shopee affiliate id ไม่ตรง (expected ${normalizedExpectedUtmId}, actual ${resolvedShopeeAffiliateId || '-'})`
                : 'Shopee ย่อลิงก์ไม่สำเร็จ ตรวจสอบลิงก์ Shopee ที่ส่งมาให้ครบและถูกต้อง'
            console.log(`[${params.logPrefix}] Admin managed Shopee shortlink not ready for ${item.id}: ${reason}${traceErr ? ` | trace=${traceErr}` : ''}`)
            recordFailure(reason, 'shopee_shortlink_not_ready', {
                expected_utm_id: normalizedExpectedUtmId || null,
                resolved_affiliate_id: resolvedShopeeAffiliateId || null,
                shortener_status: shopeeTrace.status || null,
                shortener_error: traceErr || null,
            })
            return null
        }
    }

    let lazadaTrace: {
        utmSource?: string | null
        memberId?: string | null
        status?: 'disabled' | 'shortened' | 'fallback'
        error?: string | null
    } = {}
    let nextLazadaLink = await shortenLazadaLinkForNamespace({
        env: params.env,
        namespaceId,
        lazadaLink: sourceLazadaLink,
        logPrefix: `${params.logPrefix} LAZADA`,
        forceShortlink: forceManagedShortlink,
        allowFallbackWhenEnforced: true,
        trace: lazadaTrace,
    })
    let normalizedMemberId = normalizeLazadaMemberId(String(lazadaTrace.memberId || ''))
    const lazadaReady = !!nextLazadaLink && (
        lazadaTrace.status === 'shortened'
        && isLikelyConvertedLazadaLink(nextLazadaLink)
        && (!forceManagedShortlink || nextLazadaLink !== sourceLazadaLink)
    )
    if (!lazadaReady) {
        const resolvedLazadaTrackingLink = await resolveAffiliateTrackingLink(sourceLazadaLink, `${params.logPrefix} LAZADA_RESOLVE`).catch(() => sourceLazadaLink)
        const resolvedLazadaMemberId = normalizeLazadaMemberId(extractLazadaMemberIdFromLink(resolvedLazadaTrackingLink))
        const inferredLazadaReady = !!resolvedLazadaTrackingLink
            && isLikelyConvertedLazadaLink(resolvedLazadaTrackingLink)
        if (inferredLazadaReady) {
            nextLazadaLink = sourceLazadaLink
            normalizedMemberId = resolvedLazadaMemberId
        } else if (isManagedShortlinkTransientFailure(lazadaTrace.error)) {
            console.warn(`[${params.logPrefix}] Lazada shortlink bridge failed transiently; continuing processing with original link for ${item.id}`)
            nextLazadaLink = sourceLazadaLink
            normalizedMemberId = resolvedLazadaMemberId
        } else {
            const traceErr = sanitizeProcessingError(lazadaTrace.error)
            const reason = expectedLazadaMemberId && normalizedMemberId && normalizedMemberId !== expectedLazadaMemberId
                ? `Lazada member id ไม่ตรง (expected ${expectedLazadaMemberId}, actual ${normalizedMemberId})`
                : !isLikelyConvertedLazadaLink(nextLazadaLink || sourceLazadaLink)
                    ? 'Lazada ย่อลิงก์ไม่สำเร็จ: ลิงก์ที่ได้กลับมายังไม่ใช่ short link ที่ใช้งานได้'
                    : 'Lazada ย่อลิงก์ไม่สำเร็จ ตรวจสอบลิงก์ Lazada ที่ส่งมาให้ครบและถูกต้อง'
            console.log(`[${params.logPrefix}] Admin managed Lazada shortlink not ready for ${item.id}; source=${sourceLazadaLink} short=${nextLazadaLink || '-'} status=${lazadaTrace.status || '-'} error=${traceErr || '-'} member_id=${normalizedMemberId || '-'} expected_member_id=${expectedLazadaMemberId || '-'}`)
            recordFailure(reason, 'lazada_shortlink_not_ready', {
                expected_member_id: expectedLazadaMemberId || null,
                resolved_member_id: normalizedMemberId || null,
                shortener_status: lazadaTrace.status || null,
                shortener_error: traceErr || null,
            })
            return null
        }
    }

    await upsertNamespaceVideoState(params.env.DB, namespaceId, item.id, {
        shopee_link: nextShopeeLink,
        lazada_link: nextLazadaLink,
        shopee_original_link: sourceShopeeLink,
        lazada_original_link: sourceLazadaLink,
        shopee_converted_at: nextConvertedAt,
        lazada_converted_at: nextConvertedAt,
        lazada_member_id: normalizedMemberId,
    })

    if (nextShopeeLink === item.shopeeLink && nextLazadaLink === item.lazadaLink) {
        return item
    }

    return putInboxVideoRecord(params.bucket, {
        ...item,
        shopeeLink: nextShopeeLink,
        lazadaLink: nextLazadaLink,
        shopeeOriginalLink: sourceShopeeLink,
        lazadaOriginalLink: sourceLazadaLink,
        updatedAt: new Date().toISOString(),
    })
}

async function startInboxVideoProcessing(params: {
    env: Env
    bucket: R2Bucket
    executionCtx: ExecutionContext
    botId: string
    item: InboxVideoRecord
    runInline?: boolean
}): Promise<{ status: 'queued' | 'processing'; id: string }> {
    const nowIso = new Date().toISOString()
    const item = normalizeInboxVideoRecord(params.item)
    if (!item || item.status !== 'ready') throw new Error('inbox_video_not_ready')

    await params.bucket.put(`_link_context/${item.id}.json`, JSON.stringify({
        id: item.id,
        videoUrl: item.videoUrl,
        shopeeLink: String(item.shopeeLink || '').trim(),
        lazadaLink: String(item.lazadaLink || '').trim(),
        shopeeOriginalLink: String(item.shopeeOriginalLink || item.shopeeLink || '').trim(),
        lazadaOriginalLink: String(item.lazadaOriginalLink || item.lazadaLink || '').trim(),
        manualCaption: normalizeManualCaption(item.manualCaption),
        captionProvidedAt: String(item.captionProvidedAt || '').trim(),
        chatId: item.chatId,
        createdAt: nowIso,
    }), {
        httpMetadata: { contentType: 'application/json' },
    })

    const queuedJobPayload = {
        id: item.id,
        videoUrl: item.videoUrl,
        shopeeLink: String(item.shopeeLink || '').trim(),
        lazadaLink: String(item.lazadaLink || '').trim(),
        manualCaption: normalizeManualCaption(item.manualCaption),
        chatId: item.chatId,
        createdAt: nowIso,
    }

    if (await hasActiveProcessingJob(params.bucket, params.botId)) {
        await params.bucket.put(`_queue/${item.id}.json`, JSON.stringify({
            ...queuedJobPayload,
            status: 'queued',
        }), {
            httpMetadata: { contentType: 'application/json' },
        })
        return { status: 'queued', id: item.id }
    }

    await params.bucket.put(`_processing/${item.id}.json`, JSON.stringify({
        id: item.id,
        videoUrl: item.videoUrl,
        shopeeLink: String(item.shopeeLink || '').trim(),
        lazadaLink: String(item.lazadaLink || '').trim(),
        manualCaption: normalizeManualCaption(item.manualCaption),
        chatId: item.chatId,
        createdAt: nowIso,
        status: 'processing',
        step: 0,
        stepName: '⏳ กำลังเชื่อมต่อเครื่องประมวลผล...',
    }), {
        httpMetadata: { contentType: 'application/json' },
    })
    const run = async () => {
        let pipelineSucceeded = false
        try {
            await runPipeline(
                params.env,
                item.videoUrl,
                item.chatId,
                0,
                item.id,
                params.botId,
                String(item.shopeeLink || '').trim(),
                String(item.lazadaLink || '').trim(),
            )
            pipelineSucceeded = true
        } finally {
            if (pipelineSucceeded) {
                const completedAt = new Date().toISOString()
                await putInboxVideoRecord(params.bucket, {
                    ...item,
                    processedAt: completedAt,
                    updatedAt: completedAt,
                }).catch((error) => {
                    console.error(`[INBOX-PROCESS-AUTOSTART] failed to mark inbox processed before dispatch ${params.botId}/${item.id}: ${error instanceof Error ? error.message : String(error)}`)
                })
            }
            await dispatchNextProcessingJobForNamespace(params.env, params.executionCtx, params.botId, { runInline: false, excludeVideoIds: [item.id] }).then((result) => {
                console.log(`[INBOX-PROCESS-AUTOSTART] ${params.botId}/${item.id}: started=${result.started ? 'yes' : 'no'} source=${result.source}${result.detail ? ` detail=${result.detail}` : ''}`)
            }).catch((error) => {
                console.error(`[INBOX-PROCESS-AUTOSTART] failed after ${params.botId}/${item.id}: ${error instanceof Error ? error.message : String(error)}`)
            })
        }
    }
    if (params.runInline) {
        await run()
    } else {
        params.executionCtx.waitUntil(run())
    }
    return { status: 'processing', id: item.id }
}

async function markInboxProcessingFailed(params: {
    bucket: R2Bucket
    item: InboxVideoRecord
    message: string
    stepName?: string
}): Promise<void> {
    const item = normalizeInboxVideoRecord(params.item)
    if (!item) return
    const nowIso = new Date().toISOString()
    await params.bucket.delete(`_queue/${item.id}.json`).catch(() => { })
    await params.bucket.put(`_processing/${item.id}.json`, JSON.stringify({
        id: item.id,
        videoUrl: item.videoUrl,
        shopeeLink: String(item.shopeeLink || '').trim(),
        lazadaLink: String(item.lazadaLink || '').trim(),
        manualCaption: normalizeManualCaption(item.manualCaption),
        chatId: item.chatId,
        createdAt: nowIso,
        status: 'failed',
        step: 0,
        stepName: String(params.stepName || '').trim() || '❌ ย่อลิงก์ไม่สำเร็จ',
        error: String(params.message || '').trim() || 'shortlink_failed',
    }), {
        httpMetadata: { contentType: 'application/json' },
    })
}

type InboxProcessingStartResult =
    | { outcome: 'started'; item: InboxVideoRecord; job: { status: 'queued' | 'processing'; id: string } }
    | { outcome: 'already_running'; item: InboxVideoRecord; status: InboxProcessingState; id: string }
    | { outcome: 'already_processed'; item: InboxVideoRecord; id: string }

async function ensureInboxVideoProcessingStarted(params: {
    env: Env
    bucket: R2Bucket
    executionCtx: ExecutionContext
    botId: string
    item: InboxVideoRecord
    skipIfAlreadyProcessed?: boolean
    runInline?: boolean
}): Promise<InboxProcessingStartResult> {
    const botId = String(params.botId || '').trim()
    if (!botId) throw new Error('missing_bot_id')

    const rawItem = normalizeInboxVideoRecord(params.item)
    if (!rawItem || rawItem.status !== 'ready') throw new Error('inbox_video_not_ready')

    // Admin originals must pass the configured managed shortlink flow before
    // entering the processing pipeline. Member namespaces keep their raw links.

    let item = await recordInboxLinkSubmissionIfNeeded({
        db: params.env.DB,
        bucket: params.bucket,
        namespaceId: botId,
        item: rawItem,
    })
    await syncInboxRecordLinksToNamespaceIndex({
        env: params.env,
        namespaceId: botId,
        item,
    }).catch((error) => {
        console.warn(`[INBOX-PROCESS] link sync failed for ${botId}/${item.id}: ${error instanceof Error ? error.message : String(error)}`)
        return false
    })

    const failureTrace: ManagedLinkFailureTrace = {}
    const preparedItem = await prepareInboxVideoForManagedLinks({
        env: params.env,
        bucket: params.bucket,
        namespaceId: botId,
        item,
        logPrefix: `INBOX-PROCESS ${botId}/${item.id}`,
        failureTrace,
    })
    if (!preparedItem) {
        const readableReason = String(failureTrace.reason || '').trim()
            || 'Shopee/Lazada shortlink for this workspace is not ready'
        await writeProcessingJobFailure(params.bucket, {
            id: item.id,
            chatId: item.chatId,
            videoUrl: item.videoUrl,
            shopeeLink: String(item.shopeeLink || '').trim(),
            lazadaLink: String(item.lazadaLink || '').trim(),
            manualCaption: normalizeManualCaption(item.manualCaption),
            error: readableReason,
            errorCategory: String(failureTrace.category || 'managed_shortlink_conversion_failed'),
            errorDetails: failureTrace.details,
        }).catch(() => { })
        throw new Error('managed_shortlink_conversion_failed')
    }
    item = preparedItem
    await syncInboxRecordLinksToNamespaceIndex({
        env: params.env,
        namespaceId: botId,
        item,
    }).catch((error) => {
        console.warn(`[INBOX-PROCESS] prepared link sync failed for ${botId}/${item.id}: ${error instanceof Error ? error.message : String(error)}`)
        return false
    })

    const processingStateMap = await getInboxProcessingStateMap(params.bucket)
    const currentProcessingState = processingStateMap.get(item.id) || 'idle'
    if (currentProcessingState !== 'idle') {
        return { outcome: 'already_running', item, status: currentProcessingState, id: item.id }
    }

    if (params.skipIfAlreadyProcessed) {
        const processedAt = await getGalleryIndexProcessedAt(params.env.DB, botId, item.id).catch(() => '')
        if (processedAt) {
            await putInboxVideoRecord(params.bucket, {
                ...item,
                processedAt,
                updatedAt: new Date().toISOString(),
            }).catch(() => { })
            return { outcome: 'already_processed', item, id: item.id }
        }
    }

    await ensureInboxAutoCoverSuggestion({
        env: params.env,
        bucket: params.bucket,
        namespaceId: botId,
        videoId: item.id,
    }).catch((error) => {
        console.log(`[AUTO-COVER] namespace=${botId} video=${item.id}: ${error instanceof Error ? error.message : String(error)}`)
    })

    const started = await startInboxVideoProcessing({
        env: params.env,
        bucket: params.bucket,
        executionCtx: params.executionCtx,
        botId,
        item,
        runInline: params.runInline,
    })

    await putInboxVideoRecord(params.bucket, {
        ...item,
        updatedAt: new Date().toISOString(),
    }).catch(() => { })

    const waitingKey = `_waiting_video/${item.chatId}.json`
    const waitingObj = await params.bucket.get(waitingKey)
    if (waitingObj) {
        const waiting = await waitingObj.json().catch(() => ({} as Record<string, unknown>)) as Record<string, unknown>
        if (String(waiting.id || '').trim() === item.id) {
            await params.bucket.delete(waitingKey).catch(() => { })
        }
    }

    return { outcome: 'started', item, job: started }
}

const PROCESSING_HISTORY_PREFIX = '_processing_history/'
const PROCESSING_STALE_TIMEOUT_MS = 30 * 60 * 1000
const PROCESSING_GEMINI_PREP_STALE_TIMEOUT_MS = 7 * 60 * 1000
const PROCESSING_PIPELINE_HANDOFF_STALE_TIMEOUT_MS = 3 * 60 * 1000
const PROCESSING_PIPELINE_HANDOFF_STALE_ERROR = 'pipeline_handoff_stale_timeout — งานค้างตอนเชื่อมต่อเครื่องประมวลผลเกิน 3 นาที ระบบข้ามไปทำวิดีโอถัดไปแล้ว'
const PROCESSING_GEMINI_RATE_LIMIT_PAUSE_MS = 15 * 60 * 1000
// Bound how much of `_processing/` we touch on each /api/processing load.
// Namespaces accumulate hundreds of old failed records that linger here even
// after they've been mirrored into `_processing_history/`. Reading every one
// per request was pushing /api/processing past the webapp's 20s budget. Active
// jobs are always the most recent uploads, so capping by upload time + small N
// keeps the active view truthful while skipping historical noise.
const PROCESSING_ACTIVE_LIST_MAX = 60
const PROCESSING_STALE_CHECK_MAX = 30
// Records uploaded longer ago than this haven't been written since creation —
// they're either already terminal (failed/processed and not re-touched) or
// they're well past every possible stale-timeout we currently use. A small
// safety multiplier on the longest configured timeout keeps the check honest.
const PROCESSING_STALE_CHECK_WINDOW_MS = PROCESSING_STALE_TIMEOUT_MS * 2
const PROCESSING_STALE_ERROR = 'processing_stale_timeout — งานประมวลผลค้างเกิน 30 นาที ระบบข้ามไปทำวิดีโอถัดไปแล้ว'
const PROCESSING_GEMINI_PREP_STALE_ERROR = 'gemini_preparation_stale_timeout — งานค้างที่ขั้น Gemini เกิน 7 นาที ระบบข้ามไปทำวิดีโอถัดไปแล้ว'

async function readProcessingListPrefix(
    bucket: R2Bucket,
    prefix: '_processing/' | '_queue/' | typeof PROCESSING_HISTORY_PREFIX,
    defaultStatus: 'processing' | 'queued' | 'processed',
    options: { maxObjects?: number } = {},
): Promise<Array<Record<string, unknown>>> {
    const list = await bucket.list({ prefix })
    const objects = typeof options.maxObjects === 'number' && options.maxObjects > 0
        ? list.objects
            .slice()
            .sort((a, b) => b.uploaded.getTime() - a.uploaded.getTime())
            .slice(0, Math.floor(options.maxObjects))
        : list.objects
    const tasks = await Promise.all(
        objects.map(async obj => {
            const data = await bucket.get(obj.key)
            if (!data) return null

            let json: Record<string, unknown> = {}
            try {
                json = await data.json() as Record<string, unknown>
            } catch {
                json = {}
            }

            const keyId = obj.key.startsWith(prefix)
                ? obj.key.slice(prefix.length).replace(/\.json$/i, '').trim()
                : obj.key.trim()
            const id = String(json.id || keyId || '').trim()
            if (!id) {
                await bucket.delete(obj.key).catch(() => { })
                return null
            }

            const createdAt = String(json.createdAt || json.startedAt || '').trim() || obj.uploaded.toISOString()
            const completedAt = String(json.completedAt || json.processedAt || '').trim()
            const updatedAt = String(json.updatedAt || completedAt || '').trim() || obj.uploaded.toISOString()
            const status = String(json.status || '').trim() || defaultStatus
            const error = sanitizeProcessingError(json.error || json.error_message || json.last_error)

            return {
                ...json,
                id,
                createdAt,
                updatedAt,
                completedAt: completedAt || undefined,
                status,
                error,
                stepName: normalizeProcessingStepName(json.stepName),
                historyKey: prefix === PROCESSING_HISTORY_PREFIX ? obj.key : undefined,
            }
        })
    )
    return tasks.filter(Boolean) as Array<Record<string, unknown>>
}

async function putProcessingHistoryRecord(
    bucket: R2Bucket,
    videoId: string,
    payload: Record<string, unknown>,
): Promise<void> {
    const id = String(videoId || payload.id || '').trim()
    if (!id) return
    const nowIso = new Date().toISOString()
    const record = {
        ...payload,
        id,
        createdAt: String(payload.createdAt || payload.startedAt || '').trim() || nowIso,
        updatedAt: String(payload.updatedAt || payload.completedAt || '').trim() || nowIso,
    }
    await bucket.put(`${PROCESSING_HISTORY_PREFIX}${id}.json`, JSON.stringify(record, null, 2), {
        httpMetadata: { contentType: 'application/json' },
    })
}

function buildProcessingRetryQueuedJob(
    failedJob: Record<string, unknown>,
    linkContext: Record<string, unknown> | null,
    decision: ProcessingRetryDecision,
): Record<string, unknown> | null {
    const id = String(failedJob.id || linkContext?.id || '').trim()
    const videoUrl = String(failedJob.videoUrl || linkContext?.videoUrl || '').trim()
    if (!id || !videoUrl) return null
    const chatIdRaw = Number(failedJob.chatId ?? linkContext?.chatId ?? 0)
    const retryHistory = Array.isArray(failedJob.retryHistory) ? failedJob.retryHistory.slice(-10) : []
    const nowIso = new Date().toISOString()
    return {
        id,
        videoUrl,
        shopeeLink: String(failedJob.shopeeLink || linkContext?.shopeeLink || '').trim(),
        lazadaLink: String(failedJob.lazadaLink || linkContext?.lazadaLink || '').trim(),
        manualCaption: normalizeManualCaption(failedJob.manualCaption || linkContext?.manualCaption || ''),
        chatId: Number.isFinite(chatIdRaw) && chatIdRaw >= 0 ? chatIdRaw : 0,
        createdAt: nowIso,
        status: 'queued',
        retryCount: decision.attempts + 1,
        retryNextAt: decision.nextRetryAt,
        retryHistory: [
            ...retryHistory,
            {
                at: nowIso,
                errorCategory: String(failedJob.errorCategory || '').trim(),
                error: sanitizeProcessingError(failedJob.error || failedJob.last_error || ''),
                decision: decision.reason,
            },
        ],
        autoRetry: true,
        autoRetryReason: decision.reason,
    }
}

async function requeueDueFailedProcessingJob(env: Env, botId: string): Promise<boolean> {
    const namespaceId = String(botId || '').trim()
    if (!namespaceId) return false
    const bucket = new BotBucket(env.BUCKET, namespaceId) as unknown as R2Bucket
    const list = await bucket.list({ prefix: '_processing/' }).catch(() => null)
    if (!list || list.objects.length === 0) return false

    const failedObjects = list.objects
        .slice()
        .sort((a, b) => a.uploaded.getTime() - b.uploaded.getTime())
        .slice(0, 120)

    for (const obj of failedObjects) {
        const dataObj = await bucket.get(obj.key).catch(() => null)
        if (!dataObj) continue
        const failedJob = await dataObj.json().catch(() => ({} as Record<string, unknown>)) as Record<string, unknown>
        const status = String(failedJob.status || '').trim().toLowerCase()
        if (status !== 'failed') continue
        const decision = decideProcessingRetry({
            status,
            errorCategory: failedJob.errorCategory,
            error: failedJob.error || failedJob.last_error,
            failedAt: failedJob.failedAt,
            updatedAt: failedJob.updatedAt || obj.uploaded.toISOString(),
            retryCount: failedJob.retryCount,
            retryHistory: failedJob.retryHistory,
            now: Date.now(),
        })
        if (decision.action === 'wait') continue
        if (decision.action === 'terminal') {
            if (decision.reason === 'max_attempts_exceeded' && String(failedJob.autoRetryTerminal || '') !== '1') {
                const terminal = {
                    ...failedJob,
                    status: 'failed',
                    autoRetryTerminal: '1',
                    autoRetryReason: decision.reason,
                    retryNextAt: decision.nextRetryAt,
                    updatedAt: new Date().toISOString(),
                }
                await bucket.put(obj.key, JSON.stringify(terminal, null, 2), { httpMetadata: { contentType: 'application/json' } }).catch(() => { })
                const id = String(failedJob['id'] || obj.key.replace(/^_processing\//, '').replace(/\.json$/i, '')).trim()
                await putProcessingHistoryRecord(bucket, id, terminal).catch(() => { })
            }
            continue
        }

        const id = String(failedJob.id || obj.key.replace(/^_processing\//, '').replace(/\.json$/i, '')).trim()
        const linkContextObj = id ? await bucket.get(`_link_context/${id}.json`).catch(() => null) : null
        const linkContext = linkContextObj
            ? await linkContextObj.json().catch(() => ({} as Record<string, unknown>)) as Record<string, unknown>
            : null
        const queuedJob = buildProcessingRetryQueuedJob({ ...failedJob, id }, linkContext, decision)
        if (!queuedJob) continue
        await putProcessingHistoryRecord(bucket, id, {
            ...failedJob,
            id,
            status: 'retrying',
            retryCount: decision.attempts + 1,
            retryQueuedAt: new Date().toISOString(),
            autoRetryReason: decision.reason,
        }).catch(() => { })
        await bucket.delete(obj.key).catch(() => { })
        await bucket.put(`_queue/${id}.json`, JSON.stringify(queuedJob, null, 2), {
            httpMetadata: { contentType: 'application/json' },
        })
        console.log(`[PROCESSING-RETRY] Requeued ${namespaceId}/${id} attempt=${decision.attempts + 1}/${decision.maxAttempts} reason=${decision.reason}`)
        return processNextInQueue(env, namespaceId).catch((error) => {
            console.error(`[PROCESSING-RETRY] dispatch failed for ${namespaceId}/${id}: ${error instanceof Error ? error.message : String(error)}`)
            return false
        })
    }

    return false
}

async function hasRecentNamespaceGeminiRateLimitFailure(env: Env, namespaceId: string): Promise<boolean> {
    const botId = String(namespaceId || '').trim()
    if (!botId) return false
    const bucket = new BotBucket(env.BUCKET, botId) as unknown as R2Bucket
    const list = await bucket.list({ prefix: '_processing/' }).catch(() => null)
    if (!list || list.objects.length === 0) return false
    for (const obj of list.objects.slice().sort((a, b) => b.uploaded.getTime() - a.uploaded.getTime()).slice(0, 120)) {
        const dataObj = await bucket.get(obj.key).catch(() => null)
        if (!dataObj) continue
        const data = await dataObj.json().catch(() => ({} as Record<string, unknown>)) as Record<string, unknown>
        if (String(data.status || '').trim().toLowerCase() !== 'failed') continue
        const combined = `${String(data.errorCategory || '')} ${String(data.error || data['last_error'] || '')}`.toLowerCase()
        if (!combined.includes('429') && !combined.includes('resource exhausted') && !combined.includes('quota')) continue
        const timestamp = String(data.failedAt || data.updatedAt || data.createdAt || '').trim()
        const parsed = timestamp ? Date.parse(timestamp) : NaN
        const fallbackMs = obj.uploaded instanceof Date ? obj.uploaded.getTime() : NaN
        const effectiveMs = Number.isFinite(parsed) && parsed > 0 ? parsed : fallbackMs
        if (Number.isFinite(effectiveMs) && effectiveMs > 0 && Date.now() - effectiveMs < PROCESSING_GEMINI_RATE_LIMIT_PAUSE_MS) return true
    }
    return false
}

function isProcessingJobStale(data: Record<string, unknown>, uploadedAt?: Date): boolean {
    const status = String(data.status || '').trim().toLowerCase()
    if (status && status !== 'processing' && status !== 'queued') return false
    const timestamp = String(data.updatedAt || data.startedAt || data.createdAt || '').trim()
    const lastTouchedMs = timestamp ? Date.parse(timestamp) : NaN
    const fallbackMs = uploadedAt instanceof Date ? uploadedAt.getTime() : NaN
    const effectiveMs = Number.isFinite(lastTouchedMs) && lastTouchedMs > 0 ? lastTouchedMs : fallbackMs
    return Number.isFinite(effectiveMs) && effectiveMs > 0 && Date.now() - effectiveMs > getProcessingJobStaleTimeoutMs(data)
}

function isPipelineHandoffStep(data: Record<string, unknown>): boolean {
    const step = Number(data.step)
    const stepName = String(data.stepName || '').trim().toLowerCase()
    return step === 0
        || stepName.includes('กำลังเชื่อมต่อเครื่องประมวลผล')
        || stepName.includes('connecting')
        || stepName.includes('เชื่อมต่อเครื่องประมวลผล')
}

function isGeminiPreparationStep(data: Record<string, unknown>): boolean {
    const step = Number(data.step)
    const stepName = String(data.stepName || '').trim()
    return step === 2.2
        || step === 2.7
        || stepName.includes('แปลงวิดีโอให้ Gemini อ่านได้')
        || stepName.includes('สร้างบทพากย์ผ่าน Vertex Gemini')
        || stepName.toLowerCase().includes('gemini-safe transcode')
}

function getProcessingJobStaleTimeoutMs(data: Record<string, unknown>): number {
    if (isPipelineHandoffStep(data)) return PROCESSING_PIPELINE_HANDOFF_STALE_TIMEOUT_MS
    return isGeminiPreparationStep(data)
        ? PROCESSING_GEMINI_PREP_STALE_TIMEOUT_MS
        : PROCESSING_STALE_TIMEOUT_MS
}

function getProcessingJobStaleError(data: Record<string, unknown>): string {
    if (isPipelineHandoffStep(data)) return PROCESSING_PIPELINE_HANDOFF_STALE_ERROR
    return isGeminiPreparationStep(data)
        ? PROCESSING_GEMINI_PREP_STALE_ERROR
        : PROCESSING_STALE_ERROR
}

function getProcessingJobStaleCategory(data: Record<string, unknown>): string {
    if (isPipelineHandoffStep(data)) return 'pipeline_handoff_stale_timeout'
    return isGeminiPreparationStep(data)
        ? 'gemini_preparation_stale_timeout'
        : 'stale_timeout'
}

// Marks a single active `_processing/{id}.json` record as failed because it has
// stalled past its timeout, then mirrors the terminal record into
// `_processing_history/`. Shared by the bounded active-job check
// (hasActiveProcessingJob) and the full stale sweep (expireStaleProcessingJobs)
// so both paths write identical stale-failure records and neither leaves a stale
// job blocking the one-at-a-time dispatcher.
async function markProcessingJobStale(
    bucket: R2Bucket,
    key: string,
    data: Record<string, unknown>,
    uploadedAt: Date,
): Promise<void> {
    const nowIso = new Date().toISOString()
    const idFromKey = key.replace(/^_processing\//, '').replace(/\.json$/i, '').trim()
    const id = String(data.id || idFromKey || '').trim()
    const failedRecord = {
        ...data,
        id,
        status: 'failed',
        error: sanitizeProcessingError(data.error || getProcessingJobStaleError(data)),
        errorCategory: String(data.errorCategory || getProcessingJobStaleCategory(data)).trim(),
        staleTimedOutAt: nowIso,
        failedAt: nowIso,
        updatedAt: nowIso,
        createdAt: String(data.createdAt || data.startedAt || '').trim() || uploadedAt.toISOString(),
    }
    await bucket.put(key, JSON.stringify(failedRecord, null, 2), {
        httpMetadata: { contentType: 'application/json' },
    })
    await putProcessingHistoryRecord(bucket, id, failedRecord).catch(() => { })
}

async function expireStaleProcessingJobs(bucket: R2Bucket): Promise<number> {
    const processingList = await bucket.list({ prefix: '_processing/' })
    // Only records uploaded within the stale-check window can still flip from
    // active → stale. Anything older is either already-marked-failed (and we'd
    // rewrite the same status) or so old that subsequent passes will have
    // handled it. Filtering here is the main /api/processing speedup: a
    // namespace with hundreds of old failed `_processing/*.json` records no
    // longer fans out hundreds of R2 GETs per page load.
    const nowMs = Date.now()
    const candidates = processingList.objects
        .filter((obj) => {
            const uploadedMs = obj.uploaded instanceof Date ? obj.uploaded.getTime() : NaN
            return !Number.isFinite(uploadedMs) || nowMs - uploadedMs <= PROCESSING_STALE_CHECK_WINDOW_MS
        })
        .sort((a, b) => b.uploaded.getTime() - a.uploaded.getTime())
        .slice(0, PROCESSING_STALE_CHECK_MAX)

    const results = await Promise.all(candidates.map(async (obj) => {
        const dataObj = await bucket.get(obj.key).catch(() => null)
        if (!dataObj) return 0
        const data = await dataObj.json().catch(() => ({} as Record<string, unknown>)) as Record<string, unknown>
        if (!isProcessingJobStale(data, obj.uploaded)) return 0

        await markProcessingJobStale(bucket, obj.key, data, obj.uploaded)
        return 1
    }))
    return results.reduce((acc, n) => acc + n, 0)
}

async function listActiveProcessingVideos(
    bucket: R2Bucket,
    options: { resultLimit?: number; historyMaxObjects?: number } = {},
): Promise<Array<Record<string, unknown>>> {
    const resultLimit = Math.min(Math.max(Math.floor(options.resultLimit ?? 120), 1), 120)
    const historyMaxObjects = Math.min(Math.max(Math.floor(options.historyMaxObjects ?? 120), 1), 120)
    await expireStaleProcessingJobs(bucket).catch((error) => {
        console.error(`[PROCESSING-STALE] failed to expire stale jobs: ${error instanceof Error ? error.message : String(error)}`)
    })
    // `_processing/` accumulates terminal `failed` records that get mirrored
    // into `_processing_history/` but never deleted from production. Reading
    // every one on each /api/processing call drove the endpoint past 30s for
    // large namespaces. Capping at the most-recent N covers any active job
    // (active uploads are always newest) and yields enough recently-failed
    // records for the UI; older failures still surface via the history prefix.
    const [processing, queued, history] = await Promise.all([
        readProcessingListPrefix(bucket, '_processing/', 'processing', { maxObjects: PROCESSING_ACTIVE_LIST_MAX }),
        readProcessingListPrefix(bucket, '_queue/', 'queued'),
        readProcessingListPrefix(bucket, PROCESSING_HISTORY_PREFIX, 'processed', { maxObjects: historyMaxObjects }),
    ])

    const seen = new Set<string>()
    const videos = [...processing, ...queued, ...history].filter((video) => {
        const id = String(video.id || '').trim()
        if (!id || seen.has(id)) return false
        seen.add(id)
        return true
    })

    videos.sort((a, b) => {
        const at = new Date(String(a.completedAt || a.updatedAt || a.createdAt || '')).getTime()
        const bt = new Date(String(b.completedAt || b.updatedAt || b.createdAt || '')).getTime()
        return (Number.isFinite(bt) ? bt : 0) - (Number.isFinite(at) ? at : 0)
    })
    return videos.slice(0, resultLimit)
}

async function startNextReadyInboxForNamespace(env: Env, ctx: ExecutionContext, namespaceId: string, options: { runInline?: boolean; excludeVideoIds?: string[] } = {}): Promise<boolean> {
    const botId = String(namespaceId || '').trim()
    if (!botId) return false
    const excludeVideoIds = new Set((options.excludeVideoIds || []).map((id) => String(id || '').trim()).filter(Boolean))

    const bucket = new BotBucket(env.BUCKET, botId) as unknown as R2Bucket
    if (await hasActiveProcessingJob(bucket, botId).catch(() => true)) return false
    await syncReadyInboxLinksToNamespaceIndex({
        env,
        bucket,
        namespaceId: botId,
        limit: 40,
    }).catch((error) => {
        console.error(`[PROCESSING-AUTOSTART] Failed to sync ready inbox links for ${botId}: ${error instanceof Error ? error.message : String(error)}`)
        return 0
    })

    const galleryIndexVideo = await getNextReadyGalleryIndexInboxRecord({
        env,
        bucket,
        namespaceId: botId,
        excludeVideoIds: Array.from(excludeVideoIds),
    }).catch((error) => {
        console.error(`[PROCESSING-AUTOSTART] Failed to read gallery_index next ready video for ${botId}: ${error instanceof Error ? error.message : String(error)}`)
        return null
    })

    const recentCandidates = await listRecentInboxVideoRecords(bucket, 50).catch(() => [])
    const candidates = galleryIndexVideo
        ? [
            galleryIndexVideo,
            ...recentCandidates.filter((record) => String(record.id || '').trim() !== String(galleryIndexVideo.id || '').trim()),
        ]
        : recentCandidates

    for (const candidate of candidates) {
        const item = normalizeInboxVideoRecord(candidate)
        if (item && excludeVideoIds.has(String(item.id || '').trim())) continue
        if (!item || item.status !== 'ready') continue

        const processedAt = await getGalleryIndexProcessedAt(env.DB, botId, item.id).catch(() => '')
        if (processedAt || String(item.processedAt || '').trim()) {
            if (!String(item.processedAt || '').trim()) {
                await putInboxVideoRecord(bucket, {
                    ...item,
                    processedAt,
                    updatedAt: new Date().toISOString(),
                }).catch(() => { })
            }
            continue
        }

        const existingProcessingStatus = await getProcessingJobStatus(bucket, item.id).catch(() => '')
        if (existingProcessingStatus) continue

        try {
            const result = await ensureInboxVideoProcessingStarted({
                env,
                bucket,
                executionCtx: ctx,
                botId,
                item,
                skipIfAlreadyProcessed: true,
                runInline: options.runInline,
            })
            if (result.outcome === 'started') {
                console.log(`[PROCESSING-AUTOSTART] Started ${botId}/${item.id}: ${result.job.status}`)
                return true
            }
            if (result.outcome === 'already_running') return true
        } catch (error) {
            console.error(`[PROCESSING-AUTOSTART] Failed ${botId}/${item.id}: ${error instanceof Error ? error.message : String(error)}`)
        }
    }

    return false
}

// Single entry point every completion / scheduled / manual drainer uses to keep
// the Processing flow self-perpetuating: drain the durable `_queue/` first, then
// fall back to the ready inbox / gallery_index, then (admin only) import + start
// from the original library. Guarantees at most one active job per namespace and
// returns structured evidence so callers can log a sanitized one-liner. The
// ordering lives in the import-free `processing-dispatch` module; this wrapper
// just supplies the real side-effecting steps.
// Materialize AT MOST ONE unprocessed AI clip from the new source library
// (`_ai_clips/<namespace>/`) into the durable `_queue/` and promote it to processing —
// the exact same handoff `/api/dashboard/ai-clips/process` performs, minus the per-id
// response bookkeeping. This is the ONLY automatic backlog source the Dashboard
// processing flow uses: the legacy ready-inbox / admin-original auto-pick is disabled in
// dispatchNextProcessingJobForNamespace, so old Chinese/legacy clips are never auto-started.
//
// The durable `_queue/` stays a transient one-job handoff: when the namespace already has
// an active OR queued job, `selectNextAiClipToProcess` defers the whole backlog and we
// start nothing. Returns true only when a job was actually started this call.

async function drainAiClipQueueOnlyForNamespace(
    env: Env,
    bucket: R2Bucket,
    namespaceId: string,
): Promise<boolean> {
    const botId = String(namespaceId || '').trim()
    if (!botId) return false
    const list = await bucket.list({ prefix: '_queue/' }).catch(() => ({ objects: [] as Array<{ key: string }> }))
    const objects = Array.isArray(list.objects) ? list.objects : []
    if (!objects.length) return false

    let hasAiClipQueue = false
    for (const obj of objects) {
        const queued = await bucket.get(obj.key).catch(() => null)
        const job = queued ? await queued.json().catch(() => ({} as Record<string, unknown>)) as Record<string, unknown> : {}
        if (isAiClipQueueHandoff(job)) {
            hasAiClipQueue = true
            continue
        }
        // Stop old legacy/Chinese queued handoffs from being promoted in the new Dashboard flow.
        await bucket.delete(obj.key).catch(() => { })
    }

    if (!hasAiClipQueue) return false
    return processNextInQueue(env, botId)
}

async function startNextAiClipSourceForNamespace(
    env: Env,
    bucket: R2Bucket,
    namespaceId: string,
): Promise<boolean> {
    const botId = String(namespaceId || '').trim()
    if (!botId) return false
    const workerUrl = String(env.WORKER_URL || '').trim()
    if (!workerUrl) return false

    const allRecords = await listAiClipRecords(bucket, botId).catch(() => [] as AiClipRecord[])
    if (!allRecords.length) return false
    const knownIds = new Set(allRecords.map((record) => record.id))
    const processedIds = new Set(allRecords.filter((record) => isAiClipProcessed(record)).map((record) => record.id))
    const unprocessed = allRecords.filter((record) => !isAiClipProcessed(record))
    if (!unprocessed.length) return false

    // Never grow the durable queue while a job is active or already queued: the queue is a
    // transient one-job handoff, never the operator's backlog.
    const inFlight = await namespaceHasInFlightProcessingJob(bucket, botId).catch(() => true)
    const selection = selectNextAiClipToProcess(unprocessed, { requestedIds: [], inFlight, knownIds, processedIds })
    if (!selection.selectedId) return false

    const record = allRecords.find((item) => item.id === selection.selectedId) || null
    if (!record) return false

    const nowIso = new Date().toISOString()
    const job = buildAiClipProcessingQueueJob(record, { workerUrl, namespaceId: botId, nowIso })
    if (!job) return false

    // Mirror the route's handoff: persist a `_link_context` record so the completion webhook
    // writes the product links onto the finished gallery meta. chatId 0 → no Telegram DM.
    await bucket.put(`_link_context/${record.id}.json`, JSON.stringify({
        id: record.id,
        videoUrl: job.videoUrl,
        shopeeLink: job.shopeeLink,
        lazadaLink: job.lazadaLink,
        shopeeOriginalLink: job.shopeeLink,
        lazadaOriginalLink: job.lazadaLink,
        chatId: 0,
        sourceType: job.sourceType,
        sourceLabel: job.sourceLabel,
        createdAt: nowIso,
    }), { httpMetadata: { contentType: 'application/json' } })
    await bucket.put(`_queue/${record.id}.json`, JSON.stringify(job), {
        httpMetadata: { contentType: 'application/json' },
    })

    // Promote the single queued job to processing now — the same drain completion + cron use.
    const started = await processNextInQueue(env, botId).catch(() => false)
    return started || (await hasActiveProcessingJob(bucket, botId).catch(() => false))
}

// Discriminator that decides which dispatch contract a namespace gets. The AI Clips
// dashboard flow (e.g. the new /Media namespace) materializes ONE AI clip at a time from
// its dedicated `_ai_clips/<namespace>/` source library and must never auto-pick the old
// Chinese/legacy gallery-index inbox or admin originals. Legacy app.oomnn namespaces have
// NO AI clip source records — they keep the legacy durable-queue + ready-inbox autostart,
// and their queued/failed handoffs must NOT be deleted.
//
// "AI-only mode" is therefore true exactly when the namespace owns at least one AI clip
// source record. Cheap: lists only the first object under the namespace prefix. On error we
// fail to LEGACY mode (false) so a transient R2 hiccup never silently disables an
// app.oomnn namespace's legacy retry/autostart paths.
async function namespaceUsesAiClipSourceLibrary(bucket: R2Bucket, namespaceId: string): Promise<boolean> {
    const prefix = aiClipNamespacePrefix(namespaceId)
    if (!prefix) return false
    const list = await bucket.list({ prefix, limit: 1 }).catch(() => null)
    return !!(list && Array.isArray(list.objects) && list.objects.length > 0)
}

async function dispatchNextProcessingJobForNamespace(
    env: Env,
    ctx: ExecutionContext,
    namespaceId: string,
    options: { runInline?: boolean; excludeVideoIds?: string[] } = {},
): Promise<ProcessingDispatchResult> {
    const botId = String(namespaceId || '').trim()
    if (!botId) return { namespaceId: '', started: false, source: 'idle', detail: 'missing_namespace' }

    const bucket = new BotBucket(env.BUCKET, botId) as unknown as R2Bucket

    if (await hasRecentNamespaceGeminiRateLimitFailure(env, botId).catch(() => false)) {
        return { namespaceId: botId, started: false, source: 'idle', detail: 'gemini_rate_limit_cooldown' }
    }

    const aiOnlyMode = await namespaceUsesAiClipSourceLibrary(bucket, botId).catch(() => false)
    const mode = resolveProcessingDispatchMode(aiOnlyMode)

    // LEGACY namespaces (app.oomnn etc.) keep the original durable-queue + ready-inbox
    // autostart. processNextInQueue only promotes a durable `_queue/` job — it never deletes
    // a non-AI handoff — so a reprocessed/failed legacy job that was requeued into `_queue/`
    // is drained and started here. Ready-inbox / admin-original auto-pick stays enabled so
    // the Processing tab keeps self-perpetuating one-at-a-time.
    if (!mode.aiOnly) {
        return dispatchNextProcessingJob(botId, {
            // On error, assume a job is active so we never race a second start.
            hasActiveJob: () => hasActiveProcessingJob(bucket, botId).catch(() => true),
            // Drain the durable queue with the legacy-capable helper (no AI-clip-only delete).
            drainQueue: () => processNextInQueue(env, botId),
            startReadyInbox: () => startNextReadyInboxForNamespace(env, ctx, botId, { runInline: options.runInline, excludeVideoIds: options.excludeVideoIds }),
            startAdminOriginal: async () => {
                const adminNamespaceId = await resolvePrimaryAdminNamespaceId(env.DB).catch(() => '')
                if (!adminNamespaceId || adminNamespaceId !== botId) return false
                // autoImportAndProcessForAdmin starts the next waiting admin original
                // (if any) and refills the ready inbox from member namespaces. It
                // returns void, so confirm a job is now in flight to report `started`.
                await autoImportAndProcessForAdmin(env, ctx)
                return hasActiveProcessingJob(bucket, botId).catch(() => false)
            },
        }, { disableLegacySources: mode.disableLegacySources })
    }

    // New Dashboard/AI-source flow: do NOT run the old broad processNextInQueue
    // pre-sweep here. That helper can promote legacy ready-inbox/admin-original
    // items before the pure dispatcher gets a chance to apply disableLegacySources,
    // which is how old Chinese clips kept auto-starting after the queue was cleared.
    // The pure dispatcher below still drains an already-materialized durable queue
    // via drainQueue, then starts at most one AI clip source item; legacy sources are
    // disabled for automatic dispatch.

    return dispatchNextProcessingJob(botId, {
        // On error, assume a job is active so we never race a second start.
        hasActiveJob: () => hasActiveProcessingJob(bucket, botId).catch(() => true),
        // New flow must not requeue old failed legacy jobs. Failed AI/source records stay
        // visible as failures; a new start comes from the AI source library below.
        retryFailedJob: async () => false,
        // Drain only AI-clip handoffs. The legacy processNextInQueue helper can fall back
        // to old ready inbox/admin originals when called with an empty/non-AI queue, so guard it.
        drainQueue: () => drainAiClipQueueOnlyForNamespace(env, bucket, botId),
        // New Dashboard flow: the AI clips / source library is the ONLY automatic backlog.
        startAiClipSource: () => startNextAiClipSourceForNamespace(env, bucket, botId),
        // LEGACY auto-pick — kept available but DISABLED via `disableLegacySources` below so
        // automatic dispatch (cron / completion / manual) never starts old Chinese/legacy
        // gallery_index ready-inbox items or admin-original-library clips for this flow.
        startReadyInbox: () => startNextReadyInboxForNamespace(env, ctx, botId, { runInline: options.runInline, excludeVideoIds: options.excludeVideoIds }),
        startAdminOriginal: async () => {
            const adminNamespaceId = await resolvePrimaryAdminNamespaceId(env.DB).catch(() => '')
            if (!adminNamespaceId || adminNamespaceId !== botId) return false
            // autoImportAndProcessForAdmin starts the next waiting admin original
            // (if any) and refills the ready inbox from member namespaces. It
            // returns void, so confirm a job is now in flight to report `started`.
            await autoImportAndProcessForAdmin(env, ctx)
            return hasActiveProcessingJob(bucket, botId).catch(() => false)
        },
    }, { disableLegacySources: mode.disableLegacySources })
}

app.get('/api/processing', async (c) => {
    try {
        const namespaceId = String(c.get('botId') || '').trim()
        const includeSummary = String(c.req.query('summary') || '').trim() === '1'
        const requestedLimit = parseNonNegativeInt(c.req.query('limit'), 120)
        const requestedHistoryLimit = parseNonNegativeInt(c.req.query('history_limit'), 120)
        const resultLimit = Math.min(Math.max(requestedLimit || 120, 1), 120)
        const historyMaxObjects = Math.min(Math.max(requestedHistoryLimit || 120, 1), 120)
        const requestedSystemView = String(c.req.query('system') || '').trim() === '1'
        let ownerEmail = ''
        let processingNamespaceId = namespaceId
        if (requestedSystemView) {
            const authCheck = await requireSystemAdminSession(c)
            if (!authCheck.ok) return authCheck.response
            ownerEmail = authCheck.email
            processingNamespaceId = authCheck.namespaceId || namespaceId
        }

        const processingHistoryVideos = await listActiveProcessingVideos(c.get('bucket'), {
            resultLimit,
            historyMaxObjects,
        })
        const activeOrFailedProcessingVideos = processingHistoryVideos.filter((video) => {
            const status = String(video.status || '').trim().toLowerCase()
            return status === 'processing' || status === 'queued' || status === 'failed' || status === 'error' || status === 'cancelled' || status === 'canceled'
        })
        const processedGalleryPage = processingNamespaceId
            ? await getNamespaceInboxGalleryIndexPage({
                env: c.env,
                namespaceId: processingNamespaceId,
                ownerEmail,
                view: 'processed',
                offset: 0,
                limit: resultLimit,
            }).catch(() => null)
            : null
        const processedGalleryVideos = (processedGalleryPage?.videos || []).map((video) => {
            const processedAt = String(video.processedAt || video.processed_at || video.updatedAt || video.createdAt || '').trim()
            return {
                ...video,
                status: 'processed',
                completedAt: processedAt,
                processedAt,
                processingSource: 'gallery_index',
            }
        })
        const processedIds = new Set(processedGalleryVideos.map((video) => String(video.id || video.video_id || '').trim()).filter(Boolean))
        const videos = [
            ...activeOrFailedProcessingVideos,
            ...processedGalleryVideos,
            ...processingHistoryVideos.filter((video) => {
                const status = String(video.status || '').trim().toLowerCase()
                const id = String(video.id || video.video_id || '').trim()
                return (status === 'processed' || status === 'success' || status === 'done') && (!id || !processedIds.has(id))
            }),
        ]
        const activeProcessingVideos = videos.filter((video) => {
            const status = String(video.status || '').trim().toLowerCase()
            return status === 'processing' || status === 'queued'
        })
        // Auto-start the next available item in the same deterministic order as
        // completion + cron. This keeps the Processing tab from becoming a
        // partial ready-inbox-only drainer when active=0.
        if (activeProcessingVideos.length === 0 && namespaceId) {
            c.executionCtx.waitUntil(
                dispatchNextProcessingJobForNamespace(c.env, c.executionCtx, namespaceId, { runInline: false })
                    .then((result) => {
                        console.log(`[PROCESSING-AUTOSTART] ${namespaceId}: started=${result.started ? 'yes' : 'no'} source=${result.source}${result.detail ? ` detail=${result.detail}` : ''}`)
                    })
                    .catch((error) => {
                        console.error(`[PROCESSING-AUTOSTART] Failed for ${namespaceId}: ${error instanceof Error ? error.message : String(error)}`)
                    })
            )
        }
        let pendingShortlinkVideos: Array<Record<string, unknown>> = []
        let pendingTotal = 0
        let pendingHasLazadaTotal = 0
        let readyTotal = 0
        let inventoryTotal = 0
        let libraryTotal = 0

        if (includeSummary && namespaceId) {
            const shortlinkRequired = await isNamespaceAffiliateShortlinkProcessingRequired(c.env.DB, namespaceId).catch(() => false)
            const summary = await getNamespaceProcessingSummaryFast(c.env, namespaceId, shortlinkRequired)
            pendingShortlinkVideos = summary.pendingShortlinkVideos
            readyTotal = summary.readyTotal
            inventoryTotal = summary.inventoryTotal
            libraryTotal = summary.libraryTotal
            pendingTotal = summary.pendingTotal
            pendingHasLazadaTotal = summary.pendingHasLazadaTotal
        }
        return c.json({
            videos,
            pending_shortlink_videos: pendingShortlinkVideos,
            processing_total: activeProcessingVideos.length,
            history_total: Math.max(0, videos.length - activeProcessingVideos.length),
            pending_total: pendingTotal,
            pending_has_lazada_total: pendingHasLazadaTotal,
            pending_missing_lazada_total: Math.max(0, pendingTotal - pendingHasLazadaTotal),
            ready_total: readyTotal,
            inventory_total: inventoryTotal,
            library_total: libraryTotal,
        }, 200, { 'Cache-Control': 'private, max-age=5, stale-while-revalidate=15', 'Vary': 'x-auth-token' })
    } catch (e) {
        return c.json({ error: String(e) }, 500)
    }
})

app.get('/api/inbox', async (c) => {
    try {
        const namespaceId = String(c.get('botId') || '').trim()
        const offset = parseNonNegativeInt(c.req.query('offset'), 0)
        const requestedLimit = parseNonNegativeInt(c.req.query('limit'), 24)
        const limit = Math.min(Math.max(requestedLimit, 1), 120)
        const view = parseInboxListView(c.req.query('view'))
        const bucket = c.get('bucket')
        const ownerEmail = await resolveOwnerEmailForNamespace(c.env.DB, namespaceId).catch(() => '')
        if (namespaceId && offset === 0 && (view === 'unprocessed' || view === 'missing_links')) {
            c.executionCtx.waitUntil(syncReadyInboxLinksToNamespaceIndex({
                env: c.env,
                bucket,
                namespaceId,
                limit: 120,
            }).catch((error) => {
                console.error(`[INBOX-LINK-SYNC] Failed for ${namespaceId}: ${error instanceof Error ? error.message : String(error)}`)
                return 0
            }))
        }
        const galleryIndexPage = await getNamespaceInboxGalleryIndexPage({
            env: c.env,
            namespaceId,
            ownerEmail,
            view,
            offset,
            limit,
        }).catch(() => null)
        if (galleryIndexPage && galleryIndexPage.total > 0) {
            return c.json({
                videos: galleryIndexPage.videos,
                total: galleryIndexPage.total,
                processed_total: galleryIndexPage.processedTotal,
                unprocessed_total: galleryIndexPage.unprocessedTotal,
                missing_link_total: galleryIndexPage.missingLinkTotal,
                offset,
                limit,
                has_more: galleryIndexPage.hasMore,
                view,
            }, 200, {
                'Cache-Control': offset === 0
                    ? 'private, no-store'
                    : 'private, max-age=15, stale-while-revalidate=60',
                'Vary': 'x-auth-token',
            })
        }
        const cachedSnapshot = await readNamespaceInboxSnapshot(bucket, namespaceId).catch(() => null)
        const cacheAgeMs = cachedSnapshot ? Math.max(0, Date.now() - cachedSnapshot.builtAtMs) : Number.POSITIVE_INFINITY
        const shouldRefreshCache = !cachedSnapshot || cacheAgeMs > NAMESPACE_INBOX_CACHE_TTL_MS

        if (shouldRefreshCache) {
            c.executionCtx.waitUntil((async () => {
                try {
                    const freshVideos = await buildNamespaceInboxSnapshot(c.env, namespaceId)
                    await writeNamespaceInboxSnapshot(bucket, namespaceId, freshVideos)
                } catch (error) {
                    console.log(`[INBOX-CACHE] refresh failed ns=${namespaceId}: ${error instanceof Error ? error.message : String(error)}`)
                }
            })())
        }

        const visibleVideos: Array<Record<string, unknown>> = Array.isArray(cachedSnapshot?.videos) && cachedSnapshot!.videos.length > 0
            ? cachedSnapshot!.videos
            : await buildNamespaceInboxSnapshot(c.env, namespaceId)
        if (!cachedSnapshot?.videos?.length) {
            await writeNamespaceInboxSnapshot(bucket, namespaceId, visibleVideos).catch(() => { })
        }

        const processedTotal = visibleVideos.filter((video) => isInboxResponseProcessed(video)).length
        const missingLinkTotal = visibleVideos.filter((video) => isInboxResponseMissingLinks(video)).length
        const unprocessedTotal = Math.max(0, visibleVideos.length - processedTotal - missingLinkTotal)
        const filteredVideos = filterInboxVideosByView(visibleVideos, view)
        const page = sliceGalleryPage(filteredVideos, offset, limit)
        c.executionCtx.waitUntil(backfillNamespaceInboxOriginalAssets({
            env: c.env,
            bucket,
            namespaceId,
        }).catch((error) => {
            console.log(`[INBOX-BACKFILL] namespace=${namespaceId}: ${error instanceof Error ? error.message : String(error)}`)
        }))
        c.executionCtx.waitUntil(Promise.all(
            page.videos.slice(0, 6).map((video) => ensureInboxAutoCoverSuggestion({
                env: c.env,
                bucket,
                namespaceId,
                videoId: String(video.id || '').trim(),
            }).catch(() => false))
        ))
        return c.json({
            videos: page.videos,
            total: visibleVideos.length,
            processed_total: processedTotal,
            unprocessed_total: unprocessedTotal,
            missing_link_total: missingLinkTotal,
            offset,
            limit,
            has_more: page.hasMore,
            view,
        }, 200, {
            'Cache-Control': offset === 0
                ? 'private, no-store'
                : 'private, max-age=15, stale-while-revalidate=60',
            'Vary': 'x-auth-token',
        })
    } catch (e) {
        return c.json({ error: String(e), videos: [] }, 500)
    }
})

app.get('/api/inbox/system', async (c) => {
    try {
        const offset = parseNonNegativeInt(c.req.query('offset'), 0)
        const requestedLimit = parseNonNegativeInt(c.req.query('limit'), 24)
        const limit = Math.min(Math.max(requestedLimit, 1), 120)
        const view = parseInboxListView(c.req.query('view'))
        const forceFresh = String(c.req.query('fresh') || '').trim() === '1' && offset === 0
        const token = getSessionTokenFromRequest(c)
        if (!token.startsWith('sess_')) return c.json({ error: 'Unauthorized' }, 401)
        const me = await c.env.DB.prepare('SELECT email, namespace_id FROM users WHERE session_token = ?').bind(token).first() as { email?: string; namespace_id?: string } | null
        if (!me?.email) return c.json({ error: 'Unauthorized' }, 401)
        const sysAdmin = await isSystemAdmin(c.env.DB, String(me.email))
        if (!sysAdmin) return c.json({ error: 'Forbidden' }, 403)
        const currentNamespaceId = String(me.namespace_id || c.get('botId') || '').trim()

        const bucket = c.get('bucket')
        const galleryIndexPage = await getNamespaceInboxGalleryIndexPage({
            env: c.env,
            namespaceId: currentNamespaceId,
            ownerEmail: String(me.email || '').trim().toLowerCase(),
            view,
            offset,
            limit,
        }).catch(() => null)
        if (galleryIndexPage && galleryIndexPage.total > 0) {
            return c.json({
                videos: galleryIndexPage.videos,
                total: galleryIndexPage.total,
                processed_total: galleryIndexPage.processedTotal,
                unprocessed_total: galleryIndexPage.unprocessedTotal,
                missing_link_total: galleryIndexPage.missingLinkTotal,
                offset,
                limit,
                has_more: galleryIndexPage.hasMore,
                view,
            }, 200, {
                'Cache-Control': forceFresh || offset === 0
                    ? 'private, no-store'
                    : 'private, max-age=15, stale-while-revalidate=60',
                'Vary': 'x-auth-token',
            })
        }
        const cachedSnapshot = forceFresh
            ? null
            : await readSystemInboxSnapshot(bucket, currentNamespaceId).catch(() => null)
        const cachedVideos = cachedSnapshot?.videos || []
        const cacheAgeMs = cachedSnapshot ? Math.max(0, Date.now() - cachedSnapshot.builtAtMs) : Number.POSITIVE_INFINITY
        const shouldRefreshCache = !cachedSnapshot || cacheAgeMs > SYSTEM_INBOX_CACHE_TTL_MS

        if (shouldRefreshCache) {
            c.executionCtx.waitUntil((async () => {
                try {
                    const freshVideos = await buildSystemInboxSnapshot(c.env, currentNamespaceId)
                    await writeSystemInboxSnapshot(bucket, currentNamespaceId, freshVideos)
                } catch (error) {
                    console.log(`[SYSTEM-INBOX-CACHE] refresh failed: ${error instanceof Error ? error.message : String(error)}`)
                }
            })())
        }

        const dedupedVideos: Array<Record<string, unknown>> = cachedVideos.length > 0
            ? cachedVideos
            : await buildSystemInboxSnapshot(c.env, currentNamespaceId)
        if (!cachedVideos.length) {
            await writeSystemInboxSnapshot(bucket, currentNamespaceId, dedupedVideos).catch(() => { })
        }
        const visibleVideos = dedupedVideos.filter((video) => (
            !!String(video.thumbnailUrl || '').trim()
            || !!String((video as Record<string, unknown>).fallbackThumbnailUrl || '').trim()
        ))
        const processedTotal = visibleVideos.filter((video) => isInboxResponseProcessed(video)).length
        const missingLinkTotal = visibleVideos.filter((video) => isInboxResponseMissingLinks(video)).length
        const unprocessedTotal = Math.max(0, visibleVideos.length - processedTotal - missingLinkTotal)
        const filteredVideos = filterInboxVideosByView(visibleVideos, view)
        const page = sliceGalleryPage(filteredVideos, offset, limit)
        c.executionCtx.waitUntil(Promise.all(
            page.videos.slice(0, 6).map((video) => {
                const videoId = String(video.id || '').trim()
                const namespaceId = String(video.namespace_id || '').trim()
                if (!videoId || !namespaceId) return Promise.resolve(false)
                const scopedBucket = new BotBucket(c.env.BUCKET, namespaceId) as unknown as R2Bucket
                return ensureInboxAutoCoverSuggestion({
                    env: c.env,
                    bucket: scopedBucket,
                    namespaceId,
                    videoId,
                }).catch(() => false)
            })
        ))

        return c.json({
            videos: page.videos,
            total: visibleVideos.length,
            processed_total: processedTotal,
            unprocessed_total: unprocessedTotal,
            missing_link_total: missingLinkTotal,
            offset,
            limit,
            has_more: page.hasMore,
            view,
        }, 200, {
            'Cache-Control': forceFresh || offset === 0
                ? 'private, no-store'
                : 'private, max-age=15, stale-while-revalidate=60',
            'Vary': 'x-auth-token',
        })
    } catch (e) {
        return c.json({ error: String(e), videos: [] }, 500)
    }
})

app.post('/api/inbox/reset-processed', async (c) => {
    const authCheck = await requireSystemAdminSession(c)
    if (!authCheck.ok) return authCheck.response

    try {
        const body = await c.req.json().catch(() => ({})) as { namespace_id?: string }
        const targetNamespaceId = String(body.namespace_id || authCheck.namespaceId || '').trim()
        if (!targetNamespaceId) return c.json({ error: 'missing_namespace_id' }, 400)

        const bucket = new BotBucket(c.env.BUCKET, targetNamespaceId) as unknown as R2Bucket
        const records = await listInboxVideoRecords(bucket)

        let processedBefore = 0
        let resetCount = 0
        const nextRecords: InboxVideoRecord[] = []
        for (const record of records) {
            if (!String(record.processedAt || '').trim()) {
                nextRecords.push(record)
                continue
            }
            processedBefore += 1
            const nextRecord = await putInboxVideoRecord(bucket, {
                ...record,
                processedAt: '',
                updatedAt: new Date().toISOString(),
            })
            nextRecords.push(nextRecord)
            resetCount += 1
        }

        await writeNamespaceInboxSnapshot(
            bucket,
            targetNamespaceId,
            nextRecords.map((record) => buildInboxVideoResponseForNamespace(c.env, record, targetNamespaceId)),
        ).catch(() => { })

        if (authCheck.namespaceId === targetNamespaceId) {
            await writeSystemInboxSnapshot(bucket, targetNamespaceId, []).catch(() => { })
        }

        return c.json({
            ok: true,
            namespace_id: targetNamespaceId,
            total: records.length,
            processed_before: processedBefore,
            processed_reset: resetCount,
            unprocessed_after: records.length,
            processed_after: 0,
        })
    } catch (e) {
        return c.json({ error: String(e) }, 500)
    }
})

app.post('/api/desktop-prepare', async (c) => {
    const authCheck = await requireAuthSession(c)
    if (!authCheck.ok) return authCheck.response

    try {
        const token = getSessionTokenFromRequest(c)
        const sessionUser = await c.env.DB.prepare(
            'SELECT email, namespace_id FROM users WHERE session_token = ? LIMIT 1'
        ).bind(token).first().catch(() => null) as { email?: string; namespace_id?: string } | null

        const namespaceId = String(sessionUser?.namespace_id || c.get('botId') || '').trim()
        const email = String(sessionUser?.email || '').trim().toLowerCase()
        if (!namespaceId || !email) return c.json({ error: 'unauthorized' }, 401)

        const currentNamespaceId = String(c.get('botId') || '').trim()
        const bucket = currentNamespaceId === namespaceId
            ? c.get('bucket')
            : new BotBucket(c.env.BUCKET, namespaceId) as unknown as R2Bucket

        const body = await c.req.json().catch(() => ({})) as {
            sourceMode?: 'upload' | 'url'
            videoId?: string
            sourceUrl?: string
            sourceLabel?: string
        }

        const sourceMode = String(body.sourceMode || '').trim().toLowerCase() === 'upload' ? 'upload' : 'url'
        let videoId = String(body.videoId || '').trim()
        let originalVideoUrl = ''
        let thumbnailUrl = ''
        let sourceType: InboxVideoSourceType = 'telegram_video'
        let sourceLabel = 'Desktop upload'

        if (sourceMode === 'upload') {
            if (!videoId) return c.json({ error: 'video_id_required' }, 400)
            const originalKey = getPrimaryOriginalVideoAssetKey(videoId)
            const originalObj = await bucket.head(originalKey).catch(() => null)
            if (!originalObj) return c.json({ error: 'uploaded_video_not_found' }, 404)

            originalVideoUrl = getVideoOriginalUrlForNamespace(c.env.R2_PUBLIC_URL, namespaceId, videoId)
            sourceType = 'telegram_video'
            sourceLabel = 'Desktop upload'
            thumbnailUrl = await backfillOriginalThumbnail(c.env, namespaceId, videoId)
                .then((result) => String(result.thumbnailUrl || '').trim())
                .catch(() => '')
            if (!thumbnailUrl) {
                thumbnailUrl = getVideoOriginalThumbnailUrlForNamespace(c.env.R2_PUBLIC_URL, namespaceId, videoId)
            }
        } else {
            const sourceUrl = String(body.sourceUrl || '').trim()
            if (!sourceUrl) return c.json({ error: 'source_url_required' }, 400)
            if (!videoId) videoId = crypto.randomUUID().replace(/-/g, '').slice(0, 8)

            const isXhs = /https?:\/\/(xhslink\.com|www\.xiaohongshu\.com)\S+/i.test(sourceUrl)
            sourceType = isXhs ? 'xhs_url' : 'telegram_video'
            sourceLabel = isXhs
                ? sourceUrl
                : (String(body.sourceLabel || '').trim().slice(0, 500) || 'Desktop URL')

            const materialized = await materializeOriginalVideoAsset({
                env: c.env,
                bucket,
                namespaceId,
                videoId,
                sourceType,
                sourceUrl,
            })
            originalVideoUrl = materialized.originalUrl
            thumbnailUrl = String(materialized.thumbnailUrl || '').trim()
                || getVideoOriginalThumbnailUrlForNamespace(c.env.R2_PUBLIC_URL, namespaceId, videoId)
        }

        const workerBase = String(c.env.WORKER_URL || '').trim().replace(/\/+$/, '')
        const frameUrlBase = workerBase
            ? `${workerBase}/api/gallery/${encodeURIComponent(videoId)}/frame?namespace_id=${encodeURIComponent(namespaceId)}`
            : ''

        return c.json({
            ok: true,
            namespace_id: namespaceId,
            video: {
                id: videoId,
                namespace_id: namespaceId,
                sourceMode,
                sourceType,
                sourceLabel,
                originalUrl: originalVideoUrl,
                thumbnailUrl,
                frameUrlBase,
            },
        })
    } catch (e) {
        return c.json({ error: String(e) }, 500)
    }
})

app.post('/api/desktop-submit', async (c) => {
    const authCheck = await requireAuthSession(c)
    if (!authCheck.ok) return authCheck.response

    try {
        const token = getSessionTokenFromRequest(c)
        const sessionUser = await c.env.DB.prepare(
            'SELECT email, namespace_id FROM users WHERE session_token = ? LIMIT 1'
        ).bind(token).first().catch(() => null) as { email?: string; namespace_id?: string } | null

        const namespaceId = String(sessionUser?.namespace_id || c.get('botId') || '').trim()
        const email = String(sessionUser?.email || '').trim().toLowerCase()
        if (!namespaceId || !email) return c.json({ error: 'unauthorized' }, 401)

        const currentNamespaceId = String(c.get('botId') || '').trim()
        const bucket = currentNamespaceId === namespaceId
            ? c.get('bucket')
            : new BotBucket(c.env.BUCKET, namespaceId) as unknown as R2Bucket

        const body = await c.req.json().catch(() => ({})) as {
            sourceMode?: 'upload' | 'url' | 'prepared'
            videoId?: string
            sourceUrl?: string
            sourceLabel?: string
            sourceType?: InboxVideoSourceType
            shopeeLink?: string
            lazadaLink?: string
            manualCaption?: string
            autoStart?: boolean
        }

        const sourceModeRaw = String(body.sourceMode || '').trim().toLowerCase()
        const sourceMode = sourceModeRaw === 'upload'
            ? 'upload'
            : sourceModeRaw === 'prepared'
                ? 'prepared'
                : 'url'
        const shopeeLink = pickFirstShopeeUrl(String(body.shopeeLink || '')) || ''
        const lazadaLink = pickFirstLazadaUrl(String(body.lazadaLink || '')) || ''
        const manualCaption = normalizeManualCaption(body.manualCaption)
        if (!shopeeLink || !lazadaLink) {
            return c.json({ error: 'missing_affiliate_links' }, 400)
        }

        const createdAt = new Date().toISOString()
        let videoId = String(body.videoId || '').trim()
        let originalVideoUrl = ''
        let sourceType: InboxVideoSourceType = 'telegram_video'
        let sourceLabel = 'Desktop upload'

        if (sourceMode === 'prepared') {
            if (!videoId) return c.json({ error: 'video_id_required' }, 400)
            const originalKey = getPrimaryOriginalVideoAssetKey(videoId)
            const originalObj = await bucket.head(originalKey).catch(() => null)
            if (!originalObj) return c.json({ error: 'prepared_video_not_found' }, 404)

            originalVideoUrl = getVideoOriginalUrlForNamespace(c.env.R2_PUBLIC_URL, namespaceId, videoId)
            const sourceTypeRaw = String(body.sourceType || '').trim().toLowerCase()
            sourceType = sourceTypeRaw === 'xhs_url'
                ? 'xhs_url'
                : sourceTypeRaw === 'line_video'
                    ? 'line_video'
                    : 'telegram_video'
            sourceLabel = String(body.sourceLabel || '').trim().slice(0, 500)
                || (sourceType === 'xhs_url' ? 'Desktop XHS URL' : 'Desktop upload')
            await backfillOriginalThumbnail(c.env, namespaceId, videoId).catch(() => ({ generated: false, thumbnailUrl: '' }))
        } else if (sourceMode === 'upload') {
            if (!videoId) return c.json({ error: 'video_id_required' }, 400)
            const originalKey = getPrimaryOriginalVideoAssetKey(videoId)
            const originalObj = await bucket.head(originalKey).catch(() => null)
            if (!originalObj) return c.json({ error: 'uploaded_video_not_found' }, 404)

            originalVideoUrl = getVideoOriginalUrlForNamespace(c.env.R2_PUBLIC_URL, namespaceId, videoId)
            sourceType = 'telegram_video'
            sourceLabel = 'Desktop upload'
            await backfillOriginalThumbnail(c.env, namespaceId, videoId).catch(() => ({ generated: false, thumbnailUrl: '' }))
        } else {
            const sourceUrl = String(body.sourceUrl || '').trim()
            if (!sourceUrl) return c.json({ error: 'source_url_required' }, 400)
            if (!videoId) videoId = crypto.randomUUID().replace(/-/g, '').slice(0, 8)

            const isXhs = /https?:\/\/(xhslink\.com|www\.xiaohongshu\.com)\S+/i.test(sourceUrl)
            sourceType = isXhs ? 'xhs_url' : 'telegram_video'
            sourceLabel = isXhs
                ? sourceUrl
                : (String(body.sourceLabel || '').trim().slice(0, 500) || 'Desktop URL')

            const materialized = await materializeOriginalVideoAsset({
                env: c.env,
                bucket,
                namespaceId,
                videoId,
                sourceType,
                sourceUrl,
            })
            originalVideoUrl = materialized.originalUrl
        }

        const chatId = await resolveSessionSubmissionChatId(c.env.DB, email)
        const inboxRecord = await putInboxVideoRecord(bucket, {
            id: videoId,
            videoUrl: originalVideoUrl,
            chatId,
            createdAt,
            updatedAt: createdAt,
            sourceType,
            sourceLabel,
            shopeeLink,
            lazadaLink,
            shopeeOriginalLink: shopeeLink,
            lazadaOriginalLink: lazadaLink,
            manualCaption,
            captionProvidedAt: manualCaption ? createdAt : '',
        })

        const autoStart = body.autoStart === true
        let result: InboxProcessingStartResult | null = null
        if (autoStart) {
            try {
                result = await ensureInboxVideoProcessingStarted({
                    env: c.env,
                    bucket,
                    executionCtx: c.executionCtx,
                    botId: namespaceId,
                    item: inboxRecord,
                })
            } catch (error) {
                if (error instanceof Error && error.message === 'managed_shortlink_conversion_failed') {
                    return c.json({
                        error: 'shortlink_failed',
                        message: 'ย่อลิ้ง Shopee/Lazada สำหรับ workspace นี้ไม่ผ่าน กรุณาลองใหม่',
                    }, 400)
                }
                throw error
            }
        }

        return c.json({
            ok: true,
            namespace_id: namespaceId,
            video: toInboxVideoResponse(inboxRecord, {
                namespaceId,
                originalUrl: originalVideoUrl,
                previewUrl: originalVideoUrl,
            }),
            job: result,
            processing_url: buildScopedTabWebAppUrl(getDesktopWebBaseUrl(c.env), namespaceId, 'processing'),
            gallery_url: buildScopedTabWebAppUrl(getDesktopWebBaseUrl(c.env), namespaceId, 'gallery'),
        })
    } catch (e) {
        return c.json({ error: e instanceof Error ? e.message : String(e) }, 500)
    }
})

app.post('/api/inbox/:id/process', async (c) => {
    try {
        const id = String(c.req.param('id') || '').trim()
        if (!id) return c.json({ error: 'missing_id' }, 400)

        const requestedNamespaceId = String(c.req.query('namespace_id') || '').trim()
        const currentNamespaceId = String(c.get('botId') || '').trim()
        let processBucket = c.get('bucket')

        // Try current namespace first
        let item = await getInboxVideoRecord(processBucket, id)

        // If not found and a different namespace was requested, look there and copy to current
        if (!item && requestedNamespaceId && requestedNamespaceId !== currentNamespaceId) {
            const sourceBucket = new BotBucket(c.env.BUCKET, requestedNamespaceId) as unknown as R2Bucket
            const sourceItem = await getInboxVideoRecord(sourceBucket, id)
            if (sourceItem) {
                item = await syncImportedOriginalIntoNamespace({
                    env: c.env,
                    targetNamespaceId: currentNamespaceId,
                    targetBucket: processBucket,
                    sourceNamespaceId: requestedNamespaceId,
                    sourceBucket,
                    sourceVideo: {
                        ...sourceItem,
                        id,
                    },
                }).catch(() => null)
                if (!item) {
                    item = await putInboxVideoRecord(processBucket, {
                        ...sourceItem,
                        updatedAt: new Date().toISOString(),
                    })
                }
            }
        }

        // If still not found, check all namespaces (for system inbox videos)
        if (!item) {
            const sysAdmin = await isSystemAdmin(c.env.DB, (await c.env.DB.prepare('SELECT email FROM users WHERE session_token = ?').bind(getSessionTokenFromRequest(c)).first() as any)?.email || '').catch(() => false)
            if (sysAdmin) {
                const allNamespaces = await c.env.DB.prepare('SELECT DISTINCT namespace_id FROM line_users').all().catch(() => ({ results: [] }))
                for (const row of (allNamespaces.results || [])) {
                    const ns = String((row as any).namespace_id || '').trim()
                    if (!ns || ns === currentNamespaceId) continue
                    const srcBucket = new BotBucket(c.env.BUCKET, ns) as unknown as R2Bucket
                    const srcItem = await getInboxVideoRecord(srcBucket, id).catch(() => null)
                    if (srcItem) {
                        item = await syncImportedOriginalIntoNamespace({
                            env: c.env,
                            targetNamespaceId: currentNamespaceId,
                            targetBucket: processBucket,
                            sourceNamespaceId: ns,
                            sourceBucket: srcBucket,
                            sourceVideo: {
                                ...srcItem,
                                id,
                            },
                        }).catch(() => null)
                        if (!item) {
                            item = await putInboxVideoRecord(processBucket, {
                                ...srcItem,
                                updatedAt: new Date().toISOString(),
                            })
                        }
                        break
                    }
                }
            }
        }

        if (!item) return c.json({ error: 'inbox_video_not_found' }, 404)
        if (item.status !== 'ready') return c.json({ error: 'inbox_video_not_ready' }, 400)

        let result: InboxProcessingStartResult
        try {
            result = await ensureInboxVideoProcessingStarted({
                env: c.env,
                bucket: processBucket,
                executionCtx: c.executionCtx,
                botId: String(c.get('botId') || '').trim(),
                item,
            })
        } catch (error) {
            if (error instanceof Error && error.message === 'managed_shortlink_conversion_failed') {
                return c.json({
                    error: 'shortlink_failed',
                    message: 'ย่อลิ้ง Shopee/Lazada สำหรับ workspace นี้ไม่ผ่าน กรุณาลองใหม่',
                }, 400)
            }
            throw error
        }
        if (result.outcome === 'already_running') {
            return c.json({ ok: true, job: { status: result.status, id } })
        }
        if (result.outcome === 'already_processed') {
            return c.json({ ok: true, job: { status: 'processed', id } })
        }
        return c.json({ ok: true, job: result.job })
    } catch (e) {
        return c.json({ error: String(e) }, 500)
    }
})

app.delete('/api/inbox/:id', async (c) => {
    try {
        const id = String(c.req.param('id') || '').trim()
        if (!id) return c.json({ error: 'missing_id' }, 400)

        const currentNamespaceId = String(c.get('botId') || '').trim()
        const requestedNamespaceId = String(c.req.query('namespace_id') || '').trim()
        const targetNamespaceId = requestedNamespaceId || currentNamespaceId
        if (targetNamespaceId !== currentNamespaceId) {
            return c.json({ error: 'cross_namespace_inbox_delete_forbidden' }, 403)
        }

        const bucket = targetNamespaceId === currentNamespaceId
            ? c.get('bucket')
            : new BotBucket(c.env.BUCKET, targetNamespaceId) as unknown as R2Bucket
        const [item, hasOriginalObject, hasOriginalThumb, hasProcessedVideo] = await Promise.all([
            getInboxVideoRecord(bucket, id).catch(() => null),
            Promise.all(getOriginalVideoAssetKeys(id).map((key) => bucket.head(key).catch(() => null))).then((heads) => heads.some(Boolean)),
            bucket.head(getOriginalThumbnailAssetKey(id)).catch(() => null).then(Boolean),
            bucket.head(`videos/${id}.mp4`).catch(() => null).then(Boolean),
        ])
        if (!item && !hasOriginalObject && !hasOriginalThumb) {
            return c.json({ error: 'inbox_video_not_found' }, 404)
        }

        await bucket.delete(`_inbox/${id}.json`).catch(() => { })
        const waitingKey = item ? `_waiting_video/${item.chatId}.json` : ''
        const waitingObj = waitingKey ? await bucket.get(waitingKey).catch(() => null) : null
        if (waitingObj) {
            const waiting = await waitingObj.json().catch(() => ({} as Record<string, unknown>)) as Record<string, unknown>
            if (String(waiting.id || '').trim() === id) {
                await bucket.delete(waitingKey).catch(() => { })
            }
        }

        const deleteTasks: Array<Promise<unknown>> = [
            bucket.delete(getOriginalThumbnailAssetKey(id)).catch(() => { }),
            bucket.delete(`_queue/${id}.json`).catch(() => { }),
            bucket.delete(`_processing/${id}.json`).catch(() => { }),
            ...getOriginalVideoAssetKeys(id).map((key) => bucket.delete(key).catch(() => { })),
        ]
        if (!hasProcessedVideo) {
            deleteTasks.push(
                bucket.delete(`videos/${id}.json`).catch(() => { }),
                bucket.delete(getProcessedThumbnailAssetKey(id)).catch(() => { }),
            )
        }
        await Promise.all(deleteTasks)

        if (hasProcessedVideo) {
            const metaObj = await bucket.get(`videos/${id}.json`).catch(() => null)
            if (metaObj) {
                const meta = await metaObj.json().catch(() => ({} as Record<string, unknown>)) as Record<string, unknown>
                delete meta.originalUrl
                delete meta.original_url
                delete meta.originalThumbnailUrl
                delete meta.original_thumbnail_url
                await bucket.put(`videos/${id}.json`, JSON.stringify(meta, null, 2), {
                    httpMetadata: { contentType: 'application/json' },
                })
                await updateGalleryCache(bucket, id).catch(() => { })
            }
        }

        if (!hasProcessedVideo) {
            await removeFromGalleryCache(bucket, id).catch(() => { })
        }
        await removeInboxRecordFromPrimaryAdminSnapshot({
            env: c.env,
            sourceNamespaceId: targetNamespaceId,
            videoId: id,
        }).catch(() => { })
        await syncGalleryIndexEntry(c.env, targetNamespaceId, id).catch((error) => {
            console.log(`[INBOX-DELETE] sync gallery index failed ns=${targetNamespaceId} video=${id}: ${error instanceof Error ? error.message : String(error)}`)
        })
        await c.env.BUCKET.delete('_admin_cache/all_gallery_videos.json').catch(() => { })
        await c.env.BUCKET.delete('_admin_cache/all_gallery_owner_videos.json').catch(() => { })
        return c.json({ ok: true, kept_processed_video: hasProcessedVideo })
    } catch (e) {
        return c.json({ error: String(e) }, 500)
    }
})

app.delete('/api/processing/:id', async (c) => {
    try {
        const id = String(c.req.param('id') || '').trim()
        const existing = id ? await c.get('bucket').get(`_processing/${id}.json`).catch(() => null) : null
        const nowIso = new Date().toISOString()
        if (id && existing) {
            const job = await existing.json().catch(() => ({} as Record<string, unknown>)) as Record<string, unknown>
            await putProcessingHistoryRecord(c.get('bucket'), id, {
                ...job,
                id,
                status: 'cancelled',
                cancelledAt: nowIso,
                updatedAt: nowIso,
                error: sanitizeProcessingError(job.error || 'ผู้ใช้ยกเลิกงานประมวลผล'),
            }).catch(() => { })
        }
        if (id) await c.get('bucket').delete(`_processing/${id}.json`)
        c.executionCtx.waitUntil(dispatchNextProcessingJobForNamespace(c.env, c.executionCtx, c.get('botId'), { runInline: false }))
        return c.json({ ok: true })
    } catch (e) {
        return c.json({ error: String(e) }, 500)
    }
})

app.post('/api/processing/:id/reprocess', async (c) => {
    try {
        const id = String(c.req.param('id') || '').trim()
        if (!id) return c.json({ error: 'missing_id' }, 400)

        const existing = await c.get('bucket').get(`_processing/${id}.json`)
        if (!existing) return c.json({ error: 'processing_not_found' }, 404)

        const job = await existing.json() as {
            id?: string
            videoUrl?: string
            shopeeLink?: string
            lazadaLink?: string
            manualCaption?: string
            chatId?: number
            retryCount?: number
            sourceType?: string
            sourceLabel?: string
            skipSubtitles?: boolean
        }

        const linkContextObj = await c.get('bucket').get(`_link_context/${id}.json`).catch(() => null)
        const linkContext = linkContextObj
            ? await linkContextObj.json().catch(() => ({} as Record<string, unknown>)) as {
                videoUrl?: string
                shopeeLink?: string
                lazadaLink?: string
                manualCaption?: string
                chatId?: number
                sourceType?: string
                sourceLabel?: string
            }
            : null

        const videoUrl = String(job.videoUrl || linkContext?.videoUrl || '').trim()
        const chatIdRaw = Number(job.chatId ?? linkContext?.chatId ?? 0)
        const chatId = Number.isFinite(chatIdRaw) && chatIdRaw >= 0 ? chatIdRaw : 0
        if (!videoUrl) {
            return c.json({ error: 'processing_payload_invalid' }, 400)
        }

        // Preserve the AI-clip source marker on the requeued handoff. AI-only namespaces
        // drain the queue via drainAiClipQueueOnlyForNamespace, which DELETES non-AI handoffs;
        // without this an operator reprocessing a failed AI clip would have it silently dropped.
        // Legacy app.oomnn jobs carry no sourceType, so they stay plain and drain via the
        // legacy processNextInQueue path instead.
        const sourceType = String(job.sourceType || linkContext?.sourceType || '').trim()
        const sourceLabel = String(job.sourceLabel || linkContext?.sourceLabel || '').trim()
        const queuedJob = {
            id,
            videoUrl,
            shopeeLink: String(job.shopeeLink || linkContext?.shopeeLink || '').trim(),
            lazadaLink: String(job.lazadaLink || linkContext?.lazadaLink || '').trim(),
            manualCaption: normalizeManualCaption(job.manualCaption || linkContext?.manualCaption || ''),
            chatId,
            createdAt: new Date().toISOString(),
            status: 'queued',
            retryCount: Number(job.retryCount || 0),
            ...(sourceType ? { sourceType } : {}),
            ...(sourceLabel ? { sourceLabel } : {}),
            ...(typeof job.skipSubtitles === 'boolean' ? { skipSubtitles: job.skipSubtitles } : {}),
        }

        await c.get('bucket').delete(`_processing/${id}.json`)
        await c.get('bucket').put(`_queue/${id}.json`, JSON.stringify(queuedJob), {
            httpMetadata: { contentType: 'application/json' },
        })
        c.executionCtx.waitUntil(dispatchNextProcessingJobForNamespace(c.env, c.executionCtx, c.get('botId'), { runInline: false }))
        return c.json({ ok: true, job: queuedJob })
    } catch (e) {
        return c.json({ error: String(e) }, 500)
    }
})

