// ==================== GALLERY API (R2) ====================

app.get('/api/gallery', async (c) => {
    const currentNamespaceId = String(c.get('botId') || '').trim()
    const offset = parseNonNegativeInt(c.req.query('offset'), 0)
    const requestedLimit = parseNonNegativeInt(c.req.query('limit'), 24)
    const limit = Math.min(Math.max(requestedLimit, 1), 120)
    const forceFresh = String(c.req.query('fresh') || '').trim() === '1' && offset === 0
    const searchQuery = normalizeGallerySearchQuery(c.req.query('q'))
    const linkFilterRaw = String(c.req.query('link_filter') || '').trim().toLowerCase()
    const linkFilter = linkFilterRaw === 'no-link'
        ? 'no-link'
        : linkFilterRaw === 'with-link'
            ? 'with-link'
            : 'all'
    const storeFilterRaw = String(c.req.query('store_filter') || '').trim().toLowerCase()
    const storeFilter = storeFilterRaw === 'lazada'
        ? 'lazada'
        : storeFilterRaw === 'shopee'
            ? 'shopee'
            : 'all'
    try {
        // Fallback once while gallery_index is still warming or not backfilled yet.
        c.executionCtx.waitUntil(rebuildGalleryIndexFromR2(c.env).catch((error) => {
            console.log(`[GALLERY-INDEX] warmup rebuild failed: ${error instanceof Error ? error.message : String(error)}`)
        }))

        const inventory = await getNamespaceGalleryInventory(c.env, currentNamespaceId)
        const videos = inventory.videos
        const readyVideos = videos.filter((video) => {
            const row = video as Record<string, unknown>
            return isNamespaceGalleryVideoDisplayReady(row) && !isNamespaceGalleryVideoPosted(row)
        })

        // Sort unposted videos so that videos manually moved back from "posted" tab
        // (via the amber refresh button) appear at the very top — newest first.
        // Falls back to processed_at / created_at when manualUnpostedAt is empty.
        const getReadySortMs = (video: Record<string, unknown>): number => {
            const candidates = [
                video.manualUnpostedAt,
                video.manual_unposted_at,
                video.processedAt,
                video.processed_at,
                video.updatedAt,
                video.updated_at,
                video.createdAt,
                video.created_at,
            ]
            for (const candidate of candidates) {
                const ts = new Date(String(candidate || '')).getTime()
                if (Number.isFinite(ts) && ts > 0) return ts
            }
            return 0
        }
        readyVideos.sort((a, b) => getReadySortMs(b as Record<string, unknown>) - getReadySortMs(a as Record<string, unknown>))

        const overallTotal = readyVideos.length
        const shopeeVideos = readyVideos.filter((video) => !hasLazadaLinkInMeta(video as Record<string, unknown>))
        const lazadaVideos = readyVideos.filter((video) => hasLazadaLinkInMeta(video as Record<string, unknown>))
        const searchedVideos = searchQuery
            ? readyVideos.filter((video) => matchesGallerySearchQuery(video as Record<string, unknown>, searchQuery))
            : readyVideos
        const storeScopedVideos = storeFilter === 'lazada'
            ? searchedVideos.filter((video) => hasLazadaLinkInMeta(video as Record<string, unknown>))
            : storeFilter === 'shopee'
                ? searchedVideos.filter((video) => !hasLazadaLinkInMeta(video as Record<string, unknown>))
                : searchedVideos
        const withLinkVideos = storeScopedVideos.filter((video) => hasAffiliateLinkInMeta(video as Record<string, unknown>))
        const withoutLinkVideos = storeScopedVideos.filter((video) => !hasAffiliateLinkInMeta(video as Record<string, unknown>))
        const filteredVideos = linkFilter === 'no-link'
            ? withoutLinkVideos
            : linkFilter === 'with-link'
                ? withLinkVideos
                : storeScopedVideos
        const page = sliceGalleryPage(filteredVideos, offset, limit)
        const bucket = c.get('bucket')
        const pageVideos = await Promise.all(page.videos.map(async (video) => {
            const currentVideo = video as Record<string, unknown>
            const videoId = String(currentVideo.id || '').trim()
            const currentManualCaption = normalizeManualCaption(currentVideo.manualCaption || currentVideo.caption || '')
            if (!videoId || currentManualCaption) return video

            const metaObj = await bucket.get(`videos/${videoId}.json`).catch(() => null)
            if (!metaObj) return video
            const meta = await metaObj.json().catch(() => ({} as Record<string, unknown>)) as Record<string, unknown>
            const manualCaption = normalizeManualCaption(meta.manualCaption || meta.caption || '')
            const captionProvidedAt = String(meta.captionProvidedAt || meta.caption_provided_at || '').trim()
            if (!manualCaption && !captionProvidedAt) return video

            return {
                ...currentVideo,
                manualCaption,
                hasManualCaption: !!manualCaption,
                captionProvidedAt: captionProvidedAt || undefined,
            }
        }))

        return c.json({
            videos: pageVideos,
            total: filteredVideos.length,
            overall_total: overallTotal,
            ready_total: overallTotal,
            used_total: videos.filter((video) => isNamespaceGalleryVideoVisibleInUsedTab(video as Record<string, unknown>)).length,
            inventory_total: videos.length,
            library_total: inventory.sourceTotal,
            offset,
            limit,
            has_more: page.hasMore,
            shopee_total: shopeeVideos.length,
            lazada_total: lazadaVideos.length,
            with_link_total: withLinkVideos.length,
            without_link_total: withoutLinkVideos.length,
        }, 200, {
            'Cache-Control': 'private, no-store',
            'Vary': 'x-auth-token',
        })
    } catch (e) {
        return c.json({ videos: [], error: String(e) })
    }
})

app.get('/api/gallery/system', async (c) => {
    try {
        const offset = parseNonNegativeInt(c.req.query('offset'), 0)
        const requestedLimit = parseNonNegativeInt(c.req.query('limit'), 24)
        const limit = Math.min(Math.max(requestedLimit, 1), 120)
        const forceFresh = String(c.req.query('fresh') || '').trim() === '1' && offset === 0
        const fastRequested = String(c.req.query('fast') || '').trim() === '1'
        const view = String(c.req.query('view') || '').trim().toLowerCase() === 'used' ? 'used' : 'ready'
        const token = getSessionTokenFromRequest(c)
        if (!token.startsWith('sess_')) return c.json({ error: 'Unauthorized' }, 401)

        const me = await c.env.DB.prepare(
            'SELECT email FROM users WHERE session_token = ?'
        ).bind(token).first() as { email?: string } | null
        if (!me?.email) return c.json({ error: 'Unauthorized' }, 401)

        const sysAdmin = await isSystemAdmin(c.env.DB, me.email)
        if (!sysAdmin) return c.json({ error: 'Forbidden' }, 403)

        const searchQuery = normalizeGallerySearchQuery(c.req.query('q'))
        if (fastRequested && !searchQuery) {
            const page = await getSystemGalleryPageFast(c.env.DB, {
                view,
                offset,
                limit,
            })

            return c.json({
                videos: page.videos,
                total: page.total,
                overall_total: page.overallTotal,
                ready_total: page.readyTotal,
                used_total: page.usedTotal,
                pending_total: 0,
                pending_has_lazada_total: 0,
                pending_missing_lazada_total: 0,
                inventory_total: page.inventoryTotal,
                library_total: page.libraryTotal,
                shopee_total: 0,
                lazada_total: 0,
                with_link_total: 0,
                without_link_total: 0,
                has_more: page.hasMore,
                offset,
                limit,
                view,
                fast: true,
            }, 200, {
                'Cache-Control': forceFresh
                    ? 'private, no-store'
                    : (offset === 0
                        ? 'private, max-age=15, stale-while-revalidate=60'
                        : 'private, max-age=30, stale-while-revalidate=120'),
                'Vary': 'x-auth-token',
            })
        }

        const inventory = await getSystemGalleryInventory(c.env)
        const allVideos = inventory.videos
        const readyVideos = allVideos.filter((video) => {
            const row = video as Record<string, unknown>
            return isNamespaceGalleryVideoDisplayReady(row) && !isNamespaceGalleryVideoPosted(row)
        })
        const usedVideos = allVideos.filter((video) => {
            const row = video as Record<string, unknown>
            return isNamespaceGalleryVideoVisibleInUsedTab(row)
        })
        const sourceVideos = view === 'used'
            ? sortUsedGalleryVideosNewestFirst(usedVideos as Array<Record<string, unknown>>)
            : readyVideos
        const searchedVideos = searchQuery
            ? sourceVideos.filter((video) => matchesGallerySearchQuery(video as Record<string, unknown>, searchQuery))
            : sourceVideos
        const page = sliceGalleryPage(searchedVideos, offset, limit)
        const pendingVideos = allVideos.filter((video) => !Boolean((video as Record<string, unknown>).gallery_ready))
        const pendingHasLazadaTotal = pendingVideos.filter((video) =>
            String((video as Record<string, unknown>).pending_bucket || '').trim() === 'has-lazada'
        ).length
        const withLinkTotal = sourceVideos.filter((video) => hasAffiliateLinkInMeta(video as Record<string, unknown>)).length

        return c.json({
            videos: page.videos,
            total: searchedVideos.length,
            overall_total: sourceVideos.length,
            ready_total: readyVideos.length,
            used_total: usedVideos.length,
            pending_total: pendingVideos.length,
            pending_has_lazada_total: pendingHasLazadaTotal,
            pending_missing_lazada_total: Math.max(0, pendingVideos.length - pendingHasLazadaTotal),
            inventory_total: allVideos.length,
            library_total: inventory.sourceTotal,
            shopee_total: sourceVideos.filter((video) => !hasLazadaLinkInMeta(video as Record<string, unknown>)).length,
            lazada_total: sourceVideos.filter((video) => hasLazadaLinkInMeta(video as Record<string, unknown>)).length,
            with_link_total: withLinkTotal,
            without_link_total: Math.max(0, sourceVideos.length - withLinkTotal),
            has_more: page.hasMore,
            offset,
            limit,
            view,
        }, 200, {
            'Cache-Control': 'private, no-store',
            'Vary': 'x-auth-token',
        })
    } catch (e) {
        return c.json({ videos: [], error: String(e) }, 500)
    }
})

app.post('/api/gallery/import', async (c) => {
    try {
        // 1. Auth: verify system admin
        const token = getSessionTokenFromRequest(c)
        if (!token.startsWith('sess_')) return c.json({ error: 'Unauthorized' }, 401)

        const me = await c.env.DB.prepare(
            'SELECT email FROM users WHERE session_token = ?'
        ).bind(token).first() as { email?: string } | null
        if (!me?.email) return c.json({ error: 'Unauthorized' }, 401)

        const sysAdmin = await isSystemAdmin(c.env.DB, me.email)
        if (!sysAdmin) return c.json({ error: 'Forbidden' }, 403)

        // 2. Parse body
        const body = await c.req.json() as { video_id?: string; source_namespace_id?: string }
        const videoId = String(body.video_id || '').trim()
        const sourceNamespaceId = String(body.source_namespace_id || '').trim()
        if (!videoId) return c.json({ error: 'video_id is required' }, 400)
        if (!sourceNamespaceId) return c.json({ error: 'source_namespace_id is required' }, 400)

        // 3. Get admin's namespace
        const adminNs = await c.env.DB.prepare(
            'SELECT namespace_id FROM email_namespaces WHERE email = ? LIMIT 1'
        ).bind(me.email.trim().toLowerCase()).first() as { namespace_id?: string } | null
        const adminNamespaceId = String(adminNs?.namespace_id || '').trim()
        if (!adminNamespaceId) return c.json({ error: 'Admin namespace not found' }, 400)

        if (adminNamespaceId === sourceNamespaceId) {
            return c.json({ error: 'Cannot import from your own namespace' }, 400)
        }

        // 4. Validate source video exists
        const sourceBucket = new BotBucket(c.env.BUCKET, sourceNamespaceId) as unknown as R2Bucket
        const sourceMetaKey = `videos/${videoId}.json`
        const sourceMetaObj = await sourceBucket.get(sourceMetaKey)
        if (!sourceMetaObj) return c.json({ error: 'Source video not found' }, 404)
        const sourceMeta = await sourceMetaObj.json() as Record<string, unknown>

        // 5. Import as original-only into admin namespace; never reuse processed output from source namespace
        const adminBucket = new BotBucket(c.env.BUCKET, adminNamespaceId) as unknown as R2Bucket
        const importedRecord = await syncImportedOriginalIntoNamespace({
            env: c.env,
            targetNamespaceId: adminNamespaceId,
            targetBucket: adminBucket,
            sourceNamespaceId,
            sourceBucket,
            sourceVideo: {
                ...sourceMeta,
                id: videoId,
            },
        })
        if (!importedRecord) return c.json({ error: 'Import failed' }, 500)

        // 6. Invalidate caches
        await c.env.BUCKET.delete('_admin_cache/all_gallery_videos.json').catch(() => { })
        await c.env.BUCKET.delete('_admin_cache/all_gallery_owner_videos.json').catch(() => { })

        // 7. Return success
        return c.json({
            success: true,
            video: importedRecord,
        })
    } catch (e) {
        return c.json({ error: `import_failed: ${e instanceof Error ? e.message : String(e)}` }, 500)
    }
})

app.post('/api/gallery/restore-links', async (c) => {
    const owner = await requireOwnerSession(c)
    if (!owner.ok) return owner.response

    try {
        const currentNamespaceId = String(c.get('botId') || '').trim()
        const enabled = await isSystemGalleryEnabledForNamespace(c.env.DB, currentNamespaceId)
        if (!enabled) {
            return c.json({ error: 'system_gallery_not_enabled' }, 403)
        }

        const [submissionRows, historyRows] = await Promise.all([
            c.env.DB.prepare(
                "SELECT video_id, shopee_link, created_at AS ts FROM link_submissions WHERE TRIM(COALESCE(shopee_link,'')) <> ''"
            ).all() as Promise<{ results?: Array<{ video_id?: string; shopee_link?: string; ts?: string }> }>,
            c.env.DB.prepare(
                "SELECT video_id, shopee_link, posted_at AS ts FROM post_history WHERE TRIM(COALESCE(shopee_link,'')) <> ''"
            ).all() as Promise<{ results?: Array<{ video_id?: string; shopee_link?: string; ts?: string }> }>,
        ])

        const linksByVideoId = new Map<string, Map<string, string>>()
        const collect = (videoIdRaw: string | undefined, shopeeLinkRaw: string | undefined, tsRaw: string | undefined) => {
            const videoId = String(videoIdRaw || '').trim()
            const shopeeLink = pickFirstShopeeUrl(shopeeLinkRaw || '') || ''
            const ts = String(tsRaw || '').trim()
            if (!videoId || !shopeeLink) return
            let linkMap = linksByVideoId.get(videoId)
            if (!linkMap) {
                linkMap = new Map<string, string>()
                linksByVideoId.set(videoId, linkMap)
            }
            const prevTs = String(linkMap.get(shopeeLink) || '').trim()
            if (!prevTs || ts > prevTs) {
                linkMap.set(shopeeLink, ts)
            }
        }

        for (const row of submissionRows.results || []) collect(row.video_id, row.shopee_link, row.ts)
        for (const row of historyRows.results || []) collect(row.video_id, row.shopee_link, row.ts)

        const exactMatchLinks = new Map<string, string>()
        let conflictingVideos = 0
        for (const [videoId, linkMap] of linksByVideoId.entries()) {
            const links = Array.from(linkMap.keys())
            if (links.length === 1) {
                exactMatchLinks.set(videoId, links[0] || '')
            } else if (links.length > 1) {
                conflictingVideos += 1
            }
        }

        const videos = dedupeVideosById(await getAllSystemGalleryVideos(c.env))
        const currentWithLink = videos.reduce((sum, video) => sum + (hasAffiliateLinkInMeta(video) ? 1 : 0), 0)

        const restoreTargets = videos.filter((video) => {
            const videoId = String(video?.id || '').trim()
            if (!videoId) return false
            if (hasAffiliateLinkInMeta(video)) return false
            return exactMatchLinks.has(videoId)
        })

        const touchedNamespaces = new Set<string>()
        const nowIso = new Date().toISOString()
        const batchSize = 25
        let restoredCount = 0
        for (let i = 0; i < restoreTargets.length; i += batchSize) {
            const slice = restoreTargets.slice(i, i + batchSize)
            const results = await Promise.all(slice.map(async (video) => {
                const videoId = String(video?.id || '').trim()
                const namespaceId = String(video?.namespace_id || '').trim()
                const restoredLink = String(exactMatchLinks.get(videoId) || '').trim()
                if (!videoId || !namespaceId || !restoredLink) return false

                const targetBucket = namespaceId === currentNamespaceId
                    ? c.get('bucket')
                    : new BotBucket(c.env.BUCKET, namespaceId) as unknown as R2Bucket

                const currentMetaObj = await targetBucket.get(`videos/${videoId}.json`)
                let meta: Record<string, unknown> = {}
                if (currentMetaObj) {
                    meta = await currentMetaObj.json() as Record<string, unknown>
                } else {
                    const [originalObj, publicObj, thumbObj] = await Promise.all([
                        targetBucket.head(`videos/${videoId}_original.mp4`).catch(() => null),
                        targetBucket.head(`videos/${videoId}.mp4`).catch(() => null),
                        targetBucket.head(`videos/${videoId}_thumb.webp`).catch(() => null),
                    ])
                    const uploadedAt = originalObj?.uploaded?.toISOString?.() || publicObj?.uploaded?.toISOString?.() || nowIso
                    const originalUrl = originalObj
                        ? (namespaceId === 'default'
                            ? `${c.env.R2_PUBLIC_URL}/videos/${videoId}_original.mp4`
                            : `${c.env.R2_PUBLIC_URL}/${namespaceId}/videos/${videoId}_original.mp4`)
                        : ''
                    const publicUrl = publicObj
                        ? getVideoPublicUrlForNamespace(c.env.R2_PUBLIC_URL, namespaceId, videoId)
                        : (originalUrl || getVideoPublicUrlForNamespace(c.env.R2_PUBLIC_URL, namespaceId, videoId))
                    meta = {
                        createdAt: uploadedAt,
                        updatedAt: uploadedAt,
                        duration: 0,
                        script: '',
                        title: '',
                        category: '',
                        originalUrl: originalUrl || publicUrl,
                        publicUrl,
                        thumbnailUrl: thumbObj ? getVideoThumbnailUrlForNamespace(c.env.R2_PUBLIC_URL, namespaceId, videoId) : '',
                    }
                }
                meta.shopeeLink = restoredLink
                meta.updatedAt = nowIso
                if (!String(meta.linkSubmittedAt || '').trim()) {
                    meta.linkSubmittedAt = nowIso
                }

                await targetBucket.put(`videos/${videoId}.json`, JSON.stringify(meta, null, 2), {
                    httpMetadata: { contentType: 'application/json' },
                })
                await syncGalleryIndexEntry(c.env, namespaceId, videoId).catch((error) => {
                    console.log(`[RESTORE-LINKS] sync gallery index failed ns=${namespaceId} video=${videoId}: ${error instanceof Error ? error.message : String(error)}`)
                })
                touchedNamespaces.add(namespaceId)
                return true
            }))
            restoredCount += results.filter(Boolean).length
        }

        for (const namespaceId of touchedNamespaces) {
            await rebuildGalleryCache(c.env.BUCKET, namespaceId).catch((e) => {
                console.log(`[RESTORE-LINKS] rebuild gallery cache failed ns=${namespaceId}: ${e instanceof Error ? e.message : String(e)}`)
            })
        }
        await c.env.BUCKET.delete('_admin_cache/all_gallery_videos.json').catch(() => { })
        await c.env.BUCKET.delete('_admin_cache/all_gallery_owner_videos.json').catch(() => { })

        const finalVideos = dedupeVideosById(await getAllSystemGalleryVideos(c.env))
        const finalWithLink = finalVideos.reduce((sum, video) => sum + (hasAffiliateLinkInMeta(video) ? 1 : 0), 0)

        return c.json({
            success: true,
            total_videos: videos.length,
            current_with_link: currentWithLink,
            restored_count: restoredCount,
            final_with_link: finalWithLink,
            exact_match_videos_total: exactMatchLinks.size,
            conflicting_videos_total: conflictingVideos,
            unresolved_videos_total: Math.max(0, videos.length - exactMatchLinks.size - conflictingVideos),
        })
    } catch (e) {
        return c.json({ error: `restore_links_failed: ${e instanceof Error ? e.message : String(e)}` }, 500)
    }
})

// Get videos that have been posted (used videos)
app.get('/api/gallery/used', async (c) => {
    const r2Url = c.env.R2_PUBLIC_URL
    const botId = c.get('botId')
    const offset = parseNonNegativeInt(c.req.query('offset'), 0)
    const requestedLimit = parseNonNegativeInt(c.req.query('limit'), 24)
    const limit = Math.min(Math.max(requestedLimit, 1), 120)
    const forceFresh = String(c.req.query('fresh') || '').trim() === '1' && offset === 0
    const searchQuery = normalizeGallerySearchQuery(c.req.query('q'))
    const fixUrls = (data: any) => {
        const s = JSON.stringify(data)
        return JSON.parse(s.replace(/https:\/\/pub-[a-f0-9]+\.r2\.dev\/videos\//g, `${r2Url}/${botId}/videos/`))
    }
    try {
        const inventory = await getNamespaceGalleryInventory(c.env, String(botId || '').trim())
        const videos = sortUsedGalleryVideosNewestFirst(
            dedupeVideosById(inventory.videos)
            .filter((video: any) => isNamespaceGalleryVideoVisibleInUsedTab(video as Record<string, unknown>))
        )

        const searchedVideos = searchQuery
            ? videos.filter((video: any) => matchesGallerySearchQuery(video as Record<string, unknown>, searchQuery))
            : videos
        const page = sliceGalleryPage(searchedVideos, offset, limit)

        return c.json(fixUrls({
            videos: page.videos,
            total: searchedVideos.length,
            overall_total: videos.length,
            offset,
            limit,
            has_more: page.hasMore,
        }), 200, {
            'Cache-Control': 'private, no-store',
            'Vary': 'x-auth-token',
        })
    } catch (e) {
        return c.json({ videos: [], error: String(e) }, 500)
    }
})

// Get original videos across all namespaces (owner/admin view)
const getAllOriginalGallery = async (
    c: Context<{ Bindings: Env, Variables: { botId: string; bucket: R2Bucket } }>
) => {
    try {
        const token = getSessionTokenFromRequest(c)
        if (!token.startsWith('sess_')) return c.json({ error: 'Unauthorized' }, 401)

        const me = await c.env.DB.prepare(
            'SELECT email FROM users WHERE session_token = ?'
        ).bind(token).first() as { email?: string } | null
        if (!me?.email) return c.json({ error: 'Unauthorized' }, 401)

        const ownerCheck = await isNamespaceOwner(c.env.DB, me.email)
        if (!ownerCheck) return c.json({ error: 'Forbidden' }, 403)

        const cacheKey = '_admin_cache/all_original_videos.json'
        const cached = await c.env.BUCKET.get(cacheKey)
        if (cached) {
            const payload = await cached.json() as { created_at?: string; videos?: unknown[] }
            const createdAt = payload?.created_at ? new Date(payload.created_at).getTime() : 0
            if (createdAt > 0 && (Date.now() - createdAt) < 60_000) {
                return c.json({ videos: payload.videos || [] }, 200, { 'Cache-Control': 'private, max-age=30', 'Vary': 'x-auth-token' })
            }
        }

        const namespaceEmailMap = new Map<string, string>()
        try {
            const nsRows = await c.env.DB.prepare(
                'SELECT namespace_id, MIN(email) AS email FROM users WHERE namespace_id IS NOT NULL AND TRIM(namespace_id) <> \'\' GROUP BY namespace_id'
            ).all() as { results?: Array<{ namespace_id?: string; email?: string }> }
            for (const row of nsRows.results || []) {
                const ns = String(row.namespace_id || '').trim()
                if (!ns) continue
                namespaceEmailMap.set(ns, String(row.email || '').trim().toLowerCase())
            }
        } catch {
            // Best effort only.
        }

        const videos: Array<{
            id: string
            video_id: string
            namespace_id: string
            owner_email: string
            original_url: string
            source_key: string
            created_at: string
            size: number
        }> = []

        let cursor: string | undefined = undefined
        do {
            const listed = await c.env.BUCKET.list({ prefix: '', cursor })
            for (const obj of listed.objects) {
                const key = String(obj.key || '')
                const match = key.match(/^([^/]+)\/videos\/(.+)_original\.mp4$/)
                if (!match) continue

                const namespaceId = String(match[1] || '').trim()
                const videoId = String(match[2] || '').trim()
                if (!namespaceId || !videoId) continue

                videos.push({
                    id: `${namespaceId}:${videoId}`,
                    video_id: videoId,
                    namespace_id: namespaceId,
                    owner_email: namespaceEmailMap.get(namespaceId) || '',
                    original_url: `${c.env.R2_PUBLIC_URL}/${namespaceId}/videos/${videoId}_original.mp4`,
                    source_key: key,
                    created_at: obj.uploaded.toISOString(),
                    size: Number(obj.size || 0),
                })
            }
            cursor = listed.truncated ? listed.cursor : undefined
        } while (cursor)

        videos.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime())

        await c.env.BUCKET.put(cacheKey, JSON.stringify({
            created_at: new Date().toISOString(),
            videos,
        }), {
            httpMetadata: { contentType: 'application/json' },
        })

        return c.json({ videos }, 200, { 'Cache-Control': 'private, max-age=30', 'Vary': 'x-auth-token' })
    } catch (e) {
        return c.json({ videos: [], error: String(e) }, 500)
    }
}

app.get('/api/admin/gallery/all-original', getAllOriginalGallery)
app.get('/api/gallery/all-original', getAllOriginalGallery)

app.put('/api/gallery/:id', async (c) => {
    const id = c.req.param('id')
    try {
        const body = await c.req.json() as {
            shopeeLink?: string
            lazadaLink?: string
            category?: string
            title?: string
            manualCaption?: string
            keepInPostedTab?: boolean
            resetPostedState?: boolean
            namespace_id?: string
            namespaceId?: string
        }
        const currentNamespaceId = c.get('botId')
        const requestedNamespaceId = String(body.namespace_id ?? body.namespaceId ?? c.req.query('namespace_id') ?? '').trim()
        const targetNamespaceId = requestedNamespaceId || currentNamespaceId
        if (targetNamespaceId !== currentNamespaceId) {
            return c.json({ error: 'cross_namespace_gallery_write_forbidden' }, 403)
        }
        const targetBucket = targetNamespaceId === currentNamespaceId
            ? c.get('bucket')
            : new BotBucket(c.env.BUCKET, targetNamespaceId) as unknown as R2Bucket
        const metaObj = await targetBucket.get(`videos/${id}.json`)
        let meta: Record<string, unknown> = {}
        if (metaObj) {
            meta = await metaObj.json() as Record<string, unknown>
        } else {
            const originalObj = await targetBucket.get(`videos/${id}_original.mp4`)
            const publicObj = await targetBucket.get(`videos/${id}.mp4`)
            const thumbObj = await targetBucket.head(`videos/${id}_thumb.webp`).catch(() => null)
            const sourceObj = originalObj || publicObj
            if (!sourceObj) return c.json({ error: 'Video not found' }, 404)
            const uploadedAt = sourceObj.uploaded.toISOString()
            const originalUrl = originalObj
                ? (targetNamespaceId === 'default'
                    ? `${c.env.R2_PUBLIC_URL}/videos/${id}_original.mp4`
                    : `${c.env.R2_PUBLIC_URL}/${targetNamespaceId}/videos/${id}_original.mp4`)
                : ''
            const publicUrl = publicObj
                ? getVideoPublicUrlForNamespace(c.env.R2_PUBLIC_URL, targetNamespaceId, id)
                : (originalUrl || getVideoPublicUrlForNamespace(c.env.R2_PUBLIC_URL, targetNamespaceId, id))
            meta = {
                id,
                namespace_id: targetNamespaceId,
                createdAt: uploadedAt,
                updatedAt: uploadedAt,
                duration: 0,
                script: '',
                title: '',
                category: '',
                originalUrl: originalUrl || publicUrl,
                publicUrl,
                thumbnailUrl: thumbObj ? getVideoThumbnailUrlForNamespace(c.env.R2_PUBLIC_URL, targetNamespaceId, id) : '',
            }
        }
        meta.id = String(meta.id || id).trim() || id
        meta.namespace_id = String(meta.namespace_id || targetNamespaceId).trim() || targetNamespaceId
        const shopeeExpectedUtmId = await resolveNamespaceShopeeShortlinkExpectedUtmId(c.env.DB, targetNamespaceId).catch(() => '')
        const lazadaExpectedMemberId = await resolveNamespaceLazadaExpectedMemberId(c.env.DB, targetNamespaceId).catch(() => '')
        let changed = false
        let touchedAffiliateFields = false
        const nextStateFields: Partial<NamespaceVideoStateRow> = {}
        if (body.shopeeLink !== undefined) {
            const normalizedShopeeLink = String(body.shopeeLink || '').trim()
            if (normalizedShopeeLink) {
                meta.shopeeLink = normalizedShopeeLink
                meta.shopeeOriginalLink = isLikelyConvertedShopeeLink(normalizedShopeeLink, shopeeExpectedUtmId)
                    ? (getVideoSourceShopeeLink(meta) || normalizedShopeeLink)
                    : normalizedShopeeLink
                meta.linkSubmittedAt = new Date().toISOString()
                nextStateFields.shopee_link = normalizedShopeeLink
                nextStateFields.shopee_original_link = String(meta.shopeeOriginalLink || '').trim()
                if (isLikelyConvertedShopeeLink(normalizedShopeeLink, shopeeExpectedUtmId)) {
                    meta.shopeeConvertedAt = new Date().toISOString()
                    delete meta.shopeeConversionError
                    nextStateFields.shopee_converted_at = String(meta.shopeeConvertedAt || '').trim()
                } else {
                    delete meta.shopeeConvertedAt
                    nextStateFields.shopee_converted_at = ''
                }
            } else {
                meta.shopeeLink = ''
                delete meta.shopeeOriginalLink
                delete meta.shopeeConvertedAt
                delete meta.shopeeConversionError
                nextStateFields.shopee_link = ''
                nextStateFields.shopee_original_link = ''
                nextStateFields.shopee_converted_at = ''
            }
            changed = true
            touchedAffiliateFields = true
        }
        if (body.lazadaLink !== undefined) {
            const normalizedLazadaLink = String(body.lazadaLink || '').trim()
            if (normalizedLazadaLink) {
                meta.lazadaLink = normalizedLazadaLink
                meta.lazadaOriginalLink = isLikelyConvertedLazadaLink(normalizedLazadaLink)
                    ? (getVideoSourceLazadaLink(meta) || normalizedLazadaLink)
                    : normalizedLazadaLink
                nextStateFields.lazada_link = normalizedLazadaLink
                nextStateFields.lazada_original_link = String(meta.lazadaOriginalLink || '').trim()
                if (isLikelyConvertedLazadaLink(normalizedLazadaLink)) {
                    const inferredMemberId = normalizeLazadaMemberId(
                        String(meta.lazadaMemberId || meta.lazada_member_id || lazadaExpectedMemberId || '')
                    )
                    if (inferredMemberId) {
                        meta.lazadaMemberId = inferredMemberId
                        nextStateFields.lazada_member_id = inferredMemberId
                    }
                    meta.lazadaConvertedAt = new Date().toISOString()
                    delete meta.lazadaConversionError
                    nextStateFields.lazada_converted_at = String(meta.lazadaConvertedAt || '').trim()
                } else {
                    delete meta.lazadaConvertedAt
                    nextStateFields.lazada_converted_at = ''
                }
            } else {
                meta.lazadaLink = ''
                delete meta.lazadaOriginalLink
                delete meta.lazadaConvertedAt
                delete meta.lazadaConversionError
                if (!lazadaExpectedMemberId) delete meta.lazadaMemberId
                nextStateFields.lazada_link = ''
                nextStateFields.lazada_original_link = ''
                nextStateFields.lazada_converted_at = ''
                nextStateFields.lazada_member_id = ''
            }
            changed = true
            touchedAffiliateFields = true
        }
        if (body.keepInPostedTab !== undefined) {
            if (body.keepInPostedTab) {
                meta.keepInPostedTab = true
            } else {
                delete meta.keepInPostedTab
            }
            changed = true
        }
        if (body.resetPostedState === true) {
            meta.postedAt = ''
            delete meta.keepInPostedTab
            await resetNamespaceVideoPosted(c.env.DB, targetNamespaceId, id)
            changed = true
        }
        if (body.category !== undefined) {
            meta.category = body.category
            changed = true
        }
        if (body.title !== undefined) {
            meta.title = body.title
            changed = true
        }
        if (body.manualCaption !== undefined) {
            const manualCaption = normalizeManualCaption(body.manualCaption)
            if (manualCaption) {
                meta.manualCaption = manualCaption
                meta.captionProvidedAt = new Date().toISOString()
            } else {
                delete meta.manualCaption
                delete meta.captionProvidedAt
            }
            changed = true
        }
        if (changed) {
            meta.updatedAt = new Date().toISOString()
        }
        await targetBucket.put(`videos/${id}.json`, JSON.stringify(meta, null, 2), {
            httpMetadata: { contentType: 'application/json' },
        })
        await updateGalleryCache(targetBucket, id)
        await syncGalleryIndexEntry(c.env, targetNamespaceId, id).catch((error) => {
            console.log(`[GALLERY-PUT] sync gallery index failed ns=${targetNamespaceId} video=${id}: ${error instanceof Error ? error.message : String(error)}`)
        })
        if (touchedAffiliateFields) {
            await upsertNamespaceVideoState(c.env.DB, targetNamespaceId, id, nextStateFields)
        }
        await c.env.BUCKET.delete('_admin_cache/all_gallery_videos.json').catch(() => { })
        await c.env.BUCKET.delete('_admin_cache/all_gallery_owner_videos.json').catch(() => { })
        // Inventory state changed (link/posted/etc.) — drop the cache so the next
        // gallery list request reflects the move immediately.
        invalidateNamespaceInventoryCache(targetNamespaceId)

        return c.json({
            success: true,
            video: {
                ...meta,
                id: String(meta.id || id).trim() || id,
                namespace_id: String(meta.namespace_id || targetNamespaceId).trim() || targetNamespaceId,
                manualCaption: normalizeManualCaption(meta.manualCaption || meta.caption || ''),
                hasManualCaption: !!normalizeManualCaption(meta.manualCaption || meta.caption || ''),
                shopeeLink: normalizeMetaShopeeLink(meta) || String(meta.shopeeLink || '').trim() || undefined,
                lazadaLink: normalizeMetaLazadaLink(meta) || String(meta.lazadaLink || '').trim() || undefined,
            },
        })
    } catch {
        return c.json({ error: 'Failed to update video' }, 500)
    }
})

// Bulk reset all posted videos in the CURRENT namespace back to "ยังไม่โพสต์".
// Strictly scoped to the caller's namespace_id — refuses cross-namespace requests.
// This avoids accidentally moving member clips when admin only wants to reset their own.
app.post('/api/gallery/reset-posted-bulk', async (c) => {
    try {
        const adminCheck = await requireSystemAdminSession(c)
        if (!adminCheck.ok) return adminCheck.response

        const currentNamespaceId = String(c.get('botId') || '').trim()
        const body = await c.req.json().catch(() => ({} as { namespace_id?: string; namespaceId?: string })) as { namespace_id?: string; namespaceId?: string }
        const requestedNamespaceId = String(
            body.namespace_id ?? body.namespaceId ?? c.req.query('namespace_id') ?? ''
        ).trim()
        const targetNamespaceId = requestedNamespaceId || currentNamespaceId
        if (!targetNamespaceId) {
            return c.json({ error: 'namespace_id_required' }, 400)
        }
        if (targetNamespaceId !== currentNamespaceId) {
            return c.json({ error: 'cross_namespace_gallery_write_forbidden' }, 403)
        }

        // Find only videos that are really eligible for repost: they must be
        // visible as posted AND have a confirmed post_history row. Videos moved
        // to "โพสต์แล้ว" only by state/guard/manual-marking are not a repost
        // source and must not be reset by this button.
        const inventory = await getNamespaceGalleryInventory(c.env, targetNamespaceId)
        const confirmedPostedVideoIds = await getConfirmedPostedVideoIds({
            db: c.env.DB,
            namespaceId: targetNamespaceId,
        })
        const visiblePostedVideos = inventory.videos.filter((v) =>
            isNamespaceGalleryVideoVisibleInUsedTab(v as Record<string, unknown>)
        )
        const postedVideos = visiblePostedVideos.filter((v) => {
            const id = String((v as Record<string, unknown>).id || '').trim()
            return id && confirmedPostedVideoIds.has(id)
        })

        // Bulk reset D1 — only confirmed real-posted rows in this namespace.
        await ensureNamespaceVideoStateColumns(c.env.DB)
        const postedVideoIds = postedVideos
            .map((video) => String((video as Record<string, unknown>).id || '').trim())
            .filter(Boolean)
        if (postedVideoIds.length > 0) {
            const chunkSize = 25
            for (let i = 0; i < postedVideoIds.length; i += chunkSize) {
                const chunk = postedVideoIds.slice(i, i + chunkSize)
                const placeholders = chunk.map(() => '?').join(', ')
                await c.env.DB.prepare(
                    `UPDATE namespace_video_state
                     SET posted_at = '', manual_unposted_at = datetime('now'), updated_at = datetime('now')
                     WHERE namespace_id = ?
                       AND video_id IN (${placeholders})
                       AND posted_at <> ''`
                ).bind(targetNamespaceId, ...chunk).run()
            }
        }
        await ensurePagePostedVideoGuardsTable(c.env.DB)

        // Reset R2 metadata for each posted video (clears postedAt + keepInPostedTab)
        const bucket = c.get('bucket')
        const nowIso = new Date().toISOString()
        let resetCount = 0
        for (const video of postedVideos) {
            const id = String((video as Record<string, unknown>).id || '').trim()
            if (!id) continue
            try {
                const metaObj = await bucket.get(`videos/${id}.json`)
                if (!metaObj) continue
                const meta = await metaObj.json() as Record<string, unknown>
                meta.postedAt = ''
                delete meta.keepInPostedTab
                meta.updatedAt = nowIso
                await bucket.put(`videos/${id}.json`, JSON.stringify(meta, null, 2), {
                    httpMetadata: { contentType: 'application/json' },
                })
                await updateGalleryCache(bucket, id).catch(() => { })
                resetCount++
            } catch (e) {
                console.log(`[GALLERY-RESET-BULK] reset failed ns=${targetNamespaceId} video=${id}: ${e instanceof Error ? e.message : String(e)}`)
            }
        }

        // Invalidate admin caches so the change is reflected everywhere
        await c.env.BUCKET.delete('_admin_cache/all_gallery_videos.json').catch(() => { })
        await c.env.BUCKET.delete('_admin_cache/all_gallery_owner_videos.json').catch(() => { })
        invalidateNamespaceInventoryCache(targetNamespaceId)

        return c.json({
            success: true,
            namespace_id: targetNamespaceId,
            reset_count: resetCount,
            posted_total: postedVideos.length,
            visible_posted_total: visiblePostedVideos.length,
            skipped_without_history: Math.max(0, visiblePostedVideos.length - postedVideos.length),
        })
    } catch (e) {
        return c.json({ error: e instanceof Error ? e.message : String(e) }, 500)
    }
})

// Mirror of /api/gallery/reset-posted-bulk but in the OPPOSITE direction:
// move every "ยังไม่โพสต์" (unposted) video into "โพสต์แล้ว" (posted) by stamping
// state.posted_at = now. Use this to clear the to-do list when a member wants
// to re-upload a fresh batch of clips and abandon the old queue.
//
// Does NOT post to Facebook — only marks state. Subsequent cron ticks will
// skip these videos because the unposted filter excludes posted_at != ''.
app.post('/api/gallery/mark-posted-bulk', async (c) => {
    try {
        const adminCheck = await requireSystemAdminSession(c)
        if (!adminCheck.ok) return adminCheck.response

        const currentNamespaceId = String(c.get('botId') || '').trim()
        const body = await c.req.json().catch(() => ({} as { namespace_id?: string; namespaceId?: string; confirm?: string })) as { namespace_id?: string; namespaceId?: string; confirm?: string }
        const requestedNamespaceId = String(
            body.namespace_id ?? body.namespaceId ?? c.req.query('namespace_id') ?? ''
        ).trim()
        const targetNamespaceId = requestedNamespaceId || currentNamespaceId
        if (!targetNamespaceId) {
            return c.json({ error: 'namespace_id_required' }, 400)
        }
        if (targetNamespaceId !== currentNamespaceId) {
            return c.json({ error: 'cross_namespace_gallery_write_forbidden' }, 403)
        }
        const expectedConfirm = `MARK_POSTED_${targetNamespaceId}`
        if (String(body.confirm || '').trim() !== expectedConfirm) {
            return c.json({ error: 'explicit_confirmation_required', expected_confirm: expectedConfirm }, 400)
        }

        await ensureNamespaceVideoStateColumns(c.env.DB)
        // Single SQL: upsert state.posted_at=now for every gallery_index row in
        // this namespace that is processed + has both shopee/lazada links and is
        // currently unposted. Handles both new state rows and existing rows.
        const nowIso = new Date().toISOString()
        const result = await c.env.DB.prepare(
            `INSERT INTO namespace_video_state (namespace_id, video_id, posted_at, created_at, updated_at)
             SELECT g.namespace_id, g.video_id, ?, datetime('now'), datetime('now')
             FROM gallery_index g
             LEFT JOIN namespace_video_state s
               ON s.namespace_id = g.namespace_id AND s.video_id = g.video_id
             WHERE g.namespace_id = ?
               AND g.has_public_video = 1
               AND TRIM(COALESCE(g.processed_at,'')) <> ''
               AND TRIM(COALESCE(g.shopee_link,'')) <> ''
               AND TRIM(COALESCE(g.lazada_link,'')) <> ''
               AND TRIM(COALESCE(s.posted_at,'')) = ''
             ON CONFLICT(namespace_id, video_id) DO UPDATE SET
                 posted_at = excluded.posted_at,
                 manual_unposted_at = '',
                 updated_at = excluded.updated_at`
        ).bind(nowIso, targetNamespaceId).run()

        // Invalidate admin caches so the change is reflected everywhere
        await c.env.BUCKET.delete('_admin_cache/all_gallery_videos.json').catch(() => { })
        await c.env.BUCKET.delete('_admin_cache/all_gallery_owner_videos.json').catch(() => { })

        return c.json({
            success: true,
            namespace_id: targetNamespaceId,
            marked_count: Number(result.meta?.changes || 0),
            posted_at: nowIso,
        })
    } catch (e) {
        return c.json({ error: e instanceof Error ? e.message : String(e) }, 500)
    }
})

app.delete('/api/gallery/:id', async (c) => {
    const id = String(c.req.param('id') || '').trim()
    if (!id) return c.json({ error: 'id is required' }, 400)
    try {
        const currentNamespaceId = c.get('botId')
        const requestedNamespaceId = String(c.req.query('namespace_id') || '').trim()
        const targetNamespaceId = requestedNamespaceId || currentNamespaceId
        if (targetNamespaceId !== currentNamespaceId) {
            return c.json({ error: 'cross_namespace_gallery_write_forbidden' }, 403)
        }
        const bucket = targetNamespaceId === currentNamespaceId
            ? c.get('bucket')
            : new BotBucket(c.env.BUCKET, targetNamespaceId) as unknown as R2Bucket
        const keysToDelete = [
            `videos/${id}.json`,
            `videos/${id}.mp4`,
            `videos/${id}_thumb.webp`,
            ...getOriginalVideoAssetKeys(id),
            getOriginalThumbnailAssetKey(id),
            `_inbox/${id}.json`,
            `_processing/${id}.json`,
            `_queue/${id}.json`,
            `_processing_history/${id}.json`,
        ]
        await Promise.all(keysToDelete.map((key) => bucket.delete(key).catch(() => { })))
        await removeFromGalleryCache(bucket, id).catch(() => { })
        await deleteGalleryIndexEntry(c.env.DB, targetNamespaceId, id).catch(() => { })
        await c.env.DB
            .prepare('DELETE FROM namespace_video_state WHERE namespace_id = ? AND video_id = ?')
            .bind(targetNamespaceId, id)
            .run()
            .catch(() => { })
        await c.env.BUCKET.delete('_admin_cache/all_gallery_videos.json').catch(() => { })
        await c.env.BUCKET.delete('_admin_cache/all_gallery_owner_videos.json').catch(() => { })
        invalidateNamespaceInventoryCache(targetNamespaceId)
        return c.json({ success: true })
    } catch {
        return c.json({ error: 'Failed to delete video' }, 500)
    }
})

app.get('/api/gallery/:id/asset/:variant', async (c) => {
    const id = String(c.req.param('id') || '').trim()
    const variantRaw = String(c.req.param('variant') || '').trim().toLowerCase()
    const variant = variantRaw === 'thumb' || variantRaw === 'original' || variantRaw === 'public' || variantRaw === 'original-thumb'
        ? variantRaw as GalleryAssetVariant
        : null
    if (!id || !variant) return c.text('Not found', 404)

    const currentNamespaceId = String(c.get('botId') || '').trim()
    const requestedNamespaceId = String(c.req.query('namespace_id') || '').trim()
    const targetNamespaceId = requestedNamespaceId || currentNamespaceId
    if (!targetNamespaceId) return c.text('namespace_id is required', 400)

    const bucket = new BotBucket(c.env.BUCKET, targetNamespaceId) as unknown as R2Bucket
    const key = await resolveGalleryAssetKey(bucket, id, variant)
    const response = await buildGalleryAssetResponse(bucket, key, variant, c.req.header('range'))
    if (
        response.status === 404
        && (variant === 'original-thumb' || variant === 'thumb')
    ) {
        if (variant === 'thumb') {
            const originalThumbKey = await resolveGalleryAssetKey(bucket, id, 'original-thumb').catch(() => '')
            const originalThumbResponse = originalThumbKey
                ? await buildGalleryAssetResponse(bucket, originalThumbKey, 'original-thumb', c.req.header('range')).catch(() => null)
                : null
            if (originalThumbResponse && originalThumbResponse.status !== 404) return originalThumbResponse
        }
        try {
            const frameUrl = buildWorkerGalleryFrameUrl(
                String(c.env.WORKER_URL || '').trim(),
                targetNamespaceId,
                id,
                {
                    seed: `${targetNamespaceId}:${id}:${variant}`,
                    format: 'webp',
                    width: 540,
                    height: 960,
                },
            )
            if (!frameUrl) return response
            const thumbBytes = await generateThumbnailViaContainer(
                c.env,
                buildWorkerGalleryAssetUrl(
                    String(c.env.WORKER_URL || '').trim(),
                    targetNamespaceId,
                    id,
                    variant === 'thumb' ? 'public' : 'original',
                ),
                `${targetNamespaceId}:${id}:${variant}`,
                undefined,
                'webp',
                540,
                960,
            )
            return new Response(thumbBytes, {
                status: 200,
                headers: {
                    'Content-Type': 'image/webp',
                    'Cache-Control': 'public, max-age=300, stale-while-revalidate=86400',
                    'Access-Control-Allow-Origin': '*',
                },
            })
        } catch {
            return response
        }
    }
    return response
})

async function handleGalleryFrameRequest(c: Context<{ Bindings: Env, Variables: { botId: string; bucket: R2Bucket } }>) {
    const id = String(c.req.param('id') || '').trim()
    const targetNamespaceId = String(c.req.query('namespace_id') || c.get('botId') || '').trim()
    const timeParam = String(c.req.query('t') || '').trim()
    const timeRaw = Number(timeParam)
    const seekSeconds = timeParam !== '' && Number.isFinite(timeRaw) ? Math.max(0, timeRaw) : undefined
    const seed = String(c.req.query('seed') || '').trim()
    const targetWidthRaw = Number(c.req.query('w') || c.req.query('width') || '')
    const targetHeightRaw = Number(c.req.query('h') || c.req.query('height') || '')
    const targetWidth = Number.isFinite(targetWidthRaw) ? Math.max(120, Math.min(1440, Math.round(targetWidthRaw))) : undefined
    const targetHeight = Number.isFinite(targetHeightRaw) ? Math.max(160, Math.min(2560, Math.round(targetHeightRaw))) : undefined
    const requestedFormat = (() => {
        const format = String(c.req.query('format') || c.req.query('fmt') || '').trim().toLowerCase()
        return format === 'jpg' || format === 'jpeg' ? 'jpg' : 'webp'
    })()
    const coverText = normalizeLineCoverText(c.req.query('ct') || c.req.query('cover_text') || '')
    const coverTextYPercentRaw = Number(c.req.query('cy') || c.req.query('text_y_pct') || '')
    const coverTextYPercent = Number.isFinite(coverTextYPercentRaw)
        ? Math.max(10, Math.min(90, Math.round(coverTextYPercentRaw)))
        : undefined
    const coverTemplateId = normalizeCoverTemplateId(String(c.req.query('tid') || c.req.query('template_id') || ''))
    const coverTextStyle = normalizeCoverTextStyle({
        font_id: c.req.query('tf') || c.req.query('font_id') || '',
        text_color: c.req.query('tc') || c.req.query('text_color') || '',
        secondary_text_color: c.req.query('tc2') || c.req.query('secondary_text_color') || '',
        background_color: c.req.query('bc') || c.req.query('bg_color') || '',
        background_opacity: c.req.query('bo') || c.req.query('bg_opacity') || '',
        size_scale: c.req.query('ts') || c.req.query('text_scale') || '',
        auto_fit: c.req.query('af') || c.req.query('auto_fit') || '',
        mode: c.req.query('om') || c.req.query('overlay_mode') || '',
        outline_color: c.req.query('oc') || c.req.query('outline_color') || '',
        outline_width: c.req.query('ow') || c.req.query('outline_width') || '',
    }, coverTemplateId)
    if (!id || !targetNamespaceId) return c.text('Not found', 404)

    try {
        const videoUrl = buildWorkerGalleryAssetUrl(
            String(c.env.WORKER_URL || '').trim(),
            targetNamespaceId,
            id,
            'original',
        )
        if (!videoUrl) return c.text('Not found', 404)

        const thumbBytes = await generateThumbnailViaContainer(
            c.env,
            videoUrl,
            seed || `${targetNamespaceId}:${id}:cover:${Number.isFinite(seekSeconds) ? Number(seekSeconds || 0).toFixed(2) : 'auto'}`,
            seekSeconds,
            requestedFormat,
            targetWidth,
            targetHeight,
            coverText
                ? {
                    text: coverText,
                    yPercent: coverTextYPercent,
                    fontId: coverTextStyle.fontId,
                    textColor: coverTextStyle.textColor,
                    secondaryTextColor: coverTextStyle.secondaryTextColor,
                    backgroundColor: coverTextStyle.backgroundColor,
                    backgroundOpacity: coverTextStyle.backgroundOpacity,
                    sizeScale: coverTextStyle.sizeScale,
                    autoFit: coverTextStyle.autoFit,
                    mode: coverTextStyle.mode,
                    outlineColor: coverTextStyle.outlineColor,
                    outlineWidth: coverTextStyle.outlineWidth,
                }
                : undefined,
        )

        return new Response(thumbBytes, {
            status: 200,
            headers: {
                'Content-Type': requestedFormat === 'jpg' ? 'image/jpeg' : 'image/webp',
                'Cache-Control': coverText
                    ? 'no-store, max-age=0'
                    : 'public, max-age=31536000, immutable',
                'Access-Control-Allow-Origin': '*',
            },
        })
    } catch (error) {
        return c.json({
            error: error instanceof Error ? error.message : String(error),
        }, 500)
    }
}

app.get('/api/gallery/:id/frame', async (c) => handleGalleryFrameRequest(c))
app.get('/api/gallery/:id/frame-preview/:cacheKey', async (c) => handleGalleryFrameRequest(c))

app.get('/api/gallery/:id', async (c) => {
    const id = c.req.param('id')
    try {
        const currentNamespaceId = c.get('botId')
        const requestedNamespaceId = String(c.req.query('namespace_id') || '').trim()
        const targetNamespaceId = requestedNamespaceId || currentNamespaceId
        if (targetNamespaceId !== currentNamespaceId) {
            const enabled = isUnifiedGalleryEnabled()
            if (!enabled) return c.json({ error: 'cross_namespace_gallery_not_enabled' }, 403)
        }
        const bucket = targetNamespaceId === currentNamespaceId
            ? c.get('bucket')
            : new BotBucket(c.env.BUCKET, targetNamespaceId) as unknown as R2Bucket
        const metaObj = await bucket.get(`videos/${id}.json`)
        if (!metaObj) return c.json({ error: 'ไม่พบวิดีโอ' }, 404)
        const metadata = await metaObj.json() as Record<string, unknown>
        return c.json({
            ...metadata,
            id: String(metadata.id || id).trim() || id,
            namespace_id: String(metadata.namespace_id || targetNamespaceId).trim() || targetNamespaceId,
        })
    } catch {
        return c.json({ error: 'ไม่พบวิดีโอ' }, 404)
    }
})

