async function getNamespaceBrowserSavingOwnerEmails(db: D1Database, namespaceId: string): Promise<string[]> {
    const ns = String(namespaceId || '').trim()
    if (!ns) return []

    const rows = await db.prepare(
        `SELECT DISTINCT lower(trim(coalesce(email, ''))) AS email
         FROM users
         WHERE namespace_id = ?
           AND trim(coalesce(email, '')) <> ''
         ORDER BY email`
    ).bind(ns).all() as { results?: Array<{ email?: string | null }> }

    const out: string[] = []
    const seen = new Set<string>()
    for (const row of rows.results || []) {
        const email = String(row?.email || '').trim().toLowerCase()
        if (!email || seen.has(email)) continue
        seen.add(email)
        out.push(email)
    }
    return out
}

async function upsertNamespacePageFromProfileSync(env: Env, params: {
    namespaceId: string
    pageId: string
    pageName?: string
    pageAvatarUrl?: string
    accessToken: string
    commentToken?: string
    tokenSource?: string
    // Initial is_active value for a NEWLY INSERTED row only. Defaults to 1 (active) so normal
    // profile-sync / Bridge Token export / token-refresh behavior is unchanged. A bulk Facebook
    // Lite bridge import passes 0 to STAGE imported pages inactive (the operator turns them on
    // later). This NEVER changes the is_active of an existing/moved row — only the INSERT path.
    initialIsActive?: number
    // Onboarding/import marker. When this is a staging import (import_mode
    // 'facebook_lite_bridge_import' OR initialIsActive=0) and the page already exists in ANOTHER
    // namespace, the page is NOT moved/stolen — the existing row (and its active posting cron in
    // that other namespace) is left intact and a structured { skipped: true, conflict } result is
    // returned. Normal /token/export and token-refresh callers omit this and keep moving rows.
    importMode?: string
    // Guarded refresh-only mode (requirement: a stale-token refresh must never create/move a page).
    // When true, the upsert refreshes the token of an EXISTING row in THIS namespace only — it never
    // INSERTs a brand-new (active) page and never MOVES a page out of another namespace; if the page
    // is absent here it returns { skipped:true } without touching anything. Default false keeps the
    // existing create/move behavior for onboarding/export callers.
    updateOnly?: boolean
}): Promise<{
    created: boolean
    updated: boolean
    moved: boolean
    // true when a staging import declined to move an existing page that lives in another namespace.
    skipped: boolean
    // The namespace that already owns the page when skipped (so importers can report the conflict).
    conflictNamespaceId?: string
}> {
    const namespaceId = String(params.namespaceId || '').trim()
    const pageId = String(params.pageId || '').trim()
    const pageName = String(params.pageName || '').trim() || pageId
    const pageAvatarUrl = String(params.pageAvatarUrl || '').trim() ||
        `https://graph.facebook.com/${encodeURIComponent(pageId)}/picture?type=large`
    const accessToken = String(params.accessToken || '').trim()
    const commentToken = String(params.commentToken || '').trim()
    const tokenSource = String(params.tokenSource || '').trim().toLowerCase()
    // Only 0 stages a new row inactive; anything else (incl. undefined) keeps the legacy default (1).
    const initialIsActive = params.initialIsActive === 0 ? 0 : 1
    // A staging import (Facebook Lite bridge bulk onboarding) must NOT steal a page that already
    // posts in another namespace. Gate on the explicit import_mode marker OR the inactive-staging
    // signal (initialIsActive=0) — both mean "admin is onboarding pages into the admin namespace,
    // not relocating live ones". Normal export/refresh callers omit both and keep moving rows.
    const importMode = String(params.importMode || '').trim().toLowerCase()
    const isStagingImport = importMode === 'facebook_lite_bridge_import' || initialIsActive === 0

    if (!namespaceId) throw new Error('namespace_not_found')
    if (!pageId) throw new Error('page_id_required')
    if (!accessToken) throw new Error('access_token_required')

    // The freshly-synced page token must lead BOTH pools and become the stored primary, so a
    // facebook_lite_bridge export (or any newer access_token) immediately outranks a stale EAABsb
    // already present. Facebook Lite page tokens are EAAD6V-prefixed; the legacy isPostRoleToken()
    // gate excluded EAAD6 and so let a stale EAABsb stay primary (live row 33519 posted with a stale
    // EAABsb after a successful EAAD6V export). prioritizeSyncedPageTokenPools() makes the fresh
    // token authoritative and is independent of that gate. The comment_token (if any, else the
    // access_token) seeds the comment pool so commenting uses the same fresh token.
    let created = false
    let updated = false
    let moved = false
    let skipped = false
    let conflictNamespaceId: string | undefined

    const tokenPool = await getNamespacePagesTokenPool(env.DB, namespaceId)
    const existingEntry = tokenPool[pageId] || { post_tokens: [], comment_tokens: [] }
    const existing = await env.DB.prepare(
        'SELECT id, access_token FROM pages WHERE id = ? AND bot_id = ?'
    ).bind(pageId, namespaceId).first() as { id?: string; access_token?: string | null } | null

    const prioritized = prioritizeSyncedPageTokenPools({
        incomingToken: accessToken,
        incomingCommentToken: commentToken || (isCommentRoleToken(accessToken) ? accessToken : ''),
        // Preserve the existing stored primary ONLY as a fallback when the incoming token is empty
        // (it never is here — access_token is validated above). Keeping EAAD6V-eligible (any valid)
        // tokens means a previously-synced Lite token is never blanked.
        existingPrimaryToken: isPersistablePagePrimaryToken(existing?.access_token)
            ? String(existing?.access_token || '').trim()
            : '',
        existingPostTokens: existingEntry.post_tokens || [],
        existingCommentTokens: existingEntry.comment_tokens || [],
    })
    if (tokenSource) {
        console.log(`[PAGE-PROFILE-SYNC] ns=${namespaceId} page=${pageId} token_source=${tokenSource} lite=${isFacebookLitePageToken(accessToken)} primary_is_incoming=${prioritized.primaryToken === accessToken}`)
    }
    const nextPostTokens = prioritized.postTokens
    const nextCommentTokens = prioritized.commentTokens
    const nextPrimaryToken = prioritized.primaryToken

    if (existing?.id) {
        await env.DB.prepare(
            'UPDATE pages SET access_token = ?, image_url = ?, name = ?, updated_at = datetime(\"now\") WHERE id = ? AND bot_id = ?'
        ).bind(nextPrimaryToken, pageAvatarUrl, pageName, pageId, namespaceId).run()
        updated = true
    } else if (params.updateOnly) {
        // Guarded refresh-only: the page does not exist in THIS namespace. A token refresh must never
        // create a new active page or move one out of another namespace, so skip without touching
        // anything (and report the conflicting owner namespace if the page lives elsewhere).
        const existingInOtherNamespace = await env.DB.prepare(
            'SELECT bot_id FROM pages WHERE id = ? LIMIT 1'
        ).bind(pageId).first() as { bot_id?: string } | null
        const otherNamespaceId = String(existingInOtherNamespace?.bot_id || '').trim()
        console.log(`[PAGE-PROFILE-SYNC] update-only refresh skipped (page absent in ns) page=${pageId} ns=${namespaceId}${otherNamespaceId && otherNamespaceId !== namespaceId ? ` owner_ns=${otherNamespaceId}` : ''}`)
        skipped = true
        if (otherNamespaceId && otherNamespaceId !== namespaceId) conflictNamespaceId = otherNamespaceId
        return { created, updated, moved, skipped, conflictNamespaceId }
    } else {
        const existingInOtherNamespace = await env.DB.prepare(
            'SELECT bot_id, access_token FROM pages WHERE id = ? LIMIT 1'
        ).bind(pageId).first() as { bot_id?: string; access_token?: string | null } | null

        if (existingInOtherNamespace?.bot_id && String(existingInOtherNamespace.bot_id || '').trim() !== namespaceId) {
            const otherNamespaceId = String(existingInOtherNamespace.bot_id || '').trim()
            if (isStagingImport) {
                // SAFE ONBOARDING: the page already lives (and posts) in another namespace. A bulk
                // import must NEVER move its bot_id / blank its is_active / disturb its post_hours —
                // doing so is exactly what stopped page "เฉียบ" (id 1008898512617594) posting after
                // it was relocated from namespace 177… to the admin namespace 615…. Leave the row
                // untouched and report a structured conflict so the importer counts it as skipped.
                console.log(`[PAGE-PROFILE-SYNC] staging import skipped existing page page=${pageId} owner_ns=${otherNamespaceId} requested_ns=${namespaceId} import_mode=${importMode || '(initial_is_active=0)'}`)
                skipped = true
                conflictNamespaceId = otherNamespaceId
                // Do NOT touch the pages row OR the requested namespace token pool — leave the page
                // entirely owned by its existing namespace.
                return { created, updated, moved, skipped, conflictNamespaceId }
            }
            const existingOtherPrimaryToken = isPersistablePagePrimaryToken(existingInOtherNamespace.access_token)
                ? String(existingInOtherNamespace.access_token || '').trim()
                : ''
            const movedPrimaryToken = String(nextPrimaryToken || existingOtherPrimaryToken || '').trim()
            await env.DB.prepare(
                'UPDATE pages SET bot_id = ?, access_token = ?, image_url = ?, name = ?, updated_at = datetime(\"now\") WHERE id = ?'
            ).bind(namespaceId, movedPrimaryToken, pageAvatarUrl, pageName, pageId).run()
            moved = true
        } else {
            await env.DB.prepare(
                'INSERT INTO pages (id, name, image_url, access_token, post_interval_minutes, post_hours, is_active, bot_id) VALUES (?, ?, ?, ?, ?, ?, ?, ?)'
            ).bind(pageId, pageName, pageAvatarUrl, nextPrimaryToken, 60, generateRandomPostHours(), initialIsActive, namespaceId).run()
            created = true
        }
    }

    tokenPool[pageId] = {
        post_tokens: nextPostTokens,
        comment_tokens: nextCommentTokens,
        updated_at: new Date().toISOString(),
    }
    await setNamespacePagesTokenPool(env.DB, namespaceId, tokenPool)

    return { created, updated, moved, skipped, conflictNamespaceId }
}

function uniqueTokens(raw: string[]): string[] {
    const out: string[] = []
    const seen = new Set<string>()
    for (const item of raw) {
        const token = String(item || '').trim()
        if (!token) continue
        const key = token.toLowerCase()
        if (seen.has(key)) continue
        seen.add(key)
        out.push(token)
    }
    return out
}

function hasTokenList(tokens: string[] | undefined | null): boolean {
    return Array.isArray(tokens) && tokens.some((token) => !!String(token || '').trim())
}

function isTokenString(token: string): boolean {
    return !!String(token || '').trim()
}

function isTokenValid(token: string): boolean {
    return isTokenString(token)
}

function normalizeTokenPool(tokens: string[]): string[] {
    return uniqueTokens(tokens.filter((t) => isTokenValid(t)))
}

/**
 * Generate random post_hours for new pages.
 * Creates 4 posting slots spread across 24 hours (~6 hour intervals) with random minutes.
 * Output format: "H:MM,H:MM,H:MM,H:MM" e.g. "3:47,9:12,15:33,21:08"
 */
function generateRandomPostHours(): string {
    const slotCount = 4
    const intervalHours = 24 / slotCount // 6 hours
    const baseOffset = Math.floor(Math.random() * intervalHours) // random starting hour 0-5
    const slots: string[] = []
    for (let i = 0; i < slotCount; i++) {
        const hour = Math.floor(baseOffset + i * intervalHours) % 24 || 24 // 1-24 range
        const minute = Math.floor(Math.random() * 60)
        slots.push(`${hour}:${minute.toString().padStart(2, '0')}`)
    }
    return slots.join(',')
}

function normalizePostTokenPool(tokens: string[]): string[] {
    // Accept any valid (non-empty) token. Previously filtered EAAD6 prefix as "user token",
    // but that's unreliable — EAAD6 encodes the Facebook app id (e.g. Facebook Lite), not
    // the token type. We now trust whatever the operator pastes in the page-token field
    // and use the same token for both post + comment.
    return uniqueTokens((tokens || []).filter((token) => isTokenValid(token)))
}

function isCommentRoleToken(token: string): boolean {
    return /^EAAD6/i.test(String(token || '').trim())
}

function isPostRoleToken(token: string): boolean {
    // Post role = page-scoped tokens (non-EAAD6). These are now preferred for
    // both reel posting and comment resolution, with EAAD6 kept as legacy fallback.
    const normalized = String(token || '').trim()
    return !!normalized && isTokenValid(normalized) && !isCommentRoleToken(normalized)
}

function isPageScopedRoleToken(token: string): boolean {
    return isPostRoleToken(token)
}

function isResolvedCommentToken(token: string): boolean {
    return isTokenValid(String(token || '').trim())
}

function isResolvedRoleTokenForMode(token: string, mode: BrowserSavingTokenMode): boolean {
    return mode === 'comment'
        ? isResolvedCommentToken(token)
        : isPageScopedRoleToken(token)
}

function isRoleTokenForMode(token: string, mode: BrowserSavingTokenMode): boolean {
    return mode === 'comment'
        ? isCommentRoleToken(token)
        : isPostRoleToken(token)
}

function normalizeCommentTokenPool(tokens: string[]): string[] {
    // Accept any valid (non-empty) token. The operator-pasted page-token is the single
    // source of truth for both post + comment, regardless of the EAAD6/EAACh prefix
    // (those prefixes just encode the Facebook app id — Lite, Marketing etc —
    // not the token's scope).
    return uniqueTokens(tokens.filter((token) => isTokenValid(token)))
}

function normalizeDirectVideoTokenPool(tokens: string[]): string[] {
    // Direct video posting/comment now runs with page-scoped tokens only.
    return normalizeCommentTokenPool(tokens)
}

function buildPreferredCommentTokenPool(params: {
    primaryToken?: string | null
    postTokens?: string[]
    commentTokens?: string[]
}): string[] {
    return normalizeDirectVideoTokenPool([
        String(params.primaryToken || '').trim(),
        ...normalizePostTokenPool(params.postTokens || []),
        ...normalizeCommentTokenPool(params.commentTokens || []),
    ])
}

function buildPrimaryPostingTokenCandidates(params: {
    primaryToken?: string | null
    postTokens?: string[]
    commentTokens?: string[]
}): string[] {
    return normalizeDirectVideoTokenPool([
        String(params.primaryToken || '').trim(),
        ...normalizePostTokenPool(params.postTokens || []),
        ...normalizeCommentTokenPool(params.commentTokens || []),
    ])
}

function preferCommentToken(existingRaw: string, candidateRaw: string): string {
    const existing = String(existingRaw || '').trim()
    const candidate = String(candidateRaw || '').trim()
    return existing || candidate
}

async function getNamespacePagesTokenPool(db: D1Database, namespaceId: string): Promise<NamespacePageTokenPool> {
    await ensureNamespaceSettingsTable(db)
    const row = await db.prepare(
        'SELECT value FROM namespace_settings WHERE namespace_id = ? AND key = ?'
    ).bind(namespaceId, NS_SETTING_PAGES_TOKEN_POOL_V1).first() as { value?: string } | null

    const raw = String(row?.value || '').trim()
    if (!raw) return {}

    try {
        const parsed = JSON.parse(raw) as Record<string, unknown>
        if (!parsed || typeof parsed !== 'object') return {}
        const out: NamespacePageTokenPool = {}
        for (const [pageIdRaw, entryRaw] of Object.entries(parsed)) {
            const pageId = String(pageIdRaw || '').trim()
            if (!pageId || !entryRaw || typeof entryRaw !== 'object') continue
            const entryObj = entryRaw as Record<string, unknown>
            const postTokens = normalizePostTokenPool(
                (Array.isArray(entryObj.post_tokens) ? entryObj.post_tokens : []).map((x) => String(x || ''))
            )
            const commentTokens = normalizeCommentTokenPool(
                (Array.isArray(entryObj.comment_tokens) ? entryObj.comment_tokens : []).map((x) => String(x || ''))
            )
            if (postTokens.length === 0 && commentTokens.length === 0) continue
            out[pageId] = {
                post_tokens: postTokens,
                comment_tokens: commentTokens,
                updated_at: typeof entryObj.updated_at === 'string' ? entryObj.updated_at : undefined,
            }
        }
        return out
    } catch {
        return {}
    }
}

async function setNamespacePagesTokenPool(db: D1Database, namespaceId: string, pool: NamespacePageTokenPool): Promise<void> {
    await ensureNamespaceSettingsTable(db)
    const normalized: NamespacePageTokenPool = {}
    for (const [pageIdRaw, entryRaw] of Object.entries(pool || {})) {
        const pageId = String(pageIdRaw || '').trim()
        if (!pageId || !entryRaw) continue
        const postTokens = normalizePostTokenPool(
            (Array.isArray(entryRaw.post_tokens) ? entryRaw.post_tokens : []).map((x) => String(x || ''))
        )
        const commentTokens = normalizeCommentTokenPool(
            (Array.isArray(entryRaw.comment_tokens) ? entryRaw.comment_tokens : []).map((x) => String(x || ''))
        )
        if (postTokens.length === 0 && commentTokens.length === 0) continue
        normalized[pageId] = {
            post_tokens: postTokens,
            comment_tokens: commentTokens,
            updated_at: (entryRaw as { updated_at?: string }).updated_at || new Date().toISOString(),
        }
    }

    const value = JSON.stringify(normalized)
    await db.prepare(
        `INSERT INTO namespace_settings (namespace_id, key, value, created_at, updated_at)
         VALUES (?, ?, ?, datetime('now'), datetime('now'))
         ON CONFLICT(namespace_id, key) DO UPDATE SET
           value = excluded.value,
           updated_at = datetime('now')`
    ).bind(namespaceId, NS_SETTING_PAGES_TOKEN_POOL_V1, value).run()
}

function normalizeHiddenTaggedProfileIds(profileIds: string[]): string[] {
    const out: string[] = []
    const seen = new Set<string>()
    for (const rawValue of profileIds || []) {
        const value = String(rawValue || '').trim().toLowerCase()
        if (!value || seen.has(value)) continue
        seen.add(value)
        out.push(value)
    }
    return out
}

async function getNamespaceHiddenTaggedProfiles(db: D1Database, namespaceId: string): Promise<NamespacePageHiddenTaggedProfiles> {
    await ensureNamespaceSettingsTable(db)
    const row = await db.prepare(
        'SELECT value FROM namespace_settings WHERE namespace_id = ? AND key = ?'
    ).bind(namespaceId, NS_SETTING_PAGES_HIDDEN_TAGGED_PROFILES_V1).first() as { value?: string } | null

    const raw = String(row?.value || '').trim()
    if (!raw) return {}

    try {
        const parsed = JSON.parse(raw) as Record<string, unknown>
        if (!parsed || typeof parsed !== 'object') return {}
        const out: NamespacePageHiddenTaggedProfiles = {}
        for (const [pageIdRaw, idsRaw] of Object.entries(parsed)) {
            const pageId = String(pageIdRaw || '').trim()
            if (!pageId || !Array.isArray(idsRaw)) continue
            const ids = normalizeHiddenTaggedProfileIds(idsRaw.map((value) => String(value || '')))
            if (ids.length > 0) out[pageId] = ids
        }
        return out
    } catch {
        return {}
    }
}

async function setNamespaceHiddenTaggedProfiles(db: D1Database, namespaceId: string, hiddenProfiles: NamespacePageHiddenTaggedProfiles): Promise<void> {
    await ensureNamespaceSettingsTable(db)
    const normalized: NamespacePageHiddenTaggedProfiles = {}
    for (const [pageIdRaw, idsRaw] of Object.entries(hiddenProfiles || {})) {
        const pageId = String(pageIdRaw || '').trim()
        if (!pageId) continue
        const ids = normalizeHiddenTaggedProfileIds(Array.isArray(idsRaw) ? idsRaw : [])
        if (ids.length > 0) normalized[pageId] = ids
    }

    if (Object.keys(normalized).length === 0) {
        await db.prepare(
            'DELETE FROM namespace_settings WHERE namespace_id = ? AND key = ?'
        ).bind(namespaceId, NS_SETTING_PAGES_HIDDEN_TAGGED_PROFILES_V1).run()
        return
    }

    const value = JSON.stringify(normalized)
    await db.prepare(
        `INSERT INTO namespace_settings (namespace_id, key, value, created_at, updated_at)
         VALUES (?, ?, ?, datetime('now'), datetime('now'))
         ON CONFLICT(namespace_id, key) DO UPDATE SET
           value = excluded.value,
           updated_at = datetime('now')`
    ).bind(namespaceId, NS_SETTING_PAGES_HIDDEN_TAGGED_PROFILES_V1, value).run()
}

async function getNamespaceLinkedTaggedProfiles(db: D1Database, namespaceId: string): Promise<NamespacePageLinkedTaggedProfiles> {
    await ensureNamespaceSettingsTable(db)
    const row = await db.prepare(
        'SELECT value FROM namespace_settings WHERE namespace_id = ? AND key = ?'
    ).bind(namespaceId, NS_SETTING_PAGES_LINKED_TAGGED_PROFILES_V1).first() as { value?: string } | null

    const raw = String(row?.value || '').trim()
    if (!raw) return {}

    try {
        const parsed = JSON.parse(raw) as Record<string, unknown>
        if (!parsed || typeof parsed !== 'object') return {}
        const out: NamespacePageLinkedTaggedProfiles = {}
        for (const [pageIdRaw, idsRaw] of Object.entries(parsed)) {
            const pageId = String(pageIdRaw || '').trim()
            if (!pageId || !Array.isArray(idsRaw)) continue
            out[pageId] = normalizeHiddenTaggedProfileIds(idsRaw.map((value) => String(value || '')))
        }
        return out
    } catch {
        return {}
    }
}

async function setNamespaceLinkedTaggedProfiles(db: D1Database, namespaceId: string, linkedProfiles: NamespacePageLinkedTaggedProfiles): Promise<void> {
    await ensureNamespaceSettingsTable(db)
    const normalized: NamespacePageLinkedTaggedProfiles = {}
    for (const [pageIdRaw, idsRaw] of Object.entries(linkedProfiles || {})) {
        const pageId = String(pageIdRaw || '').trim()
        if (!pageId) continue
        normalized[pageId] = normalizeHiddenTaggedProfileIds(Array.isArray(idsRaw) ? idsRaw : [])
    }

    if (Object.keys(normalized).length === 0) {
        await db.prepare(
            'DELETE FROM namespace_settings WHERE namespace_id = ? AND key = ?'
        ).bind(namespaceId, NS_SETTING_PAGES_LINKED_TAGGED_PROFILES_V1).run()
        return
    }

    const value = JSON.stringify(normalized)
    await db.prepare(
        `INSERT INTO namespace_settings (namespace_id, key, value, created_at, updated_at)
         VALUES (?, ?, ?, datetime('now'), datetime('now'))
         ON CONFLICT(namespace_id, key) DO UPDATE SET
           value = excluded.value,
           updated_at = datetime('now')`
    ).bind(namespaceId, NS_SETTING_PAGES_LINKED_TAGGED_PROFILES_V1, value).run()
}

async function clearNamespaceHiddenTaggedProfiles(db: D1Database, namespaceId: string): Promise<void> {
    await db.prepare(
        'DELETE FROM namespace_settings WHERE namespace_id = ? AND key = ?'
    ).bind(namespaceId, NS_SETTING_PAGES_HIDDEN_TAGGED_PROFILES_V1).run()
}

async function clearNamespaceHiddenTaggedProfilesForPage(db: D1Database, namespaceId: string, pageId: string): Promise<void> {
    const normalizedPageId = String(pageId || '').trim()
    if (!normalizedPageId) return
    const hiddenProfiles = await getNamespaceHiddenTaggedProfiles(db, namespaceId)
    if (!hiddenProfiles[normalizedPageId]) return
    delete hiddenProfiles[normalizedPageId]
    await setNamespaceHiddenTaggedProfiles(db, namespaceId, hiddenProfiles)
}

function getHiddenTaggedProfileIdsForPage(hiddenProfiles: NamespacePageHiddenTaggedProfiles, pageId: string): Set<string> {
    return new Set(normalizeHiddenTaggedProfileIds(hiddenProfiles[String(pageId || '').trim()] || []))
}

function hasLinkedTaggedProfilesEntryForPage(linkedProfiles: NamespacePageLinkedTaggedProfiles, pageId: string): boolean {
    const normalizedPageId = String(pageId || '').trim()
    if (!normalizedPageId) return false
    return Object.prototype.hasOwnProperty.call(linkedProfiles || {}, normalizedPageId)
}

function getLinkedTaggedProfileIdsForPage(linkedProfiles: NamespacePageLinkedTaggedProfiles, pageId: string): Set<string> {
    const normalizedPageId = String(pageId || '').trim()
    if (!normalizedPageId) return new Set()
    if (!hasLinkedTaggedProfilesEntryForPage(linkedProfiles, normalizedPageId)) return new Set()
    return new Set(normalizeHiddenTaggedProfileIds(linkedProfiles[normalizedPageId] || []))
}

function collectExplicitLinkedProfileIdsForPage(
    profiles: BrowserSavingProfileRecord[],
    selectors: string[],
    pageId: string,
    pageName: string,
): string[] {
    const explicitIds: string[] = []
    for (const selectorRaw of selectors) {
        const selector = String(selectorRaw || '').trim()
        if (!selector) continue
        if (looksLikeBrowserSavingProfileId(selector)) {
            explicitIds.push(selector)
            continue
        }
        const tag = parseBrowserSavingTagSelector(selector)
        if (!tag) continue
        const selectedProfiles = collectProfilesBySelectors(profiles, [selector])
        for (const profile of selectedProfiles) {
            if (!matchesProfileToPage(profile, pageId, pageName)) continue
            explicitIds.push(String(profile.id || ''))
        }
    }
    return normalizeHiddenTaggedProfileIds(explicitIds)
}

function filterProfilesForTaggedPage(params: {
    profiles: BrowserSavingProfileRecord[]
    pageId: string
    pageName: string
    hiddenProfiles: NamespacePageHiddenTaggedProfiles
    linkedProfiles?: NamespacePageLinkedTaggedProfiles
}): BrowserSavingProfileRecord[] {
    const normalizedPageId = String(params.pageId || '').trim()
    const normalizedPageName = String(params.pageName || '').trim()
    const hiddenProfileIds = getHiddenTaggedProfileIdsForPage(params.hiddenProfiles, normalizedPageId)
    const linkedProfiles = params.linkedProfiles || {}
    const hasLinkedEntry = hasLinkedTaggedProfilesEntryForPage(linkedProfiles, normalizedPageId)
    const linkedProfileIds = hasLinkedEntry
        ? getLinkedTaggedProfileIdsForPage(linkedProfiles, normalizedPageId)
        : new Set<string>()
    const hasActiveLinkedProfile = hasLinkedEntry && (params.profiles || []).some((profile) => {
        const profileId = String(profile.id || '').trim().toLowerCase()
        if (!profileId) return false
        if (hiddenProfileIds.has(profileId)) return false
        return linkedProfileIds.has(profileId)
    })

    return (params.profiles || []).filter((profile) => {
        const profileId = String(profile.id || '').trim().toLowerCase()
        if (!profileId) return false
        if (hiddenProfileIds.has(profileId)) return false
        if (hasLinkedEntry && hasActiveLinkedProfile) return linkedProfileIds.has(profileId)
        return matchesProfileToPage(profile, normalizedPageId, normalizedPageName)
    })
}

function isHiddenTaggedProfileForPage(hiddenProfiles: NamespacePageHiddenTaggedProfiles, pageId: string, profileId: string): boolean {
    const normalizedProfileId = String(profileId || '').trim().toLowerCase()
    if (!normalizedProfileId) return false
    return getHiddenTaggedProfileIdsForPage(hiddenProfiles, pageId).has(normalizedProfileId)
}

function isHiddenTaggedProfileForDerivedPage(hiddenProfiles: NamespacePageHiddenTaggedProfiles, profile: BrowserSavingProfileRecord): boolean {
    const profileId = String(profile.id || '').trim().toLowerCase()
    if (!profileId) return false
    const pageId = parsePageIdFromAvatarUrl(String(profile.page_avatar_url || ''))
    if (!pageId) return false
    return isHiddenTaggedProfileForPage(hiddenProfiles, pageId, profileId)
}

async function rebuildTaggedPageProfileTokens(env: Env, namespaceId: string, pageId: string, pageName: string): Promise<{ primaryToken: string; tokens: string[]; postTokens: string[]; commentTokens: string[] }> {
    const profiles = await fetchBrowserSavingProfilesForNamespace(env, env.DB, namespaceId)
    const cfg = await getNamespacePagesSyncConfig(env.DB, namespaceId)
    const hiddenProfiles = await getNamespaceHiddenTaggedProfiles(env.DB, namespaceId)
    const linkedProfiles = await getNamespaceLinkedTaggedProfiles(env.DB, namespaceId)

    const visibleProfiles = filterProfilesForTaggedPage({
        profiles,
        pageId,
        pageName,
        hiddenProfiles,
        linkedProfiles,
    })

    const { postProfileIds, commentProfileIds } = deriveRoleProfileIdsForTaggedPage({
        profiles: visibleProfiles,
        pageId,
        linkedProfiles,
        cfg,
    })

    const byProfileId = new Map<string, {
        profile_id: string
        roles: Array<'post' | 'comment'>
        post_token: string
        comment_token: string
    }>()

    for (const profile of visibleProfiles) {
        const id = String(profile.id || '').trim()
        if (!id) continue
        const key = id.toLowerCase()
        const postToken = pickProfilePostToken(profile)
        const commentToken = pickProfileCommentToken(profile)
        const existing = byProfileId.get(key)
        if (!existing) {
            const roles: Array<'post' | 'comment'> = []
            if (postProfileIds.has(key)) roles.push('post')
            if (commentProfileIds.has(key) && !roles.includes('comment')) roles.push('comment')
            byProfileId.set(key, {
                profile_id: id,
                roles,
                post_token: postToken,
                comment_token: commentToken,
            })
            continue
        }
        if (postProfileIds.has(key) && !existing.roles.includes('post')) existing.roles.push('post')
        if (commentProfileIds.has(key) && !existing.roles.includes('comment')) existing.roles.push('comment')
        if (!existing.post_token) existing.post_token = postToken
        if (!existing.comment_token) existing.comment_token = commentToken
    }

    const rebuiltPostTokens = normalizePostTokenPool(
        Array.from(byProfileId.values())
            .filter((item) => item.roles.includes('post') && !!String(item.post_token || '').trim())
            .map((item) => String(item.post_token || '').trim())
            .filter(Boolean)
    )

    const allProfileValues = Array.from(byProfileId.values())
    const rebuiltCommentTokens = buildPreferredCommentTokenPool({
        postTokens: rebuiltPostTokens,
        commentTokens: [
            ...allProfileValues
                .filter((item) => !!String(item.comment_token || '').trim())
                .map((item) => String(item.comment_token || '').trim()),
        ],
    })

    const existingPage = await env.DB.prepare(
        'SELECT access_token FROM pages WHERE id = ? AND bot_id = ?'
    ).bind(pageId, namespaceId).first() as { access_token?: string | null } | null
    // Keep ANY existing stored page token (EAAB- or EAAD6V-prefixed) as the preserve fallback so a
    // freshly-synced Facebook Lite (EAAD6V) primary is never blanked when the rebuild has no token.
    const preservedPrimaryToken = isPersistablePagePrimaryToken(existingPage?.access_token)
        ? String(existingPage?.access_token || '').trim()
        : ''
    const rebuiltPrimaryToken = String(rebuiltPostTokens[0] || preservedPrimaryToken || '').trim()
    await env.DB.prepare(
        'UPDATE pages SET access_token = ?, updated_at = datetime("now") WHERE id = ? AND bot_id = ?'
    ).bind(rebuiltPrimaryToken, pageId, namespaceId).run()

    const tokenPool = await getNamespacePagesTokenPool(env.DB, namespaceId)
    if (rebuiltPostTokens.length > 0 || rebuiltCommentTokens.length > 0) {
        tokenPool[pageId] = {
            post_tokens: rebuiltPostTokens,
            comment_tokens: rebuiltCommentTokens,
            updated_at: new Date().toISOString(),
        }
    } else {
        delete tokenPool[pageId]
    }
    await setNamespacePagesTokenPool(env.DB, namespaceId, tokenPool)

    return {
        primaryToken: rebuiltPrimaryToken,
        tokens: uniqueTokens([...rebuiltPostTokens, ...rebuiltCommentTokens]),
        postTokens: rebuiltPostTokens,
        commentTokens: rebuiltCommentTokens,
    }
}

async function getPageTokenCandidates(params: {
    db: D1Database
    namespaceId: string
    pageId: string
    primaryToken?: string | null
}): Promise<{ tokens: string[]; postTokens: string[]; commentTokens: string[] }> {
    const pageId = String(params.pageId || '').trim()
    const primaryToken = String(params.primaryToken || '').trim()

    const pool = await getNamespacePagesTokenPool(params.db, params.namespaceId)
    const entry = pool[pageId]
    const storedPostTokens = normalizePostTokenPool(entry?.post_tokens || [])
    const storedCommentTokens = normalizeCommentTokenPool(entry?.comment_tokens || [])

    const postTokens = normalizePostTokenPool([
        primaryToken,
        ...storedPostTokens,
    ])
    const commentTokens = buildPreferredCommentTokenPool({
        primaryToken,
        postTokens,
        commentTokens: storedCommentTokens,
    })
    const tokens = uniqueTokens([
        ...postTokens,
        ...commentTokens,
    ])

    return {
        tokens,
        postTokens,
        commentTokens,
    }
}

async function ensurePageTokenCandidates(params: {
    env: Env
    db: D1Database
    namespaceId: string
    pageId: string
    pageName: string
    primaryToken?: string | null
    logPrefix: string
}): Promise<{ tokens: string[]; postTokens: string[]; commentTokens: string[] }> {
    // Posting tokens: use the per-page namespace token pool first-class, not only the
    // legacy pages.access_token field. Token Bridge/Facebook Lite sync writes fresh
    // page tokens into pages_token_pool_v1 (and pages.access_token); force-post must
    // include that pool so a stale primary token cannot keep the page permanently
    // broken after a successful /token/export sync.
    // Comment tokens: still prefer the per-namespace dedicated comment token (LIFF
    // settings → ตั้งค่า → คอมเม้น → "Access Token (คอมเม้น)"), then the pool/primary
    // candidates for legacy single-token behavior.
    const pooled = await getPageTokenCandidates({
        db: params.db,
        namespaceId: params.namespaceId,
        pageId: params.pageId,
        primaryToken: params.primaryToken,
    })
    const dedicatedComment = await resolveNamespaceDedicatedCommentToken(params.db, params.namespaceId).catch(() => '')
    const commentTokens = normalizeCommentTokenPool([
        String(dedicatedComment || '').trim(),
        ...pooled.commentTokens,
    ])
    const postTokens = normalizePostTokenPool(pooled.postTokens)
    const tokens = uniqueTokens([
        ...(postTokens.length > 0 ? postTokens : commentTokens),
        ...commentTokens,
    ])
    if (postTokens.length === 0 && commentTokens.length === 0) {
        return { tokens: [], postTokens: [], commentTokens: [] }
    }
    return { tokens, postTokens, commentTokens }
}

function getFacebookErrorMessage(rawError: unknown): string {
    const parsed = parseFacebookErrorLike(rawError)
    return String(parsed?.message || (rawError instanceof Error ? rawError.message : String(rawError))).trim()
}

function shouldAttemptFacebookBarrierAutoRecover(rawError: unknown): boolean {
    const message = getFacebookErrorMessage(rawError).toLowerCase()
    if (!message) return false
    return message.includes('you cannot access the app till you log in to www.facebook.com')
        || message.includes('log in to www.facebook.com and follow the instructions')
        || message.includes('follow the instructions given')
        || message.includes('facebook checkpoint')
        || message.includes('facebook.com/checkpoint')
        || message.includes('facebook_checkpoint')
        || message.includes('facebook_automated_behavior')
        || message.includes('automated behavior')
        || message.includes('พฤติกรรมอัตโนมัติ')
}

async function refreshPagePostTokensFromBrowserSaving(params: {
    env: Env
    db: D1Database
    namespaceId: string
    pageId: string
    pageName: string
    currentPostTokens: string[]
    logPrefix: string
}): Promise<{ postTokens: string[]; profileCount: number; errors: string[] }> {
    void params
    // BrowserSaving token refresh DISABLED 2026-04-29 by user request:
    // page tokens come exclusively from operator-pasted values via Settings page.
    // Returning current pool unchanged (no refresh, no fetch from BrowserSaving).
    return { postTokens: params.currentPostTokens || [], profileCount: 0, errors: [] }
    const namespaceId = String(params.namespaceId || '').trim()
    const pageId = String(params.pageId || '').trim()
    const pageName = String(params.pageName || '').trim()
    if (!namespaceId || !pageId) {
        throw new Error('checkpoint_recover_invalid_namespace_or_page')
    }

    const cfg = await getNamespacePagesSyncConfig(params.db, namespaceId)
    if (!cfg.enabled) throw new Error('checkpoint_recover_pages_sync_disabled')

    const profiles = await fetchBrowserSavingProfilesForNamespace(params.env, params.db, namespaceId)
    const hiddenProfiles = await getNamespaceHiddenTaggedProfiles(params.db, namespaceId)
    const linkedProfiles = await getNamespaceLinkedTaggedProfiles(params.db, namespaceId)
    const scopedProfiles = filterProfilesForTaggedPage({
        profiles,
        pageId,
        pageName,
        hiddenProfiles,
        linkedProfiles,
    })
    const pageProfiles = hasLinkedTaggedProfilesEntryForPage(linkedProfiles, pageId)
        ? scopedProfiles.filter((profile) => !!pickProfilePostToken(profile))
        : collectProfilesBySelectors(scopedProfiles, cfg.postSelectors)
    if (pageProfiles.length === 0) {
        throw new Error(`checkpoint_recover_no_post_profile_for_page:${pageId}`)
    }

    const resolved = await resolveTaggedProfilesToPageRecords(pageProfiles, params.env, 'post')
    const records = resolved.byId.get(pageId) || []
    const resolvedTokens = normalizePostTokenPool(records.map((record) => String(record.access_token || '').trim()))
    if (resolvedTokens.length === 0) {
        const details = resolved.errors.join(' | ') || 'no_token_after_profile_resolve'
        throw new Error(`checkpoint_recover_no_token:${details}`)
    }

    const mergedTokens = normalizePostTokenPool([
        ...resolvedTokens,
        ...(params.currentPostTokens || []),
    ])
    const primary = String(mergedTokens[0] || '').trim()
    if (!primary) {
        throw new Error('checkpoint_recover_primary_token_missing')
    }

    const existingPage = await params.db.prepare(
        'SELECT access_token FROM pages WHERE id = ? AND bot_id = ?'
    ).bind(pageId, namespaceId).first() as { access_token?: string | null } | null
    const preservedAccessToken = isPostRoleToken(String(existingPage?.access_token || '').trim())
        ? String(existingPage?.access_token || '').trim()
        : ''
    const nextStoredAccessToken = preservedAccessToken || primary
    await params.db.prepare(
        'UPDATE pages SET access_token = ?, updated_at = datetime("now") WHERE id = ? AND bot_id = ?'
    ).bind(nextStoredAccessToken, pageId, namespaceId).run()

    try {
        const tokenPool = await getNamespacePagesTokenPool(params.db, namespaceId)
        const existingEntry = tokenPool[pageId] || { post_tokens: [], comment_tokens: [] }
        tokenPool[pageId] = {
            post_tokens: normalizePostTokenPool([
                ...mergedTokens,
                ...(existingEntry.post_tokens || []),
            ]),
            comment_tokens: normalizeCommentTokenPool(existingEntry.comment_tokens || []),
            updated_at: new Date().toISOString(),
        }
        await setNamespacePagesTokenPool(params.db, namespaceId, tokenPool)
    } catch (e) {
        console.log(`[${params.logPrefix}] checkpoint recover: token pool update skipped (${e instanceof Error ? e.message : String(e)})`)
    }

    return {
        postTokens: mergedTokens,
        profileCount: pageProfiles.length,
        errors: resolved.errors,
    }
}

// Resolve the BrowserSaving profile ids that can re-mint a fresh Facebook Lite token for a
// page. Prefer the operator-linked profiles (pages_linked_tagged_profiles_v1); fall back to
// the tag-derived profiles scoped to the page. Returns a short, de-duplicated id list.
// Token-free — only profile ids leave this function.
async function resolveFacebookLiteRefreshProfileIdsForPage(params: {
    env: Env
    db: D1Database
    namespaceId: string
    pageId: string
    pageName: string
}): Promise<string[]> {
    const namespaceId = String(params.namespaceId || '').trim()
    const pageId = String(params.pageId || '').trim()
    if (!namespaceId || !pageId) return []

    const ids: string[] = []
    let linkedProfiles: NamespacePageLinkedTaggedProfiles = {}
    try {
        linkedProfiles = await getNamespaceLinkedTaggedProfiles(params.db, namespaceId)
        if (hasLinkedTaggedProfilesEntryForPage(linkedProfiles, pageId)) {
            for (const id of getLinkedTaggedProfileIdsForPage(linkedProfiles, pageId)) {
                const v = String(id || '').trim()
                if (v) ids.push(v)
            }
        }
    } catch { /* fall through to tag-derived resolution */ }

    if (ids.length === 0) {
        try {
            const profiles = await fetchBrowserSavingProfilesForNamespace(params.env, params.db, namespaceId)
            const hiddenProfiles = await getNamespaceHiddenTaggedProfiles(params.db, namespaceId)
            const scoped = filterProfilesForTaggedPage({
                profiles,
                pageId,
                pageName: String(params.pageName || '').trim(),
                hiddenProfiles,
                linkedProfiles,
            })
            for (const profile of scoped) {
                const v = String(profile.id || '').trim()
                if (v) ids.push(v)
            }
        } catch { /* no profiles resolvable for this page */ }
    }

    return uniqueTokens(ids)
}

// The namespace operator email(s) — used to scope BrowserSaving's server-side auto-discovery
// to this tenant's stored Account Manager profiles. Empty when unknown (BrowserSaving then
// searches all credentialed profiles, bounded; page ownership is itself the authority).
async function resolveNamespaceOwnerEmails(db: D1Database, namespaceId: string): Promise<string[]> {
    const ns = String(namespaceId || '').trim()
    if (!ns) return []
    try {
        const rows = await db.prepare(
            "SELECT DISTINCT lower(trim(email)) AS email FROM users WHERE namespace_id = ? AND TRIM(COALESCE(email,'')) <> ''"
        ).bind(ns).all() as { results?: Array<{ email?: string }> }
        return uniqueTokens((rows.results || [])
            .map((r) => String(r?.email || '').trim().toLowerCase())
            .filter((e) => e.includes('@')))
    } catch {
        return []
    }
}

// POST helper to BrowserSaving's FB Lite refresh route; tries each base, parses the token-free
// outcome. Returns null only when every base threw (transport error).
async function postFacebookLiteRefresh(
    env: Env,
    bases: string[],
    requestBody: FacebookLiteRefreshRequestBody,
    onTransportError: (reason: string) => void,
): Promise<FacebookLiteRefreshOutcome | null> {
    const body = JSON.stringify(requestBody)
    let outcome: FacebookLiteRefreshOutcome | null = null
    for (const base of bases) {
        try {
            const response = await fetchFromBrowserSavingBase(env, base, '/api/fb-lite/refresh-comment-token', {
                method: 'POST',
                headers: { Accept: 'application/json', 'Content-Type': 'application/json' },
                body,
            })
            const data = await response.json().catch(() => ({}))
            outcome = parseFacebookLiteRefreshResponse(response.ok, data)
            // Stop probing other bases on success or any definite (non-5xx) answer.
            if (outcome.ok || response.status < 500) break
        } catch (e) {
            onTransportError(e instanceof Error ? e.message : String(e))
        }
    }
    return outcome
}

// On-demand Facebook Lite (FB GET Token) refresh for a page's stored comment token. NO manual
// linking/tagging is required: BrowserSaving re-mints a fresh page token from the stored
// Account Manager credentials (uid/password/TOTP/datr) and pushes it into this namespace's
// token pool via profile-sync. We try operator-LINKED profiles first (optimization), then ask
// BrowserSaving to AUTO-DISCOVER the profile that owns/admins the page (page_id only, scoped by
// the namespace owner email). On return the pool holds the fresh token, so the caller re-reads
// it (resolveFacebookCommentToken) and retries. Best-effort: any failure returns
// refreshed:false and the caller keeps its bridge-fallback / fail behavior. Token-free — the
// Worker never logs a token; BrowserSaving returns only booleans + redacted hints + ids.
async function refreshFacebookLiteCommentTokenForPage(params: {
    env: Env
    db: D1Database
    namespaceId: string
    pageId: string
    pageName: string
    candidateProfileIds?: string[]
    candidateLoginIds?: string[]
    logPrefix: string
}): Promise<{ refreshed: boolean; synced: boolean; profileCount: number; reason: string }> {
    const namespaceId = String(params.namespaceId || '').trim()
    const pageId = String(params.pageId || '').trim()
    if (!namespaceId || !pageId) {
        return { refreshed: false, synced: false, profileCount: 0, reason: 'invalid_namespace_or_page' }
    }

    const bases = buildBrowserSavingProfileBaseUrls(params.env)
    if (bases.length === 0) {
        return { refreshed: false, synced: false, profileCount: 0, reason: 'browsersaving_not_configured' }
    }

    const explicitCandidateIds = normalizeHiddenTaggedProfileIds(params.candidateProfileIds || [])
    const explicitCandidateLoginIds = uniqueTokens((params.candidateLoginIds || []).map((v) => String(v || '').trim()).filter(Boolean))
    const linkedIds = normalizeHiddenTaggedProfileIds([
        ...explicitCandidateIds,
        ...await resolveFacebookLiteRefreshProfileIdsForPage({
            env: params.env,
            db: params.db,
            namespaceId,
            pageId,
            pageName: params.pageName,
        }),
    ])
    const ownerEmails = await resolveNamespaceOwnerEmails(params.db, namespaceId)

    let refreshed = false
    let synced = false
    let lastReason = 'refresh_failed'
    const onTransportError = (reason: string) => { lastReason = reason }

    const applyOutcome = (outcome: FacebookLiteRefreshOutcome | null): boolean => {
        if (outcome?.refreshed) {
            refreshed = true
            lastReason = outcome.reason
            if (outcome.synced) { synced = true; return true }
        } else if (outcome) {
            lastReason = outcome.reason
        }
        return false
    }

    // 1) Operator-linked profiles first (fast path when a page is explicitly linked).
    for (const profileId of linkedIds) {
        const outcome = await postFacebookLiteRefresh(
            params.env, bases,
            buildFacebookLiteRefreshRequestBody({ profileId, pageId, pageName: params.pageName, namespaceId, ownerEmails, candidateLoginIds: explicitCandidateLoginIds }),
            onTransportError,
        )
        if (applyOutcome(outcome)) break // one synced profile is enough
    }

    // 2) Auto-discover by page when no linked profile synchronized a fresh token. This is the
    // key behavior: a credentialed Account Manager profile that owns the page is found and used
    // even though it was never manually linked/tagged ("no_linked_profile" is NOT terminal).
    if (!synced) {
        const outcome = await postFacebookLiteRefresh(
            params.env, bases,
            buildFacebookLiteRefreshRequestBody({ pageId, pageName: params.pageName, namespaceId, ownerEmails, candidateProfileIds: linkedIds, candidateLoginIds: explicitCandidateLoginIds }),
            onTransportError,
        )
        applyOutcome(outcome)
    }

    console.log(`[${params.logPrefix}] fb-lite refresh ns=${namespaceId} page=${pageId} linked=${linkedIds.length} owners=${ownerEmails.length} refreshed=${refreshed} synced=${synced} reason=${lastReason}`)
    return { refreshed, synced, profileCount: linkedIds.length, reason: lastReason }
}

// Read-only probe (no mint) for the dry-run maintenance path: ask BrowserSaving whether a
// stored Account Manager profile owns/admins the page and could be refreshed. Token-free.
async function probeFacebookLiteProfilesForPage(params: {
    env: Env
    db: D1Database
    namespaceId: string
    pageId: string
    pageName: string
    candidateProfileIds?: string[]
    candidateLoginIds?: string[]
}): Promise<{ ok: boolean; wouldRefresh: boolean; profileFound: boolean; credentialedCount: number; linkedCount: number; reason: string }> {
    const namespaceId = String(params.namespaceId || '').trim()
    const pageId = String(params.pageId || '').trim()
    const explicitCandidateIds = normalizeHiddenTaggedProfileIds(params.candidateProfileIds || [])
    const explicitCandidateLoginIds = uniqueTokens((params.candidateLoginIds || []).map((v) => String(v || '').trim()).filter(Boolean))
    const linkedIds = normalizeHiddenTaggedProfileIds([
        ...explicitCandidateIds,
        ...await resolveFacebookLiteRefreshProfileIdsForPage({
            env: params.env,
            db: params.db,
            namespaceId,
            pageId,
            pageName: params.pageName,
        }),
    ])
    const ownerEmails = await resolveNamespaceOwnerEmails(params.db, namespaceId)
    const bases = buildBrowserSavingProfileBaseUrls(params.env)
    if (bases.length === 0) {
        return { ok: false, wouldRefresh: linkedIds.length > 0, profileFound: false, credentialedCount: 0, linkedCount: linkedIds.length, reason: 'browsersaving_not_configured' }
    }
    const body = JSON.stringify({
        page_id: pageId,
        namespace_id: namespaceId,
        page_name: params.pageName,
        owner_emails: ownerEmails,
        candidate_profile_ids: linkedIds,
        candidate_login_ids: explicitCandidateLoginIds,
    })
    for (const base of bases) {
        try {
            const response = await fetchFromBrowserSavingBase(params.env, base, '/api/fb-lite/profiles-for-page', {
                method: 'POST',
                headers: { Accept: 'application/json', 'Content-Type': 'application/json' },
                body,
            })
            const data = await response.json().catch(() => ({})) as Record<string, unknown>
            if (response.ok && data?.ok === true) {
                return {
                    ok: true,
                    wouldRefresh: data.would_refresh === true,
                    profileFound: data.profile_found === true,
                    credentialedCount: Number(data.credentialed_count || 0),
                    linkedCount: linkedIds.length,
                    reason: String(data.via || (data.profile_found ? 'owner_found' : '')).slice(0, 120),
                }
            }
            if (response.status < 500) break
        } catch { /* try next base */ }
    }
    return { ok: false, wouldRefresh: linkedIds.length > 0, profileFound: false, credentialedCount: 0, linkedCount: linkedIds.length, reason: 'probe_failed' }
}

// Bridge Token (Facebook Lite / Power Editor) fallback page-token fetch. Pulls a fresh
// page-scoped access token directly from the Bridge Token local tool's `/pages?...&includeToken=1`
// route via the production tunnel (CLOAK_FB_BRIDGE_URL = https://short.wwoom.com). Used ONLY when
// the BrowserSaving secret refresh route did not sync a fresh token (e.g. it returned "Not found").
// Tries each candidate login id first, then the tool's default logged-in session (no account),
// which lists every administered page. The returned token is held IN MEMORY by the caller and is
// NEVER logged or returned to a client — only its presence is logged.
async function fetchFacebookLitePageTokenFromBridge(params: {
    env: Env
    pageId: string
    candidateLoginIds?: string[]
    logPrefix: string
}): Promise<{ token: string; account: string }> {
    const baseUrl = resolveCloakFbBridgeBaseUrl(params.env)
    const pageId = String(params.pageId || '').trim()
    if (!baseUrl || !pageId) return { token: '', account: '' }
    // Candidate login ids first (multi-account bridge), THEN the default session (''). The ''
    // sentinel must be appended AFTER de-duping the non-empty candidates — uniqueTokens() drops
    // blanks, so folding it into the dedupe would silently skip the default-session lookup, which
    // is the live production path (no candidate ids are passed by force-post/retry/cron, and the
    // tool's default session lists every administered page, e.g. CHEARB).
    const accounts = [
        ...uniqueTokens((params.candidateLoginIds || []).map((v) => String(v || '').trim())),
        '',
    ]
    for (const account of accounts) {
        const url = buildBridgeTokenPagesUrl({ baseUrl, account, includeToken: true })
        if (!url) continue
        try {
            const resp = await fetchWithTimeout(url, {
                method: 'GET',
                headers: { Accept: 'application/json' },
            }, 30000, 'bridge_token_pages')
            const data = await resp.json().catch(() => ({}))
            const lookup = extractBridgeTokenPageAccessToken(data, pageId)
            if (lookup.found && lookup.accessToken) {
                console.log(`[${params.logPrefix}] bridge token /pages lookup ok page=${pageId} account=${account ? 'candidate' : 'default'} token_present=true`)
                return { token: lookup.accessToken, account }
            }
        } catch (e) {
            console.warn(`[${params.logPrefix}] bridge token /pages lookup failed (${e instanceof Error ? e.message : String(e)})`)
        }
    }
    return { token: '', account: '' }
}

// Dedicated bridge sync secret for the Worker → bridge /token/auto-sync recovery trigger. Prefers a
// purpose-provisioned BRIDGE_TOKEN_SYNC_SECRET, then the existing BrowserSaving tag-sync secrets, so
// the auto-sync can be authorized without rotating any existing secret. Never logged.
function getBridgeTokenSyncSecret(env: Env): string {
    const e = env as Env & { BRIDGE_TOKEN_SYNC_SECRET?: string; BROWSERSAVING_TAG_SYNC_SECRET?: string }
    return String(e.BRIDGE_TOKEN_SYNC_SECRET || e.TAG_SYNC_PUSH_SECRET || e.BROWSERSAVING_TAG_SYNC_SECRET || '').trim()
}

// Resolve the ordered Facebook Lite fallback-account chain for a failing page from env mappings. The
// mapping lets an operator declare "when page P / account A can no longer mint a token, try account B"
// WITHOUT hardcoding any uid in the binary (e.g. Chanalai 100090320823561 → Thanwan 100077795357192).
// Two env vars, both optional JSON objects (malformed → ignored, never throws):
//   FACEBOOK_LITE_PAGE_FALLBACK_ACCOUNTS    {"<pageId>":["<accountUid>", ...]}
//   FACEBOOK_LITE_ACCOUNT_FALLBACKS         {"<primaryAccountUid>":["<fallbackUid>", ...]}
// The bridge ALSO merges these (and tries the primary first), so this is the Worker-side hint. Primary
// account + the page itself are excluded from the result. Token-free (uids are public ids).
function resolveFacebookLiteFallbackAccounts(env: Env, params: { pageId?: string; primaryAccount?: string }): string[] {
    const e = env as Env & { FACEBOOK_LITE_PAGE_FALLBACK_ACCOUNTS?: string; FACEBOOK_LITE_ACCOUNT_FALLBACKS?: string }
    return resolveBridgeFallbackAccounts({
        primaryAccount: params.primaryAccount,
        pageId: params.pageId,
        pageFallbackMap: parseAccountFallbackMap(e.FACEBOOK_LITE_PAGE_FALLBACK_ACCOUNTS),
        accountFallbackMap: parseAccountFallbackMap(e.FACEBOOK_LITE_ACCOUNT_FALLBACKS),
    })
}

// Per-namespace backoff for the AUTOMATIC bridge auto-sync trigger. A repeated invalidated-token
// failure across pages / cron passes must not re-mint a fresh token every time (that trips Facebook's
// login rate limiter). One live recovery per namespace per TTL window is enough — its profile-sync
// refreshes EVERY administered page in that namespace at once, so siblings recover from a single call.
const BRIDGE_AUTO_SYNC_TTL_MS = (() => {
    const raw = Number(((globalThis as { BRIDGE_AUTO_SYNC_TTL_MS_OVERRIDE?: number }).BRIDGE_AUTO_SYNC_TTL_MS_OVERRIDE) ?? NaN)
    return Number.isFinite(raw) && raw >= 0 ? raw : 5 * 60 * 1000
})()
const bridgeAutoSyncLastAttemptByNamespace = new Map<string, number>()

// Per-page POSTING auth-failure circuit breaker. The per-namespace auto-sync TTL above only throttles
// tier-3 auto-sync, and at 5 min it re-arms before the ~30-min posting cron fires again — so every
// cron pass still re-mints (a Facebook LOGIN) for an invalidated page, which is exactly what trips
// Facebook's automated-behavior/checkpoint detection. This breaker sits in FRONT of the WHOLE
// posting-token recovery (all three tiers): once a recovery fails after actually reaching Facebook,
// it opens for a cooldown window (longer for a checkpoint/automation signal) so subsequent cron
// passes skip every re-mint for that page and return a sanitized `auth_failure_cooldown`. A
// successful recovery clears it immediately. In-memory only (mirrors the auto-sync TTL map); an
// isolate recycle resets it, which only makes the breaker more lenient, never more aggressive.
const POSTING_AUTH_COOLDOWN_MS = (() => {
    const raw = Number(((globalThis as { POSTING_AUTH_COOLDOWN_MS_OVERRIDE?: number }).POSTING_AUTH_COOLDOWN_MS_OVERRIDE) ?? NaN)
    return Number.isFinite(raw) && raw >= 0 ? raw : 30 * 60 * 1000
})()
const POSTING_AUTH_CHECKPOINT_COOLDOWN_MS = (() => {
    const raw = Number(((globalThis as { POSTING_AUTH_CHECKPOINT_COOLDOWN_MS_OVERRIDE?: number }).POSTING_AUTH_CHECKPOINT_COOLDOWN_MS_OVERRIDE) ?? NaN)
    return Number.isFinite(raw) && raw >= 0 ? raw : 6 * 60 * 60 * 1000
})()
const postingAuthCircuitByPage = new Map<string, { until: number; reason: string }>()
function postingAuthCircuitKey(namespaceId: string, pageId: string): string {
    return `${String(namespaceId || '').trim()}::${String(pageId || '').trim()}`
}
// Read the breaker for a page. Open → recovery must be skipped (no Facebook contact at all). Expired
// entries are pruned so the map cannot grow unbounded across pages.
function getPostingAuthCircuit(namespaceId: string, pageId: string, nowMs: number): { open: boolean; reason: string; until: number } {
    const key = postingAuthCircuitKey(namespaceId, pageId)
    const entry = postingAuthCircuitByPage.get(key)
    if (!entry) return { open: false, reason: '', until: 0 }
    if (!isPostingAuthCooldownActive(entry.until, nowMs)) {
        postingAuthCircuitByPage.delete(key)
        return { open: false, reason: '', until: 0 }
    }
    return { open: true, reason: entry.reason, until: entry.until }
}
// Arm the breaker after a recovery that actually reached Facebook and still failed. Checkpoint /
// automation signals earn the longer cooldown. `reason` is a short sanitized hint, never a token.
function armPostingAuthCircuit(namespaceId: string, pageId: string, params: { checkpoint: boolean; reason: string; nowMs: number }): number {
    const cooldownMs = resolvePostingAuthCooldownMs({
        checkpoint: params.checkpoint,
        authCooldownMs: POSTING_AUTH_COOLDOWN_MS,
        checkpointCooldownMs: POSTING_AUTH_CHECKPOINT_COOLDOWN_MS,
    })
    if (!(cooldownMs > 0)) return 0
    const until = params.nowMs + cooldownMs
    postingAuthCircuitByPage.set(postingAuthCircuitKey(namespaceId, pageId), {
        until,
        reason: String(params.reason || (params.checkpoint ? 'checkpoint' : 'auth')).slice(0, 60),
    })
    return until
}
function clearPostingAuthCircuit(namespaceId: string, pageId: string): void {
    postingAuthCircuitByPage.delete(postingAuthCircuitKey(namespaceId, pageId))
}

// AUTOMATIC true-bridge recovery. When a stored/Facebook Lite token has been invalidated (190 /
// "session has been invalidated"), the Worker asks the local Facebook Lite bridge to re-mint a fresh
// token from the stored credentials/session and refresh every matching page token in this namespace's
// pool — NO operator action, button, or manual export. This is the machine-to-machine counterpart of
// the (now removed) UI sync: the bridge endpoint is secret-authenticated. Fails CLOSED with a
// sanitized reason (and does NOT mark anything recovered) when the bridge URL or secret is missing.
// Rate-limit-backed off to one live attempt per namespace per TTL. Token-free everywhere.
async function triggerBridgeAutoSyncForPage(params: {
    env: Env
    namespaceId: string
    candidateLoginIds?: string[]
    // Page-targeted recovery context: when the failing page id is known the bridge scopes its scan to
    // that page and falls back across the configured accounts (primary → Thanwan, etc.) that actually
    // administer it — reporting page_not_found_for_all_accounts instead of silently doing nothing.
    pageId?: string
    fallbackAccounts?: string[]
    logPrefix: string
    nowMs?: number
}): Promise<{ ok: boolean; synced: boolean; reason: string; skipped?: boolean }> {
    const namespaceId = String(params.namespaceId || '').trim()
    if (!namespaceId) return { ok: false, synced: false, reason: 'invalid_namespace' }
    const baseUrl = resolveCloakFbBridgeBaseUrl(params.env)
    if (!baseUrl) return { ok: false, synced: false, reason: 'bridge_not_configured' }
    const secret = getBridgeTokenSyncSecret(params.env)
    if (!secret) return { ok: false, synced: false, reason: 'sync_secret_missing' }

    const now = Number.isFinite(params.nowMs) ? Number(params.nowMs) : Date.now()
    const last = bridgeAutoSyncLastAttemptByNamespace.get(namespaceId)
    if (!isBridgeAutoSyncAllowed(last, now, BRIDGE_AUTO_SYNC_TTL_MS)) {
        console.log(`[${params.logPrefix}] bridge auto-sync throttled ns=${namespaceId} (recent attempt within ttl)`)
        return { ok: false, synced: false, reason: 'auto_sync_throttled', skipped: true }
    }
    bridgeAutoSyncLastAttemptByNamespace.set(namespaceId, now)

    const url = buildBridgeAutoSyncUrl(baseUrl)
    if (!url) return { ok: false, synced: false, reason: 'bridge_not_configured' }
    // Merge per-call fallback hints with the env-configured mapping for this page/account, so a
    // page-targeted recovery (Chanalai → Thanwan) works even when the caller only knows the page id.
    const fallbackAccounts = resolveBridgeFallbackAccounts({
        primaryAccount: (params.candidateLoginIds ?? [])[0],
        pageId: params.pageId,
        explicit: params.fallbackAccounts,
        pageFallbackMap: parseAccountFallbackMap((params.env as Env & { FACEBOOK_LITE_PAGE_FALLBACK_ACCOUNTS?: string }).FACEBOOK_LITE_PAGE_FALLBACK_ACCOUNTS),
        accountFallbackMap: parseAccountFallbackMap((params.env as Env & { FACEBOOK_LITE_ACCOUNT_FALLBACKS?: string }).FACEBOOK_LITE_ACCOUNT_FALLBACKS),
    })
    const body = buildBridgeAutoSyncRequestBody({
        namespaceId,
        candidateLoginIds: params.candidateLoginIds,
        pageId: params.pageId,
        fallbackAccounts,
    })
    try {
        const resp = await fetchWithTimeout(url, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                Accept: 'application/json',
                // Machine-to-machine auth so the remote Worker (over the cloudflared tunnel) can drive
                // a LIVE recovery without the local-only UI. Both header names are accepted by the bridge.
                'x-bridge-sync-secret': secret,
                'x-tag-sync-secret': secret,
            },
            body: JSON.stringify(body),
        }, 60000, 'bridge_token_auto_sync')
        const data = await resp.json().catch(() => ({}))
        const outcome = parseBridgeAutoSyncResponse(resp.ok !== false && resp.status >= 200 && resp.status < 300, data)
        console.log(`[${params.logPrefix}] bridge auto-sync ns=${namespaceId} status=${resp.status} ok=${outcome.ok} synced=${outcome.synced} reason=${outcome.reason}`)
        return outcome
    } catch (e) {
        const reason = (e instanceof Error ? e.message : String(e)).slice(0, 120)
        console.warn(`[${params.logPrefix}] bridge auto-sync failed ns=${namespaceId} (${reason})`)
        return { ok: false, synced: false, reason: 'bridge_auto_sync_unreachable' }
    }
}

// On-demand Facebook Lite (FB GET Token) refresh for a stored-token page's POSTING token. There is
// no permanent "token expired" state for a Facebook Lite page: this re-mints a fresh page token and
// syncs it into this namespace's pool so the caller can re-read it and retry publishing.
//   1) Preferred — the BrowserSaving secret route re-mints from stored Account Manager credentials
//      and pushes the fresh token back via profile-sync (token-free, auto-discovers by page_id).
//   2) Fallback — if that route did NOT sync (unavailable / "Not found"), pull a fresh page token
//      straight from the Bridge Token tool's /pages route and upsert it into the pool ourselves.
//   3) Last resort — trigger the bridge's own /token/auto-sync TRUE-RECOVERY (it re-mints from the
//      stored bridge session/credentials and refreshes every administered page in this namespace).
// Best-effort and token-free in logs: the Worker never logs a raw token value.
async function refreshFacebookLitePostingTokenForPage(params: {
    env: Env
    db: D1Database
    namespaceId: string
    pageId: string
    pageName: string
    candidateLoginIds?: string[]
    // Per-page Accounts Bridge posting account UID (pages.posting_profile_uid). When set, the refresh
    // request targets this exact account as profile_id / candidate_profile_ids. Blank → unchanged
    // auto-discovery behavior (the bridge finds the credentialed profile that owns the page).
    configuredPostingProfileUid?: string
    // The sanitized publish error that triggered this refresh. Used ONLY to classify the cooldown
    // severity (checkpoint/automation vs plain auth) when arming the circuit breaker — never logged raw.
    originalError?: string
    // Test seam for the auth-failure circuit breaker clock. Omitted → Date.now().
    nowMs?: number
    logPrefix: string
}): Promise<{ refreshed: boolean; synced: boolean; via: string; reason: string }> {
    const now = Number.isFinite(params.nowMs) ? Number(params.nowMs) : Date.now()
    // Circuit breaker: if a recent recovery for this page already failed after reaching Facebook,
    // skip EVERY re-mint tier (BrowserSaving login, bridge /pages, auto-sync) until the cooldown
    // expires. This is the anti-automation guard — it stops the ~30-min cron from re-logging-in on a
    // checkpointed/invalidated account. Returns a sanitized reason; no Facebook contact whatsoever.
    const circuit = getPostingAuthCircuit(params.namespaceId, params.pageId, now)
    if (circuit.open) {
        console.log(`[${params.logPrefix}] posting-token refresh skipped page=${params.pageId} (auth_failure_cooldown active until=${new Date(circuit.until).toISOString()} reason=${circuit.reason})`)
        return { refreshed: false, synced: false, via: 'auth_cooldown', reason: 'auth_failure_cooldown' }
    }
    const configuredProfileUid = sanitizePostingProfileUid(params.configuredPostingProfileUid)
    // Prepend the configured UID so it is tried first as both an explicit candidate profile id and a
    // candidate login id, without discarding any caller-supplied candidates. Blank → no override.
    const candidateProfileIds = configuredProfileUid ? [configuredProfileUid] : undefined
    const candidateLoginIds = configuredProfileUid
        ? [configuredProfileUid, ...(params.candidateLoginIds ?? [])]
        : params.candidateLoginIds
    // 1) BrowserSaving secret mint + profile-sync (the fresh page token lands in the post pool).
    const bs = await refreshFacebookLiteCommentTokenForPage({
        env: params.env,
        db: params.db,
        namespaceId: params.namespaceId,
        pageId: params.pageId,
        pageName: params.pageName,
        candidateProfileIds,
        candidateLoginIds,
        logPrefix: `${params.logPrefix} POST-REFRESH`,
    }).catch((e) => ({ refreshed: false, synced: false, profileCount: 0, reason: (e instanceof Error ? e.message : String(e)).slice(0, 120) }))
    if (bs.synced) {
        clearPostingAuthCircuit(params.namespaceId, params.pageId)
        return { refreshed: true, synced: true, via: 'browsersaving', reason: bs.reason }
    }

    // 2) Bridge Token /pages fallback when BrowserSaving did not sync a token.
    const bridge = await fetchFacebookLitePageTokenFromBridge({
        env: params.env,
        pageId: params.pageId,
        candidateLoginIds,
        logPrefix: `${params.logPrefix} BRIDGE-TOKEN`,
    })
    if (bridge.token) {
        try {
            await upsertNamespacePageFromProfileSync(params.env, {
                namespaceId: params.namespaceId,
                pageId: params.pageId,
                pageName: params.pageName,
                accessToken: bridge.token,
                commentToken: bridge.token,
                // Token REFRESH must never materialize a brand-new active page — only refresh the token
                // of a row that already exists in this namespace. If the page is gone, skip (no create).
                updateOnly: true,
            })
            console.log(`[${params.logPrefix}] bridge token synced into pool page=${params.pageId} via=bridge_token_pages`)
            clearPostingAuthCircuit(params.namespaceId, params.pageId)
            return { refreshed: true, synced: true, via: 'bridge_token_pages', reason: 'bridge_token_synced' }
        } catch (e) {
            const reason = (e instanceof Error ? e.message : String(e)).slice(0, 120)
            console.warn(`[${params.logPrefix}] bridge token sync into pool failed (${reason})`)
            return { refreshed: true, synced: false, via: 'bridge_token_pages', reason }
        }
    }

    // 3) Bridge /token/auto-sync TRUE-RECOVERY as the last automatic tier: the bridge re-mints from
    // its stored session/credentials and refreshes every administered page in this namespace's pool.
    // Fully automatic — no operator action — and bounded by the per-namespace backoff inside it.
    const autoSync = await triggerBridgeAutoSyncForPage({
        env: params.env,
        namespaceId: params.namespaceId,
        candidateLoginIds,
        // Page-targeted true-recovery: scope the bridge to the exact failing page and pass the
        // env-configured fallback chain (e.g. Chanalai → Thanwan) so an account that lost the page
        // hands off to one that still administers it.
        pageId: params.pageId,
        fallbackAccounts: resolveFacebookLiteFallbackAccounts(params.env, {
            pageId: params.pageId,
            primaryAccount: (candidateLoginIds ?? [])[0],
        }),
        logPrefix: `${params.logPrefix} BRIDGE-AUTOSYNC`,
    })
    if (autoSync.synced) {
        clearPostingAuthCircuit(params.namespaceId, params.pageId)
        return { refreshed: true, synced: true, via: 'bridge_auto_sync', reason: autoSync.reason }
    }

    // Every recovery tier failed. Arm the circuit breaker so the next ~30-min cron pass backs off
    // instead of re-minting (re-logging-in) again — UNLESS the failure never reached Facebook
    // (bridge unreachable / not configured / throttled), in which case cooling down would only block
    // recovery without preventing any hammering. A checkpoint/automation signal in the original
    // publish error (or the recovery reason) earns the much longer cooldown.
    const failureReason = autoSync.reason || bs.reason
    if (shouldArmPostingAuthCooldown(failureReason)) {
        const checkpoint =
            isFacebookCheckpointOrAutomationFailure(params.originalError) ||
            isFacebookCheckpointOrAutomationFailure(autoSync.reason) ||
            isFacebookCheckpointOrAutomationFailure(bs.reason)
        const until = armPostingAuthCircuit(params.namespaceId, params.pageId, { checkpoint, reason: checkpoint ? 'checkpoint' : 'auth', nowMs: now })
        if (until > 0) {
            console.warn(`[${params.logPrefix}] posting-token recovery failed page=${params.pageId} — armed auth_failure_cooldown (${checkpoint ? 'checkpoint' : 'auth'}) until=${new Date(until).toISOString()}`)
        }
    }

    return { refreshed: bs.refreshed, synced: false, via: 'none', reason: failureReason }
}

async function initReelUploadWithPostingTokenAutoRecover(params: {
    env: Env
    db: D1Database
    namespaceId: string
    pageId: string
    pageName: string
    postTokens: string[]
    logPrefix: string
}): Promise<{
    video_id?: string
    upload_url?: string
    postingToken: string
    tried: number
}> {
    const initialTokens = normalizePostTokenPool(params.postTokens || [])
    return initReelUploadWithPostingTokenFallback({
        pageId: params.pageId,
        postTokens: initialTokens,
        logPrefix: params.logPrefix,
    })
}

async function getPostedVideoIds(params: {
    db: D1Database
    namespaceId?: string
    pageId?: string
    withinDays?: number
}): Promise<Set<string>> {
    const namespaceId = String(params.namespaceId || '').trim()
    const pageId = String(params.pageId || '').trim()
    const hasNamespace = !!namespaceId
    const hasPage = !!pageId
    const withinDays = Number(params.withinDays || 0)
    const cutoffMs = withinDays > 0 ? (Date.now() - withinDays * 24 * 60 * 60 * 1000) : null

    const where: string[] = [
        `(
            status = 'success'
            OR TRIM(COALESCE(fb_post_id, '')) <> ''
            OR TRIM(COALESCE(fb_reel_url, '')) <> ''
        )`,
    ]
    const binds: string[] = []

    if (hasNamespace) {
        where.push('bot_id = ?')
        binds.push(namespaceId)
    }
    if (hasPage) {
        where.push('page_id = ?')
        binds.push(pageId)
    }

    const sql = `SELECT video_id, posted_at
        FROM post_history
        WHERE ${where.join('\n          AND ')}`

    const result = await params.db.prepare(sql).bind(...binds).all() as {
        results?: Array<{ video_id?: string; posted_at?: string }>
    }

    const out = new Set<string>()
    for (const row of result.results || []) {
        const id = String(row?.video_id || '').trim()
        if (cutoffMs !== null) {
            const postedAtMs = Date.parse(String(row?.posted_at || ''))
            if (!Number.isFinite(postedAtMs) || postedAtMs < cutoffMs) continue
        }
        if (id) out.add(id)
    }
    return out
}

async function getLatestPostedAtByVideoIds(params: {
    db: D1Database
    namespaceId: string
    videoIds: string[]
}): Promise<Map<string, string>> {
    const namespaceId = String(params.namespaceId || '').trim()
    const videoIds = Array.from(new Set((params.videoIds || []).map((videoId) => String(videoId || '').trim()).filter(Boolean)))
    const out = new Map<string, string>()
    if (!namespaceId || videoIds.length === 0) return out

    // D1/SQLite can reject larger IN lists in some production paths.
    // Keep this conservative because system gallery reconciliation can span
    // many videos across many namespaces on a single request.
    const chunkSize = 25
    for (let i = 0; i < videoIds.length; i += chunkSize) {
        const chunk = videoIds.slice(i, i + chunkSize)
        const placeholders = chunk.map(() => '?').join(', ')
        const sql = `SELECT video_id, MAX(posted_at) AS posted_at
            FROM post_history
            WHERE bot_id = ?
              AND video_id IN (${placeholders})
              AND (
                status = 'success'
                OR TRIM(COALESCE(fb_post_id, '')) <> ''
                OR TRIM(COALESCE(fb_reel_url, '')) <> ''
              )
            GROUP BY video_id`
        const result = await params.db.prepare(sql).bind(namespaceId, ...chunk).all() as {
            results?: Array<{ video_id?: string; posted_at?: string }>
        }
        for (const row of result.results || []) {
            const videoId = String(row?.video_id || '').trim()
            const postedAt = String(row?.posted_at || '').trim()
            if (videoId && postedAt) out.set(videoId, postedAt)
        }
    }

    return out
}

async function getLatestPostedAtBySourceFingerprints(params: {
    db: D1Database
    namespaceId: string
    sourceFingerprints: string[]
}): Promise<Map<string, string>> {
    const namespaceId = String(params.namespaceId || '').trim()
    const sourceFingerprints = Array.from(new Set((params.sourceFingerprints || [])
        .map((value) => normalizeNamespaceVideoSourceFingerprint(value))
        .filter(Boolean)))
    const out = new Map<string, string>()
    if (!namespaceId || sourceFingerprints.length === 0) return out

    const chunkSize = 25
    for (let i = 0; i < sourceFingerprints.length; i += chunkSize) {
        const chunk = sourceFingerprints.slice(i, i + chunkSize)
        const placeholders = chunk.map(() => '?').join(', ')
        const sql = `SELECT
                COALESCE(NULLIF(TRIM(ph.source_fingerprint), ''), nvs.source_fingerprint) AS source_fingerprint,
                MAX(ph.posted_at) AS posted_at
            FROM post_history ph
            LEFT JOIN namespace_video_state nvs
              ON nvs.namespace_id = ph.bot_id
             AND nvs.video_id = ph.video_id
            WHERE ph.bot_id = ?
              AND COALESCE(NULLIF(TRIM(ph.source_fingerprint), ''), nvs.source_fingerprint) IN (${placeholders})
              AND (
                ph.status IN ('success', 'posting')
                OR TRIM(COALESCE(ph.fb_post_id, '')) <> ''
                OR TRIM(COALESCE(ph.fb_reel_url, '')) <> ''
              )
            GROUP BY COALESCE(NULLIF(TRIM(ph.source_fingerprint), ''), nvs.source_fingerprint)`
        const result = await params.db.prepare(sql).bind(namespaceId, ...chunk).all() as {
            results?: Array<{ source_fingerprint?: string; posted_at?: string }>
        }
        for (const row of result.results || []) {
            const sourceFingerprint = normalizeNamespaceVideoSourceFingerprint(row?.source_fingerprint)
            const postedAt = String(row?.posted_at || '').trim()
            if (sourceFingerprint && postedAt) out.set(sourceFingerprint, postedAt)
        }
    }

    return out
}

async function reconcileNamespacePostedStateFromHistory(params: {
    db: D1Database
    namespaceId: string
    sourceVideos: Array<Record<string, unknown>>
    stateByVideoId: Map<string, NamespaceVideoStateRow>
}): Promise<void> {
    const namespaceId = String(params.namespaceId || '').trim()
    if (!namespaceId || params.sourceVideos.length === 0) return

    const candidateVideoIds = params.sourceVideos
        .map((video) => String(video?.id || '').trim())
        .filter(Boolean)
        .filter((videoId) => !String(params.stateByVideoId.get(videoId)?.posted_at || '').trim())

    if (candidateVideoIds.length === 0) return

    // 2026-04-29: Reconciler now matches by EXACT video_id only — no longer
    // back-fills posted_at from sibling videos that share the same
    // source_fingerprint. Cross-video fingerprint dedup is enforced at cron
    // post-time inside claimGalleryVideoForPosting (safety net checks
    // post_history for both video_id AND source_fingerprint), so freshly
    // uploaded videos with the same content as a previously-posted video
    // still appear in the "ยังไม่โพสต์" gallery tab. The cron then refuses to
    // re-post duplicate content, but the user can see the upload landed.
    const postedAtByVideoId = await getLatestPostedAtByVideoIds({
        db: params.db,
        namespaceId,
        videoIds: candidateVideoIds,
    })
    if (postedAtByVideoId.size === 0) return

    for (const videoId of candidateVideoIds) {
        const currentRow = params.stateByVideoId.get(videoId) || {
            namespace_id: namespaceId,
            video_id: videoId,
        }
        if (String(currentRow.posted_at || '').trim()) continue
        const postedAt = postedAtByVideoId.get(videoId) || ''
        if (!postedAt) continue

        const manualUnpostedAt = String(currentRow.manual_unposted_at || '').trim()
        if (manualUnpostedAt) {
            const postedAtMs = Date.parse(postedAt)
            const manualUnpostedMs = Date.parse(manualUnpostedAt)
            if (
                Number.isFinite(postedAtMs)
                && Number.isFinite(manualUnpostedMs)
                && postedAtMs <= manualUnpostedMs
            ) {
                continue
            }
        }

        await upsertNamespaceVideoState(params.db, namespaceId, videoId, { posted_at: postedAt })
        params.stateByVideoId.set(videoId, {
            ...currentRow,
            namespace_id: namespaceId,
            video_id: videoId,
            posted_at: postedAt,
        })
    }
}

async function getConfirmedPostedVideoIds(params: {
    db: D1Database
    namespaceId?: string
}): Promise<Set<string>> {
    const namespaceId = String(params.namespaceId || '').trim()
    const hasNamespace = !!namespaceId
    const sql = hasNamespace
        ? `SELECT DISTINCT video_id
           FROM post_history
           WHERE bot_id = ?
             AND (
               status = 'success'
               OR TRIM(COALESCE(fb_post_id, '')) <> ''
               OR TRIM(COALESCE(fb_reel_url, '')) <> ''
             )`
        : `SELECT DISTINCT video_id
           FROM post_history
           WHERE (
             status = 'success'
             OR TRIM(COALESCE(fb_post_id, '')) <> ''
             OR TRIM(COALESCE(fb_reel_url, '')) <> ''
           )`

    const result = hasNamespace
        ? await params.db.prepare(sql).bind(namespaceId).all() as { results?: Array<{ video_id?: string }> }
        : await params.db.prepare(sql).all() as { results?: Array<{ video_id?: string }> }

    const out = new Set<string>()
    for (const row of result.results || []) {
        const id = String(row?.video_id || '').trim()
        if (id) out.add(id)
    }
    return out
}

