app.get('/api/pages/:id/avatar-video/public', async (c) => {
    const pageId = String(c.req.param('id') || '').trim()
    const namespaceId = String(c.req.query('namespace_id') || c.get('botId') || '').trim()
    if (!pageId) return c.json({ error: 'Page ID is required' }, 400)
    if (!namespaceId) return c.json({ error: 'namespace_id_required' }, 400)

    const page = await c.env.DB.prepare(
        'SELECT id, name FROM pages WHERE id = ? AND bot_id = ?'
    ).bind(pageId, namespaceId).first() as { id?: string; name?: string } | null
    if (!page?.id) return c.json({ error: 'Page not found' }, 404)

    const settings = await getPageAvatarSettings(c.env.DB, pageId)
    if (!settings.enabled || !settings.videoKey) return c.json({ error: 'avatar_video_not_enabled' }, 404)

    const bucket = new BotBucket(c.env.BUCKET, namespaceId) as unknown as R2Bucket
    const head = await bucket.head(settings.videoKey).catch(() => null)
    if (!head) return c.json({ error: 'avatar_video_not_found' }, 404)

    const response = await buildGalleryAssetResponse(bucket, settings.videoKey, 'public', c.req.header('range'))
    response.headers.set('Cache-Control', 'public, max-age=300')
    response.headers.set('X-Avatar-Version', settings.version || '')
    return response
})

app.put('/api/pages/:id/avatar-settings', async (c) => {
    const ownerCheck = await requireAuthSession(c)
    if (!ownerCheck.ok) return ownerCheck.response

    const pageId = String(c.req.param('id') || '').trim()
    const namespaceId = c.get('botId')
    if (!pageId) return c.json({ error: 'Page ID is required' }, 400)

    const page = await c.env.DB.prepare(
        'SELECT id, name FROM pages WHERE id = ? AND bot_id = ?'
    ).bind(pageId, namespaceId).first() as { id?: string; name?: string } | null
    if (!page?.id) return c.json({ error: 'Page not found' }, 404)

    const body = await c.req.json().catch(() => ({})) as Record<string, unknown>
    const previous = await getPageAvatarSettings(c.env.DB, pageId)
    const clearVideo = body.clear_video === true || body.remove_video === true || body.video_key === ''
    const nextVersion = clearVideo
        ? ''
        : sanitizeAvatarVersion(body.version ?? body.avatar_version ?? previous.version)
    const nextVideoKey = clearVideo
        ? ''
        : (nextVersion ? buildPageAvatarVideoKey(pageId, nextVersion) : previous.videoKey)

    if (!clearVideo && nextVersion && !nextVideoKey) {
        return c.json({ error: 'avatar_version_invalid' }, 400)
    }
    if (nextVideoKey) {
        const uploaded = await c.get('bucket').head(nextVideoKey).catch(() => null)
        if (!uploaded) return c.json({ error: 'avatar_video_not_uploaded' }, 400)
    }

    const enabledRaw = body.enabled ?? body.avatar_enabled
    const enabled = enabledRaw === undefined
        ? previous.enabled
        : enabledRaw === true || enabledRaw === 1 || String(enabledRaw).trim().toLowerCase() === 'true'
    if (enabled && !nextVideoKey) {
        return c.json({ error: 'avatar_video_required' }, 400)
    }

    const updatedAt = new Date().toISOString()
    const nextSettings: PageAvatarSettings = {
        enabled,
        videoKey: nextVideoKey,
        version: nextVersion,
        chromakeySimilarity: clampChromakeySimilarity(body.chromakey_similarity ?? body.chromakeySimilarity ?? previous.chromakeySimilarity),
        chromakeyBlend: clampChromakeyBlend(body.chromakey_blend ?? body.chromakeyBlend ?? previous.chromakeyBlend),
        updatedAt,
    }
    await setPageAvatarSettings(c.env.DB, pageId, nextSettings)

    return c.json({
        ok: true,
        page: {
            id: String(page.id || pageId),
            name: String(page.name || ''),
        },
        settings: serializePageAvatarSettings(nextSettings),
    }, 200, { 'Cache-Control': 'no-store' })
})

app.get('/api/dashboard', async (c) => {
    try {
        const botId = c.get('botId')
        const requestedDate = String(c.req.query('date') || '').trim()
        const targetDate = /^\d{4}-\d{2}-\d{2}$/.test(requestedDate)
            ? requestedDate
            : toThaiDateString(new Date())

        await ensureLinkSubmissionsTable(c.env.DB)
        await ensureTelegramBotSessionsTable(c.env.DB)
        await ensureLineUsersTable(c.env.DB)
        c.executionCtx.waitUntil(
            backfillRecentInboxLinkSubmissions({
                db: c.env.DB,
                bucket: c.get('bucket'),
                namespaceId: String(botId || ''),
            }).catch((e) => {
                console.error(`[DASHBOARD] Failed to backfill link submissions: ${e instanceof Error ? e.message : String(e)}`)
                return 0
            })
        )

        const [postsAllRow, postsOnDateRow, linksAllRow, linksOnDateRow, usersRes, scopedSessionsRes, lineUsersRes, linksByAdminRes] = await Promise.all([
            c.env.DB.prepare(
                "SELECT COUNT(*) AS total FROM post_history WHERE bot_id = ? AND status IN ('success','posting')"
            ).bind(botId).first() as Promise<{ total?: number } | null>,
            c.env.DB.prepare(
                "SELECT COUNT(*) AS total FROM post_history WHERE bot_id = ? AND status IN ('success','posting') AND date(datetime(posted_at, '+7 hours')) = ?"
            ).bind(botId, targetDate).first() as Promise<{ total?: number } | null>,
            c.env.DB.prepare(
                'SELECT COUNT(*) AS total FROM link_submissions WHERE namespace_id = ?'
            ).bind(botId).first() as Promise<{ total?: number } | null>,
            c.env.DB.prepare(
                "SELECT COUNT(*) AS total FROM link_submissions WHERE namespace_id = ? AND date(datetime(created_at, '+7 hours')) = ?"
            ).bind(botId, targetDate).first() as Promise<{ total?: number } | null>,
            c.env.DB.prepare(
                'SELECT telegram_id, email FROM users WHERE namespace_id = ? AND telegram_id IS NOT NULL AND TRIM(telegram_id) <> \'\''
            ).bind(botId).all() as Promise<{ results?: Array<{ telegram_id?: string | number; email?: string }> }>,
            c.env.DB.prepare(
                'SELECT telegram_id, email FROM telegram_bot_sessions WHERE namespace_id = ? AND telegram_id IS NOT NULL AND TRIM(telegram_id) <> \'\''
            ).bind(botId).all() as Promise<{ results?: Array<{ telegram_id?: string | number; email?: string }> }>,
            c.env.DB.prepare(
                'SELECT line_user_id, display_name, picture_url, email FROM line_users WHERE namespace_id = ?'
            ).bind(botId).all() as Promise<{ results?: Array<{ line_user_id?: string; display_name?: string; picture_url?: string; email?: string }> }>,
            c.env.DB.prepare(
                "SELECT telegram_id, COUNT(*) AS total FROM link_submissions WHERE namespace_id = ? AND date(datetime(created_at, '+7 hours')) = ? GROUP BY telegram_id"
            ).bind(botId, targetDate).all() as Promise<{ results?: Array<{ telegram_id?: string | number; total?: number }> }>,
        ])

        const emailByTelegram = new Map<string, string>()
        for (const row of usersRes.results || []) {
            const telegramId = String(row?.telegram_id || '').trim()
            const email = String(row?.email || '').trim().toLowerCase()
            if (telegramId && email && !emailByTelegram.has(telegramId)) {
                emailByTelegram.set(telegramId, email)
            }
        }
        for (const row of scopedSessionsRes.results || []) {
            const telegramId = String(row?.telegram_id || '').trim()
            const email = String(row?.email || '').trim().toLowerCase()
            if (telegramId && email && !emailByTelegram.has(telegramId)) {
                emailByTelegram.set(telegramId, email)
            }
        }

        const lineProfileByActorId = new Map<string, {
            line_user_id: string
            display_name: string
            picture_url: string
            email: string
        }>()
        for (const row of lineUsersRes.results || []) {
            const lineUserId = String(row?.line_user_id || '').trim()
            const actorId = deriveLineSubmissionActorId(lineUserId)
            if (!lineUserId || !actorId || lineProfileByActorId.has(actorId)) continue
            lineProfileByActorId.set(actorId, {
                line_user_id: lineUserId,
                display_name: String(row?.display_name || '').trim(),
                picture_url: String(row?.picture_url || '').trim(),
                email: String(row?.email || '').trim().toLowerCase(),
            })
        }

        const adminMap = new Map<string, {
            telegram_id: string
            email: string
            display_name: string
            picture_url: string
            line_user_id: string
            links: number
        }>()
        for (const row of linksByAdminRes.results || []) {
            const telegramId = String(row?.telegram_id || '').trim()
            const count = Math.max(0, Number(row?.total || 0))
            if (!count) continue
            const key = telegramId || 'unknown'
            const existing = adminMap.get(key)
            if (existing) {
                existing.links += count
                continue
            }

            const lineProfile = telegramId ? lineProfileByActorId.get(telegramId) : undefined
            const email = lineProfile?.email || (telegramId ? (emailByTelegram.get(telegramId) || `telegram:${telegramId}`) : 'unknown')
            const displayName = String(lineProfile?.display_name || '').trim() || email

            adminMap.set(key, {
                telegram_id: telegramId || '-',
                email,
                display_name: displayName,
                picture_url: String(lineProfile?.picture_url || '').trim(),
                line_user_id: String(lineProfile?.line_user_id || '').trim(),
                links: count,
            })
        }

        const admins = Array.from(adminMap.values()).sort((a, b) => {
            if (b.links !== a.links) return b.links - a.links
            return a.display_name.localeCompare(b.display_name)
        })

        c.header('Cache-Control', 'private, max-age=15, stale-while-revalidate=60')
        return c.json({
            date: targetDate,
            totals: {
                posts_all: Number(postsAllRow?.total || 0),
                posts_on_date: Number(postsOnDateRow?.total || 0),
                links_all: Number(linksAllRow?.total || 0),
                links_on_date: Number(linksOnDateRow?.total || 0),
            },
            admins,
        })
    } catch (e) {
        console.error(`[DASHBOARD] Failed to build dashboard: ${String(e)}`)
        return c.json({ error: 'Failed to fetch dashboard' }, 500)
    }
})

// Get single page
app.get('/api/pages/:id', async (c) => {
    const id = c.req.param('id')
    try {
        await ensurePagesOneCardColumns(c.env.DB)
        const page = await c.env.DB.prepare(
            'SELECT id, name, image_url, access_token, post_interval_minutes, post_hours, is_active, onecard_enabled, onecard_link_mode, onecard_cta, ads_publish_enabled, caption_link_enabled, posting_token_source, comment_token_source, posting_profile_uid, last_post_at, created_at, updated_at FROM pages WHERE id = ? AND bot_id = ?'
        ).bind(id, c.get('botId')).first()
        if (!page) return c.json({ error: 'Page not found' }, 404)
        c.header('Cache-Control', 'private, no-store')
        return c.json({ page })
    } catch (e) {
        return c.json({ error: 'Failed to fetch page' }, 500)
    }
})

// Returns the full latest system-managed (Facebook Lite) token for ONE page,
// scoped to the authenticated namespace (same botId guard as GET /api/pages/:id).
// Backs the page-settings "ดู token / คัดลอก" affordance: the operator fetches the
// raw token only on explicit click (it is NOT shown automatically). Never logged.
app.get('/api/pages/:id/managed-token', async (c) => {
    const id = c.req.param('id')
    try {
        const row = await c.env.DB.prepare(
            'SELECT access_token, updated_at FROM pages WHERE id = ? AND bot_id = ?'
        ).bind(id, c.get('botId')).first() as { access_token?: string | null; updated_at?: string | null } | null
        if (!row) return c.json({ error: 'Page not found' }, 404)
        const token = String(row.access_token || '').trim()
        c.header('Cache-Control', 'private, no-store')
        return c.json({
            ok: true,
            has_token: !!token,
            token,
            preview: token ? `${token.slice(0, 20)}...` : '',
            updated_at: row.updated_at || null,
        })
    } catch (e) {
        return c.json({ error: 'Failed to fetch managed token' }, 500)
    }
})

app.get('/api/pages/:id/tag-profiles', async (c) => {
    return c.json({ error: 'direct_page_management_only' }, 410)
    const pageId = String(c.req.param('id') || '').trim()
    const botId = c.get('botId')

    if (!pageId) return c.json({ error: 'Page ID is required' }, 400)

    try {
        const page = await c.env.DB.prepare(
            'SELECT id, name FROM pages WHERE id = ? AND bot_id = ?'
        ).bind(pageId, botId).first() as { id?: string; name?: string } | null

        if (!page?.id) return c.json({ error: 'Page not found' }, 404)

        const profiles = await fetchBrowserSavingProfilesForNamespace(c.env, c.env.DB, botId)
        const hiddenProfiles = await getNamespaceHiddenTaggedProfiles(c.env.DB, botId)
        const linkedProfiles = await getNamespaceLinkedTaggedProfiles(c.env.DB, botId)
        const visibleProfiles = filterProfilesForTaggedPage({
            profiles,
            pageId: String(page.id || ''),
            pageName: String(page.name || ''),
            hiddenProfiles,
            linkedProfiles,
        })
        const cfg = await getNamespacePagesSyncConfig(c.env.DB, botId)
        const { postProfileIds, commentProfileIds } = deriveRoleProfileIdsForTaggedPage({
            profiles: visibleProfiles,
            pageId: String(page.id || ''),
            linkedProfiles,
            cfg,
        })

        const byProfileId = new Map<string, {
            profile_id: string
            profile_name: string
            facebook_name: string
            roles: Array<'post' | 'comment'>
            tags: string[]
            post_token: string
            comment_token: string
            token: string
            postcron_token: string
        }>()

        const upsertProfile = (profile: BrowserSavingProfileRecord) => {
            const id = String(profile.id || '').trim()
            if (!id) return
            const key = id.toLowerCase()
            const profileName = String(profile.name || '').trim() || id
            const facebookName = String(profile.username || profile.uid || '').trim()
            const tags = normalizeBrowserSavingProfileTags(profile.tags)

            const existing = byProfileId.get(key)
            if (!existing) {
                const postToken = pickProfilePostToken(profile)
                const commentToken = pickProfileCommentToken(profile)
                const postcronToken = pickProfilePostcronToken(profile)
                const token = commentToken
                const roles: Array<'post' | 'comment'> = []
                if (postProfileIds.has(key)) roles.push('post')
                if (commentProfileIds.has(key) && !roles.includes('comment')) roles.push('comment')
                byProfileId.set(key, {
                    profile_id: id,
                    profile_name: profileName,
                    facebook_name: facebookName,
                    roles,
                    tags,
                    post_token: postToken,
                    comment_token: commentToken,
                    token,
                    postcron_token: postcronToken,
                })
                return
            }

            if (postProfileIds.has(key) && !existing.roles.includes('post')) existing.roles.push('post')
            if (commentProfileIds.has(key) && !existing.roles.includes('comment')) existing.roles.push('comment')
            if (!existing.facebook_name && facebookName) existing.facebook_name = facebookName
            if (!existing.post_token) existing.post_token = pickProfilePostToken(profile)
            if (!existing.comment_token) existing.comment_token = pickProfileCommentToken(profile)
            if (!existing.token) existing.token = pickProfileCommentToken(profile)
            if (!existing.postcron_token) existing.postcron_token = pickProfilePostcronToken(profile)
            if (existing.tags.length === 0 && tags.length > 0) existing.tags = tags
        }

        for (const profile of visibleProfiles) upsertProfile(profile)

        const items = Array.from(byProfileId.values()).sort((a, b) => {
            const aBoth = a.roles.length > 1 ? 1 : 0
            const bBoth = b.roles.length > 1 ? 1 : 0
            if (aBoth !== bBoth) return bBoth - aBoth
            if (a.roles.includes('post') !== b.roles.includes('post')) {
                return a.roles.includes('post') ? -1 : 1
            }
            return a.profile_name.localeCompare(b.profile_name)
        })

        const resolvedItems = await Promise.all(items.map(async (item) => {
            let comment_token = String(item.comment_token || item.token || '').trim()
            if (item.roles.includes('comment')) {
                let refreshedCommentToken = ''
                try {
                    const resolvedComment = await resolveBrowserSavingProfileToken(c.env, item.profile_id, 'comment')
                    const recoveredCommentToken = String(resolvedComment.token || '').trim()
                    if (isCommentRoleToken(recoveredCommentToken)) {
                        refreshedCommentToken = recoveredCommentToken
                    }
                } catch {
                    refreshedCommentToken = ''
                }
                if (refreshedCommentToken) {
                    comment_token = refreshedCommentToken
                } else if (!isCommentRoleToken(comment_token)) {
                    comment_token = ''
                }
            }

            let token = comment_token
            let token_scoped = !!token
            let comment_page_token = ''
            if (comment_token && item.roles.includes('comment')) {
                comment_page_token = await resolveCommentPageTokenForPage(c.env, String(page.id || ''), comment_token)
                token_scoped = !!comment_page_token
            }

            let postcron_token = String(item.postcron_token || '').trim()
            if (item.roles.includes('post')) {
                let refreshedPostToken = ''
                try {
                    const resolvedPost = await resolveBrowserSavingProfileToken(c.env, item.profile_id, 'post')
                    const recoveredPostToken = String(resolvedPost.token || '').trim()
                    if (isPostRoleToken(recoveredPostToken)) {
                        refreshedPostToken = recoveredPostToken
                    }
                } catch {
                    refreshedPostToken = ''
                }
                if (refreshedPostToken) {
                    postcron_token = refreshedPostToken
                } else if (!isPostRoleToken(postcron_token)) {
                    postcron_token = ''
                }
            }

            let post_token = String(item.post_token || postcron_token).trim()
            let post_token_scoped = false
            if (post_token && item.roles.includes('post')) {
                try {
                    const resolved = await resolvePageScopedToken(post_token, String(page.id || ''), c.env, 'post')
                    if (resolved.token) {
                        post_token = String(resolved.token).trim()
                        post_token_scoped = true
                    } else {
                        post_token = ''
                    }
                } catch {
                    post_token = ''
                }
            }

            return { ...item, comment_token, comment_page_token, token, token_scoped, postcron_token, post_token, post_token_scoped }
        }))

        try {
            const pageRecord = await c.env.DB.prepare(
                'SELECT access_token FROM pages WHERE id = ? AND bot_id = ?'
            ).bind(String(page.id || ''), botId).first() as { access_token?: string | null } | null

            const storedAccess = String(pageRecord?.access_token || '').trim()
            let storedAccessScoped = storedAccess
            if (storedAccess) {
                try {
                    const accessResolved = await resolvePageScopedToken(storedAccess, String(page.id || ''), c.env, 'post')
                    storedAccessScoped = String(accessResolved.token || '').trim()
                } catch {
                    storedAccessScoped = ''
                }
            }

            const discoveredPostTokens = normalizePostTokenPool([
                ...resolvedItems
                    .filter((item) => item.post_token_scoped && item.roles.includes('post'))
                    .map((item) => String(item.post_token || '').trim()),
            ])
            const discoveredCommentTokens = buildPreferredCommentTokenPool({
                primaryToken: storedAccessScoped,
                postTokens: discoveredPostTokens,
                commentTokens: resolvedItems
                    .filter((item) => item.roles.includes('comment'))
                    .map((item) => String((item as any).comment_page_token || '').trim()),
            })

            const tokenPool = await getNamespacePagesTokenPool(c.env.DB, botId)
            const existingEntry = tokenPool[String(page.id || '')] || { post_tokens: [], comment_tokens: [] }

            const nextPostTokenPool = discoveredPostTokens.length > 0
                ? discoveredPostTokens
                : normalizePostTokenPool([
                    ...(existingEntry.post_tokens || []),
                    storedAccessScoped,
                ])
            const nextCommentTokenPool = discoveredCommentTokens.length > 0
                ? normalizeCommentTokenPool([
                    ...discoveredCommentTokens,
                    ...(existingEntry.comment_tokens || []),
                ])
                : normalizeCommentTokenPool(existingEntry.comment_tokens || [])

            // Preserve a stored EAAD6V Facebook Lite token too (not only EAAB-prefixed) so it is
            // never blanked when the rebuilt pool is empty.
            const storedPostScoped = isPersistablePagePrimaryToken(storedAccessScoped) ? storedAccessScoped : ''
            const nextAccess = nextPostTokenPool[0] || storedPostScoped || ''

            if (
                nextAccess !== storedAccess ||
                !sameTokenList(existingEntry.post_tokens || [], nextPostTokenPool) ||
                !sameTokenList(existingEntry.comment_tokens || [], nextCommentTokenPool)
            ) {
                await c.env.DB.prepare(
                    'UPDATE pages SET access_token = ?, updated_at = datetime("now") WHERE id = ? AND bot_id = ?'
                ).bind(nextAccess || null, String(page.id || ''), botId).run()

                tokenPool[String(page.id || '')] = {
                    post_tokens: nextPostTokenPool,
                    comment_tokens: nextCommentTokenPool,
                    updated_at: new Date().toISOString(),
                }
                await setNamespacePagesTokenPool(c.env.DB, botId, tokenPool)
            }
        } catch (e) {
            console.log(`[TAG-PROFILES] token sync before display failed: ${e instanceof Error ? e.message : String(e)}`)
        }

        return c.json({
            page: { id: String(page.id || ''), name: String(page.name || '') },
            summary: {
                profiles_total: items.length,
                post_profiles: items.filter((item) => item.roles.includes('post')).length,
                comment_profiles: items.filter((item) => item.roles.includes('comment')).length,
            },
            profiles: resolvedItems,
        })
    } catch (e) {
        const message = e instanceof Error ? e.message : String(e)
        return c.json({ error: `Failed to fetch BrowserSaving profiles: ${message}` }, 500)
    }
})

app.put('/api/pages/:id/tag-profiles/:profileId/token', async (c) => {
    return c.json({ error: 'direct_page_management_only' }, 410)
    const pageId = String(c.req.param('id') || '').trim()
    const profileId = String(c.req.param('profileId') || '').trim()
    const botId = c.get('botId')

    if (!pageId) return c.json({ error: 'Page ID is required' }, 400)
    if (!profileId || !looksLikeBrowserSavingProfileId(profileId)) {
        return c.json({ error: 'Profile ID is invalid' }, 400)
    }

    let body: any = {}
    try {
        body = await c.req.json()
    } catch {
        body = {}
    }

    const modeRaw = String(body?.mode || 'post').trim().toLowerCase()
    const mode: BrowserSavingTokenMode = modeRaw === 'comment' ? 'comment' : 'post'

    const token = String(body?.token || '').trim()

    try {
        const page = await c.env.DB.prepare(
            'SELECT id, name FROM pages WHERE id = ? AND bot_id = ?'
        ).bind(pageId, botId).first() as { id?: string; name?: string } | null
        if (!page?.id) return c.json({ error: 'Page not found' }, 404)

        const profiles = await fetchBrowserSavingProfilesForNamespace(c.env, c.env.DB, botId)
        const hiddenProfiles = await getNamespaceHiddenTaggedProfiles(c.env.DB, botId)
        const linkedProfiles = await getNamespaceLinkedTaggedProfiles(c.env.DB, botId)
        const scopedProfiles = filterProfilesForTaggedPage({
            profiles,
            pageId: String(page.id || ''),
            pageName: String(page.name || ''),
            hiddenProfiles,
            linkedProfiles,
        })

        const targetProfile = scopedProfiles.find((profile) => {
            return String(profile.id || '').trim().toLowerCase() === profileId.toLowerCase()
        })
        if (!targetProfile) {
            return c.json({
                error: 'Profile not found for this page',
                code: 'PROFILE_NOT_FOUND_FOR_PAGE',
            }, 404)
        }

        const updatePayload: Record<string, string | null> = mode === 'comment'
            ? (token ? { access_token: token } : { access_token: null })
            : (token ? { facebook_token: token } : { facebook_token: null })

        const endpointBases = buildBrowserSavingProfileBaseUrls(c.env)
        const path = `/api/profiles/${encodeURIComponent(profileId)}`
        const errors: string[] = []

        for (const baseUrl of endpointBases) {
            const label = buildBrowserSavingRequestLabel(baseUrl, path)
            try {
                const resp = await fetchFromBrowserSavingBase(c.env, baseUrl, path, {
                    method: 'PUT',
                    headers: {
                        'Accept': 'application/json',
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify(updatePayload),
                })
                const data = await resp.json().catch(() => ({} as any)) as any
                if (!resp.ok) {
                    const details = String(data?.error || data?.details || `HTTP ${resp.status}`)
                    errors.push(`${label}: ${details}`)
                    continue
                }

                const profile = data?.profile || null
                const savedTokenRaw = mode === 'comment'
                    ? String(profile?.access_token || '').trim()
                    : String(profile?.facebook_token || profile?.postcron_token || '').trim()
                const savedToken = token
                    ? (savedTokenRaw || token)
                    : ''
                let scopedToken = ''
                let scopedSource = ''
                let scopedReason = ''

                if (savedToken && mode === 'post') {
                    const scoped = await resolvePageScopedToken(savedToken, pageId, c.env, mode)
                    scopedSource = String(scoped.source || '')
                    scopedReason = String(scoped.reason || '')
                    scopedToken = String(scoped.token || '').trim()
                    if (!scopedToken) {
                        const reason = String(scoped.reason || 'token_conversion_failed')
                        errors.push(`${label}: page_token_conversion_failed_${reason}`)
                        continue
                    }
                }
                if (!savedToken) {
                    scopedToken = ''
                }

                let sync_error: string | undefined
                try {
                    await autoSyncPagesForNamespace(c.env, botId)
                } catch (syncErr) {
                    sync_error = syncErr instanceof Error ? syncErr.message : String(syncErr)
                }

                try {
                    const nextLinkedProfiles = await getNamespaceLinkedTaggedProfiles(c.env.DB, botId)
                    const pageKey = String(page.id || '')
                    const nextIds = normalizeHiddenTaggedProfileIds([
                        ...(hasLinkedTaggedProfilesEntryForPage(nextLinkedProfiles, pageKey) ? nextLinkedProfiles[pageKey] || [] : []),
                        profileId,
                    ])
                    nextLinkedProfiles[pageKey] = nextIds
                    await setNamespaceLinkedTaggedProfiles(c.env.DB, botId, nextLinkedProfiles)
                } catch (e) {
                    console.log(`[TAG-PROFILES] failed to persist linked profile for page ${pageId}: ${e instanceof Error ? e.message : String(e)}`)
                }

                let rebuiltPrimaryToken = scopedToken || ''
                try {
                    const rebuilt = await rebuildTaggedPageProfileTokens(c.env, botId, pageId, String(page.name || ''))
                    rebuiltPrimaryToken = rebuilt.primaryToken
                } catch (e) {
                    console.log(`[PAGES-TOKEN-POOL] failed to rebuild token pool for page ${pageId}: ${e instanceof Error ? e.message : String(e)}`)
                }

                if (mode === 'comment') {
                    const issueKey = `_alerts/comment_token/${botId}/${pageId}.json`
                    await c.env.BUCKET.delete(issueKey).catch(() => undefined)
                }

                return c.json({
                    success: true,
                    page_id: pageId,
                    profile_id: profileId,
                    mode,
                    token: token ? (mode === 'comment' ? savedToken : (scopedToken || savedToken || rebuiltPrimaryToken)) : '',
                    postcron_token: token
                        ? String(profile?.facebook_token || profile?.postcron_token || '').trim()
                        : '',
                    scoped_token: scopedToken || '',
                    token_scope: scopedSource,
                    scope_reason: scopedReason,
                    sync_error,
                })
            } catch (e) {
                errors.push(`${label}: ${e instanceof Error ? e.message : String(e)}`)
            }
        }

        return c.json({
            error: 'Failed to update BrowserSaving profile token',
            details: errors.join(' | ') || 'no_endpoint_available',
        }, 502)
    } catch (e) {
        return c.json({ error: `Failed to update tagged profile token: ${e instanceof Error ? e.message : String(e)}` }, 500)
    }
})

app.delete('/api/pages/:id/tag-profiles/:profileId', async (c) => {
    return c.json({ error: 'direct_page_management_only' }, 410)
    const pageId = String(c.req.param('id') || '').trim()
    const profileId = String(c.req.param('profileId') || '').trim()
    const botId = c.get('botId')

    if (!pageId) return c.json({ error: 'Page ID is required' }, 400)
    if (!profileId || !looksLikeBrowserSavingProfileId(profileId)) {
        return c.json({ error: 'Profile ID is invalid' }, 400)
    }

    try {
        const page = await c.env.DB.prepare(
            'SELECT id, name FROM pages WHERE id = ? AND bot_id = ?'
        ).bind(pageId, botId).first() as { id?: string; name?: string } | null
        if (!page?.id) return c.json({ error: 'Page not found' }, 404)

        const profiles = await fetchBrowserSavingProfilesForNamespace(c.env, c.env.DB, botId)
        const hiddenProfiles = await getNamespaceHiddenTaggedProfiles(c.env.DB, botId)
        const linkedProfiles = await getNamespaceLinkedTaggedProfiles(c.env.DB, botId)
        const scopedProfiles = filterProfilesForTaggedPage({
            profiles,
            pageId: String(page.id || ''),
            pageName: String(page.name || ''),
            hiddenProfiles,
            linkedProfiles,
        })
        const targetProfile = scopedProfiles.find((profile) => {
            return String(profile.id || '').trim().toLowerCase() === profileId.toLowerCase()
        })
        if (!targetProfile) {
            return c.json({
                error: 'Profile not found for this page',
                code: 'PROFILE_NOT_FOUND_FOR_PAGE',
            }, 404)
        }

        hiddenProfiles[String(page.id || '')] = normalizeHiddenTaggedProfileIds([
            ...(hiddenProfiles[String(page.id || '')] || []),
            profileId,
        ])
        await setNamespaceHiddenTaggedProfiles(c.env.DB, botId, hiddenProfiles)

        const pageKey = String(page.id || '')
        if (hasLinkedTaggedProfilesEntryForPage(linkedProfiles, pageKey)) {
            linkedProfiles[pageKey] = normalizeHiddenTaggedProfileIds(
                (linkedProfiles[pageKey] || []).filter((id) => String(id || '').trim().toLowerCase() !== profileId.toLowerCase()),
            )
            await setNamespaceLinkedTaggedProfiles(c.env.DB, botId, linkedProfiles)
        }

        const rebuilt = await rebuildTaggedPageProfileTokens(c.env, botId, String(page.id || ''), String(page.name || ''))

        return c.json({
            success: true,
            page_id: String(page.id || ''),
            profile_id: profileId,
            token: rebuilt.primaryToken,
            hidden_profiles: hiddenProfiles[String(page.id || '')] || [],
        })
    } catch (e) {
        return c.json({ error: `Failed to unlink tagged profile: ${e instanceof Error ? e.message : String(e)}` }, 500)
    }
})

// Create page
app.post('/api/pages', async (c) => {
    try {
        const body = await c.req.json()
        const { id, name, image_url, access_token, post_interval_minutes = 60, onecard_enabled = false, onecard_link_mode, onecard_cta, caption_link_enabled = false } = body
        const botId = c.get('botId')
        const postToken = String(access_token || '').trim()
        const onecardEnabled = onecard_enabled === true || Number(onecard_enabled || 0) === 1 ? 1 : 0
        const captionLinkEnabled = caption_link_enabled === true || Number(caption_link_enabled || 0) === 1 ? 1 : 0
        const onecardLinkMode = normalizePageOneCardLinkMode(onecard_link_mode)
        const onecardCta = normalizePageOneCardCta(onecard_cta)
        await ensurePagesOneCardColumns(c.env.DB)
        const existingInNamespace = await c.env.DB.prepare(
            'SELECT id, name, image_url, access_token, post_interval_minutes, post_hours, is_active, onecard_enabled, onecard_link_mode, onecard_cta, ads_publish_enabled, caption_link_enabled, posting_token_source, comment_token_source, posting_profile_uid, last_post_at, created_at, updated_at FROM pages WHERE id = ? AND bot_id = ?'
        ).bind(id, botId).first()
        if (existingInNamespace) {
            return c.json({ success: true, id, updated: false, page: existingInNamespace })
        }

        const existingInOtherNamespace = await c.env.DB.prepare(
            'SELECT bot_id FROM pages WHERE id = ?'
        ).bind(id).first() as any
        if (existingInOtherNamespace?.bot_id) {
            return c.json({
                error: 'Page is already connected to another workspace',
                code: 'PAGE_ALREADY_BOUND',
                existing_bot_id: String(existingInOtherNamespace.bot_id),
            }, 409)
        }

        await c.env.DB.prepare(
            'INSERT INTO pages (id, name, image_url, access_token, post_interval_minutes, bot_id, onecard_enabled, onecard_link_mode, onecard_cta, caption_link_enabled) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)'
        ).bind(id, name, image_url, postToken, post_interval_minutes, botId, onecardEnabled, onecardLinkMode, onecardCta, captionLinkEnabled).run()

        const page = await c.env.DB.prepare(
            'SELECT id, name, image_url, access_token, post_interval_minutes, post_hours, is_active, onecard_enabled, onecard_link_mode, onecard_cta, ads_publish_enabled, caption_link_enabled, posting_token_source, comment_token_source, posting_profile_uid, last_post_at, created_at, updated_at FROM pages WHERE id = ? AND bot_id = ?'
        ).bind(id, botId).first()
        return c.json({ success: true, id, page })
    } catch (e) {
        return c.json({ error: 'Failed to create page' }, 500)
    }
})

// Update page settings
app.put('/api/pages/:id', async (c) => {
    const id = c.req.param('id')
    try {
        const body = await c.req.json()
        const {
            post_interval_minutes,
            post_hours,
            is_active,
            access_token,
            comment_token,
            onecard_enabled,
            onecard_link_mode,
            onecard_cta,
            ads_publish_enabled,
            posting_token_source,
            comment_token_source,
            posting_profile_uid,
            postingProfileUid,
            caption_link_enabled,
            base_post_hours,
            base_post_interval_minutes,
            base_is_active,
        } = body
        // DIAGNOSTIC: log every save attempt so we can trace stale-state overwrites.
        // The big 2026-05-01 incident was a webapp tab with cached `every:30` re-saving
        // over a server-cleared post_hours='' — visible only by knowing PUT was hit and
        // with which payload. token redacted to a short tail to avoid leaking secrets.
        const tokenTail = access_token !== undefined ? String(access_token || '').trim().slice(-6) : '(unset)'
        console.log(`[PAGES-PUT] page=${id} ns=${c.get('botId')} post_hours=${JSON.stringify(post_hours ?? null)} post_interval_minutes=${JSON.stringify(post_interval_minutes ?? null)} is_active=${JSON.stringify(is_active ?? null)} access_token_tail=${tokenTail} onecard_enabled=${JSON.stringify(onecard_enabled ?? null)} ads_publish_enabled=${JSON.stringify(ads_publish_enabled ?? null)} posting_token_source=${JSON.stringify(posting_token_source ?? null)} comment_token_source=${JSON.stringify(comment_token_source ?? null)} caption_link_enabled=${JSON.stringify(caption_link_enabled ?? null)}`)
        // comment_token is now treated as access_token (unified token model)
        let normalizedPostHours = post_hours as string | undefined
        let normalizedInterval = post_interval_minutes as number | undefined
        const nextOneCardEnabled = onecard_enabled !== undefined ? ((onecard_enabled === true || Number(onecard_enabled || 0) === 1) ? 1 : 0) : undefined
        const nextCaptionLinkEnabled = caption_link_enabled !== undefined ? ((caption_link_enabled === true || Number(caption_link_enabled || 0) === 1) ? 1 : 0) : undefined
        const nextOneCardLinkMode = onecard_link_mode !== undefined ? normalizePageOneCardLinkMode(onecard_link_mode) : undefined
        const nextOneCardCta = onecard_cta !== undefined ? normalizePageOneCardCta(onecard_cta) : undefined

        // posting_profile_uid — per-page Accounts Bridge posting account UID (e.g. 100077795357192).
        // Public FB account uid only, NEVER a token. Strict validation: trimmed, then either '' (clears
        // the override → auto-discovery) or 5–32 digits. Anything else is rejected up-front (400) so a
        // malformed value can never be persisted or threaded into the Facebook Lite refresh request.
        let nextPostingProfileUid: string | undefined
        const rawPostingProfileUid = posting_profile_uid !== undefined ? posting_profile_uid : postingProfileUid
        if (rawPostingProfileUid !== undefined) {
            const trimmed = String(rawPostingProfileUid ?? '').trim()
            if (trimmed !== '' && !/^\d{5,32}$/.test(trimmed)) {
                return c.json({ error: 'invalid_posting_profile_uid' }, 400)
            }
            nextPostingProfileUid = trimmed
        }

        await ensurePagesOneCardColumns(c.env.DB)
        const page = await c.env.DB.prepare(
            'SELECT id, access_token, post_hours, post_interval_minutes, is_active FROM pages WHERE id = ? AND bot_id = ?'
        ).bind(id, c.get('botId')).first() as {
            id: string
            access_token?: string | null
            post_hours?: string | null
            post_interval_minutes?: number | null
            is_active?: number | null
        } | null
        if (!page) return c.json({ error: 'Page not found' }, 404)
        let effectivePostToken = String(page.access_token || '').trim()
        const touchesSchedule = post_hours !== undefined || post_interval_minutes !== undefined || is_active !== undefined
        if (touchesSchedule) {
            const hasScheduleBase = base_post_hours !== undefined
                && base_post_interval_minutes !== undefined
                && base_is_active !== undefined
            if (!hasScheduleBase) {
                console.warn(`[PAGES-PUT] legacy schedule save without base accepted page=${id} ns=${c.get('botId')}`)
            } else {
                const currentSchedule = {
                    post_hours: String(page.post_hours || '').trim(),
                    post_interval_minutes: page.post_interval_minutes === null || page.post_interval_minutes === undefined
                        ? null
                        : Number(page.post_interval_minutes),
                    is_active: Number(page.is_active || 0) ? 1 : 0,
                }
                const clientBaseSchedule = {
                    post_hours: String(base_post_hours || '').trim(),
                    post_interval_minutes: base_post_interval_minutes === null || base_post_interval_minutes === undefined || base_post_interval_minutes === ''
                        ? null
                        : Number(base_post_interval_minutes),
                    is_active: Number(base_is_active || 0) ? 1 : 0,
                }
                const scheduleMatches = currentSchedule.post_hours === clientBaseSchedule.post_hours
                    && currentSchedule.post_interval_minutes === clientBaseSchedule.post_interval_minutes
                    && currentSchedule.is_active === clientBaseSchedule.is_active
                if (!scheduleMatches) {
                    console.warn(
                        `[PAGES-PUT] stale schedule rejected page=${id} ns=${c.get('botId')} base=${JSON.stringify(clientBaseSchedule)} current=${JSON.stringify(currentSchedule)}`
                    )
                    return c.json({
                        error: 'stale_schedule_state',
                        details: 'ค่า schedule บนเซิร์ฟเวอร์เปลี่ยนไปแล้ว กรุณารีเฟรชก่อนบันทึก',
                        page: {
                            id,
                            ...currentSchedule,
                        },
                    }, 409)
                }
            }
        }

        // Normalize schedule payload:
        // - Slot mode: "2:10,9:35,16:42"
        // - Interval mode: "every:30"
        if (typeof normalizedPostHours === 'string') {
            const trimmed = normalizedPostHours.trim()
            const intervalMatch = trimmed.match(/^every:(\d{1,4})$/i)
            if (intervalMatch) {
                const parsed = Math.max(5, Math.min(720, parseInt(intervalMatch[1], 10) || 60))
                normalizedPostHours = `every:${parsed}`
                if (normalizedInterval === undefined) normalizedInterval = parsed
            } else {
                normalizedPostHours = trimmed
            }
        }
        if (normalizedInterval !== undefined) {
            const parsed = Number(normalizedInterval)
            normalizedInterval = Math.max(5, Math.min(720, Number.isFinite(parsed) ? Math.floor(parsed) : 60))
        }

        // === Drift guard ===
        // post_hours is the cron's source of truth (every:N or H:MM slot list).
        // post_interval_minutes is a UI-display field. They MUST stay in sync, otherwise
        // toggling the UI from "ติ๊กเวลา" to "ทุกๆ X นาที" leaves a stale slot string in
        // post_hours and the cron silently keeps posting on the old slots.
        //
        // Rule: when the request implies interval mode (interval is set AND post_hours
        // is either absent or already an every:N string), force post_hours = every:N
        // so the cron immediately honors the user's intent. We don't touch explicit
        // slot strings because those signal the user is in slot mode.
        if (normalizedInterval !== undefined) {
            const phStr = String(normalizedPostHours ?? '').trim()
            const isAlreadyInterval = /^every:\d+$/i.test(phStr)
            const isExplicitSlot = phStr.length > 0 && phStr.includes(':') && !isAlreadyInterval
            if (!isExplicitSlot) {
                normalizedPostHours = `every:${normalizedInterval}`
            }
        }

        // === Persist schedule + flags BEFORE touching the token ===
        // The token resolution block below can early-return 400 (invalid_access_token,
        // page_not_found_in_me_accounts, etc.). If we left the schedule UPDATE after
        // it, a stale or expired token would silently swallow the user's schedule
        // change — they tap "60 นาที", hit Save, see a token error, dismiss it, and
        // the schedule never persists. Token health and schedule are independent
        // settings; one failing must not silently veto the other.
        if (normalizedPostHours !== undefined) {
            if (is_active !== undefined) {
                await c.env.DB.prepare(
                    'UPDATE pages SET post_hours = ?, is_active = ?, updated_at = datetime("now") WHERE id = ? AND bot_id = ?'
                ).bind(normalizedPostHours, is_active ? 1 : 0, id, c.get('botId')).run()
            } else {
                await c.env.DB.prepare(
                    'UPDATE pages SET post_hours = ?, updated_at = datetime("now") WHERE id = ? AND bot_id = ?'
                ).bind(normalizedPostHours, id, c.get('botId')).run()
            }
        }
        if (normalizedInterval !== undefined) {
            if (is_active !== undefined) {
                await c.env.DB.prepare(
                    'UPDATE pages SET post_interval_minutes = ?, is_active = ?, updated_at = datetime("now") WHERE id = ? AND bot_id = ?'
                ).bind(normalizedInterval, is_active ? 1 : 0, id, c.get('botId')).run()
            } else {
                await c.env.DB.prepare(
                    'UPDATE pages SET post_interval_minutes = ?, updated_at = datetime("now") WHERE id = ? AND bot_id = ?'
                ).bind(normalizedInterval, id, c.get('botId')).run()
            }
        }
        if (is_active !== undefined && normalizedPostHours === undefined && normalizedInterval === undefined) {
            await c.env.DB.prepare(
                'UPDATE pages SET is_active = ?, updated_at = datetime("now") WHERE id = ? AND bot_id = ?'
            ).bind(is_active ? 1 : 0, id, c.get('botId')).run()
        }
        if (nextOneCardEnabled !== undefined) {
            await c.env.DB.prepare(
                'UPDATE pages SET onecard_enabled = ?, updated_at = datetime("now") WHERE id = ? AND bot_id = ?'
            ).bind(nextOneCardEnabled, id, c.get('botId')).run()
        }
        if (nextOneCardLinkMode !== undefined) {
            await c.env.DB.prepare(
                'UPDATE pages SET onecard_link_mode = ?, updated_at = datetime("now") WHERE id = ? AND bot_id = ?'
            ).bind(nextOneCardLinkMode, id, c.get('botId')).run()
        }
        if (nextOneCardCta !== undefined) {
            await c.env.DB.prepare(
                'UPDATE pages SET onecard_cta = ?, updated_at = datetime("now") WHERE id = ? AND bot_id = ?'
            ).bind(nextOneCardCta, id, c.get('botId')).run()
        }
        if (nextCaptionLinkEnabled !== undefined) {
            await c.env.DB.prepare(
                'UPDATE pages SET caption_link_enabled = ?, updated_at = datetime("now") WHERE id = ? AND bot_id = ?'
            ).bind(nextCaptionLinkEnabled, id, c.get('botId')).run()
        }

        const tokenUpdated = access_token !== undefined || comment_token !== undefined
        const resolved: { access_token?: string; comment_token?: string } = {}
        const resolved_details: { access_token?: string; comment_token?: string } = {}
        const tokenPool = await getNamespacePagesTokenPool(c.env.DB, c.get('botId'))
        const existingEntry = tokenPool[id] || { post_tokens: [], comment_tokens: [] }
        let nextPostTokenPool = normalizePostTokenPool(existingEntry.post_tokens || [])
        let nextCommentTokenPool = normalizeCommentTokenPool(existingEntry.comment_tokens || [])

        if (access_token !== undefined) {
            const rawToken = String(access_token || '').trim()
            if (rawToken) {
                const accessResolved = await resolvePageScopedToken(rawToken, id, c.env, 'post')
                const resolvedAccessToken = String(accessResolved.token || '').trim()
                if (!resolvedAccessToken) {
                    return c.json({
                        error: 'invalid_access_token',
                        details: String(accessResolved.reason || 'page_not_found_in_me_accounts'),
                    }, 400)
                }

                await c.env.DB.prepare(
                    'UPDATE pages SET access_token = ?, updated_at = datetime("now") WHERE id = ? AND bot_id = ?'
                ).bind(resolvedAccessToken, id, c.get('botId')).run()
                effectivePostToken = resolvedAccessToken
                nextPostTokenPool = normalizePostTokenPool([
                    resolvedAccessToken,
                    ...nextPostTokenPool,
                ])
                nextCommentTokenPool = buildPreferredCommentTokenPool({
                    primaryToken: resolvedAccessToken,
                    postTokens: nextPostTokenPool,
                    commentTokens: nextCommentTokenPool,
                })
                resolved.access_token = accessResolved.source
                if (accessResolved.reason) resolved_details.access_token = accessResolved.reason
            } else {
                await c.env.DB.prepare(
                    'UPDATE pages SET access_token = ?, updated_at = datetime("now") WHERE id = ? AND bot_id = ?'
                ).bind('', id, c.get('botId')).run()
                effectivePostToken = ''
                nextPostTokenPool = []
                if (comment_token === undefined) {
                    nextCommentTokenPool = []
                    resolved.comment_token = 'provided_as_is'
                }
                resolved.access_token = 'provided_as_is'
            }
        }

        if (comment_token !== undefined || access_token !== undefined) {
            const rawCommentToken = String(comment_token ?? access_token ?? '').trim()
            if (rawCommentToken) {
                const resolvedCommentToken = await resolveCommentPageTokenForPage(c.env, id, rawCommentToken)
                nextCommentTokenPool = buildPreferredCommentTokenPool({
                    primaryToken: effectivePostToken,
                    postTokens: nextPostTokenPool,
                    commentTokens: [
                        resolvedCommentToken,
                        ...nextCommentTokenPool,
                    ],
                })
                resolved.comment_token = 'resolved_for_page'
            } else if (comment_token !== undefined) {
                nextCommentTokenPool = []
                resolved.comment_token = 'provided_as_is'
            }
        }

        if (tokenUpdated) {
            if (nextPostTokenPool.length > 0 || nextCommentTokenPool.length > 0) {
                tokenPool[id] = {
                    post_tokens: nextPostTokenPool,
                    comment_tokens: nextCommentTokenPool,
                    updated_at: new Date().toISOString(),
                }
            } else {
                delete tokenPool[id]
            }
            await setNamespacePagesTokenPool(c.env.DB, c.get('botId'), tokenPool)
        }

        // Schedule + is_active + onecard_* are already persisted above (before token
        // resolution) so they never get vetoed by a stale-token early-return.
        // ads_publish_enabled — admin-namespace ONLY.
        // This feature routes cron/force-post through /api/dashboard/create-ad which uses
        // admin's ad account (act_1030797047648459) and admin's template adset. Allowing
        // member namespaces to enable this would spend admin's ad budget on member videos.
        // (Shortlink integrity handled elsewhere by isNamespaceShortlinkAdminManaged — see
        //  SACRED-RULES-READ-FIRST drawer.)
        if (ads_publish_enabled !== undefined) {
            const wantsEnabled = ads_publish_enabled === true || Number(ads_publish_enabled || 0) === 1
            if (wantsEnabled) {
                const namespaceIsAdminManaged = await isNamespaceShortlinkAdminManaged(c.env.DB, c.get('botId')).catch(() => false)
                if (!namespaceIsAdminManaged) {
                    return c.json({
                        error: 'ads_publish_admin_only',
                        details: 'auto-ads feature is restricted to the admin namespace (uses admin ad account)',
                    }, 403)
                }
            }
            await c.env.DB.prepare(
                'UPDATE pages SET ads_publish_enabled = ?, updated_at = datetime("now") WHERE id = ? AND bot_id = ?'
            ).bind(wantsEnabled ? 1 : 0, id, c.get('botId')).run()
        }

        // posting_token_source — per-page Facebook posting token selector. Only two modes:
        // 'stored_token' (manual token) and 'cloak_browser' (CloakBrowser session-cookie
        // bridge). Legacy DB values ('post-reels-token-cloak'/'post-reels-token-ads')
        // normalize to 'cloak_browser'. Persisted independently of manual access_token
        // validation so that selecting CloakBrowser and saving does NOT require the operator
        // to re-enter a page token (the bug where saving jumped back to Page/Token).
        // Selecting CloakBrowser is NOT admin-restricted — it posts organically with the
        // operator's own browser session. The OneCard/create-ad route keeps its own
        // admin-namespace guard (ads_publish_enabled + the runtime check in create-ad).
        // Power Editor / CloakBrowser is admin-owned only (restrictCloakToAdminNamespace). For
        // a non-admin (member/team) namespace we persist 'stored_token' even when the client
        // sends 'cloak_browser' or a legacy alias, so a member page can never be silently
        // routed to the session bridge it has no access to. Resolved once for both selectors.
        const namespaceIsAdminOwned = posting_token_source !== undefined || comment_token_source !== undefined
            ? await isNamespaceShortlinkAdminManaged(c.env.DB, String(c.get('botId') || '')).catch(() => false)
            : false
        if (posting_token_source !== undefined) {
            const normalizedPostingTokenSource = restrictCloakToAdminNamespace(
                normalizePagePostingTokenSource(posting_token_source),
                namespaceIsAdminOwned,
            )
            await c.env.DB.prepare(
                'UPDATE pages SET posting_token_source = ?, updated_at = datetime("now") WHERE id = ? AND bot_id = ?'
            ).bind(normalizedPostingTokenSource, id, c.get('botId')).run()
        }

        // comment_token_source — per-page Facebook COMMENT token selector. Independent of
        // posting_token_source and of any raw token validation: it only decides HOW the
        // automatic affiliate comment is sent after a post ('stored_token' = stored page
        // comment token over Graph; 'cloak_browser' = CloakBrowser bridge /page-comment).
        // Legacy aliases collapse to 'cloak_browser'. Persisted as-is (no token gate). When
        // the page never set it, runtime falls back to the effective posting source so
        // existing pages are unaffected — hence we only write when the operator sends it.
        if (comment_token_source !== undefined) {
            const normalizedCommentTokenSource = restrictCloakToAdminNamespace(
                normalizePageCommentTokenSource(comment_token_source),
                namespaceIsAdminOwned,
            )
            await c.env.DB.prepare(
                'UPDATE pages SET comment_token_source = ?, updated_at = datetime("now") WHERE id = ? AND bot_id = ?'
            ).bind(normalizedCommentTokenSource, id, c.get('botId')).run()
        }

        // posting_profile_uid — persist the validated UID (or '' to clear). Independent of any token
        // validation: it only hints which Accounts Bridge account the stored-token refresh should target.
        if (nextPostingProfileUid !== undefined) {
            await c.env.DB.prepare(
                'UPDATE pages SET posting_profile_uid = ?, updated_at = datetime("now") WHERE id = ? AND bot_id = ?'
            ).bind(nextPostingProfileUid, id, c.get('botId')).run()
        }
        if (tokenUpdated) {
            const issueKey = `_alerts/comment_token/${c.get('botId')}/${id}.json`
            await c.env.BUCKET.delete(issueKey).catch(() => undefined)
        }

        const updatedPage = await c.env.DB.prepare(
            'SELECT id, name, image_url, access_token, post_interval_minutes, post_hours, is_active, onecard_enabled, onecard_link_mode, onecard_cta, ads_publish_enabled, caption_link_enabled, posting_token_source, comment_token_source, posting_profile_uid, last_post_at, created_at, updated_at FROM pages WHERE id = ? AND bot_id = ?'
        ).bind(id, c.get('botId')).first()

        return c.json({ success: true, resolved, resolved_details, page: updatedPage })
    } catch (e) {
        return c.json({ error: 'Failed to update page' }, 500)
    }
})

// Delete page
app.delete('/api/pages/:id', async (c) => {
    const id = c.req.param('id')
    try {
        const deleted = await c.env.DB.prepare('DELETE FROM pages WHERE id = ? AND bot_id = ?').bind(id, c.get('botId')).run() as any
        if (!deleted?.meta?.changes) return c.json({ error: 'Page not found' }, 404)
        return c.json({ success: true })
    } catch (e) {
        return c.json({ error: 'Failed to delete page' }, 500)
    }
})

// ==================== FACEBOOK IMPORT ====================

app.post('/api/pages/import', async (c) => {
    try {
        const body = await c.req.json()
        const { user_token, post_user_token, comment_user_token } = body || {}
        const botId = c.get('botId')
        const postRawInput = String(post_user_token || user_token || '').trim()
        const commentRawInput = String(comment_user_token || postRawInput).trim()

        if (!postRawInput) {
            return c.json({ error: 'User token is required' }, 400)
        }

        const postImportToken = postRawInput
        const commentImportToken = commentRawInput || postImportToken

        let fbPages: Array<{ id?: string; name?: string; picture?: { data?: { url?: string } }; access_token?: string }> = []
        try {
            fbPages = await fetchMeAccountsViaHttp(postImportToken)
        } catch (e) {
            const parsed = parseFacebookErrorLike(e)
            const msg = String(parsed?.message || (e instanceof Error ? e.message : '')).toLowerCase()
            // When the user pastes a PAGE token (not a USER token), /me/accounts fails with
            //   (#100) Tried accessing nonexisting field (accounts)
            // because only USER tokens can enumerate accounts. Fall back to /me — a page
            // token lets /me return that single page's id/name, and the pasted token IS
            // the access_token for that page.
            const isPageTokenLike = /nonexisting field.*accounts/i.test(msg)
                || (/\(#100\)/.test(msg) && /accounts/i.test(msg))
            if (isPageTokenLike) {
                try {
                    const meUrl = buildFacebookGraphUrl(`${FB_GRAPH_V19}/me`, {
                        fields: 'id,name,picture.type(large)',
                        access_token: postImportToken,
                    })
                    const meResp = await fetch(meUrl, { method: 'GET' })
                    const meData = await meResp.json().catch(() => ({})) as {
                        id?: string
                        name?: string
                        picture?: { data?: { url?: string } }
                        error?: { message?: string } | string
                    }
                    if (!meResp.ok) {
                        const errPayload = typeof meData?.error === 'string'
                            ? { message: meData.error }
                            : (meData?.error || {})
                        throw new Error(String(errPayload?.message || `HTTP ${meResp.status}`))
                    }
                    const fallbackPageId = String(meData?.id || '').trim()
                    if (!fallbackPageId) {
                        throw new Error('Page token /me returned no id')
                    }
                    fbPages = [{
                        id: fallbackPageId,
                        name: String(meData?.name || '').trim() || fallbackPageId,
                        picture: meData?.picture,
                        access_token: postImportToken,
                    }]
                } catch (fallbackErr) {
                    return c.json({
                        error: 'Facebook API error',
                        details: fallbackErr instanceof Error ? fallbackErr.message : String(fallbackErr)
                    }, 400)
                }
            } else {
                return c.json({
                    error: 'Facebook API error',
                    details: parsed?.message || (e instanceof Error ? e.message : 'Unknown error')
                }, 400)
            }
        }

        if (fbPages.length === 0) {
            return c.json({ error: 'No pages found for this account' }, 404)
        }

        const imported: { id: string; name: string }[] = []
        const updated: { id: string; name: string; reason: string }[] = []
        const conflicts: { id: string; name: string; reason: string; existing_bot_id: string }[] = []
        const invalidPostTokenPages: { id: string; name: string; reason: string }[] = []
        const commentPageTokenById = new Map<string, string>()
        const tokenPool = await getNamespacePagesTokenPool(c.env.DB, botId)

        // Only run a SEPARATE /me/accounts pass for comment tokens when the operator
        // actually pasted a distinct comment token. In the single-token model (same
        // token used for post + comment) and when a Page token was pasted, this extra
        // call is unnecessary and will fail with "#100 accounts" for page tokens.
        const hasDistinctCommentToken = !!String(commentImportToken || '').trim()
            && String(commentImportToken || '').trim() !== String(postImportToken || '').trim()
        if (hasDistinctCommentToken) {
            try {
                const commentPages = await fetchMeAccountsViaHttp(commentImportToken)
                for (const item of commentPages) {
                    const id = String(item?.id || '').trim()
                    const pageToken = String(item?.access_token || '').trim()
                    if (!id || !isResolvedCommentToken(pageToken)) continue
                    if (!commentPageTokenById.has(id)) commentPageTokenById.set(id, pageToken)
                }
            } catch (e) {
                const parsed = parseFacebookErrorLike(e)
                const msg = String(parsed?.message || (e instanceof Error ? e.message : '')).toLowerCase()
                // Comment token is a page token too — fall back to /me and treat it as
                // the comment token for that single page.
                const isPageTokenLike = /nonexisting field.*accounts/i.test(msg)
                    || (/\(#100\)/.test(msg) && /accounts/i.test(msg))
                if (isPageTokenLike) {
                    try {
                        const meUrl = buildFacebookGraphUrl(`${FB_GRAPH_V19}/me`, {
                            fields: 'id,name',
                            access_token: commentImportToken,
                        })
                        const meResp = await fetch(meUrl, { method: 'GET' })
                        const meData = await meResp.json().catch(() => ({})) as {
                            id?: string
                            error?: { message?: string } | string
                        }
                        if (!meResp.ok) {
                            const errPayload = typeof meData?.error === 'string'
                                ? { message: meData.error }
                                : (meData?.error || {})
                            throw new Error(String(errPayload?.message || `HTTP ${meResp.status}`))
                        }
                        const fallbackPageId = String(meData?.id || '').trim()
                        if (fallbackPageId && isResolvedCommentToken(commentImportToken)) {
                            commentPageTokenById.set(fallbackPageId, commentImportToken)
                        }
                    } catch (fallbackErr) {
                        return c.json({
                            error: 'Failed to resolve comment page tokens via /me/accounts',
                            details: fallbackErr instanceof Error ? fallbackErr.message : String(fallbackErr),
                        }, 400)
                    }
                } else {
                    return c.json({
                        error: 'Failed to resolve comment page tokens via /me/accounts',
                        details: parsed?.message || (e instanceof Error ? e.message : String(e)),
                    }, 400)
                }
            }
        }

        for (const fbPage of fbPages) {
            const pageId = String(fbPage.id || '').trim()
            if (!pageId) continue
            const pageName = String(fbPage.name || '').trim() || pageId
            const pageImageUrl = pageId
                ? `https://graph.facebook.com/${encodeURIComponent(pageId)}/picture?type=large`
                : (fbPage.picture?.data?.url || '')
            const pageAccessToken = String(fbPage.access_token || '').trim()
            // Accept any non-empty token — the EAAD6/EAACh prefix encodes the Facebook
            // app id, not the token's scope. Matches the single-token model where
            // whatever the operator pasted is used for both posting and commenting.
            if (!isTokenValid(pageAccessToken)) {
                invalidPostTokenPages.push({
                    id: pageId,
                    name: pageName,
                    reason: 'missing_page_access_token_from_me_accounts',
                })
                continue
            }
            const pageCommentTokenRaw = String(commentPageTokenById.get(pageId) || '').trim()
            const primaryToken = String(pageAccessToken || '').trim()
            const existingEntry = tokenPool[pageId] || { post_tokens: [], comment_tokens: [] }
            const nextPostTokens = normalizePostTokenPool([
                pageAccessToken,
                ...(existingEntry.post_tokens || []),
            ])
            tokenPool[pageId] = {
                post_tokens: nextPostTokens,
                comment_tokens: buildPreferredCommentTokenPool({
                    primaryToken: pageAccessToken,
                    postTokens: nextPostTokens,
                    commentTokens: [
                        pageCommentTokenRaw,
                        ...(existingEntry.comment_tokens || []),
                    ],
                }),
                updated_at: new Date().toISOString(),
            }

            const existingInNamespace = await c.env.DB.prepare(
                'SELECT id FROM pages WHERE id = ? AND bot_id = ?'
            ).bind(pageId, botId).first() as { id?: string } | null

            if (existingInNamespace?.id) {
                await c.env.DB.prepare(
                    'UPDATE pages SET access_token = ?, image_url = ?, name = ?, updated_at = datetime("now") WHERE id = ? AND bot_id = ?'
                ).bind(primaryToken, pageImageUrl, pageName, pageId, botId).run()
                updated.push({ id: pageId, name: pageName, reason: 'updated' })
                continue
            }

            // pages.id is globally unique in current schema. If the page is currently
            // registered under a different namespace and the operator is re-adding it
            // here with a fresh token, treat that as an explicit "move" — reassign
            // ownership to the current workspace and purge the token pool from the
            // previous namespace. Confirmed user intent: "ถ้าไม่ว่ายูสใส่ โทเค้นที่
            // namespace id ไหน ให้ลบเพจออกจากที่เก่า แล้วเพิ่มเพจ namespace id ใหม่"
            const existingInOtherNamespace = await c.env.DB.prepare(
                'SELECT bot_id FROM pages WHERE id = ?'
            ).bind(pageId).first() as { bot_id?: string } | null
            if (existingInOtherNamespace?.bot_id) {
                const oldBotId = String(existingInOtherNamespace.bot_id || '').trim()
                // Best-effort: remove the page entry from the OLD namespace's token pool
                // so stale tokens don't linger in a workspace that no longer owns the page.
                if (oldBotId && oldBotId !== botId) {
                    try {
                        const oldPool = await getNamespacePagesTokenPool(c.env.DB, oldBotId)
                        if (oldPool[pageId]) {
                            delete oldPool[pageId]
                            await setNamespacePagesTokenPool(c.env.DB, oldBotId, oldPool)
                        }
                    } catch { /* best-effort cleanup */ }
                }
                await c.env.DB.prepare(
                    'UPDATE pages SET bot_id = ?, access_token = ?, image_url = ?, name = ?, updated_at = datetime("now") WHERE id = ?'
                ).bind(botId, primaryToken, pageImageUrl, pageName, pageId).run()
                imported.push({ id: pageId, name: pageName })
            } else {
                await c.env.DB.prepare(
                    'INSERT INTO pages (id, name, image_url, access_token, post_interval_minutes, is_active, bot_id) VALUES (?, ?, ?, ?, 60, 1, ?)'
                ).bind(pageId, pageName, pageImageUrl, primaryToken, botId).run()
                imported.push({ id: pageId, name: pageName })
            }
        }

        await setNamespacePagesTokenPool(c.env.DB, botId, tokenPool)

        return c.json({
            success: true,
            imported: imported.length,
            updated: updated.length,
            conflicts: conflicts.length,
            invalid_post_token_pages: invalidPostTokenPages.length,
            source: 'provided_as_is',
            source_comment: 'provided_as_is',
            pages: [...imported, ...updated],
            conflict_pages: conflicts,
            invalid_pages: invalidPostTokenPages,
        })
    } catch (e) {
        return c.json({ error: 'Failed to import pages', details: String(e) }, 500)
    }
})

