// ==================== POST HISTORY API ====================

app.get('/api/post-history', async (c) => {
    try {
        const botId = c.get('botId')
        const dateFilter = String(c.req.query('date') || '').trim()
        const limitParam = Number(c.req.query('limit') || 100)
        const limit = Math.max(1, Math.min(200, Number.isFinite(limitParam) ? Math.floor(limitParam) : 100))
        const hasDateFilter = /^\d{4}-\d{2}-\d{2}$/.test(dateFilter)
        const { results } = await c.env.DB.prepare(
            `WITH ranked_history AS (
                 SELECT
                     ph.*,
                     p.name as page_name,
                     p.image_url as page_image,
                     ROW_NUMBER() OVER (
                         PARTITION BY CASE
                             WHEN ph.status = 'failed' THEN ph.page_id || '|' || COALESCE(ph.video_id, '')
                             ELSE 'row:' || CAST(ph.id AS TEXT)
                         END
                         ORDER BY ph.posted_at DESC, ph.id DESC
                     ) AS rn
                 FROM post_history ph
                 JOIN pages p ON ph.page_id = p.id
                 WHERE ph.status != 'deleted' AND p.bot_id = ?
                   AND (? = '' OR date(datetime(ph.posted_at, '+7 hours')) = ?)
             )
             SELECT *
             FROM ranked_history
             WHERE rn = 1
             ORDER BY posted_at DESC
             LIMIT ?`
        ).bind(botId, hasDateFilter ? dateFilter : '', hasDateFilter ? dateFilter : '', limit).all()
        return c.json({ history: results }, 200, {
            'Cache-Control': 'private, max-age=15, stale-while-revalidate=30',
        })
    } catch (e) {
        return c.json({ error: 'Failed to fetch history' }, 500)
    }
})

app.delete('/api/post-history/:id', async (c) => {
    try {
        const id = c.req.param('id')
        const row = await c.env.DB.prepare(
            'SELECT ph.fb_post_id, p.access_token FROM post_history ph JOIN pages p ON ph.page_id = p.id WHERE ph.id = ?'
        ).bind(id).first() as { fb_post_id?: string; access_token: string } | null

        if (row?.fb_post_id && row.access_token) {
            await facebookGraphDelete(row.access_token, `${FB_GRAPH_V19}/${row.fb_post_id}`).catch(() => { })
        }

        // Mark as hidden instead of deleting (keep record to prevent re-posting same video)
        await c.env.DB.prepare("UPDATE post_history SET status = 'deleted' WHERE id = ?").bind(id).run()
        return c.json({ success: true })
    } catch {
        return c.json({ error: 'Failed to delete' }, 500)
    }
})

// Namespace-scoped maintenance: recover a SINGLE failed post_history row whose Reel
// FB actually published but whose publish confirmation was lost (fb_post_id stayed
// null, e.g. cloak_post_failed: browser_graph_request_failed). Same engine as the
// cron backstop and the admin route (attemptFailedRowFeedRecovery), reachable with
// normal history (x-bot-id) auth — UNLIKE the /admin/* variant which needs the admin
// token. It does NOT repost (unlike retry-post): it only matches the already-published
// page-story and flips the row to success + comment_status='pending' so the existing
// pending-comment backlog posts the Shopee link.
//
// Safety: dry_run defaults TRUE (preview only). A write (dry_run:false) REQUIRES
// body.expected_fb_post_id to exactly equal the matched story tail, so a public caller
// can never pin an arbitrary/wrong story id — they must first read the matched id from
// a dry run and echo it back. Refuses rows that are not failed, already have an
// fb_post_id, or whose comment was already attempted. Returns redacted metadata only.
app.post('/api/post-history/:id/recover-from-feed', async (c) => {
    try {
        const botId = String(c.get('botId') || '').trim()
        if (!botId) return c.json({ ok: false, error: 'missing_namespace' }, 400)

        const historyId = Number(c.req.param('id'))
        if (!Number.isFinite(historyId) || historyId <= 0) return c.json({ ok: false, error: 'invalid_history_id' }, 400)

        const body = await c.req.json().catch(() => ({})) as {
            dry_run?: boolean
            expected_fb_post_id?: string
            ahead_minutes?: number
            behind_minutes?: number
        }
        const isExplicitFalse = (v: unknown): boolean => {
            const s = String(v ?? '').trim().toLowerCase()
            return v === false || s === 'false' || s === '0' || s === 'no' || s === 'off'
        }
        // dry_run defaults TRUE; only an explicit false enables the write.
        const dryRunRaw = body.dry_run !== undefined ? body.dry_run : c.req.query('dry_run')
        const dryRun = !isExplicitFalse(dryRunRaw)
        const expectedFbPostId = String(body.expected_fb_post_id ?? c.req.query('expected_fb_post_id') ?? '').trim()
        const aheadMinutes = Math.min(720, Math.max(1, Math.floor(Number(body.ahead_minutes ?? c.req.query('ahead_minutes') ?? 60))))
        const behindMinutes = Math.min(720, Math.max(1, Math.floor(Number(body.behind_minutes ?? c.req.query('behind_minutes') ?? 10))))

        // Writes must echo back the exact matched id from a prior dry run.
        if (!dryRun && !expectedFbPostId) {
            return c.json({ ok: false, error: 'expected_fb_post_id_required' }, 400)
        }

        await ensurePostHistoryTraceColumns(c.env.DB)
        const row = await c.env.DB.prepare(
            `SELECT ph.id, ph.bot_id, ph.page_id, ph.video_id, ph.posted_at, ph.shopee_link, ph.status,
                    ph.fb_post_id, ph.comment_status, p.name AS page_name, p.access_token
             FROM post_history ph
             JOIN pages p ON p.id = ph.page_id AND p.bot_id = ph.bot_id
             WHERE ph.id = ? AND ph.bot_id = ?
             LIMIT 1`
        ).bind(historyId, botId).first() as {
            id: number
            bot_id: string
            page_id: string
            video_id: string
            posted_at: string
            shopee_link?: string | null
            status?: string
            fb_post_id?: string | null
            comment_status?: string | null
            page_name?: string | null
            access_token?: string | null
        } | null

        if (!row) return c.json({ ok: false, error: 'history_row_not_found' }, 404)
        if (String(row.status || '').trim() !== 'failed') {
            return c.json({ ok: false, error: 'row_not_failed', status: row.status }, 409)
        }
        if (String(row.fb_post_id || '').trim()) {
            return c.json({ ok: false, error: 'row_already_has_fb_post_id' }, 409)
        }
        const commentStatus = String(row.comment_status || '').trim()
        if (commentStatus && commentStatus !== 'not_attempted') {
            return c.json({ ok: false, error: 'comment_already_attempted', comment_status: commentStatus }, 409)
        }

        const result = await attemptFailedRowFeedRecovery({
            env: c.env,
            row: {
                id: row.id,
                bot_id: String(row.bot_id || ''),
                page_id: String(row.page_id || ''),
                video_id: String(row.video_id || ''),
                posted_at: String(row.posted_at || ''),
                shopee_link: row.shopee_link,
                page_name: row.page_name,
                access_token: row.access_token,
            },
            aheadMs: aheadMinutes * 60 * 1000,
            behindMs: behindMinutes * 60 * 1000,
            freshnessGuardMs: 0,
            dryRun,
            expectedFbPostId,
            logPrefix: 'NS-RECOVER-FAILED',
        })

        // Confirmation mismatch on a write: report the matched id, do not write.
        if (result.reason === 'expected_fb_post_id_mismatch') {
            return c.json({
                ok: false,
                error: 'expected_fb_post_id_mismatch',
                history_id: historyId,
                expected_fb_post_id: expectedFbPostId,
                matched_fb_post_id: result.fb_post_id || null,
                candidates_scanned: result.candidates_scanned,
            }, 409)
        }

        return c.json({
            ok: true,
            history_id: historyId,
            dry_run: dryRun,
            recovered: result.recovered,
            reason: result.reason,
            candidates_scanned: result.candidates_scanned,
            fb_post_id: result.fb_post_id || null,
            fb_reel_url: result.fb_reel_url || null,
            comment_status: result.comment_status || null,
            caption_matched: result.caption_matched ?? null,
        })
    } catch (e) {
        return c.json({ ok: false, error: 'recover_from_feed_failed', details: e instanceof Error ? e.message : String(e) }, 500)
    }
})

app.post('/api/post-history/:id/retry-post', async (c) => {
    const id = c.req.param('id')
    const env = c.env
    const botId = String(c.get('botId') || '').trim()
    let pageId = ''
    let pageName = ''
    let pageAccessToken = ''
    let pageCommentToken: string | null = null
    let selectedVideoId = ''
    let selectedVideoNamespaceId = ''
    let selectedCaption = ''
    let attemptPostedAtIso = ''
    let normalizedShopeeLink = ''
    let normalizedLazadaLink = ''
    let selectedSourceFingerprint = ''
    let fbVideoId = ''
    let postingTokenUsed = ''
    let hasCommentToken = false
    let commentTokenCandidates: string[] = []
    let retryHistoryId: number | null = null
    let skipComment = false
    let pagePostingLockKey: string | null = null
    let videoPostingLockKey: string | null = null

    try {
        const body = await c.req.json().catch(() => ({})) as { skipComment?: boolean }
        skipComment = body.skipComment === true

        const sourceRow = await env.DB.prepare(
            `SELECT
                ph.id,
                ph.page_id,
                ph.video_id,
                ph.shopee_link,
                ph.posted_at,
                p.name AS page_name,
                p.access_token
             FROM post_history ph
             JOIN pages p ON p.id = ph.page_id
             WHERE ph.id = ?
               AND p.bot_id = ?
             LIMIT 1`
        ).bind(id, botId).first() as {
            id?: number
            page_id?: string
            video_id?: string
            shopee_link?: string | null
            posted_at?: string
            page_name?: string
            access_token?: string
        } | null

        if (!sourceRow?.page_id || !sourceRow?.video_id) {
            return c.json({ error: 'History not found' }, 404)
        }

        pageId = String(sourceRow.page_id || '').trim()
        pageName = String(sourceRow.page_name || pageId).trim()
        pageAccessToken = String(sourceRow.access_token || '').trim()
        selectedVideoId = String(sourceRow.video_id || '').trim()

        // Recover stale posting rows first so a dead attempt does not block the retry.
        await recoverStalePostingAttemptsForPage(env.DB, {
            namespaceId: botId,
            pageId,
            reason: 'stale_posting_timeout_no_fb_post_id_retry',
        }).catch(() => 0)

        const activePosting = await env.DB.prepare(
            `SELECT id
             FROM post_history
             WHERE bot_id = ?
               AND page_id = ?
               AND status = 'posting'
             ORDER BY posted_at DESC, id DESC
             LIMIT 1`
        ).bind(botId, pageId).first() as { id?: number } | null
        if (typeof activePosting?.id === 'number') {
            return c.json({
                error: 'page_already_posting',
                details: { history_id: activePosting.id },
            }, 409)
        }

        const page = await env.DB.prepare(
            'SELECT id, name, access_token, onecard_enabled, onecard_link_mode, onecard_cta, ads_publish_enabled FROM pages WHERE id = ? AND bot_id = ? LIMIT 1'
        ).bind(pageId, botId).first() as {
            id?: string
            name?: string
            access_token?: string
            onecard_enabled?: number | null
            onecard_link_mode?: string | null
            onecard_cta?: string | null
            ads_publish_enabled?: number | null
        } | null
        if (!page?.id) {
            return c.json({ error: 'Page not found' }, 404)
        }
        const pageOneCardEnabled = Number(page.onecard_enabled || 0) === 1
        const pageOneCardLinkMode = normalizePageOneCardLinkMode(page.onecard_link_mode)
        const pageOneCardCta = normalizePageOneCardCta(page.onecard_cta)
        const pageAdsPublishEnabled = Number(page.ads_publish_enabled || 0) === 1

        pagePostingLockKey = await tryAcquirePostingLock(env.DB, {
            scope: 'page',
            namespaceId: botId,
            pageId,
        })
        if (!pagePostingLockKey) {
            return c.json({ error: 'page_already_posting' }, 409)
        }

        const videoRef = await resolveGalleryVideoForRepost({
            env,
            fallbackNamespaceId: botId,
            videoId: selectedVideoId,
        })
        if (!videoRef) {
            return c.json({ error: 'Video metadata not found for repost' }, 404)
        }
        selectedVideoNamespaceId = String(videoRef.sourceNamespaceId || botId).trim() || botId
        const sourceBucket = selectedVideoNamespaceId === botId
            ? c.get('bucket')
            : new BotBucket(env.BUCKET, selectedVideoNamespaceId) as unknown as R2Bucket
        const meta = await loadLatestVideoMetaForPosting(sourceBucket, selectedVideoId, videoRef.meta)
        const sourceFingerprint = await resolveNamespaceVideoSourceFingerprint({
            env,
            namespaceId: botId,
            videoId: selectedVideoId,
            bucket: sourceBucket,
            sourceMeta: meta,
        })
        selectedSourceFingerprint = sourceFingerprint
        videoPostingLockKey = await tryAcquirePostingLock(env.DB, {
            scope: 'video',
            namespaceId: botId,
            videoId: sourceFingerprint || selectedVideoId,
        })
        if (!videoPostingLockKey) {
            return c.json({ error: 'video_already_posting' }, 409)
        }
        const rawShopeeLink = pickFirstShopeeUrl(String(sourceRow.shopee_link || '').trim()) || videoRef.shopeeLink || ''

        const publicUrl = metaToString(meta, 'publicUrl')
        const rawLazadaLink = normalizeMetaLazadaLink(meta) || metaToString(meta, 'lazadaLink')
        const rawLazadaMemberId = String(metaToString(meta, 'lazadaMemberId') || metaToString(meta, 'lazada_member_id') || '').trim()
        const apiKeys = await resolveNamespaceGeminiApiKeys(env.DB, botId)
        const hasManualCaption = !!normalizeManualCaption(meta.manualCaption || meta.caption || '')
        const title = metaToString(meta, 'title')
        const script = metaToString(meta, 'script')
        if (!hasManualCaption && !title && script && apiKeys.length === 0) {
            return c.json({ error: 'Gemini API key กลางของระบบยังไม่ได้ตั้งค่า' }, 400)
        }
        const model = env.GEMINI_MODEL || 'gemini-3-flash-preview'
        const caption = await buildPostingCaptionFromMeta(meta, apiKeys, model)
        selectedCaption = caption

        const shortlinkResolution = await resolvePrePostingShortlinksForNamespace({
            env,
            namespaceId: botId,
            pageId: String(page.id || ''),
            pageName,
            shopeeLink: rawShopeeLink,
            lazadaLink: rawLazadaLink,
            lazadaMemberId: rawLazadaMemberId,
            pageOneCardEnabled,
            pageOneCardLinkMode,
            pageOneCardCta,
            pageAdsPublishEnabled,
            logPrefix: 'RETRY-POST',
        })
        normalizedShopeeLink = shortlinkResolution.shopeeLink
        normalizedLazadaLink = shortlinkResolution.lazadaLink
        const normalizedLazadaMemberId = shortlinkResolution.lazadaMemberId
        const normalizedShopeeUtmSource = shortlinkResolution.shopeeTrace.utmSource ?? null
        const normalizedShopeeStatus = shortlinkResolution.shopeeTrace.status ?? null
        const normalizedShopeeError = shortlinkResolution.shopeeTrace.error ?? null
        const normalizedShopeeUtmMatch = null

        const tokenCandidates = await ensurePageTokenCandidates({
            env,
            db: env.DB,
            namespaceId: botId,
            pageId: pageId,
            pageName: pageName,
            primaryToken: pageAccessToken,
            logPrefix: 'RETRY-POST',
        })
        commentTokenCandidates = tokenCandidates.commentTokens
        pageCommentToken = commentTokenCandidates[0] || null
        const fallbackPostTokenCandidates = tokenCandidates.postTokens.length > 0
            ? tokenCandidates.postTokens
            : normalizePostTokenPool([pageAccessToken])
        const primaryPostingTokenCandidates = buildPrimaryPostingTokenCandidates({
            primaryToken: pageAccessToken,
            postTokens: fallbackPostTokenCandidates,
            commentTokens: commentTokenCandidates,
        })
        if (primaryPostingTokenCandidates.length === 0) {
            throw new Error('access_token_missing')
        }

        await ensurePostHistoryTraceColumns(env.DB)
        const commentTokenHint = deriveCommentTokenHint(pageCommentToken)
        const initialPostTokenHint = deriveCommentTokenHint(primaryPostingTokenCandidates[0] || null)
        const initialPostProfile = await resolvePostHistoryProfileByToken(env, primaryPostingTokenCandidates[0] || null)
        hasCommentToken = commentTokenCandidates.length > 0 && !!String(pageCommentToken || '').trim()
        const initialCommentState = getInitialCommentTraceState(!!normalizedShopeeLink)
        attemptPostedAtIso = new Date().toISOString()
        const inserted = await env.DB.prepare(
            'INSERT INTO post_history (page_id, video_id, posted_at, status, trigger_source, bot_id, post_token_hint, post_profile_id, post_profile_name, comment_status, comment_token_hint, comment_error, comment_fb_id, shopee_link, lazada_link, lazada_member_id, shortlink_utm_source, shortlink_status, shortlink_error, shortlink_expected_utm_id, shortlink_utm_match, shortlink_conversion_status, shortlink_conversion_error, source_fingerprint) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)'
        ).bind(
            pageId,
            selectedVideoId,
            attemptPostedAtIso,
            'posting',
            'retry_post',
            botId,
            initialPostTokenHint,
            initialPostProfile.profileId,
            initialPostProfile.profileName,
            initialCommentState.status,
            commentTokenHint,
            initialCommentState.error,
            null,
            normalizedShopeeLink || null,
            normalizedLazadaLink || null,
            normalizedLazadaMemberId || null,
            normalizedShopeeUtmSource,
            normalizedShopeeStatus,
            normalizedShopeeError,
            null,
            normalizedShopeeUtmMatch,
            shortlinkResolution.conversionStatus,
            shortlinkResolution.conversionError,
            selectedSourceFingerprint || null,
        ).run() as { meta?: { last_row_id?: number } }
        retryHistoryId = Number(inserted?.meta?.last_row_id || 0) || null

        if (shortlinkResolution.errorMessage) {
            if (retryHistoryId) {
                await env.DB.prepare(
                    "UPDATE post_history SET status = 'failed', error_message = ?, comment_status = 'not_attempted' WHERE id = ? AND status = 'posting'"
                ).bind(shortlinkResolution.errorMessage, retryHistoryId).run().catch(() => { })
            }
            return c.json({
                error: 'shortlink_failed',
                details: shortlinkResolution.errorMessage,
            }, 409)
        }

        const affiliateVerification = await verifyAffiliateLinksForPosting({
            env,
            namespaceId: botId,
            pageId: String(page.id || ''),
            shopeeLink: normalizedShopeeLink,
            lazadaLink: normalizedLazadaLink,
            requireLazadaLink: shortlinkResolution.lazadaRequired,
            logPrefix: 'RETRY-POST VERIFY',
        })
        if (retryHistoryId) {
            await updatePostHistoryAffiliateVerificationById(env.DB, retryHistoryId, affiliateVerification)
        }
        if (!affiliateVerification.ok) {
            if (retryHistoryId) {
                await env.DB.prepare(
                    "UPDATE post_history SET status = 'failed', error_message = ?, comment_status = 'not_attempted' WHERE id = ? AND status = 'posting'"
                ).bind(affiliateVerification.error || 'affiliate_verification_failed', retryHistoryId).run().catch(() => { })
            }
            return c.json({
                error: 'affiliate_verification_failed',
                details: affiliateVerification.error || 'Affiliate verification failed',
            }, 400)
        }

        const affiliateCommentPreflight = validateAffiliateCommentPreflight({
            shopeeLink: normalizedShopeeLink,
            hasCommentToken,
            skipComment,
        })
        if (!affiliateCommentPreflight.ok) {
            const errorCode = affiliateCommentPreflight.error || 'affiliate_comment_not_configured'
            if (retryHistoryId) {
                await env.DB.prepare(
                    "UPDATE post_history SET status = 'failed', error_message = ?, comment_status = 'not_attempted', comment_error = ? WHERE id = ? AND status = 'posting'"
                ).bind(errorCode, errorCode, retryHistoryId).run().catch(() => { })
            }
            return c.json({
                error: errorCode,
                details: 'Affiliate comment token is required before posting',
            }, 409)
        }

        await env.DB.prepare('UPDATE pages SET last_post_at = ? WHERE id = ? AND bot_id = ?').bind(attemptPostedAtIso, pageId, botId).run()

        const realVideoUrl = resolvePostingVideoDownloadUrl(env, selectedVideoNamespaceId, selectedVideoId, publicUrl)

        let videoBuffer: ArrayBuffer | null = null
        const avatarSettings = await getPageAvatarSettings(env.DB, pageId).catch(() => null)
        if (avatarSettings?.enabled && !TEMP_DISABLE_AVATAR_COMPOSE_FOR_POSTING) {
            if (!avatarSettings.videoKey) throw new Error('avatar_compose_failed: avatar_video_key_missing')
            const avatarHead = await c.get('bucket').head(avatarSettings.videoKey).catch(() => null)
            if (!avatarHead) throw new Error('avatar_compose_failed: avatar_video_missing')
            const avatarVideoUrl = buildAvatarObjectUrl(env, botId, avatarSettings.videoKey)
            if (!avatarVideoUrl) throw new Error('avatar_compose_failed: avatar_url_missing')
            try {
                const parsedAvatarUrl = new URL(avatarVideoUrl)
                if (!['http:', 'https:'].includes(parsedAvatarUrl.protocol)) {
                    throw new Error('invalid_protocol')
                }
            } catch {
                throw new Error('avatar_compose_failed: avatar_url_invalid')
            }
            videoBuffer = await composeAvatarVideoForPosting({
                env,
                baseVideoUrl: realVideoUrl,
                avatarVideoUrl,
                chromakeySimilarity: avatarSettings.chromakeySimilarity,
                chromakeyBlend: avatarSettings.chromakeyBlend,
            })
        }
        if (!videoBuffer) {
            const videoResp = await fetchWithTimeout(realVideoUrl, {}, 60000, 'retry_post_download_video')
            if (!videoResp.ok) throw new Error(`Fetch video failed with status ${videoResp.status}`)
            videoBuffer = await videoResp.arrayBuffer()
        }
        if (videoBuffer.byteLength < 100000) throw new Error(`Video too small (${videoBuffer.byteLength} bytes). Download failed.`)
        const postingThumbnail = await loadPostingThumbnailAsset({
            env,
            namespaceId: selectedVideoNamespaceId,
            videoId: selectedVideoId,
        }).catch(() => null)

        postingTokenUsed = String(primaryPostingTokenCandidates[0] || '').trim()
        const reelResult = await publishReelWithCommentTokenPrimaryFallbackAndLiteRefresh({
            env,
            db: env.DB,
            namespaceId: botId,
            pageId,
            pageName,
            commentTokens: commentTokenCandidates,
            postTokens: fallbackPostTokenCandidates,
            videoBuffer,
            thumbnailBuffer: postingThumbnail?.buffer || null,
            thumbnailContentType: postingThumbnail?.contentType || '',
            description: caption,
            logPrefix: 'RETRY-POST',
            reloadTokens: async () => {
                const refreshed = await ensurePageTokenCandidates({
                    env,
                    db: env.DB,
                    namespaceId: botId,
                    pageId,
                    pageName,
                    primaryToken: pageAccessToken,
                    logPrefix: 'RETRY-POST RELOAD',
                })
                const post = refreshed.postTokens.length > 0
                    ? refreshed.postTokens
                    : normalizePostTokenPool([pageAccessToken])
                return { commentTokens: refreshed.commentTokens, postTokens: post }
            },
        })
        postingTokenUsed = reelResult.postingToken
        const postingProfile = await resolvePostHistoryProfileByToken(env, postingTokenUsed)

        fbVideoId = reelResult.id
        const confirmedCanonicalPostId = String(reelResult.postId || '').trim()
        const confirmedPostId = confirmedCanonicalPostId || fbVideoId
        let commentShopeeLink = normalizedShopeeLink
        if (commentShopeeLink && !skipComment && hasCommentToken) {
            try {
                const commentSubIds = buildPostingCommentShortlinkSubIds({
                    canonicalPostId: confirmedCanonicalPostId,
                    fbVideoId,
                    pageId,
                    historyId: retryHistoryId,
                    logPrefix: 'RETRY-POST COMMENT-SHORTLINK',
                })
                const reshortened = await resolvePostingShopeeLinkForNamespace({
                    env,
                    namespaceId: botId,
                    pageId,
                    shopeeLink: rawShopeeLink || normalizedShopeeLink,
                    logPrefix: 'RETRY-POST COMMENT-SHORTLINK',
                    ...commentSubIds,
                })
                if (reshortened) commentShopeeLink = reshortened
            } catch (reshortenErr) {
                console.log(`[RETRY-POST COMMENT-SHORTLINK] re-shorten with post id failed; falling back to preflight link: ${reshortenErr instanceof Error ? reshortenErr.message : String(reshortenErr)}`)
            }
        }
        const fbReelUrl = String(reelResult.permalinkUrl || '').trim() || `https://www.facebook.com/reel/${fbVideoId}`
        const scheduledCommentDelaySeconds = commentShopeeLink && !skipComment && hasCommentToken
            ? getRandomCommentDelaySeconds()
            : null
        const scheduledCommentDueAt = scheduledCommentDelaySeconds
            ? new Date(Date.now() + (scheduledCommentDelaySeconds * 1000)).toISOString()
            : null
        const postReadyCommentState = getPostReadyCommentTraceState(!!commentShopeeLink, hasCommentToken, skipComment)
        await env.DB.prepare(
            "UPDATE post_history SET fb_post_id = ?, fb_reel_url = ?, post_token_hint = ?, post_profile_id = ?, post_profile_name = ?, comment_status = ?, comment_token_hint = ?, comment_error = ?, comment_delay_seconds = ?, comment_due_at = ?, shopee_link = ? WHERE id = ? AND status = 'posting'"
        ).bind(
            confirmedPostId,
            fbReelUrl,
            deriveCommentTokenHint(postingTokenUsed),
            postingProfile.profileId,
            postingProfile.profileName,
            postReadyCommentState.status,
            deriveCommentTokenHint(pageCommentToken),
            postReadyCommentState.error,
            scheduledCommentDelaySeconds,
            scheduledCommentDueAt,
            commentShopeeLink || normalizedShopeeLink || null,
            retryHistoryId,
        ).run()

        let commentStatus = postReadyCommentState.status
        let commentError: string | null = postReadyCommentState.error
        let commentFbId: string | null = null
        let commentTokenUsed = String(pageCommentToken || '').trim()
        let commentProfileId: string | null = null
        let commentProfileName: string | null = null

        if (commentShopeeLink && !skipComment && hasCommentToken) {
            commentStatus = 'pending'
            commentError = null
        } else if (skipComment) {
            commentStatus = 'skipped'
            commentError = null
        }

        await env.DB.prepare(
            "UPDATE post_history SET fb_post_id = ?, fb_reel_url = ?, status = 'success', error_message = NULL, post_token_hint = ?, post_profile_id = ?, post_profile_name = ?, comment_status = ?, comment_token_hint = ?, comment_profile_id = ?, comment_profile_name = ?, comment_error = ?, comment_fb_id = ?, shopee_link = ? WHERE id = ? AND status = 'posting'"
        ).bind(
            confirmedPostId,
            fbReelUrl,
            deriveCommentTokenHint(postingTokenUsed),
            postingProfile.profileId,
            postingProfile.profileName,
            commentStatus,
            deriveCommentTokenHint(commentTokenUsed || pageCommentToken),
            commentProfileId,
            commentProfileName,
            commentError,
            commentFbId,
            commentShopeeLink || normalizedShopeeLink || null,
            retryHistoryId,
        ).run()
        if (commentStatus === 'pending') {
            runPendingCommentBacklogSoon(env, retryHistoryId, 'RETRY-POST IMMEDIATE-COMMENT', c.executionCtx)
        }
        await markNamespaceVideoPosted(env.DB, botId, selectedVideoId, new Date().toISOString())
        await recordPagePostedVideoGuard(env.DB, {
            namespaceId: botId,
            pageId,
            videoId: selectedVideoId,
            sourceFingerprint: selectedSourceFingerprint,
            historyId: retryHistoryId,
            postedAt: attemptPostedAtIso,
        }).catch(() => { })

        await clearVideoShopeeLink(sourceBucket, selectedVideoId)
        return c.json({
            success: true,
            reposted_from_history_id: Number(id),
            history_id: retryHistoryId,
            page: pageName,
            video_id: selectedVideoId,
            fb_video_id: fbVideoId,
            fb_post_id: confirmedPostId,
            fb_reel_url: fbReelUrl,
            log_id: retryHistoryId,
            post_history_id: retryHistoryId,
        })
    } catch (e) {
        const errorMsg = e instanceof Error ? e.message : String(e)

        if (pageAccessToken && pageId && selectedVideoId && retryHistoryId) {
            try {
                let recoveredPostId = ''
                let recoveredReelUrl = ''

                if (fbVideoId) {
                    const recovered = await pollPublishedReelAfterProcessing({
                        accessToken: pageAccessToken,
                        fbVideoId,
                        logPrefix: 'RETRY-POST-RECOVER',
                    })
                    if (recovered.published && recovered.post_id) {
                        recoveredPostId = String(recovered.post_id || '').trim() || fbVideoId
                        recoveredReelUrl = String(recovered.permalink_url || '').trim() || `https://www.facebook.com/reel/${recoveredPostId}`
                    }
                }

                if (!recoveredPostId && selectedCaption) {
                    const feedRecovered = await recoverPublishedReelFromRecentFeed({
                        accessToken: pageAccessToken,
                        pageId,
                        expectedCaption: selectedCaption,
                        notBeforeIso: attemptPostedAtIso,
                        logPrefix: 'RETRY-POST-RECOVER-FEED',
                    })
                    if (feedRecovered.published && feedRecovered.post_id) {
                        recoveredPostId = String(feedRecovered.post_id || '').trim()
                        recoveredReelUrl = String(feedRecovered.permalink_url || '').trim() || `https://www.facebook.com/reel/${recoveredPostId}`
                    }
                }

                if (recoveredPostId) {
                    let commentShopeeLink = normalizedShopeeLink
                    if (commentShopeeLink && !skipComment && hasCommentToken) {
                        try {
                            const commentSubIds = buildPostingCommentShortlinkSubIds({
                                canonicalPostId: recoveredPostId,
                                fbVideoId,
                                reelId: extractIdFromCommentTargetInput(recoveredReelUrl),
                                pageId,
                                historyId: retryHistoryId,
                                logPrefix: 'RETRY-POST-RECOVER COMMENT-SHORTLINK',
                            })
                            const reshortened = await resolvePostingShopeeLinkForNamespace({
                                env,
                                namespaceId: botId,
                                pageId,
                                shopeeLink: normalizedShopeeLink,
                                logPrefix: 'RETRY-POST-RECOVER COMMENT-SHORTLINK',
                                ...commentSubIds,
                            })
                            if (reshortened) commentShopeeLink = reshortened
                        } catch (reshortenErr) {
                            console.log(`[RETRY-POST-RECOVER COMMENT-SHORTLINK] re-shorten with post id failed; falling back to preflight link: ${reshortenErr instanceof Error ? reshortenErr.message : String(reshortenErr)}`)
                        }
                    }
                    const recoveredCommentState = getPostReadyCommentTraceState(!!commentShopeeLink, hasCommentToken, skipComment)
                    let commentStatus = recoveredCommentState.status
                    let commentError: string | null = recoveredCommentState.error
                    let commentFbId: string | null = null
                    let commentTokenUsed = String(pageCommentToken || '').trim()
                    let commentProfileId: string | null = null
                    let commentProfileName: string | null = null
                    const commentTargetId = fbVideoId || extractReelIdFromPermalink(normalizeFacebookPermalink(recoveredReelUrl)) || recoveredPostId

                    if (commentShopeeLink && !skipComment && hasCommentToken) {
                        const commentWaitMs = getRandomCommentDelayMs()
                        await waitMs(commentWaitMs)
                        const commentResult = await postShopeeCommentWithFallback({
                            env,
                            namespaceId: botId,
                            fbVideoId: commentTargetId,
                            shopeeLink: commentShopeeLink,
                            lazadaLink: normalizedLazadaLink,
                            commentTokens: commentTokenCandidates,
                            pageId,
                            logPrefix: 'RETRY-POST-RECOVER',
                        })
                        if (!commentResult.ok) {
                            commentStatus = 'failed'
                            commentError = commentResult.error || 'comment_failed'
                            commentTokenUsed = String(commentResult.commentToken || commentTokenUsed || '').trim()
                            const commentProfile = await resolvePostHistoryProfileByToken(env, commentTokenUsed)
                            commentProfileId = commentProfile.profileId
                            commentProfileName = commentProfile.profileName
                            await notifyCommentTokenIssue(
                                env,
                                botId,
                                pageId,
                                pageName || pageId,
                                commentError,
                            ).catch((notifyErr) => {
                                console.error(`[RETRY-POST-RECOVER] notifyCommentTokenIssue failed: ${notifyErr instanceof Error ? notifyErr.message : String(notifyErr)}`)
                            })
                        } else {
                            commentStatus = 'success'
                            commentFbId = commentResult.id || null
                            commentTokenUsed = String(commentResult.commentToken || commentTokenUsed || '').trim()
                            const commentProfile = await resolvePostHistoryProfileByToken(env, commentTokenUsed)
                            commentProfileId = commentProfile.profileId
                            commentProfileName = commentProfile.profileName
                        }
                    }

                    const recoveredPostProfile = await resolvePostHistoryProfileByToken(env, postingTokenUsed)
                    await env.DB.prepare(
                        "UPDATE post_history SET fb_post_id = ?, fb_reel_url = ?, status = 'success', error_message = NULL, post_token_hint = ?, post_profile_id = ?, post_profile_name = ?, comment_status = ?, comment_token_hint = ?, comment_profile_id = ?, comment_profile_name = ?, comment_error = ?, comment_fb_id = ? WHERE id = ? AND status IN ('posting','failed')"
                    ).bind(
                        recoveredPostId,
                        recoveredReelUrl || `https://www.facebook.com/reel/${recoveredPostId}`,
                        deriveCommentTokenHint(postingTokenUsed),
                        recoveredPostProfile.profileId,
                        recoveredPostProfile.profileName,
                        commentStatus,
                        deriveCommentTokenHint(commentTokenUsed || pageCommentToken),
                        commentProfileId,
                        commentProfileName,
                        commentError,
                        commentFbId,
                        retryHistoryId,
                    ).run()
                    await markNamespaceVideoPosted(env.DB, botId, selectedVideoId, new Date().toISOString())
                    await recordPagePostedVideoGuard(env.DB, {
                        namespaceId: botId,
                        pageId,
                        videoId: selectedVideoId,
                        sourceFingerprint: selectedSourceFingerprint,
                        historyId: retryHistoryId,
                        postedAt: attemptPostedAtIso,
                    }).catch(() => { })

                    const sourceBucket = selectedVideoNamespaceId === botId
                        ? c.get('bucket')
                        : new BotBucket(env.BUCKET, selectedVideoNamespaceId || botId) as unknown as R2Bucket
                    await clearVideoShopeeLink(sourceBucket, selectedVideoId)
                    return c.json({
                        success: true,
                        recovered: true,
                        reposted_from_history_id: Number(id),
                        history_id: retryHistoryId,
                        log_id: retryHistoryId,
                        post_history_id: retryHistoryId,
                        page: pageName || pageId,
                        video_id: selectedVideoId,
                        fb_video_id: fbVideoId,
                        fb_post_id: recoveredPostId,
                        fb_reel_url: recoveredReelUrl || `https://www.facebook.com/reel/${recoveredPostId}`,
                    })
                }
            } catch (recoverErr) {
                console.error(`[RETRY-POST-RECOVER] failed: ${recoverErr instanceof Error ? recoverErr.message : String(recoverErr)}`)
            }
        }

        if (retryHistoryId) {
            await env.DB.prepare(
                "UPDATE post_history SET status = 'failed', error_message = ?, comment_status = 'not_attempted' WHERE id = ? AND status = 'posting'"
            ).bind(errorMsg, retryHistoryId).run().catch(() => { })
        }

        return c.json({ error: 'Retry post failed', details: errorMsg }, 500)
    } finally {
        await releasePostingLock(env.DB, videoPostingLockKey)
        await releasePostingLock(env.DB, pagePostingLockKey)
    }
})

app.get('/api/pages/:id/history', async (c) => {
    const pageId = c.req.param('id')
    try {
        const { results } = await c.env.DB.prepare(
            'SELECT * FROM post_history WHERE page_id = ? ORDER BY posted_at DESC LIMIT 50'
        ).bind(pageId).all()
        return c.json({ history: results })
    } catch (e) {
        return c.json({ error: 'Failed to fetch history' }, 500)
    }
})

// Authenticated maintenance endpoint: re-queue already-failed affiliate comments so the
// stored→CloakBrowser bridge fallback (processPendingCommentBacklog) can repair them, without
// a manual D1 remote write. Same dashboard-session auth + namespace scoping as the page
// settings/history routes — NOT an admin endpoint. Only rows that the backlog fallback could
// actually fix are touched: post went out via the admin-owned bridge (post_token_hint eligible)
// and the comment failed on a token auth/availability error. dry_run defaults true.
// Manual/maintenance trigger for the Facebook Lite (FB GET Token) refresh. Authenticated +
// namespace-scoped + dry-run-safe (dry_run defaults TRUE). Re-mints a fresh page comment
// token from the page's stored BrowserSaving credentials and syncs it into the namespace
// pool. Returns ONLY booleans + counts + a redacted reason hint — never a token. Use this to
// repair a page stuck behind an invalidated Facebook Lite token without waiting for the cron.
app.post('/api/pages/:id/refresh-comment-token', async (c) => {
    const ownerCheck = await requireAuthSession(c)
    if (!ownerCheck.ok) return ownerCheck.response

    const pageId = String(c.req.param('id') || '').trim()
    const namespaceId = String(c.get('botId') || '').trim()
    if (!pageId) return c.json({ error: 'Page ID is required' }, 400)
    if (!namespaceId) return c.json({ error: 'Unauthorized' }, 401)

    const page = await c.env.DB.prepare(
        'SELECT id, name FROM pages WHERE id = ? AND bot_id = ?'
    ).bind(pageId, namespaceId).first() as { id?: string; name?: string } | null
    if (!page?.id) return c.json({ error: 'Page not found' }, 404)
    const pageName = String(page.name || '').trim()

    const body = await c.req.json().catch(() => ({})) as { dry_run?: unknown; dryRun?: unknown; candidate_login_ids?: unknown; candidateLoginIds?: unknown }
    // dry_run defaults TRUE — only an explicit false performs the live refresh + sync.
    const dryRunRaw = body.dry_run ?? body.dryRun ?? c.req.query('dry_run')
    const dryRun = !(dryRunRaw === false || String(dryRunRaw ?? '').trim().toLowerCase() === 'false')
    const rawCandidateLogins = body.candidate_login_ids ?? body.candidateLoginIds
    const candidateLoginIds = Array.isArray(rawCandidateLogins)
        ? rawCandidateLogins.map((v) => String(v || '').trim()).filter(Boolean)
        : String(rawCandidateLogins || '').split(',').map((v) => v.trim()).filter(Boolean)

    try {
        if (dryRun) {
            // No mint: ask BrowserSaving whether a stored Account Manager profile owns/admins
            // the page (auto-discovery), so a missing manual link is NOT reported as terminal.
            const probe = await probeFacebookLiteProfilesForPage({
                env: c.env,
                db: c.env.DB,
                namespaceId,
                pageId,
                pageName,
                candidateLoginIds,
            })
            return c.json({
                ok: true,
                dry_run: true,
                page_id: pageId,
                would_refresh: probe.wouldRefresh,
                profile_found: probe.profileFound,
                linked_profile_count: probe.linkedCount,
                credentialed_count: probe.credentialedCount,
                reason: probe.reason || (probe.wouldRefresh ? 'refresh_available' : 'no_credentialed_profile'),
            })
        }

        const result = await refreshFacebookLiteCommentTokenForPage({
            env: c.env,
            db: c.env.DB,
            namespaceId,
            pageId,
            pageName,
            candidateLoginIds,
            logPrefix: `MANUAL-REFRESH ${pageName || pageId}`,
        })
        return c.json({
            ok: result.refreshed,
            dry_run: false,
            page_id: pageId,
            refreshed: result.refreshed,
            synced: result.synced,
            profile_count: result.profileCount,
            reason: String(result.reason || '').slice(0, 120),
        }, result.refreshed ? 200 : 502)
    } catch (e) {
        return c.json({
            ok: false,
            dry_run: dryRun,
            page_id: pageId,
            error: 'fb_lite_refresh_failed',
            reason: (e instanceof Error ? e.message : String(e)).slice(0, 120),
        }, 500)
    }
})

app.post('/api/pages/:id/retry-failed-comments', async (c) => {
    const ownerCheck = await requireAuthSession(c)
    if (!ownerCheck.ok) return ownerCheck.response

    const pageId = String(c.req.param('id') || '').trim()
    const namespaceId = String(c.get('botId') || '').trim()
    if (!pageId) return c.json({ error: 'Page ID is required' }, 400)
    if (!namespaceId) return c.json({ error: 'Unauthorized' }, 401)

    const page = await c.env.DB.prepare(
        'SELECT id, name FROM pages WHERE id = ? AND bot_id = ?'
    ).bind(pageId, namespaceId).first() as { id?: string; name?: string } | null
    if (!page?.id) return c.json({ error: 'Page not found' }, 404)

    const body = await c.req.json().catch(() => ({})) as { dry_run?: unknown; dryRun?: unknown; limit?: unknown }
    // dry_run defaults TRUE — only an explicit false (body or query) performs the write.
    const dryRunRaw = body.dry_run ?? body.dryRun ?? c.req.query('dry_run')
    const dryRun = !(dryRunRaw === false || String(dryRunRaw ?? '').trim().toLowerCase() === 'false')

    const limitRaw = body.limit ?? c.req.query('limit')
    let limit = Math.floor(Number(limitRaw))
    if (!Number.isFinite(limit) || limit <= 0) limit = 10
    limit = Math.min(10, Math.max(1, limit))

    try {
        // Coarse SQL cut (index-friendly), precise eligibility re-checked in JS via the shared
        // helpers so the route and the backlog processor agree on what is repairable.
        const SCAN_CAP = 100
        const scan = await c.env.DB.prepare(
            `SELECT id, video_id, fb_post_id, post_token_hint, comment_error, comment_token_hint, posted_at
             FROM post_history
             WHERE page_id = ?
               AND bot_id = ?
               AND status = 'success'
               AND comment_status = 'failed'
               AND TRIM(COALESCE(fb_post_id, '')) <> ''
             ORDER BY datetime(posted_at) DESC, id DESC
             LIMIT ?`
        ).bind(pageId, namespaceId, SCAN_CAP).all() as {
            results?: Array<{
                id?: number
                video_id?: string
                fb_post_id?: string
                post_token_hint?: string
                comment_error?: string
                comment_token_hint?: string
                posted_at?: string
            }>
        }

        const eligible = (scan.results || []).filter((r) =>
            isCloakBridgeCommentFallbackEligible(r.post_token_hint) &&
            isStoredCommentTokenAuthFailure(r.comment_error)
        ).slice(0, limit)

        // Safe, token-free projection. comment_error is the already-sanitized stored string
        // (a Graph auth/session message, never a token); truncate defensively anyway.
        const candidates = eligible.map((r) => ({
            id: Number(r.id || 0),
            video_id: String(r.video_id || ''),
            fb_post_id: String(r.fb_post_id || ''),
            post_token_hint: String(r.post_token_hint || ''),
            comment_token_hint: String(r.comment_token_hint || ''),
            posted_at: String(r.posted_at || ''),
            comment_error: String(r.comment_error || '').substring(0, 200),
        }))
        const candidateIds = candidates.map((r) => r.id).filter((id) => id > 0)

        if (dryRun || candidateIds.length === 0) {
            return c.json({
                page_id: pageId,
                namespace_id: namespaceId,
                dry_run: true,
                limit,
                before: { eligible_failed_comments: candidateIds.length },
                candidate_ids: candidateIds,
                candidates,
            })
        }

        // Write mode: re-queue each candidate to 'pending' (idempotent, still namespace +
        // page + state guarded) so the bridge-fallback backlog can repair it now.
        let reset = 0
        for (const id of candidateIds) {
            const res = await c.env.DB.prepare(
                `UPDATE post_history
                 SET comment_status='pending', comment_error=NULL, comment_fb_id=NULL, comment_due_at=datetime('now')
                 WHERE id = ?
                   AND page_id = ?
                   AND bot_id = ?
                   AND status='success'
                   AND comment_status='failed'`
            ).bind(id, pageId, namespaceId).run().catch(() => null)
            reset += Number(res?.meta?.changes || 0)
        }

        // Process the backlog once so the operator sees immediate repair results.
        await processPendingCommentBacklog(c.env).catch((error) => {
            console.error(`[RETRY-FAILED-COMMENTS] backlog run failed page=${pageId}:`, error)
        })

        // After-state for exactly the re-queued ids.
        const placeholders = candidateIds.map(() => '?').join(',')
        const after = await c.env.DB.prepare(
            `SELECT comment_status, COUNT(*) AS n
             FROM post_history
             WHERE id IN (${placeholders}) AND page_id = ? AND bot_id = ?
             GROUP BY comment_status`
        ).bind(...candidateIds, pageId, namespaceId).all() as {
            results?: Array<{ comment_status?: string; n?: number }>
        }
        const afterCounts: Record<string, number> = {}
        for (const row of after.results || []) {
            afterCounts[String(row.comment_status || 'unknown')] = Number(row.n || 0)
        }

        return c.json({
            page_id: pageId,
            namespace_id: namespaceId,
            dry_run: false,
            limit,
            before: { eligible_failed_comments: candidateIds.length },
            reset_count: reset,
            after: afterCounts,
            candidate_ids: candidateIds,
            candidates,
        })
    } catch (e) {
        return c.json({ error: 'retry_failed_comments_failed', details: String(e instanceof Error ? e.message : e).substring(0, 200) }, 500)
    }
})

app.get('/api/pages/:id/stats', async (c) => {
    const pageId = c.req.param('id')
    try {
        const today = await c.env.DB.prepare(
            "SELECT COUNT(*) as count FROM post_history WHERE page_id = ? AND date(posted_at) = date('now')"
        ).bind(pageId).first()

        const week = await c.env.DB.prepare(
            "SELECT COUNT(*) as count FROM post_history WHERE page_id = ? AND posted_at >= datetime('now', '-7 days')"
        ).bind(pageId).first()

        const total = await c.env.DB.prepare(
            'SELECT COUNT(*) as count FROM post_history WHERE page_id = ?'
        ).bind(pageId).first()

        return c.json({
            today: today?.count || 0,
            week: week?.count || 0,
            total: total?.count || 0
        })
    } catch (e) {
        return c.json({ error: 'Failed to fetch stats' }, 500)
    }
})

// ==================== SCHEDULER ====================

app.get('/api/scheduler/process', async (c) => {
    try {
        const { results: pendingPosts } = await c.env.DB.prepare(
            "SELECT pq.*, p.access_token, p.name as page_name FROM post_queue pq JOIN pages p ON pq.page_id = p.id WHERE pq.status = 'pending' AND pq.scheduled_at <= datetime('now') AND p.is_active = 1 LIMIT 10"
        ).all()

        const processed: number[] = []

        for (const post of pendingPosts || []) {
            await c.env.DB.prepare(
                "UPDATE post_queue SET status = 'processing' WHERE id = ?"
            ).bind(post.id).run()

            // TODO: Implement actual Facebook Reels posting
            await c.env.DB.prepare(
                'INSERT INTO post_history (video_id, page_id, fb_post_id, status, trigger_source) VALUES (?, ?, ?, ?, ?)'
            ).bind(post.video_id, post.page_id, 'simulated_' + Date.now(), 'success', 'queue').run()

            await c.env.DB.prepare(
                'DELETE FROM post_queue WHERE id = ?'
            ).bind(post.id).run()

            await c.env.DB.prepare(
                "UPDATE pages SET last_post_at = datetime('now') WHERE id = ?"
            ).bind(post.page_id).run()

            processed.push(post.id as number)
        }

        return c.json({ processed: processed.length, ids: processed })
    } catch (e) {
        return c.json({ error: 'Scheduler failed', details: String(e) }, 500)
    }
})

// Generate short caption from long script using Gemini
async function generateCaption(script: string, apiKeys: string[], model: string): Promise<string> {
    const normalizedKeys = normalizeGeminiApiKeyList(apiKeys)
    for (const apiKey of normalizedKeys) {
        try {
            const resp = await fetch(
                `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${apiKey}`,
                {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        contents: [{ parts: [{ text: `สร้างแคปชั่น Facebook Reels จาก script นี้ 1 บรรทัด มี emoji ดึงดูด จบประโยคสมบูรณ์ ห้ามตัดคำกลางคัน ตอบแค่แคปชั่น:\n\n${script}` }] }],
                        generationConfig: { temperature: 0.9, maxOutputTokens: 1024 },
                    }),
                }
            )
            if (!resp.ok) continue
            const result = await resp.json() as { candidates?: Array<{ content?: { parts?: Array<{ text?: string }> } }> }
            const caption = result?.candidates?.[0]?.content?.parts?.[0]?.text?.trim()
            if (caption) return caption
        } catch {
            // try next key
        }
    }
    return script.slice(0, 100)
}

function extractJsonObjectFromText(rawText: string): Record<string, unknown> | null {
    const text = String(rawText || '').trim()
    if (!text) return null
    const direct = (() => {
        try {
            return JSON.parse(text) as Record<string, unknown>
        } catch {
            return null
        }
    })()
    if (direct && typeof direct === 'object' && !Array.isArray(direct)) return direct

    const match = text.match(/\{[\s\S]*\}/)
    if (!match) return null
    try {
        const parsed = JSON.parse(match[0]) as Record<string, unknown>
        return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : null
    } catch {
        return null
    }
}

function normalizeAiCoverTextPosition(rawValue: unknown): number {
    const allowed = [20, 35, 50, 65, 80]
    const parsed = Number(rawValue)
    if (!Number.isFinite(parsed)) return 65
    let best = allowed[0] || 65
    let bestDistance = Math.abs(best - parsed)
    for (const candidate of allowed) {
        const distance = Math.abs(candidate - parsed)
        if (distance < bestDistance) {
            best = candidate
            bestDistance = distance
        }
    }
    return best
}

async function writeInboxAutoCoverMeta(params: {
    bucket: R2Bucket
    videoId: string
    mutate: (meta: Record<string, unknown>) => void
}): Promise<void> {
    const videoId = String(params.videoId || '').trim()
    if (!videoId) return
    const metaObj = await params.bucket.get(`videos/${videoId}.json`).catch(() => null)
    if (!metaObj) return
    let meta: Record<string, unknown> = {}
    try {
        meta = await metaObj.json() as Record<string, unknown>
    } catch {
        meta = {}
    }
    params.mutate(meta)
    meta.updatedAt = new Date().toISOString()
    await params.bucket.put(`videos/${videoId}.json`, JSON.stringify(meta, null, 2), {
        httpMetadata: { contentType: 'application/json' },
    }).catch(() => { })
}

async function generateAiCoverTextForOption(params: {
    env: Env
    bucket: R2Bucket
    namespaceId: string
    videoId: string
    option: LineCoverOption
}): Promise<{ coverText: string; textYPercent: number } | null> {
    const namespaceId = String(params.namespaceId || '').trim()
    const videoId = String(params.videoId || '').trim()
    const option = params.option
    if (!namespaceId || !videoId || !option?.seed) return null

    const apiKeys = await resolveNamespaceGeminiApiKeys(params.env.DB, namespaceId).catch(() => [])
    const normalizedKeys = normalizeGeminiApiKeyList(apiKeys)
    if (normalizedKeys.length === 0) return null

    const originalVideoUrl = buildWorkerGalleryAssetUrl(
        String(params.env.WORKER_URL || '').trim(),
        namespaceId,
        videoId,
        'original',
    )
    if (!originalVideoUrl) return null

    let frameBase64 = ''
    try {
        const jpgBytes = await generateThumbnailViaContainer(
            params.env,
            originalVideoUrl,
            option.seed,
            undefined,
            'jpg',
            360,
            640,
        )
        frameBase64 = jpgBytes.toString('base64')
    } catch {
        frameBase64 = ''
    }
    if (!frameBase64) return null

    const prompt = [
        'นี่คือหน้าปกวิดีโอรีวิวสินค้า ช่วยคิดข้อความบนปกภาษาไทย 1 บรรทัดให้น่าสนใจ น่าดึงดูด และชวนกดดู',
        'กติกา:',
        '- ความยาวไม่เกิน 18 ตัวอักษร',
        '- ห้ามอีโมจิ',
        '- ห้ามหลายบรรทัด',
        '- ห้ามใส่เครื่องหมายคำพูด',
        '- ห้ามตอบเป็น JSON',
        '- ห้ามขึ้นต้นด้วยคำว่า headline',
        '- ห้ามเป็นคำกริยาเดี่ยวหรือคำไม่สมบูรณ์ เช่น ทำไข, ทำครัว, ใช้งาน',
        '- ห้ามตอบเป็นคำทั่วไปล้วน ๆ เช่น พัดลม, แก้ว, กล่อง, เครื่องครัว',
        '- ต้องมี hook หรือจุดเด่นอย่างน้อย 1 อย่าง เช่น น่ารัก, พกง่าย, เย็นไว, มินิ, ไฟฟ้า, ตีฟูไว',
        '- ถ้าเห็นดีไซน์เด่น ให้หยิบดีไซน์มาทำ hook ก่อนประโยชน์',
        '- ถ้าเห็นประโยชน์การใช้งานชัด ให้หยิบประโยชน์มาทำ hook',
        '- โทนคำต้องเป็นภาษาหน้าปกคลิปรีวิวสินค้า ไม่ใช่แค่บอกชื่อของ',
        '- ตัวอย่างคำตอบที่ดี: พัดลมคิตตี้มินิ, น่ารักแต่ลมแรง, เครื่องตีไข่ไฟฟ้า, ตีไข่ฟูไว, ปั่นง่ายในแก้วเดียว',
        'ตอบเป็นข้อความบรรทัดเดียวเท่านั้น',
    ].filter(Boolean).join('\n')

    for (const apiKey of normalizedKeys) {
        try {
            const model = String(params.env.GEMINI_MODEL || '').trim() || 'gemini-3-flash-preview'
            const resp = await fetch(
                `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${encodeURIComponent(apiKey)}`,
                {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        contents: [{
                            parts: [
                                { text: prompt },
                                {
                                    inlineData: {
                                        mimeType: 'image/jpeg',
                                        data: frameBase64,
                                    },
                                },
                            ],
                        }],
                        generationConfig: { temperature: 0.4, maxOutputTokens: 64 },
                    }),
                },
            )
            if (!resp.ok) continue
            const result = await resp.json().catch(() => ({})) as {
                candidates?: Array<{ content?: { parts?: Array<{ text?: string }> } }>
            }
            const responseText = (result.candidates || [])
                .flatMap((candidate) => candidate.content?.parts || [])
                .map((part) => String(part.text || '').trim())
                .filter(Boolean)
                .join('\n')
            const fallbackHeadline = extractAiHeadlineFromText(responseText)
            const coverText = normalizeLineCoverText(fallbackHeadline)
            if (isInvalidAiCoverHeadline(coverText)) continue
            return {
                coverText,
                textYPercent: 65,
            }
        } catch {
            // try next key
        }
    }

    return null
}

async function generateAiInboxCoverSuggestion(params: {
    env: Env
    bucket: R2Bucket
    namespaceId: string
    videoId: string
}): Promise<{ option: LineCoverOption; coverText: string; textYPercent: number } | null> {
    const namespaceId = String(params.namespaceId || '').trim()
    const videoId = String(params.videoId || '').trim()
    if (!namespaceId || !videoId) return null

    const apiKeys = await resolveNamespaceGeminiApiKeys(params.env.DB, namespaceId).catch(() => [])
    const normalizedKeys = normalizeGeminiApiKeyList(apiKeys)
    if (normalizedKeys.length === 0) return null

    const originalVideoUrl = buildWorkerGalleryAssetUrl(
        String(params.env.WORKER_URL || '').trim(),
        namespaceId,
        videoId,
        'original',
    )
    if (!originalVideoUrl) return null

    const metaObj = await params.bucket.get(`videos/${videoId}.json`).catch(() => null)
    const meta = metaObj
        ? await metaObj.json().catch(() => ({} as Record<string, unknown>)) as Record<string, unknown>
        : {}
    const contextTitle = metaToString(meta, 'title')
    const contextCategory = metaToString(meta, 'category')
    const contextManualCaption = normalizeManualCaption(meta.manualCaption || meta.caption || '')
    const contextScript = metaToString(meta, 'script').slice(0, 800)
    const contextSourceLabel = metaToString(meta, 'sourceLabel') || metaToString(meta, 'source_label')

    const optionCount = 6
    const options = buildLineCoverOptions(videoId, optionCount, 'gemini-auto-cover-v1')
    const frameResults = await Promise.all(options.map(async (option) => {
        try {
            const jpgBytes = await generateThumbnailViaContainer(
                params.env,
                originalVideoUrl,
                option.seed,
                undefined,
                'jpg',
                540,
                960,
            )
            return {
                option,
                mimeType: 'image/jpeg',
                data: jpgBytes.toString('base64'),
            }
        } catch {
            return null
        }
    }))
    const usableFrames = frameResults.filter((item): item is { option: LineCoverOption; mimeType: string; data: string } => !!item && !!item.data)
    if (usableFrames.length === 0) return null

    const prompt = [
        'คุณคือผู้ช่วยทำปกวิดีโอสั้นแนวไวรัลขายของภาษาไทย สไตล์ TikTok/Reel',
        'จากภาพตัวเลือกหลายภาพ ให้ทำ 3 อย่าง:',
        '1) เลือกเฟรมที่น่าสนใจที่สุด (เห็นสินค้าหรือจุดเด่นชัด มุมดี แสงโอเค) สำหรับทำปก',
        '2) เขียนข้อความบนปก 2 บรรทัดภาษาไทย (ใช้ \\n คั่น)',
        '3) เลือกตำแหน่งที่ข้อความจะแสดงบนปก ไม่บังสินค้า/ใบหน้า',
        'กติกาข้อความ:',
        '- บรรทัด 1 = hook สั้น สะดุด ดึงความสนใจ 3-6 คำ',
        '- บรรทัด 2 = ประโยชน์/เรียกให้ดู 3-6 คำ',
        '- ห้ามใส่อีโมจิ เครื่องหมายคำพูด แฮชแทก ลิงก์',
        '- ห้ามเขียนว่า "ดูเลย" "คลิกเลย" หรือคำเชิญทั่วไป ให้สื่อเฉพาะของชิ้นนี้',
        '- ถ้าเห็นสินค้าชัด ให้ระบุประโยชน์/ปัญหาที่แก้',
        'กติกาตำแหน่ง (textYPercent):',
        '- เลือกจาก 20 (บนสุด), 35, 50 (กลาง), 65, 80 (ล่างสุด)',
        '- ถ้าสินค้า/คนอยู่กลาง → 20 หรือ 80',
        '- ถ้าสินค้าอยู่ล่าง → 20',
        '- ถ้าสินค้าอยู่บน → 65 หรือ 80',
        'ตอบเป็น JSON เท่านั้น ห้ามมีข้อความอื่นหน้า/หลัง',
        'รูปแบบตอบกลับ:',
        '{"optionId":"1","headline":"ของเล่นใหม่\\nเอาไว้แกล้งแมว","textYPercent":20}',
        '',
        `ข้อมูลเสริม: title=${contextTitle || '-'} | category=${contextCategory || '-'} | source=${contextSourceLabel || '-'}`,
        contextManualCaption ? `caption=${contextManualCaption}` : '',
        contextScript ? `script=${contextScript}` : '',
    ].filter(Boolean).join('\n')

    for (const apiKey of normalizedKeys) {
        try {
            const parts: Array<Record<string, unknown>> = [{ text: prompt }]
            for (const frame of usableFrames) {
                parts.push({ text: `ตัวเลือก ${frame.option.optionId}` })
                parts.push({
                    inlineData: {
                        mimeType: frame.mimeType,
                        data: frame.data,
                    },
                })
            }
            const model = String(params.env.GEMINI_MODEL || '').trim() || 'gemini-2.5-flash'
            const resp = await fetch(
                `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${encodeURIComponent(apiKey)}`,
                {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        contents: [{ parts }],
                        generationConfig: { temperature: 0.4, maxOutputTokens: 256 },
                    }),
                },
            )
            if (!resp.ok) continue
            const result = await resp.json().catch(() => ({})) as {
                candidates?: Array<{ content?: { parts?: Array<{ text?: string }> } }>
            }
            const responseText = (result.candidates || [])
                .flatMap((candidate) => candidate.content?.parts || [])
                .map((part) => String(part.text || '').trim())
                .filter(Boolean)
                .join('\n')
            const parsed = extractJsonObjectFromText(responseText)
            const optionId = String(parsed?.optionId || '').trim()
            const selected = usableFrames.find((frame) => String(frame.option.optionId || '').trim() === optionId)
            const coverText = normalizeLineCoverText(String(parsed?.headline || ''))
            if (!selected || !coverText) continue
            return {
                option: selected.option,
                coverText,
                textYPercent: normalizeAiCoverTextPosition(parsed?.textYPercent),
            }
        } catch {
            // try next key
        }
    }

    return null
}

async function ensureInboxAutoCoverSuggestion(params: {
    env: Env
    bucket: R2Bucket
    namespaceId: string
    videoId: string
}): Promise<boolean> {
    const namespaceId = String(params.namespaceId || '').trim()
    const videoId = String(params.videoId || '').trim()
    if (!namespaceId || !videoId) return false

    const existingCover = await params.bucket.head(`_inbox_cover/${videoId}.webp`).catch(() => null)
    if (existingCover) return true

    const metaObj = await params.bucket.get(`videos/${videoId}.json`).catch(() => null)
    let meta: Record<string, unknown> = {}
    if (metaObj) {
        try {
            meta = await metaObj.json() as Record<string, unknown>
        } catch {
            meta = {}
        }
    }
    const attemptedAtMs = Date.parse(String(meta.autoCoverAttemptedAt || '').trim())
    if (Number.isFinite(attemptedAtMs) && Date.now() - attemptedAtMs < 30 * 60 * 1000) {
        return false
    }

    await writeInboxAutoCoverMeta({
        bucket: params.bucket,
        videoId,
        mutate(nextMeta) {
            nextMeta.autoCoverAttemptedAt = new Date().toISOString()
        },
    })

    const suggestion = await generateAiInboxCoverSuggestion(params)
    if (!suggestion) {
        await writeInboxAutoCoverMeta({
            bucket: params.bucket,
            videoId,
            mutate(nextMeta) {
                nextMeta.autoCoverError = 'gemini_cover_suggestion_failed'
            },
        })
        return false
    }

    const coverTemplateSettings = await getNamespaceCoverTemplateSettings(params.env.DB, namespaceId).catch(() => ({
        template_id: DEFAULT_COVER_TEMPLATE_ID,
        text_style: createDefaultCoverTextStyle(DEFAULT_COVER_TEMPLATE_ID),
    }))
    const coverTemplateId = normalizeCoverTemplateId(String(coverTemplateSettings?.template_id || ''))
    const coverTextStyle = normalizeCoverTextStyle(coverTemplateSettings?.text_style, coverTemplateId)

    await materializeSelectedLineCoverOptionAssets({
        env: params.env,
        bucket: params.bucket,
        namespaceId,
        videoId,
        option: suggestion.option,
        coverText: suggestion.coverText,
        coverTextYPercent: suggestion.textYPercent,
        coverTemplateId,
        coverTextStyle,
    })

    await writeInboxAutoCoverMeta({
        bucket: params.bucket,
        videoId,
        mutate(nextMeta) {
            nextMeta.autoCoverText = suggestion.coverText
            nextMeta.autoCoverSeed = String(suggestion.option.seed || '').trim()
            nextMeta.autoCoverTextYPercent = suggestion.textYPercent
            nextMeta.autoCoverGeneratedAt = new Date().toISOString()
            delete nextMeta.autoCoverError
        },
    })
    return true
}

// Generate title for ONE video at a time (call repeatedly to process all)
app.post('/api/generate-title/:id', async (c) => {
    const env = c.env
    const id = c.req.param('id')
    const apiKeys = await resolveNamespaceGeminiApiKeys(env.DB, String(c.get('botId') || ''))
    if (apiKeys.length === 0) return c.json({ error: 'Gemini API key กลางของระบบยังไม่ได้ตั้งค่า' }, 400)
    const model = env.GEMINI_MODEL || 'gemini-3-flash-preview'

    const obj = await env.BUCKET.get(`videos/${id}.json`)
    if (!obj) return c.json({ error: 'not found' }, 404)
    const meta = await obj.json() as Record<string, unknown>
    if (!meta.script) return c.json({ error: 'no script' }, 400)

    const script = (meta.script as string).slice(0, 300)
    let title = ''
    for (const apiKey of apiKeys) {
        const resp = await fetch(
            `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${apiKey}`,
            {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    contents: [{
                        parts: [{
                            text: `จาก script รีวิวสินค้านี้ ช่วยเขียนแคปชั่น Facebook Reels ให้หน่อย

ตัวอย่างแคปชั่นที่ดี:
- "🔧 ประแจ 8 in 1 ตัวเดียวครบ ไม่ต้องหาหลายอัน!"
- "⚡ เลื่อยไร้สายจิ๋วแต่แจ๋ว ตัดกิ่งไม้ได้ลื่นปรื๊ด!"
- "🛠️ คีมเชื่อมรุ่นใหม่ หนีบแน่น เชื่อมนานมือไม่พอง!"

กฎสำคัญ:
- ตอบแค่ 1 บรรทัดเท่านั้น ห้ามขึ้นบรรทัดใหม่
- ใส่ emoji นำหน้า 1 ตัว
- ต้องจบประโยคสมบูรณ์ ห้ามตัดคำกลางคัน
- ตอบแค่แคปชั่น ไม่ต้องใส่เครื่องหมายคำพูด

script: ${script}`
                        }]
                    }],
                    generationConfig: { temperature: 0.9, maxOutputTokens: 1024 },
                }),
            }
        )
        if (!resp.ok) continue
        const result = await resp.json() as { candidates?: Array<{ content?: { parts?: Array<{ text?: string }> } }> }
        title = result?.candidates?.[0]?.content?.parts?.[0]?.text?.trim() || ''
        if (title) break
    }
    if (title.startsWith('"') && title.endsWith('"')) title = title.slice(1, -1)
    if (title.startsWith('\u201c') && title.endsWith('\u201d')) title = title.slice(1, -1)

    if (!title) return c.json({ error: 'no title generated' }, 500)

    meta.title = title
    await c.get('bucket').put(`videos/${id}.json`, JSON.stringify(meta, null, 2), {
        httpMetadata: { contentType: 'application/json' },
    })
    await updateGalleryCache(c.get('bucket'), id)
    await syncGalleryIndexEntry(c.env, String(c.get('botId') || ''), id).catch((error) => {
        console.log(`[GENERATE-TITLE] sync gallery index failed video=${id}: ${error instanceof Error ? error.message : String(error)}`)
    })

    return c.json({ id, title })
})

// Rebuild gallery cache
app.post('/api/rebuild-cache', async (c) => {
    const videos = await rebuildGalleryCache(c.get('bucket'))
    return c.json({ rebuilt: true, count: videos.length })
})

// List videos needing titles
app.get('/api/generate-titles/pending', async (c) => {
    const videoIds = await listAllVideoJsonIds(c.get('bucket'))
    const pending: Array<{ id: string; currentTitle: string }> = []
    for (const id of videoIds) {
        const obj = await c.get('bucket').get(`videos/${id}.json`)
        if (!obj) continue
        const meta = await obj.json() as Record<string, unknown>
        if (!meta.script) continue
        pending.push({ id, currentTitle: (meta.title as string) || '' })
    }
    return c.json({ total: pending.length, videos: pending })
})

// Force post for a specific page (bypass time check)
app.post('/api/pages/:id/force-post', async (c) => {
    const pageId = c.req.param('id')
    const env = c.env
    const botId = c.get('botId')
    let pageName = ''
    let pageAccessToken = ''
    let pageCommentToken: string | null = null
    let selectedVideoId = ''
    let fbVideoId = ''
    let selectedCaption = ''
    let attemptPostedAtIso = ''
    let normalizedShopeeLink = ''
    let normalizedLazadaLink = ''
    let selectedVideoNamespaceId = ''
    let commentTokenHint: string | null = null
    let skipComment = false
    let primaryPostingTokenCandidates: string[] = []
    let fallbackPostTokenCandidates: string[] = []
    let commentTokenCandidates: string[] = []
    let selectedSourceFingerprint = ''
    let postingTokenUsed = ''
    let hasCommentToken = false
    let initialCommentStatus = 'not_configured'
    let initialCommentError: string | null = null
    let forceHistoryId: number | null = null
    let pagePostingLockKey: string | null = null
    let videoPostingLockKey: string | null = null
    let pageOneCardEnabled = false
    let pageOneCardLinkMode: PageOneCardLinkMode = 'shopee'
    let pageOneCardCta: PageOneCardCta = 'SHOP_NOW'
    let pageCaptionLinkEnabled = false
    let avatarApplied = false
    let avatarVersion = ''

    try {
        // Check if skip comment
        const body = await c.req.json().catch(() => ({})) as {
            skipComment?: boolean
        }
        skipComment = body.skipComment === true
        // Get page info
        await ensurePagesOneCardColumns(env.DB)
        const page = await env.DB.prepare(
            'SELECT id, name, access_token, post_hours, onecard_enabled, onecard_link_mode, onecard_cta, ads_publish_enabled, caption_link_enabled, posting_token_source, comment_token_source, posting_profile_uid FROM pages WHERE id = ? AND bot_id = ?'
        ).bind(pageId, botId).first() as { id: string; name: string; access_token: string; post_hours: string; onecard_enabled?: number | null; onecard_link_mode?: string | null; onecard_cta?: string | null; caption_link_enabled?: number | null; posting_token_source?: string | null; comment_token_source?: string | null; posting_profile_uid?: string | null } | null

        if (!page) return c.json({ error: 'Page not found' }, 404)
        // Clear any posting attempt that died before flipping status so a stale
        // row can't permanently return page_already_posting for this page.
        await recoverStalePostingAttemptsForPage(env.DB, {
            namespaceId: botId,
            pageId: page.id,
            reason: 'stale_posting_timeout_no_fb_post_id_force_post',
        }).catch(() => 0)
        // Hot path guard: a Worker request can die after acquiring posting_locks but before
        // inserting/finishing post_history. Do not let that orphaned page lock block urgent
        // operator force-posts for the full TTL. Only clear the page lock when no fresh
        // status='posting' row exists for this namespace/page, so a real in-flight post is kept safe.
        await env.DB.prepare(
            `DELETE FROM posting_locks
             WHERE namespace_id = ?
               AND page_id = ?
               AND scope = 'page'
               AND NOT EXISTS (
                   SELECT 1
                   FROM post_history
                   WHERE bot_id = ?
                     AND page_id = ?
                     AND status = 'posting'
                     AND datetime(posted_at) >= datetime('now', '-5 minutes')
               )`
        ).bind(botId, page.id, botId, page.id).run().catch(() => { })
        pagePostingLockKey = await tryAcquirePostingLock(env.DB, {
            scope: 'page',
            namespaceId: botId,
            pageId: page.id,
        })
        if (!pagePostingLockKey) {
            return c.json({ error: 'page_already_posting' }, 409)
        }
        pageName = page.name
        pageAccessToken = String(page.access_token || '').trim()
        pageOneCardEnabled = Number(page.onecard_enabled || 0) === 1
        pageOneCardLinkMode = normalizePageOneCardLinkMode(page.onecard_link_mode)
        pageOneCardCta = normalizePageOneCardCta(page.onecard_cta)
        pageCaptionLinkEnabled = Number(page.caption_link_enabled || 0) === 1
        pageCommentToken = null
        const tokenCandidates = await ensurePageTokenCandidates({
            env,
            db: env.DB,
            namespaceId: botId,
            pageId: page.id,
            pageName: page.name,
            primaryToken: pageAccessToken,
            logPrefix: 'FORCE-POST',
        })
        commentTokenCandidates = tokenCandidates.commentTokens
        pageCommentToken = commentTokenCandidates[0] || null
        fallbackPostTokenCandidates = tokenCandidates.postTokens.length > 0
            ? tokenCandidates.postTokens
            : normalizePostTokenPool([pageAccessToken])
        primaryPostingTokenCandidates = buildPrimaryPostingTokenCandidates({
            primaryToken: pageAccessToken,
            postTokens: fallbackPostTokenCandidates,
            commentTokens: commentTokenCandidates,
        })
        if (primaryPostingTokenCandidates.length === 0) {
            throw new Error('access_token_missing')
        }

        const postingOrderSettings = await resolveEffectivePagePostingOrder(env.DB, botId, page.id)
        const postingOrder = postingOrderSettings.postingOrder
        const postingOrderSource = postingOrderSettings.source
        console.log(`[FORCE-POST] Page ${page.name}: posting_order=${postingOrder} source=${postingOrderSource}`)
        const fastClaim = await claimFastGalleryVideoForPosting({
            env,
            namespaceId: botId,
            pageId: page.id,
            postingOrder,
        })
        console.log(`[FORCE-POST] Page ${page.name}: fast_gallery source=${fastClaim.stats.source} candidates=${fastClaim.stats.candidateTotal} scanned=${fastClaim.stats.scanned} pages=${fastClaim.stats.pages} elapsed_ms=${fastClaim.stats.elapsedMs}`)
        if (!fastClaim.picked) return c.json({ error: 'No unposted gallery video left' }, 404)
        const pickedVideoEntry = fastClaim.picked
        const pickedVideo = pickedVideoEntry.video
        videoPostingLockKey = pickedVideoEntry.videoLockKey
        const unpostedId = String(pickedVideo.id || '').trim()
        console.log(`[FORCE-POST] Page ${page.name}: fast_gallery picked=${unpostedId} candidates=${fastClaim.stats.candidateTotal} scanned=${fastClaim.stats.scanned}`)
        selectedSourceFingerprint = normalizeNamespaceVideoSourceFingerprint(
            pickedVideo.sourceFingerprint || pickedVideo.source_fingerprint,
        )
        selectedVideoId = unpostedId
        selectedVideoNamespaceId = String(pickedVideo.sourceNamespaceId || pickedVideo.source_namespace_id || botId).trim() || botId
        const duplicateCheck = await ensurePageVideoNeverPosted({
            db: env.DB,
            namespaceId: botId,
            pageId: String(page.id || ''),
            videoId: unpostedId,
            sourceFingerprint: selectedSourceFingerprint,
        })
        if (duplicateCheck.ok === false) {
            await releasePostingLock(env.DB, videoPostingLockKey)
            videoPostingLockKey = null
            return c.json({
                error: 'video_already_posted',
                details: {
                    history_id: duplicateCheck.historyId,
                    posted_at: duplicateCheck.postedAt,
                },
            }, 409)
        }
        const sourceBucket = selectedVideoNamespaceId === botId
            ? c.get('bucket')
            : new BotBucket(env.BUCKET, selectedVideoNamespaceId) as unknown as R2Bucket
        const meta = await loadLatestVideoMetaForPosting(sourceBucket, unpostedId, pickedVideo)
        const rawShopeeLink = normalizeMetaShopeeLink(meta) || ''
        const publicUrl = metaToString(meta, 'publicUrl')
        const rawLazadaLink = normalizeMetaLazadaLink(meta) || metaToString(meta, 'lazadaLink')
        const rawLazadaMemberId = String(metaToString(meta, 'lazadaMemberId') || metaToString(meta, 'lazada_member_id') || '').trim()
        // Posting backend = explicit per-page token source selection. Electron Ads bridge
        // ('post-reels-token-ads') and the legacy ads_publish_enabled flag both route
        // through /api/dashboard/create-ad. CloakBrowser/session-cookie bridge
        // (CloakBrowser) routes the organic Reel through the CloakBrowser
        // bridge /post route (VIDEO_ONECARD_WORKER_URL) — never the stored token. Stored
        // token remains the default legacy path.
        // Power Editor / CloakBrowser is admin-owned only: a non-admin namespace can never
        // reach the session bridge, so we collapse its posting/comment source to stored_token
        // here (restrictCloakToAdminNamespace) BEFORE resolving the route. This keeps a
        // member/manual-token page (e.g. ข่าวสด) on publishReelWithCommentTokenPrimaryFallback
        // instead of publishReelViaSessionBridge.
        const namespaceIsAdminOwned = await isNamespaceShortlinkAdminManaged(env.DB, String(botId || '')).catch(() => false)
        const pagePostingTokenSource = restrictCloakToAdminNamespace(
            normalizePagePostingTokenSource((page as Record<string, unknown>).posting_token_source),
            namespaceIsAdminOwned,
        )
        // Per-page Accounts Bridge posting account UID — threaded into the stored-token Facebook Lite
        // refresh so it targets the right account (blank → unchanged auto-discovery).
        const configuredPostingProfileUid = sanitizePostingProfileUid((page as Record<string, unknown>).posting_profile_uid)
        const pageAdsPublishLegacyFlag = Number((page as Record<string, unknown>).ads_publish_enabled || 0) === 1
        // The legacy ads_publish_enabled flag promotes even a stored_token source to the
        // CloakBrowser OneCard/create-ad bridge route — also admin-owned only. Gate it on
        // namespace ownership so a non-admin page with a stale ads_publish_enabled=1 can never
        // be promoted onto the bridge it has no access to.
        const pagePostingRoute: PostingRoute = resolvePostingRoute({ source: pagePostingTokenSource, oneCardEnabled: pageOneCardEnabled, adsPublishLegacyFlag: pageAdsPublishLegacyFlag && namespaceIsAdminOwned })
        const pageAdsPublishEnabled = pagePostingRoute === 'cloak_onecard_bridge'
        const pageCloakPostSelected = pagePostingRoute === 'cloak_organic_reel'
        // Comment backend is chosen INDEPENDENTLY of the posting route. Missing/invalid
        // comment_token_source falls back to the effective posting source so existing pages
        // keep commenting exactly as before. 'cloak_browser' → CloakBrowser bridge
        // /page-comment; 'stored_token' → stored page comment token (deferred pending path).
        // Non-admin namespaces are likewise pinned to stored_token (admin-owned bridge only).
        const pageCommentTokenSource: PageCommentTokenSource = restrictCloakToAdminNamespace(
            normalizePageCommentTokenSource(
                (page as Record<string, unknown>).comment_token_source,
                defaultCommentSourceForRoute(pagePostingRoute),
            ),
            namespaceIsAdminOwned,
        )
        const commentViaCloakBridge = pageCommentTokenSource === 'cloak_browser'
        console.log(`[FORCE-POST] page=${String(page.id || '')} posting_token_source=${pagePostingTokenSource} route=${pagePostingRoute} source_hint=${postingSourceHint(pagePostingRoute)} comment_token_source=${pageCommentTokenSource} ads_publish_legacy_flag=${pageAdsPublishLegacyFlag} onecard=${pageOneCardEnabled} ads_publish=${pageAdsPublishEnabled} cloak=${pageCloakPostSelected}`)

        // Use title if available, otherwise generate caption from script
        const apiKeys = await resolveNamespaceGeminiApiKeys(env.DB, botId)
        const hasManualCaption = !!normalizeManualCaption(meta.manualCaption || meta.caption || '')
        const title = metaToString(meta, 'title')
        const script = metaToString(meta, 'script')
        if (!hasManualCaption && !title && script && apiKeys.length === 0) {
            return c.json({ error: 'Gemini API key กลางของระบบยังไม่ได้ตั้งค่า' }, 400)
        }
        const model = env.GEMINI_MODEL || 'gemini-3-flash-preview'
        const caption = await buildPostingCaptionFromMeta(meta, apiKeys, model)
        selectedCaption = caption

        const shortlinkResolution = await resolvePrePostingShortlinksForNamespace({
            env,
            namespaceId: botId,
            pageId: String(page.id || ''),
            pageName: page.name,
            shopeeLink: rawShopeeLink,
            lazadaLink: rawLazadaLink,
            lazadaMemberId: rawLazadaMemberId,
            pageOneCardEnabled,
            pageOneCardLinkMode,
            pageOneCardCta,
            pageAdsPublishEnabled,
            logPrefix: 'FORCE-POST',
        })
        normalizedShopeeLink = shortlinkResolution.shopeeLink
        normalizedLazadaLink = shortlinkResolution.lazadaLink
        const normalizedLazadaMemberId = shortlinkResolution.lazadaMemberId
        const normalizedShopeeUtmSource = shortlinkResolution.shopeeTrace.utmSource ?? null
        const normalizedShopeeStatus = shortlinkResolution.shopeeTrace.status ?? null
        const normalizedShopeeError = shortlinkResolution.shopeeTrace.error ?? null
        const normalizedShopeeUtmMatch = null

        await ensurePostHistoryTraceColumns(env.DB)
        commentTokenHint = deriveCommentTokenHint(pageCommentToken)
        // Cloak source must never derive its post hint/profile from a stored/manual token.
        const initialPostTokenHint = pageCloakPostSelected ? 'cloak_session_bridge' : deriveCommentTokenHint(primaryPostingTokenCandidates[0] || null)
        const initialPostProfile = await resolvePostHistoryProfileByToken(env, pageCloakPostSelected ? null : (primaryPostingTokenCandidates[0] || null))
        hasCommentToken = commentTokenCandidates.length > 0 && !!String(pageCommentToken || '').trim()
        const initialCommentState = getInitialCommentTraceState(!!normalizedShopeeLink)
        initialCommentStatus = initialCommentState.status
        initialCommentError = initialCommentState.error
        // Record attempt BEFORE posting (prevents duplicate on failure)
        const nowStr = new Date().toISOString()
        attemptPostedAtIso = nowStr
        const inserted = await env.DB.prepare(
            'INSERT INTO post_history (page_id, video_id, posted_at, status, trigger_source, bot_id, post_token_hint, post_profile_id, post_profile_name, comment_status, comment_token_hint, comment_error, comment_fb_id, shopee_link, lazada_link, lazada_member_id, shortlink_utm_source, shortlink_status, shortlink_error, shortlink_expected_utm_id, shortlink_utm_match, shortlink_conversion_status, shortlink_conversion_error, source_fingerprint) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)'
        ).bind(
            page.id,
            unpostedId,
            nowStr,
            'posting',
            'force_post',
            botId,
            initialPostTokenHint,
            initialPostProfile.profileId,
            initialPostProfile.profileName,
            initialCommentStatus,
            commentTokenHint,
            initialCommentError,
            null,
            normalizedShopeeLink || null,
            normalizedLazadaLink || null,
            normalizedLazadaMemberId || null,
            normalizedShopeeUtmSource,
            normalizedShopeeStatus,
            normalizedShopeeError,
            null,
            normalizedShopeeUtmMatch,
            shortlinkResolution.conversionStatus,
            shortlinkResolution.conversionError,
            selectedSourceFingerprint || null,
        ).run()
        forceHistoryId = Number(inserted.meta?.last_row_id || 0) || null

        if (shortlinkResolution.errorMessage) {
            if (forceHistoryId) {
                await env.DB.prepare(
                    "UPDATE post_history SET status = 'failed', error_message = ?, comment_status = 'not_attempted' WHERE id = ? AND status = 'posting'"
                ).bind(shortlinkResolution.errorMessage, forceHistoryId).run().catch(() => { })
            }
            return c.json({
                error: 'shortlink_failed',
                details: shortlinkResolution.errorMessage,
            }, 409)
        }

        const affiliateVerification = await verifyAffiliateLinksForPosting({
            env,
            namespaceId: botId,
            pageId: String(page.id || ''),
            shopeeLink: normalizedShopeeLink,
            lazadaLink: normalizedLazadaLink,
            requireLazadaLink: shortlinkResolution.lazadaRequired,
            logPrefix: 'FORCE-POST VERIFY',
        })
        if (forceHistoryId) {
            await updatePostHistoryAffiliateVerificationById(env.DB, forceHistoryId, affiliateVerification)
        }
        if (!affiliateVerification.ok) {
            if (forceHistoryId) {
                await env.DB.prepare(
                    "UPDATE post_history SET status = 'failed', error_message = ?, comment_status = 'not_attempted' WHERE id = ? AND status = 'posting'"
                ).bind(
                    affiliateVerification.error || 'affiliate_verification_failed',
                    forceHistoryId,
                ).run().catch(() => { })
            }
            return c.json({
                error: 'affiliate_verification_failed',
                details: affiliateVerification.error || 'Affiliate verification failed',
            }, 400)
        }

        // The stored/manual comment-token preflight only applies when the comment will be
        // sent with a STORED page token (comment_token_source='stored_token'). When comments
        // go through the CloakBrowser bridge they are page-authored with no stored token, so
        // skip the preflight regardless of posting route. (Comment success/failure is
        // recorded from the bridge/backlog result in the branches below.)
        if (!commentViaCloakBridge) {
            const affiliateCommentPreflight = validateAffiliateCommentPreflight({
                shopeeLink: normalizedShopeeLink,
                hasCommentToken,
                skipComment,
            })
            if (!affiliateCommentPreflight.ok) {
                const errorCode = affiliateCommentPreflight.error || 'affiliate_comment_not_configured'
                if (forceHistoryId) {
                    await env.DB.prepare(
                        "UPDATE post_history SET status = 'failed', error_message = ?, comment_status = 'not_attempted', comment_error = ? WHERE id = ? AND status = 'posting'"
                    ).bind(errorCode, errorCode, forceHistoryId).run().catch(() => { })
                }
                return c.json({
                    error: errorCode,
                    details: 'Affiliate comment token is required before posting',
                }, 409)
            }
        }

        await env.DB.prepare('UPDATE pages SET last_post_at = ? WHERE id = ?').bind(nowStr, page.id).run()

        // Handle legacy publicUrl without namespace path
        const realVideoUrl = resolvePostingVideoDownloadUrl(env, selectedVideoNamespaceId, unpostedId, publicUrl)
        let postingVideoUrl = realVideoUrl
        let avatarApplied = false
        let avatarVersion = ''

        // Page-specific avatar must be applied before every Facebook posting route,
        // including OneCard/Ads post-first. Those bridge routes accept only video_url,
        // so compose first and publish the composed R2 URL instead of the raw source.
        if (pageAdsPublishEnabled || pageCloakPostSelected || pageOneCardEnabled) {
            const prepared = await prepareAvatarComposedPostingVideo({
                env,
                db: env.DB,
                bucket: c.get('bucket'),
                namespaceId: botId,
                pageId: String(page.id || ''),
                videoId: unpostedId,
                baseVideoUrl: realVideoUrl,
                logPrefix: 'FORCE-POST AVATAR',
            })
            postingVideoUrl = prepared.videoUrl
            avatarApplied = prepared.avatarApplied
            avatarVersion = prepared.avatarVersion
        }

        // caption_link_enabled: prepend the managed Shopee shortlink as the first caption
        // line of the FB post. Applies to EVERY posting route (organic Reel, OneCard publish,
        // and the CloakBrowser session bridge) — not just the plain organic path. The create-ad
        // / Ads route prepends its own (post-specific) managed link inside /api/dashboard/create-ad
        // instead, so the raw caption is forwarded there unchanged. Comment text, the CTA button
        // link, shortlink reminting and token routing are all unaffected.
        const publishDescription = resolvePublishCaption({
            caption,
            captionLinkEnabled: pageCaptionLinkEnabled,
            shopeeLink: normalizedShopeeLink,
        })

        // AUTO-ADS MODE (per-page toggle, admin-only).
        // Mirrors the cron branch: skip normal Reel post entirely, route through
        // /api/dashboard/create-ad (upload → creative → adset → ad → publish-to-page → comment).
        if (pageAdsPublishEnabled) {
            const namespaceIsAdminManaged = await isNamespaceShortlinkAdminManaged(env.DB, botId).catch(() => false)
            if (!namespaceIsAdminManaged) {
                throw new Error('ads_publish_admin_only_runtime_check_failed')
            }

            // POST-FIRST (opt-in): publish the page post → mint final link → promote the ad
            // with that link in the CTA → comment the same link. Makes the live ad CTA equal
            // the comment link (sub2=post id, sub3=page id). Default OFF (env gate).
            if (oneCardPostFirstEnabled(env)) {
                const pf = await runOneCardPostFirstAds({
                    env,
                    pageId: String(page.id || ''),
                    namespaceId: botId,
                    caption,
                    videoUrl: postingVideoUrl,
                    sourceVideoId: unpostedId,
                    rawShopeeLink,
                    managedShopeeLink: normalizedShopeeLink,
                    historyId: forceHistoryId,
                    skipComment,
                    commentSource: pageCommentTokenSource,
                    hasCommentToken,
                    storedCommentTokenHint: deriveCommentTokenHint(pageCommentToken),
                    logPrefix: 'FORCE-POST',
                })
                if (!pf.ok && !pf.storyId) {
                    if (forceHistoryId) {
                        await env.DB.prepare(
                            "UPDATE post_history SET status='failed', error_message=?, comment_status='not_attempted' WHERE id=? AND status='posting'"
                        ).bind(`ads_post_first_failed: ${pf.step || ''}:${pf.error || ''}`.substring(0, 240), forceHistoryId).run().catch(() => { })
                    }
                    throw new Error(String(pf.error || 'ads_post_first_failed'))
                }
                fbVideoId = String(pf.adId || pf.storyId || unpostedId)
                postingTokenUsed = 'ads_publish'
                const pfCommentStatus = pf.ok ? pf.commentStatus : (pf.commentStatus || 'not_configured')
                if (forceHistoryId) {
                    await env.DB.prepare(
                        "UPDATE post_history SET status=?, fb_post_id=?, fb_reel_url=?, post_token_hint='ads_publish', comment_status=?, comment_fb_id=?, comment_error=?, comment_token_hint=?, comment_delay_seconds=?, comment_due_at=?, shopee_link=?, error_message=? WHERE id=? AND status='posting'"
                    ).bind(
                        pf.ok ? 'success' : 'failed',
                        pf.confirmedPostId || pf.storyId,
                        pf.fbReelUrl,
                        pfCommentStatus,
                        pf.commentId,
                        pf.commentError,
                        pf.commentTokenHint,
                        pf.commentDelaySeconds,
                        pf.commentDueAt,
                        pf.ctaShortlink || normalizedShopeeLink || null,
                        pf.ok ? null : `ads_post_first_partial: ${pf.step || ''}:${pf.error || ''}`.substring(0, 240),
                        forceHistoryId,
                    ).run().catch(() => { })
                }
                if (pf.ok && pfCommentStatus === 'pending') {
                    runPendingCommentBacklogSoon(env, forceHistoryId, 'FORCE-POST POST-FIRST IMMEDIATE-COMMENT', c.executionCtx)
                }
                await markNamespaceVideoPosted(env.DB, botId, unpostedId, new Date().toISOString())
                await recordPagePostedVideoGuard(env.DB, {
                    namespaceId: botId, pageId: page.id, videoId: unpostedId,
                    sourceFingerprint: selectedSourceFingerprint, historyId: forceHistoryId, postedAt: attemptPostedAtIso,
                }).catch(() => { })
                await clearVideoShopeeLink(c.get('bucket'), unpostedId)
                console.log(`[FORCE-POST] Page ${page.name}: POST-FIRST ADS ${pf.ok ? 'OK' : 'PARTIAL'} — story=${pf.storyId} ad_id=${pf.adId} comment=${pfCommentStatus} promoted_ad_cta_final=${pf.promotedAdCtaFinal} visible_cta_update=${pf.visibleCtaUpdateStatus}${pf.visibleCtaUpdateError ? `(${pf.visibleCtaUpdateError})` : ''} visible_page_cta_final=${pf.visiblePageCtaFinal} cta_sub2=${pf.ctaSub2} cta_sub3=${pf.ctaSub3}`)
                return c.json({
                    success: pf.ok,
                    page: page.name,
                    video_id: unpostedId,
                    fb_video_id: fbVideoId,
                    fb_post_id: pf.confirmedPostId || pf.storyId,
                    fb_reel_url: pf.fbReelUrl,
                    ads_publish: true,
                    post_first: true,
                    promote_ad_id: pf.adId || null,
                    cta_shortlink: pf.ctaShortlink || null,
                    // Reflects the PROMOTED AD CTA (where the final link lives); the organic page
                    // post CTA is intentionally not modified, so this is not a "visible CTA" status.
                    cta_update_status: pf.promotedAdCtaFinal ? 'promoted_ad_final_link' : (pf.ok ? 'promoted_ad_cta_unconfirmed' : `failed:${pf.step || ''}`),
                    cta_sub2: pf.ctaSub2,
                    cta_sub3: pf.ctaSub3,
                    // CTA parity is reported PER OBJECT and never overclaimed:
                    //  - promoted_ad_cta_comment_parity: the paid ad creative CTA == the final comment link.
                    //  - visible_page_cta_comment_parity: true ONLY after Phase B confirms the final
                    //    direct Shopee CTA link. Never report a Worker redirect as visible CTA.
                    // cta_comment_parity is retained for back-compat and means the PROMOTED AD only.
                    cta_comment_parity: pf.promotedAdCtaFinal,
                    promoted_ad_cta_comment_parity: pf.promotedAdCtaFinal,
                    promoted_ad_cta_link: pf.promotedAdCtaFinal ? (pf.ctaShortlink || null) : null,
                    visible_page_cta_comment_parity: pf.visiblePageCtaCommentParity,
                    visible_page_cta_final: pf.visiblePageCtaFinal,
                    visible_page_cta_link: pf.visiblePageCtaFinal ? (pf.visiblePageCtaLink || pf.ctaShortlink || null) : null,
                    // Outcome of the visible Reel CTA update (bridge /update-cta) after the final
                    // sub2/sub3 link was minted. Best-effort; does not gate run success.
                    visible_cta_update_status: pf.visibleCtaUpdateStatus,
                    visible_cta_update_error: pf.visibleCtaUpdateError,
                    comment_status: pfCommentStatus,
                    comment_posted: pfCommentStatus === 'success',
                    history_id: forceHistoryId,
                    log_id: forceHistoryId,
                    post_history_id: forceHistoryId,
                }, pf.ok ? 200 : 502)
            }

            const workerUrl = String(env.WORKER_URL || 'https://api.pubilo.com').trim().replace(/\/+$/, '')
            const adsResp = await fetchWithTimeout(`${workerUrl}/api/dashboard/create-ad`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    page_id: String(page.id || ''),
                    // unpostedId is an INTERNAL gallery/state id, not a Facebook video id.
                    // Send the downloadable URL so the CloakBrowser bridge uploads the file instead of
                    // doing a Graph GET on the internal id (which 500s "Object … does not
                    // exist"). source_video_id keeps ads naming/history linked to the
                    // internal system id.
                    video_url: postingVideoUrl,
                    source_video_id: unpostedId,
                    caption,
                    // CTA button → original Shopee product URL (falls back to the managed
                    // link if no raw URL is available). Comment shortlink → the already
                    // managed/shortened link so create-ad does NOT re-shorten it.
                    shopee_url: rawShopeeLink || normalizedShopeeLink,
                    comment_shortlink: normalizedShopeeLink,
                    // Defer the first comment to this branch: after story_id exists we
                    // re-mint the comment shortlink with sub2=post id / sub3=page id and
                    // post the single final comment via /page-comment below. Without this
                    // create-ad would comment with the pre-posting link (sub2/sub3 blank).
                    skip_comment: true,
                }),
            }, 300000, 'force_ads_publish')
            const adsData = await adsResp.json().catch(() => ({})) as {
                ok?: boolean
                error?: string
                story_id?: string
                ad_id?: string
                adset_id?: string
                commentPosted?: boolean
                commentId?: string
            }
            if (!adsResp.ok || !adsData?.ok) {
                throw new Error(String(adsData?.error || `ads_publish_http_${adsResp.status}`))
            }
            const storyId = String(adsData.story_id || '')
            const confirmedPostId = storyId.includes('_') ? storyId.split('_').slice(1).join('_') : storyId
            const fbReelUrl = storyId ? `https://www.facebook.com/${storyId.replace('_', '/posts/')}` : ''
            fbVideoId = String(adsData.ad_id || storyId || unpostedId)
            postingTokenUsed = 'ads_publish'

            // OneCard/Ads must comment as the PAGE too — parity with organic Reels.
            // create-ad ran with skip_comment, so it never commented (commentPosted is
            // false). Re-mint the comment shortlink now that story_id exists so the live
            // comment link carries sub2=post id tail / sub3=page id (sub1/campaign and
            // sub4/sub5 defaults preserved), then post the single affiliate comment as the
            // Page via the CloakBrowser bridge /page-comment route (the bridge resolves the
            // page token internally, fails closed, never the user token). A failed comment
            // never fails the post. NOTE: the ad CTA button is still built pre-story_id and
            // does NOT carry sub2/sub3 — documented limitation (no safe post-story_id
            // creative update wired into the bridge flow yet).
            let adsCommentStatus = adsData.commentPosted ? 'success' : 'not_configured'
            let adsCommentId: string | null = adsData.commentId || null
            let adsCommentError: string | null = null
            let adsCommentShopeeLink = normalizedShopeeLink
            let adsCommentRemint: OneCardCommentShortlinkRemint | null = null
            // Comment token-free hint + deferred schedule (only used by the stored path).
            let adsCommentTokenHint: string | null = commentViaCloakBridge ? 'cloak_session_bridge' : deriveCommentTokenHint(pageCommentToken)
            let adsCommentDelaySeconds: number | null = null
            let adsCommentDueAt: string | null = null
            if (!adsData.commentPosted && normalizedShopeeLink && !skipComment && storyId) {
                adsCommentRemint = await remintOneCardCommentShortlink({
                    env,
                    namespaceId: botId,
                    pageId: String(page.id || ''),
                    storyId,
                    fbVideoId,
                    managedShopeeLink: normalizedShopeeLink,
                    historyId: forceHistoryId,
                    logPrefix: 'FORCE-POST ADS COMMENT-SHORTLINK',
                })
                adsCommentShopeeLink = adsCommentRemint.commentShopeeLink
            }
            if (!adsData.commentPosted && adsCommentShopeeLink && !skipComment && storyId && commentViaCloakBridge) {
                // comment_token_source='cloak_browser' (default for an ADS page): comment as
                // the Page via the bridge. Fails closed; never falls back to a stored token.
                const adsCommentText = (await buildAffiliateCommentMessage(env.DB, botId, adsCommentShopeeLink).catch(() => '')) || adsCommentShopeeLink
                const bridged = await sendPageCommentViaCloakBridge({
                    env,
                    pageId: String(page.id || ''),
                    storyId,
                    message: adsCommentText,
                    logPrefix: 'FORCE-POST ADS',
                })
                adsCommentStatus = bridged.status
                adsCommentId = bridged.id
                adsCommentError = bridged.error
                adsCommentTokenHint = 'cloak_session_bridge'
            } else if (!adsData.commentPosted && adsCommentShopeeLink && !skipComment && storyId && !commentViaCloakBridge) {
                // comment_token_source='stored_token': defer to the pending backlog processor
                // which comments with the stored page token against the Page story id. Requires
                // a stored comment token (else fail per existing stored semantics).
                if (hasCommentToken) {
                    adsCommentStatus = 'pending'
                    adsCommentId = null
                    adsCommentError = null
                    adsCommentDelaySeconds = getRandomCommentDelaySeconds()
                    adsCommentDueAt = new Date(Date.now() + (adsCommentDelaySeconds * 1000)).toISOString()
                } else {
                    adsCommentStatus = 'failed'
                    adsCommentError = 'access_token_missing'
                }
                adsCommentTokenHint = deriveCommentTokenHint(pageCommentToken)
            }

            if (forceHistoryId) {
                await env.DB.prepare(
                    "UPDATE post_history SET status='success', fb_post_id=?, fb_reel_url=?, post_token_hint='ads_publish', comment_status=?, comment_fb_id=?, comment_error=?, comment_token_hint=?, comment_delay_seconds=?, comment_due_at=?, shopee_link=?, error_message=NULL WHERE id=? AND status='posting'"
                ).bind(
                    confirmedPostId || storyId,
                    fbReelUrl,
                    adsCommentStatus,
                    adsCommentId,
                    adsCommentError,
                    adsCommentTokenHint,
                    adsCommentDelaySeconds,
                    adsCommentDueAt,
                    adsCommentShopeeLink || normalizedShopeeLink || null,
                    forceHistoryId,
                ).run().catch(() => { })
            }
            if (adsCommentStatus === 'pending') {
                runPendingCommentBacklogSoon(env, forceHistoryId, 'FORCE-POST ADS IMMEDIATE-COMMENT', c.executionCtx)
            }
            await markNamespaceVideoPosted(env.DB, botId, unpostedId, new Date().toISOString())
            await recordPagePostedVideoGuard(env.DB, {
                namespaceId: botId,
                pageId: page.id,
                videoId: unpostedId,
                sourceFingerprint: selectedSourceFingerprint,
                historyId: forceHistoryId,
                postedAt: attemptPostedAtIso,
            }).catch(() => { })
            await clearVideoShopeeLink(c.get('bucket'), unpostedId)
            console.log(`[FORCE-POST] Page ${page.name}: ADS PUBLISH OK — story=${storyId} ad_id=${adsData.ad_id || ''} comment=${adsCommentStatus} remint=${adsCommentRemint?.reminted ? `sub2=${adsCommentRemint.sub2} sub3=${adsCommentRemint.sub3}` : (adsCommentRemint?.error || 'n/a')}`)
            return c.json({
                success: true,
                page: page.name,
                video_id: unpostedId,
                fb_video_id: fbVideoId,
                fb_post_id: confirmedPostId || storyId,
                fb_reel_url: fbReelUrl,
                ads_publish: true,
                comment_status: adsCommentStatus,
                comment_posted: adsCommentStatus === 'success',
                // Final comment link + the sub ids it carries, for Dev verification.
                // The ad CTA button still uses the pre-story_id link (no sub2/sub3) —
                // documented limitation.
                comment_shortlink: adsCommentShopeeLink || null,
                comment_sub2: adsCommentRemint?.sub2 || '',
                comment_sub3: adsCommentRemint?.sub3 || '',
                comment_shortlink_reminted: !!adsCommentRemint?.reminted,
                ...(adsCommentRemint?.error ? { comment_shortlink_remint_error: adsCommentRemint.error } : {}),
                history_id: forceHistoryId,
                log_id: forceHistoryId,
                post_history_id: forceHistoryId,
            })
        }

        // CLOAKBROWSER / SESSION-COOKIE BRIDGE ORGANIC POST (source = 'post-reels-token-cloak').
        // Routes the organic Reel through the CloakBrowser session-cookie bridge /post
        // route (NOT the stored token, NOT facebook-token-cloak). Fails closed
        // (throw → history 'failed') rather than ever using the stored/manual token.
        if (pageCloakPostSelected) {
            const cloakOneCardWebsiteUrl = pageOneCardEnabled
                ? pickOneCardWebsiteUrl({ linkMode: pageOneCardLinkMode, shopeeLink: normalizedShopeeLink, lazadaLink: normalizedLazadaLink })
                : ''
            // Publish FIRST with no inline comment. The bridge would otherwise comment the
            // pre-publish shortlink (blank sub2/sub3 → utm_content=...FBSPCAD----). When
            // comment_token_source='cloak_browser' we re-mint the shortlink with the post id
            // below, then comment via the bridge; stored-token defers to the backlog.
            const cloakResult = await publishReelViaSessionBridge({
                env,
                pageId: String(page.id || ''),
                videoUrl: postingVideoUrl,
                message: publishDescription,
                websiteUrl: cloakOneCardWebsiteUrl,
                cta: pageOneCardCta,
                commentText: '',
                logPrefix: 'FORCE-POST CLOAK-BRIDGE',
            })
            fbVideoId = cloakResult.id
            postingTokenUsed = cloakResult.postingToken
            const confirmedCanonicalPostId = String(cloakResult.postId || '').trim()
            const confirmedPostId = confirmedCanonicalPostId || fbVideoId
            const cloakCommentEligible = !!normalizedShopeeLink && !skipComment
            // Comment parity: success → success+comment_fb_id; attempted-but-failed →
            // failed+sanitized error; nothing to post → not_configured. Never claim success.
            let cloakCommentStatus: string
            let cloakCommentFbId: string | null
            let cloakCommentError: string | null
            let cloakCommentTokenHint: string | null
            let cloakCommentDelaySeconds: number | null = null
            let cloakCommentDueAt: string | null = null
            let cloakCommentShopeeLink = normalizedShopeeLink
            if (commentViaCloakBridge) {
                if (!cloakCommentEligible) {
                    cloakCommentStatus = 'not_configured'
                    cloakCommentFbId = null
                    cloakCommentError = null
                    cloakCommentTokenHint = 'cloak_session_bridge'
                } else {
                    // Re-shorten with the post id FIRST so the commented link carries
                    // sub2=post id / sub3=page id, then comment as the Page via the bridge
                    // (fails closed). Mirrors the stored→cloak branch.
                    let commentShopeeLink = normalizedShopeeLink
                    try {
                        const commentSubIds = buildPostingCommentShortlinkSubIds({
                            canonicalPostId: confirmedCanonicalPostId,
                            fbVideoId,
                            pageId: page.id,
                            historyId: forceHistoryId,
                            logPrefix: 'FORCE-POST CLOAK COMMENT-SHORTLINK',
                        })
                        const reshortened = await resolvePostingShopeeLinkForNamespace({
                            env,
                            namespaceId: botId,
                            pageId: page.id,
                            shopeeLink: normalizedShopeeLink,
                            logPrefix: 'FORCE-POST CLOAK COMMENT-SHORTLINK',
                            ...commentSubIds,
                        })
                        if (reshortened) commentShopeeLink = reshortened
                    } catch (reshortenErr) {
                        console.log(`[FORCE-POST CLOAK COMMENT-SHORTLINK] re-shorten with post id failed; falling back to preflight link: ${reshortenErr instanceof Error ? reshortenErr.message : String(reshortenErr)}`)
                    }
                    cloakCommentShopeeLink = commentShopeeLink
                    const cloakOverrideText = (await buildAffiliateCommentMessage(env.DB, botId, commentShopeeLink).catch(() => '')) || commentShopeeLink
                    const bridged = await sendPageCommentViaCloakBridge({
                        env,
                        pageId: String(page.id || ''),
                        storyId: buildPageStoryId(String(page.id || ''), confirmedPostId),
                        message: cloakOverrideText,
                        logPrefix: 'FORCE-POST CLOAK-COMMENT',
                    })
                    cloakCommentStatus = bridged.status
                    cloakCommentFbId = bridged.id
                    cloakCommentError = bridged.error
                    cloakCommentTokenHint = 'cloak_session_bridge'
                }
            } else {
                // comment_token_source='stored_token': defer to the pending backlog, which
                // comments with the stored page token against the Page story id (and re-mints
                // the shortlink itself). Requires a stored comment token (else fail).
                const cloakCommentText = cloakCommentEligible
                    ? await buildAffiliateCommentMessage(env.DB, botId, normalizedShopeeLink).catch(() => '')
                    : ''
                cloakCommentFbId = null
                if (!cloakCommentText) {
                    cloakCommentStatus = skipComment ? 'skipped' : 'not_configured'
                    cloakCommentError = null
                } else if (hasCommentToken) {
                    cloakCommentStatus = 'pending'
                    cloakCommentError = null
                    cloakCommentDelaySeconds = getRandomCommentDelaySeconds()
                    cloakCommentDueAt = new Date(Date.now() + (cloakCommentDelaySeconds * 1000)).toISOString()
                } else {
                    cloakCommentStatus = 'failed'
                    cloakCommentError = 'access_token_missing'
                }
                cloakCommentTokenHint = deriveCommentTokenHint(pageCommentToken)
            }
            const fbReelUrl = String(cloakResult.permalinkUrl || '').trim()
            if (forceHistoryId) {
                await env.DB.prepare(
                    "UPDATE post_history SET status='success', fb_post_id=?, fb_reel_url=?, post_token_hint='cloak_session_bridge', comment_status=?, comment_fb_id=?, comment_error=?, comment_token_hint=?, comment_delay_seconds=?, comment_due_at=?, shopee_link=?, error_message=NULL WHERE id=? AND status='posting'"
                ).bind(confirmedPostId, fbReelUrl, cloakCommentStatus, cloakCommentFbId, cloakCommentError, cloakCommentTokenHint, cloakCommentDelaySeconds, cloakCommentDueAt, cloakCommentShopeeLink || normalizedShopeeLink || null, forceHistoryId).run().catch(() => { })
            }
            if (cloakCommentStatus === 'pending') {
                runPendingCommentBacklogSoon(env, forceHistoryId, 'FORCE-POST CLOAK IMMEDIATE-COMMENT', c.executionCtx)
            }
            await markNamespaceVideoPosted(env.DB, botId, unpostedId, new Date().toISOString())
            await recordPagePostedVideoGuard(env.DB, {
                namespaceId: botId,
                pageId: page.id,
                videoId: unpostedId,
                sourceFingerprint: selectedSourceFingerprint,
                historyId: forceHistoryId,
                postedAt: attemptPostedAtIso,
            }).catch(() => { })
            await clearVideoShopeeLink(c.get('bucket'), unpostedId)
            console.log(`[FORCE-POST] Page ${page.name}: CLOAK-BRIDGE POST OK — post=${confirmedPostId} comment=${cloakCommentStatus}`)
            return c.json({
                success: true,
                page: page.name,
                video_id: unpostedId,
                fb_video_id: fbVideoId,
                fb_post_id: confirmedPostId,
                fb_reel_url: fbReelUrl,
                posting_source: 'cloak',
                comment_status: cloakCommentStatus,
                comment_posted: cloakCommentStatus === 'success',
                history_id: forceHistoryId,
                log_id: forceHistoryId,
                post_history_id: forceHistoryId,
            })
        }

        // Prefer the stored page-scoped token pool, then fall back to legacy tokens if needed.
        let videoBuffer: ArrayBuffer | null = null
        if (!pageOneCardEnabled) {
            const avatarSettings = await getPageAvatarSettings(env.DB, page.id).catch(() => null)
            if (avatarSettings?.enabled && !TEMP_DISABLE_AVATAR_COMPOSE_FOR_POSTING) {
                if (!avatarSettings.videoKey) throw new Error('avatar_compose_failed: avatar_video_key_missing')
                const avatarHead = await c.get('bucket').head(avatarSettings.videoKey).catch(() => null)
                if (!avatarHead) throw new Error('avatar_compose_failed: avatar_video_missing')
                const avatarVideoUrl = buildAvatarObjectUrl(env, botId, avatarSettings.videoKey)
                if (!avatarVideoUrl) throw new Error('avatar_compose_failed: avatar_url_missing')
                try {
                    const parsedAvatarUrl = new URL(avatarVideoUrl)
                    if (!['http:', 'https:'].includes(parsedAvatarUrl.protocol)) {
                        throw new Error('invalid_protocol')
                    }
                } catch {
                    throw new Error('avatar_compose_failed: avatar_url_invalid')
                }
                videoBuffer = await composeAvatarVideoForPosting({
                    env,
                    baseVideoUrl: realVideoUrl,
                    avatarVideoUrl,
                    chromakeySimilarity: avatarSettings.chromakeySimilarity,
                    chromakeyBlend: avatarSettings.chromakeyBlend,
                })
                avatarApplied = true
                avatarVersion = avatarSettings.version || avatarSettings.updatedAt || 'v1'
            }
        }
        if (!videoBuffer) {
            const videoResp = await fetchWithTimeout(realVideoUrl, {}, 60000, 'force_download_video')
            if (!videoResp.ok) throw new Error(`Fetch video failed with status ${videoResp.status}`)
            videoBuffer = await videoResp.arrayBuffer()
        }
        if (videoBuffer.byteLength < 100000) throw new Error(`Video too small (${videoBuffer.byteLength} bytes). Download failed.`)
        const postingThumbnail = pageOneCardEnabled
            ? null
            : await loadPostingThumbnailAsset({
                env,
                namespaceId: selectedVideoNamespaceId,
                videoId: unpostedId,
            }).catch(() => null)

        // Normal post path always uses the page's post tokens from settings (organic Reel).
        // The legacy `ads_publish_enabled` flag is intentionally NOT consulted here — ads
        // creation is now a fully separate flow via the dashboard ad queue.
        postingTokenUsed = pageOneCardEnabled ? 'onecard' : String(primaryPostingTokenCandidates[0] || '').trim()
        const oneCardWebsiteUrl = pickOneCardWebsiteUrl({
            linkMode: pageOneCardLinkMode,
            shopeeLink: normalizedShopeeLink,
            lazadaLink: normalizedLazadaLink,
        })
        // Real organic Page reel via the STORED Facebook Lite (EAAD6V) page token — Worker-direct
        // Graph (/video_reels → /videos), with the Facebook Lite Token Bridge fallback baked into
        // publishReelWithCommentTokenPrimaryFallbackAndLiteRefresh. NEVER the ad account / Power
        // Editor. Reused both as the default stored_token path and as the OneCard failure fallback.
        const publishStoredFacebookLiteReel = () => publishReelWithCommentTokenPrimaryFallbackAndLiteRefresh({
            env,
            db: env.DB,
            namespaceId: botId,
            pageId: page.id,
            pageName: page.name,
            videoUrl: postingVideoUrl,
            commentTokens: commentTokenCandidates,
            postTokens: fallbackPostTokenCandidates,
            videoBuffer,
            thumbnailBuffer: postingThumbnail?.buffer || null,
            thumbnailContentType: postingThumbnail?.contentType || '',
            description: publishDescription,
            logPrefix: 'FORCE-POST',
            preferVideoReelsFirst: true,
            configuredPostingProfileUid,
            reloadTokens: async () => {
                const refreshed = await ensurePageTokenCandidates({
                    env,
                    db: env.DB,
                    namespaceId: botId,
                    pageId: page.id,
                    pageName: page.name,
                    primaryToken: pageAccessToken,
                    logPrefix: 'FORCE-POST RELOAD',
                })
                const post = refreshed.postTokens.length > 0
                    ? refreshed.postTokens
                    : normalizePostTokenPool([pageAccessToken])
                return { commentTokens: refreshed.commentTokens, postTokens: post }
            },
        })

        // A Facebook Lite (EAAD6V) stored token cannot use the ad account, so NEVER route it through
        // OneCard/advideos/Power Editor — publish the organic Page reel directly (the bridge-free
        // /{page}/videos lane). Non-Lite OneCard pages keep the OneCard path.
        const useOneCardForThisPost = pageOneCardEnabled && !isFacebookLitePageToken(primaryPostingTokenCandidates[0] || '')
        let reelResult: { id: string; postId: string; permalinkUrl: string; postingToken: string }
        if (useOneCardForThisPost) {
            try {
                reelResult = await publishVideoViaOneCard({
                    env,
                    pageId: page.id,
                    videoUrl: postingVideoUrl,
                    message: publishDescription,
                    websiteUrl: oneCardWebsiteUrl,
                    cta: pageOneCardCta,
                    logPrefix: 'FORCE-POST ONECARD',
                })
            } catch (oneCardErr) {
                // OneCard runs through the cloak-fb-bridge ad-account/create-ad path (Power Editor).
                // A stored Facebook Lite (EAAD6V) page token cannot drive the ad account, so an
                // ad-permission failure (e.g. "(#10) Permission Denied") must NOT burn the row: when
                // a stored page token exists, fall back to a REAL organic Page reel via that EAAD6V
                // token. Pages with no stored token (pure admin/CloakBrowser OneCard) still fail closed.
                const oneCardMsg = parseFacebookErrorLike(oneCardErr)?.message || (oneCardErr instanceof Error ? oneCardErr.message : String(oneCardErr))
                const haveStoredPostToken = normalizePostTokenPool(fallbackPostTokenCandidates).length > 0
                if (!shouldFallbackToOrganicAfterOneCardFailure({ haveStoredPostToken, error: oneCardMsg })) throw oneCardErr
                console.warn(`[FORCE-POST] OneCard publish failed (${oneCardMsg}); falling back to stored Facebook Lite organic Page reel (EAAD6V), not Power Editor`)
                reelResult = await publishStoredFacebookLiteReel()
            }
        } else {
            reelResult = await publishStoredFacebookLiteReel()
        }
        postingTokenUsed = reelResult.postingToken
        const postingProfile = await resolvePostHistoryProfileByToken(env, postingTokenUsed)

        fbVideoId = reelResult.id
        const confirmedCanonicalPostId = String(reelResult.postId || '').trim()
        const confirmedPostId = confirmedCanonicalPostId || fbVideoId
        const facebookLiteBridgeAccount = postingTokenUsed === 'facebook_lite_bridge'
            ? (DEFAULT_FACEBOOK_LITE_BRIDGE_ACCOUNT)
            : ''
        let commentShopeeLink = normalizedShopeeLink
        // Re-shorten with the post id when we intend to comment — either via the stored
        // token (needs hasCommentToken), via the CloakBrowser bridge override, or via the
        // Facebook Lite Token Bridge fallback that created the post.
        const willComment = !!commentShopeeLink && !skipComment && (hasCommentToken || commentViaCloakBridge || !!facebookLiteBridgeAccount)
        if (willComment) {
            try {
                const commentSubIds = buildPostingCommentShortlinkSubIds({
                    canonicalPostId: confirmedCanonicalPostId,
                    fbVideoId,
                    pageId,
                    historyId: forceHistoryId,
                    logPrefix: 'FORCE-POST COMMENT-SHORTLINK',
                })
                const reshortened = await resolvePostingShopeeLinkForNamespace({
                    env,
                    namespaceId: botId,
                    pageId,
                    shopeeLink: normalizedShopeeLink,
                    logPrefix: 'FORCE-POST COMMENT-SHORTLINK',
                    ...commentSubIds,
                })
                if (reshortened) commentShopeeLink = reshortened
            } catch (reshortenErr) {
                console.log(`[FORCE-POST COMMENT-SHORTLINK] re-shorten with post id failed; falling back to preflight link: ${reshortenErr instanceof Error ? reshortenErr.message : String(reshortenErr)}`)
            }
        }
        const fbReelUrl = String(reelResult.permalinkUrl || '').trim() || `https://www.facebook.com/reel/${fbVideoId}`
        // Only the stored-token path defers via comment_due_at; the bridge override comments
        // immediately below, so it schedules no delay.
        const scheduledCommentDelaySeconds = commentShopeeLink && !skipComment && hasCommentToken && !commentViaCloakBridge && !facebookLiteBridgeAccount
            ? getRandomCommentDelaySeconds()
            : null
        const scheduledCommentDueAt = scheduledCommentDelaySeconds
            ? new Date(Date.now() + (scheduledCommentDelaySeconds * 1000)).toISOString()
            : null
        const postReadyCommentState = getPostReadyCommentTraceState(!!commentShopeeLink, hasCommentToken, skipComment)
        if (forceHistoryId) {
            await env.DB.prepare(
                "UPDATE post_history SET fb_post_id = ?, fb_reel_url = ?, post_token_hint = ?, post_profile_id = ?, post_profile_name = ?, comment_status = ?, comment_token_hint = ?, comment_error = ?, comment_delay_seconds = ?, comment_due_at = ?, shopee_link = ? WHERE id = ? AND status = 'posting'"
            ).bind(
                confirmedPostId,
                fbReelUrl,
                deriveCommentTokenHint(postingTokenUsed),
                postingProfile.profileId,
                postingProfile.profileName,
                postReadyCommentState.status,
                deriveCommentTokenHint(pageCommentToken),
                postReadyCommentState.error,
                scheduledCommentDelaySeconds,
                scheduledCommentDueAt,
                commentShopeeLink || normalizedShopeeLink || null,
                forceHistoryId,
            ).run()
        }

        let commentStatus = postReadyCommentState.status
        let commentError: string | null = postReadyCommentState.error
        let commentFbId: string | null = null
        let commentTokenUsed = String(pageCommentToken || '').trim()
        let commentProfileId: string | null = null
        let commentProfileName: string | null = null
        let commentTokenHintFinal = deriveCommentTokenHint(commentTokenUsed || pageCommentToken)

        if (skipComment) {
            commentStatus = 'skipped'
            commentError = null
            console.log(`[FORCE-POST] Skipped comment for ${fbVideoId}`)
        } else if (commentShopeeLink && commentViaCloakBridge) {
            // comment_token_source='cloak_browser' on a stored-token POST: comment as the
            // Page via the bridge immediately (fails closed, never a stored-token fallback).
            const cloakOverrideText = (await buildAffiliateCommentMessage(env.DB, botId, commentShopeeLink).catch(() => '')) || commentShopeeLink
            const bridged = await sendPageCommentViaCloakBridge({
                env,
                pageId,
                storyId: buildPageStoryId(pageId, confirmedCanonicalPostId || confirmedPostId),
                message: cloakOverrideText,
                logPrefix: 'FORCE-POST STORED→CLOAK-COMMENT',
            })
            commentStatus = bridged.status
            commentFbId = bridged.id
            commentError = bridged.error
            commentTokenHintFinal = 'cloak_session_bridge'
        } else if (commentShopeeLink && facebookLiteBridgeAccount) {
            // Facebook Lite bridge POST path: raw exported token is not Graph-usable server-side,
            // so comment through the same Token Bridge account that created the post.
            const facebookLiteCommentText = (await buildAffiliateCommentMessage(env.DB, botId, commentShopeeLink).catch(() => '')) || commentShopeeLink
            const bridged = await sendPageCommentViaCloakBridge({
                env,
                pageId,
                storyId: buildPageStoryId(pageId, confirmedCanonicalPostId || confirmedPostId),
                message: facebookLiteCommentText,
                account: facebookLiteBridgeAccount,
                logPrefix: 'FORCE-POST FB-LITE-COMMENT',
            })
            commentStatus = bridged.status
            commentFbId = bridged.id
            commentError = bridged.error
            commentTokenHintFinal = 'facebook_lite_bridge'
        } else if (commentShopeeLink && hasCommentToken) {
            // Stored-token comment deferred to the pending backlog processor.
            commentStatus = 'pending'
            commentError = null
        }

        // Update to success
        if (forceHistoryId) {
            await env.DB.prepare(
                "UPDATE post_history SET fb_post_id = ?, fb_reel_url = ?, status = 'success', error_message = NULL, post_token_hint = ?, post_profile_id = ?, post_profile_name = ?, comment_status = ?, comment_token_hint = ?, comment_profile_id = ?, comment_profile_name = ?, comment_error = ?, comment_fb_id = ?, shopee_link = ? WHERE id = ? AND status = 'posting'"
            ).bind(
                confirmedPostId,
                fbReelUrl,
                deriveCommentTokenHint(postingTokenUsed),
                postingProfile.profileId,
                postingProfile.profileName,
                commentStatus,
                commentTokenHintFinal,
                commentProfileId,
                commentProfileName,
                commentError,
                commentFbId,
                commentShopeeLink || normalizedShopeeLink || null,
                forceHistoryId,
            ).run()
        }
        if (commentStatus === 'pending') {
            runPendingCommentBacklogSoon(env, forceHistoryId, 'FORCE-POST IMMEDIATE-COMMENT', c.executionCtx)
        }
        await markNamespaceVideoPosted(env.DB, botId, unpostedId, new Date().toISOString())
        await recordPagePostedVideoGuard(env.DB, {
            namespaceId: botId,
            pageId: page.id,
            videoId: unpostedId,
            sourceFingerprint: selectedSourceFingerprint,
            historyId: forceHistoryId,
            postedAt: attemptPostedAtIso,
        }).catch(() => { })

        await clearVideoShopeeLink(c.get('bucket'), unpostedId)
        return c.json({
            success: true,
            page: page.name,
            video_id: unpostedId,
            fb_video_id: fbVideoId,
            fb_post_id: confirmedPostId,
            fb_reel_url: fbReelUrl,
            history_id: forceHistoryId,
            log_id: forceHistoryId,
            post_history_id: forceHistoryId,
            ...(avatarApplied ? { avatar_applied: true, avatar_version: avatarVersion } : {}),
        })
    } catch (e) {
        const errorMsg = e instanceof Error ? e.message : String(e)
        const isAvatarComposeError = errorMsg.includes('avatar_compose_failed')

        // Recovery path: if Facebook already accepted the reel and it becomes published
        // after a transient upload/finish error, mark history as success instead of failed.
        if (!isAvatarComposeError && pageAccessToken && pageId && selectedVideoId) {
            try {
                let recoveredPostId = ''
                let recoveredReelUrl = ''

                if (fbVideoId) {
                    const recovered = await pollPublishedReelAfterProcessing({
                        accessToken: pageAccessToken,
                        fbVideoId,
                        logPrefix: 'FORCE-POST-RECOVER',
                    })
                    if (recovered.published && recovered.post_id) {
                        recoveredPostId = String(recovered.post_id || '').trim() || fbVideoId
                        recoveredReelUrl = String(recovered.permalink_url || '').trim() || `https://www.facebook.com/reel/${recoveredPostId}`
                    }
                }

                if (!recoveredPostId && selectedCaption) {
                    const feedRecovered = await recoverPublishedReelFromRecentFeed({
                        accessToken: pageAccessToken,
                        pageId,
                        expectedCaption: selectedCaption,
                        notBeforeIso: attemptPostedAtIso,
                        logPrefix: 'FORCE-POST-RECOVER-FEED',
                    })
                    if (feedRecovered.published && feedRecovered.post_id) {
                        recoveredPostId = String(feedRecovered.post_id || '').trim()
                        recoveredReelUrl = String(feedRecovered.permalink_url || '').trim() || `https://www.facebook.com/reel/${recoveredPostId}`
                    }
                }

                if (recoveredPostId) {
                    if (!recoveredReelUrl) {
                        recoveredReelUrl = `https://www.facebook.com/reel/${recoveredPostId}`
                    }

                    const recoveredCommentState = getPostReadyCommentTraceState(!!normalizedShopeeLink, hasCommentToken, skipComment)
                    let commentStatus = recoveredCommentState.status
                    let commentError: string | null = recoveredCommentState.error
                    let commentFbId: string | null = null
                    let commentTokenUsed = String(pageCommentToken || '').trim()
                    let commentProfileId: string | null = null
                    let commentProfileName: string | null = null
                    const commentTargetId = fbVideoId || extractReelIdFromPermalink(normalizeFacebookPermalink(recoveredReelUrl)) || recoveredPostId
                    let recoveryCommentShopeeLink = normalizedShopeeLink

                    if (recoveryCommentShopeeLink && !skipComment && hasCommentToken) {
                        try {
                            const commentSubIds = buildPostingCommentShortlinkSubIds({
                                canonicalPostId: recoveredPostId,
                                fbVideoId,
                                reelId: extractIdFromCommentTargetInput(recoveredReelUrl),
                                pageId,
                                historyId: forceHistoryId,
                                logPrefix: 'FORCE-POST-RECOVER COMMENT-SHORTLINK',
                            })
                            const reshortened = await resolvePostingShopeeLinkForNamespace({
                                env,
                                namespaceId: botId,
                                pageId,
                                shopeeLink: recoveryCommentShopeeLink,
                                logPrefix: 'FORCE-POST-RECOVER COMMENT-SHORTLINK',
                                ...commentSubIds,
                            })
                            if (reshortened) recoveryCommentShopeeLink = reshortened
                        } catch (reshortenErr) {
                            console.log(`[FORCE-POST-RECOVER COMMENT-SHORTLINK] re-shorten with post id failed; falling back to preflight link: ${reshortenErr instanceof Error ? reshortenErr.message : String(reshortenErr)}`)
                        }
                        const commentWaitMs = getRandomCommentDelayMs()
                        console.log(`[FORCE-POST-RECOVER] Waiting ${Math.ceil(commentWaitMs / 1000)}s before recovery comment...`)
                        await waitMs(commentWaitMs)
                        const commentResult = await postShopeeCommentWithFallback({
                            env,
                            namespaceId: botId,
                            fbVideoId: commentTargetId,
                            shopeeLink: recoveryCommentShopeeLink,
                            lazadaLink: normalizedLazadaLink,
                            commentTokens: commentTokenCandidates,
                            pageId,
                            logPrefix: 'FORCE-POST-RECOVER',
                        })
                        if (!commentResult.ok) {
                            commentStatus = 'failed'
                            commentError = commentResult.error || 'comment_failed'
                            commentTokenUsed = String(commentResult.commentToken || commentTokenUsed || '').trim()
                            const commentProfile = await resolvePostHistoryProfileByToken(env, commentTokenUsed)
                            commentProfileId = commentProfile.profileId
                            commentProfileName = commentProfile.profileName
                            await notifyCommentTokenIssue(
                                env,
                                botId,
                                pageId,
                                pageName || pageId,
                                commentError,
                            ).catch((notifyErr) => {
                                console.error(`[FORCE-POST-RECOVER] notifyCommentTokenIssue failed: ${notifyErr instanceof Error ? notifyErr.message : String(notifyErr)}`)
                            })
                        } else {
                            commentStatus = 'success'
                            commentFbId = commentResult.id || null
                            commentTokenUsed = String(commentResult.commentToken || commentTokenUsed || '').trim()
                            const commentProfile = await resolvePostHistoryProfileByToken(env, commentTokenUsed)
                            commentProfileId = commentProfile.profileId
                            commentProfileName = commentProfile.profileName
                        }
                    } else if (skipComment) {
                        commentStatus = 'skipped'
                        commentError = null
                    }

                    const recoveredPostProfile = await resolvePostHistoryProfileByToken(env, postingTokenUsed)
                    if (forceHistoryId) {
                        await env.DB.prepare(
                            "UPDATE post_history SET fb_post_id = ?, fb_reel_url = ?, status = 'success', error_message = NULL, post_token_hint = ?, post_profile_id = ?, post_profile_name = ?, comment_status = ?, comment_token_hint = ?, comment_profile_id = ?, comment_profile_name = ?, comment_error = ?, comment_fb_id = ? WHERE id = ? AND status IN ('posting','failed')"
                        ).bind(
                            recoveredPostId,
                            recoveredReelUrl,
                            deriveCommentTokenHint(postingTokenUsed),
                            recoveredPostProfile.profileId,
                            recoveredPostProfile.profileName,
                            commentStatus,
                            deriveCommentTokenHint(commentTokenUsed || pageCommentToken),
                            commentProfileId,
                            commentProfileName,
                            commentError,
                            commentFbId,
                            forceHistoryId,
                        ).run()
                    }
                    await markNamespaceVideoPosted(env.DB, botId, selectedVideoId, new Date().toISOString())
                    await recordPagePostedVideoGuard(env.DB, {
                        namespaceId: botId,
                        pageId,
                        videoId: selectedVideoId,
                        sourceFingerprint: selectedSourceFingerprint,
                        historyId: forceHistoryId,
                        postedAt: attemptPostedAtIso,
                    }).catch(() => { })

                    await clearVideoShopeeLink(new BotBucket(env.BUCKET, selectedVideoNamespaceId || botId) as unknown as R2Bucket, selectedVideoId)
                    return c.json({
                        success: true,
                        recovered: true,
                        page: pageName || pageId,
                        video_id: selectedVideoId,
                        fb_video_id: fbVideoId,
                        fb_post_id: recoveredPostId,
                        fb_reel_url: recoveredReelUrl,
                        history_id: forceHistoryId,
                        log_id: forceHistoryId,
                        post_history_id: forceHistoryId,
                    })
                }
            } catch (recoverErr) {
                console.error(`[FORCE-POST-RECOVER] failed: ${recoverErr instanceof Error ? recoverErr.message : String(recoverErr)}`)
            }
        }

        try {
            if (forceHistoryId) {
                await env.DB.prepare(
                    "UPDATE post_history SET status = 'failed', error_message = ?, comment_status = 'not_attempted' WHERE id = ? AND status = 'posting'"
                ).bind(errorMsg, forceHistoryId).run()
            } else if (pageId && selectedVideoId && attemptPostedAtIso) {
                await env.DB.prepare(
                    "UPDATE post_history SET status = 'failed', error_message = ?, comment_status = 'not_attempted' WHERE page_id = ? AND video_id = ? AND bot_id = ? AND posted_at = ? AND status = 'posting'"
                ).bind(errorMsg, pageId, selectedVideoId, botId, attemptPostedAtIso).run()
            } else if (pageId && botId && attemptPostedAtIso) {
                await env.DB.prepare(
                    "UPDATE post_history SET status = 'failed', error_message = ?, comment_status = 'not_attempted' WHERE page_id = ? AND bot_id = ? AND posted_at = ? AND status = 'posting'"
                ).bind(errorMsg, pageId, botId, attemptPostedAtIso).run()
            }
        } catch { }
        return c.json({
            error: isAvatarComposeError ? 'avatar_compose_failed' : 'Post failed',
            details: errorMsg,
        }, 500)
    } finally {
        await releasePostingLock(env.DB, videoPostingLockKey)
        await releasePostingLock(env.DB, pagePostingLockKey)
    }
})

// ==================== MANUAL REEL POST (ใส่ Page ID + Token เอง) ====================

function inferManualPostHistoryVideoId(videoUrl: string, fallback = 'manual-reel'): string {
    const raw = String(videoUrl || '').trim()
    if (!raw) return fallback

    try {
        const url = new URL(raw)
        const path = decodeURIComponent(url.pathname || '')
        const candidates = [
            path.match(/\/videos\/([^/?#]+?)(?:_line)?_original\.mp4$/i)?.[1],
            path.match(/\/videos\/([^/?#]+?)\.mp4$/i)?.[1],
        ]
        for (const candidate of candidates) {
            const normalized = String(candidate || '').trim()
            if (normalized) return normalized
        }
    } catch {
        // fall through to regex parsing
    }

    const fallbackMatch = raw.match(/\/videos\/([^/?#]+?)(?:_line)?_original\.mp4(?:[?#]|$)/i)
        || raw.match(/\/videos\/([^/?#]+?)\.mp4(?:[?#]|$)/i)
    return String(fallbackMatch?.[1] || '').trim() || fallback
}



// Extension-side ad creation log (เพจ ฟีด only)
//
// The feed-ad-extension does the entire ad-creation pipeline inside the user's
// logged-in Chrome tab (Ads Manager) — bypassing the Electron app — and posts
// here once successful so the result lands in post_history alongside everything
// else (gallery "used" filter, dashboard history, etc.).
//
// Locked to ฉ่ำ page id 114142457961643 because:
//   - This is the page we agreed to migrate to extension; เฉียบ keeps Electron.
//   - Other pages have their own Electron flow that already writes post_history.
// Anything else is rejected up-front so a misconfigured extension build can't
// log against the wrong workspace.
//
// History note (2026-05-02): originally locked to ฟีด (116759241338040). User
// switched the extension target to ฉ่ำ (114142457961643). Behaviour identical
// — only the page id literal changed.
const EXTENSION_PAGE_ID = '114142457961643'

app.post('/api/dashboard/extension-ad-log', async (c) => {
    const body = await c.req.json().catch(() => ({})) as {
        page_id?: string
        video_id?: string
        story_id?: string
        ad_id?: string
        adset_id?: string
        creative_id?: string
        shopee_link?: string
        short_link?: string
        comment_id?: string
    }
    const pageId = String(body.page_id || '').trim()
    if (pageId !== EXTENSION_PAGE_ID) {
        return c.json({ ok: false, error: 'extension_log_only_for_extension_page', expected_page_id: EXTENSION_PAGE_ID }, 403)
    }
    const videoId = String(body.video_id || '').trim()
    const storyId = String(body.story_id || '').trim()
    if (!videoId || !storyId) {
        return c.json({ ok: false, error: 'video_id_and_story_id_required' }, 400)
    }

    const pageRow = await c.env.DB.prepare(
        'SELECT bot_id FROM pages WHERE id = ? LIMIT 1'
    ).bind(pageId).first().catch(() => null) as { bot_id?: string } | null
    const namespaceId = String(pageRow?.bot_id || '').trim()

    await ensurePostHistoryTraceColumns(c.env.DB).catch(() => { })
    const nowIso = new Date().toISOString()
    const shopeeLink = String(body.shopee_link || '').trim()
    const commentId = String(body.comment_id || '').trim()
    const commentStatus = commentId ? 'success' : 'not_attempted'

    try {
        await c.env.DB.prepare(
            `INSERT INTO post_history (
                page_id, video_id, fb_post_id, posted_at, status, trigger_source, bot_id,
                shopee_link, comment_status, comment_fb_id
            ) VALUES (?, ?, ?, ?, 'success', 'feed_extension', ?, ?, ?, ?)`
        ).bind(
            pageId, videoId, storyId, nowIso, namespaceId,
            shopeeLink, commentStatus, commentId || null,
        ).run()
    } catch (e) {
        return c.json({ ok: false, error: 'post_history_insert_failed', detail: String(e instanceof Error ? e.message : e) }, 500)
    }

    if (namespaceId) {
        await markNamespaceVideoPosted(c.env.DB, namespaceId, videoId, nowIso).catch(() => { })
    }

    return c.json({
        ok: true,
        page_id: pageId,
        video_id: videoId,
        story_id: storyId,
        ad_id: String(body.ad_id || '').trim(),
        adset_id: String(body.adset_id || '').trim(),
        creative_id: String(body.creative_id || '').trim(),
        short_link: String(body.short_link || '').trim(),
        logged_at: nowIso,
    })
})

