app.post('/api/pages/:id/promote-ad', async (c) => {
    const pageId = c.req.param('id')
    const botId = c.get('botId')
    try {
        const body = await c.req.json().catch(() => ({})) as { story_id?: string }
        const storyId = String(body.story_id || '').trim()
        if (!storyId) return c.json({ error: 'Missing story_id' }, 400)

        const baseUrl = resolveCloakFbBridgeBaseUrl(c.env)
        if (!baseUrl) return c.json({ ok: false, error: 'bridge_not_configured' }, 503)
        const resp = await fetchWithTimeout(baseUrl + '/promote', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ story_id: storyId }),
        }, 60000, 'promote_ad')
        const data = await resp.json().catch(() => ({} as any)) as { ok?: boolean; error?: string; post_url?: string }
        if (!resp.ok || !data?.ok) {
            return c.json({ error: String(data?.error || 'promote_failed') }, 500)
        }
        return c.json({ success: true, story_id: storyId, post_url: data.post_url })
    } catch (e) {
        return c.json({ error: e instanceof Error ? e.message : String(e) }, 500)
    }
})

app.post('/api/manual-post-reel', async (c) => {
    const t0 = Date.now()
    let manualHistoryId: number | null = null

    try {
        const body = await c.req.json() as {
            pageId: string
            accessToken: string
            videoUrl: string
            videoId?: string
            video_id?: string
            caption?: string
            commentToken?: string
            shopeeLink?: string
            lazadaLink?: string
        }

        const { pageId, accessToken, videoUrl, caption, commentToken, shopeeLink, lazadaLink } = body

        if (!pageId || !accessToken || !videoUrl) {
            return c.json({ error: 'Missing required fields: pageId, accessToken, videoUrl' }, 400)
        }

        console.log(`[MANUAL-REEL] Starting for page ${pageId}`)
        console.log(`[MANUAL-REEL] Video: ${videoUrl}`)
        const incomingNamespaceId = String(c.get('botId') || '').trim()
        const pageRow = await c.env.DB.prepare(
            `SELECT id, name, bot_id, is_active
             FROM pages
             WHERE id = ?
             ORDER BY CASE WHEN bot_id = ? THEN 0 ELSE 1 END
             LIMIT 1`
        ).bind(pageId, incomingNamespaceId).first() as { id?: string; name?: string; bot_id?: string; is_active?: number } | null
        if (!pageRow?.id) {
            return c.json({ error: 'page_not_registered_for_manual_post', pageId }, 404)
        }
        if (Number(pageRow.is_active || 0) !== 1) {
            return c.json({ error: 'page_posting_disabled', pageId, page: String(pageRow.name || pageId) }, 409)
        }
        const namespaceId = String(pageRow.bot_id || incomingNamespaceId || '').trim()
        const pageName = String(pageRow.name || pageId).trim()
        const historyVideoId = String(body.videoId || body.video_id || '').trim()
            || inferManualPostHistoryVideoId(videoUrl)
        const effectiveLazadaLink = String(lazadaLink || '').trim()
        const affiliateVerification = await verifyAffiliateLinksForPosting({
            env: c.env,
            namespaceId,
            pageId,
            shopeeLink: shopeeLink || '',
            lazadaLink: effectiveLazadaLink,
            logPrefix: 'MANUAL-REEL VERIFY',
        })
        if (!affiliateVerification.ok) {
            return c.json({
                error: 'affiliate_verification_failed',
                details: affiliateVerification.error || 'Affiliate verification failed',
                shopee_expected_id: affiliateVerification.shopee.expectedId || null,
                shopee_actual_id: affiliateVerification.shopee.actualId || null,
                lazada_expected_member_id: affiliateVerification.lazada.expectedId || null,
                lazada_actual_member_id: affiliateVerification.lazada.actualId || null,
            }, 400)
        }
        const effectiveShopeeLink = shopeeLink
            ? await resolvePostingShopeeLinkForNamespace({
                env: c.env,
                namespaceId,
                pageId,
                shopeeLink,
                logPrefix: 'MANUAL-REEL',
            })
            : ''
        if (shopeeLink && !effectiveShopeeLink) {
            return c.json({ error: 'shopee_shortlink_failed', details: 'Shopee shortlink is required before posting' }, 409)
        }

        await ensurePostHistoryTraceColumns(c.env.DB)
        const nowIso = new Date().toISOString()
        const initialPostProfile = await resolvePostHistoryProfileByToken(c.env, accessToken)
        const inserted = await c.env.DB.prepare(
            'INSERT INTO post_history (page_id, video_id, posted_at, status, trigger_source, bot_id, post_token_hint, post_profile_id, post_profile_name, comment_status, comment_token_hint, comment_error, comment_fb_id, shopee_link, lazada_link) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)'
        ).bind(
            pageId,
            historyVideoId,
            nowIso,
            'posting',
            'manual_post_reel',
            namespaceId,
            deriveCommentTokenHint(accessToken),
            initialPostProfile.profileId,
            initialPostProfile.profileName,
            shopeeLink ? 'pending' : 'not_configured',
            deriveCommentTokenHint(commentToken || ''),
            shopeeLink ? null : 'shopee_link_missing',
            null,
            effectiveShopeeLink || shopeeLink || null,
            effectiveLazadaLink || null,
        ).run() as { meta?: { last_row_id?: number } }
        manualHistoryId = Number(inserted?.meta?.last_row_id || 0) || null
        await c.env.DB.prepare('UPDATE pages SET last_post_at = ? WHERE id = ? AND bot_id = ?')
            .bind(nowIso, pageId, namespaceId)
            .run()
            .catch(() => { })
        console.log(`[MANUAL-REEL] history row=${manualHistoryId || 'n/a'} ns=${namespaceId} page=${pageName} video=${historyVideoId}`)

        // Step 1: Init upload
        let initData: { video_id?: string; upload_url?: string }
        try {
            initData = await facebookGraphPost<{ video_id?: string; upload_url?: string }>(
                accessToken,
                `${FB_GRAPH_V19}/${pageId}/video_reels`,
                { upload_phase: 'start' },
            )
        } catch (e) {
            const parsed = parseFacebookErrorLike(e)
            throw new Error(`init_failed: ${parsed?.message || (e instanceof Error ? e.message : 'unknown')}`)
        }

        const { video_id: fbVideoId, upload_url } = initData
        if (!upload_url || !fbVideoId) {
            throw new Error('init_failed: No upload URL or video ID returned')
        }
        console.log(`[MANUAL-REEL] Init OK: video_id=${fbVideoId}`)

        // Step 2: Upload video
        const videoResp = await fetch(videoUrl)
        if (!videoResp.ok) {
            throw new Error(`fetch_video_failed: HTTP ${videoResp.status}`)
        }
        const videoBuffer = await videoResp.arrayBuffer()
        console.log(`[MANUAL-REEL] Video size: ${(videoBuffer.byteLength / 1024 / 1024).toFixed(1)}MB`)

        const uploadResp = await fetch(upload_url, {
            method: 'POST',
            headers: {
                'Authorization': `OAuth ${accessToken}`,
                'offset': '0',
                'file_size': videoBuffer.byteLength.toString(),
            },
            body: videoBuffer,
        })
        const uploadData = await uploadResp.json() as { success?: boolean; error?: { message: string } }
        if (uploadData.error) {
            throw new Error(`upload_failed: ${uploadData.error.message}`)
        }
        console.log(`[MANUAL-REEL] Upload OK`)

        // Step 3: Finish (publish)
        let finishData: { success?: boolean; post_id?: string; permalink_url?: string }
        try {
            finishData = await finishReelPublishWithRetry({
                accessToken,
                pageId,
                fbVideoId,
                description: caption || '',
                logPrefix: 'MANUAL-REEL',
            })
        } catch (e) {
            const parsed = parseFacebookErrorLike(e)
            throw new Error(`publish_failed: ${parsed?.message || (e instanceof Error ? e.message : 'unknown')}`)
        }

        const dur = ((Date.now() - t0) / 1000).toFixed(1)
        console.log(`[MANUAL-REEL] ✅ Published: ${fbVideoId} in ${dur}s`)
        const confirmedCanonicalPostId = String(finishData.post_id || '').trim()
        const confirmedPostId = confirmedCanonicalPostId || fbVideoId
        const fbReelUrl = String(finishData.permalink_url || '').trim() || `https://www.facebook.com/watch/?v=${fbVideoId}`
        if (historyVideoId && historyVideoId !== 'manual-reel') {
            await markNamespaceVideoPosted(c.env.DB, namespaceId, historyVideoId, new Date().toISOString()).catch(() => { })
        }
        if (manualHistoryId) {
            await c.env.DB.prepare(
                `UPDATE post_history
                 SET fb_post_id = ?,
                     fb_reel_url = ?,
                     status = 'success',
                     error_message = NULL,
                     post_token_hint = ?,
                     post_profile_id = ?,
                     post_profile_name = ?,
                     comment_status = ?,
                     comment_token_hint = ?,
                     comment_error = ?
                 WHERE id = ? AND status = 'posting'`
            ).bind(
                confirmedPostId,
                fbReelUrl,
                deriveCommentTokenHint(accessToken),
                initialPostProfile.profileId,
                initialPostProfile.profileName,
                shopeeLink ? 'pending' : 'not_configured',
                deriveCommentTokenHint(commentToken || ''),
                shopeeLink ? null : 'shopee_link_missing',
                manualHistoryId,
            ).run().catch(() => { })
        }

        // Step 4: Auto comment (if shopeeLink provided)
        let commentResult: string | null = null
        let commentStatus = shopeeLink ? 'pending' : 'not_configured'
        let commentError: string | null = shopeeLink ? null : 'shopee_link_missing'
        let commentFbId: string | null = null
        let commentTokenUsed = String(commentToken || '').trim()
        let commentProfileId: string | null = null
        let commentProfileName: string | null = null
        if (shopeeLink) {
            const commentWaitMs = getRandomCommentDelayMs()
            console.log(`[MANUAL-REEL] Waiting ${Math.ceil(commentWaitMs / 1000)}s before commenting...`)
            await waitMs(commentWaitMs)
            // Re-shorten with the freshly known Facebook post id as Sub ID 2 so
            // affiliate clicks can be attributed to the visible page post. The
            // pre-upload `effectiveShopeeLink` is kept as a validated fallback
            // in case the re-shorten transiently fails.
            let commentShopeeLink = effectiveShopeeLink
            if (confirmedPostId) {
                try {
                    const commentSubIds = buildPostingCommentShortlinkSubIds({
                        canonicalPostId: confirmedCanonicalPostId,
                        fbVideoId,
                        pageId,
                        historyId: manualHistoryId,
                        logPrefix: 'MANUAL-REEL',
                    })
                    const reshortened = await resolvePostingShopeeLinkForNamespace({
                        env: c.env,
                        namespaceId,
                        pageId,
                        shopeeLink,
                        logPrefix: 'MANUAL-REEL',
                        ...commentSubIds,
                    })
                    if (reshortened) commentShopeeLink = reshortened
                } catch (reshortenErr) {
                    console.log(`[MANUAL-REEL] re-shorten with post id failed; falling back to preflight link: ${reshortenErr instanceof Error ? reshortenErr.message : String(reshortenErr)}`)
                }
            }
            try {
                const res = await postShopeeCommentWithFallback({
                    env: c.env,
                    namespaceId,
                    fbVideoId: fbVideoId || confirmedPostId,
                    shopeeLink: commentShopeeLink,
                    lazadaLink: effectiveLazadaLink,
                    commentTokens: [commentToken || ''],
                    pageId,
                    logPrefix: 'MANUAL-REEL',
                })
                if (res.ok) {
                    commentResult = res.id || 'ok'
                    commentStatus = 'success'
                    commentError = null
                    commentFbId = res.id || null
                    commentTokenUsed = String(res.commentToken || commentTokenUsed || '').trim()
                    const commentProfile = await resolvePostHistoryProfileByToken(c.env, commentTokenUsed)
                    commentProfileId = commentProfile.profileId
                    commentProfileName = commentProfile.profileName
                } else {
                    commentResult = `failed: ${res.error || 'unknown'}`
                    commentStatus = 'failed'
                    commentError = res.error || 'comment_failed'
                    commentTokenUsed = String(res.commentToken || commentTokenUsed || '').trim()
                    const commentProfile = await resolvePostHistoryProfileByToken(c.env, commentTokenUsed)
                    commentProfileId = commentProfile.profileId
                    commentProfileName = commentProfile.profileName
                    await notifyCommentTokenIssue(
                        c.env,
                        namespaceId,
                        pageId,
                        pageName || pageId,
                        res.error || 'comment_failed',
                    ).catch((notifyErr) => {
                        console.error(`[MANUAL-REEL] notifyCommentTokenIssue failed: ${notifyErr instanceof Error ? notifyErr.message : String(notifyErr)}`)
                    })
                }
            } catch (e) {
                commentError = e instanceof Error ? e.message : String(e)
                commentStatus = 'failed'
                commentResult = `exception: ${commentError}`
            }
        }
        if (manualHistoryId) {
            await c.env.DB.prepare(
                `UPDATE post_history
                 SET comment_status = ?,
                     comment_error = ?,
                     comment_fb_id = ?,
                     comment_token_hint = ?,
                     comment_profile_id = ?,
                     comment_profile_name = ?
                 WHERE id = ?`
            ).bind(
                commentStatus,
                commentError,
                commentFbId,
                deriveCommentTokenHint(commentTokenUsed),
                commentProfileId,
                commentProfileName,
                manualHistoryId,
            ).run().catch(() => { })
        }

        return c.json({
            success: true,
            videoId: fbVideoId,
            postId: confirmedPostId,
            reelUrl: fbReelUrl,
            pageId,
            namespaceId,
            historyId: manualHistoryId,
            logId: manualHistoryId,
            log_id: manualHistoryId,
            post_history_id: manualHistoryId,
            caption: caption || '',
            duration: dur + 's',
            comment: commentResult,
        })
    } catch (e) {
        const errorMsg = e instanceof Error ? e.message : String(e)
        console.error(`[MANUAL-REEL] ❌ Error:`, errorMsg)
        if (manualHistoryId) {
            await c.env.DB.prepare(
                "UPDATE post_history SET status = 'failed', error_message = ?, comment_status = 'not_attempted' WHERE id = ? AND status = 'posting'"
            ).bind(errorMsg, manualHistoryId).run().catch(() => { })
        }
        return c.json({ error: errorMsg, stage: 'exception' }, 500)
    }
})

// ==================== SCHEDULED HANDLER (CRON) ====================

function enqueueBackgroundTask(
    ctx: ExecutionContext | undefined,
    label: string,
    task: () => Promise<unknown>,
): void {
    const runner = Promise.resolve()
        .then(async () => {
            await task()
        })
        .catch((error) => {
            console.error(`[${label}] ${error instanceof Error ? error.message : String(error)}`)
        })

    if (ctx) {
        ctx.waitUntil(runner)
    } else {
        void runner
    }
}

async function processPendingCommentBacklog(
    env: Env,
    options: { historyId?: number; ignoreDueAt?: boolean; limit?: number } = {},
): Promise<void> {
    const pendingList = await env.BUCKET.list({ prefix: '_pending_comments/' })

    for (const obj of pendingList.objects) {
        console.log(`[CRON] Pending comment cleanup: deleting legacy object ${obj.key}`)
        await env.BUCKET.delete(obj.key)
    }

    await ensurePostHistoryTraceColumns(env.DB)

    // Targeted drain (post-success path): when a concrete historyId is given, process ONLY
    // that just-created row, ignoring comment_due_at so it never has to wait for the next
    // cron scan. The general cron scan keeps respecting comment_due_at and its 20-row cap.
    const targetHistoryId = Number(options.historyId || 0)
    const ignoreDueAt = !!options.ignoreDueAt || targetHistoryId > 0
    const scanLimit = targetHistoryId > 0
        ? 1
        : Math.max(1, Math.min(100, Number(options.limit || 20)))

    // Backstop (general cron scan only): recover rows stranded in comment_status='processing'
    // — a targeted drain that crashed after the claim but before writing a terminal state.
    // Reset them to 'pending' so the scan below retries them, but ONLY when no fresh
    // (<15 min) comment-job posting lock is held for that row, so a drain currently in flight
    // is never disturbed. Failure-tolerant: a backstop error must not block the scan.
    if (targetHistoryId <= 0) {
        try {
            await ensurePostingLocksTable(env.DB)
            await env.DB.prepare(
                `UPDATE post_history
                 SET comment_status='pending', comment_error=NULL
                 WHERE comment_status='processing'
                   AND NOT EXISTS (
                        SELECT 1 FROM posting_locks pl
                        WHERE pl.lock_key = 'video::' || post_history.bot_id || '::comment:' || post_history.id
                          AND datetime(pl.created_at) > datetime('now', '-15 minutes')
                   )`
            ).run()
        } catch (error) {
            console.error(`[CRON-COMMENTS] stuck-processing backstop failed: ${error instanceof Error ? error.message : String(error)}`)
        }
    }

    const whereClauses = [
        "ph.comment_status = 'pending'",
        "TRIM(COALESCE(ph.fb_post_id, '')) <> ''",
    ]
    const whereBindings: unknown[] = []
    if (targetHistoryId > 0) {
        whereClauses.push('ph.id = ?')
        whereBindings.push(targetHistoryId)
    }
    if (!ignoreDueAt) {
        whereClauses.push("(ph.comment_due_at IS NULL OR datetime(ph.comment_due_at) <= datetime('now'))")
    }

    // Order: a targeted drain has a single row, so ordering is moot. The general cron fallback
    // must NOT be oldest-first only — that lets a months-old backlog (LIMIT 20) starve fresh
    // posts created at a deploy boundary whose targeted drain missed/failed. Prioritize rows
    // posted in the last 6 hours, then newest-first, so a fresh stuck post is always serviced
    // ahead of stale backlog while old rows still drain over subsequent ticks.
    const orderBy = targetHistoryId > 0
        ? 'datetime(ph.posted_at) ASC, ph.id ASC'
        : `CASE WHEN datetime(ph.posted_at) >= datetime('now', '-6 hours') THEN 0 ELSE 1 END ASC,
                  datetime(ph.posted_at) DESC,
                  ph.id DESC`

    const pendingRows = await env.DB.prepare(
        `SELECT ph.id,
                ph.bot_id,
                ph.page_id,
                ph.video_id,
                ph.fb_post_id,
                ph.fb_reel_url,
                ph.shopee_link,
                ph.lazada_link,
                ph.status,
                ph.post_token_hint,
                p.name AS page_name,
                p.access_token
         FROM post_history ph
         JOIN pages p ON p.id = ph.page_id
         WHERE ${whereClauses.join('\n           AND ')}
         ORDER BY ${orderBy}
         LIMIT ${scanLimit}`
    ).bind(...whereBindings).all() as {
        results?: Array<{
            id?: number
            bot_id?: string
            page_id?: string
            video_id?: string
            fb_post_id?: string
            fb_reel_url?: string
            shopee_link?: string
            lazada_link?: string
            status?: string
            post_token_hint?: string
            page_name?: string
            access_token?: string
        }>
    }

    for (const row of pendingRows.results || []) {
        const historyId = Number(row.id || 0)
        const botId = String(row.bot_id || '').trim()
        const pageId = String(row.page_id || '').trim()
        const pageName = String(row.page_name || '').trim()
        const fbPostIdRaw = String(row.fb_post_id || '').trim()
        const fbReelUrlRaw = String(row.fb_reel_url || '').trim()
        // Story-first: page-story target before reel object. Comments posted on
        // the reel object do NOT appear on the visible page-story feed, which
        // was the operator-visible bug ("History says comment success but the
        // page post shows no comments"). Build the candidate list here so the
        // missing page-story branch can block before live comment writes.
        const visibleCandidates = buildVisibleCommentTargetCandidates({
            pageId,
            fbPostId: fbPostIdRaw,
            fbReelUrlOrId: fbReelUrlRaw,
        })
        const targetId = visibleCandidates[0]
        const videoId = String(row.video_id || '').trim()
        const pageLockKey = buildPostingLockKey({ scope: 'page', namespaceId: botId, pageId })
        const videoLockKey = buildPostingLockKey({ scope: 'video', namespaceId: botId, videoId })
        const commentJobLockKey = await tryAcquirePostingLock(env.DB, {
            scope: 'video',
            namespaceId: botId,
            videoId: `comment:${historyId}`,
            ttlMinutes: 15,
        })

        if (!commentJobLockKey) {
            continue
        }

        const claimResult = await env.DB.prepare(
            `UPDATE post_history
             SET comment_status='processing',
                 comment_error=NULL
             WHERE id = ?
               AND comment_status = 'pending'`
        ).bind(historyId).run().catch(() => null)

        if (Number(claimResult?.meta?.changes || 0) === 0) {
            await releasePostingLock(env.DB, commentJobLockKey).catch(() => { })
            continue
        }

        if (!historyId || !botId || !pageId || !targetId) {
            await env.DB.prepare(
                "UPDATE post_history SET status='success', comment_status='failed', comment_error=? WHERE id=?"
            ).bind('missing_page_story_object_id', historyId).run().catch(() => { })
            await releasePostingLock(env.DB, pageLockKey).catch(() => { })
            await releasePostingLock(env.DB, videoLockKey).catch(() => { })
            await releasePostingLock(env.DB, commentJobLockKey).catch(() => { })
            continue
        }

        try {
            let tokenCandidates = await ensurePageTokenCandidates({
                env,
                db: env.DB,
                namespaceId: botId,
                pageId,
                pageName,
                primaryToken: String(row.access_token || ''),
                logPrefix: `PENDING-COMMENT ${pageName || pageId} ${historyId}`,
            })
            let commentToken = String(tokenCandidates.commentTokens[0] || '').trim()
            let commentTokenHint = deriveCommentTokenHint(commentToken)
            let commentProfile = await resolvePostHistoryProfileByToken(env, commentToken)

            // Resolve the shopee shortlink up front (before the missing-token check): the
            // CloakBrowser bridge fallback below reuses this SAME re-minted shortlink, and a
            // row that can't produce a link can't comment by any route anyway.
            const bucket = new BotBucket(env.BUCKET, botId) as unknown as R2Bucket
            const shopeeLink = await resolveShopeeLinkForRetry({
                db: env.DB,
                bucket,
                namespaceId: botId,
                videoId,
                preferred: String(row.shopee_link || ''),
            })

            if (!shopeeLink) {
                await env.DB.prepare(
                    "UPDATE post_history SET status='success', comment_status='failed', comment_error=?, comment_token_hint=?, comment_profile_id=?, comment_profile_name=? WHERE id=?"
                ).bind('shopee_link_missing', commentTokenHint, commentProfile.profileId, commentProfile.profileName, historyId).run().catch(() => { })
                continue
            }

            const commentSubIds = buildPostingCommentShortlinkSubIds({
                canonicalPostId: fbPostIdRaw,
                fbVideoId: videoId,
                reelId: extractIdFromCommentTargetInput(fbReelUrlRaw),
                pageId,
                historyId,
                logPrefix: `PENDING-COMMENT ${pageName || pageId} ${historyId}`,
            })
            const shortShopeeLink = await resolvePostingShopeeLinkForNamespace({
                env,
                namespaceId: botId,
                pageId,
                shopeeLink,
                logPrefix: `PENDING-COMMENT ${pageName || pageId} ${historyId}`,
                ...commentSubIds,
            })
            if (!shortShopeeLink) {
                await env.DB.prepare(
                    "UPDATE post_history SET status='success', comment_status='failed', comment_error=?, comment_token_hint=?, comment_profile_id=?, comment_profile_name=? WHERE id=?"
                ).bind('shopee_shortlink_failed', commentTokenHint, commentProfile.profileId, commentProfile.profileName, historyId).run().catch(() => { })
                continue
            }
            const lazadaLink = await resolveLazadaLinkForRetry({
                bucket,
                videoId,
                preferred: String(row.lazada_link || '').trim(),
            })

            // Bridge-fallback eligibility: only when the ORIGINAL post itself went out through
            // the admin-owned CloakBrowser/Power Editor bridge (post_token_hint proves the
            // bridge already has authorized access to this Page) AND the namespace is admin
            // managed. The DB lookup is short-circuited so a plain stored-token post never
            // pays for it. This is what lets page เฉียบ (post via Power Editor, comment via
            // Facebook Lite) still get a Page comment when its stored token is invalidated.
            const bridgeFallbackEligible =
                isCloakBridgeCommentFallbackEligible(row.post_token_hint) &&
                await isNamespaceShortlinkAdminManaged(env.DB, botId).catch(() => false)

            // Root fix for the "permanent token expired" state on Facebook Lite pages: this
            // backlog IS the stored_token comment path, so a missing or auth-rejected
            // (190 / invalidated session) stored token is never terminal — stored credentials
            // can always re-mint a fresh page token. Try BrowserSaving's FB GET Token refresh
            // ONCE, reload the fresh token from the namespace pool, and let the caller retry
            // before falling back to the admin bridge / failing. Returns true only when a
            // usable comment token now exists.
            let fbLiteRefreshAttempted = false
            const reloadCommentTokenViaFacebookLiteRefresh = async (
                trigger: 'missing' | 'auth_failure',
                error?: unknown,
            ): Promise<boolean> => {
                if (fbLiteRefreshAttempted) return false
                if (!shouldAttemptFacebookLiteRefresh({
                    commentSource: 'stored_token',
                    tokenMissing: trigger === 'missing',
                    error,
                })) return false
                fbLiteRefreshAttempted = true
                const refreshOutcome = await refreshFacebookLiteCommentTokenForPage({
                    env,
                    db: env.DB,
                    namespaceId: botId,
                    pageId,
                    pageName,
                    logPrefix: `PENDING-COMMENT ${pageName || pageId} ${historyId}`,
                }).catch((e) => ({
                    refreshed: false,
                    synced: false,
                    profileCount: 0,
                    reason: e instanceof Error ? e.message : String(e),
                }))
                if (!refreshOutcome.refreshed) {
                    // BrowserSaving could not re-mint from the linked/discovered profiles. Fall through
                    // to the bridge's own AUTOMATIC true-recovery (/token/auto-sync): it re-mints from
                    // the stored bridge session/credentials and refreshes every administered page token
                    // in this namespace's pool. No operator action / button / manual export.
                    const autoSync = await triggerBridgeAutoSyncForPage({
                        env,
                        namespaceId: botId,
                        pageId,
                        fallbackAccounts: resolveFacebookLiteFallbackAccounts(env, { pageId }),
                        logPrefix: `PENDING-COMMENT ${pageName || pageId} ${historyId} BRIDGE-AUTOSYNC`,
                    }).catch(() => ({ ok: false, synced: false, reason: 'auto_sync_error' }))
                    if (!autoSync.synced) return false
                }
                // BrowserSaving (or the bridge auto-sync) pushed the fresh page token into the namespace
                // pool; read it back (resolveFacebookCommentToken prefers pool comment/post tokens, then
                // pages.access_token) and put it at the head of the candidate list.
                const refreshedResolution = await resolveFacebookCommentToken(env.DB, pageId, botId).catch(() => null)
                const refreshedToken = String(refreshedResolution?.token || '').trim()
                if (!refreshedToken) return false
                tokenCandidates = {
                    ...tokenCandidates,
                    commentTokens: normalizeCommentTokenPool([
                        refreshedToken,
                        ...(tokenCandidates.commentTokens || []),
                    ]),
                }
                commentToken = String(tokenCandidates.commentTokens[0] || '').trim()
                commentTokenHint = deriveCommentTokenHint(commentToken)
                commentProfile = await resolvePostHistoryProfileByToken(env, commentToken)
                return !!commentToken
            }

            if (!commentToken) {
                // Re-mint a fresh Facebook Lite token before any fallback. On success the loop
                // falls through to the normal comment attempt below with the fresh token.
                const recovered = await reloadCommentTokenViaFacebookLiteRefresh('missing')
                if (!recovered) {
                    // Missing/expired stored Facebook Lite token and refresh unavailable. If the
                    // page can still comment as the Page via the bridge, do that instead of
                    // leaving a posted-but-no-comment row.
                    if (bridgeFallbackEligible) {
                        const bridged = await sendStoredCommentBridgeFallback({
                            env,
                            namespaceId: botId,
                            pageId,
                            storyId: targetId,
                            shortShopeeLink,
                            logPrefix: `PENDING-COMMENT ${pageName || pageId} ${historyId}`,
                        })
                        if (bridged.ok) {
                            await env.DB.prepare(
                                "UPDATE post_history SET status='success', comment_status='success', comment_error=NULL, comment_fb_id=?, comment_token_hint=?, comment_profile_id=NULL, comment_profile_name=NULL WHERE id=?"
                            ).bind(bridged.id || null, 'stored_token_missing_fallback_cloak_session_bridge', historyId).run().catch(() => { })
                            continue
                        }
                        await env.DB.prepare(
                            "UPDATE post_history SET status='success', comment_status='failed', comment_error=?, comment_token_hint=? WHERE id=?"
                        ).bind(`access_token_missing; cloak_fallback_failed:${bridged.error || 'bridge_failed'}`.substring(0, 200), commentTokenHint, historyId).run().catch(() => { })
                        continue
                    }
                    await env.DB.prepare(
                        "UPDATE post_history SET status='success', comment_status='failed', comment_error=?, comment_token_hint=? WHERE id=?"
                    ).bind('access_token_missing', commentTokenHint, historyId).run().catch(() => { })
                    continue
                }
            }

            let commentResult = await postShopeeCommentWithFallback({
                env,
                namespaceId: botId,
                fbVideoId: targetId,
                fbPostId: fbPostIdRaw,
                fbReelUrlOrId: fbReelUrlRaw,
                shopeeLink: shortShopeeLink,
                lazadaLink,
                commentTokens: tokenCandidates.commentTokens,
                pageId,
                logPrefix: `PENDING-COMMENT ${pageName || pageId} ${historyId}`,
            })

            // The stored Facebook Lite token was rejected with an auth error (190 / invalidated
            // session). Re-mint a fresh token from stored credentials ONCE and retry before
            // falling back to the admin bridge / failing — a Facebook Lite token is never
            // permanently expired while its credentials are stored.
            if (!commentResult.ok && isStoredCommentTokenAuthFailure(commentResult.error)) {
                const recovered = await reloadCommentTokenViaFacebookLiteRefresh('auth_failure', commentResult.error)
                if (recovered) {
                    commentResult = await postShopeeCommentWithFallback({
                        env,
                        namespaceId: botId,
                        fbVideoId: targetId,
                        fbPostId: fbPostIdRaw,
                        fbReelUrlOrId: fbReelUrlRaw,
                        shopeeLink: shortShopeeLink,
                        lazadaLink,
                        commentTokens: tokenCandidates.commentTokens,
                        pageId,
                        logPrefix: `PENDING-COMMENT ${pageName || pageId} ${historyId} (fb-lite-refreshed)`,
                    })
                }
            }

            if (commentResult.ok) {
                const usedToken = String(commentResult.commentToken || commentToken || '').trim()
                const usedTokenHint = deriveCommentTokenHint(usedToken)
                const usedProfile = await resolvePostHistoryProfileByToken(env, usedToken)
                await env.DB.prepare(
                    "UPDATE post_history SET status='success', comment_status='success', comment_error=NULL, comment_fb_id=?, comment_token_hint=?, comment_profile_id=?, comment_profile_name=? WHERE id=?"
                ).bind(
                    commentResult.id || null,
                    usedTokenHint,
                    usedProfile.profileId,
                    usedProfile.profileName,
                    historyId,
                ).run().catch(() => { })
            } else {
                const usedToken = String(commentResult.commentToken || commentToken || '').trim()
                const usedTokenHint = deriveCommentTokenHint(usedToken)
                const usedProfile = await resolvePostHistoryProfileByToken(env, usedToken)
                // Stored/Facebook Lite token comment failed. If it failed because the token is
                // invalid/expired/missing AND the page is bridge-eligible, post the comment as
                // the Page through the CloakBrowser bridge so we don't leave it uncommented.
                if (bridgeFallbackEligible && isStoredCommentTokenAuthFailure(commentResult.error)) {
                    const bridged = await sendStoredCommentBridgeFallback({
                        env,
                        namespaceId: botId,
                        pageId,
                        storyId: targetId,
                        shortShopeeLink,
                        logPrefix: `PENDING-COMMENT ${pageName || pageId} ${historyId}`,
                    })
                    if (bridged.ok) {
                        await env.DB.prepare(
                            "UPDATE post_history SET status='success', comment_status='success', comment_error=NULL, comment_fb_id=?, comment_token_hint=?, comment_profile_id=NULL, comment_profile_name=NULL WHERE id=?"
                        ).bind(bridged.id || null, 'stored_token_failed_fallback_cloak_session_bridge', historyId).run().catch(() => { })
                        continue
                    }
                    await env.DB.prepare(
                        "UPDATE post_history SET status='success', comment_status='failed', comment_error=?, comment_token_hint=?, comment_profile_id=?, comment_profile_name=? WHERE id=?"
                    ).bind(
                        `${commentResult.error || 'comment_failed'}; cloak_fallback_failed:${bridged.error || 'bridge_failed'}`.substring(0, 200),
                        usedTokenHint,
                        usedProfile.profileId,
                        usedProfile.profileName,
                        historyId,
                    ).run().catch(() => { })
                    continue
                }
                await env.DB.prepare(
                    "UPDATE post_history SET status='success', comment_status='failed', comment_error=?, comment_token_hint=?, comment_profile_id=?, comment_profile_name=? WHERE id=?"
                ).bind(
                    commentResult.error || 'comment_failed',
                    usedTokenHint,
                    usedProfile.profileId,
                    usedProfile.profileName,
                    historyId,
                ).run().catch(() => { })
            }
        } catch (error) {
            const errorMessage = error instanceof Error ? error.message : String(error)
            await env.DB.prepare(
                `UPDATE post_history
                 SET status='success',
                     comment_status='pending',
                     comment_error=?
                 WHERE id = ?
                   AND comment_status = 'processing'`
            ).bind(errorMessage || 'comment_backlog_failed', historyId).run().catch(() => { })
        } finally {
            await releasePostingLock(env.DB, pageLockKey).catch(() => { })
            await releasePostingLock(env.DB, videoLockKey).catch(() => { })
            await releasePostingLock(env.DB, commentJobLockKey).catch(() => { })
        }
    }
}

// Post-success comment trigger: after a route/cron post persists comment_status='pending'
// for a concrete post_history row, drain THAT row shortly after instead of waiting for the
// next cron scan. The short fixed delay reuses FACEBOOK_PAGE_COMMENT_DELAY_MS so the page
// post/product card is attached and commentable. Comment failure stays non-fatal (the post
// already succeeded), errors are swallowed/sanitized, and cron remains the fallback.
//
// When an ExecutionContext is available (HTTP routes, cron) the drain runs in waitUntil so it
// never blocks the response; otherwise it runs detached. Either way it never throws.
function runPendingCommentBacklogSoon(
    env: Env,
    historyId: number,
    logPrefix: string,
    ctx?: ExecutionContext,
): void {
    const targetHistoryId = Number(historyId || 0)
    if (targetHistoryId <= 0) return
    enqueueBackgroundTask(ctx, logPrefix, async () => {
        await waitMs(FACEBOOK_PAGE_COMMENT_DELAY_MS)
        await processPendingCommentBacklog(env, {
            historyId: targetHistoryId,
            ignoreDueAt: true,
            limit: 1,
        }).catch((error) => {
            console.error(`[${logPrefix}] targeted comment drain failed for history ${targetHistoryId}: ${error instanceof Error ? error.message : String(error)}`)
        })
    })
}

async function ensureCronRuntimeStateTable(db: D1Database): Promise<void> {
    await db.prepare(
        `CREATE TABLE IF NOT EXISTS cron_runtime_state (
            id TEXT PRIMARY KEY,
            run_id TEXT,
            status TEXT NOT NULL DEFAULT 'idle',
            started_at TEXT,
            finished_at TEXT,
            heartbeat_at TEXT,
            current_page_id TEXT,
            current_page_name TEXT,
            current_namespace_id TEXT,
            pages_total INTEGER NOT NULL DEFAULT 0,
            pages_visited INTEGER NOT NULL DEFAULT 0,
            pages_posted INTEGER NOT NULL DEFAULT 0,
            pages_failed INTEGER NOT NULL DEFAULT 0,
            last_error TEXT
        )`
    ).run()
}

async function updateCronRuntimeState(db: D1Database, patch: {
    runId?: string | null
    status?: string | null
    startedAt?: string | null
    finishedAt?: string | null
    heartbeatAt?: string | null
    currentPageId?: string | null
    currentPageName?: string | null
    currentNamespaceId?: string | null
    pagesTotal?: number | null
    pagesVisited?: number | null
    pagesPosted?: number | null
    pagesFailed?: number | null
    lastError?: string | null
}): Promise<void> {
    await ensureCronRuntimeStateTable(db)
    await db.prepare(
        `INSERT INTO cron_runtime_state (
            id,
            run_id,
            status,
            started_at,
            finished_at,
            heartbeat_at,
            current_page_id,
            current_page_name,
            current_namespace_id,
            pages_total,
            pages_visited,
            pages_posted,
            pages_failed,
            last_error
        ) VALUES ('scheduled', ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        ON CONFLICT(id) DO UPDATE SET
            run_id = COALESCE(excluded.run_id, cron_runtime_state.run_id),
            status = COALESCE(excluded.status, cron_runtime_state.status),
            started_at = COALESCE(excluded.started_at, cron_runtime_state.started_at),
            finished_at = excluded.finished_at,
            heartbeat_at = COALESCE(excluded.heartbeat_at, cron_runtime_state.heartbeat_at),
            current_page_id = excluded.current_page_id,
            current_page_name = excluded.current_page_name,
            current_namespace_id = excluded.current_namespace_id,
            pages_total = COALESCE(excluded.pages_total, cron_runtime_state.pages_total),
            pages_visited = COALESCE(excluded.pages_visited, cron_runtime_state.pages_visited),
            pages_posted = COALESCE(excluded.pages_posted, cron_runtime_state.pages_posted),
            pages_failed = COALESCE(excluded.pages_failed, cron_runtime_state.pages_failed),
            last_error = excluded.last_error`
    ).bind(
        patch.runId ?? null,
        patch.status ?? null,
        patch.startedAt ?? null,
        patch.finishedAt ?? null,
        patch.heartbeatAt ?? null,
        patch.currentPageId ?? null,
        patch.currentPageName ?? null,
        patch.currentNamespaceId ?? null,
        typeof patch.pagesTotal === 'number' ? patch.pagesTotal : null,
        typeof patch.pagesVisited === 'number' ? patch.pagesVisited : null,
        typeof patch.pagesPosted === 'number' ? patch.pagesPosted : null,
        typeof patch.pagesFailed === 'number' ? patch.pagesFailed : null,
        patch.lastError ?? null,
    ).run()
}

async function recoverStaleScheduledRun(db: D1Database, maxStaleMs = 90_000): Promise<boolean> {
    const runtime = await db.prepare(
        `SELECT run_id, status, started_at, heartbeat_at, pages_visited
         FROM cron_runtime_state
         WHERE id = 'scheduled'
         LIMIT 1`
    ).first() as {
        run_id?: string | null
        status?: string | null
        started_at?: string | null
        heartbeat_at?: string | null
        pages_visited?: number | null
    } | null

    const status = String(runtime?.status || '').trim().toLowerCase()
    const heartbeatAt = String(runtime?.heartbeat_at || '').trim()
    const heartbeatMs = Date.parse(heartbeatAt)
    const startedAtMs = Date.parse(String(runtime?.started_at || '').trim())
    const pagesVisited = Number(runtime?.pages_visited || 0)
    if (status !== 'running' || !Number.isFinite(heartbeatMs)) return false
    const ageMs = Date.now() - heartbeatMs
    const startupAgeMs = Number.isFinite(startedAtMs) ? (Date.now() - startedAtMs) : ageMs
    const startupHung = pagesVisited <= 0 && startupAgeMs > 20_000
    if (!startupHung && ageMs <= Math.max(30_000, maxStaleMs)) return false

    const staleError = `stale_scheduled_run_recovered:${String(runtime?.run_id || '').trim() || 'unknown'}`
    await db.prepare(
        `DELETE FROM posting_locks
         WHERE lock_key = 'page::__scheduled__::run'`
    ).run().catch(() => { })
    await updateCronRuntimeState(db, {
        status: 'failed',
        finishedAt: new Date().toISOString(),
        heartbeatAt: new Date().toISOString(),
        currentPageId: null,
        currentPageName: null,
        currentNamespaceId: null,
        lastError: staleError,
    }).catch(() => { })
    console.warn(`[CRON] Recovered stale scheduled run: ${staleError}`)
    return true
}

async function handleScheduled(env: Env, ctx?: ExecutionContext) {
    const cronTickIso = new Date().toISOString()
    console.log(`[CRON] tick=${cronTickIso} starting auto-post check...`)
    const dedupCommentTargets = new Set<string>()
    await env.DB.prepare(
        `DELETE FROM posting_locks
         WHERE lock_key = 'page::__scheduled__::run'
           AND NOT EXISTS (
               SELECT 1
               FROM cron_runtime_state
               WHERE id = 'scheduled'
                 AND status = 'running'
           )`
    ).run().catch(() => { })
    await env.DB.prepare(
        `DELETE FROM posting_locks
         WHERE lock_key = 'page::__scheduled__::run'
           AND datetime(created_at) < datetime('now', '-2 minutes')`
    ).run().catch(() => { })
    await recoverStaleScheduledRun(env.DB).catch(() => { })
    // Keep the posting cron isolated. Background import/warm-up/comment/ad jobs
    // can consume subrequest slots and starve the auto-post loop before it gets
    // to pages_visited; run them from their dedicated/manual paths instead.
    let scheduledRunLockKey = await tryAcquirePostingLock(env.DB, {
        scope: 'page',
        namespaceId: '__scheduled__',
        pageId: 'run',
        ttlMinutes: 10,
    })
    if (!scheduledRunLockKey) {
        const recovered = await recoverStaleScheduledRun(env.DB).catch(() => false)
        if (recovered) {
            scheduledRunLockKey = await tryAcquirePostingLock(env.DB, {
                scope: 'page',
                namespaceId: '__scheduled__',
                pageId: 'run',
                ttlMinutes: 10,
            })
        }
    }
    if (!scheduledRunLockKey) {
        console.log('[CRON] Skip run (scheduled global lock busy)')
        await updateCronRuntimeState(env.DB, {
            status: 'busy',
            heartbeatAt: new Date().toISOString(),
            currentPageId: null,
            currentPageName: null,
            currentNamespaceId: null,
            lastError: 'scheduled_run_busy',
        }).catch(() => { })
        return
    }

    // Get current time in Thailand timezone (UTC+7) using proper Intl
    const now = new Date()
    const nowISO = now.toISOString()

    // Use Intl.DateTimeFormat for accurate Thailand time
    const thaiTimeFormatter = new Intl.DateTimeFormat('en-US', {
        timeZone: 'Asia/Bangkok',
        hour: '2-digit',
        minute: '2-digit',
        hour12: false,
    })
    const thaiDateFormatter = new Intl.DateTimeFormat('en-US', {
        timeZone: 'Asia/Bangkok',
        year: 'numeric',
        month: '2-digit',
        day: '2-digit',
    })

    const thaiTimeParts = thaiTimeFormatter.formatToParts(now)
    const thaiHour = parseInt(thaiTimeParts.find(p => p.type === 'hour')?.value || '0', 10)
    const thaiMinute = parseInt(thaiTimeParts.find(p => p.type === 'minute')?.value || '0', 10)

    const thaiDateParts = thaiDateFormatter.formatToParts(now)
    const thaiYear = thaiDateParts.find(p => p.type === 'year')?.value
    const thaiMonth = thaiDateParts.find(p => p.type === 'month')?.value
    const thaiDay = thaiDateParts.find(p => p.type === 'day')?.value
    const todayStr = `${thaiYear}-${thaiMonth}-${thaiDay}`
    const slotEarlyToleranceMinutes = 1
    const slotLateGraceRaw = parseInt(String((env as any).CRON_SLOT_GRACE_MINUTES || '10'), 10)
    const slotLateGraceMinutes = Number.isFinite(slotLateGraceRaw)
        ? Math.max(1, Math.min(60, slotLateGraceRaw))
        : 10
    const formatSlot = (slot: { hour: number; minute: number }) => `${slot.hour}:${slot.minute.toString().padStart(2, '0')}`

    await ensurePagesOneCardColumns(env.DB)
    // 1. Get active pages whose schedule field tells the cron WHEN to post.
    //
    // post_hours is the single source of truth. Empty post_hours = explicit
    // "no schedule" = do not post — even if post_interval_minutes still has a
    // stale value from a previous interval-mode save. The earlier version of
    // this query OR'd in post_interval_minutes >= 5 as a fallback, which
    // caused pages to keep posting after the operator switched the UI to
    // "ติ๊กเวลา" with zero slots ticked (the user-facing intent of "off").
    //
    // The API-side drift guard already ensures post_hours stays in sync with
    // interval-mode saves, so a NULL/empty post_hours genuinely means "off".
    const { results: pages } = await env.DB.prepare(`
        SELECT id, name, access_token, post_hours, last_post_at, bot_id, onecard_enabled, onecard_link_mode, onecard_cta, caption_link_enabled, ads_publish_enabled, posting_token_source, comment_token_source, posting_profile_uid
        FROM pages
        WHERE is_active = 1
          AND post_hours IS NOT NULL
          AND post_hours != ''
    `).all() as {
        results: Array<{
            id: string
            name: string
            access_token: string
            post_hours: string
            last_post_at: string | null
            bot_id: string | null
            onecard_enabled?: number | null
            onecard_link_mode?: string | null
            onecard_cta?: string | null
            caption_link_enabled?: number | null
            ads_publish_enabled?: number | null
            posting_token_source?: string | null
            comment_token_source?: string | null
            posting_profile_uid?: string | null
        }>
    }
    // Keep scheduled handler logs compact. Dumping every candidate page on every
    // cron tick can consume enough Worker CPU to abort the run before posting.
    console.log(`[CRON] tick=${cronTickIso} candidate_pages=${pages.length}`)

    // Current time in minutes since midnight (Thailand)
    const nowMinutes = thaiHour * 60 + thaiMinute

    console.log(`[CRON] Found ${pages.length} active pages, Thai time: ${thaiHour}:${thaiMinute.toString().padStart(2, '0')} (${nowMinutes}m), date: ${todayStr}`)

    const runId = crypto.randomUUID()
    const cronStats = {
        pagesVisited: 0,
        pagesPosted: 0,
        pagesFailed: 0,
    }
    const geminiApiKeysByNamespace = new Map<string, string[]>()
    const shortlinkEnabledByNamespace = new Map<string, boolean>()
    const galleryVideosByNamespace = new Map<string, Array<Record<string, unknown>>>()
    const reconciledNamespaces = new Set<string>()
    let fatalError: Error | null = null
    await updateCronRuntimeState(env.DB, {
        runId,
        status: 'running',
        startedAt: nowISO,
        finishedAt: null,
        heartbeatAt: nowISO,
        currentPageId: null,
        currentPageName: null,
        currentNamespaceId: null,
        pagesTotal: pages.length,
        pagesVisited: 0,
        pagesPosted: 0,
        pagesFailed: 0,
        lastError: null,
    }).catch(() => { })

    try {
        for (const page of pages) {
            const botId = page.bot_id || 'default'
            cronStats.pagesVisited += 1
            updateCronRuntimeState(env.DB, {
                runId,
                heartbeatAt: new Date().toISOString(),
                currentPageId: String(page.id || ''),
                currentPageName: String(page.name || ''),
                currentNamespaceId: botId,
                pagesVisited: cronStats.pagesVisited,
                pagesPosted: cronStats.pagesPosted,
                pagesFailed: cronStats.pagesFailed,
            }).catch(() => { })

            try {
                // ใช้ bot_id ของ page เป็น namespace สำหรับหา videos
                if (!reconciledNamespaces.has(botId)) {
                    // Reconcile/recover maintenance is intentionally not launched
                    // inside the scheduled posting loop; keeping the loop free of
                    // background fetch/R2 work prevents subrequest starvation.
                    reconciledNamespaces.add(botId)
                }
                failStalePostingRows(env.DB, botId, String(page.id || ''), 15 * 60).catch(() => { })
                // Bounded stale-posting recovery: clear an attempt that died with
                // no fb_post_id before the active-posting guards so cron is not
                // permanently blocked for this page.
                await recoverStalePostingAttemptsForPage(env.DB, {
                    namespaceId: botId,
                    pageId: String(page.id || ''),
                    reason: 'stale_posting_timeout_no_fb_post_id_cron',
                }).catch(() => 0)

                // Universal min-gap guard — prevents back-to-back posts regardless of schedule mode.
                // Catches bucket-boundary races (every:N) and stale last_post_at across cron ticks.
                // 5-minute hard floor: if the page posted anything within the last 5 minutes, skip.
                const MIN_GAP_SECONDS = 5 * 60
                const recentRow = await env.DB.prepare(
                    `SELECT MAX(posted_at) AS last_at FROM post_history
                     WHERE page_id = ? AND bot_id = ? AND status IN ('success','posting')
                     AND posted_at > datetime('now', '-2 hours')`
                ).bind(page.id, botId).first<{ last_at: string | null }>().catch(() => null)
                if (recentRow?.last_at) {
                    const elapsedSeconds = (Date.now() - Date.parse(String(recentRow.last_at))) / 1000
                    if (Number.isFinite(elapsedSeconds) && elapsedSeconds >= 0 && elapsedSeconds < MIN_GAP_SECONDS) {
                        console.log(`[CRON] Page ${page.name}: skip (min-gap guard, last post ${Math.round(elapsedSeconds)}s ago < ${MIN_GAP_SECONDS}s)`)
                        continue
                    }
                }

                const rawSchedule = (page.post_hours || '').trim()
                const intervalMatch = rawSchedule.match(/^every:(\d{1,4})$/i)

                // Decide whether this page is due before touching gallery/token work.
                let dedupKey = ''
                if (intervalMatch) {
                    const intervalMinutes = Math.max(5, Math.min(720, parseInt(intervalMatch[1], 10) || 60))
                    const intervalMs = intervalMinutes * 60_000
                    const nowMs = now.getTime()
                    const lastPostedMs = page.last_post_at ? new Date(page.last_post_at).getTime() : 0
                    const elapsedMs = page.last_post_at ? (nowMs - lastPostedMs) : Number.POSITIVE_INFINITY

                    if (page.last_post_at && elapsedMs < intervalMs) {
                        const remainMin = Math.ceil((intervalMs - elapsedMs) / 60_000)
                        console.log(`[CRON] Page ${page.name}: skip (interval every ${intervalMinutes}m, remaining ${remainMin}m)`)
                        continue
                    }

                    const intervalBucket = Math.floor(nowMs / intervalMs)
                    dedupKey = `_cron_dedup/${page.id}/interval_${intervalMinutes}_${intervalBucket}`
                    console.log(`[CRON] Page ${page.name}: posting by interval every ${intervalMinutes}m`)
                } else {
                    const scheduledTimes = rawSchedule
                .split(',')
                .map(part => part.trim())
                .filter(Boolean)
                .map((trimmed) => {
                    if (trimmed.includes(':')) {
                        const [h, m] = trimmed.split(':').map(Number)
                        const normalizedHour = h === 24 ? 0 : h
                        return {
                            hour: normalizedHour,
                            minute: m,
                            totalMin: normalizedHour * 60 + m,
                            rawHour: h,
                        }
                    }
                    const h = Number(trimmed)
                    const normalizedHour = h === 24 ? 0 : h
                    return {
                        hour: normalizedHour,
                        minute: 0,
                        totalMin: normalizedHour * 60,
                        rawHour: h,
                    }
                })
                .filter(({ hour, minute, totalMin, rawHour }) =>
                    Number.isFinite(rawHour) &&
                    Number.isFinite(minute) &&
                    Number.isFinite(totalMin) &&
                    rawHour >= 0 &&
                    rawHour <= 24 &&
                    minute >= 0 &&
                    minute <= 59
                )
                .sort((a, b) => a.totalMin - b.totalMin)

                    if (scheduledTimes.length === 0) {
                        console.log(`[CRON] Page ${page.name}: skip (invalid slots: ${rawSchedule || 'empty'})`)
                        continue
                    }

                    // Failed cron rows count as a "slot fill" so the same minute
                    // slot does not get hammered every tick when shortlink /
                    // affiliate-verification / comment preflight fails. Without
                    // this, a single 18:00 slot with a broken shortlink keeps
                    // re-firing every minute until the late-grace window closes,
                    // and post_history fills with duplicate failure rows.
                    const { results: todayPosts } = await env.DB.prepare(
                        "SELECT posted_at FROM post_history WHERE page_id = ? AND bot_id = ? AND (status IN ('success','posting') OR (status = 'failed' AND trigger_source = 'cron'))"
                    ).bind(page.id, botId).all() as { results: Array<{ posted_at: string }> }

                    const getThaiTimeParts = (isoDate: string) => {
                        const d = new Date(isoDate)
                        const timeParts = thaiTimeFormatter.formatToParts(d)
                        const dateParts = thaiDateFormatter.formatToParts(d)
                        const hour = parseInt(timeParts.find(p => p.type === 'hour')?.value || '0', 10)
                        const minute = parseInt(timeParts.find(p => p.type === 'minute')?.value || '0', 10)
                        const year = dateParts.find(p => p.type === 'year')?.value
                        const month = dateParts.find(p => p.type === 'month')?.value
                        const day = dateParts.find(p => p.type === 'day')?.value
                        return {
                            totalMin: hour * 60 + minute,
                            dateStr: `${year}-${month}-${day}`
                        }
                    }

                    // Use a windowed check: a slot is "already posted" if ANY post landed within
                    // [slot - earlyTolerance, slot + lateGrace] today. Previously used exact-minute
                    // match against postedSlots which broke when posts landed late (e.g. slot 19:02
                    // but post landed 19:08, so 19:02 stayed "due" and could fire again).
                    const todayPostMinutes = todayPosts.map(p => getThaiTimeParts(p.posted_at))
                        .filter(pt => pt.dateStr === todayStr)
                        .map(pt => pt.totalMin)
                        .sort((a, b) => a - b)

                    const isSlotAlreadyPosted = (slotTotalMin: number) => {
                        const windowStart = slotTotalMin - slotEarlyToleranceMinutes
                        const windowEnd = slotTotalMin + slotLateGraceMinutes
                        return todayPostMinutes.some(m => m >= windowStart && m <= windowEnd)
                    }

                    const dueSlots = scheduledTimes.filter(({ totalMin }) => {
                        if (isSlotAlreadyPosted(totalMin)) return false
                        const lagMinutes = nowMinutes - totalMin
                        return lagMinutes >= -slotEarlyToleranceMinutes && lagMinutes <= slotLateGraceMinutes
                    })
                    const matchedSlot = dueSlots.length > 0
                        ? dueSlots.reduce((latest, slot) => (slot.totalMin > latest.totalMin ? slot : latest), dueSlots[0])
                        : null

                    if (!matchedSlot) {
                        const unpostedFutureSlot = scheduledTimes.find((slot) => !isSlotAlreadyPosted(slot.totalMin) && slot.totalMin >= nowMinutes) || null
                        const unpostedPastSlot = [...scheduledTimes].reverse().find((slot) => !isSlotAlreadyPosted(slot.totalMin) && slot.totalMin < nowMinutes) || null
                        const hintSlot = unpostedFutureSlot || unpostedPastSlot
                        const hintText = hintSlot ? formatSlot(hintSlot) : 'none'
                        console.log(
                            `[CRON] Page ${page.name}: skip (no due slot, now=${nowMinutes}m, grace=${slotLateGraceMinutes}m, next=${hintText}, slots=${rawSchedule})`
                        )
                        continue
                    }

                    const slotLagMinutes = nowMinutes - matchedSlot.totalMin
                    const slotLagText = slotLagMinutes >= 0 ? `+${slotLagMinutes}` : `${slotLagMinutes}`
                    console.log(`[CRON] Page ${page.name}: posting for slot ${formatSlot(matchedSlot)} (lag ${slotLagText}m)`)
                    dedupKey = `_cron_dedup/${page.id}/${todayStr}/${matchedSlot.hour}_${matchedSlot.minute}`
                }

                const pagePostingLockKey = await tryAcquirePostingLock(env.DB, {
                    scope: 'page',
                    namespaceId: botId,
                    pageId: String(page.id || ''),
                })
                if (!pagePostingLockKey) {
                    console.log(`[CRON] Page ${page.name}: skip (page lock busy)`)
                    continue
                }
                let videoPostingLockKey: string | null = null

                try {
                    const botBucket = new BotBucket(env.BUCKET, botId) as unknown as R2Bucket
                    const scheduleLockAcquired = await tryAcquireCronScheduleLock(env.DB, dedupKey, botId, String(page.id || ''))
                    if (!scheduleLockAcquired) {
                        console.log(`[CRON] Page ${page.name}: already locked for this schedule window`)
                        continue
                    }
                    const existingDedup = await botBucket.head(dedupKey)
                    if (existingDedup) {
                        console.log(`[CRON] Page ${page.name}: already posted for this schedule window (dedup key exists)`)
                        continue
                    }
                    await botBucket.put(dedupKey, nowISO, {
                        httpMetadata: { contentType: 'text/plain' },
                        customMetadata: { createdAt: nowISO }
                    })

                    let shortlinkEnabled = shortlinkEnabledByNamespace.get(botId)
                    if (typeof shortlinkEnabled !== 'boolean') {
                        shortlinkEnabled = await isSystemGalleryEnabledForNamespace(env.DB, botId)
                        shortlinkEnabledByNamespace.set(botId, shortlinkEnabled)
                    }
                    if (!shortlinkEnabled) {
                        await env.DB.prepare(
                            `UPDATE post_history
                             SET status = 'failed',
                                 error_message = 'shortlink_disabled_gallery_empty',
                                 comment_status = CASE WHEN comment_status = 'pending' THEN 'failed' ELSE comment_status END,
                                 comment_error = CASE WHEN comment_status = 'pending' THEN 'shortlink_disabled_gallery_empty' ELSE comment_error END
                             WHERE bot_id = ? AND page_id = ? AND status = 'posting'`
                        ).bind(botId, page.id).run().catch(() => { })
                        console.log(`[CRON] Page ${page.name}: skip (shortlink disabled for namespace ${botId})`)
                        await botBucket.delete(dedupKey).catch(() => { })
                        await releaseCronScheduleLock(env.DB, dedupKey, botId).catch(() => { })
                        continue
                    }

                    // Read posting order fresh for every page selection. This is intentionally
                    // not cached: when a member changes Settings > Post, the next cron/force
                    // selection must obey the live namespace setting exactly.
                    const postingOrderSettings = await resolveEffectivePagePostingOrder(env.DB, botId, String(page.id || ''))
                    const postingOrder = postingOrderSettings.postingOrder
                    const postingOrderSource = postingOrderSettings.source
                    console.log(`[CRON] Page ${page.name}: posting_order=${postingOrder} source=${postingOrderSource}`)
                    const fastClaim = await claimFastGalleryVideoForPosting({
                        env,
                        namespaceId: botId,
                        pageId: String(page.id || ''),
                        postingOrder,
                        skipFailedTodayThaiDate: todayStr,
                    })
                    console.log(`[CRON] Page ${page.name}: fast_gallery source=${fastClaim.stats.source} candidates=${fastClaim.stats.candidateTotal} scanned=${fastClaim.stats.scanned} pages=${fastClaim.stats.pages} elapsed_ms=${fastClaim.stats.elapsedMs}`)
                    if (!fastClaim.picked) {
                        console.log(`[CRON] Page ${page.name}: no unposted gallery video left (fast candidates=${fastClaim.stats.candidateTotal}, scanned=${fastClaim.stats.scanned})`)
                        await botBucket.delete(dedupKey).catch(() => { }) // Clean up dedup key
                        await releaseCronScheduleLock(env.DB, dedupKey, botId).catch(() => { })
                        continue
                    }
                    const pickedVideoEntry = fastClaim.picked
                    const pickedVideo = pickedVideoEntry.video
                    videoPostingLockKey = pickedVideoEntry.videoLockKey
                    const unpostedId = String(pickedVideo.id || '').trim()
                    console.log(`[CRON] Page ${page.name}: fast_gallery picked=${unpostedId} candidates=${fastClaim.stats.candidateTotal} scanned=${fastClaim.stats.scanned}`)
                    const sourceFingerprint = normalizeNamespaceVideoSourceFingerprint(
                        pickedVideo.sourceFingerprint || pickedVideo.source_fingerprint,
                    )
                    const sourceNamespaceId = String(pickedVideo.sourceNamespaceId || pickedVideo.source_namespace_id || botId).trim() || botId
                    const duplicateCheck = await ensurePageVideoNeverPosted({
                        db: env.DB,
                        namespaceId: botId,
                        pageId: String(page.id || ''),
                        videoId: unpostedId,
                        sourceFingerprint,
                    })
                    if (duplicateCheck.ok === false) {
                        await releasePostingLock(env.DB, videoPostingLockKey)
                        videoPostingLockKey = null
                        console.log(`[CRON] Page ${page.name}: skip ${unpostedId} (already posted history=${duplicateCheck.historyId || 'n/a'})`)
                        continue
                    }
                    // Get video metadata
                    const sourceBucket = sourceNamespaceId === botId
                        ? botBucket
                        : new BotBucket(env.BUCKET, sourceNamespaceId) as unknown as R2Bucket
                    const meta = await loadLatestVideoMetaForPosting(sourceBucket, unpostedId, pickedVideo)
                    // === SHORTLINK BEFORE POSTING: ONLY for admin namespace. Members use raw links from gallery as-is ===
                    const [isAdminManaged, shortlinkRequired] = await Promise.all([
            isNamespaceShortlinkAdminManaged(env.DB, botId).catch(() => false),
            isNamespaceAffiliateShortlinkRequired(env.DB, botId).catch(() => false),
        ])
        const isAdminNamespace = isAdminManaged && shortlinkRequired
        const rawShopeeLink = normalizeMetaShopeeLink(meta) || ''
        const shopeeShortlinkTrace: { utmSource?: string | null; status?: 'disabled' | 'shortened' | 'fallback'; error?: string | null } = {}
        let normalizedShopeeLink = rawShopeeLink
        if (isAdminNamespace && rawShopeeLink) {
            try {
                normalizedShopeeLink = await shortenShopeeLinkForNamespace({
                    env,
                    namespaceId: botId,
                    pageId: String(page.id || ''),
                    shopeeLink: rawShopeeLink,
                    logPrefix: `CRON ${page.name} SHORTLINK`,
                    trace: shopeeShortlinkTrace,
                })
                console.log(`[CRON] Page ${page.name}: shopee shortlink ${shopeeShortlinkTrace.status} — ${rawShopeeLink.slice(0, 80)} → ${normalizedShopeeLink.slice(0, 80)}`)
            } catch (e) {
                const errMsg = e instanceof Error ? e.message : String(e)
                shopeeShortlinkTrace.status = 'fallback'
                shopeeShortlinkTrace.error = errMsg
                console.error(`[CRON] Page ${page.name}: shopee shortlink failed — ${errMsg}`)
            }
        } else if (rawShopeeLink) {
            // Member namespace: use raw link as-is, mark as disabled (no conversion needed)
            shopeeShortlinkTrace.status = 'disabled'
            console.log(`[CRON] Page ${page.name}: member namespace — using raw shopee link as-is`)
        }
        const normalizedShopeeUtmSource = shopeeShortlinkTrace.utmSource ?? null
        const normalizedShopeeStatus = shopeeShortlinkTrace.status ?? null
        const normalizedShopeeError = shopeeShortlinkTrace.error ?? null
        const normalizedShopeeUtmMatch = null
        const publicUrl = metaToString(meta, 'publicUrl')
        const rawLazadaLink = normalizeMetaLazadaLink(meta) || metaToString(meta, 'lazadaLink')
        const pageOneCardEnabled = Number(page.onecard_enabled || 0) === 1
        const pageOneCardLinkMode = normalizePageOneCardLinkMode(page.onecard_link_mode)
        const pageOneCardCta = normalizePageOneCardCta(page.onecard_cta)
        const pageCaptionLinkEnabled = Number(page.caption_link_enabled || 0) === 1
        // Posting backend mirrors the force-post path: explicit per-page token source
        // selection wins. Electron Ads bridge ('post-reels-token-ads') and the legacy
        // ads_publish_enabled flag route through /api/dashboard/create-ad; CloakBrowser/
        // session-cookie bridge ('post-reels-token-cloak') routes the organic Reel through
        // the CloakBrowser bridge /post route. Never silently fall back to the stored
        // token when a non-stored source is explicitly selected.
        // Power Editor / CloakBrowser is admin-owned only — mirror the force-post guard so the
        // scheduled auto-post path also pins non-admin namespaces to stored_token and never
        // hands a member page to the session bridge (restrictCloakToAdminNamespace).
        const namespaceIsAdminOwned = await isNamespaceShortlinkAdminManaged(env.DB, String(botId || '')).catch(() => false)
        const pagePostingTokenSource = restrictCloakToAdminNamespace(
            normalizePagePostingTokenSource(page.posting_token_source),
            namespaceIsAdminOwned,
        )
        // Per-page Accounts Bridge posting account UID — threaded into the stored-token Facebook Lite
        // refresh (blank → unchanged auto-discovery). Mirror of the force-post path.
        const configuredPostingProfileUid = sanitizePostingProfileUid(page.posting_profile_uid)
        const pageAdsPublishLegacyFlag = Number(page.ads_publish_enabled || 0) === 1
        // Gate the legacy ads_publish_enabled → OneCard/create-ad bridge promotion on namespace
        // ownership (mirror of the force-post guard): the bridge route is admin-owned only.
        const pagePostingRoute: PostingRoute = resolvePostingRoute({ source: pagePostingTokenSource, oneCardEnabled: pageOneCardEnabled, adsPublishLegacyFlag: pageAdsPublishLegacyFlag && namespaceIsAdminOwned })
        const pageAdsPublishEnabled = pagePostingRoute === 'cloak_onecard_bridge'
        const pageCloakPostSelected = pagePostingRoute === 'cloak_organic_reel'
        // Comment backend chosen independently of the posting route (see force-post).
        const pageCommentTokenSource: PageCommentTokenSource = restrictCloakToAdminNamespace(
            normalizePageCommentTokenSource(
                page.comment_token_source,
                defaultCommentSourceForRoute(pagePostingRoute),
            ),
            namespaceIsAdminOwned,
        )
        const commentViaCloakBridge = pageCommentTokenSource === 'cloak_browser'
        if (pageAdsPublishEnabled || pageCloakPostSelected || commentViaCloakBridge) {
            console.log(`[CRON] page=${String(page.id || '')} posting_token_source=${pagePostingTokenSource} route=${pagePostingRoute} source_hint=${postingSourceHint(pagePostingRoute)} comment_token_source=${pageCommentTokenSource} ads_publish_legacy_flag=${pageAdsPublishLegacyFlag} ads_publish=${pageAdsPublishEnabled} cloak=${pageCloakPostSelected}`)
        }
        const commentTemplateRequiresLazada = await namespaceCommentTemplateRequiresLazadaLink(env.DB, botId).catch(() => true)
        const oneCardRequiresLazada = pageOneCardEnabled && pageOneCardCta !== 'NO_BUTTON' && pageOneCardLinkMode === 'lazada'
        const lazadaLinkRequiredForPosting = !!rawLazadaLink && !pageAdsPublishEnabled && !pageCloakPostSelected && (commentTemplateRequiresLazada || oneCardRequiresLazada)
        const lazadaShortlinkTrace: { utmSource?: string | null; memberId?: string | null; status?: 'disabled' | 'shortened' | 'fallback'; error?: string | null } = {}
        let normalizedLazadaLink = rawLazadaLink
        if (isAdminNamespace && rawLazadaLink && lazadaLinkRequiredForPosting) {
            try {
                normalizedLazadaLink = await shortenLazadaLinkForNamespace({
                    env,
                    namespaceId: botId,
                    pageId: String(page.id || ''),
                    lazadaLink: rawLazadaLink,
                    logPrefix: `CRON ${page.name} SHORTLINK`,
                    trace: lazadaShortlinkTrace,
                })
                console.log(`[CRON] Page ${page.name}: lazada shortlink ${lazadaShortlinkTrace.status} — ${rawLazadaLink.slice(0, 80)} → ${normalizedLazadaLink.slice(0, 80)}`)
            } catch (e) {
                const errMsg = e instanceof Error ? e.message : String(e)
                lazadaShortlinkTrace.status = 'fallback'
                lazadaShortlinkTrace.error = errMsg
                console.error(`[CRON] Page ${page.name}: lazada shortlink failed — ${errMsg}`)
            }
        } else if (rawLazadaLink && !lazadaLinkRequiredForPosting) {
            lazadaShortlinkTrace.status = 'disabled'
            console.log(`[CRON] Page ${page.name}: lazada shortlink skipped — not required by comment template or OneCard link mode`)
        } else if (rawLazadaLink) {
            // Member namespace: use raw link as-is, mark as disabled (no conversion needed)
            lazadaShortlinkTrace.status = 'disabled'
            console.log(`[CRON] Page ${page.name}: member namespace — using raw lazada link as-is`)
        }
        const normalizedLazadaMemberId = String(lazadaShortlinkTrace.memberId || metaToString(meta, 'lazadaMemberId') || metaToString(meta, 'lazada_member_id') || '').trim()

        // === BLOCK POSTING if shortlink failed ===
        const combinedConversionStatus = (shopeeShortlinkTrace.status === 'fallback' || lazadaShortlinkTrace.status === 'fallback')
            ? 'fallback'
            : (shopeeShortlinkTrace.status === 'shortened' || lazadaShortlinkTrace.status === 'shortened')
                ? 'shortened'
                : (shopeeShortlinkTrace.status === 'disabled' || lazadaShortlinkTrace.status === 'disabled')
                    ? 'disabled'
                    : null
        const combinedConversionError = shopeeShortlinkTrace.error || lazadaShortlinkTrace.error || null
        const shopeeShortlinkFailed = rawShopeeLink && shopeeShortlinkTrace.status !== 'shortened' && shopeeShortlinkTrace.status !== 'disabled'
        const lazadaShortlinkFailed = lazadaLinkRequiredForPosting && lazadaShortlinkTrace.status !== 'shortened' && lazadaShortlinkTrace.status !== 'disabled'
        if (shopeeShortlinkFailed || lazadaShortlinkFailed) {
            const failedPlatforms = [shopeeShortlinkFailed ? 'shopee' : '', lazadaShortlinkFailed ? 'lazada' : ''].filter(Boolean).join('+')
            const shortlinkErrorMsg = `shortlink_failed:${failedPlatforms} — ${combinedConversionError || 'unknown'}`
            console.error(`[CRON] Page ${page.name}: BLOCKED — ${shortlinkErrorMsg}`)
            // Record failed attempt in post_history
            await ensurePostHistoryTraceColumns(env.DB)
            await env.DB.prepare(
                "INSERT INTO post_history (page_id, video_id, posted_at, status, trigger_source, bot_id, error_message, shopee_link, lazada_link, shortlink_conversion_status, shortlink_conversion_error, comment_status, source_fingerprint) VALUES (?, ?, ?, 'failed', 'cron', ?, ?, ?, ?, 'failed', ?, 'not_attempted', ?)"
            ).bind(
                page.id, unpostedId, nowISO, botId,
                shortlinkErrorMsg,
                rawShopeeLink || null, rawLazadaLink || null,
                combinedConversionError || 'shortlink_failed',
                sourceFingerprint || null,
            ).run().catch((err) => {
                console.error(`[CRON] Page ${page.name}: failed to insert shortlink-failure history row: ${err instanceof Error ? err.message : String(err)}`)
            })
            await releasePostingLock(env.DB, videoPostingLockKey).catch(() => { })
            videoPostingLockKey = null
            await botBucket.delete(dedupKey).catch(() => { })
            await releaseCronScheduleLock(env.DB, dedupKey, botId).catch(() => { })
            cronStats.pagesFailed++
            continue
        }

        // Generate short caption from script (no Shopee link)
        let apiKeys = geminiApiKeysByNamespace.get(botId)
        if (!apiKeys) {
            apiKeys = await resolveNamespaceGeminiApiKeys(env.DB, botId)
            geminiApiKeysByNamespace.set(botId, apiKeys)
        }
        const hasManualCaption = !!normalizeManualCaption(meta.manualCaption || meta.caption || '')
        const title = metaToString(meta, 'title')
        const script = metaToString(meta, 'script')
        if (!hasManualCaption && !title && script && apiKeys.length === 0) {
            console.log(`[CRON] Page ${page.name}: skip ${unpostedId} (Gemini API key กลางของระบบยังไม่ได้ตั้งค่า)`)
            await botBucket.delete(dedupKey).catch(() => { })
            await releaseCronScheduleLock(env.DB, dedupKey, botId).catch(() => { })
            continue
        }
        const geminiModel = env.GEMINI_MODEL || 'gemini-3-flash-preview'
        const caption = await buildPostingCaptionFromMeta(meta, apiKeys, geminiModel)

        // Handle legacy publicUrls without botId or wrong domain
        const realVideoUrl = resolvePostingVideoDownloadUrl(env, sourceNamespaceId, unpostedId, publicUrl)
        if (!realVideoUrl) {
            throw new Error('Video public URL missing')
        }
        let postingVideoUrl = realVideoUrl
        let avatarAppliedForBridge = false
        let avatarVersionForBridge = ''
        if (pageAdsPublishEnabled || pageCloakPostSelected || pageOneCardEnabled) {
            const prepared = await prepareAvatarComposedPostingVideo({
                env,
                db: env.DB,
                bucket: botBucket,
                namespaceId: botId,
                pageId: String(page.id || ''),
                videoId: unpostedId,
                baseVideoUrl: realVideoUrl,
                logPrefix: `CRON ${page.name} AVATAR`,
            })
            postingVideoUrl = prepared.videoUrl
            avatarAppliedForBridge = prepared.avatarApplied
            avatarVersionForBridge = prepared.avatarVersion
        }

        console.log(`[CRON] Page ${page.name}: posting video ${unpostedId}${avatarAppliedForBridge ? ` avatar=${avatarVersionForBridge}` : ''} — caption: ${caption}`)

        const tokenCandidates = await ensurePageTokenCandidates({
            env,
            db: env.DB,
            namespaceId: botId,
            pageId: String(page.id || ''),
            pageName: String(page.name || ''),
            primaryToken: String(page.access_token || ''),
            logPrefix: `CRON ${page.name}`,
        })
        const commentTokenCandidates = tokenCandidates.commentTokens
        const pageCommentToken = commentTokenCandidates[0] || null
        const fallbackPostTokenCandidates = tokenCandidates.postTokens.length > 0
            ? tokenCandidates.postTokens
            : normalizePostTokenPool([String(page.access_token || '')])
        const primaryPostingTokenCandidates = buildPrimaryPostingTokenCandidates({
            primaryToken: String(page.access_token || ''),
            postTokens: fallbackPostTokenCandidates,
            commentTokens: commentTokenCandidates,
        })
        await ensurePostHistoryTraceColumns(env.DB)
        const commentTokenHint = deriveCommentTokenHint(commentTokenCandidates[0] || null)
        // Cloak source must never derive its post hint/profile from a stored/manual token.
        const initialPostTokenHint = pageCloakPostSelected ? 'cloak_session_bridge' : deriveCommentTokenHint(primaryPostingTokenCandidates[0] || null)
        const initialPostProfile = await resolvePostHistoryProfileByToken(env, pageCloakPostSelected ? null : (primaryPostingTokenCandidates[0] || null))
        const hasCommentToken = commentTokenCandidates.length > 0 && !!String(pageCommentToken || '').trim()
        if (primaryPostingTokenCandidates.length === 0) {
            throw new Error('access_token_missing')
        }
        const initialCommentState = getInitialCommentTraceState(!!normalizedShopeeLink)
        const initialCommentStatus = initialCommentState.status
        const initialCommentError = initialCommentState.error
        // 3. Record attempt BEFORE posting (prevents duplicate posts if FB succeeds but D1 fails after)
        const inserted = await env.DB.prepare(
            'INSERT INTO post_history (page_id, video_id, posted_at, status, trigger_source, bot_id, post_token_hint, post_profile_id, post_profile_name, comment_status, comment_token_hint, comment_error, comment_fb_id, shopee_link, lazada_link, lazada_member_id, shortlink_utm_source, shortlink_status, shortlink_error, shortlink_expected_utm_id, shortlink_utm_match, shortlink_conversion_status, shortlink_conversion_error, source_fingerprint) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)'
        ).bind(
            page.id,
            unpostedId,
            nowISO,
            'posting',
            'cron',
            botId,
            initialPostTokenHint,
            initialPostProfile.profileId,
            initialPostProfile.profileName,
            initialCommentStatus,
            commentTokenHint,
            initialCommentError,
            null,
            normalizedShopeeLink || null,
            normalizedLazadaLink || null,
            normalizedLazadaMemberId || null,
            normalizedShopeeUtmSource,
            normalizedShopeeStatus,
            normalizedShopeeError,
            null,
            normalizedShopeeUtmMatch,
            combinedConversionStatus,
            combinedConversionError,
            sourceFingerprint || null,
        ).run()
        const cronHistoryId = Number(inserted.meta?.last_row_id || 0) || null

        const affiliateVerification = await verifyAffiliateLinksForPosting({
            env,
            namespaceId: botId,
            pageId: String(page.id || ''),
            shopeeLink: normalizedShopeeLink,
            lazadaLink: normalizedLazadaLink,
            requireLazadaLink: lazadaLinkRequiredForPosting,
            logPrefix: `CRON ${page.name} VERIFY`,
        })
        if (cronHistoryId) {
            await updatePostHistoryAffiliateVerificationById(env.DB, cronHistoryId, affiliateVerification)
        }
        if (!affiliateVerification.ok) {
            if (cronHistoryId) {
                await env.DB.prepare(
                    "UPDATE post_history SET status = 'failed', error_message = ?, comment_status = 'not_attempted' WHERE id = ? AND status = 'posting'"
                ).bind(
                    affiliateVerification.error || 'affiliate_verification_failed',
                    cronHistoryId,
                ).run().catch(() => { })
            }
            console.error(`[CRON] Page ${page.name}: affiliate verification failed - ${affiliateVerification.error || 'unknown'}`)
            await botBucket.delete(dedupKey).catch(() => { })
            await releaseCronScheduleLock(env.DB, dedupKey, botId).catch(() => { })
            continue
        }

        // The stored/manual comment-token preflight only applies when the comment will be
        // sent with a STORED page token (comment_token_source='stored_token'). When comments
        // go through the CloakBrowser bridge they are page-authored with no stored token, so
        // skip the preflight regardless of posting route. (Comment success/failure is
        // recorded from the bridge/backlog result in the branches below.)
        if (!commentViaCloakBridge) {
            const affiliateCommentPreflight = validateAffiliateCommentPreflight({
                shopeeLink: normalizedShopeeLink,
                hasCommentToken,
            })
            if (!affiliateCommentPreflight.ok) {
                const errorCode = affiliateCommentPreflight.error || 'affiliate_comment_not_configured'
                if (cronHistoryId) {
                    await env.DB.prepare(
                        "UPDATE post_history SET status = 'failed', error_message = ?, comment_status = 'not_attempted', comment_error = ? WHERE id = ? AND status = 'posting'"
                    ).bind(errorCode, errorCode, cronHistoryId).run().catch(() => { })
                }
                console.error(`[CRON] Page ${page.name}: blocked before publish - ${errorCode}`)
                await botBucket.delete(dedupKey).catch(() => { })
                await releaseCronScheduleLock(env.DB, dedupKey, botId).catch(() => { })
                cronStats.pagesFailed++
                continue
            }
        }

        await env.DB.prepare('UPDATE pages SET last_post_at = ? WHERE id = ? AND bot_id = ?').bind(nowISO, page.id, botId).run()

        let fbVideoId = ''
        // Cron normal-post path always uses page post tokens from settings (organic Reel).
        let postingTokenUsed = pageAdsPublishEnabled
            ? 'ads_publish'
            : pageOneCardEnabled
                ? 'onecard'
                : String(primaryPostingTokenCandidates[0] || page.access_token || '').trim()

        // caption_link_enabled: prepend the managed Shopee shortlink as the first caption
        // line of the FB post, for every posting route (organic Reel, OneCard publish, and the
        // CloakBrowser session bridge). The Ads/create-ad route prepends its own post-specific
        // managed link inside /api/dashboard/create-ad, so the raw caption is forwarded there.
        const publishDescription = resolvePublishCaption({
            caption,
            captionLinkEnabled: pageCaptionLinkEnabled,
            shopeeLink: normalizedShopeeLink,
        })

        // AUTO-ADS MODE (per-page toggle, admin-only enforced at PUT).
        // When enabled, skip the normal Reel post entirely and route through
        // /api/dashboard/create-ad which handles: re-shorten (admin-namespace already
        // verified by PUT gate) → electron /create-ad (upload + creative + adset copy
        // + ad create + publish-to-page) → comment with shortlink using dedicated
        // comment token. Produces an ad post visible on the page feed + paid ad.
        if (pageAdsPublishEnabled) {
            try {
                // Paranoid runtime re-check: toggle could have been persisted before the
                // admin-only gate landed, or namespace could have been downgraded.
                const namespaceIsAdminManaged = await isNamespaceShortlinkAdminManaged(env.DB, botId).catch(() => false)
                if (!namespaceIsAdminManaged) {
                    throw new Error('ads_publish_admin_only_runtime_check_failed')
                }

                // POST-FIRST (opt-in, same gate as force-post): page post → mint → promote
                // with final link CTA → comment. Default OFF.
                if (oneCardPostFirstEnabled(env)) {
                    const pf = await runOneCardPostFirstAds({
                        env,
                        pageId: String(page.id || ''),
                        namespaceId: botId,
                        caption,
                        videoUrl: postingVideoUrl,
                        sourceVideoId: unpostedId,
                        rawShopeeLink,
                        managedShopeeLink: normalizedShopeeLink,
                        historyId: cronHistoryId,
                        skipComment: false,
                        commentSource: pageCommentTokenSource,
                        hasCommentToken,
                        storedCommentTokenHint: deriveCommentTokenHint(pageCommentToken),
                        logPrefix: `CRON ${page.name}`,
                    })
                    if (!pf.ok && !pf.storyId) {
                        throw new Error(String(pf.error || 'ads_post_first_failed'))
                    }
                    if (cronHistoryId) {
                        await env.DB.prepare(
                            "UPDATE post_history SET status=?, fb_post_id=?, fb_reel_url=?, post_token_hint='ads_publish', comment_status=?, comment_fb_id=?, comment_error=?, comment_token_hint=?, comment_delay_seconds=?, comment_due_at=?, shopee_link=?, posted_at=?, error_message=? WHERE id=? AND status='posting'"
                        ).bind(
                            pf.ok ? 'success' : 'failed',
                            pf.confirmedPostId || pf.storyId,
                            pf.fbReelUrl,
                            pf.commentStatus,
                            pf.commentId,
                            pf.commentError,
                            pf.commentTokenHint,
                            pf.commentDelaySeconds,
                            pf.commentDueAt,
                            pf.ctaShortlink || normalizedShopeeLink || null,
                            nowISO,
                            pf.ok ? null : `ads_post_first_partial: ${pf.step || ''}:${pf.error || ''}`.substring(0, 240),
                            cronHistoryId,
                        ).run().catch(() => { })
                    }
                    if (pf.ok && pf.commentStatus === 'pending') {
                        runPendingCommentBacklogSoon(env, Number(cronHistoryId || 0), `CRON ${page.name} POST-FIRST IMMEDIATE-COMMENT`, ctx)
                    }
                    await markNamespaceVideoPosted(env.DB, botId, unpostedId, nowISO)
                    markCachedNamespaceVideoPosted(galleryVideosByNamespace, botId, unpostedId, nowISO)
                    await recordPagePostedVideoGuard(env.DB, {
                        namespaceId: botId, pageId: page.id, videoId: unpostedId,
                        sourceFingerprint, historyId: cronHistoryId, postedAt: nowISO,
                    }).catch(() => { })
                    if (pf.ok) cronStats.pagesPosted++; else cronStats.pagesFailed++
                    console.log(`[CRON] Page ${page.name}: POST-FIRST ADS ${pf.ok ? 'OK' : 'PARTIAL'} — story=${pf.storyId} ad_id=${pf.adId} comment=${pf.commentStatus} promoted_ad_cta_final=${pf.promotedAdCtaFinal} visible_cta_update=${pf.visibleCtaUpdateStatus} visible_page_cta_final=${pf.visiblePageCtaFinal}`)
                    await clearVideoShopeeLink(botBucket, unpostedId)
                    await updateCronRuntimeState(env.DB, {
                        runId, heartbeatAt: new Date().toISOString(),
                        pagesVisited: cronStats.pagesVisited, pagesPosted: cronStats.pagesPosted, pagesFailed: cronStats.pagesFailed,
                    }).catch(() => { })
                    continue
                }

                const workerUrl = String(env.WORKER_URL || 'https://api.pubilo.com').trim().replace(/\/+$/, '')
                const adsResp = await fetchWithTimeout(`${workerUrl}/api/dashboard/create-ad`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        page_id: String(page.id || ''),
                        // unpostedId is an INTERNAL gallery/state id, not a Facebook video
                        // id. Send the downloadable URL so the CloakBrowser bridge uploads the file
                        // instead of doing a Graph GET on the internal id (which 500s).
                        // source_video_id keeps ads naming/history linked to the internal id.
                        video_url: postingVideoUrl,
                        source_video_id: unpostedId,
                        caption,
                        // CTA button → original Shopee product URL (falls back to the
                        // managed link). Comment shortlink → the already managed/shortened
                        // link so create-ad does NOT re-shorten it (double-shorten fails).
                        shopee_url: rawShopeeLink || normalizedShopeeLink,
                        comment_shortlink: normalizedShopeeLink,
                        // Defer the comment so we can re-mint it with sub2=post id /
                        // sub3=page id once story_id exists (see force-post branch).
                        skip_comment: true,
                    }),
                }, 300000, 'cron_ads_publish')
                const adsData = await adsResp.json().catch(() => ({})) as {
                    ok?: boolean
                    error?: string
                    story_id?: string
                    ad_id?: string
                    adset_id?: string
                    commentPosted?: boolean
                    commentId?: string
                }
                if (!adsResp.ok || !adsData?.ok) {
                    throw new Error(String(adsData?.error || `ads_publish_http_${adsResp.status}`))
                }
                const storyId = String(adsData.story_id || '')
                const confirmedPostId = storyId.includes('_') ? storyId.split('_').slice(1).join('_') : storyId
                const fbReelUrl = storyId ? `https://www.facebook.com/${storyId.replace('_', '/posts/')}` : ''

                // create-ad ran with skip_comment, so post the single affiliate comment
                // here with the re-minted link (sub2=post id tail / sub3=page id) once
                // story_id exists. Parity with the force-post ads branch. The ad CTA button
                // remains the pre-story_id link (no sub2/sub3) — documented limitation.
                let cronAdsCommentStatus = 'not_configured'
                let cronAdsCommentId: string | null = null
                let cronAdsCommentError: string | null = null
                let cronAdsCommentShopeeLink = normalizedShopeeLink
                let cronAdsCommentRemint: OneCardCommentShortlinkRemint | null = null
                let cronAdsCommentTokenHint: string | null = commentViaCloakBridge ? 'cloak_session_bridge' : deriveCommentTokenHint(pageCommentToken)
                let cronAdsCommentDelaySeconds: number | null = null
                let cronAdsCommentDueAt: string | null = null
                if (normalizedShopeeLink && storyId) {
                    cronAdsCommentRemint = await remintOneCardCommentShortlink({
                        env,
                        namespaceId: botId,
                        pageId: String(page.id || ''),
                        storyId,
                        fbVideoId: String(adsData.ad_id || storyId || unpostedId),
                        managedShopeeLink: normalizedShopeeLink,
                        historyId: cronHistoryId,
                        logPrefix: `CRON ADS COMMENT-SHORTLINK ${page.name}`,
                    })
                    cronAdsCommentShopeeLink = cronAdsCommentRemint.commentShopeeLink
                    if (commentViaCloakBridge) {
                        // comment_token_source='cloak_browser' (default for an ADS page): comment
                        // as the Page via the bridge. Fails closed; never a stored-token fallback.
                        const cronAdsCommentText = (await buildAffiliateCommentMessage(env.DB, botId, cronAdsCommentShopeeLink).catch(() => '')) || cronAdsCommentShopeeLink
                        const bridged = await sendPageCommentViaCloakBridge({
                            env,
                            pageId: String(page.id || ''),
                            storyId,
                            message: cronAdsCommentText,
                            logPrefix: `CRON ADS ${page.name}`,
                        })
                        cronAdsCommentStatus = bridged.status
                        cronAdsCommentId = bridged.id
                        cronAdsCommentError = bridged.error
                        cronAdsCommentTokenHint = 'cloak_session_bridge'
                    } else if (hasCommentToken) {
                        // comment_token_source='stored_token': defer to the pending backlog
                        // processor (stored page token against the Page story id).
                        cronAdsCommentStatus = 'pending'
                        cronAdsCommentDelaySeconds = getRandomCommentDelaySeconds()
                        cronAdsCommentDueAt = new Date(Date.now() + (cronAdsCommentDelaySeconds * 1000)).toISOString()
                        cronAdsCommentTokenHint = deriveCommentTokenHint(pageCommentToken)
                    } else {
                        cronAdsCommentStatus = 'failed'
                        cronAdsCommentError = 'access_token_missing'
                        cronAdsCommentTokenHint = deriveCommentTokenHint(pageCommentToken)
                    }
                }

                if (cronHistoryId) {
                    await env.DB.prepare(
                        "UPDATE post_history SET status='success', fb_post_id=?, fb_reel_url=?, post_token_hint='ads_publish', comment_status=?, comment_fb_id=?, comment_error=?, comment_token_hint=?, comment_delay_seconds=?, comment_due_at=?, shopee_link=?, posted_at=?, error_message=NULL WHERE id=? AND status='posting'"
                    ).bind(
                        confirmedPostId || storyId,
                        fbReelUrl,
                        cronAdsCommentStatus,
                        cronAdsCommentId,
                        cronAdsCommentError,
                        cronAdsCommentTokenHint,
                        cronAdsCommentDelaySeconds,
                        cronAdsCommentDueAt,
                        cronAdsCommentShopeeLink || normalizedShopeeLink || null,
                        nowISO,
                        cronHistoryId,
                    ).run().catch(() => { })
                }
                if (cronAdsCommentStatus === 'pending') {
                    runPendingCommentBacklogSoon(env, Number(cronHistoryId || 0), `CRON ${page.name} ADS IMMEDIATE-COMMENT`, ctx)
                }
                await markNamespaceVideoPosted(env.DB, botId, unpostedId, nowISO)
                markCachedNamespaceVideoPosted(galleryVideosByNamespace, botId, unpostedId, nowISO)
                await recordPagePostedVideoGuard(env.DB, {
                    namespaceId: botId,
                    pageId: page.id,
                    videoId: unpostedId,
                    sourceFingerprint,
                    historyId: cronHistoryId,
                    postedAt: nowISO,
                }).catch(() => { })
                cronStats.pagesPosted++
                console.log(`[CRON] Page ${page.name}: ADS PUBLISH OK — story=${storyId} ad_id=${adsData.ad_id || ''} comment=${cronAdsCommentStatus} remint=${cronAdsCommentRemint?.reminted ? `sub2=${cronAdsCommentRemint.sub2} sub3=${cronAdsCommentRemint.sub3}` : (cronAdsCommentRemint?.error || 'n/a')}`)
                await clearVideoShopeeLink(botBucket, unpostedId)
                await updateCronRuntimeState(env.DB, {
                    runId,
                    heartbeatAt: new Date().toISOString(),
                    pagesVisited: cronStats.pagesVisited,
                    pagesPosted: cronStats.pagesPosted,
                    pagesFailed: cronStats.pagesFailed,
                }).catch(() => { })
                continue
            } catch (e) {
                const errMsg = e instanceof Error ? e.message : String(e)
                if (cronHistoryId) {
                    await env.DB.prepare(
                        "UPDATE post_history SET status='failed', error_message=?, comment_status='not_attempted' WHERE id=? AND status='posting'"
                    ).bind(`ads_publish_failed: ${errMsg}`, cronHistoryId).run().catch(() => { })
                }
                cronStats.pagesFailed++
                console.error(`[CRON] Page ${page.name}: ADS PUBLISH FAILED — ${errMsg}`)
                await releasePostingLock(env.DB, videoPostingLockKey).catch(() => { })
                videoPostingLockKey = null
                await botBucket.delete(dedupKey).catch(() => { })
                await releaseCronScheduleLock(env.DB, dedupKey, botId).catch(() => { })
                continue
            }
        }

        // CLOAKBROWSER / SESSION-COOKIE BRIDGE ORGANIC POST (source = 'post-reels-token-cloak').
        // Routes the organic Reel through the CloakBrowser session-cookie bridge /post
        // route (NOT the stored token, NOT facebook-token-cloak). Fails closed (no
        // stored-token fallback).
        if (pageCloakPostSelected) {
            try {
                // Cron is automatic, so comment whenever a managed shortlink exists.
                const cloakOneCardWebsiteUrl = pageOneCardEnabled
                    ? pickOneCardWebsiteUrl({ linkMode: pageOneCardLinkMode, shopeeLink: normalizedShopeeLink, lazadaLink: normalizedLazadaLink })
                    : ''
                // Publish FIRST with no inline comment. The bridge would otherwise comment the
                // pre-publish shortlink (blank sub2/sub3 → utm_content=...FBSPCAD----). When
                // comment_token_source='cloak_browser' we re-mint the shortlink with the post id
                // below, then comment via the bridge; stored-token defers to the backlog.
                const cloakResult = await publishReelViaSessionBridge({
                    env,
                    pageId: String(page.id || ''),
                    videoUrl: postingVideoUrl,
                    message: publishDescription,
                    websiteUrl: cloakOneCardWebsiteUrl,
                    cta: pageOneCardCta,
                    commentText: '',
                    logPrefix: `CRON CLOAK-BRIDGE ${page.name}`,
                })
                const confirmedCanonicalPostId = String(cloakResult.postId || '').trim()
                const confirmedPostId = confirmedCanonicalPostId || String(cloakResult.id || '').trim()
                const fbReelUrl = String(cloakResult.permalinkUrl || '').trim()
                let cloakCommentStatus: string
                let cloakCommentFbId: string | null
                let cloakCommentError: string | null
                let cloakCommentTokenHint: string | null
                let cloakCommentDelaySeconds: number | null = null
                let cloakCommentDueAt: string | null = null
                let cloakCommentShopeeLink = normalizedShopeeLink
                if (commentViaCloakBridge) {
                    if (!normalizedShopeeLink) {
                        cloakCommentStatus = 'not_configured'
                        cloakCommentFbId = null
                        cloakCommentError = null
                        cloakCommentTokenHint = 'cloak_session_bridge'
                    } else {
                        // Re-shorten with the post id FIRST so the commented link carries
                        // sub2=post id / sub3=page id, then comment as the Page via the bridge
                        // (fails closed). Mirrors the stored→cloak branch below.
                        let commentShopeeLink = normalizedShopeeLink
                        try {
                            const commentSubIds = buildPostingCommentShortlinkSubIds({
                                canonicalPostId: confirmedCanonicalPostId,
                                fbVideoId: String(cloakResult.id || '').trim(),
                                pageId: page.id,
                                historyId: cronHistoryId,
                                logPrefix: `CRON ${page.name} CLOAK COMMENT-SHORTLINK`,
                            })
                            const reshortened = await resolvePostingShopeeLinkForNamespace({
                                env,
                                namespaceId: botId,
                                pageId: page.id,
                                shopeeLink: normalizedShopeeLink,
                                logPrefix: `CRON ${page.name} CLOAK COMMENT-SHORTLINK`,
                                ...commentSubIds,
                            })
                            if (reshortened) commentShopeeLink = reshortened
                        } catch (reshortenErr) {
                            console.log(`[CRON ${page.name} CLOAK COMMENT-SHORTLINK] re-shorten with post id failed; falling back to preflight link: ${reshortenErr instanceof Error ? reshortenErr.message : String(reshortenErr)}`)
                        }
                        cloakCommentShopeeLink = commentShopeeLink
                        const cloakOverrideText = (await buildAffiliateCommentMessage(env.DB, botId, commentShopeeLink).catch(() => '')) || commentShopeeLink
                        const bridged = await sendPageCommentViaCloakBridge({
                            env,
                            pageId: String(page.id || ''),
                            storyId: buildPageStoryId(String(page.id || ''), confirmedPostId),
                            message: cloakOverrideText,
                            logPrefix: `CRON CLOAK-COMMENT ${page.name}`,
                        })
                        cloakCommentStatus = bridged.status
                        cloakCommentFbId = bridged.id
                        cloakCommentError = bridged.error
                        cloakCommentTokenHint = 'cloak_session_bridge'
                    }
                } else {
                    // comment_token_source='stored_token': defer to the pending backlog
                    // (stored page token against the Page story id). The backlog re-mints the
                    // shortlink with the post id itself.
                    const cloakCommentText = normalizedShopeeLink
                        ? await buildAffiliateCommentMessage(env.DB, botId, normalizedShopeeLink).catch(() => '')
                        : ''
                    cloakCommentFbId = null
                    if (!cloakCommentText) {
                        cloakCommentStatus = 'not_configured'
                        cloakCommentError = null
                    } else if (hasCommentToken) {
                        cloakCommentStatus = 'pending'
                        cloakCommentError = null
                        cloakCommentDelaySeconds = getRandomCommentDelaySeconds()
                        cloakCommentDueAt = new Date(Date.now() + (cloakCommentDelaySeconds * 1000)).toISOString()
                    } else {
                        cloakCommentStatus = 'failed'
                        cloakCommentError = 'access_token_missing'
                    }
                    cloakCommentTokenHint = deriveCommentTokenHint(pageCommentToken)
                }
                if (cronHistoryId) {
                    await env.DB.prepare(
                        "UPDATE post_history SET status='success', fb_post_id=?, fb_reel_url=?, post_token_hint='cloak_session_bridge', comment_status=?, comment_fb_id=?, comment_error=?, comment_token_hint=?, comment_delay_seconds=?, comment_due_at=?, shopee_link=?, posted_at=?, error_message=NULL WHERE id=? AND status='posting'"
                    ).bind(confirmedPostId, fbReelUrl, cloakCommentStatus, cloakCommentFbId, cloakCommentError, cloakCommentTokenHint, cloakCommentDelaySeconds, cloakCommentDueAt, cloakCommentShopeeLink || normalizedShopeeLink || null, nowISO, cronHistoryId).run().catch(() => { })
                }
                if (cloakCommentStatus === 'pending') {
                    runPendingCommentBacklogSoon(env, Number(cronHistoryId || 0), `CRON ${page.name} CLOAK IMMEDIATE-COMMENT`, ctx)
                }
                await markNamespaceVideoPosted(env.DB, botId, unpostedId, nowISO)
                markCachedNamespaceVideoPosted(galleryVideosByNamespace, botId, unpostedId, nowISO)
                await recordPagePostedVideoGuard(env.DB, {
                    namespaceId: botId,
                    pageId: page.id,
                    videoId: unpostedId,
                    sourceFingerprint,
                    historyId: cronHistoryId,
                    postedAt: nowISO,
                }).catch(() => { })
                cronStats.pagesPosted++
                console.log(`[CRON] Page ${page.name}: CLOAK-BRIDGE POST OK — post=${confirmedPostId} comment=${cloakCommentStatus}`)
                await clearVideoShopeeLink(botBucket, unpostedId)
                await updateCronRuntimeState(env.DB, {
                    runId,
                    heartbeatAt: new Date().toISOString(),
                    pagesVisited: cronStats.pagesVisited,
                    pagesPosted: cronStats.pagesPosted,
                    pagesFailed: cronStats.pagesFailed,
                }).catch(() => { })
                continue
            } catch (e) {
                const errMsg = e instanceof Error ? e.message : String(e)
                if (cronHistoryId) {
                    await env.DB.prepare(
                        "UPDATE post_history SET status='failed', error_message=?, comment_status='not_attempted' WHERE id=? AND status='posting'"
                    ).bind(`cloak_post_failed: ${errMsg}`, cronHistoryId).run().catch(() => { })
                }
                cronStats.pagesFailed++
                console.error(`[CRON] Page ${page.name}: CLOAK POST FAILED — ${errMsg}`)
                await releasePostingLock(env.DB, videoPostingLockKey).catch(() => { })
                videoPostingLockKey = null
                await botBucket.delete(dedupKey).catch(() => { })
                await releaseCronScheduleLock(env.DB, dedupKey, botId).catch(() => { })
                continue
            }
        }

        try {
            // Download video and publish via the preferred page-scoped token pool first.
            const videoResp = await fetchWithTimeout(realVideoUrl, {}, 60000, 'cron_download_video')
            if (!videoResp.ok) throw new Error(`Fetch video failed with status ${videoResp.status}`)
            let videoBuffer = await videoResp.arrayBuffer()
            if (videoBuffer.byteLength < 100000) throw new Error(`Video too small (${videoBuffer.byteLength} bytes). Download failed.`)
            let avatarApplied = false
            let avatarVersion = ''
            if (!pageOneCardEnabled && !pageAdsPublishEnabled) {
                const avatarSettings = await getPageAvatarSettings(env.DB, page.id).catch(() => null)
                if (avatarSettings?.enabled && !TEMP_DISABLE_AVATAR_COMPOSE_FOR_POSTING) {
                    if (!avatarSettings.videoKey) throw new Error('avatar_compose_failed: avatar_video_key_missing')
                    const avatarHead = await botBucket.head(avatarSettings.videoKey).catch(() => null)
                    if (!avatarHead) throw new Error('avatar_compose_failed: avatar_video_missing')
                    const avatarVideoUrl = buildAvatarObjectUrl(env, botId, avatarSettings.videoKey)
                    if (!avatarVideoUrl) throw new Error('avatar_compose_failed: avatar_url_missing')
                    try {
                        const parsedAvatarUrl = new URL(avatarVideoUrl)
                        if (!['http:', 'https:'].includes(parsedAvatarUrl.protocol)) {
                            throw new Error('invalid_protocol')
                        }
                    } catch {
                        throw new Error('avatar_compose_failed: avatar_url_invalid')
                    }
                    videoBuffer = await composeAvatarVideoForPosting({
                        env,
                        baseVideoUrl: realVideoUrl,
                        avatarVideoUrl,
                        chromakeySimilarity: avatarSettings.chromakeySimilarity,
                        chromakeyBlend: avatarSettings.chromakeyBlend,
                    })
                    avatarApplied = true
                    avatarVersion = avatarSettings.version || avatarSettings.updatedAt || 'v1'
                    console.log(`[CRON] Page ${page.name}: avatar applied version=${avatarVersion}`)
                }
            }
            const postingThumbnail = pageOneCardEnabled
                ? null
                : await loadPostingThumbnailAsset({
                    env,
                    namespaceId: sourceNamespaceId,
                    videoId: unpostedId,
                }).catch(() => null)
            const oneCardWebsiteUrl = pickOneCardWebsiteUrl({
                linkMode: pageOneCardLinkMode,
                shopeeLink: normalizedShopeeLink,
                lazadaLink: normalizedLazadaLink,
            })
            // Real organic Page reel via the STORED Facebook Lite (EAAD6V) token (Worker Graph +
            // Facebook Lite bridge fallback) — never the ad account / Power Editor. Used as the
            // default stored_token path AND as the OneCard ad-permission-failure fallback below.
            const publishStoredFacebookLiteReel = () => publishReelWithCommentTokenPrimaryFallbackAndLiteRefresh({
                env,
                db: env.DB,
                namespaceId: botId,
                pageId: String(page.id || ''),
                pageName: String(page.name || ''),
                commentTokens: commentTokenCandidates,
                postTokens: fallbackPostTokenCandidates,
                videoBuffer,
                thumbnailBuffer: postingThumbnail?.buffer || null,
                thumbnailContentType: postingThumbnail?.contentType || '',
                description: publishDescription,
                logPrefix: `CRON ${page.name}`,
                preferVideoReelsFirst: true,
                configuredPostingProfileUid,
                reloadTokens: async () => {
                    const refreshed = await ensurePageTokenCandidates({
                        env,
                        db: env.DB,
                        namespaceId: botId,
                        pageId: String(page.id || ''),
                        pageName: String(page.name || ''),
                        primaryToken: String(page.access_token || ''),
                        logPrefix: `CRON ${page.name} RELOAD`,
                    })
                    const post = refreshed.postTokens.length > 0
                        ? refreshed.postTokens
                        : normalizePostTokenPool([String(page.access_token || '')])
                    return { commentTokens: refreshed.commentTokens, postTokens: post }
                },
            })

            // Facebook Lite (EAAD6V) stored tokens never use the ad account / OneCard / Power Editor:
            // publish the organic Page reel directly (/{page}/videos lane). Non-Lite OneCard unchanged.
            const useOneCardForThisPost = pageOneCardEnabled && !isFacebookLitePageToken(primaryPostingTokenCandidates[0] || '')
            let reelResult: { id: string; postId: string; permalinkUrl: string; postingToken: string }
            if (useOneCardForThisPost) {
                try {
                    reelResult = await publishVideoViaOneCard({
                        env,
                        pageId: String(page.id || ''),
                        videoUrl: postingVideoUrl,
                        message: publishDescription,
                        websiteUrl: oneCardWebsiteUrl,
                        cta: pageOneCardCta,
                        logPrefix: `CRON ${page.name} ONECARD`,
                    })
                } catch (oneCardErr) {
                    // OneCard = cloak-fb-bridge ad-account/create-ad (Power Editor). A stored Facebook
                    // Lite (EAAD6V) token cannot drive the ad account, so an ad-permission failure must
                    // not burn the row: fall back to a REAL organic Page reel via EAAD6V when a stored
                    // token exists (pure admin/CloakBrowser OneCard pages still fail closed).
                    const oneCardMsg = parseFacebookErrorLike(oneCardErr)?.message || (oneCardErr instanceof Error ? oneCardErr.message : String(oneCardErr))
                    const haveStoredPostToken = normalizePostTokenPool(fallbackPostTokenCandidates).length > 0
                    if (!shouldFallbackToOrganicAfterOneCardFailure({ haveStoredPostToken, error: oneCardMsg })) throw oneCardErr
                    console.warn(`[CRON ${page.name}] OneCard publish failed (${oneCardMsg}); falling back to stored Facebook Lite organic Page reel (EAAD6V), not Power Editor`)
                    reelResult = await publishStoredFacebookLiteReel()
                }
            } else {
                reelResult = await publishStoredFacebookLiteReel()
            }
            postingTokenUsed = reelResult.postingToken
            const postingProfile = await resolvePostHistoryProfileByToken(env, postingTokenUsed)
            fbVideoId = reelResult.id
            const confirmedCanonicalPostId = String(reelResult.postId || '').trim()
            const confirmedPostId = confirmedCanonicalPostId || fbVideoId
            const fbReelUrl = String(reelResult.permalinkUrl || '').trim() || `https://www.facebook.com/reel/${fbVideoId}`
            // Only the stored-token path defers via comment_due_at; the bridge override
            // comments immediately below, so it schedules no delay.
            const scheduledCommentDelaySeconds = normalizedShopeeLink && hasCommentToken && !commentViaCloakBridge
                ? getRandomCommentDelaySeconds()
                : null
            const scheduledCommentDueAt = scheduledCommentDelaySeconds
                ? new Date(Date.now() + (scheduledCommentDelaySeconds * 1000)).toISOString()
                : null
            const postReadyCommentState = getPostReadyCommentTraceState(!!normalizedShopeeLink, hasCommentToken, false)
            if (cronHistoryId) {
                await env.DB.prepare(
                    "UPDATE post_history SET fb_post_id = ?, fb_reel_url = ?, post_token_hint = ?, post_profile_id = ?, post_profile_name = ?, comment_status = ?, comment_token_hint = ?, comment_error = ?, comment_delay_seconds = ?, comment_due_at = ? WHERE id = ? AND status = 'posting'"
                ).bind(
                    confirmedPostId,
                    fbReelUrl,
                    deriveCommentTokenHint(postingTokenUsed),
                    postingProfile.profileId,
                    postingProfile.profileName,
                    postReadyCommentState.status,
                    deriveCommentTokenHint(commentTokenCandidates[0] || null),
                    postReadyCommentState.error,
                    scheduledCommentDelaySeconds,
                    scheduledCommentDueAt,
                    cronHistoryId,
                ).run()
            }

            let commentStatus = postReadyCommentState.status
            let commentError: string | null = postReadyCommentState.error
            let commentFbId: string | null = null
            let commentTokenUsed = String(commentTokenCandidates[0] || '').trim()
            let commentProfileId: string | null = null
            let commentProfileName: string | null = null
            let commentTokenHintFinal = deriveCommentTokenHint(commentTokenUsed)

            if (normalizedShopeeLink && commentViaCloakBridge) {
                // comment_token_source='cloak_browser' on a stored-token POST: comment as the
                // Page via the bridge immediately (fails closed, never a stored-token fallback).
                // Re-shorten with the post id FIRST so the commented link carries
                // sub2=post id / sub3=page id — mirrors the force-post bridge branch. Without
                // this the bridge commented the pre-publish shortlink (blank sub2/sub3). The
                // stored-token pending path re-mints in processPendingCommentBacklog instead.
                let commentShopeeLink = normalizedShopeeLink
                try {
                    const commentSubIds = buildPostingCommentShortlinkSubIds({
                        canonicalPostId: confirmedCanonicalPostId,
                        fbVideoId,
                        pageId: page.id,
                        historyId: cronHistoryId,
                        logPrefix: `CRON ${page.name} STORED→CLOAK COMMENT-SHORTLINK`,
                    })
                    const reshortened = await resolvePostingShopeeLinkForNamespace({
                        env,
                        namespaceId: botId,
                        pageId: page.id,
                        shopeeLink: normalizedShopeeLink,
                        logPrefix: `CRON ${page.name} STORED→CLOAK COMMENT-SHORTLINK`,
                        ...commentSubIds,
                    })
                    if (reshortened) commentShopeeLink = reshortened
                } catch (reshortenErr) {
                    console.log(`[CRON ${page.name} STORED→CLOAK COMMENT-SHORTLINK] re-shorten with post id failed; falling back to preflight link: ${reshortenErr instanceof Error ? reshortenErr.message : String(reshortenErr)}`)
                }
                const cloakOverrideText = (await buildAffiliateCommentMessage(env.DB, botId, commentShopeeLink).catch(() => '')) || commentShopeeLink
                const bridged = await sendPageCommentViaCloakBridge({
                    env,
                    pageId: String(page.id || ''),
                    storyId: buildPageStoryId(String(page.id || ''), confirmedPostId),
                    message: cloakOverrideText,
                    logPrefix: `CRON STORED→CLOAK-COMMENT ${page.name}`,
                })
                commentStatus = bridged.status
                commentFbId = bridged.id
                commentError = bridged.error
                commentTokenHintFinal = 'cloak_session_bridge'
            } else if (normalizedShopeeLink && hasCommentToken) {
                commentStatus = 'pending'
                commentError = null
            }

            // Update to success
            if (cronHistoryId) {
                await env.DB.prepare(
                    "UPDATE post_history SET fb_post_id = ?, fb_reel_url = ?, status = 'success', error_message = NULL, post_token_hint = ?, post_profile_id = ?, post_profile_name = ?, comment_status = ?, comment_token_hint = ?, comment_profile_id = ?, comment_profile_name = ?, comment_error = ?, comment_fb_id = ? WHERE id = ? AND status = 'posting'"
                ).bind(
                    confirmedPostId,
                    fbReelUrl,
                    deriveCommentTokenHint(postingTokenUsed),
                    postingProfile.profileId,
                    postingProfile.profileName,
                    commentStatus,
                    commentTokenHintFinal,
                    commentProfileId,
                    commentProfileName,
                    commentError,
                    commentFbId,
                    cronHistoryId,
                ).run()
            }
            if (commentStatus === 'pending') {
                runPendingCommentBacklogSoon(env, Number(cronHistoryId || 0), `CRON ${page.name} IMMEDIATE-COMMENT`, ctx)
            }
            const postedAtIso = new Date().toISOString()
            await markNamespaceVideoPosted(env.DB, botId, unpostedId, postedAtIso)
            markCachedNamespaceVideoPosted(galleryVideosByNamespace, botId, unpostedId, postedAtIso)
            await recordPagePostedVideoGuard(env.DB, {
                namespaceId: botId,
                pageId: page.id,
                videoId: unpostedId,
                sourceFingerprint,
                historyId: cronHistoryId,
                postedAt: nowISO,
            }).catch(() => { })
            cronStats.pagesPosted += 1
            await updateCronRuntimeState(env.DB, {
                runId,
                heartbeatAt: new Date().toISOString(),
                pagesVisited: cronStats.pagesVisited,
                pagesPosted: cronStats.pagesPosted,
                pagesFailed: cronStats.pagesFailed,
            }).catch(() => { })

            await clearVideoShopeeLink(botBucket, unpostedId)
            console.log(`[CRON] Page ${page.name}: posted successfully (fb_video_id: ${fbVideoId}, post_id: ${confirmedPostId}${avatarApplied ? `, avatar_version: ${avatarVersion}` : ''})`)

        } catch (e) {
            const errorMsg = e instanceof Error ? e.message : String(e)
            const isAvatarComposeError = errorMsg.includes('avatar_compose_failed')
            console.error(`[CRON] Page ${page.name}: post failed - ${errorMsg}`)

            // Recovery path: Facebook may already publish this reel even when upload/finish returns transient errors.
            let recovered = false
            if (!isAvatarComposeError) {
                try {
                    let recoveredPostId = ''
                    let recoveredReelUrl = ''

                    if (fbVideoId) {
                        const recoveredResult = await pollPublishedReelAfterProcessing({
                            accessToken: postingTokenUsed || String(page.access_token || ''),
                            fbVideoId,
                            logPrefix: `CRON ${page.name} RECOVER`,
                        })
                        if (recoveredResult.published && recoveredResult.post_id) {
                            recoveredPostId = String(recoveredResult.post_id || '').trim() || fbVideoId
                            recoveredReelUrl = String(recoveredResult.permalink_url || '').trim() || `https://www.facebook.com/reel/${recoveredPostId}`
                        }
                    }

                    if (!recoveredPostId && caption) {
                        const feedRecovered = await recoverPublishedReelFromRecentFeed({
                            accessToken: page.access_token,
                            pageId: page.id,
                            expectedCaption: caption,
                            notBeforeIso: nowISO,
                            logPrefix: `CRON ${page.name} RECOVER-FEED`,
                        })
                        if (feedRecovered.published && feedRecovered.post_id) {
                            recoveredPostId = String(feedRecovered.post_id || '').trim()
                            recoveredReelUrl = String(feedRecovered.permalink_url || '').trim() || `https://www.facebook.com/reel/${recoveredPostId}`
                        }
                    }

                    if (recoveredPostId) {
                        if (!recoveredReelUrl) {
                            recoveredReelUrl = `https://www.facebook.com/reel/${recoveredPostId}`
                        }

                        const recoveredCommentState = getPostReadyCommentTraceState(!!normalizedShopeeLink, hasCommentToken, false)
                        let commentStatus = recoveredCommentState.status
                        let commentError: string | null = recoveredCommentState.error
                        let commentFbId: string | null = null
                        let commentTokenUsed = String(commentTokenCandidates[0] || '').trim()
                        let commentProfileId: string | null = null
                        let commentProfileName: string | null = null
                        const commentTargetId = fbVideoId || extractReelIdFromPermalink(normalizeFacebookPermalink(recoveredReelUrl)) || recoveredPostId
                        const commentTargetDedupKey = buildCommentTargetDedupKey(commentTargetId, page.id)
                        let recoveryCommentShopeeLink = normalizedShopeeLink

                        if (recoveryCommentShopeeLink && hasCommentToken) {
                            if (dedupCommentTargets.has(commentTargetDedupKey)) {
                                console.log(`[CRON] Page ${page.name}: recovery comment skip for ${commentTargetId} (already commented in this run)`)
                                commentStatus = 'success'
                            } else {
                                try {
                                    const commentSubIds = buildPostingCommentShortlinkSubIds({
                                        canonicalPostId: recoveredPostId,
                                        fbVideoId,
                                        reelId: extractIdFromCommentTargetInput(recoveredReelUrl),
                                        pageId: page.id,
                                        historyId: cronHistoryId,
                                        logPrefix: `CRON ${page.name} RECOVER COMMENT-SHORTLINK`,
                                    })
                                    const reshortened = await resolvePostingShopeeLinkForNamespace({
                                        env,
                                        namespaceId: botId,
                                        pageId: page.id,
                                        shopeeLink: recoveryCommentShopeeLink,
                                        logPrefix: `CRON ${page.name} RECOVER COMMENT-SHORTLINK`,
                                        ...commentSubIds,
                                    })
                                    if (reshortened) recoveryCommentShopeeLink = reshortened
                                } catch (reshortenErr) {
                                    console.log(`[CRON ${page.name} RECOVER COMMENT-SHORTLINK] re-shorten with post id failed; falling back to preflight link: ${reshortenErr instanceof Error ? reshortenErr.message : String(reshortenErr)}`)
                                }
                                const commentWaitMs = getRandomCommentDelayMs()
                                console.log(`[CRON] Page ${page.name}: recovery comment wait ${Math.ceil(commentWaitMs / 1000)}s...`)
                                await waitMs(commentWaitMs)
                                const commentResult = await postShopeeCommentWithFallback({
                                    env,
                                    namespaceId: botId,
                                    fbVideoId: commentTargetId,
                                    fbPostId: recoveredPostId,
                                    fbReelUrlOrId: recoveredReelUrl,
                                    shopeeLink: recoveryCommentShopeeLink,
                                    lazadaLink: normalizedLazadaLink,
                                    commentTokens: commentTokenCandidates,
                                    pageId: page.id,
                                    logPrefix: `CRON ${page.name} RECOVER`,
                                })
                                if (!commentResult.ok) {
                                    commentStatus = 'failed'
                                    commentError = commentResult.error || 'comment_failed'
                                    commentTokenUsed = String(commentResult.commentToken || commentTokenUsed || '').trim()
                                    const commentProfile = await resolvePostHistoryProfileByToken(env, commentTokenUsed)
                                    commentProfileId = commentProfile.profileId
                                    commentProfileName = commentProfile.profileName
                                    await notifyCommentTokenIssue(
                                        env,
                                        botId,
                                        page.id,
                                        page.name,
                                        commentError,
                                    ).catch((notifyErr) => {
                                        console.error(`[CRON] Page ${page.name}: recover notifyCommentTokenIssue failed: ${notifyErr instanceof Error ? notifyErr.message : String(notifyErr)}`)
                                    })
                                } else {
                                    dedupCommentTargets.add(commentTargetDedupKey)
                                    commentStatus = 'success'
                                    commentFbId = commentResult.id || null
                                    commentTokenUsed = String(commentResult.commentToken || commentTokenUsed || '').trim()
                                    const commentProfile = await resolvePostHistoryProfileByToken(env, commentTokenUsed)
                                    commentProfileId = commentProfile.profileId
                                    commentProfileName = commentProfile.profileName
                                }
                            }
                        }

                        const recoveredPostProfile = await resolvePostHistoryProfileByToken(env, postingTokenUsed)
                        if (cronHistoryId) {
                            await env.DB.prepare(
                                "UPDATE post_history SET fb_post_id = ?, fb_reel_url = ?, status = 'success', error_message = NULL, post_token_hint = ?, post_profile_id = ?, post_profile_name = ?, comment_status = ?, comment_token_hint = ?, comment_profile_id = ?, comment_profile_name = ?, comment_error = ?, comment_fb_id = ? WHERE id = ? AND status IN ('posting','failed')"
                            ).bind(
                                recoveredPostId,
                                recoveredReelUrl,
                                deriveCommentTokenHint(postingTokenUsed),
                                recoveredPostProfile.profileId,
                                recoveredPostProfile.profileName,
                                commentStatus,
                                deriveCommentTokenHint(commentTokenUsed),
                                commentProfileId,
                                commentProfileName,
                                commentError,
                                commentFbId,
                                cronHistoryId,
                            ).run()
                        }
                        const recoveredPostedAtIso = new Date().toISOString()
                        await markNamespaceVideoPosted(env.DB, botId, unpostedId, recoveredPostedAtIso)
                        markCachedNamespaceVideoPosted(galleryVideosByNamespace, botId, unpostedId, recoveredPostedAtIso)
                        await recordPagePostedVideoGuard(env.DB, {
                            namespaceId: botId,
                            pageId: page.id,
                            videoId: unpostedId,
                            sourceFingerprint,
                            historyId: cronHistoryId,
                            postedAt: nowISO,
                        }).catch(() => { })
                        cronStats.pagesPosted += 1
                        updateCronRuntimeState(env.DB, {
                            runId,
                            heartbeatAt: new Date().toISOString(),
                            pagesVisited: cronStats.pagesVisited,
                            pagesPosted: cronStats.pagesPosted,
                            pagesFailed: cronStats.pagesFailed,
                        }).catch(() => { })

                        await clearVideoShopeeLink(botBucket, unpostedId)
                        console.log(`[CRON] Page ${page.name}: recovered as success (fb_video_id: ${fbVideoId}, post_id: ${recoveredPostId})`)
                        recovered = true
                    }
                } catch (recoverErr) {
                    console.error(`[CRON] Page ${page.name}: recover failed - ${recoverErr instanceof Error ? recoverErr.message : String(recoverErr)}`)
                }
            }

            if (recovered) {
                continue
            }

            // Update to failed
            if (cronHistoryId) {
                await env.DB.prepare(
                    "UPDATE post_history SET status = 'failed', error_message = ?, comment_status = 'not_attempted' WHERE id = ? AND status = 'posting'"
                ).bind(errorMsg, cronHistoryId).run()
            }

            // Keep dedup key so this schedule window/interval bucket does not retry again after one failed attempt.
            console.log(`[CRON] Page ${page.name}: keep dedup key after failure, skip retries until next schedule window`)
        }
        } finally {
            await releasePostingLock(env.DB, videoPostingLockKey)
            await releasePostingLock(env.DB, pagePostingLockKey)
        }
            } catch (pageError) {
                cronStats.pagesFailed += 1
                const message = pageError instanceof Error ? pageError.message : String(pageError)
                console.error(`[CRON] Page ${page.name}: unexpected fatal page error - ${message}`)
                await updateCronRuntimeState(env.DB, {
                    runId,
                    heartbeatAt: new Date().toISOString(),
                    pagesVisited: cronStats.pagesVisited,
                    pagesPosted: cronStats.pagesPosted,
                    pagesFailed: cronStats.pagesFailed,
                    lastError: `[${botId}/${String(page.name || page.id)}] ${message}`,
                }).catch(() => { })
                continue
            } finally {
                await updateCronRuntimeState(env.DB, {
                    runId,
                    heartbeatAt: new Date().toISOString(),
                    currentPageId: null,
                    currentPageName: null,
                    currentNamespaceId: null,
                    pagesVisited: cronStats.pagesVisited,
                    pagesPosted: cronStats.pagesPosted,
                    pagesFailed: cronStats.pagesFailed,
                }).catch(() => { })
            }
        }
    } catch (error) {
        fatalError = error instanceof Error ? error : new Error(String(error))
        throw fatalError
    } finally {
        await env.DB.prepare(
            `DELETE FROM posting_locks
             WHERE lock_key = 'page::__scheduled__::run'`
        ).run().catch(() => { })
        await updateCronRuntimeState(env.DB, {
            runId,
            status: fatalError ? 'failed' : 'idle',
            finishedAt: new Date().toISOString(),
            heartbeatAt: new Date().toISOString(),
            currentPageId: null,
            currentPageName: null,
            currentNamespaceId: null,
            pagesVisited: cronStats.pagesVisited,
            pagesPosted: cronStats.pagesPosted,
            pagesFailed: cronStats.pagesFailed,
            lastError: fatalError ? fatalError.message : null,
        }).catch(() => { })
        await releasePostingLock(env.DB, scheduledRunLockKey)
    }

    console.log('[CRON] Auto-post check complete')
}

// Container class สำหรับ FFmpeg merge + Full Pipeline
export class MergeContainer extends Container {
    defaultPort = 8080
    sleepAfter = '10m'
}

/** Watchdog: ตรวจจับ job ค้าง → ย้ายกลับ queue เพื่อ retry (สูงสุด 3 ครั้ง) */
async function watchdogStuckJobs(env: Env) {
    const MAX_RETRIES = 3
    const FAILED_RETRY_DELAY_MS = 60 * 1000
    const STARTUP_STUCK_THRESHOLD_MS = 60 * 1000 // งานที่ยังไม่ส่ง progress callback เลย ให้ retry เร็ว
    const STUCK_THRESHOLD_MS = 10 * 60 * 1000 // 10 นาที
    const now = Date.now()

    // รวบรวม bucket scope ทั้งหมด:
    // - legacy/default
    // - ทุก channel bot_id
    // - ทุก workspace namespace_id ที่ใช้งานจริง
    const botIds = new Set<string>(['default'])
    try {
        const { results } = await env.DB.prepare('SELECT DISTINCT bot_id FROM channels').all()
        for (const row of results) {
            const id = (row as any).bot_id
            if (id && id !== 'default') botIds.add(String(id))
        }
    } catch { /* DB might not have channels yet */ }

    try {
        const { results } = await env.DB.prepare('SELECT DISTINCT namespace_id FROM email_namespaces').all()
        for (const row of results || []) {
            const id = String((row as any)?.namespace_id || '').trim()
            if (id && id !== 'default') botIds.add(id)
        }
    } catch { /* DB might not have email_namespaces yet */ }

    try {
        const { results } = await env.DB.prepare('SELECT DISTINCT namespace_id FROM users').all()
        for (const row of results || []) {
            const id = String((row as any)?.namespace_id || '').trim()
            if (id && id !== 'default') botIds.add(id)
        }
    } catch { /* DB might not have users yet */ }

    try {
        await ensureTelegramBotSessionsTable(env.DB)
        const { results } = await env.DB.prepare('SELECT DISTINCT namespace_id FROM telegram_bot_sessions').all()
        for (const row of results || []) {
            const id = String((row as any)?.namespace_id || '').trim()
            if (id && id !== 'default') botIds.add(id)
        }
    } catch { /* DB might not have telegram_bot_sessions yet */ }

    const adminNamespaceId = await resolvePrimaryAdminNamespaceId(env.DB).catch(() => '')
    const orderedBotIds = Array.from(botIds)
    if (adminNamespaceId && orderedBotIds.includes(adminNamespaceId)) {
        orderedBotIds.splice(orderedBotIds.indexOf(adminNamespaceId), 1)
        orderedBotIds.unshift(adminNamespaceId)
    }
    const MAX_QUEUE_DRAIN_CHECKS = 8
    let queueDrainChecks = 0

    for (const botId of orderedBotIds) {
        const botBucket = new BotBucket(env.BUCKET, botId)
        try {
            const list = await botBucket.list({ prefix: '_processing/' })
            const hadProcessingEntries = list.objects.length > 0

            for (const obj of list.objects) {
                const data = await botBucket.get(obj.key)
                if (!data) continue

                const job = await data.json() as {
                    id: string; videoUrl: string; chatId: number;
                    shopeeLink?: string; lazadaLink?: string; updatedAt?: string; createdAt?: string;
                    retryCount?: number; step?: number; stepName?: string; status?: string;
                }

                if (job.status === 'failed') {
                    const errorText = String((job as Record<string, unknown>).error || '').trim()
                    const errorCategory = String((job as Record<string, unknown>).errorCategory || '').trim()
                    const nonRetryableFailure =
                        errorCategory === 'ffmpeg_timeout'
                        || errorText.includes('FFmpeg flip timed out')
                        || errorText.includes('missing_original_video_asset_unrecoverable')
                        || errorText.includes('missing_original_video_asset_recovery_failed_http_404')
                        || errorText.includes('missing_original_video_asset_recovery_invalid_content')
                    if (nonRetryableFailure) continue

                    const failedAt = String(job.updatedAt || job.createdAt || '').trim() || obj.uploaded.toISOString()
                    const elapsedSinceFailure = now - new Date(failedAt).getTime()
                    if (elapsedSinceFailure < FAILED_RETRY_DELAY_MS) continue

                    const nextRetryCount = Number(job.retryCount || 0) + 1
                    if (!String(job.videoUrl || '').trim()) continue
                    if (nextRetryCount > MAX_RETRIES) continue

                    await botBucket.delete(obj.key)
                    await botBucket.put(`_queue/${job.id}.json`, JSON.stringify({
                        id: job.id,
                        videoUrl: job.videoUrl,
                        chatId: Number(job.chatId || 0),
                        shopeeLink: job.shopeeLink || '',
                        lazadaLink: job.lazadaLink || '',
                        createdAt: new Date().toISOString(),
                        status: 'queued',
                        retryCount: nextRetryCount,
                    }), {
                        httpMetadata: { contentType: 'application/json' },
                    })
                    console.log(`[WATCHDOG] Failed job ${job.id} moved back to queue (retry #${nextRetryCount})`)
                    continue
                }

                const createdAt = String(job.createdAt || '').trim() || obj.uploaded.toISOString()
                const updatedAt = String(job.updatedAt || '').trim()
                const numericStep = typeof job.step === 'number' ? job.step : Number(job.step)
                const hasProgressCallback = (Number.isFinite(numericStep) && numericStep > 0)
                    || (!!updatedAt && updatedAt !== createdAt)
                const thresholdMs = hasProgressCallback
                    ? STUCK_THRESHOLD_MS
                    : STARTUP_STUCK_THRESHOLD_MS

                // เช็คว่าค้างหรือยัง
                const lastUpdate = hasProgressCallback
                    ? (updatedAt || createdAt || obj.uploaded.toISOString())
                    : createdAt
                const elapsed = now - new Date(lastUpdate).getTime()

                if (elapsed < thresholdMs) continue // ยังไม่ค้าง

                const retryCount = (job.retryCount || 0) + 1
                const stuckStep = job.stepName || `step ${job.step || '?'}`

                console.log(
                    `[WATCHDOG] Job ${job.id} (bot: ${botId}) stuck at "${stuckStep}" for ${Math.round(elapsed / 1000)}s `
                    + `(retry #${retryCount}, threshold=${Math.round(thresholdMs / 1000)}s)`
                )

                // ลบจาก _processing/
                await botBucket.delete(obj.key)

                if (retryCount > MAX_RETRIES) {
                    console.log(`[WATCHDOG] Job ${job.id} exceeded max retries (${MAX_RETRIES}), marking as failed`)
                    await sendTelegram(env.TELEGRAM_BOT_TOKEN, 'sendMessage', {
                        chat_id: job.chatId,
                        text: `❌ วิดีโอ ${job.id} ล้มเหลวหลัง retry ${MAX_RETRIES} ครั้ง\nกรุณาส่งลิงก์ใหม่อีกครั้ง`,
                    }).catch(() => { })
                } else {
                    // ย้ายกลับ _queue/ เพื่อ retry
                    await botBucket.put(`_queue/${job.id}.json`, JSON.stringify({
                        id: job.id,
                        videoUrl: job.videoUrl,
                        chatId: job.chatId,
                        shopeeLink: job.shopeeLink || '',
                        lazadaLink: job.lazadaLink || '',
                        createdAt: new Date().toISOString(),
                        status: 'queued',
                        retryCount,
                    }), {
                        httpMetadata: { contentType: 'application/json' },
                    })
                    console.log(`[WATCHDOG] Job ${job.id} moved back to queue (retry #${retryCount})`)
                }
            }

            // ลองเริ่มอันถัดไปของ bot นี้ด้วย dispatcher เดียวกับ completion/cron:
            // queue -> ready inbox -> admin original, while preserving one active job.
            if (hadProcessingEntries || queueDrainChecks < MAX_QUEUE_DRAIN_CHECKS) {
                queueDrainChecks++
                await processNextInQueue(env, botId)
            }
        } catch (e) {
            console.error(`[WATCHDOG] Error for bot ${botId}:`, e instanceof Error ? e.message : String(e))
        }
    }
}

export default {
    fetch: async (request: Request, env: Env, ctx: ExecutionContext): Promise<Response> => {
        // Public report aliases bypass Hono so they never touch session/admin
        // middleware and never accidentally inherit auth requirements.
        const reportResponse = await handleReportProxyRequest(request)
        if (reportResponse) return reportResponse
        return app.fetch(request, env, ctx)
    },
    scheduled: async (event: ScheduledEvent, env: Env, _ctx: ExecutionContext) => {
        // Keep scheduled posting deterministic: run the posting loop first.
        // Inbox processing and pending comments run only after posting has yielded;
        // this preserves cron isolation while still draining user-submitted videos.
        //
        // CRITICAL: handleScheduled rethrows fatal posting errors. Run it through
        // runScheduledProcessingTick so a posting failure can never skip the
        // inbox-processing guardian — the only automatic, every-minute backstop
        // that keeps draining the backlog one-at-a-time and recovers a missed
        // completion callback (a job that finished but never had its next chained).
        await runScheduledProcessingTick({
            runPosting: () => handleScheduled(env, _ctx),
            onPostingError: (error) => {
                console.error(`[CRON-POSTING] ${error instanceof Error ? error.message : String(error)}`)
            },
            runGuardian: () => _ctx.waitUntil(autoProcessReadyInboxForNamespaces(env, _ctx).then((report) => {
                console.log(`[CRON-AUTO-INBOX] scanned=${report.scanned_namespaces}/${report.total_namespaces} started=${report.started_total} active=${report.active_total} idle=${report.idle_total}`)
            }).catch((error) => {
                console.error(`[CRON-AUTO-INBOX] ${error instanceof Error ? error.message : String(error)}`)
            })),
            runComments: () => _ctx.waitUntil(processPendingCommentBacklog(env).catch((error) => {
                console.error(`[CRON-COMMENTS] ${error instanceof Error ? error.message : String(error)}`)
            })),
        })
        // Recover rows that FB actually published but whose publish confirmation failed
        // (e.g. cloak_post_failed: browser_graph_request_failed leaves fb_post_id null).
        // Scans the page feed via the namespace token pool, tolerant of public canonical
        // page-owner id mismatches, then flips the row to success + comment_status='pending'
        // so the comment backlog above posts the Shopee link on the next tick. Own waitUntil
        // so it never blocks (or is blocked by) posting, and swallows its own errors.
        _ctx.waitUntil(recoverFailedHistoryRowsFromFeed({ env, logPrefix: 'CRON' }).catch((error) => {
            console.error(`[CRON-RECOVER-FAILED] ${error instanceof Error ? error.message : String(error)}`)
        }))
        // Ad-only queue cadence — process at most ONE queued ad-only item per operator-set interval.
        // Runs in waitUntil so it never blocks (or is blocked by) the posting loop, and is wrapped to
        // swallow its own errors so an ad-only failure can never derail the every-minute cron.
        _ctx.waitUntil(maybeProcessAdOnlyQueueOnSchedule(env).catch((error) => {
            console.error(`[AD-ONLY-QUEUE] ${error instanceof Error ? error.message : String(error)}`)
        }))
        // Follow/Page-like lane cadence — OPT-IN, OFF by default. When the operator enables it, create
        // at most ONE Follow ad per interval from the OUTCOME_ENGAGEMENT/PAGE_LIKES template (separate
        // settings, separate last_run). Its own waitUntil + error swallow so it never derails the cron.
        _ctx.waitUntil(maybeProcessFollowAdOnSchedule(env).catch((error) => {
            console.error(`[FOLLOW-AD] ${error instanceof Error ? error.message : String(error)}`)
        }))
        // Turn OFF (status=PAUSED, NEVER delete) finished SALES/click-link ad-only campaigns whose
        // scheduled run window has ended. Runs in its OWN waitUntil so it never blocks (or is blocked by)
        // posting or the ad-only queue, and swallows its own errors so a pause failure can't derail the
        // cron. The Follow lane is handled separately by autoRemoveCompletedFollowAds (archive, not pause).
        _ctx.waitUntil(autoPauseCompletedAdOnlyCampaigns(env).catch((error) => {
            console.error(`[AD-ONLY-AUTOPAUSE] ${error instanceof Error ? error.message : String(error)}`)
        }))
        // REMOVE/ARCHIVE finished FOLLOW ads (recoverable status=ARCHIVED, NEVER hard-deleted) so the
        // LIKE_PAGE button detaches from the story before the click-link handoff. Pausing alone is NOT
        // completion for the Follow lane. Own waitUntil + error swallow so it can't derail the cron.
        _ctx.waitUntil(autoRemoveCompletedFollowAds(env).catch((error) => {
            console.error(`[FOLLOW-AD-REMOVE] ${error instanceof Error ? error.message : String(error)}`)
        }))
        // Per-page Create Ads automation: each ENABLED page runs its own jittered cadence + daily cap and
        // creates one ACTIVE Follow ad per slot. Disabled by default (fail-closed); separate waitUntil so
        // a slow create can't block posting or the other ad lanes.
        _ctx.waitUntil(maybeProcessPerPageAutoAdsOnSchedule(env).catch((error) => {
            console.error(`[AUTO-ADS] ${error instanceof Error ? error.message : String(error)}`)
        }))
        // 24h Follow→Click-link handoff: after a Follow ad is turned OFF, reuse the same source system
        // video to create the click-link ad in the page's fixed click-link adset (idempotent, one per row).
        _ctx.waitUntil(processFollowToClickLinkHandoffs(env).catch((error) => {
            console.error(`[AUTO-ADS-HANDOFF] ${error instanceof Error ? error.message : String(error)}`)
        }))
        // Explore: continuously refresh WATCHED EXTERNAL pages (un-owned pages the operator added).
        // Read-only Graph reads into our own cache, bounded to a few pages per tick with a global
        // cooldown. Own waitUntil + error swallow so it can never derail (or be derailed by) posting.
        _ctx.waitUntil(maybeSyncExternalWatchedPagesOnSchedule(env).catch((error) => {
            console.error(`[EXPLORE-EXTERNAL] ${error instanceof Error ? error.message : String(error)}`)
        }))
    },
}
